const WORDS_EXT = [{"id":2501,"en":"abandon","ja":"捨て去る\n完全に見捨てるニュアンス。leaveより強い断絶感","level":6,"lnum":1,"ex":"She had to abandon her plan due to the sudden storm.","exja":"突然の嵐のため、彼女は計画を断念しなければならなかった。"},{"id":2502,"en":"abnormal","ja":"異常な\nnormalからの逸脱。否定的文脈で使う","level":6,"lnum":1,"ex":"The doctor said the test results were abnormal.","exja":"医者は検査結果が異常だと言った。"},{"id":2503,"en":"aboard","ja":"乗り込んで\n船・飛行機・列車に乗った状態を指す","level":6,"lnum":1,"ex":"All passengers must be aboard the plane before departure.","exja":"出発前に全乗客が飛行機に乗り込んでいなければならない。"},{"id":2504,"en":"aborigine","ja":"先住民\nオーストラリアの先住民を指すことが多い","level":6,"lnum":1,"ex":"The aborigine guided us through the ancient forest.","exja":"先住民は私たちを古い森の中へ案内してくれた。"},{"id":2505,"en":"absence","ja":"欠席・不在\n物・人がその場にいないこと全般に使う","level":6,"lnum":1,"ex":"His absence from school worried his parents.","exja":"彼の学校欠席は両親を心配させた。"},{"id":2506,"en":"absolute","ja":"絶対的な\n例外や条件が一切ない最上の強調","level":6,"lnum":1,"ex":"The teacher had absolute trust in her students.","exja":"その教師は生徒たちを絶対的に信頼していた。"},{"id":2507,"en":"absolutely","ja":"まったく\n強い同意や否定に使う口語でも頻出","level":6,"lnum":1,"ex":"I absolutely agree with your decision.","exja":"あなたの決断にまったく同意します。"},{"id":2508,"en":"absorb","ja":"吸収する\n液体・知識・衝撃など幅広く使える","level":6,"lnum":1,"ex":"A sponge can absorb a large amount of water.","exja":"スポンジは大量の水を吸収することができる。"},{"id":2509,"en":"abstract","ja":"抽象的な\n具体性がなく概念的な意味を持つ","level":6,"lnum":1,"ex":"The concept of freedom is quite abstract.","exja":"自由という概念はかなり抽象的だ。"},{"id":2510,"en":"abundance","ja":"豊富さ\n必要以上にあふれるほど多い状態","level":6,"lnum":1,"ex":"The garden was filled with an abundance of flowers.","exja":"その庭には花があふれるほど咲いていた。"},{"id":2511,"en":"abundant","ja":"豊富な\n量が非常に多い。plentyより書き言葉的","level":6,"lnum":1,"ex":"Fresh water is abundant in this mountain region.","exja":"この山岳地帯では新鮮な水が豊富だ。"},{"id":2512,"en":"academy","ja":"学院\n専門的な教育機関や学術団体を指す","level":6,"lnum":1,"ex":"She was accepted into a prestigious music academy.","exja":"彼女は名門の音楽学院に入学を許可された。"},{"id":2513,"en":"accent","ja":"なまり・強勢\n話し方の地域差や音節の強調両方に使う","level":6,"lnum":1,"ex":"He spoke English with a strong French accent.","exja":"彼は強いフランスなまりで英語を話した。"},{"id":2514,"en":"acceptance","ja":"受け入れ\n状況や提案を認めること。approvalより広い","level":6,"lnum":1,"ex":"Her acceptance of the award surprised everyone.","exja":"彼女の受賞への受け入れはみんなを驚かせた。"},{"id":2515,"en":"accessible","ja":"利用しやすい\n誰でも近づけるまたは理解しやすい状態","level":6,"lnum":1,"ex":"The new library is accessible to people with disabilities.","exja":"新しい図書館は障害のある人にも利用しやすい。"},{"id":2516,"en":"accessory","ja":"アクセサリー\n服飾小物や付属品。犯罪の共犯者の意味も","level":6,"lnum":1,"ex":"She chose a simple accessory to complete her outfit.","exja":"彼女はコーディネートを完成させるシンプルなアクセサリーを選んだ。"},{"id":2517,"en":"accidental","ja":"偶然の\n意図せず起きた出来事に使う","level":6,"lnum":1,"ex":"The fire was caused by an accidental spark.","exja":"その火事は偶然の火花によって引き起こされた。"},{"id":2518,"en":"accidentally","ja":"偶然に\nわざとではなくうっかりという場面で頻出","level":6,"lnum":1,"ex":"He accidentally knocked over the glass of water.","exja":"彼は誤ってコップの水をこぼしてしまった。"},{"id":2519,"en":"accompany","ja":"同行する\n一緒についていく。音楽の伴奏にも使う","level":6,"lnum":1,"ex":"Would you like me to accompany you to the station?","exja":"駅まで一緒についていきましょうか。"},{"id":2520,"en":"accomplish","ja":"達成する\n努力の末に目標を成し遂げる","level":6,"lnum":1,"ex":"She worked hard to accomplish her goal of becoming a doctor.","exja":"彼女は医者になるという目標を達成するために懸命に努力した。"},{"id":2521,"en":"according to","ja":"〜によると\n情報の出所を示すフォーマルな表現","level":6,"lnum":1,"ex":"According to the weather forecast, it will rain tomorrow.","exja":"天気予報によると、明日は雨が降るだろう。"},{"id":2522,"en":"account","ja":"説明する\naccount forで「〜の理由を説明する」の意味","level":6,"lnum":1,"ex":"Can you account for the missing funds?","exja":"行方不明の資金について説明できますか。"},{"id":2523,"en":"accountant","ja":"会計士\nお金の管理・帳簿を扱う専門職","level":6,"lnum":1,"ex":"Her father works as an accountant at a large company.","exja":"彼女の父は大きな会社で会計士として働いている。"},{"id":2524,"en":"accuracy","ja":"正確さ\n誤りのない精度の高さを指す","level":6,"lnum":1,"ex":"The accuracy of the report was checked by the editor.","exja":"報告書の正確さは編集者によって確認された。"},{"id":2525,"en":"accurate","ja":"正確な\n事実や測定に誤りがない状態","level":6,"lnum":1,"ex":"The map is accurate enough to use for hiking.","exja":"その地図はハイキングに使えるほど正確だ。"},{"id":2526,"en":"accurately","ja":"正確に\n誤りなく精密に行う様子","level":6,"lnum":1,"ex":"The machine measures temperature accurately to one decimal place.","exja":"その機械は小数点第一位まで正確に温度を測定する。"},{"id":2527,"en":"accuse","ja":"告発する\n人を責めたり罪に問う。強い非難のニュアンス","level":6,"lnum":1,"ex":"He was accused of stealing money from the store.","exja":"彼はその店からお金を盗んだと告発された。"},{"id":2528,"en":"accustom","ja":"慣れさせる\naccustomed toで「〜に慣れている」の形で頻出","level":6,"lnum":1,"ex":"It takes time to accustom yourself to a new environment.","exja":"新しい環境に慣れるには時間がかかる。"},{"id":2529,"en":"ache","ja":"痛み\n鈍く続く痛み。painより持続的なイメージ","level":6,"lnum":1,"ex":"Her back began to ache after sitting for hours.","exja":"何時間も座っていると、彼女の背中が痛み始めた。"},{"id":2530,"en":"acknowledge","ja":"認める\n事実や功績を公式に認める。フォーマルな場面","level":6,"lnum":1,"ex":"He acknowledged his mistake in front of the class.","exja":"彼はクラスの前で自分の間違いを認めた。"},{"id":2531,"en":"acknowledgment","ja":"承認\n感謝や確認の意を示すこと","level":6,"lnum":1,"ex":"The professor sent an acknowledgment of the student's research.","exja":"教授は学生の研究への承認を送った。"},{"id":2532,"en":"acquaintance","ja":"知り合い\nfriendほど親しくない間柄の人","level":6,"lnum":1,"ex":"She is not a close friend, just an acquaintance.","exja":"彼女は親しい友人ではなく、ただの知り合いだ。"},{"id":2533,"en":"acquire","ja":"習得する\n努力や時間をかけて手に入れる","level":6,"lnum":1,"ex":"It takes years to acquire fluency in a foreign language.","exja":"外国語を流暢に話せるようになるには何年もかかる。"},{"id":2534,"en":"actress","ja":"女優\n女性の俳優。近年はactorで統一される傾向も","level":6,"lnum":1,"ex":"The actress won an award for her outstanding performance.","exja":"その女優は優れた演技で賞を受賞した。"},{"id":2535,"en":"ad","ja":"広告\nadvertisementの略。口語でよく使う","level":6,"lnum":1,"ex":"I saw an ad for the new smartphone on TV.","exja":"テレビで新しいスマートフォンの広告を見た。"},{"id":2536,"en":"adapt","ja":"適応する\n新しい環境や状況に合わせて変化する","level":6,"lnum":1,"ex":"Animals must adapt to survive in changing environments.","exja":"動物は変化する環境で生き残るために適応しなければならない。"},{"id":2537,"en":"addressee","ja":"受取人\n手紙や荷物を受け取る側の人","level":6,"lnum":1,"ex":"Please make sure the addressee's name is written clearly.","exja":"受取人の名前が明確に書かれているか確認してください。"},{"id":2538,"en":"administration","ja":"行政・管理\n政府や組織の運営・管理業務全般","level":6,"lnum":1,"ex":"The administration announced new rules for students.","exja":"学校の管理部門が生徒向けの新しいルールを発表した。"},{"id":2539,"en":"admiration","ja":"称賛\n感心・尊敬の気持ち。愛情より尊敬寄り","level":6,"lnum":1,"ex":"She looked at the sunset with deep admiration.","exja":"彼女は深い称賛の気持ちで夕日を眺めた。"},{"id":2540,"en":"admission","ja":"入場・入学\n施設への入場や学校への入学許可","level":6,"lnum":1,"ex":"Admission to the museum is free on Sundays.","exja":"日曜日はその博物館への入場が無料だ。"},{"id":2541,"en":"adopt","ja":"採用する\n制度・意見・子供を受け入れ自分のものとする","level":6,"lnum":1,"ex":"The city decided to adopt a new recycling policy.","exja":"市は新しいリサイクル方針を採用することにした。"},{"id":2542,"en":"adorable","ja":"かわいらしい\n思わず愛したくなるほどかわいい","level":6,"lnum":1,"ex":"The little puppy was absolutely adorable.","exja":"その小さな子犬はとてもかわいらしかった。"},{"id":2543,"en":"advance","ja":"前進する\n先に進む・発展する。名詞でも使う","level":6,"lnum":1,"ex":"Science has advanced greatly over the past century.","exja":"科学はここ1世紀で大きく前進した。"},{"id":2544,"en":"adverb","ja":"副詞\n動詞・形容詞を修飾する品詞","level":6,"lnum":1,"ex":"\"Quickly\" is an adverb that modifies the verb \"run.\"","exja":"\"quickly\"は動詞\"run\"を修飾する副詞だ。"},{"id":2545,"en":"adverbial","ja":"副詞的な\n副詞の働きをする文法用語","level":6,"lnum":1,"ex":"He used an adverbial phrase to add more detail to the sentence.","exja":"彼は文に詳細を加えるために副詞的な句を使った。"},{"id":2546,"en":"advert","ja":"広告\nadvertisementの英国式短縮形","level":6,"lnum":1,"ex":"The advert for the new movie caught my attention.","exja":"その新映画の広告が私の注意を引いた。"},{"id":2547,"en":"advertise","ja":"広告する\n商品やサービスを宣伝する","level":6,"lnum":1,"ex":"The company decided to advertise its products online.","exja":"その会社はオンラインで製品を広告することにした。"},{"id":2548,"en":"adviser","ja":"アドバイザー\n専門的な助言を与える人","level":6,"lnum":1,"ex":"She asked her academic adviser for guidance.","exja":"彼女はアドバイザーに指導を求めた。"},{"id":2549,"en":"aerobics","ja":"エアロビクス\n有酸素運動を目的とした体操の一種","level":6,"lnum":1,"ex":"She does aerobics every morning to stay fit.","exja":"彼女は体型を維持するために毎朝エアロビクスをする。"},{"id":2550,"en":"affection","ja":"愛情\n家族や友人への温かい感情。恋愛より穏やか","level":6,"lnum":1,"ex":"He showed great affection for his younger sister.","exja":"彼は妹に深い愛情を示した。"},{"id":2551,"en":"afford","ja":"余裕がある\n経済的・時間的に〜できる余裕がある","level":6,"lnum":1,"ex":"We cannot afford to waste any more time.","exja":"私たちはこれ以上時間を無駄にする余裕はない。"},{"id":2552,"en":"afterward","ja":"その後\n出来事の後で。米国式つづり","level":6,"lnum":1,"ex":"We had dinner, and afterward we went for a walk.","exja":"夕食を食べた後、私たちは散歩に行った。"},{"id":2553,"en":"agenda","ja":"議題\n会議で話し合う項目のリスト","level":6,"lnum":1,"ex":"The meeting agenda was sent to all participants in advance.","exja":"会議の議題は事前に全参加者に送られた。"},{"id":2554,"en":"aggressive","ja":"攻撃的な\n強引で相手を圧迫するような態度","level":6,"lnum":1,"ex":"The aggressive dog scared the children in the park.","exja":"その攻撃的な犬は公園にいた子供たちを怖がらせた。"},{"id":2555,"en":"agreement","ja":"合意\n双方が同意すること。契約書の意味も","level":6,"lnum":1,"ex":"Both countries signed an agreement to reduce pollution.","exja":"両国は汚染を減らすための合意に署名した。"},{"id":2556,"en":"agricultural","ja":"農業の\n農業に関連するフォーマルな形容詞","level":6,"lnum":1,"ex":"The agricultural land in this region is very fertile.","exja":"この地域の農地はとても肥沃だ。"},{"id":2557,"en":"aid","ja":"援助\n困っている人への支援。formalな場面で使う","level":6,"lnum":1,"ex":"Volunteers aided the rescue team during the disaster.","exja":"ボランティアたちは災害時に救助チームを援助した。"},{"id":2558,"en":"aid","ja":"援助する\n人や組織を助けるフォーマルな表現","level":6,"lnum":1},{"id":2559,"en":"aim","ja":"目的\n達成しようとする目標や方向性","level":6,"lnum":1,"ex":"Her aim is to become a professional musician someday.","exja":"彼女の目的はいつかプロの音楽家になることだ。"},{"id":2560,"en":"air conditioning","ja":"エアコン\n室温を調整する空調システム","level":6,"lnum":1,"ex":"The air conditioning in the office was broken all week.","exja":"オフィスのエアコンが1週間ずっと壊れていた。"},{"id":2561,"en":"air force","ja":"空軍\n国の軍隊の航空部門","level":6,"lnum":1,"ex":"He dreams of joining the air force after graduation.","exja":"彼は卒業後に空軍に入ることを夢見ている。"},{"id":2562,"en":"airline","ja":"航空会社\n航空輸送サービスを提供する企業","level":6,"lnum":1,"ex":"Which airline did you choose for your trip to Europe?","exja":"ヨーロッパへの旅行にどの航空会社を選びましたか。"},{"id":2563,"en":"alcohol","ja":"アルコール\n飲料・消毒など広く使われる物質","level":6,"lnum":1,"ex":"Teenagers should not be allowed to drink alcohol.","exja":"10代の若者はアルコールを飲むことを許可されるべきではない。"},{"id":2564,"en":"alcoholic","ja":"アルコールの\nアルコールを含む、または依存症の意味も","level":6,"lnum":1,"ex":"The doctor advised him to avoid alcoholic drinks.","exja":"医者は彼にアルコール飲料を避けるよう勧めた。"},{"id":2565,"en":"alike","ja":"似ている\n2つ以上のものが共通点を持つ","level":6,"lnum":1,"ex":"The rule applies to students and teachers alike.","exja":"そのルールは生徒と教師に同様に適用される。"},{"id":2566,"en":"alike","ja":"同様に\n同じように・等しくという副詞的用法","level":6,"lnum":1},{"id":2567,"en":"allergic","ja":"アレルギーの\n特定の物質に過敏な体質を表す","level":6,"lnum":1,"ex":"She is allergic to peanuts and must avoid them carefully.","exja":"彼女はピーナッツアレルギーがあり、注意して避けなければならない。"},{"id":2568,"en":"allowance","ja":"手当・小遣い\n定期的に支給されるお金や許容量","level":6,"lnum":1,"ex":"He receives a weekly allowance from his parents.","exja":"彼は両親から毎週小遣いをもらっている。"},{"id":2569,"en":"alternative","ja":"代わりの\n別の選択肢となる。「他の」より積極的な響き","level":6,"lnum":1,"ex":"Is there an alternative to using plastic bags?","exja":"ビニール袋を使う代替案はありますか。"},{"id":2570,"en":"alternative","ja":"代替案\n既存のものに代わる別の選択肢","level":6,"lnum":1},{"id":2571,"en":"altogether","ja":"全体で\n合計して・完全に。completelyより強調的","level":6,"lnum":1,"ex":"The project cost altogether more than we expected.","exja":"そのプロジェクトの費用は全体で予想以上にかかった。"},{"id":2572,"en":"amazed","ja":"驚いた\n予想外のことに強く驚いた状態","level":6,"lnum":1,"ex":"I was amazed by the beautiful scenery of the mountains.","exja":"私は山々の美しい景色に驚いた。"},{"id":2573,"en":"ambitious","ja":"野心的な\n高い目標を持ち積極的に追い求める","level":6,"lnum":1,"ex":"She is ambitious and works hard to reach the top.","exja":"彼女は野心的で、トップに立つために懸命に働いている。"},{"id":2574,"en":"amusing","ja":"おもしろい\n軽く笑えて楽しい。funnyより上品な印象","level":6,"lnum":1,"ex":"The clown told amusing stories that made everyone laugh.","exja":"ピエロはみんなを笑わせるおもしろい話をした。"},{"id":2575,"en":"analysis","ja":"分析\n詳しく調べて要素に分けること","level":6,"lnum":1,"ex":"The analysis of the data took several days to complete.","exja":"データの分析を完了するのに数日かかった。"},{"id":2576,"en":"analyze","ja":"分析する\nデータや状況を詳しく調べる","level":6,"lnum":1,"ex":"Scientists analyze water samples to check for pollution.","exja":"科学者たちは汚染を調べるために水のサンプルを分析する。"},{"id":2577,"en":"anger","ja":"怒り\n不満や不正義への強い感情","level":6,"lnum":1,"ex":"She could not hide her anger when she heard the news.","exja":"彼女はそのニュースを聞いたとき、怒りを隠せなかった。"},{"id":2578,"en":"angle","ja":"角度\n2つの線がなす向き・見方・切り口","level":6,"lnum":1,"ex":"The photographer took the shot from an unusual angle.","exja":"写真家は珍しい角度から写真を撮った。"},{"id":2579,"en":"animated","ja":"生き生きした\n活発で元気な様子。アニメの意味も","level":6,"lnum":1,"ex":"The children were animated and excited at the party.","exja":"子供たちはパーティーで生き生きとして興奮していた。"},{"id":2580,"en":"annoyance","ja":"いらだち\n小さなことへの不満やイライラ感","level":6,"lnum":1,"ex":"His constant interruptions were a source of annoyance.","exja":"彼の絶え間ない割り込みはいらだちの原因だった。"},{"id":2581,"en":"annoyed","ja":"イライラした\n不快な出来事への軽い怒り","level":6,"lnum":1,"ex":"She was annoyed when her brother turned off the TV.","exja":"兄がテレビを消したとき、彼女はイライラした。"},{"id":2582,"en":"annual","ja":"年1回の\n毎年行われる・年間の","level":6,"lnum":1,"ex":"The company holds an annual meeting every December.","exja":"その会社は毎年12月に年次会議を開催する。"},{"id":2583,"en":"annually","ja":"毎年\n1年に1度の頻度で","level":6,"lnum":1,"ex":"The festival is held annually in the town square.","exja":"その祭りは毎年、町の広場で開催される。"},{"id":2584,"en":"anti","ja":"反対の\n何かに反対する立場を示す接頭辞的用法","level":6,"lnum":1,"ex":"He joined an anti-war protest in the city center.","exja":"彼は市内中心部で反戦抗議運動に参加した。"},{"id":2585,"en":"antique","ja":"骨董品\n古くて価値のある物品","level":6,"lnum":1,"ex":"She found a beautiful antique clock at the flea market.","exja":"彼女はフリーマーケットで美しい骨董品の時計を見つけた。"},{"id":2586,"en":"antonym","ja":"反意語\n意味が反対の単語。対義語ともいう","level":6,"lnum":1,"ex":"\"Hot\" is the antonym of \"cold.\"","exja":"\"hot\"は\"cold\"の反意語だ。"},{"id":2587,"en":"anxiety","ja":"不安\n将来への漠然とした心配や緊張感","level":6,"lnum":1,"ex":"The exam caused a lot of anxiety among the students.","exja":"その試験は生徒たちの間に多くの不安を引き起こした。"},{"id":2588,"en":"anxiously","ja":"不安そうに\n心配しながら・気がかりな様子で","level":6,"lnum":1,"ex":"He waited anxiously for the results of the medical test.","exja":"彼は医療検査の結果を不安そうに待った。"},{"id":2589,"en":"anyhow","ja":"とにかく\n話を強引にまとめる口語表現","level":6,"lnum":1,"ex":"I don't know all the details, but anyhow, let's get started.","exja":"詳細はすべてわからないが、とにかく始めましょう。"},{"id":2590,"en":"ape","ja":"類人猿\n尾のない大型の霊長類。人間に近い","level":6,"lnum":1,"ex":"The ape swung through the trees with ease.","exja":"類人猿は軽々と木々の間を飛び回った。"},{"id":2591,"en":"apology","ja":"謝罪\n自分の誤りを認めて詫びること","level":6,"lnum":1,"ex":"He offered a sincere apology for his rude behavior.","exja":"彼は自分の失礼な行動に対して誠実な謝罪をした。"},{"id":2592,"en":"apparent","ja":"明らかな\n見た目には明らかだが真実でない可能性も含む","level":6,"lnum":1,"ex":"It was apparent that she had not slept the night before.","exja":"彼女が前夜眠れなかったことは明らかだった。"},{"id":2593,"en":"appeal","ja":"訴え・魅力\n感情に働きかけることや人を引きつける力","level":6,"lnum":1,"ex":"The charity's appeal for donations was very successful.","exja":"その慈善団体の寄付への訴えは大変成功した。"},{"id":2594,"en":"appetite","ja":"食欲\n食べたい欲求。比喩的に何かへの欲求にも","level":6,"lnum":1,"ex":"After the long hike, he had a huge appetite.","exja":"長いハイキングの後、彼はものすごい食欲があった。"},{"id":2595,"en":"applaud","ja":"拍手する\n賞賛や承認の意を手拍子で示す","level":6,"lnum":1,"ex":"The audience stood up to applaud the performers.","exja":"観客はパフォーマーに拍手を送るために立ち上がった。"},{"id":2596,"en":"applause","ja":"拍手\n大勢が行う賞賛の拍手","level":6,"lnum":1,"ex":"The speaker received warm applause at the end of his speech.","exja":"スピーカーはスピーチの終わりに温かい拍手を受けた。"},{"id":2597,"en":"application","ja":"応募・申請\n仕事や制度への申し込み。アプリの意味も","level":6,"lnum":1,"ex":"She submitted her application for the summer internship.","exja":"彼女は夏のインターンシップへの応募書類を提出した。"},{"id":2598,"en":"appoint","ja":"任命する\n役職に人を正式に指定する","level":6,"lnum":1,"ex":"The president appointed a new minister of education.","exja":"大統領は新しい文部大臣を任命した。"},{"id":2599,"en":"appreciation","ja":"感謝・鑑賞\nものの価値を理解しthanksより深い感謝","level":6,"lnum":1,"ex":"She expressed her appreciation for all the help she received.","exja":"彼女は受けたすべての援助に対して感謝を表した。"},{"id":2600,"en":"approval","ja":"承認\n公式に許可・賛成すること","level":6,"lnum":1,"ex":"The plan received approval from the school board.","exja":"その計画は学校委員会の承認を得た。"},{"id":2601,"en":"approve","ja":"承認する\n提案や計画を公式に認める","level":6,"lnum":1,"ex":"The committee approved the new budget for next year.","exja":"委員会は来年の新しい予算を承認した。"},{"id":2602,"en":"approximately","ja":"およそ\n正確ではないがだいたいの数を示す","level":6,"lnum":1,"ex":"The journey takes approximately three hours by train.","exja":"その旅は電車でおよそ3時間かかる。"},{"id":2603,"en":"arise","ja":"生じる\n問題や状況が自然に発生する","level":6,"lnum":1,"ex":"Problems often arise when people do not communicate clearly.","exja":"人々がはっきりとコミュニケーションをとらないと、問題が生じることが多い。"},{"id":2604,"en":"arithmetic","ja":"算数\n基本的な計算・四則演算の学問","level":6,"lnum":1,"ex":"Basic arithmetic skills are essential for everyday life.","exja":"基本的な算数の能力は日常生活に欠かせない。"},{"id":2605,"en":"army","ja":"陸軍\n地上の軍事組織・軍隊全般","level":6,"lnum":1,"ex":"The army was deployed to help with the flood relief.","exja":"陸軍は洪水の救援活動を支援するために派遣された。"},{"id":2606,"en":"arrange","ja":"手配する\n準備・整理・取り決めをする","level":6,"lnum":1,"ex":"She arranged all the books on the shelf by subject.","exja":"彼女は棚の本をすべて科目別に並べた。"},{"id":2607,"en":"arrangement","ja":"手配\n準備や取り決め。音楽の編曲の意味も","level":6,"lnum":1,"ex":"We made arrangements to meet at the café at noon.","exja":"私たちは正午にカフェで会う手配をした。"},{"id":2608,"en":"arrow","ja":"矢印\n方向を示す記号・弓で放つ矢","level":6,"lnum":1,"ex":"The sign has a red arrow pointing to the exit.","exja":"その標識には出口を示す赤い矢印がある。"},{"id":2609,"en":"artistic","ja":"芸術的な\n美的感覚があり創造性に富む","level":6,"lnum":1,"ex":"He is very artistic and loves to paint in his free time.","exja":"彼はとても芸術的で、暇なときに絵を描くことが好きだ。"},{"id":2610,"en":"ashamed","ja":"恥じている\n自分の行動を恥ずかしく思う感情","level":6,"lnum":1,"ex":"She felt ashamed after she realized she had lied.","exja":"嘘をついたと気づいた後、彼女は恥ずかしく思った。"},{"id":2611,"en":"aside","ja":"わきに\n中心から離れた位置に・脇へ","level":6,"lnum":1,"ex":"She set her feelings aside to focus on the task.","exja":"彼女はタスクに集中するために感情を脇に置いた。"},{"id":2612,"en":"aspect","ja":"側面\n物事の一つの面や観点","level":6,"lnum":1,"ex":"We need to consider every aspect of the problem.","exja":"私たちは問題のあらゆる側面を考慮する必要がある。"},{"id":2613,"en":"aspirin","ja":"アスピリン\n解熱・鎮痛に使う一般的な薬","level":6,"lnum":1,"ex":"He took an aspirin to relieve his headache.","exja":"彼は頭痛を和らげるためにアスピリンを飲んだ。"},{"id":2614,"en":"assign","ja":"割り当てる\n仕事や役割を特定の人に与える","level":6,"lnum":1,"ex":"The teacher assigned a research project to each student.","exja":"先生は各生徒に調査プロジェクトを割り当てた。"},{"id":2615,"en":"assignment","ja":"課題\n学校の宿題や与えられた仕事","level":6,"lnum":1,"ex":"She stayed up late to finish her English assignment.","exja":"彼女は英語の課題を終わらせるために夜遅くまで起きていた。"},{"id":2616,"en":"assist","ja":"補助する\n誰かの活動を手伝うやや丁寧な表現","level":6,"lnum":1,"ex":"The nurse assisted the doctor during the operation.","exja":"看護師は手術中に医師を補助した。"},{"id":2617,"en":"assistance","ja":"援助\n助けや支援。helpよりフォーマル","level":6,"lnum":1,"ex":"He asked for assistance in carrying the heavy boxes.","exja":"彼は重い箱を運ぶのに援助を求めた。"},{"id":2618,"en":"associate","ja":"関連させる\n物事や人を結びつけて考える","level":6,"lnum":1,"ex":"People often associate summer with hot weather and holidays.","exja":"人々はよく夏を暑い天気と休日に関連させる。"},{"id":2619,"en":"assume","ja":"仮定する\n証拠なしに〜だと思い込む","level":6,"lnum":1,"ex":"Don't assume everyone knows the answer.","exja":"みんなが答えを知っていると仮定してはいけない。"},{"id":2620,"en":"astronomer","ja":"天文学者\n星や宇宙を研究する科学者","level":6,"lnum":1,"ex":"The astronomer discovered a new star using a telescope.","exja":"天文学者は望遠鏡を使って新しい星を発見した。"},{"id":2621,"en":"athletic","ja":"運動神経のよい\nスポーツが得意で体が引き締まった","level":6,"lnum":1,"ex":"She is very athletic and excels at both swimming and track.","exja":"彼女はとても運動神経がよく、水泳と陸上競技の両方で優秀だ。"},{"id":2622,"en":"Atlantic","ja":"大西洋の\n大西洋に関連する地理的形容詞","level":6,"lnum":1,"ex":"The Atlantic Ocean separates Europe from North America.","exja":"大西洋はヨーロッパと北アメリカを隔てている。"},{"id":2623,"en":"atmosphere","ja":"雰囲気\n場の空気感・地球を囲む大気層","level":6,"lnum":1,"ex":"The atmosphere at the concert was exciting and electric.","exja":"コンサートの雰囲気は興奮に満ちていた。"},{"id":2624,"en":"attachment","ja":"添付・愛着\nメールの添付ファイルや人への強い絆","level":6,"lnum":1,"ex":"She sent the report as an attachment to the email.","exja":"彼女はレポートをメールの添付ファイルとして送った。"},{"id":2625,"en":"attain","ja":"達成する\n長い努力の末に目標に到達する","level":6,"lnum":1,"ex":"With hard work, you can attain any goal you set.","exja":"一生懸命努力すれば、設定したどんな目標でも達成できる。"},{"id":2626,"en":"attempt","ja":"試みる\n成功するかわからないが挑戦してみる","level":6,"lnum":1,"ex":"He made an attempt to climb the mountain but failed.","exja":"彼は山を登ろうと試みたが失敗した。"},{"id":2627,"en":"authority","ja":"権威・当局\n権限を持つ人や機関","level":6,"lnum":1,"ex":"The teacher has the authority to decide class rules.","exja":"先生はクラスのルールを決める権限を持っている。"},{"id":2628,"en":"auxiliary","ja":"補助の\n主なものを助けるサポート役","level":6,"lnum":1,"ex":"\"Do\" is used as an auxiliary verb in questions.","exja":"\"do\"は疑問文で補助動詞として使われる。"},{"id":2629,"en":"avenue","ja":"大通り\n広い並木道や手段・方法の比喩にも","level":6,"lnum":1,"ex":"The parade moved down the main avenue of the city.","exja":"パレードは市の大通りを進んでいった。"},{"id":2630,"en":"aware","ja":"気づいている\n情報や状況を知っている状態","level":6,"lnum":1,"ex":"Are you aware of the dangers of texting while walking?","exja":"歩きながらテキストを送ることの危険性を知っていますか。"},{"id":2631,"en":"awareness","ja":"意識\nある問題や状況への理解と関心","level":6,"lnum":1,"ex":"The campaign helped raise awareness about climate change.","exja":"そのキャンペーンは気候変動への意識を高めるのに役立った。"},{"id":2632,"en":"awkward","ja":"ぎこちない\n不器用・気まずい・扱いにくい状況","level":6,"lnum":1,"ex":"It was an awkward situation when they met unexpectedly.","exja":"彼らが思いがけず出会ったとき、気まずい状況だった。"},{"id":2633,"en":"babysit","ja":"子守りする\n親の代わりに子供の面倒を見る","level":6,"lnum":1,"ex":"She offered to babysit her neighbor's children on Saturday.","exja":"彼女は土曜日に隣人の子供たちの子守りを申し出た。"},{"id":2634,"en":"babysitter","ja":"ベビーシッター\n親の代わりに子供の世話をする人","level":6,"lnum":1,"ex":"They hired a babysitter so they could go out for dinner.","exja":"彼らは夕食に出かけるためにベビーシッターを雇った。"},{"id":2635,"en":"backache","ja":"腰痛・背中痛\n背中や腰の持続的な痛み","level":6,"lnum":1,"ex":"He developed a backache from sitting at his desk all day.","exja":"彼は一日中机に座っていたせいで腰痛になった。"},{"id":2636,"en":"backpacker","ja":"バックパッカー\n大きな荷物を背負って旅する人","level":6,"lnum":1,"ex":"The young backpacker traveled across Europe with a small budget.","exja":"その若いバックパッカーは少ない予算でヨーロッパを旅した。"},{"id":2637,"en":"backpacking","ja":"バックパック旅行\n格安・自由旅行のスタイル","level":6,"lnum":1,"ex":"We went backpacking in the mountains last summer.","exja":"私たちは去年の夏、山へバックパック旅行に行った。"},{"id":2638,"en":"baggage","ja":"手荷物\n旅行時の荷物。luggage同義でやや米国的","level":6,"lnum":1,"ex":"Please place your baggage in the overhead compartment.","exja":"手荷物を頭上の荷物入れに入れてください。"},{"id":2639,"en":"baker","ja":"パン屋\nパンや焼き菓子を作る職人・店","level":6,"lnum":1,"ex":"The baker woke up at four in the morning to make fresh bread.","exja":"パン屋は新鮮なパンを作るために朝の4時に目を覚ました。"},{"id":2640,"en":"bald","ja":"はげた\n頭髪がない状態を指す","level":6,"lnum":1,"ex":"He became bald at a very young age.","exja":"彼はとても若い年齢でハゲになった。"},{"id":2641,"en":"bandage","ja":"包帯\n傷口を覆う布製の医療用品","level":6,"lnum":1,"ex":"The nurse wrapped a bandage around his injured arm.","exja":"看護師は彼の傷ついた腕に包帯を巻いた。"},{"id":2642,"en":"bang","ja":"爆発音\n大きく鋭い衝撃音","level":6,"lnum":1,"ex":"She banged her fist on the table in frustration.","exja":"彼女は腹立たしさでテーブルに拳を強く打ちつけた。"},{"id":2643,"en":"bang","ja":"強く打つ\n物を力強く叩いたりぶつける","level":6,"lnum":1},{"id":2644,"en":"bank account","ja":"銀行口座\n銀行に開設したお金の管理口座","level":6,"lnum":1,"ex":"He opened his first bank account when he turned sixteen.","exja":"彼は16歳になったとき最初の銀行口座を開いた。"},{"id":2645,"en":"bar","ja":"禁止する\n入場や行為を公式に禁じる","level":6,"lnum":1,"ex":"He was barred from entering the building for security reasons.","exja":"彼はセキュリティ上の理由から建物への入場を禁止された。"},{"id":2646,"en":"bare","ja":"むき出しの\n覆われていない状態。比喩的にも使う","level":6,"lnum":1,"ex":"The branches of the tree were bare in winter.","exja":"その木の枝は冬に葉がむき出しになっていた。"},{"id":2647,"en":"barely","ja":"かろうじて\nほとんど〜ない・やっとという少量を表す","level":6,"lnum":1,"ex":"She could barely hear the teacher from the back of the room.","exja":"彼女は部屋の後ろからかろうじて先生の声が聞こえた。"},{"id":2648,"en":"bark","ja":"吠える音・樹皮\n犬の鳴き声または木の外皮","level":6,"lnum":1,"ex":"The dog began to bark loudly when a stranger approached.","exja":"見知らぬ人が近づくと、犬は大きな声で吠え始めた。"},{"id":2649,"en":"barman","ja":"バーテンダー\nバーで酒を提供する男性スタッフ","level":6,"lnum":1,"ex":"The barman quickly served drinks to all the customers.","exja":"バーテンダーは素早く全客に飲み物を提供した。"},{"id":2650,"en":"barrel","ja":"たる\n円筒形の大型容器。石油の単位にも使う","level":6,"lnum":1,"ex":"The winery stored its wine in old wooden barrels.","exja":"そのワイナリーは古い木製のたるにワインを保存していた。"},{"id":2651,"en":"base","ja":"基づかせる\n〜を根拠・拠点とする","level":6,"lnum":1,"ex":"His argument is based on solid scientific evidence.","exja":"彼の議論は確かな科学的証拠に基づいている。"},{"id":2652,"en":"basement","ja":"地下室\n建物の地下にある部屋や階","level":6,"lnum":1,"ex":"They converted the basement into a cozy study room.","exja":"彼らは地下室を居心地の良い勉強部屋に改装した。"},{"id":2653,"en":"basin","ja":"洗面台・盆地\n水を受ける容器や地形的なくぼみ","level":6,"lnum":1,"ex":"She filled the basin with warm water to wash her hands.","exja":"彼女は手を洗うためにぬるま湯で洗面台をいっぱいにした。"},{"id":2654,"en":"basis","ja":"基礎\non a 〜 basisの形でよく使う","level":6,"lnum":1,"ex":"We review our goals on a monthly basis.","exja":"私たちは月1回の基準で目標を見直す。"},{"id":2655,"en":"bathe","ja":"入浴する\n湯につかる。バスに使うやや古風な表現","level":6,"lnum":1,"ex":"After the long walk, she bathed to relax her tired muscles.","exja":"長い散歩の後、彼女は疲れた筋肉をほぐすために入浴した。"},{"id":2656,"en":"battle","ja":"戦闘・戦い\n軍事的な戦い。比喩的に困難への挑戦にも","level":6,"lnum":1,"ex":"The soldiers fought bravely in the long battle.","exja":"兵士たちは長い戦闘で勇敢に戦った。"},{"id":2657,"en":"beard","ja":"あごひげ\n顔の下部に生えるひげ","level":6,"lnum":1,"ex":"He grew a beard during the winter holidays.","exja":"彼は冬休みの間にあごひげを生やした。"},{"id":2658,"en":"beast","ja":"野獣\n大型の動物・残忍な人への比喩にも","level":6,"lnum":1,"ex":"The beast in the story was actually kind and gentle.","exja":"その物語の野獣は実際には親切で穏やかだった。"},{"id":2659,"en":"beaver","ja":"ビーバー\nダムを作ることで知られる動物","level":6,"lnum":1,"ex":"The beaver built a large dam across the river.","exja":"ビーバーは川の対岸に大きなダムを作った。"},{"id":2660,"en":"because of","ja":"〜のために\n原因・理由を示す前置詞句","level":6,"lnum":1,"ex":"The match was cancelled because of the heavy rain.","exja":"大雨のため、試合は中止になった。"},{"id":2661,"en":"bedside","ja":"ベッドサイド\nベッドのすぐそば","level":6,"lnum":1,"ex":"She kept a glass of water on her bedside table every night.","exja":"彼女は毎晩ベッドサイドのテーブルにコップ一杯の水を置いていた。"},{"id":2662,"en":"behalf","ja":"代理\non behalf ofで「〜を代表して」の意味","level":6,"lnum":1,"ex":"The lawyer spoke on behalf of his client in court.","exja":"弁護士は法廷で依頼人の代理として話した。"},{"id":2663,"en":"belief","ja":"信念\n証拠よりも確信に基づく考え","level":6,"lnum":1,"ex":"She had a strong belief in the power of hard work.","exja":"彼女は努力の力への強い信念を持っていた。"},{"id":2664,"en":"beloved","ja":"愛する\n深く愛されている人や物への詩的表現","level":6,"lnum":1,"ex":"He returned to his beloved hometown after many years abroad.","exja":"何年も海外で過ごした後、彼は愛する故郷へ戻った。"},{"id":2665,"en":"beneath","ja":"〜の下に\nunderより文語的・格式ある表現","level":6,"lnum":1,"ex":"The treasure was buried beneath the old oak tree.","exja":"宝はその古いオークの木の下に埋められていた。"},{"id":2666,"en":"benefit","ja":"恩恵\n何かから得られる利益や良い効果","level":6,"lnum":1,"ex":"Regular exercise has many benefits for your health.","exja":"定期的な運動はあなたの健康に多くの恩恵をもたらす。"},{"id":2667,"en":"bent","ja":"曲がった\n形状が曲がっている状態","level":6,"lnum":1,"ex":"The bent nail was difficult to remove from the wall.","exja":"曲がった釘は壁から取り外すのが難しかった。"},{"id":2668,"en":"bet","ja":"賭ける\nI bet〜で「きっと〜だ」の口語表現も","level":6,"lnum":1,"ex":"I bet she will pass the exam with a high score.","exja":"彼女はきっと高得点で試験に合格するよ。"},{"id":2669,"en":"bilingual","ja":"二言語話者の\n2つの言語を流暢に使える","level":6,"lnum":1,"ex":"Growing up in two countries made him fully bilingual.","exja":"2つの国で育ったことが彼を完全な二言語話者にした。"},{"id":2670,"en":"bin","ja":"ごみ箱\n英国で一般的なごみ入れ","level":6,"lnum":1,"ex":"Please throw your trash in the bin by the door.","exja":"ドアの近くのごみ箱にごみを捨ててください。"},{"id":2671,"en":"biochemistry","ja":"生化学\n生物の化学的過程を研究する学問","level":6,"lnum":1,"ex":"She is studying biochemistry at the university.","exja":"彼女は大学で生化学を学んでいる。"},{"id":2672,"en":"biography","ja":"伝記\n実在の人物の人生を描いた書物","level":6,"lnum":1,"ex":"I read an interesting biography of a famous scientist.","exja":"私は有名な科学者の興味深い伝記を読んだ。"},{"id":2673,"en":"biology","ja":"生物学\n生き物の仕組みを研究する学問","level":6,"lnum":1,"ex":"Biology class taught us how plants make their own food.","exja":"生物学の授業で植物がどのように自分の食べ物を作るかを学んだ。"},{"id":2674,"en":"bishop","ja":"司教\nキリスト教の高位聖職者","level":6,"lnum":1,"ex":"The bishop gave a speech at the opening of the new church.","exja":"司教は新しい教会の開会式でスピーチをした。"},{"id":2675,"en":"blame","ja":"責任・非難\n失敗や問題の責任を〜に押し付ける","level":6,"lnum":1,"ex":"Don't blame others for your own mistakes.","exja":"自分の間違いを他人のせいにしてはいけない。"},{"id":2676,"en":"blend","ja":"混ぜ合わせる\n複数のものを滑らかに組み合わせる","level":6,"lnum":1,"ex":"She blended the fruits together to make a smoothie.","exja":"彼女はスムージーを作るために果物を混ぜ合わせた。"},{"id":2677,"en":"bless","ja":"祝福する\n神や人が幸福を願う宗教的な表現","level":6,"lnum":1,"ex":"The priest blessed the food before the meal began.","exja":"食事が始まる前に神父が食べ物を祝福した。"},{"id":2678,"en":"blessing","ja":"恵み\nありがたいもの・神の祝福","level":6,"lnum":1,"ex":"Good health is truly a blessing.","exja":"健康であることは本当に恵みだ。"},{"id":2679,"en":"blogger","ja":"ブロガー\nブログを定期的に書いて発信する人","level":6,"lnum":1,"ex":"The popular blogger shares travel tips every week.","exja":"その人気ブロガーは毎週旅行のヒントを共有している。"},{"id":2680,"en":"blush","ja":"顔を赤らめる\n恥ずかしさや照れで頬が赤くなる","level":6,"lnum":1,"ex":"She began to blush when everyone clapped for her.","exja":"みんなが彼女に拍手したとき、彼女は顔を赤らめ始めた。"},{"id":2681,"en":"boast","ja":"自慢する\n自分の能力や持ち物を誇らしげに話す","level":6,"lnum":1,"ex":"He always boasts about his high grades to his friends.","exja":"彼はいつも友達に自分の高い成績を自慢する。"},{"id":2682,"en":"bold","ja":"大胆な\n恐れずに行動する・太字の意味も","level":6,"lnum":1,"ex":"It takes a bold person to speak in front of a large crowd.","exja":"大勢の人の前で話すには大胆な人間でなければならない。"},{"id":2683,"en":"boldly","ja":"大胆に\n恐れや遠慮なく行動する様子","level":6,"lnum":1,"ex":"She boldly raised her hand to answer the question.","exja":"彼女は大胆に手を挙げて質問に答えた。"},{"id":2684,"en":"bond","ja":"絆\n人や物をつなぐ強い関係","level":6,"lnum":1,"ex":"The shared experience created a strong bond between them.","exja":"共有した体験が彼らの間に強い絆を生み出した。"},{"id":2685,"en":"booking","ja":"予約\nホテルや交通機関の事前予約","level":6,"lnum":1,"ex":"She made a booking at the restaurant for six people.","exja":"彼女はレストランに6人分の予約を入れた。"},{"id":2686,"en":"boom","ja":"急成長\n急激な増加や繁栄。爆発音の意味も","level":6,"lnum":1,"ex":"There was an economic boom after the war ended.","exja":"戦争が終わった後、経済の急成長があった。"},{"id":2687,"en":"bore","ja":"退屈させる\n興味を失わせる・うんざりさせる","level":6,"lnum":1,"ex":"The long lecture began to bore the students.","exja":"長い講義は生徒たちを退屈させ始めた。"},{"id":2688,"en":"boredom","ja":"退屈\n何もすることがない無聊な状態","level":6,"lnum":1,"ex":"He listened to music to escape the boredom of the wait.","exja":"彼は待ち時間の退屈から逃れるために音楽を聴いた。"},{"id":2689,"en":"bother","ja":"面倒・悩ます\n小さな問題や迷惑をかけること","level":6,"lnum":1,"ex":"Sorry to bother you, but could you help me with this?","exja":"お手数をおかけしてすみませんが、これを手伝っていただけますか。"},{"id":2690,"en":"bounce","ja":"跳ね返る\nボールなどが弾む・元気に跳ぶ","level":6,"lnum":1,"ex":"The ball bounced off the wall and hit the door.","exja":"ボールは壁に跳ね返ってドアにぶつかった。"},{"id":2691,"en":"bound","ja":"〜するはず\nbe bound toで「必ず〜する」の意味","level":6,"lnum":1,"ex":"With all that preparation, she is bound to succeed.","exja":"あれだけ準備したのだから、彼女はきっと成功するはずだ。"},{"id":2692,"en":"bow","ja":"お辞儀\n敬意を示して頭を下げる動作","level":6,"lnum":1,"ex":"The performer bowed deeply at the end of the show.","exja":"パフォーマーはショーの終わりに深くお辞儀をした。"},{"id":2693,"en":"bracelet","ja":"ブレスレット\n手首に着ける装飾品","level":6,"lnum":1,"ex":"She wore a silver bracelet that her mother had given her.","exja":"彼女は母からもらったシルバーのブレスレットを身につけていた。"},{"id":2694,"en":"brainstorming","ja":"ブレインストーミング\nアイデアを自由に出し合う会議手法","level":6,"lnum":1,"ex":"The team held a brainstorming session to generate new ideas.","exja":"チームは新しいアイデアを出すためにブレインストーミングのセッションを行った。"},{"id":2695,"en":"branch","ja":"分岐する\n木の枝のように分かれて広がる","level":6,"lnum":1,"ex":"The river branches into two smaller streams here.","exja":"川はここで2つの小さな流れに分岐する。"},{"id":2696,"en":"brand-new","ja":"真新しい\n使ったことがない完全に新品の状態","level":6,"lnum":1,"ex":"He bought a brand-new laptop for the school year.","exja":"彼は新学期のために真新しいノートパソコンを買った。"},{"id":2697,"en":"brass","ja":"真鍮\n金色の金属合金。フォーマルな場面で","level":6,"lnum":1,"ex":"The doorknob was made of polished brass.","exja":"ドアノブは磨かれた真鍮で作られていた。"},{"id":2698,"en":"bravely","ja":"勇敢に\n恐れに打ち勝って行動する様子","level":6,"lnum":1,"ex":"She bravely spoke up about the injustice she had witnessed.","exja":"彼女は目撃した不正義について勇敢に声を上げた。"},{"id":2699,"en":"breakthrough","ja":"突破口\n長年の問題を解決する重大な発見","level":6,"lnum":1,"ex":"Scientists celebrated the breakthrough in cancer research.","exja":"科学者たちはがん研究における突破口を祝った。"},{"id":2700,"en":"breast","ja":"胸・乳房\n体の胸部分。鶏の胸肉にも使う","level":6,"lnum":1,"ex":"The recipe calls for two chicken breasts.","exja":"そのレシピには鶏の胸肉が2枚必要だ。"},{"id":2701,"en":"breathless","ja":"息を切らした\n激しい運動や興奮で呼吸が苦しい状態","level":6,"lnum":1,"ex":"She was breathless after running up the long staircase.","exja":"長い階段を駆け上がった後、彼女は息を切らしていた。"},{"id":2702,"en":"breed","ja":"繁殖させる\n動物を育てて子孫を増やす","level":6,"lnum":1,"ex":"Some farmers breed horses for racing purposes.","exja":"競馬のために馬を繁殖させる農家もいる。"},{"id":2703,"en":"breeding","ja":"飼育・繁殖\n動物の品種改良や繁殖活動","level":6,"lnum":1,"ex":"The zoo has a special program for breeding rare animals.","exja":"その動物園は希少動物を飼育・繁殖させる特別なプログラムを持っている。"},{"id":2704,"en":"brick","ja":"レンガ\n建物を作るための焼き固めた粘土","level":6,"lnum":1,"ex":"The old school building was made entirely of red brick.","exja":"その古い校舎は全体が赤いレンガで作られていた。"},{"id":2705,"en":"brief","ja":"簡潔な\n短く要点を絞った。in briefで「要約すると」","level":6,"lnum":1,"ex":"The principal gave a brief explanation about the new schedule.","exja":"校長は新しいスケジュールについて簡潔な説明をした。"},{"id":2706,"en":"briefly","ja":"手短に\n短時間で要点だけを述べる様子","level":6,"lnum":1,"ex":"She briefly explained the main points of the project.","exja":"彼女はプロジェクトの要点を手短に説明した。"},{"id":2707,"en":"brightly","ja":"明るく\n光や色が鮮やか・表情が生き生きした様子","level":6,"lnum":1,"ex":"The stars shone brightly in the clear night sky.","exja":"澄んだ夜空に星が明るく輝いていた。"},{"id":2708,"en":"broad","ja":"広い\n幅が広い・範囲が大きい","level":6,"lnum":1,"ex":"The road was broad enough for two cars to pass side by side.","exja":"その道路は2台の車が並んで通れるほど広かった。"},{"id":2709,"en":"broadcast","ja":"放送\nテレビやラジオで情報を流すこと","level":6,"lnum":1,"ex":"The game was broadcast live on national television.","exja":"その試合は全国テレビで生放送された。"},{"id":2710,"en":"brotherhood","ja":"兄弟愛・友愛\n深い仲間意識や連帯感","level":6,"lnum":1,"ex":"The soldiers felt a strong sense of brotherhood after the mission.","exja":"兵士たちは任務の後に強い兄弟愛を感じた。"},{"id":2711,"en":"bubble","ja":"泡\n液体や気体の小さな丸い膨らみ","level":6,"lnum":1,"ex":"The child blew bubbles in the park with a small wand.","exja":"子供は公園で小さな棒を使ってシャボン玉を吹いた。"},{"id":2712,"en":"buddy","ja":"友達\n親しい仲間への親しみを込めた呼び方","level":6,"lnum":1,"ex":"He called his best buddy to celebrate his birthday.","exja":"彼は誕生日を祝うために親友に電話した。"},{"id":2713,"en":"builder","ja":"建設業者\n建物を建てる職人や会社","level":6,"lnum":1,"ex":"The builder worked hard to finish the house on time.","exja":"建設業者は家を期日通りに完成させるために懸命に働いた。"},{"id":2714,"en":"bull","ja":"雄牛\n成体の雄のウシ","level":6,"lnum":1,"ex":"The farmer kept a large bull in the field.","exja":"農夫は畑に大きな雄牛を飼っていた。"},{"id":2715,"en":"bullet","ja":"弾丸\n銃から発射される金属の弾","level":6,"lnum":1,"ex":"The police found a bullet near the crime scene.","exja":"警察は犯罪現場の近くで弾丸を発見した。"},{"id":2716,"en":"bulletin","ja":"告示・速報\n短い公式のお知らせや情報","level":6,"lnum":1,"ex":"A bulletin was posted on the school board with the exam results.","exja":"試験の結果が掲示板に告示で貼り出された。"},{"id":2717,"en":"bump","ja":"ぶつかる\n軽くぶつかったり段差を踏む動作","level":6,"lnum":1,"ex":"He bumped his head on the low doorframe.","exja":"彼は低いドア枠に頭をぶつけた。"},{"id":2718,"en":"bunch","ja":"束・グループ\n花や人などが集まったかたまり","level":6,"lnum":1,"ex":"She brought a bunch of roses to the dinner party.","exja":"彼女はディナーパーティーにバラの束を持ってきた。"},{"id":2719,"en":"burden","ja":"負担\n重く感じる義務や責任","level":6,"lnum":1,"ex":"Caring for aging parents can be a heavy burden.","exja":"高齢の両親の世話をすることは重い負担になることがある。"},{"id":2720,"en":"bureau","ja":"局・事務所\n政府の部局や引き出し付き家具","level":6,"lnum":1,"ex":"She went to the employment bureau to look for a job.","exja":"彼女は仕事を探すために職業安定所に行った。"},{"id":2721,"en":"burglar","ja":"空き巣\n建物に不法侵入して盗む泥棒","level":6,"lnum":1,"ex":"The burglar broke into the house through a back window.","exja":"空き巣は裏窓から家に侵入した。"},{"id":2722,"en":"burning","ja":"燃えるような\n強烈な熱や感情を表す比喩的形容詞","level":6,"lnum":1,"ex":"She felt a burning desire to travel around the world.","exja":"彼女は世界中を旅したいという燃えるような欲求を感じた。"},{"id":2723,"en":"burst","ja":"破裂する\n突然勢いよく破れたり飛び出す","level":6,"lnum":1,"ex":"The pipe burst due to the freezing temperatures.","exja":"気温が凍えるほど低かったため、パイプが破裂した。"},{"id":2724,"en":"bust","ja":"壊す\n壊す・破産する口語的な表現","level":6,"lnum":1,"ex":"The old radio was bust, so we threw it away.","exja":"古いラジオが壊れたので、私たちは捨てた。"},{"id":2725,"en":"butcher","ja":"肉屋\n肉を解体・販売する職人や店","level":6,"lnum":1,"ex":"She bought fresh meat from the butcher on the corner.","exja":"彼女は角の肉屋で新鮮な肉を買った。"},{"id":2726,"en":"buyer","ja":"買い手\n商品を購入する人や組織","level":6,"lnum":1,"ex":"The buyer agreed to pay the full price for the car.","exja":"買い手はその車の全額を支払うことに同意した。"},{"id":2727,"en":"cabin","ja":"小屋・船室\n小さな木造の小屋や乗り物の個室","level":6,"lnum":1,"ex":"They spent the weekend in a small wooden cabin in the forest.","exja":"彼らは森の中の小さな木造小屋で週末を過ごした。"},{"id":2728,"en":"calculate","ja":"計算する\n数学的に数値を算出する","level":6,"lnum":1,"ex":"She used a formula to calculate the total cost.","exja":"彼女は公式を使って合計費用を計算した。"},{"id":2729,"en":"calculation","ja":"計算\n数値を算出するプロセスや結果","level":6,"lnum":1,"ex":"A small error in the calculation led to the wrong answer.","exja":"計算の小さな誤りが間違った答えにつながった。"},{"id":2730,"en":"calculator","ja":"電卓\n計算を自動で行う機器","level":6,"lnum":1,"ex":"He used a calculator to solve the math problem quickly.","exja":"彼は電卓を使って数学の問題を素早く解いた。"},{"id":2731,"en":"calf","ja":"子牛・ふくらはぎ\n牛の赤ちゃんまたは脚の後ろの筋肉","level":6,"lnum":1,"ex":"The baby calf stayed close to its mother in the field.","exja":"子牛は畑で母親のそばにいた。"},{"id":2732,"en":"caller","ja":"電話の相手\n電話をかけてきた人","level":6,"lnum":1,"ex":"The caller left a message asking for a callback.","exja":"電話をかけてきた人は折り返し電話を求めるメッセージを残した。"},{"id":2733,"en":"calmness","ja":"落ち着き\n穏やかで動じない精神状態","level":6,"lnum":1,"ex":"Her calmness during the emergency impressed everyone.","exja":"緊急時の彼女の落ち着きはみんなを感心させた。"},{"id":2734,"en":"camel","ja":"ラクダ\n砂漠地帯に生息するこぶのある動物","level":6,"lnum":1,"ex":"The tourists rode a camel through the desert.","exja":"観光客はラクダに乗って砂漠を横断した。"},{"id":2735,"en":"campsite","ja":"キャンプ場\nテントを張って宿泊できる野外施設","level":6,"lnum":1,"ex":"We set up our tent at a quiet campsite near the lake.","exja":"私たちは湖の近くの静かなキャンプ場にテントを張った。"},{"id":2736,"en":"canal","ja":"運河\n船を通すために掘られた人工の水路","level":6,"lnum":1,"ex":"The boat moved slowly through the narrow canal.","exja":"ボートは細い運河をゆっくりと進んだ。"},{"id":2737,"en":"canned","ja":"缶詰の\n缶に密封して保存された食品","level":6,"lnum":1,"ex":"They kept a supply of canned food in case of emergencies.","exja":"彼らは緊急時に備えて缶詰食品を備蓄していた。"},{"id":2738,"en":"canteen","ja":"社員食堂\n学校や職場の食堂・水筒の意味も","level":6,"lnum":1,"ex":"Students lined up at the school canteen during lunch break.","exja":"昼休みに生徒たちは学校食堂に並んだ。"},{"id":2739,"en":"capable","ja":"有能な\n〜できる能力がある。be capable of〜の形で","level":6,"lnum":1,"ex":"She is capable of solving complex problems on her own.","exja":"彼女は自分一人で複雑な問題を解く能力がある。"},{"id":2740,"en":"capacity","ja":"収容力・能力\n最大限に収められる量や能力","level":6,"lnum":1,"ex":"The stadium has a capacity of fifty thousand people.","exja":"そのスタジアムは5万人を収容できる。"},{"id":2741,"en":"capsule","ja":"カプセル\n薬を包む容器・宇宙船のカプセルも","level":6,"lnum":1,"ex":"The astronaut returned to Earth in a small capsule.","exja":"宇宙飛行士は小さなカプセルで地球に帰還した。"},{"id":2742,"en":"capture","ja":"捕獲\n逃げる者を捕まえること","level":6,"lnum":1,"ex":"The photograph captured the beauty of the sunset perfectly.","exja":"その写真は夕日の美しさを完璧に捉えていた。"},{"id":2743,"en":"capture","ja":"捕らえる\n逃げる者や注意・興味を捕まえる","level":6,"lnum":1},{"id":2744,"en":"careless","ja":"不注意な\n注意が足りず失敗しやすい様子","level":6,"lnum":1,"ex":"He made a careless mistake because he was rushing.","exja":"急いでいたので、彼は不注意な間違いを犯した。"},{"id":2745,"en":"carelessly","ja":"不注意に\n軽率で注意を払わない様子","level":6,"lnum":1,"ex":"She carelessly left her umbrella on the train.","exja":"彼女は不注意に電車の中に傘を忘れてしまった。"},{"id":2746,"en":"carelessness","ja":"不注意\n注意不足による失敗や過失","level":6,"lnum":1,"ex":"His carelessness caused the accident in the laboratory.","exja":"彼の不注意が実験室での事故を引き起こした。"},{"id":2747,"en":"carriage","ja":"馬車・車両\n馬に引かれる乗り物や列車の車両","level":6,"lnum":1,"ex":"The royal family arrived in a golden carriage.","exja":"王室は黄金の馬車で到着した。"},{"id":2748,"en":"carton","ja":"カートン\n牛乳などを入れる紙製容器","level":6,"lnum":1,"ex":"He bought a carton of orange juice at the supermarket.","exja":"彼はスーパーマーケットでオレンジジュースのカートンを一本買った。"},{"id":2749,"en":"cashpoint","ja":"ATM\n英国でATMを指す日常的な表現","level":6,"lnum":1,"ex":"She stopped at the cashpoint to withdraw some money.","exja":"彼女はお金を引き出すためにATMに立ち寄った。"},{"id":2750,"en":"casual","ja":"気軽な\n形式ばらないリラックスした場面での","level":6,"lnum":1,"ex":"The office has a casual dress code on Fridays.","exja":"そのオフィスは金曜日に気軽な服装コードがある。"},{"id":2751,"en":"categorize","ja":"分類する\nグループや種類に分けて整理する","level":6,"lnum":1,"ex":"The librarian categorized the books by genre.","exja":"司書は本をジャンルで分類した。"},{"id":2752,"en":"category","ja":"カテゴリー\n共通点でまとめられたグループ","level":6,"lnum":1,"ex":"Which category does this type of music fall into?","exja":"この種の音楽はどのカテゴリーに入りますか。"},{"id":2753,"en":"cattle","ja":"牛（集合）\n農場で飼育される牛の集合名詞","level":6,"lnum":1,"ex":"The farmer raised cattle for both milk and meat.","exja":"農夫は牛乳と肉のために牛を育てた。"},{"id":2754,"en":"caution","ja":"注意\n危険を避けるための慎重な態度","level":6,"lnum":1,"ex":"He crossed the icy road with great caution.","exja":"彼は細心の注意を払って凍った道路を渡った。"},{"id":2755,"en":"cautious","ja":"慎重な\nリスクを避けて注意深く行動する","level":6,"lnum":1,"ex":"She was cautious about sharing personal information online.","exja":"彼女はオンラインで個人情報を共有することに慎重だった。"},{"id":2756,"en":"cave","ja":"洞窟\n岩や山にある自然のくぼみ","level":6,"lnum":1,"ex":"The explorers discovered ancient paintings inside the cave.","exja":"探検家たちは洞窟の中に古代の絵を発見した。"},{"id":2757,"en":"CD-ROM","ja":"CD-ROM\n読み取り専用のコンパクトディスク","level":6,"lnum":1,"ex":"The software came on a CD-ROM back in the 1990s.","exja":"そのソフトウェアは1990年代にCD-ROMで提供されていた。"},{"id":2758,"en":"celebrity","ja":"有名人\n芸能・スポーツ界で名の知れた人","level":6,"lnum":1,"ex":"The celebrity signed autographs for fans outside the hotel.","exja":"その有名人はホテルの外でファンにサインをした。"},{"id":2759,"en":"cell","ja":"細胞・房\n生物の基本単位・刑務所の小部屋","level":6,"lnum":1,"ex":"The biologist observed the cell structure under a microscope.","exja":"生物学者は顕微鏡で細胞の構造を観察した。"},{"id":2760,"en":"central heating","ja":"セントラルヒーティング\n建物全体を暖める集中暖房システム","level":6,"lnum":1,"ex":"The apartment was warm thanks to the central heating system.","exja":"セントラルヒーティングシステムのおかげでアパートは暖かかった。"},{"id":2761,"en":"certainty","ja":"確実性\nまず間違いないという確かな状態","level":6,"lnum":1,"ex":"There is no certainty that the plan will succeed.","exja":"その計画が成功するという確実性はない。"},{"id":2762,"en":"challenging","ja":"やりがいのある\n難しいが取り組む価値がある課題","level":6,"lnum":1,"ex":"Learning a new language can be challenging but rewarding.","exja":"新しい言語を学ぶことはやりがいがあるが大変だ。"},{"id":2763,"en":"channel","ja":"チャンネル\nテレビ局・水路・情報の通り道","level":6,"lnum":1,"ex":"She switched to a different channel to watch the news.","exja":"彼女はニュースを見るために別のチャンネルに切り替えた。"},{"id":2764,"en":"chaos","ja":"混乱\n秩序がまったくない無秩序な状態","level":6,"lnum":1,"ex":"The sudden announcement caused chaos in the crowd.","exja":"突然の発表が群衆の中に混乱を引き起こした。"},{"id":2765,"en":"characteristic","ja":"特徴\nある人や物を他と区別する性質","level":6,"lnum":1,"ex":"Patience is an important characteristic of a good teacher.","exja":"忍耐は良い教師の重要な特徴だ。"},{"id":2766,"en":"characterize","ja":"特徴づける\nある物や人の特徴を説明・定義する","level":6,"lnum":1,"ex":"The novel is characterized by its vivid descriptions of nature.","exja":"その小説は自然の生き生きとした描写が特徴だ。"},{"id":2767,"en":"chariot","ja":"戦車\n古代の馬に引かせる二輪の戦闘用車","level":6,"lnum":1,"ex":"The warrior rode into battle on a swift chariot.","exja":"その戦士は素早い戦車に乗って戦場へと突進した。"},{"id":2768,"en":"charm","ja":"魅力\n人を引きつける自然な魅力","level":6,"lnum":1,"ex":"Her smile had a natural charm that attracted everyone.","exja":"彼女の笑顔は自然な魅力があり、みんなを引きつけた。"},{"id":2769,"en":"chase","ja":"追跡\n逃げる人や物を追いかけること","level":6,"lnum":1,"ex":"The dog chased the ball across the yard.","exja":"犬は庭中でボールを追いかけた。"},{"id":2770,"en":"chat show","ja":"トーク番組\n司会者がゲストと対話する TV番組","level":6,"lnum":1,"ex":"He appeared on a popular chat show to promote his book.","exja":"彼は自分の本を宣伝するために人気のトーク番組に出演した。"},{"id":2771,"en":"check-in counter","ja":"チェックインカウンター\n空港や宿泊施設の受付場所","level":6,"lnum":1,"ex":"We waited in line at the check-in counter for thirty minutes.","exja":"私たちはチェックインカウンターで30分並んだ。"},{"id":2772,"en":"checkout","ja":"チェックアウト\nホテルの退室手続きやレジ","level":6,"lnum":1,"ex":"Please proceed to the checkout after selecting your items.","exja":"商品を選んだ後、チェックアウトに進んでください。"},{"id":2773,"en":"chemist","ja":"薬剤師\n薬を調剤する専門家・英国での薬局も指す","level":6,"lnum":1,"ex":"She went to the chemist to pick up her prescription.","exja":"彼女は処方箋を受け取るために薬局に行った。"},{"id":2774,"en":"chemistry","ja":"化学\n物質の組成や反応を研究する学問","level":6,"lnum":1,"ex":"She found chemistry very interesting after the lab experiment.","exja":"実験室での実験の後、彼女は化学をとても興味深く感じた。"},{"id":2775,"en":"cherish","ja":"大切にする\n人や思い出を深く愛しいつまでも大事にする","level":6,"lnum":1,"ex":"He cherishes the memories of his childhood.","exja":"彼は子供の頃の思い出を大切にしている。"},{"id":2776,"en":"chest of drawers","ja":"たんす\n引き出しが複数ある収納家具","level":6,"lnum":1,"ex":"She organized her clothes neatly in the chest of drawers.","exja":"彼女はたんすに服をきれいに整理した。"},{"id":2777,"en":"chewing gum","ja":"チューインガム\n噛むが飲み込まない柔らかいお菓子","level":6,"lnum":1,"ex":"He chewed chewing gum to stay awake during the long drive.","exja":"彼は長時間のドライブ中に目を覚ましていようとチューインガムを噛んだ。"},{"id":2778,"en":"chief","ja":"主要な\n最も重要な・リーダー的な位置の","level":6,"lnum":1,"ex":"The chief reason for his success was his determination.","exja":"彼の成功の主な理由は彼の決意だった。"},{"id":2779,"en":"choir","ja":"合唱団\n一緒に歌う歌手のグループ","level":6,"lnum":1,"ex":"She sang with the school choir at the annual concert.","exja":"彼女は年1回のコンサートで学校の合唱団と一緒に歌った。"},{"id":2780,"en":"choke","ja":"窒息する\n喉がつまって呼吸できなくなる","level":6,"lnum":1,"ex":"He started to choke on a piece of bread and needed help.","exja":"彼はパンを喉に詰まらせて助けが必要になった。"},{"id":2781,"en":"Christian","ja":"キリスト教の\nキリスト教を信仰する・その教えに関する","level":6,"lnum":1,"ex":"The Christian community gathered to celebrate the holiday.","exja":"キリスト教のコミュニティが祝日を祝うために集まった。"},{"id":2782,"en":"chronological","ja":"年代順の\n時間の流れに沿って並べた順序","level":6,"lnum":1,"ex":"The history book listed events in chronological order.","exja":"その歴史書は出来事を年代順に並べていた。"},{"id":2783,"en":"chuckle","ja":"くすくす笑い\n控えめで静かな笑い声","level":6,"lnum":1,"ex":"She let out a chuckle when she read the funny message.","exja":"面白いメッセージを読んで、彼女はくすくす笑った。"},{"id":2784,"en":"circular","ja":"円形の\n丸い形をした・循環する","level":6,"lnum":1,"ex":"The students sat around a circular table for discussion.","exja":"生徒たちは議論のために円形のテーブルの周りに座った。"},{"id":2785,"en":"circus","ja":"サーカス\n曲芸や動物のショーを行う移動興行","level":6,"lnum":1,"ex":"The children were excited to see the animals at the circus.","exja":"子供たちはサーカスで動物を見て興奮していた。"},{"id":2786,"en":"citizenship","ja":"市民権\nある国の正式な国民としての権利と地位","level":6,"lnum":1,"ex":"She applied for citizenship after living in the country for ten years.","exja":"彼女はその国に10年間住んだ後、市民権を申請した。"},{"id":2787,"en":"civil","ja":"市民の\n市民社会に関する・礼儀正しい","level":6,"lnum":1,"ex":"The two sides held civil discussions despite their differences.","exja":"双方は意見の相違にもかかわらず礼儀正しい議論を行った。"},{"id":2788,"en":"civilization","ja":"文明\n高度に発展した社会・文化の総体","level":6,"lnum":1,"ex":"Ancient Egypt was one of the greatest civilizations in history.","exja":"古代エジプトは歴史上最も偉大な文明の一つだった。"},{"id":2789,"en":"claim","ja":"主張\n証拠の有無にかかわらず事実だと述べること","level":6,"lnum":1,"ex":"He claimed that he had never seen the document before.","exja":"彼はその書類を以前に見たことがないと主張した。"},{"id":2790,"en":"classify","ja":"分類する\n種類や基準に従って整理する","level":6,"lnum":1,"ex":"Scientists classify living things into different groups.","exja":"科学者たちは生き物をさまざまなグループに分類する。"},{"id":2791,"en":"click","ja":"クリック\nマウスやボタンを押す動作・カチッという音","level":6,"lnum":1,"ex":"She clicked on the link to open the website.","exja":"彼女はウェブサイトを開くためにリンクをクリックした。"},{"id":2792,"en":"cliff","ja":"崖\n海や川に面した垂直に切り立った岩場","level":6,"lnum":1,"ex":"We stood at the edge of the cliff and looked at the sea below.","exja":"私たちは崖の端に立って下の海を眺めた。"},{"id":2793,"en":"clip","ja":"クリップ・切り抜き\n物を挟む道具・動画や記事の一部","level":6,"lnum":1,"ex":"She used a clip to hold the papers together.","exja":"彼女は書類をまとめるためにクリップを使った。"},{"id":2794,"en":"closely","ja":"密接に\n近くで・注意深く・密接に関連して","level":6,"lnum":1,"ex":"He studied the map closely before starting the journey.","exja":"旅を始める前に、彼は地図を注意深く調べた。"},{"id":2795,"en":"coal","ja":"石炭\n燃料として使われる黒い化石燃料","level":6,"lnum":1,"ex":"In the past, many homes were heated by coal.","exja":"かつて、多くの家庭は石炭で暖房されていた。"},{"id":2796,"en":"coastal","ja":"沿岸の\n海岸沿いの地域に関する形容詞","level":6,"lnum":1,"ex":"The coastal town attracted many tourists in summer.","exja":"その沿岸の町は夏に多くの観光客を引き寄せた。"},{"id":2797,"en":"cod","ja":"タラ\n北大西洋に多い食用の白身魚","level":6,"lnum":1,"ex":"Fish and chips is often made with cod.","exja":"フィッシュアンドチップスはよくタラで作られる。"},{"id":2798,"en":"coffin","ja":"棺\n遺体を納める箱","level":6,"lnum":1,"ex":"The coffin was carried by six pallbearers.","exja":"棺は6人の棺担ぎ人に運ばれた。"},{"id":2799,"en":"collapse","ja":"崩壊\n建物や健康・制度が突然つぶれる","level":6,"lnum":1,"ex":"The old bridge collapsed after heavy rain and flooding.","exja":"大雨と洪水の後、その古い橋は崩壊した。"},{"id":2800,"en":"collar","ja":"襟・首輪\n服の首まわりや動物の首輪","level":6,"lnum":1,"ex":"The dog wore a bright red collar with its name on it.","exja":"その犬は名前が書かれた明るい赤い首輪をしていた。"},{"id":2801,"en":"columnist","ja":"コラムニスト\n新聞や雑誌に定期的にコラムを書く人","level":6,"lnum":1,"ex":"The columnist wrote about social issues every Sunday.","exja":"そのコラムニストは毎週日曜日に社会問題について書いた。"},{"id":2802,"en":"combination","ja":"組み合わせ\n複数のものを合わせた結果","level":6,"lnum":1,"ex":"A combination of hard work and talent led to her success.","exja":"努力と才能の組み合わせが彼女の成功につながった。"},{"id":2803,"en":"comet","ja":"彗星\n太陽に近づくと尾を引く天体","level":6,"lnum":1,"ex":"The comet was visible in the night sky for several weeks.","exja":"その彗星は数週間にわたり夜空で見えた。"},{"id":2804,"en":"comfort","ja":"慰め・快適さ\n不安を和らげる安心感や居心地の良さ","level":6,"lnum":1,"ex":"A warm cup of tea can bring a lot of comfort on a cold day.","exja":"寒い日には温かいお茶が多くの慰めをもたらしてくれる。"},{"id":2805,"en":"comma","ja":"コンマ\n文の中で使う「、」の句読点","level":6,"lnum":1,"ex":"He forgot to put a comma between the two clauses.","exja":"彼は2つの節の間にコンマを入れるのを忘れた。"},{"id":2806,"en":"command","ja":"命令\n権威をもって従わせる指示","level":6,"lnum":1,"ex":"The general issued a command to advance toward the city.","exja":"将軍は市に向けて前進するよう命令を出した。"},{"id":2807,"en":"commercial","ja":"商業的な\n利益を目的とした・広告用の","level":6,"lnum":1,"ex":"The commercial played on TV several times a day.","exja":"そのCMは一日に何度もテレビで流れた。"},{"id":2808,"en":"commit","ja":"コミットする\n犯罪を犯す・約束に従い尽くす","level":6,"lnum":1,"ex":"He committed himself fully to improving his English skills.","exja":"彼は英語のスキルを向上させることに完全にコミットした。"},{"id":2809,"en":"common sense","ja":"常識\n一般的な判断力・社会通念","level":6,"lnum":1,"ex":"Use your common sense and dress appropriately for the weather.","exja":"常識を使って、天候に合った服装をしてください。"},{"id":2810,"en":"commonly","ja":"一般的に\n広く普通に行われている様子","level":6,"lnum":1,"ex":"This word is commonly used in everyday conversation.","exja":"この単語は日常会話でよく使われる。"},{"id":2811,"en":"companion","ja":"仲間\n一緒に行動する親しい友人や同伴者","level":6,"lnum":1,"ex":"A dog is often called a loyal companion.","exja":"犬はよく忠実な仲間と呼ばれる。"},{"id":2812,"en":"comparison","ja":"比較\n2つ以上のものを比べること","level":6,"lnum":1,"ex":"In comparison to last year, sales have improved greatly.","exja":"昨年と比較して、売上は大幅に改善した。"},{"id":2813,"en":"compete","ja":"競争する\n他者と優劣を争う","level":6,"lnum":1,"ex":"Athletes from around the world compete at the Olympics.","exja":"世界中のアスリートがオリンピックで競争する。"},{"id":2814,"en":"competitive","ja":"競争心が強い\n勝ちたい意欲が高い・競争の激しい","level":6,"lnum":1,"ex":"The market is very competitive, so businesses must innovate.","exja":"市場は非常に競争が激しいため、企業は革新しなければならない。"},{"id":2815,"en":"competitor","ja":"競争相手\n同じ目標を争う相手や企業","level":6,"lnum":1,"ex":"Our main competitor launched a new product last month.","exja":"私たちの主な競争相手が先月新製品を発売した。"},{"id":2816,"en":"complement","ja":"補完するもの\n不足を補い完全にするもの","level":6,"lnum":1,"ex":"The red wine complemented the steak perfectly.","exja":"赤ワインはステーキを完璧に補完した。"},{"id":2817,"en":"complete","ja":"完成させる\nすべてを終わらせて仕上げる","level":6,"lnum":1,"ex":"She worked all night to complete the assignment.","exja":"彼女は課題を完成させるために一晩中働いた。"},{"id":2818,"en":"completely","ja":"完全に\n例外なくすべて・まったく","level":6,"lnum":1,"ex":"I completely forgot about the meeting this morning.","exja":"今朝の会議のことを完全に忘れていた。"},{"id":2819,"en":"complex","ja":"複雑な\n多くの要素が絡み合っている状態","level":6,"lnum":1,"ex":"The relationship between the two characters is quite complex.","exja":"2人の登場人物の関係はかなり複雑だ。"},{"id":2820,"en":"complicate","ja":"複雑にする\n物事をわかりにくく難しくする","level":6,"lnum":1,"ex":"Adding too many rules will only complicate the situation.","exja":"ルールを増やしすぎると状況が複雑になるだけだ。"},{"id":2821,"en":"complicated","ja":"複雑な\n理解や解決が難しい状態","level":6,"lnum":1,"ex":"The instructions were too complicated for beginners to follow.","exja":"その説明書は初心者には複雑すぎてついていけなかった。"},{"id":2822,"en":"compliment","ja":"ほめ言葉\n相手を気持ちよくさせる賞賛の言葉","level":6,"lnum":1,"ex":"He paid her a compliment on her excellent presentation.","exja":"彼は彼女の素晴らしいプレゼンテーションをほめた。"},{"id":2823,"en":"compose","ja":"作曲する\n音楽を創作する・構成する","level":6,"lnum":1,"ex":"She composed a beautiful song for her mother's birthday.","exja":"彼女は母の誕生日のために美しい歌を作曲した。"},{"id":2824,"en":"composition","ja":"作文・構成\n文章や音楽の作品・組み立ての方法","level":6,"lnum":1,"ex":"The teacher asked students to write a composition about their dreams.","exja":"先生は生徒に夢についての作文を書くよう求めた。"},{"id":2825,"en":"compound","ja":"複合語・化合物\n複数の要素が合わさったもの","level":6,"lnum":1,"ex":"\"Sunflower\" is a compound word made of two parts.","exja":"「sunflower」は2つの部分からなる複合語だ。"},{"id":2826,"en":"compromise","ja":"妥協\n双方が少し譲り合って合意する","level":6,"lnum":1,"ex":"They reached a compromise after a long discussion.","exja":"長い議論の末、彼らは妥協点に達した。"},{"id":2827,"en":"concentration","ja":"集中\n一点に注意や力を向けること","level":6,"lnum":1,"ex":"Good concentration is necessary when studying for exams.","exja":"試験勉強をするときには良い集中力が必要だ。"},{"id":2828,"en":"concept","ja":"概念\n抽象的なアイデアや考え方","level":6,"lnum":1,"ex":"The concept of fairness is important in democratic societies.","exja":"公平性という概念は民主主義社会において重要だ。"},{"id":2829,"en":"concerned","ja":"心配している\n〜について気にかけている状態","level":6,"lnum":1,"ex":"She was concerned about her friend's health.","exja":"彼女は友人の健康を心配していた。"},{"id":2830,"en":"conclude","ja":"結論づける\n考察の末に最終判断を下す","level":6,"lnum":1,"ex":"After reviewing the evidence, the judge concluded he was guilty.","exja":"証拠を検討した後、裁判官は彼が有罪だと結論づけた。"},{"id":2831,"en":"conduct","ja":"行動・指揮\nフォーマルな場での行動様式・楽団の指揮","level":6,"lnum":1,"ex":"The scientist conducted an experiment to test the hypothesis.","exja":"科学者は仮説を検証するために実験を実施した。"},{"id":2832,"en":"confirm","ja":"確認する\n事実や予定を改めて確かめる","level":6,"lnum":1,"ex":"Can you confirm the time of the appointment?","exja":"予約の時間を確認していただけますか。"},{"id":2833,"en":"confirmation","ja":"確認\n内容が正しいことを確かめる手続き","level":6,"lnum":1,"ex":"She received a confirmation email after booking the flight.","exja":"フライトを予約した後、彼女は確認メールを受け取った。"},{"id":2834,"en":"conflict","ja":"衝突\n意見・利害・武力の対立","level":6,"lnum":1,"ex":"The conflict between the two groups lasted for many years.","exja":"2つのグループ間の対立は何年も続いた。"},{"id":2835,"en":"confusing","ja":"混乱させる\n理解しにくく頭がこんがらがる","level":6,"lnum":1,"ex":"The directions on the map were confusing and hard to follow.","exja":"地図の道順は分かりにくくて、ついていくのが難しかった。"},{"id":2836,"en":"confusion","ja":"混乱\n何が何だかわからない状態","level":6,"lnum":1,"ex":"There was confusion in the crowd when the alarm went off.","exja":"アラームが鳴ったとき、群衆の中に混乱が起きた。"},{"id":2837,"en":"congratulate","ja":"祝福する\n成功や喜びの出来事を祝う","level":6,"lnum":1,"ex":"Everyone gathered to congratulate her on her promotion.","exja":"みんなが彼女の昇進を祝うために集まった。"},{"id":2838,"en":"conquer","ja":"征服する\n困難や敵を制して支配する","level":6,"lnum":1,"ex":"The climbers conquered the mountain after weeks of effort.","exja":"登山者たちは何週間もの努力の末に山を征服した。"},{"id":2839,"en":"conscious","ja":"意識している\n自分の状態や周囲を認識している","level":6,"lnum":1,"ex":"She was conscious of the need to speak more clearly.","exja":"彼女はもっとはっきり話す必要性を意識していた。"},{"id":2840,"en":"consequently","ja":"その結果\n原因の後に来る結論を示す接続副詞","level":6,"lnum":1,"ex":"He stayed up too late; consequently, he was tired all day.","exja":"彼は夜更かしをした。その結果、一日中疲れていた。"},{"id":2841,"en":"conservation","ja":"保全\n自然や文化財を守ること","level":6,"lnum":1,"ex":"The conservation of wildlife is an important global issue.","exja":"野生動物の保全は重要な世界的問題だ。"},{"id":2842,"en":"conservative","ja":"保守的な\n変化を好まず伝統を重視する","level":6,"lnum":1,"ex":"He has a conservative view on how money should be spent.","exja":"彼はお金の使い方について保守的な考えを持っている。"},{"id":2843,"en":"considerable","ja":"かなりの\n無視できないほど十分な量や程度","level":6,"lnum":1,"ex":"She made a considerable effort to improve her grades.","exja":"彼女は成績を上げるためにかなりの努力をした。"},{"id":2844,"en":"consideration","ja":"考慮\n決定の前に注意深く思い巡らすこと","level":6,"lnum":1,"ex":"Please give careful consideration to all the options before deciding.","exja":"決める前にすべての選択肢を慎重に考慮してください。"},{"id":2845,"en":"consonant","ja":"子音\n母音以外の音・文法用語","level":6,"lnum":1,"ex":"The letter \"b\" is a consonant in the English alphabet.","exja":"文字「b」は英語のアルファベットの子音だ。"},{"id":2846,"en":"constantly","ja":"絶えず\n途切れることなく続いている様子","level":6,"lnum":1,"ex":"She constantly checks her phone for new messages.","exja":"彼女は新しいメッセージを確認するために絶えずスマホを見る。"},{"id":2847,"en":"constitute","ja":"構成する\n全体の一部をなす・〜と見なされる","level":6,"lnum":1,"ex":"Hard work and creativity constitute the key to success.","exja":"努力と創造性が成功への鍵を構成している。"},{"id":2848,"en":"constitution","ja":"憲法・体質\n国の基本法・体や体質の意味も","level":6,"lnum":1,"ex":"The constitution guarantees the rights of every citizen.","exja":"憲法はすべての市民の権利を保障している。"},{"id":2849,"en":"construct","ja":"建設する\n設計に基づいて建物や文を組み立てる","level":6,"lnum":1,"ex":"Workers are constructing a new bridge over the river.","exja":"作業員たちは川の上に新しい橋を建設している。"},{"id":2850,"en":"construction","ja":"建設\n建物や構造物を作る工事や過程","level":6,"lnum":1,"ex":"The construction of the new school will be completed next year.","exja":"新しい学校の建設は来年完成する予定だ。"},{"id":2851,"en":"consume","ja":"消費する\n食べ物やエネルギーを使いつくす","level":6,"lnum":1,"ex":"Cars consume a lot of fuel on long highway trips.","exja":"車は長い高速道路の旅で多くの燃料を消費する。"},{"id":2852,"en":"consumer","ja":"消費者\n商品やサービスを購入・使用する人","level":6,"lnum":1,"ex":"The new product was designed with the consumer in mind.","exja":"その新製品は消費者を念頭に置いて設計された。"},{"id":2853,"en":"consumption","ja":"消費量\n使われるエネルギーや物の総量","level":6,"lnum":1,"ex":"Reducing energy consumption can help protect the environment.","exja":"エネルギー消費量を減らすことは環境保護に役立つ。"},{"id":2854,"en":"continual","ja":"断続的な\n止まっては繰り返す。continuousと区別","level":6,"lnum":1,"ex":"The continual noise from the road made it hard to sleep.","exja":"道路からの断続的な騒音で眠るのが難しかった。"},{"id":2855,"en":"continually","ja":"断続的に\nしばしば繰り返して止まらない様子","level":6,"lnum":1,"ex":"She continually reminded her students about the deadline.","exja":"彼女は締め切りについて繰り返し生徒に注意した。"},{"id":2856,"en":"continuous","ja":"継続的な\n途切れずずっと続いている状態","level":6,"lnum":1,"ex":"The continuous rain lasted for three days.","exja":"継続的な雨が3日間続いた。"},{"id":2857,"en":"continuously","ja":"ずっと続けて\n中断なく絶え間なく続く様子","level":6,"lnum":1,"ex":"The machine ran continuously for twenty-four hours.","exja":"機械は24時間ずっと続けて動き続けた。"},{"id":2858,"en":"contrary","ja":"反対の\non the contraryで「それどころか」の意味","level":6,"lnum":1,"ex":"On the contrary, she thought the movie was excellent.","exja":"それどころか、彼女は映画が素晴らしいと思った。"},{"id":2859,"en":"contribute","ja":"貢献する\n何かのために力や物を提供する","level":6,"lnum":1,"ex":"Everyone was encouraged to contribute ideas to the project.","exja":"みんながプロジェクトにアイデアを貢献するよう奨励された。"},{"id":2860,"en":"contribution","ja":"貢献\n目標や成果への積極的な働きかけ","level":6,"lnum":1,"ex":"His contribution to the team's success was significant.","exja":"チームの成功への彼の貢献は非常に大きかった。"},{"id":2861,"en":"controversial","ja":"賛否両論の\n意見が分かれて議論を呼ぶ話題","level":6,"lnum":1,"ex":"The new policy was controversial and sparked many debates.","exja":"その新しい方針は賛否両論を呼び、多くの議論を引き起こした。"},{"id":2862,"en":"convey","ja":"伝える\n情報や感情を他者に届ける","level":6,"lnum":1,"ex":"He could not convey his feelings in words.","exja":"彼は言葉で自分の気持ちを伝えることができなかった。"},{"id":2863,"en":"convince","ja":"納得させる\n証拠や議論で相手を信じ込ませる","level":6,"lnum":1,"ex":"She managed to convince her parents to let her study abroad.","exja":"彼女はなんとか親を説得して留学を許可してもらった。"},{"id":2864,"en":"copyright","ja":"著作権\n作品の作者が持つ独占的な権利","level":6,"lnum":1,"ex":"The author holds the copyright to all her published works.","exja":"著者はすべての出版作品の著作権を持っている。"},{"id":2865,"en":"correction","ja":"修正\n誤りを正しい状態に直すこと","level":6,"lnum":1,"ex":"The teacher made several corrections on my essay.","exja":"先生は私のエッセイにいくつかの修正を入れた。"},{"id":2866,"en":"council","ja":"議会・評議会\n地域や組織の決定機関","level":6,"lnum":1,"ex":"The city council voted to build a new public library.","exja":"市議会は新しい公共図書館を建設することに投票した。"},{"id":2867,"en":"counseling","ja":"カウンセリング\n専門家が悩みを聞いて助言する支援","level":6,"lnum":1,"ex":"She received counseling to help her deal with stress.","exja":"彼女はストレスに対処するためにカウンセリングを受けた。"},{"id":2868,"en":"counter","ja":"反論する\n相手の主張に対抗する意見を述べる","level":6,"lnum":1,"ex":"The lawyer countered every argument made by the prosecution.","exja":"弁護士は検察側のすべての主張に反論した。"},{"id":2869,"en":"countless","ja":"無数の\n多すぎて数えられないほどの","level":6,"lnum":1,"ex":"She received countless messages of support after the accident.","exja":"事故の後、彼女は無数の支援メッセージを受け取った。"},{"id":2870,"en":"county","ja":"郡・州\n国の行政区域の単位","level":6,"lnum":1,"ex":"The county held a festival to celebrate local culture.","exja":"その郡は地域文化を祝うためにフェスティバルを開催した。"},{"id":2871,"en":"courageous","ja":"勇気ある\n危険に直面しても恐れずに行動する","level":6,"lnum":1,"ex":"It was courageous of him to speak the truth despite the pressure.","exja":"プレッシャーにもかかわらず真実を話した彼は勇気があった。"},{"id":2872,"en":"courgette","ja":"ズッキーニ\n英国英語でのズッキーニの呼び方","level":6,"lnum":1,"ex":"She added sliced courgette to the stir-fry for extra nutrition.","exja":"彼女は栄養を加えるために炒め物に薄切りのズッキーニを加えた。"},{"id":2873,"en":"creator","ja":"創造者\n何かを作り出した人や存在","level":6,"lnum":1,"ex":"The creator of the app won a prize for innovation.","exja":"そのアプリの創造者は革新性で賞を受賞した。"},{"id":2874,"en":"criminal","ja":"犯罪者\n法律を破った人・犯罪に関係する","level":6,"lnum":1,"ex":"The criminal was arrested after a week-long investigation.","exja":"犯罪者は1週間にわたる捜査の末に逮捕された。"},{"id":2875,"en":"crisis","ja":"危機\n深刻な問題が起きた緊急の局面","level":6,"lnum":1,"ex":"The government had to act quickly during the economic crisis.","exja":"政府は経済危機の際に素早く行動しなければならなかった。"},{"id":2876,"en":"critic","ja":"批評家\n作品や行動を評価・批判する専門家","level":6,"lnum":1,"ex":"The film critic gave the movie a very positive review.","exja":"映画批評家はその映画に非常に肯定的なレビューを与えた。"},{"id":2877,"en":"critical","ja":"重大な\n非常に重要な・批判的な両方の意味","level":6,"lnum":1,"ex":"It is critical that we arrive at the airport on time.","exja":"私たちが時間通りに空港に到着することは非常に重要だ。"},{"id":2878,"en":"crop","ja":"作物\n農業で育てて収穫する植物","level":6,"lnum":1,"ex":"The farmers harvested their crops before the rain came.","exja":"農夫たちは雨が来る前に作物を収穫した。"},{"id":2879,"en":"crossroads","ja":"交差点\n道が交わる地点・人生の分岐点の比喩","level":6,"lnum":1,"ex":"The town developed quickly after a highway was built at the crossroads.","exja":"交差点に高速道路が建設された後、その町は急速に発展した。"},{"id":2880,"en":"crow","ja":"カラス\n黒くて賢い大型の鳥","level":6,"lnum":1,"ex":"A crow sat on the fence and watched the children play.","exja":"カラスがフェンスの上に座って子供たちが遊ぶのを見ていた。"},{"id":2881,"en":"cruel","ja":"残酷な\n他者の痛みを気にせず傷つける","level":6,"lnum":1,"ex":"It is cruel to leave animals outside in freezing weather.","exja":"凍えるような寒さの中で動物を外に置いておくのは残酷だ。"},{"id":2882,"en":"crush","ja":"押しつぶす\n力を加えて形が変わるほど押し潰す","level":6,"lnum":1,"ex":"The heavy machine crushed the empty cans in seconds.","exja":"重い機械は数秒で空き缶を押しつぶした。"},{"id":2883,"en":"cultivate","ja":"耕す・育む\n土地を耕す・関係や能力を育てる","level":6,"lnum":1,"ex":"She worked hard to cultivate good study habits.","exja":"彼女は良い勉強習慣を育むために一生懸命努力した。"},{"id":2884,"en":"cure","ja":"治療法\n病気を完全に治す方法や薬","level":6,"lnum":1,"ex":"Scientists are still searching for a cure for the disease.","exja":"科学者たちはその病気の治療法をまだ探している。"},{"id":2885,"en":"curiosity","ja":"好奇心\n知りたいという強い関心","level":6,"lnum":1,"ex":"Her curiosity about science led her to become a researcher.","exja":"科学への彼女の好奇心が彼女を研究者へと導いた。"},{"id":2886,"en":"curiously","ja":"好奇心旺盛に\n不思議そうに・興味津々で","level":6,"lnum":1,"ex":"The cat curiously sniffed the unfamiliar bag.","exja":"猫は見慣れないバッグを好奇心旺盛に嗅いだ。"},{"id":2887,"en":"curly","ja":"巻き毛の\nくるくると波打った髪の状態","level":6,"lnum":1,"ex":"She has beautiful curly hair that she inherited from her mother.","exja":"彼女は母から受け継いだ美しい巻き毛を持っている。"},{"id":2888,"en":"currency","ja":"通貨\n国で使われるお金の種類","level":6,"lnum":1,"ex":"When traveling abroad, you need to exchange currency.","exja":"海外旅行をするときは通貨を交換する必要がある。"},{"id":2889,"en":"current","ja":"現在の\n今この瞬間に起きている・進行中の","level":6,"lnum":1,"ex":"She keeps up with current events by reading the news daily.","exja":"彼女は毎日ニュースを読んで現在の出来事に追いついている。"},{"id":2890,"en":"currently","ja":"現在\n今現在この時点で","level":6,"lnum":1,"ex":"The restaurant is currently closed for renovation.","exja":"そのレストランは現在改装のため閉店している。"},{"id":2891,"en":"curriculum","ja":"カリキュラム\n学校での学習の計画や内容の全体","level":6,"lnum":1,"ex":"The school updated its curriculum to include more science classes.","exja":"学校はより多くの理科の授業を含めるようにカリキュラムを更新した。"},{"id":2892,"en":"curve","ja":"曲線\nなめらかに曲がった線や形","level":6,"lnum":1,"ex":"The road makes a sharp curve near the mountain.","exja":"道路は山の近くで急カーブを描く。"},{"id":2893,"en":"customs","ja":"税関\n入出国時の荷物検査を行う機関","level":6,"lnum":1,"ex":"We had to go through customs before entering the country.","exja":"私たちはその国に入国する前に税関を通らなければならなかった。"},{"id":2894,"en":"CV","ja":"履歴書\n職歴・学歴をまとめた書類（英国式）","level":6,"lnum":1,"ex":"She updated her CV before applying for the new job.","exja":"彼女は新しい仕事に応募する前に履歴書を更新した。"},{"id":2895,"en":"cycle","ja":"周期・自転車\n繰り返すサイクルや自転車","level":6,"lnum":1,"ex":"He cycles to school every day to stay fit.","exja":"彼は体型を維持するために毎日自転車で学校に通う。"},{"id":2896,"en":"cycle","ja":"自転車で走る\n自転車に乗って移動する","level":6,"lnum":1},{"id":2897,"en":"daisy","ja":"デイジー\n白い花びらと黄色い中心のかわいい花","level":6,"lnum":1,"ex":"She picked a daisy from the garden and put it in a vase.","exja":"彼女は庭からデイジーを摘んで花瓶に入れた。"},{"id":2898,"en":"damaged","ja":"損傷した\n物が傷ついて機能が低下した状態","level":6,"lnum":1,"ex":"The storm left several buildings severely damaged.","exja":"嵐はいくつかの建物を激しく損傷させた。"},{"id":2899,"en":"damp","ja":"湿った\n完全に濡れてはいないが湿り気がある","level":6,"lnum":1,"ex":"The towel was still damp after being left overnight.","exja":"そのタオルは一晩置いておいても、まだ湿っていた。"},{"id":2900,"en":"dangerously","ja":"危険なほど\n安全の限界に近いほど危ない様子","level":6,"lnum":1,"ex":"The car was driving dangerously close to the edge of the road.","exja":"車は道路の端に危険なほど近いところを走っていた。"},{"id":2901,"en":"dare","ja":"あえて〜する\n勇気や厚かましさが必要な行動をする","level":6,"lnum":1,"ex":"He dared to challenge the popular opinion.","exja":"彼はあえて多数意見に異議を唱えた。"},{"id":2902,"en":"dating","ja":"交際\n恋人候補と会ってお互いを知るプロセス","level":6,"lnum":1,"ex":"They started dating after meeting at a school event.","exja":"彼らは学校のイベントで出会った後、交際を始めた。"},{"id":2903,"en":"daze","ja":"ぼうっとした状態\n衝撃や疲れで頭がはっきりしない状態","level":6,"lnum":1,"ex":"She was in a daze after hearing the unexpected news.","exja":"予期しないニュースを聞いた後、彼女はぼうっとした状態だった。"},{"id":2904,"en":"dazzle","ja":"まばゆさ\n光や能力が目をくらませるほど輝かしい","level":6,"lnum":1,"ex":"The magician's performance dazzled the audience.","exja":"マジシャンのパフォーマンスは観客をまばゆいほど輝かせた。"},{"id":2905,"en":"deadline","ja":"締め切り\n作業や提出の最終期限","level":6,"lnum":1,"ex":"Please make sure to submit your report before the deadline.","exja":"締め切り前に報告書を提出するようにしてください。"},{"id":2906,"en":"deadly","ja":"致命的な\n死をもたらすほど危険な","level":6,"lnum":1,"ex":"The snake's venom is deadly if not treated immediately.","exja":"そのヘビの毒は即座に治療しなければ致命的だ。"},{"id":2907,"en":"deaf","ja":"耳の不自由な\n聴覚が失われている状態","level":6,"lnum":1,"ex":"She learned sign language to communicate with her deaf friend.","exja":"彼女は耳の不自由な友人とコミュニケーションをとるために手話を学んだ。"},{"id":2908,"en":"dealer","ja":"販売業者\n商品や車などを売買する人","level":6,"lnum":1,"ex":"He bought his car from a reliable local dealer.","exja":"彼は信頼できる地元の販売業者から車を買った。"},{"id":2909,"en":"debris","ja":"残骸\n壊れた建物などの散らばった破片","level":6,"lnum":1,"ex":"The rescue team searched through the debris for survivors.","exja":"救助チームは生存者を探して残骸の中を捜索した。"},{"id":2910,"en":"debt","ja":"借金\n返済義務のある借り入れ","level":6,"lnum":1,"ex":"She worked two jobs to pay off her student debt.","exja":"彼女は学生ローンの借金を返済するために2つの仕事をした。"},{"id":2911,"en":"declaration","ja":"宣言\n公式に意思や事実を表明すること","level":6,"lnum":1,"ex":"The declaration of independence was signed in 1776.","exja":"独立宣言は1776年に署名された。"},{"id":2912,"en":"declare","ja":"宣言する\n正式に意見や事実を公に述べる","level":6,"lnum":1,"ex":"The athlete declared that she would retire after the season.","exja":"そのアスリートはシーズン後に引退すると宣言した。"},{"id":2913,"en":"decline","ja":"減少・断り\n数が減ること・申し出を断ること","level":6,"lnum":1,"ex":"The number of students studying abroad has declined in recent years.","exja":"近年、留学する学生の数が減少している。"},{"id":2914,"en":"dedicate","ja":"捧げる\n時間や努力を特定の目的に集中させる","level":6,"lnum":1,"ex":"She dedicated years of her life to helping children in need.","exja":"彼女は困っている子供たちを助けることに人生の何年かを捧げた。"},{"id":2915,"en":"deed","ja":"行為\n実際に行った（善悪の）行動","level":6,"lnum":1,"ex":"His kind deed helped many families in the community.","exja":"彼の親切な行為はコミュニティの多くの家族を助けた。"},{"id":2916,"en":"defeat","ja":"打ち負かす\n競争や戦いで相手に勝つ","level":6,"lnum":1,"ex":"The underdog team defeated the champion in the final match.","exja":"格下のチームは決勝戦でチャンピオンを打ち負かした。"},{"id":2917,"en":"defend","ja":"守る\n攻撃や批判から保護する","level":6,"lnum":1,"ex":"A lawyer's job is to defend their client in court.","exja":"弁護士の仕事は法廷で依頼人を守ることだ。"},{"id":2918,"en":"defender","ja":"守備者\n攻撃から守る人・サッカーのDF","level":6,"lnum":1,"ex":"The defender blocked the shot just before it reached the goal.","exja":"守備者はゴールに届く直前にシュートをブロックした。"},{"id":2919,"en":"defense","ja":"防御\n攻撃や批判に対して守ること","level":6,"lnum":1,"ex":"The country spent a large amount on national defense.","exja":"その国は国家防衛に多額の費用を費やした。"},{"id":2920,"en":"deficiency","ja":"欠乏\n必要な量が不足している状態","level":6,"lnum":1,"ex":"A deficiency in vitamin D can affect bone health.","exja":"ビタミンDの欠乏は骨の健康に影響を与えることがある。"},{"id":2921,"en":"define","ja":"定義する\n言葉や概念の意味を正確に説明する","level":6,"lnum":1,"ex":"Can you define the word \"democracy\" in your own words?","exja":"「民主主義」という言葉を自分の言葉で定義できますか。"},{"id":2922,"en":"definite","ja":"明確な\n疑いの余地がなくはっきりした","level":6,"lnum":1,"ex":"There is no definite answer to this philosophical question.","exja":"この哲学的な問いには明確な答えがない。"},{"id":2923,"en":"definite article","ja":"定冠詞\n英語のtheのこと","level":6,"lnum":1,"ex":"\"The\" is the only definite article in English.","exja":"\"the\"は英語で唯一の定冠詞だ。"},{"id":2924,"en":"definitely","ja":"絶対に\nまず間違いなく・強い確信を表す","level":6,"lnum":1,"ex":"I will definitely attend the meeting tomorrow morning.","exja":"明日の朝の会議には絶対に出席します。"},{"id":2925,"en":"definition","ja":"定義\n言葉や概念の正確な意味の説明","level":6,"lnum":1,"ex":"Look up the definition of the word in the dictionary.","exja":"辞書でその単語の定義を調べなさい。"},{"id":2926,"en":"delay","ja":"遅らせる\n予定より後の時間に先送りする","level":6,"lnum":1,"ex":"The flight was delayed by two hours due to bad weather.","exja":"悪天候のためフライトが2時間遅れた。"},{"id":2927,"en":"delete","ja":"削除する\nデータや文字を取り除く","level":6,"lnum":1,"ex":"She deleted the old files to free up space on her laptop.","exja":"彼女はラップトップの空き容量を確保するために古いファイルを削除した。"},{"id":2928,"en":"delicate","ja":"繊細な\n壊れやすい・扱いに注意が必要な","level":6,"lnum":1,"ex":"The antique vase is very delicate, so handle it with care.","exja":"その骨董品の花瓶はとても繊細なので、丁寧に扱ってください。"},{"id":2929,"en":"delight","ja":"喜び\n大きな満足感や楽しさ","level":6,"lnum":1,"ex":"The children squealed with delight when they saw the puppies.","exja":"子供たちは子犬を見て喜びで歓声を上げた。"},{"id":2930,"en":"delighted","ja":"大喜びの\n予想以上の嬉しいことへの強い喜び","level":6,"lnum":1,"ex":"She was delighted to receive a surprise gift from her friend.","exja":"友達からサプライズのプレゼントをもらって彼女は大喜びだった。"},{"id":2931,"en":"delightful","ja":"素晴らしい\n人を喜ばせる楽しい・魅力的な","level":6,"lnum":1,"ex":"The food at the restaurant was absolutely delightful.","exja":"レストランの料理はとても素晴らしかった。"},{"id":2932,"en":"demand","ja":"要求\n強く求めること・市場での需要","level":6,"lnum":1,"ex":"She demanded an explanation from her teacher.","exja":"彼女は先生に説明を求めた。"},{"id":2933,"en":"demand","ja":"要求する\n権利として当然のように強く求める","level":6,"lnum":1},{"id":2934,"en":"democracy","ja":"民主主義\n国民が政治に参加する政治体制","level":6,"lnum":1,"ex":"Democracy allows citizens to vote for their leaders.","exja":"民主主義では市民が指導者を選ぶことができる。"},{"id":2935,"en":"democratic","ja":"民主的な\n民主主義の原則に基づいた","level":6,"lnum":1,"ex":"The country held its first democratic election last year.","exja":"その国は昨年初めての民主的な選挙を行った。"},{"id":2936,"en":"demonstrate","ja":"実演する\n実際に見せて証明する","level":6,"lnum":1,"ex":"The teacher demonstrated how to solve the equation on the board.","exja":"先生は黒板で方程式の解き方を実演して見せた。"},{"id":2937,"en":"deny","ja":"否定する\n事実や要求を認めない・拒む","level":6,"lnum":1,"ex":"He denied taking the money from the drawer.","exja":"彼は引き出しからお金を取ったことを否定した。"},{"id":2938,"en":"depart","ja":"出発する\n場所を離れる。leaveよりフォーマル","level":6,"lnum":1,"ex":"The train departs from platform three at eight o'clock.","exja":"電車は8時に3番ホームから出発する。"},{"id":2939,"en":"department","ja":"部署・学部\n組織の中の専門的な区分","level":6,"lnum":1,"ex":"She works in the marketing department of a large company.","exja":"彼女は大企業のマーケティング部署に勤めている。"},{"id":2940,"en":"dependent","ja":"依存した\n他のものに頼って成り立っている","level":6,"lnum":1,"ex":"Young children are completely dependent on their parents.","exja":"幼い子どもは完全に親に依存している。"},{"id":2941,"en":"deposit","ja":"預け入れ金\n銀行の預金・手付金","level":6,"lnum":1,"ex":"He made a deposit of five hundred dollars into his bank account.","exja":"彼は銀行口座に500ドルを預け入れた。"},{"id":2942,"en":"depressing","ja":"落ち込ませる\n気分を重くさせる暗い出来事や状況","level":6,"lnum":1,"ex":"The rainy weather made everything feel depressing.","exja":"雨の天気でなんだか気分が落ち込んだ。"},{"id":2943,"en":"depression","ja":"うつ・不況\n精神的落ち込みまたは経済的停滞","level":6,"lnum":1,"ex":"Many people suffer from depression without seeking help.","exja":"多くの人が助けを求めずにうつに苦しんでいる。"},{"id":2944,"en":"deprive","ja":"奪う\n必要なものを取り上げて不自由にさせる","level":6,"lnum":1,"ex":"Lack of sleep can deprive you of the ability to concentrate.","exja":"睡眠不足は集中力を奪うことがある。"},{"id":2945,"en":"depth","ja":"深さ\n表面からどれだけ深いかの度合い","level":6,"lnum":1,"ex":"Scientists measured the depth of the ocean at that point.","exja":"科学者たちはその地点の海の深さを測定した。"},{"id":2946,"en":"derive","ja":"導き出す\nderive fromで「〜に由来する」の形で頻出","level":6,"lnum":1,"ex":"The word \"biology\" derives from Greek.","exja":"「biology」という単語はギリシャ語に由来する。"},{"id":2947,"en":"deserve","ja":"ふさわしい\n行動の結果として当然受け取るべきである","level":6,"lnum":1,"ex":"She worked so hard that she deserves a break.","exja":"彼女はとても頑張ったので休息に値する。"},{"id":2948,"en":"desire","ja":"欲求\n強く望む気持ち。wishより強い感情","level":6,"lnum":1,"ex":"He had a strong desire to travel the world.","exja":"彼には世界を旅したいという強い欲求があった。"},{"id":2949,"en":"despair","ja":"絶望\n希望が完全に失われた状態","level":6,"lnum":1,"ex":"After failing the exam three times, she fell into despair.","exja":"3回試験に落ちた後、彼女は絶望に陥った。"},{"id":2950,"en":"desperate","ja":"必死の\n追い詰められて何でもしようとする状態","level":6,"lnum":1,"ex":"The lost hiker was desperate to find shelter before dark.","exja":"迷子のハイカーは暗くなる前に避難場所を見つけようと必死だった。"},{"id":2951,"en":"despite","ja":"〜にもかかわらず\n逆接を示すフォーマルな前置詞","level":6,"lnum":1,"ex":"Despite the heavy rain, they continued the outdoor event.","exja":"激しい雨にもかかわらず、彼らは屋外イベントを続けた。"},{"id":2952,"en":"destination","ja":"目的地\n旅で向かう最終的な場所","level":6,"lnum":1,"ex":"Paris is a popular destination for tourists from all over the world.","exja":"パリは世界中の観光客に人気の目的地だ。"},{"id":2953,"en":"destruction","ja":"破壊\n物や組織が完全に壊されること","level":6,"lnum":1,"ex":"The earthquake caused widespread destruction across the city.","exja":"地震は街全体に広範囲の破壊をもたらした。"},{"id":2954,"en":"destructive","ja":"破壊的な\n物や関係を壊す力を持つ","level":6,"lnum":1,"ex":"The hurricane was one of the most destructive storms in history.","exja":"そのハリケーンは歴史上最も破壊的な嵐の一つだった。"},{"id":2955,"en":"detective","ja":"探偵\n犯罪を調査して解決する専門家","level":6,"lnum":1,"ex":"The detective carefully examined all the clues at the crime scene.","exja":"探偵は犯罪現場のすべての手がかりを注意深く調べた。"},{"id":2956,"en":"determination","ja":"決意\n困難があっても諦めない強い意志","level":6,"lnum":1,"ex":"Her determination to succeed helped her overcome every obstacle.","exja":"成功への彼女の決意はあらゆる障害を乗り越える助けになった。"},{"id":2957,"en":"determine","ja":"決定する\n調査や判断で結論を出す","level":6,"lnum":1,"ex":"Scientists are trying to determine the cause of the disease.","exja":"科学者たちは病気の原因を突き止めようとしている。"},{"id":2958,"en":"devastate","ja":"荒廃させる\n激しく破壊して打ちのめす","level":6,"lnum":1,"ex":"The wildfire devastated thousands of acres of forest.","exja":"山火事は何千エーカーもの森林を壊滅させた。"},{"id":2959,"en":"devastating","ja":"壊滅的な\n非常に深刻で回復が難しい被害","level":6,"lnum":1,"ex":"The news of the accident was devastating for the whole community.","exja":"事故のニュースはコミュニティ全体にとって壊滅的なものだった。"},{"id":2960,"en":"development","ja":"発展\n成長・改善・開発のプロセス","level":6,"lnum":1,"ex":"The development of new technology has changed everyday life.","exja":"新技術の発展は日常生活を変えた。"},{"id":2961,"en":"devotion","ja":"献身\n愛情や忠誠を込めて尽くすこと","level":6,"lnum":1,"ex":"Her devotion to her students made her an outstanding teacher.","exja":"生徒への献身が彼女を優れた教師にした。"},{"id":2962,"en":"diagram","ja":"図表\n情報を視覚的に示した説明図","level":6,"lnum":1,"ex":"The science textbook included a diagram showing how the heart works.","exja":"理科の教科書には心臓の働きを示す図表が載っていた。"},{"id":2963,"en":"dial","ja":"ダイヤル\n回転式の調整つまみ・電話の文字盤","level":6,"lnum":1,"ex":"She dialed her friend's number and waited for an answer.","exja":"彼女は友人の番号をダイヤルして応答を待った。"},{"id":2964,"en":"dial","ja":"ダイヤルする\n電話をかける操作をする","level":6,"lnum":1},{"id":2965,"en":"dialog","ja":"会話・対話\n2人以上の間での言葉のやり取り","level":6,"lnum":1,"ex":"The characters in the play had a meaningful dialog about friendship.","exja":"劇の登場人物たちは友情について意味深い対話を交わした。"},{"id":2966,"en":"diameter","ja":"直径\n円の中心を通る最大の長さ","level":6,"lnum":1,"ex":"The diameter of a basketball is about 24 centimeters.","exja":"バスケットボールの直径は約24センチメートルだ。"},{"id":2967,"en":"diaper","ja":"おむつ\n赤ちゃんの排泄物を受ける布や紙","level":6,"lnum":1,"ex":"The mother changed the baby's diaper carefully.","exja":"母親は丁寧に赤ちゃんのおむつを替えた。"},{"id":2968,"en":"differ","ja":"異なる\n2つ以上のものが違いを持つ","level":6,"lnum":1,"ex":"Opinions on this issue differ greatly from person to person.","exja":"この問題に対する意見は人によって大きく異なる。"},{"id":2969,"en":"dig","ja":"掘る\n地面や土を掘り下げる動作","level":6,"lnum":1,"ex":"The children dug a hole in the sand at the beach.","exja":"子どもたちはビーチの砂に穴を掘った。"},{"id":2970,"en":"digital","ja":"デジタルの\n数値データで処理される電子的な","level":6,"lnum":1,"ex":"Digital cameras have become more affordable in recent years.","exja":"近年、デジタルカメラはより手頃な価格になった。"},{"id":2971,"en":"diligence","ja":"勤勉さ\n一生懸命努力し続ける姿勢","level":6,"lnum":1,"ex":"His diligence in studying paid off when he passed the exam.","exja":"勉強への勤勉さが試験合格という形で報われた。"},{"id":2972,"en":"diligent","ja":"勤勉な\n熱心で手を抜かずに取り組む様子","level":6,"lnum":1,"ex":"She is a diligent student who always completes her homework on time.","exja":"彼女はいつも時間通りに宿題を終える勤勉な生徒だ。"},{"id":2973,"en":"dioxide","ja":"二酸化物\n酸素原子2つと別の元素の化合物","level":6,"lnum":1,"ex":"Carbon dioxide is one of the main gases causing climate change.","exja":"二酸化炭素は気候変動を引き起こす主な気体の一つだ。"},{"id":2974,"en":"direct","ja":"指示する\n人や活動の方向を管理・指揮する","level":6,"lnum":1,"ex":"The manager directed the team to finish the project by Friday.","exja":"マネージャーはチームに金曜日までにプロジェクトを終えるよう指示した。"},{"id":2975,"en":"dirt","ja":"汚れ・土\n土や汚い物質","level":6,"lnum":1,"ex":"After playing in the garden, the children were covered in dirt.","exja":"庭で遊んだ後、子どもたちは泥だらけになった。"},{"id":2976,"en":"disable","ja":"機能を止める\n機能や能力を使えなくする","level":6,"lnum":1,"ex":"The virus disabled many important functions of the computer.","exja":"ウイルスはコンピューターの多くの重要な機能を使えなくした。"},{"id":2977,"en":"disabled","ja":"障害のある\n身体や認知に制限がある状態","level":6,"lnum":1,"ex":"The school built a ramp to make the entrance accessible for disabled students.","exja":"学校は障害のある生徒が入口を使いやすいようにスロープを設置した。"},{"id":2978,"en":"disagreement","ja":"意見の不一致\n異なる意見によるぶつかり合い","level":6,"lnum":1,"ex":"There was a disagreement between the two colleagues about the best approach.","exja":"最善の方法について2人の同僚の間で意見の不一致があった。"},{"id":2979,"en":"disappoint","ja":"失望させる\n期待に応えられずがっかりさせる","level":6,"lnum":1,"ex":"I don't want to disappoint my parents by failing the test.","exja":"テストに落ちて両親を失望させたくない。"},{"id":2980,"en":"disappointment","ja":"失望\n期待が叶わなかったときの落胆","level":6,"lnum":1,"ex":"Missing the final match was a huge disappointment for the whole team.","exja":"決勝戦を逃したことはチーム全体にとって大きな失望だった。"},{"id":2981,"en":"disastrous","ja":"悲惨な\n深刻な被害や失敗をもたらす","level":6,"lnum":1,"ex":"The storm had a disastrous effect on the coastal villages.","exja":"嵐は沿岸の村々に壊滅的な影響を与えた。"},{"id":2982,"en":"disc jockey","ja":"ディスクジョッキー\n音楽を選んで流すラジオ・クラブの司会者","level":6,"lnum":1,"ex":"The disc jockey played great music that kept everyone dancing all night.","exja":"ディスクジョッキーは素晴らしい音楽を流し、みんなが一晩中踊り続けた。"},{"id":2983,"en":"discomfort","ja":"不快感\n軽い痛みや不満の感覚","level":6,"lnum":1,"ex":"She felt some discomfort in her knee after the long run.","exja":"長距離走の後、彼女は膝に多少の不快感を覚えた。"},{"id":2984,"en":"discourage","ja":"やる気をくじく\n挑戦する意欲を失わせる","level":6,"lnum":1,"ex":"Bad grades should not discourage you from trying again.","exja":"悪い成績はもう一度挑戦する意欲をくじくべきではない。"},{"id":2985,"en":"discrimination","ja":"差別\n不公平な扱いを特定の集団に対して行う","level":6,"lnum":1,"ex":"Discrimination based on race or gender is against the law.","exja":"人種や性別に基づく差別は法律に反する。"},{"id":2986,"en":"disgusting","ja":"不快な\n吐き気をもよおすほど不快な","level":6,"lnum":1,"ex":"The smell coming from the garbage was absolutely disgusting.","exja":"ゴミから漂う臭いはまったく不快だった。"},{"id":2987,"en":"dishwasher","ja":"食器洗い機\n食器を自動で洗う家電","level":6,"lnum":1,"ex":"She put all the dirty dishes in the dishwasher after dinner.","exja":"彼女は夕食後、汚れた食器をすべて食器洗い機に入れた。"},{"id":2988,"en":"disk","ja":"ディスク\nデータを記録するための円形の記憶媒体","level":6,"lnum":1,"ex":"He saved all his important files on an external disk.","exja":"彼は重要なファイルをすべて外部ディスクに保存した。"},{"id":2989,"en":"dissolve","ja":"溶かす\n液体に固体が溶け込む・組織を解散する","level":6,"lnum":1,"ex":"Stir the sugar until it dissolves completely in the water.","exja":"砂糖が水に完全に溶けるまでかき混ぜてください。"},{"id":2990,"en":"distant","ja":"遠い\n距離が離れている・よそよそしい態度","level":6,"lnum":1,"ex":"The sound of thunder grew more distant as the storm passed.","exja":"嵐が通り過ぎるにつれて雷の音はより遠くなった。"},{"id":2991,"en":"distinction","ja":"区別・卓越\n2つを分けること・高い評価","level":6,"lnum":1,"ex":"There is an important distinction between confidence and arrogance.","exja":"自信と傲慢さの間には重要な区別がある。"},{"id":2992,"en":"distinctly","ja":"はっきりと\n明確に・疑いなくわかる様子","level":6,"lnum":1,"ex":"I can distinctly remember the day I first rode a bicycle.","exja":"初めて自転車に乗った日のことをはっきりと覚えている。"},{"id":2993,"en":"distinguish","ja":"区別する\n違いを見分けて識別する","level":6,"lnum":1,"ex":"It can be difficult to distinguish between the two twins.","exja":"二人の双子を見分けるのは難しいことがある。"},{"id":2994,"en":"distribute","ja":"配布する\n多くの人や場所に分けて届ける","level":6,"lnum":1,"ex":"Volunteers distributed food to people in need after the flood.","exja":"ボランティアたちは洪水の後に困っている人々に食料を配布した。"},{"id":2995,"en":"distribution","ja":"配布・流通\n商品や情報を広く行き渡らせること","level":6,"lnum":1,"ex":"The distribution of wealth is unequal in many countries.","exja":"多くの国で富の分配は不平等だ。"},{"id":2996,"en":"district","ja":"地区\n行政や地理的に区切られた地域","level":6,"lnum":1,"ex":"The business district of the city is always busy during weekdays.","exja":"市のビジネス地区は平日は常に賑やかだ。"},{"id":2997,"en":"disturbance","ja":"妨害・騒ぎ\n平穏を乱す出来事や騒動","level":6,"lnum":1,"ex":"The loud music from the party caused a disturbance in the neighborhood.","exja":"パーティーの大きな音楽が近所に騒ぎをもたらした。"},{"id":2998,"en":"diver","ja":"ダイバー\n水中に潜って活動する人","level":6,"lnum":1,"ex":"The diver explored the colorful coral reefs underwater.","exja":"ダイバーは水中で色鮮やかなサンゴ礁を探索した。"},{"id":2999,"en":"diverse","ja":"多様な\n異なる種類のものが豊富にある状態","level":6,"lnum":1,"ex":"Our school has a diverse student body from over thirty countries.","exja":"私たちの学校には30カ国以上から来た多様な生徒がいる。"},{"id":3000,"en":"divine","ja":"神聖な\n神に関係する・素晴らしいの口語も","level":6,"lnum":1,"ex":"The sunset over the mountains looked absolutely divine.","exja":"山の上の夕日はまったく神々しかった。"},{"id":3001,"en":"diving","ja":"ダイビング\n水中に潜るスポーツ・飛び込み競技","level":6,"lnum":1,"ex":"She took diving lessons to explore the underwater world.","exja":"彼女は水中世界を探索するためダイビングのレッスンを受けた。"},{"id":3002,"en":"divorced","ja":"離婚した\n婚姻関係を法的に解消した状態","level":6,"lnum":1,"ex":"After the couple got divorced, they remained good friends.","exja":"夫婦が離婚した後も、彼らは良い友人であり続けた。"},{"id":3003,"en":"DJ","ja":"DJ\n音楽を選曲して流す人","level":6,"lnum":1,"ex":"The DJ played popular songs that everyone knew at the party.","exja":"DJはパーティーで誰もが知る人気曲をかけた。"},{"id":3004,"en":"doc","ja":"書類・医者\ndocumentまたはdoctorの口語的短縮","level":6,"lnum":1,"ex":"The doctor asked him to bring all his medical docs to the appointment.","exja":"医師は診察に医療書類をすべて持参するよう彼に求めた。"},{"id":3005,"en":"document","ja":"書類\n公式の記録や情報を記した文書","level":6,"lnum":1,"ex":"Please sign the document before submitting it to the office.","exja":"事務所に提出する前に書類に署名してください。"},{"id":3006,"en":"documentary","ja":"ドキュメンタリー\n事実を記録したテレビ・映画番組","level":6,"lnum":1,"ex":"The class watched a documentary about climate change.","exja":"クラスは気候変動に関するドキュメンタリーを観た。"},{"id":3007,"en":"downstairs","ja":"下の階の\n建物の下の階にある状態","level":6,"lnum":1,"ex":"She heard a noise and went downstairs to check.","exja":"彼女は物音を聞いて確認しに下の階へ行った。"},{"id":3008,"en":"downward","ja":"下向きの\n上から下に向かう方向の","level":6,"lnum":1,"ex":"The temperature trend has been downward all week.","exja":"気温の傾向は1週間ずっと下向きだった。"},{"id":3009,"en":"doze","ja":"うたた寝\n浅くうとうとと眠る状態","level":6,"lnum":1,"ex":"He dozed off on the sofa while watching television.","exja":"彼はテレビを見ながらソファでうたた寝した。"},{"id":3010,"en":"dozen","ja":"1ダース\n12個をひとまとめにした単位","level":6,"lnum":1,"ex":"She bought a dozen eggs at the supermarket.","exja":"彼女はスーパーで1ダースの卵を買った。"},{"id":3011,"en":"drag","ja":"引きずる\n重いものを地面に沿って引っ張る","level":6,"lnum":1,"ex":"He dragged the heavy suitcase up the stairs.","exja":"彼は重いスーツケースを引きずって階段を上った。"},{"id":3012,"en":"dramatic","ja":"劇的な\n強い印象を与える・劇のような変化","level":6,"lnum":1,"ex":"There was a dramatic change in the weather during the afternoon.","exja":"午後に天気が劇的に変わった。"},{"id":3013,"en":"drown","ja":"溺れる\n水中で呼吸できずに死ぬ","level":6,"lnum":1,"ex":"The lifeguard jumped in to save the child who was drowning.","exja":"ライフガードは溺れている子どもを救うために飛び込んだ。"},{"id":3014,"en":"drunk","ja":"酔った\nアルコールで判断力が低下した状態","level":6,"lnum":1,"ex":"He got drunk at the party and needed a friend to drive him home.","exja":"彼はパーティーで酔っぱらい、友人に家まで送ってもらう必要があった。"},{"id":3015,"en":"dude","ja":"やつ・兄ちゃん\n男性への親しみを込めた口語的呼びかけ","level":6,"lnum":1,"ex":"Hey dude, want to come play basketball with us after school?","exja":"ねえ、放課後一緒にバスケをしないか？"},{"id":3016,"en":"dull","ja":"退屈な\n面白みがなく活気のない・鈍い","level":6,"lnum":1,"ex":"The lecture was so dull that many students fell asleep.","exja":"その授業はとても退屈で多くの生徒が眠ってしまった。"},{"id":3017,"en":"dump","ja":"ごみ捨て場\n廃棄物を捨てる場所","level":6,"lnum":1,"ex":"He dumped all his old clothes at the donation center.","exja":"彼は古い服をすべて寄付センターに捨てた。"},{"id":3018,"en":"dump","ja":"捨てる\n不要なものを無造作に放棄する","level":6,"lnum":1},{"id":3019,"en":"dustbin","ja":"ごみ箱\n英国英語での屋外用ごみ容器","level":6,"lnum":1,"ex":"She emptied the dustbin and put in a fresh bag.","exja":"彼女はごみ箱を空にして新しい袋を入れた。"},{"id":3020,"en":"dusty","ja":"ほこりだらけの\n埃が積もっている状態","level":6,"lnum":1,"ex":"The old books on the shelf were dusty and hadn't been touched in years.","exja":"棚の古い本はほこりだらけで何年も触られていなかった。"},{"id":3021,"en":"duty-free","ja":"免税の\n税金がかからない空港などの売り場","level":6,"lnum":1,"ex":"She bought a bottle of perfume at the duty-free shop in the airport.","exja":"彼女は空港の免税店で香水を一本買った。"},{"id":3022,"en":"duvet","ja":"羽根布団\n中に羽毛や綿を詰めたかけ布団","level":6,"lnum":1,"ex":"She pulled the warm duvet over herself on the cold winter night.","exja":"寒い冬の夜、彼女は温かい羽根布団を体の上に引っ張り上げた。"},{"id":3023,"en":"dynasty","ja":"王朝\n同じ一族が続けて権力を持つ時代","level":6,"lnum":1,"ex":"The Ming dynasty ruled China for nearly three centuries.","exja":"明王朝は中国をほぼ3世紀にわたって支配した。"},{"id":3024,"en":"eager","ja":"熱心な\n強い意欲と期待を持ってやりたがる","level":6,"lnum":1,"ex":"The students were eager to learn new things in science class.","exja":"生徒たちは理科の授業で新しいことを学ぼうと熱心だった。"},{"id":3025,"en":"eagerness","ja":"熱意\n積極的にやりたいという強い気持ち","level":6,"lnum":1,"ex":"His eagerness to help others made him popular among his classmates.","exja":"他人を助けようとする彼の熱意は彼をクラスメートの間で人気にした。"},{"id":3026,"en":"earache","ja":"耳の痛み\n耳の中の痛みや不快感","level":6,"lnum":1,"ex":"She stayed home from school because of a bad earache.","exja":"ひどい耳の痛みで彼女は学校を休んだ。"},{"id":3027,"en":"earnest","ja":"真剣な\n冗談でなく心から真摯に取り組む","level":6,"lnum":1,"ex":"He made an earnest effort to improve his grades this semester.","exja":"彼は今学期成績を上げようと真剣に努力した。"},{"id":3028,"en":"eco","ja":"環境の\necologyの略で環境保護に関連する","level":6,"lnum":1,"ex":"The company switched to eco-friendly packaging to reduce waste.","exja":"その会社は廃棄物を減らすためにエコフレンドリーな包装に切り替えた。"},{"id":3029,"en":"ecological","ja":"生態学の\n生物と環境の関係に関する","level":6,"lnum":1,"ex":"The oil spill had a serious ecological impact on the local wildlife.","exja":"原油流出は地域の野生動物に深刻な生態学的影響を与えた。"},{"id":3030,"en":"ecology","ja":"生態学\n生物と環境の相互関係を研究する学問","level":6,"lnum":1,"ex":"Students learned about ecology and how animals interact with their environment.","exja":"生徒たちは生態学と動物が環境とどう関わるかを学んだ。"},{"id":3031,"en":"economic","ja":"経済の\n経済活動や経済学に関連する形容詞","level":6,"lnum":1,"ex":"The government introduced new policies to boost economic growth.","exja":"政府は経済成長を促進するための新しい政策を導入した。"},{"id":3032,"en":"economics","ja":"経済学\n経済の仕組みを研究する学問","level":6,"lnum":1,"ex":"She decided to study economics at university because she was interested in markets.","exja":"彼女は市場に興味があったので大学で経済学を学ぶことにした。"},{"id":3033,"en":"ecstasy","ja":"恍惚\n極度の喜びや興奮で我を忘れる状態","level":6,"lnum":1,"ex":"She was in ecstasy when she heard she had won the scholarship.","exja":"奨学金を得たと聞いて彼女は恍惚とした。"},{"id":3034,"en":"edition","ja":"版\n本や雑誌の出版バージョン","level":6,"lnum":1,"ex":"The library has the latest edition of the encyclopedia.","exja":"図書館には百科事典の最新版がある。"},{"id":3035,"en":"educate","ja":"教育する\n知識や技能を教えて成長させる","level":6,"lnum":1,"ex":"It is important to educate children about environmental issues.","exja":"子どもたちに環境問題について教育することは重要だ。"},{"id":3036,"en":"efficiency","ja":"効率\n最小の労力で最大の成果を出す能力","level":6,"lnum":1,"ex":"The new software improved the efficiency of the entire team.","exja":"新しいソフトウェアはチーム全体の効率を向上させた。"},{"id":3037,"en":"efficient","ja":"効率的な\n無駄なく目的を達成できる","level":6,"lnum":1,"ex":"The new machine is more efficient and uses less energy.","exja":"新しい機械はより効率的でエネルギーの使用量が少ない。"},{"id":3038,"en":"election","ja":"選挙\n投票で代表者を選ぶ民主的な手続き","level":6,"lnum":1,"ex":"Millions of people voted in the presidential election last November.","exja":"先月11月の大統領選挙で何百万人もの人々が投票した。"},{"id":3039,"en":"electrical","ja":"電気の\n電気に関連する装置や現象を指す","level":6,"lnum":1,"ex":"The electrician fixed the electrical problem in the kitchen.","exja":"電気技師はキッチンの電気の問題を修理した。"},{"id":3040,"en":"electron","ja":"電子\n原子の周りを回るマイナスの電荷の粒子","level":6,"lnum":1,"ex":"An electron carries a negative electric charge.","exja":"電子はマイナスの電荷を持つ。"},{"id":3041,"en":"element","ja":"要素\n全体を構成する基本的な部分","level":6,"lnum":1,"ex":"Trust is an essential element of any good friendship.","exja":"信頼はどんな良い友情にも不可欠な要素だ。"},{"id":3042,"en":"eliminate","ja":"排除する\n不要なものを完全に取り除く","level":6,"lnum":1,"ex":"The new policy aims to eliminate food waste in school cafeterias.","exja":"新しい政策は学校の食堂での食品廃棄を排除することを目的としている。"},{"id":3043,"en":"embarrass","ja":"恥ずかしくさせる\n人を気まずい・恥ずかしい思いにさせる","level":6,"lnum":1,"ex":"He embarrassed himself by tripping on stage during the performance.","exja":"公演中に舞台でつまずいて彼は恥をかいた。"},{"id":3044,"en":"embarrassment","ja":"恥ずかしさ\n気まずい状況での羞恥心","level":6,"lnum":1,"ex":"She turned red with embarrassment when she forgot her speech.","exja":"スピーチを忘れて彼女は恥ずかしさで顔を赤くした。"},{"id":3045,"en":"emerge","ja":"現れる\n隠れていたものが姿を見せる","level":6,"lnum":1,"ex":"A solution finally emerged after hours of discussion.","exja":"何時間もの議論の後、ついに解決策が現れた。"},{"id":3046,"en":"emotion","ja":"感情\n喜怒哀楽などの心の動き","level":6,"lnum":1,"ex":"She tried to hide her emotions, but her eyes gave her away.","exja":"彼女は感情を隠そうとしたが、目が感情を表していた。"},{"id":3047,"en":"emotional","ja":"感情的な\n感情が動かされやすい・情緒的な","level":6,"lnum":1,"ex":"The emotional speech moved many people in the audience to tears.","exja":"感情的なスピーチは聴衆の多くを涙させた。"},{"id":3048,"en":"emotionally","ja":"感情的に\n感情を通して・心の面で","level":6,"lnum":1,"ex":"He was emotionally exhausted after the long argument with his parents.","exja":"両親との長い口論の後、彼は感情的に疲れ果てた。"},{"id":3049,"en":"emperor","ja":"皇帝\n帝国を統治する最高権力者","level":6,"lnum":1,"ex":"The emperor declared a day of celebration for the whole nation.","exja":"皇帝は国全体の祝賀日を宣言した。"},{"id":3050,"en":"emphasis","ja":"強調\n特に重要だと際立たせること","level":6,"lnum":1,"ex":"The teacher put special emphasis on the importance of reading.","exja":"先生は読書の重要性に特別な強調を置いた。"},{"id":3051,"en":"emphasize","ja":"強調する\n特に重要な点を際立たせる","level":6,"lnum":1,"ex":"The doctor emphasized the need to eat a balanced diet every day.","exja":"医師は毎日バランスの取れた食事をとることの必要性を強調した。"},{"id":3052,"en":"empire","ja":"帝国\n皇帝が支配する広大な国家・組織","level":6,"lnum":1,"ex":"The Roman Empire was one of the most powerful in history.","exja":"ローマ帝国は歴史上最も強力な帝国の一つだった。"},{"id":3053,"en":"employment","ja":"雇用\n仕事を得て働いている状態","level":6,"lnum":1,"ex":"Finding stable employment after graduation was her main goal.","exja":"卒業後に安定した雇用を見つけることが彼女の主な目標だった。"},{"id":3054,"en":"enable","ja":"可能にする\n何かができる条件や手段を与える","level":6,"lnum":1,"ex":"This app enables users to share photos with friends instantly.","exja":"このアプリはユーザーが友人と写真を即座に共有できるようにする。"},{"id":3055,"en":"enclose","ja":"同封する\n手紙などに書類を一緒に入れる","level":6,"lnum":1,"ex":"Please enclose your resume with the application letter.","exja":"申請書に履歴書を同封してください。"},{"id":3056,"en":"encounter","ja":"出会い\n予期せず人や問題に出くわすこと","level":6,"lnum":1,"ex":"During the hike, we encountered a family of deer in the forest.","exja":"ハイキング中、私たちは森でシカの家族に出くわした。"},{"id":3057,"en":"encouragement","ja":"励まし\nやる気を起こさせる言葉や行動","level":6,"lnum":1,"ex":"Her teacher's words of encouragement helped her believe in herself.","exja":"先生の励ましの言葉が彼女が自分を信じる助けになった。"},{"id":3058,"en":"encouraging","ja":"励みになる\n希望や自信を与えてくれる様子","level":6,"lnum":1,"ex":"The results of the experiment were very encouraging for the research team.","exja":"実験の結果は研究チームにとって非常に励みになるものだった。"},{"id":3059,"en":"encyclopedia","ja":"百科事典\n多分野の知識を網羅した参考書","level":6,"lnum":1,"ex":"He looked up information about space exploration in the encyclopedia.","exja":"彼は百科事典で宇宙探査に関する情報を調べた。"},{"id":3060,"en":"endanger","ja":"危険にさらす\n生命や安全を脅かす状態にする","level":6,"lnum":1,"ex":"Pollution can endanger many species of fish in rivers and lakes.","exja":"汚染は川や湖の多くの魚の種を危険にさらすことがある。"},{"id":3061,"en":"endless","ja":"終わりのない\n限りなく続いてきりがない様子","level":6,"lnum":1,"ex":"The desert seemed endless as they drove across it.","exja":"砂漠は横断中に果てしなく続いているように見えた。"},{"id":3062,"en":"endure","ja":"耐える\n苦しい状況を我慢して乗り越える","level":6,"lnum":1,"ex":"The soldiers had to endure harsh weather conditions during the mission.","exja":"兵士たちは任務中に過酷な気象条件に耐えなければならなかった。"},{"id":3063,"en":"engage","ja":"従事する\n活動や会話に積極的に参加する","level":6,"lnum":1,"ex":"She always engages students by asking interesting questions.","exja":"彼女はいつも面白い質問をして生徒を活動に参加させる。"},{"id":3064,"en":"engaged","ja":"婚約した\n結婚を約束した状態・使用中の意味も","level":6,"lnum":1,"ex":"They got engaged last spring and plan to marry next year.","exja":"彼らは昨年春に婚約し、来年結婚する予定だ。"},{"id":3065,"en":"engineering","ja":"工学\n科学を応用して技術を開発する学問","level":6,"lnum":1,"ex":"He studied engineering because he wanted to design bridges.","exja":"彼は橋を設計したかったので工学を学んだ。"},{"id":3066,"en":"Englishman","ja":"イギリス人男性\nイングランド出身の男性","level":6,"lnum":1,"ex":"The Englishman politely asked for directions to the nearest station.","exja":"そのイギリス人男性は最寄りの駅への道を丁寧に尋ねた。"},{"id":3067,"en":"enjoyable","ja":"楽しい\n参加や経験が喜びをもたらす","level":6,"lnum":1,"ex":"The school trip was one of the most enjoyable experiences of the year.","exja":"修学旅行はその年の最も楽しい経験の一つだった。"},{"id":3068,"en":"enjoyment","ja":"楽しみ\n何かを楽しんで得られる満足感","level":6,"lnum":1,"ex":"Reading books brings her a great sense of enjoyment.","exja":"本を読むことは彼女に大きな楽しみをもたらす。"},{"id":3069,"en":"enrich","ja":"豊かにする\n質・価値・内容をより良くする","level":6,"lnum":1,"ex":"Traveling abroad can enrich your understanding of different cultures.","exja":"海外旅行は異なる文化への理解を豊かにすることができる。"},{"id":3070,"en":"ensure","ja":"確実にする\n〜が必ず起こるよう手を打つ","level":6,"lnum":1,"ex":"Please ensure that all the windows are closed before you leave.","exja":"出発前にすべての窓が閉まっていることを確かめてください。"},{"id":3071,"en":"entertain","ja":"楽しませる\n観客や客を喜ばせる活動をする","level":6,"lnum":1,"ex":"The comedian entertained the audience with funny stories and jokes.","exja":"コメディアンはおかしな話やジョークで観客を楽しませた。"},{"id":3072,"en":"entertainer","ja":"芸能人\n人を楽しませることを職業とする人","level":6,"lnum":1,"ex":"He became a popular entertainer known for his impressive magic tricks.","exja":"彼は印象的なマジックで知られる人気芸能人になった。"},{"id":3073,"en":"enthusiasm","ja":"熱意\n何かに対する強い興味と積極性","level":6,"lnum":1,"ex":"Her enthusiasm for music inspired everyone around her.","exja":"音楽に対する彼女の熱意は周りの全員を刺激した。"},{"id":3074,"en":"enthusiast","ja":"熱狂者\n特定のことに強い関心を持つ人","level":6,"lnum":1,"ex":"He is a car enthusiast who knows everything about classic models.","exja":"彼はクラシックモデルについて何でも知っているカー熱狂者だ。"},{"id":3075,"en":"enthusiastic","ja":"熱狂的な\n強い興味と積極性を持っている状態","level":6,"lnum":1,"ex":"The students were enthusiastic about the science fair project.","exja":"生徒たちはサイエンスフェアのプロジェクトに熱狂的だった。"},{"id":3076,"en":"entire","ja":"全体の\n省略せず全部の・完全な","level":6,"lnum":1,"ex":"She read the entire book in just one day.","exja":"彼女はたった1日で本全体を読んだ。"},{"id":3077,"en":"entirely","ja":"まったく\n完全に・例外なくすべて","level":6,"lnum":1,"ex":"The situation is entirely different from what I had expected.","exja":"状況は私が予想していたものとはまったく違う。"},{"id":3078,"en":"entry","ja":"入り口・記入\n建物への入り口または記録の1件","level":6,"lnum":1,"ex":"Please fill in all the required fields in the entry form.","exja":"エントリーフォームの必須項目をすべて記入してください。"},{"id":3079,"en":"environmentalist","ja":"環境保護活動家\n環境保護を推進する活動家","level":6,"lnum":1,"ex":"The environmentalist gave a speech about the importance of protecting forests.","exja":"環境保護活動家は森林を守る重要性について演説した。"},{"id":3080,"en":"equal","ja":"平等な\n差のない同じ扱いを受ける状態","level":6,"lnum":1,"ex":"Every student deserves equal access to quality education.","exja":"すべての生徒は質の高い教育に平等にアクセスする権利がある。"},{"id":3081,"en":"equality","ja":"平等\nすべての人が同じ権利を持つこと","level":6,"lnum":1,"ex":"The organization works hard to promote equality in the workplace.","exja":"その組織は職場での平等を促進するために懸命に取り組んでいる。"},{"id":3082,"en":"equally","ja":"平等に\n同じように・同程度に","level":6,"lnum":1,"ex":"Both candidates are equally qualified for the position.","exja":"両候補者はその職位に同様に資格を有している。"},{"id":3083,"en":"equipment","ja":"設備\n特定の目的のために必要な道具や機器","level":6,"lnum":1,"ex":"The hospital received new medical equipment to treat patients more effectively.","exja":"病院は患者をより効果的に治療するための新しい医療設備を受け取った。"},{"id":3084,"en":"era","ja":"時代\n特定の性質を持つ歴史的な期間","level":6,"lnum":1,"ex":"The invention of the internet marked the beginning of a new era.","exja":"インターネットの発明は新しい時代の始まりを告げた。"},{"id":3085,"en":"essence","ja":"本質\n物事の中心にある最も重要な性質","level":6,"lnum":1,"ex":"The essence of good communication is listening as well as speaking.","exja":"良いコミュニケーションの本質は話すことと同様に聞くことだ。"},{"id":3086,"en":"essential","ja":"不可欠な\nなくてはならない非常に重要な","level":6,"lnum":1,"ex":"Water is essential for all living things to survive.","exja":"水はすべての生き物が生きるために不可欠だ。"},{"id":3087,"en":"establishment","ja":"機関・設立\n組織や施設・公式に設立すること","level":6,"lnum":1,"ex":"The establishment of a new library in the town was welcomed by residents.","exja":"街への新しい図書館の設立は住民に歓迎された。"},{"id":3088,"en":"estimate","ja":"見積もる\n正確ではないがおおよその数値を出す","level":6,"lnum":1,"ex":"The contractor estimated that the repairs would cost about three thousand dollars.","exja":"業者は修理費用が約3000ドルかかると見積もった。"},{"id":3089,"en":"eternal","ja":"永遠の\n時間的な限りがなく続く","level":6,"lnum":1,"ex":"True love is often described as eternal and unconditional.","exja":"真の愛はしばしば永遠で無条件なものとして描かれる。"},{"id":3090,"en":"eternity","ja":"永遠\n終わりがない無限の時間","level":6,"lnum":1,"ex":"It felt like an eternity waiting for the test results.","exja":"テストの結果を待つのは永遠のように感じられた。"},{"id":3091,"en":"evenly","ja":"均等に\n偏りなく等しく分配する様子","level":6,"lnum":1,"ex":"Spread the butter evenly on both sides of the bread.","exja":"パンの両面に均等にバターを塗ってください。"},{"id":3092,"en":"eventually","ja":"最終的に\n時間をかけて結局〜になる","level":6,"lnum":1,"ex":"She practiced every day and eventually became a great pianist.","exja":"彼女は毎日練習し、最終的に素晴らしいピアニストになった。"},{"id":3093,"en":"evident","ja":"明らかな\n証拠から見て明白な状態","level":6,"lnum":1,"ex":"It was evident from her smile that she was happy.","exja":"彼女の笑顔から彼女が幸せであることは明らかだった。"},{"id":3094,"en":"exact","ja":"正確な\n誤差なくぴったり一致している","level":6,"lnum":1,"ex":"Can you give me the exact time the meeting will start?","exja":"会議が始まる正確な時間を教えてもらえますか？"},{"id":3095,"en":"examination","ja":"試験・診察\n学力を測るテストや医師の診察","level":6,"lnum":1,"ex":"The students studied hard for the final examination.","exja":"生徒たちは期末試験に向けて一生懸命勉強した。"},{"id":3096,"en":"examine","ja":"調べる\n詳しく注意深く観察・検査する","level":6,"lnum":1,"ex":"The doctor examined the patient thoroughly before making a diagnosis.","exja":"医師は診断を下す前に患者を徹底的に診察した。"},{"id":3097,"en":"examiner","ja":"試験官\n試験を管理・採点する人","level":6,"lnum":1,"ex":"The examiner reminded students not to use their phones during the test.","exja":"試験官はテスト中に携帯電話を使わないよう生徒に念を押した。"},{"id":3098,"en":"excellence","ja":"卓越\n非常に高い水準の優秀さ","level":6,"lnum":1,"ex":"The award recognizes excellence in science and technology.","exja":"その賞は科学と技術における卓越さを称えるものだ。"},{"id":3099,"en":"excess","ja":"過剰\n必要以上に多すぎる量","level":6,"lnum":1,"ex":"Eating excess amounts of sugar can lead to health problems.","exja":"過剰な砂糖の摂取は健康上の問題につながることがある。"},{"id":3100,"en":"exchange rate","ja":"為替レート\n異なる通貨間の交換比率","level":6,"lnum":1,"ex":"He checked the exchange rate before converting his dollars to euros.","exja":"彼はドルをユーロに換える前に為替レートを確認した。"},{"id":3101,"en":"excitedly","ja":"興奮して\nわくわくした気持ちで行動する様子","level":6,"lnum":1,"ex":"The children talked excitedly about their plans for the summer vacation.","exja":"子どもたちは夏休みの計画について興奮して話した。"},{"id":3102,"en":"excitement","ja":"興奮\nわくわくして心が高まっている状態","level":6,"lnum":1,"ex":"There was great excitement in the crowd as the singer walked onto the stage.","exja":"歌手が舞台に上がると観客の中に大きな興奮が広がった。"},{"id":3103,"en":"exclusive","ja":"限定的な\n特定の人だけが使える高級なもの","level":6,"lnum":1,"ex":"The hotel offers exclusive services to its members only.","exja":"そのホテルは会員限定の限定的なサービスを提供している。"},{"id":3104,"en":"exhausted","ja":"疲れ果てた\nエネルギーが完全に使い果たされた状態","level":6,"lnum":1,"ex":"After hiking for eight hours, they were completely exhausted.","exja":"8時間ハイキングした後、彼らは完全に疲れ果てた。"},{"id":3105,"en":"existence","ja":"存在\n実際にあること・生きていること","level":6,"lnum":1,"ex":"The discovery proved the existence of ancient civilizations in the area.","exja":"その発見はその地域に古代文明が存在したことを証明した。"},{"id":3106,"en":"expand","ja":"拡大する\n大きく広げる・成長させる","level":6,"lnum":1,"ex":"The company plans to expand its business to other countries.","exja":"その会社は他の国にビジネスを拡大する計画だ。"},{"id":3107,"en":"expense","ja":"費用\nお金がかかること・経費","level":6,"lnum":1,"ex":"The unexpected car repair was a big expense for the family.","exja":"予期しない車の修理は家族にとって大きな出費だった。"},{"id":3108,"en":"experienced","ja":"経験豊富な\n多くの経験を積んでいる状態","level":6,"lnum":1,"ex":"She is an experienced nurse who has worked in hospitals for over ten years.","exja":"彼女は10年以上病院で働いてきた経験豊富な看護師だ。"},{"id":3109,"en":"exploration","ja":"探検・探索\n未知の場所や知識を調べること","level":6,"lnum":1,"ex":"The exploration of Mars has been a major goal for space agencies.","exja":"火星の探査は宇宙機関の大きな目標だった。"},{"id":3110,"en":"explosion","ja":"爆発\n突然の大きな爆破・急激な増加","level":6,"lnum":1,"ex":"The explosion in the factory was heard from several kilometers away.","exja":"工場での爆発は数キロ先から聞こえた。"},{"id":3111,"en":"expose","ja":"さらす\n隠れていたものを外に出す・暴露する","level":6,"lnum":1,"ex":"The journalist exposed corruption within the local government.","exja":"ジャーナリストは地方政府内の汚職を暴露した。"},{"id":3112,"en":"extend","ja":"延ばす\n長さ・期間・範囲を大きくする","level":6,"lnum":1,"ex":"The school decided to extend the deadline for submitting assignments.","exja":"学校は課題提出の締め切りを延ばすことにした。"},{"id":3113,"en":"extensively","ja":"広範囲に\n広い範囲にわたって徹底的に","level":6,"lnum":1,"ex":"He researched the topic extensively before writing his essay.","exja":"彼はエッセイを書く前に広範囲にわたってその話題を調査した。"},{"id":3114,"en":"extent","ja":"程度・範囲\nどれくらいかを示す広さや度合い","level":6,"lnum":1,"ex":"To some extent, success depends on luck as well as hard work.","exja":"ある程度まで、成功は努力だけでなく運にも左右される。"},{"id":3115,"en":"extinct","ja":"絶滅した\n生き物の種が完全に消滅した状態","level":6,"lnum":1,"ex":"The dodo became extinct in the late seventeenth century.","exja":"ドードーは17世紀後半に絶滅した。"},{"id":3116,"en":"extinction","ja":"絶滅\n生き物の種が完全になくなること","level":6,"lnum":1,"ex":"Climate change is a major threat to the extinction of many animal species.","exja":"気候変動は多くの動物種の絶滅への大きな脅威だ。"},{"id":3117,"en":"extra","ja":"余分なもの\n必要以上に追加されたもの","level":6,"lnum":1,"ex":"She always carries an extra pen in case the first one runs out of ink.","exja":"彼女は最初のペンがインク切れになった場合に備えて予備のペンを常に持ち歩く。"},{"id":3118,"en":"extraordinary","ja":"並外れた\n普通の基準をはるかに超えた","level":6,"lnum":1,"ex":"The young musician gave an extraordinary performance that amazed everyone.","exja":"若い音楽家は全員を驚かせる並外れた演奏を披露した。"},{"id":3119,"en":"extreme","ja":"極端な\n限界に近いほど非常に強い状態","level":6,"lnum":1,"ex":"Extreme temperatures in the desert make survival very difficult.","exja":"砂漠の極端な気温は生存を非常に困難にする。"},{"id":3120,"en":"extreme sports","ja":"エクストリームスポーツ\n危険を伴うスリルを楽しむスポーツ","level":6,"lnum":1,"ex":"Rock climbing and bungee jumping are popular extreme sports among young people.","exja":"ロッククライミングとバンジージャンプは若者に人気のエクストリームスポーツだ。"},{"id":3121,"en":"eyesight","ja":"視力\n目で物を見る能力","level":6,"lnum":1,"ex":"His eyesight has weakened, so he now wears glasses.","exja":"視力が低下したため、彼は今メガネをかけている。"},{"id":3122,"en":"face to face","ja":"面と向かって\n直接会って対話する様子","level":6,"lnum":1,"ex":"It is better to discuss serious matters face to face rather than by text.","exja":"深刻な問題はテキストよりも面と向かって話し合う方が良い。"},{"id":3123,"en":"face-to-face","ja":"対面の\n直接顔を合わせた形式の","level":6,"lnum":1,"ex":"The company prefers face-to-face meetings for important decisions.","exja":"その会社は重要な決定には対面の会議を好む。"},{"id":3124,"en":"fade","ja":"色あせる\n色や音が徐々に薄れていく","level":6,"lnum":1,"ex":"The colors in the old photograph had faded over the years.","exja":"古い写真の色は年月とともに色あせていた。"},{"id":3125,"en":"faint","ja":"かすかな\n音や色が薄く弱い・気絶するの意味も","level":6,"lnum":1,"ex":"She felt faint after standing in the hot sun for too long.","exja":"強い日差しの下に長時間立っていて彼女はぼーっとした。"},{"id":3126,"en":"faithful","ja":"忠実な\n約束や信仰を守り続ける","level":6,"lnum":1,"ex":"He has been a faithful friend who has always kept his promises.","exja":"彼はいつも約束を守ってくれた忠実な友人だ。"},{"id":3127,"en":"fake","ja":"偽物の\n本物に見せかけた偽りのもの","level":6,"lnum":1,"ex":"The antique dealer discovered that the painting was a fake.","exja":"骨董品商はその絵が偽物だと発見した。"},{"id":3128,"en":"fallen","ja":"落ちた\n高い位置から下に落ちた状態","level":6,"lnum":1,"ex":"The road was blocked by a fallen tree after the storm.","exja":"嵐の後、倒れた木で道路がふさがれた。"},{"id":3129,"en":"fancy","ja":"気まぐれな好み\n風変わりな・高級な・気に入る","level":6,"lnum":1,"ex":"She has always fancied living in a small house by the sea.","exja":"彼女はずっと海辺の小さな家に住むことに憧れていた。"},{"id":3130,"en":"fancy","ja":"〜が欲しい\n〜したい・〜が好きの口語的表現","level":6,"lnum":1},{"id":3131,"en":"fantasy","ja":"空想\n現実ではない夢や想像の世界","level":6,"lnum":1,"ex":"He escaped into a world of fantasy by reading adventure novels.","exja":"彼は冒険小説を読むことで空想の世界に逃げ込んだ。"},{"id":3132,"en":"faraway","ja":"遠い\n物理的または心理的に遠く離れた","level":6,"lnum":1,"ex":"She often dreamed of visiting faraway lands and exotic cultures.","exja":"彼女はしばしば遠い土地や異国の文化を訪れる夢を見た。"},{"id":3133,"en":"farmland","ja":"農地\n農業に使われる土地","level":6,"lnum":1,"ex":"Much of the farmland in this region was destroyed by the flood.","exja":"この地域の農地の多くは洪水で破壊された。"},{"id":3134,"en":"farther","ja":"より遠くに\n物理的距離のfurtherとの使い分けに注意","level":6,"lnum":1,"ex":"The next rest stop is farther than I thought.","exja":"次の休憩場所は思ったより遠い。"},{"id":3135,"en":"farthest","ja":"最も遠くに\n物理的に最も距離が離れた場所に","level":6,"lnum":1,"ex":"She lives the farthest from school among all her classmates.","exja":"彼女はクラスメートの中で学校から最も遠くに住んでいる。"},{"id":3136,"en":"fascinate","ja":"魅了する\n強い興味や魅力でひきつける","level":6,"lnum":1,"ex":"Ancient Egyptian history never fails to fascinate her.","exja":"古代エジプトの歴史は彼女を常に魅了してやまない。"},{"id":3137,"en":"fashionable","ja":"流行の\n現在のトレンドに合ったおしゃれな","level":6,"lnum":1,"ex":"She always dresses in fashionable clothes that attract attention.","exja":"彼女は常に注目を集めるファッショナブルな服を着ている。"},{"id":3138,"en":"fasten","ja":"固定する\nベルトやボタンをとめる・しっかり結ぶ","level":6,"lnum":1,"ex":"Please fasten your seatbelt before the plane takes off.","exja":"飛行機が離陸する前にシートベルトをお締めください。"},{"id":3139,"en":"favorable","ja":"好意的な\n賛成・支持する態度の","level":6,"lnum":1,"ex":"The weather conditions were favorable for the outdoor concert.","exja":"屋外コンサートには好都合な気象条件だった。"},{"id":3140,"en":"fax","ja":"ファックス\n電話回線で文書を送受信する機器","level":6,"lnum":1,"ex":"She faxed the signed contract to the head office.","exja":"彼女は署名した契約書を本社にファックスした。"},{"id":3141,"en":"fax","ja":"ファックスする\nファックスで文書を送る","level":6,"lnum":1},{"id":3142,"en":"feast","ja":"ごちそう\n豪華な食事の宴会や祝いの食事","level":6,"lnum":1,"ex":"The family gathered for a wonderful feast on New Year's Day.","exja":"家族は元日に素晴らしいごちそうのために集まった。"},{"id":3143,"en":"fellow","ja":"仲間\n同じ集団や境遇にある男性","level":6,"lnum":1,"ex":"He and his fellow students studied together every evening.","exja":"彼と仲間の学生たちは毎晩一緒に勉強した。"},{"id":3144,"en":"festive","ja":"祝祭の\nお祝いムードの明るく華やかな","level":6,"lnum":1,"ex":"The streets were filled with a festive atmosphere during the holiday season.","exja":"休暇シーズン中、街は祝祭の雰囲気に満ちていた。"},{"id":3145,"en":"fetch","ja":"取ってくる\n別の場所から何かを持ってくる","level":6,"lnum":1,"ex":"Could you fetch me a glass of water from the kitchen?","exja":"キッチンから水を一杯取ってきてもらえますか？"},{"id":3146,"en":"feverishly","ja":"熱心に\n熱にうかされたように必死で行動する","level":6,"lnum":1,"ex":"He worked feverishly to finish the project before the deadline.","exja":"彼は締め切り前にプロジェクトを終わらせようと熱心に取り組んだ。"},{"id":3147,"en":"filling","ja":"詰め物\n歯の詰め物やサンドイッチの具材","level":6,"lnum":1,"ex":"The dentist put a filling in her tooth to stop the pain.","exja":"歯科医は痛みを止めるために彼女の歯に詰め物をした。"},{"id":3148,"en":"film-maker","ja":"映画監督\n映画を制作する人","level":6,"lnum":1,"ex":"The young film-maker won an award for her short documentary.","exja":"若い映画監督は短編ドキュメンタリーで賞を受賞した。"},{"id":3149,"en":"filter","ja":"フィルター\n不要なものを取り除くための装置","level":6,"lnum":1,"ex":"The water filter removes harmful chemicals from tap water.","exja":"水フィルターは水道水から有害な化学物質を取り除く。"},{"id":3150,"en":"finance","ja":"資金提供する\nプロジェクトや事業にお金を出す","level":6,"lnum":1,"ex":"The government financed the construction of a new highway.","exja":"政府は新しい高速道路の建設に資金を提供した。"},{"id":3151,"en":"financial","ja":"財政的な\nお金や財産に関係する","level":6,"lnum":1,"ex":"She asked a financial advisor for help planning her savings.","exja":"彼女は貯蓄計画を立てる助けを求めてファイナンシャルアドバイザーに相談した。"},{"id":3152,"en":"finding","ja":"調査結果\n研究や調査から得られた発見や結論","level":6,"lnum":1,"ex":"The findings of the research suggest that exercise improves mental health.","exja":"研究の調査結果は運動が精神的健康を改善することを示唆している。"},{"id":3153,"en":"firm","ja":"しっかりした\n簡単に変わらない確固とした","level":6,"lnum":1,"ex":"She gave a firm answer and refused to change her mind.","exja":"彼女はしっかりした返答をして意見を変えることを拒んだ。"},{"id":3154,"en":"firm","ja":"会社\nビジネスを行う企業・フォーマルな表現","level":6,"lnum":1},{"id":3155,"en":"firmly","ja":"しっかりと\n強くぶれずに確固として","level":6,"lnum":1,"ex":"He firmly believed that honesty was the most important value.","exja":"彼は正直さが最も重要な価値だと固く信じていた。"},{"id":3156,"en":"first floor","ja":"2階\n英国では2階・米国では1階を指す","level":6,"lnum":1,"ex":"The library is located on the first floor of the building.","exja":"図書館は建物の1階にある。"},{"id":3157,"en":"first lady","ja":"ファーストレディー\n国家元首の妻","level":6,"lnum":1,"ex":"The first lady gave a speech about the importance of education.","exja":"ファーストレディーは教育の重要性についてスピーチを行った。"},{"id":3158,"en":"fitness","ja":"体力・健康\n体が健康で良い状態に保たれていること","level":6,"lnum":1,"ex":"Regular exercise is important for maintaining good fitness.","exja":"定期的な運動は良い体力を維持するために重要だ。"},{"id":3159,"en":"fix","ja":"修理する\n壊れたものを直す・決定する","level":6,"lnum":1,"ex":"The technician came to fix the broken heating system.","exja":"技術者は壊れた暖房システムを修理しに来た。"},{"id":3160,"en":"flash","ja":"派手な\n目立つほど華やかでゴージャスな","level":6,"lnum":1,"ex":"Her dress was too flash for the casual dinner party.","exja":"彼女のドレスはカジュアルなディナーパーティーには派手すぎた。"},{"id":3161,"en":"flat","ja":"平らな\n凹凸がない・英国でマンションの一室","level":6,"lnum":1,"ex":"She rented a small flat in the center of the city.","exja":"彼女は市内中心部に小さなアパートを借りた。"},{"id":3162,"en":"float","ja":"浮かぶ\n水や空気の上に沈まずに漂う","level":6,"lnum":1,"ex":"The colorful balloons floated up into the clear blue sky.","exja":"カラフルな風船が澄んだ青い空へ浮かび上がった。"},{"id":3163,"en":"flock","ja":"群れ\n鳥や羊などが集まったグループ","level":6,"lnum":1,"ex":"A flock of birds flew south for the winter.","exja":"鳥の群れが冬のために南へ飛んでいった。"},{"id":3164,"en":"flow","ja":"流れ\n水や情報などが一方向に動くこと","level":6,"lnum":1,"ex":"Water flows naturally from higher to lower ground.","exja":"水は自然に高い土地から低い土地へ流れる。"},{"id":3165,"en":"flow","ja":"流れる\n液体や情報が滑らかに動く","level":6,"lnum":1},{"id":3166,"en":"flu","ja":"インフルエンザ\ninfluenzaの略。発熱・筋肉痛を伴う感染症","level":6,"lnum":1,"ex":"She stayed home from work because she had the flu.","exja":"インフルエンザにかかったので彼女は仕事を休んだ。"},{"id":3167,"en":"fluent","ja":"流暢な\n言語をなめらかに話せる状態","level":6,"lnum":1,"ex":"After two years in Japan, he became fluent in Japanese.","exja":"日本での2年間で彼は日本語が流暢になった。"},{"id":3168,"en":"flunk","ja":"落第する\n試験や科目に落ちる口語的な表現","level":6,"lnum":1,"ex":"He was afraid he might flunk the final exam if he didn't study more.","exja":"もっと勉強しなければ期末試験に落第するかもしれないと彼は心配した。"},{"id":3169,"en":"folk","ja":"民衆\n一般の人々・伝統的な文化を指す","level":6,"lnum":1,"ex":"The old folk songs from this region are beautiful and full of history.","exja":"この地域の古い民謡は美しく歴史に満ちている。"},{"id":3170,"en":"fond","ja":"好きな\nbe fond ofで「〜が好き」の穏やかな表現","level":6,"lnum":1,"ex":"She is very fond of spending time with her grandchildren.","exja":"彼女は孫と過ごすことがとても好きだ。"},{"id":3171,"en":"fondness","ja":"好意\n人や物への温かくて穏やかな愛着","level":6,"lnum":1,"ex":"He has a great fondness for classical music and listens to it every day.","exja":"彼はクラシック音楽をとても好み、毎日聴いている。"},{"id":3172,"en":"fool","ja":"だます\n相手をうまく信じ込ませてだます","level":6,"lnum":1,"ex":"Don't let anyone fool you into buying something you don't need.","exja":"必要のないものを買わされるようにだまされてはいけない。"},{"id":3173,"en":"forbidden","ja":"禁じられた\n規則や権威によって許可されていない","level":6,"lnum":1,"ex":"Taking photographs inside the museum is strictly forbidden.","exja":"博物館内での撮影は厳しく禁じられている。"},{"id":3174,"en":"form","ja":"形成する\n新しい形や組織を作り上げる","level":6,"lnum":1,"ex":"Ice forms when the temperature drops below zero degrees.","exja":"気温がゼロ度以下に下がると氷が形成される。"},{"id":3175,"en":"formal","ja":"正式な\n公式の場にふさわしい礼儀正しい","level":6,"lnum":1,"ex":"You should wear formal clothes to the job interview.","exja":"就職面接にはフォーマルな服を着るべきだ。"},{"id":3176,"en":"formally","ja":"正式に\n公式の手続きや形式に従って","level":6,"lnum":1,"ex":"He was formally introduced to the board of directors at the meeting.","exja":"彼は会議で取締役会に正式に紹介された。"},{"id":3177,"en":"format","ja":"形式\n文書やデータの配置・構成の仕方","level":6,"lnum":1,"ex":"The teacher asked students to format their essays in a specific way.","exja":"先生は生徒にエッセイを特定の形式で整えるよう求めた。"},{"id":3178,"en":"format","ja":"フォーマットする\nデータを使えるよう初期化・整形する","level":6,"lnum":1},{"id":3179,"en":"former","ja":"以前の\n現在ではなく過去のその立場の","level":6,"lnum":1,"ex":"The former president gave a speech at the university graduation ceremony.","exja":"元大統領は大学の卒業式でスピーチを行った。"},{"id":3180,"en":"formula","ja":"公式\n数学や化学の法則を表した式","level":6,"lnum":1,"ex":"The scientist wrote the chemical formula on the whiteboard.","exja":"科学者はホワイトボードに化学式を書いた。"},{"id":3181,"en":"forth","ja":"前へ\nand so forthで「などなど」の意味でも使う","level":6,"lnum":1,"ex":"She set forth on her journey to discover new opportunities.","exja":"彼女は新しいチャンスを求めて旅に出発した。"},{"id":3182,"en":"fortnight","ja":"2週間\n14日間を表す英国でよく使う表現","level":6,"lnum":1,"ex":"They planned to stay at the seaside resort for a fortnight.","exja":"彼らは2週間海辺のリゾートに滞在する計画を立てた。"},{"id":3183,"en":"fortunate","ja":"幸運な\n良いことが起きてラッキーな状態","level":6,"lnum":1,"ex":"We are very fortunate to live in such a peaceful neighborhood.","exja":"私たちはとても平和な近所に住めて非常に幸運だ。"},{"id":3184,"en":"foundation","ja":"基盤・財団\n物事の土台・慈善活動の組織","level":6,"lnum":1,"ex":"Reading and writing are the foundation of all education.","exja":"読み書きはすべての教育の基盤だ。"},{"id":3185,"en":"fragment","ja":"断片\n全体から切り離された小さな部分","level":6,"lnum":1,"ex":"A fragment of ancient pottery was found at the excavation site.","exja":"発掘現場で古代の陶器の断片が見つかった。"},{"id":3186,"en":"freezer","ja":"冷凍庫\n食品を凍らせて保存する電気機器","level":6,"lnum":1,"ex":"She put the leftover soup in the freezer to eat later.","exja":"彼女は残ったスープを後で食べるために冷凍庫に入れた。"},{"id":3187,"en":"freezing","ja":"凍えるほど寒い\n非常に冷たい・凍るような温度","level":6,"lnum":1,"ex":"It was freezing outside, so she put on her warmest coat.","exja":"外は凍えるほど寒かったので、彼女は最も暖かいコートを着た。"},{"id":3188,"en":"frequency","ja":"頻度\nある出来事が起こる回数の多さ","level":6,"lnum":1,"ex":"The frequency of buses on this route increases during rush hours.","exja":"このルートのバスの頻度はラッシュアワーに増加する。"},{"id":3189,"en":"frequent","ja":"頻繁な\n何度もよく起こる状態","level":6,"lnum":1,"ex":"She makes frequent visits to the library to find books for her research.","exja":"彼女は研究のための本を見つけるために図書館をよく訪れる。"},{"id":3190,"en":"frequently","ja":"頻繁に\n何度も繰り返して・よく","level":6,"lnum":1,"ex":"He frequently checks his email to make sure he doesn't miss any messages.","exja":"彼はメッセージを見逃さないようにメールを頻繁に確認する。"},{"id":3191,"en":"freshman","ja":"新入生\n大学や高校の1年生","level":6,"lnum":1,"ex":"As a freshman, she was nervous about starting high school.","exja":"新入生として、彼女は高校を始めることに緊張していた。"},{"id":3192,"en":"friendliness","ja":"友好的な態度\n親切で親しみやすい性格や様子","level":6,"lnum":1,"ex":"Her friendliness made it easy for new students to feel welcome.","exja":"彼女の友好的な態度は新しい生徒が歓迎されていると感じやすくした。"},{"id":3193,"en":"fright","ja":"恐怖\n突然の驚きや恐れ","level":6,"lnum":1,"ex":"The sudden sound of thunder gave the small child a terrible fright.","exja":"突然の雷の音が小さな子どもをひどく怖がらせた。"},{"id":3194,"en":"frost","ja":"霜\n気温が低下して地面に降りる氷の結晶","level":6,"lnum":1,"ex":"There was frost on the grass every morning during the cold winter.","exja":"寒い冬の間、毎朝芝生に霜が降りていた。"},{"id":3195,"en":"frozen","ja":"凍った\n液体が固体になるほど冷えた状態","level":6,"lnum":1,"ex":"The pond was frozen solid, and children skated on it safely.","exja":"池は完全に凍り、子どもたちは安全にその上でスケートをした。"},{"id":3196,"en":"frustration","ja":"欲求不満\n思い通りにならないイライラ感","level":6,"lnum":1,"ex":"She expressed her frustration when the computer crashed again.","exja":"コンピューターがまたクラッシュしたとき、彼女は欲求不満を表した。"},{"id":3197,"en":"fry","ja":"揚げる・炒める\n油で食材を調理する","level":6,"lnum":1,"ex":"He fried eggs and bacon for breakfast every Sunday morning.","exja":"彼は毎週日曜日の朝食に卵とベーコンを炒めた。"},{"id":3198,"en":"frying pan","ja":"フライパン\n平らな底の調理用の鍋","level":6,"lnum":1,"ex":"She heated the oil in the frying pan before adding the vegetables.","exja":"彼女は野菜を加える前にフライパンで油を熱した。"},{"id":3199,"en":"fuel","ja":"燃料\nエネルギーを得るために燃やす物質","level":6,"lnum":1,"ex":"The car ran out of fuel on the way to the airport.","exja":"車は空港に向かう途中で燃料切れになった。"},{"id":3200,"en":"full stop","ja":"ピリオド\n文末に使う「.」の英国での呼び方","level":6,"lnum":1,"ex":"In British English, a period at the end of a sentence is called a full stop.","exja":"英国英語では、文末のピリオドはフルストップと呼ばれる。"},{"id":3201,"en":"full-time","ja":"フルタイムの\n週5日・1日8時間の正規勤務","level":6,"lnum":1,"ex":"She decided to take a full-time job after finishing her studies.","exja":"彼女は学業を終えた後、フルタイムの仕事に就くことにした。"},{"id":3202,"en":"function","ja":"機能\n物や人が果たす役割や働き","level":6,"lnum":1,"ex":"The main function of the lungs is to supply oxygen to the blood.","exja":"肺の主な機能は血液に酸素を供給することだ。"},{"id":3203,"en":"fund","ja":"資金\n特定の目的のために集められたお金","level":6,"lnum":1,"ex":"The charity raised enough money to fund a new community center.","exja":"慈善団体は新しいコミュニティセンターに資金を提供するのに十分なお金を集めた。"},{"id":3204,"en":"fund","ja":"資金提供する\nプロジェクトにお金を出して支援する","level":6,"lnum":1},{"id":3205,"en":"funeral","ja":"葬儀\n亡くなった人を弔う式典","level":6,"lnum":1,"ex":"Hundreds of people attended the funeral to pay their respects.","exja":"何百人もの人々が敬意を表するために葬儀に参列した。"},{"id":3206,"en":"fur","ja":"毛皮\n動物の体を覆う密集した柔らかい毛","level":6,"lnum":1,"ex":"The cat has soft white fur that is pleasant to touch.","exja":"その猫は触ると気持ちの良い柔らかい白い毛皮を持っている。"},{"id":3207,"en":"furnish","ja":"家具を備える\n部屋に家具を設置してそろえる","level":6,"lnum":1,"ex":"They furnished the new apartment with simple but comfortable furniture.","exja":"彼らは新しいアパートをシンプルだが快適な家具で備えた。"},{"id":3208,"en":"further","ja":"さらに遠く\n距離・程度・議論を先に進める","level":6,"lnum":1,"ex":"The scientist decided to investigate the matter further before publishing.","exja":"科学者は発表する前にさらに詳しく問題を調査することにした。"},{"id":3209,"en":"furthermore","ja":"さらに加えて\n前の主張に新しい論拠を追加する接続副詞","level":6,"lnum":1,"ex":"She is talented; furthermore, she works harder than anyone else.","exja":"彼女は才能があり、さらに加えて誰よりも一生懸命働く。"},{"id":3210,"en":"furthest","ja":"最も遠い\n距離・程度が最も大きい状態","level":6,"lnum":1,"ex":"The furthest he had ever traveled from home was to another continent.","exja":"彼が家から旅したことのある最も遠い場所は別の大陸だった。"},{"id":3211,"en":"fuss","ja":"大騒ぎ\n小さなことを大げさに騒ぎ立てること","level":6,"lnum":1,"ex":"He made a big fuss about the small scratch on his new car.","exja":"彼は新しい車の小さな傷について大騒ぎした。"},{"id":3212,"en":"gain","ja":"利益・増加\n得ること・体重や速度の増加","level":6,"lnum":1,"ex":"She gained valuable experience working at the hospital last summer.","exja":"彼女は昨年の夏に病院で働いて貴重な経験を得た。"},{"id":3213,"en":"gain","ja":"得る\n努力によって何かを手に入れる","level":6,"lnum":1},{"id":3214,"en":"gall","ja":"厚かましさ\n失礼なほど図々しい態度","level":6,"lnum":1,"ex":"He had the gall to ask for a refund after using the product for a year.","exja":"彼は1年間製品を使った後に返金を求める厚かましさがあった。"},{"id":3215,"en":"gallon","ja":"ガロン\n約3.8リットル（米）または4.5リットル（英）","level":6,"lnum":1,"ex":"The car's fuel tank holds about fifteen gallons of gasoline.","exja":"その車の燃料タンクは約15ガロンのガソリンを入れられる。"},{"id":3216,"en":"gardening","ja":"ガーデニング\n庭の手入れや植物を育てる趣味","level":6,"lnum":1,"ex":"Gardening is a relaxing hobby that also keeps you physically active.","exja":"ガーデニングはリラックスできる趣味であり、体も活発に保つ。"},{"id":3217,"en":"garment","ja":"衣服\n着用する衣類全般のフォーマルな表現","level":6,"lnum":1,"ex":"The factory produces thousands of garments every day for export.","exja":"その工場は毎日輸出用に何千枚もの衣服を生産している。"},{"id":3218,"en":"gay","ja":"ゲイの\n同性愛者の・陽気なの古い意味も","level":6,"lnum":1,"ex":"She has many gay friends and fully supports equal rights for everyone.","exja":"彼女にはゲイの友人がたくさんおり、すべての人の平等な権利を全面的に支持している。"},{"id":3219,"en":"gee","ja":"ああ・わあ\n驚きや感心を表す米国の感嘆詞","level":6,"lnum":1,"ex":"Gee, I had no idea that the concert tickets were so expensive.","exja":"わあ、コンサートのチケットがそんなに高いとは知らなかった。"},{"id":3220,"en":"gene","ja":"遺伝子\n親から子に伝わる遺伝情報の単位","level":6,"lnum":1,"ex":"Scientists discovered a gene that may be linked to certain types of cancer.","exja":"科学者たちは特定の種類のがんと関連している可能性のある遺伝子を発見した。"},{"id":3221,"en":"general","ja":"一般的な\n特定ではなく広く当てはまる","level":6,"lnum":1,"ex":"In general, students who study regularly tend to do well on exams.","exja":"一般的に、定期的に勉強する生徒は試験でうまくいく傾向がある。"},{"id":3222,"en":"general","ja":"将軍\n軍の最高位の指揮官","level":6,"lnum":1},{"id":3223,"en":"generate","ja":"生み出す\nエネルギーやアイデアを作り出す","level":6,"lnum":1,"ex":"Wind turbines generate electricity from the power of the wind.","exja":"風力タービンは風の力から電気を生み出す。"},{"id":3224,"en":"generous","ja":"寛大な\n惜しみなく与える・心が広い","level":6,"lnum":1,"ex":"She was generous enough to share her lunch with her classmate.","exja":"彼女はクラスメートと昼食を分け合うほど寛大だった。"},{"id":3225,"en":"genetic","ja":"遺伝の\n遺伝子や遺伝に関係する","level":6,"lnum":1,"ex":"The researchers found a genetic link between the two diseases.","exja":"研究者たちは2つの病気の間の遺伝的なつながりを発見した。"},{"id":3226,"en":"genetically","ja":"遺伝的に\n遺伝子レベルで・遺伝によって","level":6,"lnum":1,"ex":"Some people are genetically predisposed to certain health conditions.","exja":"一部の人は特定の健康状態に遺伝的にかかりやすい。"},{"id":3227,"en":"genetics","ja":"遺伝学\n遺伝の仕組みを研究する科学","level":6,"lnum":1,"ex":"Advances in genetics have made it possible to detect diseases early.","exja":"遺伝学の進歩によって病気を早期に発見することが可能になった。"},{"id":3228,"en":"geographical","ja":"地理的な\n地理や地形に関連する形容詞","level":6,"lnum":1,"ex":"The geographical location of the country gives it a mild climate.","exja":"その国の地理的な位置は穏やかな気候をもたらしている。"},{"id":3229,"en":"geography","ja":"地理学\n地球の地形・気候・人口を研究する学問","level":6,"lnum":1,"ex":"We studied the geography of South America in our social studies class.","exja":"私たちは社会科の授業で南アメリカの地理を学んだ。"},{"id":3230,"en":"geology","ja":"地質学\n地球の岩石や地層を研究する学問","level":6,"lnum":1,"ex":"The geology of this region reveals millions of years of Earth's history.","exja":"この地域の地質学は何百万年もの地球の歴史を明らかにしている。"},{"id":3231,"en":"gifted","ja":"才能ある\n生まれつき特別な才能を持つ","level":6,"lnum":1,"ex":"The gifted student was invited to join the advanced science program.","exja":"その才能ある生徒は上級理科プログラムに参加するよう招かれた。"},{"id":3232,"en":"giggle","ja":"くすくす笑う\n楽しさや照れから出る軽い笑い","level":6,"lnum":1,"ex":"The girls giggled when the teacher mispronounced a word in class.","exja":"先生が授業で単語を発音し間違えたとき、女の子たちはくすくす笑った。"},{"id":3233,"en":"glance","ja":"ちら見\n素早くさっと見ること","level":6,"lnum":1,"ex":"She glanced at her watch and realized she was late for the meeting.","exja":"彼女は時計をちらりと見て会議に遅れていると気づいた。"},{"id":3234,"en":"glance","ja":"ちらりと見る\n短時間に素早く目を向ける","level":6,"lnum":1},{"id":3235,"en":"glide","ja":"滑空\nなめらかに音なく進む・滑る動き","level":6,"lnum":1,"ex":"The swan glided gracefully across the surface of the lake.","exja":"白鳥は湖の水面を優雅に滑空した。"},{"id":3236,"en":"glimpse","ja":"垣間見る\nわずかな時間だけ見えること","level":6,"lnum":1,"ex":"She caught a glimpse of the actor as he walked past the crowd.","exja":"俳優が群衆の前を通り過ぎたとき、彼女は彼を一目見た。"},{"id":3237,"en":"glint","ja":"きらめき\n光が反射してきらっと光る瞬間","level":6,"lnum":1,"ex":"The diamond ring glinted in the sunlight as she held it up.","exja":"彼女が指輪を掲げると、ダイヤモンドの指輪が日光できらめいた。"},{"id":3238,"en":"glorious","ja":"素晴らしい\n非常に印象的で輝かしい","level":6,"lnum":1,"ex":"The mountains looked glorious in the early morning sunlight.","exja":"山々は朝の日光の中で輝かしく見えた。"},{"id":3239,"en":"glory","ja":"栄光\n誰もが称賛するような輝かしい名誉","level":6,"lnum":1,"ex":"The athlete received great glory after winning the gold medal.","exja":"その選手は金メダルを獲得した後、大きな栄光を受けた。"},{"id":3240,"en":"goalkeeper","ja":"ゴールキーパー\nゴールを守るサッカーのポジション","level":6,"lnum":1,"ex":"The goalkeeper made an amazing save in the final minute of the match.","exja":"ゴールキーパーは試合の最後の1分に素晴らしいセーブをした。"},{"id":3241,"en":"goddess","ja":"女神\n神話や宗教に登場する女性の神","level":6,"lnum":1,"ex":"Athena was the ancient Greek goddess of wisdom and war.","exja":"アテナは古代ギリシャの知恵と戦の女神だった。"},{"id":3242,"en":"golfer","ja":"ゴルファー\nゴルフをする人・競技選手","level":6,"lnum":1,"ex":"The famous golfer won three major tournaments in a single year.","exja":"その有名なゴルファーは1年間に3つのメジャートーナメントで優勝した。"},{"id":3243,"en":"goodness","ja":"なんてこった\n驚きを表す感嘆詞・善良さの意味も","level":6,"lnum":1,"ex":"Goodness, I can't believe how much you've grown since I last saw you!","exja":"なんてこった、前回会ってからどれほど大きくなったか信じられない！"},{"id":3244,"en":"gorgeous","ja":"とても美しい\n見た目が素晴らしくて目を引く","level":6,"lnum":1,"ex":"The bride looked absolutely gorgeous in her white wedding dress.","exja":"花嫁は白いウェディングドレスを着て絶対的に美しかった。"},{"id":3245,"en":"gossip","ja":"うわさ話\n他人の私生活についての軽率なおしゃべり","level":6,"lnum":1,"ex":"She tries to avoid gossip and prefers to focus on positive things.","exja":"彼女はうわさ話を避け、ポジティブなことに集中することを好む。"},{"id":3246,"en":"govern","ja":"統治する\n国や組織を管理・支配する","level":6,"lnum":1,"ex":"A good leader must govern fairly and with the interests of all citizens in mind.","exja":"良い指導者はすべての市民の利益を念頭に置いて公平に統治しなければならない。"},{"id":3247,"en":"governor","ja":"知事・総督\n州や地域の最高行政責任者","level":6,"lnum":1,"ex":"The governor announced a new plan to improve public transportation.","exja":"知事は公共交通機関を改善する新計画を発表した。"},{"id":3248,"en":"gown","ja":"ガウン・ドレス\n正式な場や式典用の長いドレス","level":6,"lnum":1,"ex":"She wore a beautiful evening gown to the formal dinner party.","exja":"彼女は正式なディナーパーティーに美しいイブニングドレスを着た。"},{"id":3249,"en":"grab","ja":"つかむ\n急いで勢いよく手でとらえる","level":6,"lnum":1,"ex":"He grabbed his bag and rushed out the door to catch the bus.","exja":"彼はバスに乗るためにバッグをつかんでドアから急いで出た。"},{"id":3250,"en":"graceful","ja":"優雅な\n動きや外見がしなやかで品がある","level":6,"lnum":1,"ex":"The ballet dancer was graceful as she moved across the stage.","exja":"バレエダンサーは舞台を横切るときに優雅だった。"},{"id":3251,"en":"grant","ja":"補助金\n政府や団体が与える資金援助","level":6,"lnum":1,"ex":"The university granted her a scholarship to continue her studies.","exja":"大学は彼女に研究を続けるための奨学金を与えた。"},{"id":3252,"en":"grant","ja":"認める\n公式に許可や権利を与える","level":6,"lnum":1},{"id":3253,"en":"graphic","ja":"グラフィックの\n視覚的に表現された・鮮明な描写","level":6,"lnum":1,"ex":"The documentary contained some graphic images of the aftermath of the war.","exja":"そのドキュメンタリーには戦争の余波に関するいくつかの鮮明な映像が含まれていた。"},{"id":3254,"en":"graphics","ja":"グラフィックス\nコンピューターや印刷の視覚的な画像","level":6,"lnum":1,"ex":"The new video game features stunning graphics that look very realistic.","exja":"新しいビデオゲームは非常にリアルに見える見事なグラフィックスを特徴としている。"},{"id":3255,"en":"gratitude","ja":"感謝の気持ち\n受けた恩に対する深い感謝","level":6,"lnum":1,"ex":"She expressed her gratitude by sending a handwritten thank-you note.","exja":"彼女は手書きのお礼状を送ることで感謝の気持ちを表した。"},{"id":3256,"en":"grave","ja":"墓\n遺体を埋葬した場所","level":6,"lnum":1,"ex":"They placed flowers on the grave of the soldier who died in the war.","exja":"彼らは戦争で亡くなった兵士の墓に花を置いた。"},{"id":3257,"en":"gravy","ja":"グレービーソース\n肉汁を使ったトロミのあるソース","level":6,"lnum":1,"ex":"She poured rich gravy over the roast chicken and vegetables.","exja":"彼女はローストチキンと野菜の上にコクのあるグレービーソースをかけた。"},{"id":3258,"en":"greenhouse","ja":"温室\n植物を育てるガラス張りの建物","level":6,"lnum":1,"ex":"The farmer grew tomatoes and peppers in a large greenhouse.","exja":"農家は大きな温室でトマトとピーマンを育てた。"},{"id":3259,"en":"groom","ja":"花婿・手入れする\n結婚式の新郎・体の手入れをする","level":6,"lnum":1,"ex":"The groom smiled nervously as he waited at the altar for his bride.","exja":"花婿は花嫁を待つために祭壇で緊張しながら微笑んだ。"},{"id":3260,"en":"ground floor","ja":"1階\n英国での建物の1番下の階","level":6,"lnum":1,"ex":"The reception desk is located on the ground floor of the hotel.","exja":"受付は1階に位置している。"},{"id":3261,"en":"grouping","ja":"グループ分け\n共通点をもとにまとめること","level":6,"lnum":1,"ex":"The teacher created groupings based on students' learning levels.","exja":"先生は生徒の学習レベルに基づいてグループ分けを行った。"},{"id":3262,"en":"growth","ja":"成長\n大きくなること・経済や生物の発展","level":6,"lnum":1,"ex":"The rapid growth of the city led to a need for more housing.","exja":"都市の急速な成長はより多くの住宅への需要につながった。"},{"id":3263,"en":"guarantee","ja":"保証\n約束を確実に守ること・品質保証書","level":6,"lnum":1,"ex":"The company offers a two-year guarantee on all its products.","exja":"その会社はすべての製品に2年間の保証を提供している。"},{"id":3264,"en":"guidance","ja":"指導\n正しい方向に導くアドバイス","level":6,"lnum":1,"ex":"The student sought guidance from her teacher before choosing a career.","exja":"生徒はキャリアを選ぶ前に先生に指導を求めた。"},{"id":3265,"en":"guilt","ja":"罪悪感\n悪いことをしたという後ろめたさ","level":6,"lnum":1,"ex":"He felt deep guilt for not helping his friend when he needed it most.","exja":"最も必要なときに友人を助けなかったことに深い罪悪感を感じた。"},{"id":3266,"en":"guilty","ja":"有罪の\n罪を犯した・後ろめたく感じる","level":6,"lnum":1,"ex":"The jury found the man guilty of stealing from the store.","exja":"陪審員はその男が店から盗んだことに有罪を認定した。"},{"id":3267,"en":"guitarist","ja":"ギタリスト\nギターを演奏する人","level":6,"lnum":1,"ex":"The guitarist played a beautiful solo that impressed the entire audience.","exja":"ギタリストは観客全員を感動させる美しいソロを演奏した。"},{"id":3268,"en":"habitat","ja":"生息地\n動植物が自然に暮らす環境","level":6,"lnum":1,"ex":"Deforestation is destroying the natural habitat of many animals.","exja":"森林伐採は多くの動物の自然な生息地を破壊している。"},{"id":3269,"en":"hairdresser","ja":"美容師\n髪を切ったりスタイリングする専門家","level":6,"lnum":1,"ex":"She made an appointment at the hairdresser to cut her hair before the party.","exja":"彼女はパーティー前に髪を切るために美容師の予約を取った。"},{"id":3270,"en":"hairdryer","ja":"ドライヤー\n髪を乾かす電気機器","level":6,"lnum":1,"ex":"She dried her wet hair quickly with a powerful hairdryer.","exja":"彼女は強力なドライヤーで濡れた髪をすばやく乾かした。"},{"id":3271,"en":"hammer","ja":"ハンマー\n釘を打つための重い工具","level":6,"lnum":1,"ex":"He used a hammer to hang a picture on the wall.","exja":"彼は壁に絵を掛けるためにハンマーを使った。"},{"id":3272,"en":"hand-held","ja":"手持ちの\n片手で持って操作できる機器","level":6,"lnum":1,"ex":"She used a hand-held camera to record the school festival.","exja":"彼女は学校祭を録画するために手持ちカメラを使った。"},{"id":3273,"en":"handshake","ja":"握手\n挨拶や合意を表す右手を握り合う動作","level":6,"lnum":1,"ex":"They sealed the deal with a firm handshake.","exja":"彼らはしっかりとした握手で取引を確定した。"},{"id":3274,"en":"handwriting","ja":"手書き\nペンなどで手で書かれた文字のスタイル","level":6,"lnum":1,"ex":"His handwriting is so neat that it looks like it was printed.","exja":"彼の手書きはとても丁寧で印刷されたように見える。"},{"id":3275,"en":"handy","ja":"便利な\n使いやすく役に立つ","level":6,"lnum":1,"ex":"A pocket dictionary is handy when you are learning a new language.","exja":"ポケット辞書は新しい言語を学ぶときに便利だ。"},{"id":3276,"en":"hanging","ja":"ぶら下がった\n上部に固定されて垂れ下がった状態","level":6,"lnum":1,"ex":"There was a beautiful painting hanging on the wall of the living room.","exja":"リビングの壁に美しい絵がぶら下がっていた。"},{"id":3277,"en":"harbor","ja":"港・かくまう\n船が停泊する場所・秘密を持ち続ける","level":6,"lnum":1,"ex":"The fishing boats returned to the harbor after a long day at sea.","exja":"漁船は長い一日の後、港に戻ってきた。"},{"id":3278,"en":"hardship","ja":"苦難\n生活上の困難や経済的な苦しさ","level":6,"lnum":1,"ex":"Many families experienced great hardship during the economic crisis.","exja":"経済危機の間、多くの家族が大きな苦難を経験した。"},{"id":3279,"en":"hard-working","ja":"勤勉な\n一生懸命働く・怠けない性格","level":6,"lnum":1,"ex":"She is a hard-working student who spends hours studying every night.","exja":"彼女は毎晩何時間も勉強する勤勉な生徒だ。"},{"id":3280,"en":"harness","ja":"利用する\nエネルギーや能力を有効に活用する","level":6,"lnum":1,"ex":"We need to harness the power of the sun to create clean energy.","exja":"清潔なエネルギーを作るために太陽の力を利用する必要がある。"},{"id":3281,"en":"hasty","ja":"早まった\n十分に考えずに急いで行動する","level":6,"lnum":1,"ex":"He made a hasty decision and later regretted it.","exja":"彼は早まった決断をして後で後悔した。"},{"id":3282,"en":"hatch","ja":"ハッチ・ふ化する\n卵から生まれる・屋根や床の小扉","level":6,"lnum":1,"ex":"The baby chicks hatched from their eggs on a warm spring morning.","exja":"暖かい春の朝にひよこが卵からふ化した。"},{"id":3283,"en":"hatred","ja":"憎しみ\n強い嫌悪と敵意の感情","level":6,"lnum":1,"ex":"His hatred for injustice motivated him to become a human rights lawyer.","exja":"不正への憎しみが彼を人権弁護士になる動機づけた。"},{"id":3284,"en":"haunt","ja":"取りつく\n幽霊が出る・嫌な記憶が頭から離れない","level":6,"lnum":1,"ex":"The memory of that terrible accident still haunts him.","exja":"あの恐ろしい事故の記憶が今でも彼の頭から離れない。"},{"id":3285,"en":"haven","ja":"安全な場所\n危険から保護された避難場所","level":6,"lnum":1,"ex":"The small café became a haven for students looking for a quiet place to study.","exja":"その小さなカフェは静かな勉強場所を求める学生の安全な場所となった。"},{"id":3286,"en":"hazard","ja":"危険\n事故や損害につながる可能性のあるもの","level":6,"lnum":1,"ex":"Icy roads are a major hazard for drivers in winter.","exja":"凍結した道路は冬にドライバーにとって大きな危険だ。"},{"id":3287,"en":"headline","ja":"見出し\n新聞やニュースの記事タイトル","level":6,"lnum":1,"ex":"The earthquake was the top headline in every major newspaper.","exja":"地震はすべての大手新聞のトップ見出しだった。"},{"id":3288,"en":"heal","ja":"治癒する\n傷や病気が良くなる・心を癒やす","level":6,"lnum":1,"ex":"It took several weeks for the broken bone to heal completely.","exja":"骨折が完全に治癒するのに数週間かかった。"},{"id":3289,"en":"healing","ja":"癒やしの\n心身の回復を助ける効果がある","level":6,"lnum":1,"ex":"Music can have a powerful healing effect on people who are feeling sad.","exja":"音楽は悲しんでいる人々に強力な癒やしの効果をもたらすことがある。"},{"id":3290,"en":"hearing","ja":"聴覚・聴取\n音を聞く能力・法廷での公聴会","level":6,"lnum":1,"ex":"His hearing has become weak, so he uses a hearing aid.","exja":"聴覚が弱くなったので彼は補聴器を使っている。"},{"id":3291,"en":"heart attack","ja":"心臓発作\n心臓の血流が止まる緊急の病状","level":6,"lnum":1,"ex":"He was rushed to the hospital after suffering a sudden heart attack.","exja":"突然の心臓発作に見舞われ、彼は急いで病院に運ばれた。"},{"id":3292,"en":"hearted","ja":"〜心の\n接尾辞として kind-hearted などに使う","level":6,"lnum":1,"ex":"She is a kind-hearted person who always thinks of others before herself.","exja":"彼女は自分より先に他人のことを考える優しい心の人だ。"},{"id":3293,"en":"hearty","ja":"心からの\n温かく誠実で元気のいい","level":6,"lnum":1,"ex":"They gave the returning athletes a hearty welcome at the airport.","exja":"彼らは帰国した選手たちを空港で心からの歓迎でもてなした。"},{"id":3294,"en":"heavenly","ja":"天国のような\n非常に美しく幸せな状態","level":6,"lnum":1,"ex":"The chocolate cake tasted absolutely heavenly.","exja":"チョコレートケーキは天国のような味がした。"},{"id":3295,"en":"heel","ja":"かかと\n足の後部・靴の踵部分","level":6,"lnum":1,"ex":"She hurt her heel while running in shoes that didn't fit well.","exja":"合わない靴で走っていてかかとを痛めた。"},{"id":3296,"en":"height","ja":"高さ\n地面から頂点までの距離・身長","level":6,"lnum":1,"ex":"The height of the building is over two hundred meters.","exja":"その建物の高さは200メートルを超える。"},{"id":3297,"en":"helpless","ja":"無力な\n自分では何もできない状態","level":6,"lnum":1,"ex":"He felt completely helpless when he saw the accident but had no phone to call for help.","exja":"事故を見たが助けを呼ぶ電話もなく、彼は完全に無力感を感じた。"},{"id":3298,"en":"herd","ja":"群れ\n牛など大型動物の集まり","level":6,"lnum":1,"ex":"A large herd of cattle grazed peacefully in the green meadow.","exja":"大きな牛の群れが緑の牧草地で穏やかに草を食んでいた。"},{"id":3299,"en":"hesitate","ja":"ためらう\n決断できずに一時止まる","level":6,"lnum":1,"ex":"Don't hesitate to ask for help if you don't understand the lesson.","exja":"授業が理解できなければためらわずに助けを求めてください。"},{"id":3300,"en":"hidden","ja":"隠された\n見えないよう隠れている状態","level":6,"lnum":1,"ex":"The treasure was hidden beneath the old oak tree in the garden.","exja":"宝は庭の古いオークの木の下に隠されていた。"},{"id":3301,"en":"highlight","ja":"強調する\n重要な部分を目立たせる","level":6,"lnum":1,"ex":"The teacher highlighted the most important points of the lesson.","exja":"先生は授業の最も重要な点を強調した。"},{"id":3302,"en":"highly","ja":"非常に\n程度が大きいことを示す強調の副詞","level":6,"lnum":1,"ex":"She is highly respected by all her colleagues at work.","exja":"彼女は職場のすべての同僚から非常に尊敬されている。"},{"id":3303,"en":"hip","ja":"腰・ヒップ\n体の腰まわりの骨格部分","level":6,"lnum":1,"ex":"He injured his hip during the football match and had to rest.","exja":"彼はサッカーの試合中に腰を痛めて休まなければならなかった。"},{"id":3304,"en":"hire","ja":"雇う\n仕事のために人やものを使う契約をする","level":6,"lnum":1,"ex":"The restaurant decided to hire more staff for the busy summer season.","exja":"レストランは夏の繁忙期のためにさらに多くのスタッフを雇うことにした。"},{"id":3305,"en":"historian","ja":"歴史家\n歴史を研究・記録する専門家","level":6,"lnum":1,"ex":"The historian spent years researching the events of World War II.","exja":"歴史家は第二次世界大戦の出来事を調査するのに何年もかけた。"},{"id":3306,"en":"historic","ja":"歴史的な\n重要な歴史的意義を持つ出来事","level":6,"lnum":1,"ex":"The signing of the peace agreement was a truly historic moment.","exja":"平和協定の署名は真に歴史的な瞬間だった。"},{"id":3307,"en":"HIV","ja":"HIV\n免疫を破壊するウイルスの略称","level":6,"lnum":1},{"id":3308,"en":"holy","ja":"神聖な\n宗教的に清らかで崇敬される","level":6,"lnum":1,"ex":"Millions of pilgrims travel to the holy city every year.","exja":"毎年何百万人もの巡礼者が聖地を訪れる。"},{"id":3309,"en":"homeless","ja":"ホームレスの\n住む場所を持たない状態","level":6,"lnum":1,"ex":"The charity provides food and shelter for homeless people in the city.","exja":"その慈善団体は市のホームレスの人々に食料と住居を提供している。"},{"id":3310,"en":"honestly","ja":"正直に\n嘘なく真実を述べる様子","level":6,"lnum":1,"ex":"She honestly told her friend that the dress didn't suit her.","exja":"彼女はそのドレスが似合わないと友人に正直に伝えた。"},{"id":3311,"en":"honeymoon","ja":"新婚旅行\n結婚直後のカップルの旅行","level":6,"lnum":1,"ex":"They spent their honeymoon on a beautiful tropical island.","exja":"彼らは美しい南国の島で新婚旅行を過ごした。"},{"id":3312,"en":"hop","ja":"ひょこりと跳ぶ\n片足または両足で軽く跳ぶ動作","level":6,"lnum":1,"ex":"The rabbit hopped across the garden and disappeared into the bushes.","exja":"ウサギは庭を跳んで藪の中に消えた。"},{"id":3313,"en":"hopeful","ja":"希望に満ちた\n良い結果を期待している前向きな状態","level":6,"lnum":1,"ex":"She was hopeful that the interview would lead to a job offer.","exja":"彼女は面接が仕事のオファーにつながることを希望していた。"},{"id":3314,"en":"hopefully","ja":"うまくいけば\n期待を込めた文修飾の副詞","level":6,"lnum":1,"ex":"Hopefully, the weather will improve before the outdoor event starts.","exja":"屋外イベントが始まる前に天気が改善することを期待している。"},{"id":3315,"en":"horn","ja":"角・クラクション\n動物の角または車のクラクション","level":6,"lnum":1,"ex":"The driver honked the horn to warn the cyclist on the road.","exja":"ドライバーは道路上の自転車乗りに警告するためにクラクションを鳴らした。"},{"id":3316,"en":"horrible","ja":"恐ろしい\n非常に不快で嫌な状態・口語でも頻出","level":6,"lnum":1,"ex":"The smell from the garbage can was absolutely horrible.","exja":"ゴミ箱からの臭いはまったく恐ろしかった。"},{"id":3317,"en":"horrify","ja":"ぞっとさせる\n強い恐怖や衝撃を与える","level":6,"lnum":1,"ex":"The graphic images in the news report horrified many viewers.","exja":"ニュースレポートの鮮明な画像は多くの視聴者をぞっとさせた。"},{"id":3318,"en":"hostel","ja":"ホステル\n安価な宿泊施設。バックパッカーに人気","level":6,"lnum":1,"ex":"They stayed at a youth hostel to save money while traveling in Europe.","exja":"彼らはヨーロッパ旅行中に節約するためにユースホステルに宿泊した。"},{"id":3319,"en":"household","ja":"世帯\n同じ家に住むグループの単位","level":6,"lnum":1,"ex":"Every household in the neighborhood was invited to the community meeting.","exja":"近所のすべての世帯がコミュニティ会議に招待された。"},{"id":3320,"en":"humanity","ja":"人類・人間性\n人類全体・思いやりの心","level":6,"lnum":1,"ex":"We should treat all people with kindness and respect for their humanity.","exja":"私たちはすべての人を人間性への敬意と優しさで扱うべきだ。"},{"id":3321,"en":"humorous","ja":"ユーモアのある\nおかしくて笑いを生む様子","level":6,"lnum":1,"ex":"The teacher used humorous examples to make the lesson more interesting.","exja":"先生は授業をより面白くするためにユーモアのある例を使った。"},{"id":3322,"en":"hunger","ja":"飢え\n食べ物がなく苦しい状態・強い欲求","level":6,"lnum":1,"ex":"The humanitarian organization works to fight hunger in developing countries.","exja":"その人道支援団体は発展途上国の飢えと戦うために取り組んでいる。"},{"id":3323,"en":"hurriedly","ja":"急いで\n時間がなく急ぎながら行動する様子","level":6,"lnum":1,"ex":"She hurriedly packed her bag because she was late for school.","exja":"学校に遅れていたので彼女は急いでバッグを詰めた。"},{"id":3324,"en":"hut","ja":"小屋\n粗末な作りの簡単な小さな建物","level":6,"lnum":1,"ex":"The hikers took shelter from the rain in a small wooden hut.","exja":"ハイカーたちは小さな木の小屋で雨宿りした。"},{"id":3325,"en":"ice hockey","ja":"アイスホッケー\n氷上でパックを打ち合うスポーツ","level":6,"lnum":1,"ex":"Ice hockey is very popular in Canada and northern Europe.","exja":"アイスホッケーはカナダと北ヨーロッパで非常に人気がある。"},{"id":3326,"en":"ice skating","ja":"アイススケート\n氷の上をスケートで滑るスポーツ","level":6,"lnum":1,"ex":"She loves ice skating and goes to the rink every weekend in winter.","exja":"彼女はアイススケートが大好きで冬は毎週末リンクに行く。"},{"id":3327,"en":"identity","ja":"アイデンティティ\n自分が誰であるかを規定する特性","level":6,"lnum":1,"ex":"A passport is an important document that proves your identity.","exja":"パスポートは身元を証明する重要な書類だ。"},{"id":3328,"en":"identity card","ja":"身分証明書\n本人確認のための公式書類","level":6,"lnum":1,"ex":"She showed her identity card at the entrance to the government building.","exja":"彼女は政府の建物の入口で身分証明書を提示した。"},{"id":3329,"en":"idiom","ja":"イディオム\n字義通りでない慣用的な言い回し","level":6,"lnum":1,"ex":"Learning idioms is an important part of becoming fluent in a language.","exja":"イディオムを学ぶことは言語が流暢になる重要な部分だ。"},{"id":3330,"en":"idol","ja":"アイドル\n崇拝される有名人や偶像","level":6,"lnum":1,"ex":"Many young people look up to her as a pop idol and role model.","exja":"多くの若者が彼女をポップアイドルとロールモデルとして尊敬している。"},{"id":3331,"en":"ignore","ja":"無視する\n意図的に注意を向けない","level":6,"lnum":1,"ex":"She ignored his rude comment and continued with her presentation.","exja":"彼女は彼の失礼なコメントを無視してプレゼンを続けた。"},{"id":3332,"en":"illegally","ja":"違法に\n法律に反した方法で","level":6,"lnum":1,"ex":"He was fined for parking illegally in front of the hospital.","exja":"彼は病院の前に違法に駐車して罰金を科された。"},{"id":3333,"en":"illness","ja":"病気\n体や心の不健康な状態全般","level":6,"lnum":1,"ex":"She missed a week of school due to a serious illness.","exja":"深刻な病気のため彼女は1週間学校を休んだ。"},{"id":3334,"en":"illuminate","ja":"照らす\n光を当てて明るくする・理解を深める","level":6,"lnum":1,"ex":"The candles illuminated the room with a warm, soft light.","exja":"ろうそくが温かく柔らかい光で部屋を照らした。"},{"id":3335,"en":"imaginary","ja":"架空の\n実在せず想像の中にだけある","level":6,"lnum":1,"ex":"When he was young, he had an imaginary friend named Sam.","exja":"幼い頃、彼はサムという名前の架空の友達がいた。"},{"id":3336,"en":"imitate","ja":"まねる\n他者の動作や言葉を真似する","level":6,"lnum":1,"ex":"Young children often imitate the behavior of their parents.","exja":"幼い子どもはしばしば親の行動をまねる。"},{"id":3337,"en":"immediate","ja":"即座の\n遅れなく今すぐに起こる","level":6,"lnum":1,"ex":"The government took immediate action to help the victims of the flood.","exja":"政府は洪水の被害者を助けるために即座に行動した。"},{"id":3338,"en":"immigrate","ja":"移住する\n他の国に永住するために移る","level":6,"lnum":1,"ex":"Many people immigrate to other countries in search of better opportunities.","exja":"多くの人々がより良い機会を求めて他の国に移住する。"},{"id":3339,"en":"immigration","ja":"移民・入国管理\n他国へ移り住む行為・入出国審査","level":6,"lnum":1,"ex":"The country has strict immigration laws that control who can enter.","exja":"その国は誰が入国できるかを管理する厳格な移民法を持っている。"},{"id":3340,"en":"impair","ja":"損なう\n機能や能力を低下させる","level":6,"lnum":1,"ex":"Driving while tired can seriously impair your reaction time.","exja":"疲れた状態での運転は反応時間を深刻に損なうことがある。"},{"id":3341,"en":"impression","ja":"印象\n最初に受ける感じや意見","level":6,"lnum":1,"ex":"The new employee made a great impression on everyone during her first week.","exja":"新しい従業員は最初の週に全員に素晴らしい印象を与えた。"},{"id":3342,"en":"impressive","ja":"印象的な\n強く心に残るすぐれた","level":6,"lnum":1,"ex":"The students gave an impressive performance at the school concert.","exja":"生徒たちは学校のコンサートで印象的な演奏を披露した。"},{"id":3343,"en":"improper","ja":"不適切な\n社会的・道徳的に正しくない行為","level":6,"lnum":1,"ex":"It is improper to use your phone during an important business meeting.","exja":"重要なビジネス会議中に携帯電話を使うことは不適切だ。"},{"id":3344,"en":"improvement","ja":"改善\nより良い状態に変化すること","level":6,"lnum":1,"ex":"There has been a significant improvement in her English since she started practicing every day.","exja":"毎日練習を始めてから彼女の英語に著しい改善があった。"},{"id":3345,"en":"incident","ja":"出来事\n特に問題のある出来事・事件","level":6,"lnum":1,"ex":"The police investigated an incident that occurred near the train station.","exja":"警察は駅近くで起きた出来事を調査した。"},{"id":3346,"en":"income","ja":"収入\n労働などで得る定期的なお金","level":6,"lnum":1,"ex":"His monthly income is enough to cover all his living expenses.","exja":"彼の月収は生活費をすべてまかなうのに十分だ。"},{"id":3347,"en":"inconvenient","ja":"不便な\n都合が悪く使いにくい状態","level":6,"lnum":1,"ex":"The train delay was very inconvenient for passengers who had connections to catch.","exja":"電車の遅延は乗り継ぎがある乗客にとって非常に不便だった。"},{"id":3348,"en":"incorrect","ja":"間違った\n事実や基準に合っていない","level":6,"lnum":1,"ex":"She realized her answer was incorrect and asked to change it.","exja":"彼女は自分の答えが間違っていることに気づいて変更を求めた。"},{"id":3349,"en":"increasingly","ja":"ますます\n程度が徐々に大きくなっていく様子","level":6,"lnum":1,"ex":"People are increasingly concerned about the effects of climate change.","exja":"人々は気候変動の影響についてますます心配している。"},{"id":3350,"en":"incredible","ja":"信じられない\n普通ではありえないほど驚くべき","level":6,"lnum":1,"ex":"The view from the top of the mountain was absolutely incredible.","exja":"山頂からの景色はまったく信じられないほど素晴らしかった。"},{"id":3351,"en":"incredibly","ja":"信じられないほど\n程度を極端に強調する副詞","level":6,"lnum":1,"ex":"The athlete ran incredibly fast and broke the world record.","exja":"その選手は信じられないほど速く走り世界記録を破った。"},{"id":3352,"en":"indefinite article","ja":"不定冠詞\n英語のa/anのこと","level":6,"lnum":1,"ex":"In English, 'a' and 'an' are called the indefinite article.","exja":"英語では'a'と'an'は不定冠詞と呼ばれる。"},{"id":3353,"en":"independent","ja":"独立した\n他に依存せず自分だけで成り立つ","level":6,"lnum":1,"ex":"She became more independent after moving away from home for university.","exja":"大学のために実家を離れてから彼女はより独立した。"},{"id":3354,"en":"indirect","ja":"間接的な\n直接ではなく迂回した方法で","level":6,"lnum":1,"ex":"He gave an indirect answer that didn't really address the question.","exja":"彼は質問に正面から答えない間接的な返答をした。"},{"id":3355,"en":"indirectly","ja":"間接的に\n直接ではなく第三者を介して","level":6,"lnum":1,"ex":"Her advice indirectly helped him solve the problem he was facing.","exja":"彼女のアドバイスは間接的に彼が直面していた問題を解決するのに役立った。"},{"id":3356,"en":"individual","ja":"個々の\n集団ではなく1人1人に関する","level":6,"lnum":1,"ex":"Each individual student has different strengths and learning styles.","exja":"個々の生徒はそれぞれ異なる強みと学習スタイルを持っている。"},{"id":3357,"en":"industrial","ja":"産業の\n製造業や工業に関する","level":6,"lnum":1,"ex":"The city was once an important industrial center for steel production.","exja":"その都市はかつて鉄鋼生産の重要な産業の中心地だった。"},{"id":3358,"en":"inevitable","ja":"避けられない\nどんな努力をしても起こってしまう","level":6,"lnum":1,"ex":"Change is inevitable, and we must learn to adapt to it.","exja":"変化は避けられないものであり、私たちはそれに適応することを学ばなければならない。"},{"id":3359,"en":"infection","ja":"感染\n病原体が体内に侵入して広がること","level":6,"lnum":1,"ex":"He was treated with antibiotics to clear up the bacterial infection.","exja":"彼は細菌感染を治すために抗生物質で治療された。"},{"id":3360,"en":"infinitive","ja":"不定詞\nto+動詞の基本形。文法用語","level":6,"lnum":1,"ex":"In the sentence \"I want to go\", \"to go\" is an infinitive.","exja":"「I want to go」という文で「to go」は不定詞だ。"},{"id":3361,"en":"inform","ja":"知らせる\n必要な情報を伝える","level":6,"lnum":1,"ex":"Please inform me as soon as the results are available.","exja":"結果が出たらすぐに知らせてください。"},{"id":3362,"en":"informative","ja":"有益な\n役立つ情報を多く含んでいる","level":6,"lnum":1,"ex":"The museum exhibition was very informative and easy to understand.","exja":"博物館の展示はとても有益でわかりやすかった。"},{"id":3363,"en":"ingredient","ja":"材料\n料理を作るために使う食材の一つ","level":6,"lnum":1,"ex":"She checked the list of ingredients before buying the sauce.","exja":"彼女はソースを買う前に材料のリストを確認した。"},{"id":3364,"en":"inhabitant","ja":"住民\nある場所に住んでいる人","level":6,"lnum":1,"ex":"The inhabitants of the island depend on fishing for their livelihood.","exja":"島の住民は生計を漁業に頼っている。"},{"id":3365,"en":"inhale","ja":"吸い込む\n空気や煙などを肺に吸い込む","level":6,"lnum":1,"ex":"She inhaled deeply and tried to calm herself before the speech.","exja":"スピーチの前に彼女は深く息を吸い込んで落ち着こうとした。"},{"id":3366,"en":"initial","ja":"頭文字\n名前の最初の文字","level":6,"lnum":1,"ex":"His initial reaction to the news was complete surprise.","exja":"そのニュースへの彼の最初の反応は完全な驚きだった。"},{"id":3367,"en":"initially","ja":"最初は\n始めの段階では。後で変化するニュアンス","level":6,"lnum":1,"ex":"She was initially nervous about her new job, but soon felt confident.","exja":"彼女は最初は新しい仕事に緊張していたが、すぐに自信を持てるようになった。"},{"id":3368,"en":"inject","ja":"注射する\n薬物を体内に強制的に入れる動作。比喩的に「活気を注入する」にも使用","level":6,"lnum":1,"ex":"The nurse injected the medicine into his arm.","exja":"看護師は彼の腕に薬を注射した。"},{"id":3369,"en":"injury","ja":"負傷\n事故や暴力による体の損傷。illnessは病気でinjuryは外傷","level":6,"lnum":1,"ex":"He suffered a serious injury during the game.","exja":"彼は試合中に重傷を負った。"},{"id":3370,"en":"innermost","ja":"最も奥の\n感情や場所の最も深い部分。「innermost feelings」で本音を指す","level":6,"lnum":1,"ex":"She kept her innermost feelings to herself.","exja":"彼女は自分の最も深い気持ちを胸の内に秘めていた。"},{"id":3371,"en":"innocent","ja":"無実の\n罪を犯していない状態。子どもらしい純粋さにも使う","level":6,"lnum":1,"ex":"The jury found him innocent of all charges.","exja":"陪審員は彼をすべての罪状について無実と判断した。"},{"id":3372,"en":"innovator","ja":"革新者\n新しいアイデアや技術を生み出す人。inventorより広い概念","level":6,"lnum":1,"ex":"Steve Jobs was known as a great innovator in technology.","exja":"スティーブ・ジョブズはテクノロジーの偉大な革新者として知られていた。"},{"id":3373,"en":"inquiry/enquiry","ja":"問い合わせ\n情報を求める行為。inquiryは正式な調査、enquiryは日常的な質問","level":6,"lnum":1,"ex":"The school received many inquiries about the new program.","exja":"学校は新しいプログラムについて多くの問い合わせを受けた。"},{"id":3374,"en":"insane","ja":"正気でない\n精神的に不健全な状態。口語では「信じられない」の意味でも使用","level":6,"lnum":1,"ex":"The idea of climbing that mountain alone seemed insane to everyone.","exja":"一人であの山に登るという考えは誰にとっても正気でないように思えた。"},{"id":3375,"en":"inscribe","ja":"刻む\n石や金属などに文字を彫り込む。書くより永続性・儀式性が高い","level":6,"lnum":1,"ex":"The jeweler inscribed their names on the wedding rings.","exja":"宝石職人は結婚指輪に二人の名前を刻んだ。"},{"id":3376,"en":"inscription","ja":"碑文\n石・記念品などに刻まれた文字。記念や永続を目的とした記録","level":6,"lnum":1,"ex":"The ancient inscription on the stone wall was difficult to read.","exja":"石壁に刻まれた古い碑文は読むのが難しかった。"},{"id":3377,"en":"insight","ja":"洞察\n物事の本質を深く理解すること。表面的理解を超えた知見","level":6,"lnum":1,"ex":"Her research gave us a new insight into human behavior.","exja":"彼女の研究は人間の行動について新たな洞察をもたらした。"},{"id":3378,"en":"insist","ja":"主張する\n強く繰り返し主張する。assertより感情的・頑固なニュアンス","level":6,"lnum":1,"ex":"He insisted that he had done nothing wrong.","exja":"彼は自分は何も悪いことをしていないと主張した。"},{"id":3379,"en":"inspection","ja":"検査\n公式・詳細な調査・点検。checkより組織的で権威的","level":6,"lnum":1,"ex":"The health inspector conducted a thorough inspection of the restaurant.","exja":"保健検査官はレストランを徹底的に検査した。"},{"id":3380,"en":"inspire","ja":"鼓舞する\n人に意欲や創造力を与える。外からの影響で内なる力を引き出す","level":6,"lnum":1,"ex":"The coach's speech inspired the team to work harder.","exja":"コーチのスピーチはチームをより一生懸命取り組む気にさせた。"},{"id":3381,"en":"install/instal","ja":"設置する\n機器やソフトウェアを使える状態に取り付ける","level":6,"lnum":1,"ex":"He installed a new app on his smartphone.","exja":"彼はスマートフォンに新しいアプリをインストールした。"},{"id":3382,"en":"instance","ja":"例\n具体的な事例。「for instance」で「例えば」の意味","level":6,"lnum":1,"ex":"For instance, you could take the bus instead of driving.","exja":"例えば、車を運転する代わりにバスに乗ることもできる。"},{"id":3383,"en":"instead of","ja":"〜の代わりに\n別の選択肢を示す前置詞句。代替・置き換えを表す","level":6,"lnum":1,"ex":"She drank tea instead of coffee this morning.","exja":"彼女は今朝、コーヒーの代わりにお茶を飲んだ。"},{"id":3384,"en":"institute","ja":"研究所\n特定の目的のために設立された組織・機関","level":6,"lnum":1,"ex":"He works at a research institute studying climate change.","exja":"彼は気候変動を研究する研究所で働いている。"},{"id":3385,"en":"instructor","ja":"指導者\n実技・技術を教える人。teacherより実践的な指導に使う","level":6,"lnum":1,"ex":"The yoga instructor taught the class how to breathe properly.","exja":"ヨガのインストラクターはクラスに正しい呼吸法を教えた。"},{"id":3386,"en":"insurance","ja":"保険\nリスクに備えて保険料を支払う制度","level":6,"lnum":1,"ex":"It is important to have health insurance in case of an accident.","exja":"事故に備えて健康保険に加入していることが大切だ。"},{"id":3387,"en":"intend","ja":"意図する\n目的を持って計画する。accidentally（偶然）の反対","level":6,"lnum":1,"ex":"She intended to finish the report by Friday.","exja":"彼女は金曜日までにレポートを終わらせるつもりだった。"},{"id":3388,"en":"intense","ja":"激しい\n感情・活動・強度が非常に高い状態。momentaryで強烈な印象","level":6,"lnum":1,"ex":"The summer heat in the city was incredibly intense.","exja":"都市の夏の暑さは信じられないほど激しかった。"},{"id":3389,"en":"intensive","ja":"集中的な\n短期間に集中して行うこと。「intensive course」で集中講座","level":6,"lnum":1,"ex":"She took an intensive English course before moving abroad.","exja":"彼女は海外に移住する前に集中英語講座を受講した。"},{"id":3390,"en":"intention","ja":"意図\n行動の目的・狙い。計画的な目的を示す","level":6,"lnum":1,"ex":"His intention was to help, not to cause trouble.","exja":"彼の意図は助けることであって、迷惑をかけることではなかった。"},{"id":3391,"en":"intentionally","ja":"故意に\nわざと行うさま。accidentally（うっかり）の対義語","level":6,"lnum":1,"ex":"He intentionally left the door unlocked for his friend.","exja":"彼は友人のために故意にドアの鍵をかけなかった。"},{"id":3392,"en":"interact","ja":"交流する\n人や物と相互に作用する。双方向のやり取りを強調","level":6,"lnum":1,"ex":"Children learn social skills when they interact with each other.","exja":"子どもは互いに交流することで社会的スキルを学ぶ。"},{"id":3393,"en":"interaction","ja":"交流\n双方向のやり取り・相互作用。一方通行のcommunicationと区別","level":6,"lnum":1,"ex":"The interaction between the teacher and students made the class lively.","exja":"先生と生徒の交流が授業を活気づけた。"},{"id":3394,"en":"intermediate","ja":"中級の\n初級と上級の間の段階。レベルの中間を示す","level":6,"lnum":1,"ex":"She joined the intermediate level swimming class at the gym.","exja":"彼女はジムの中級水泳クラスに参加した。"},{"id":3395,"en":"intermission","ja":"休憩\n公演・映画などの途中の休止時間。breakより公式な場面で使用","level":6,"lnum":1,"ex":"The audience stretched their legs during the intermission.","exja":"観客は休憩中に脚を伸ばした。"},{"id":3396,"en":"internal","ja":"内部の\n組織や体の内側に関すること。externalの反対","level":6,"lnum":1,"ex":"The company had several internal problems that needed to be solved.","exja":"その会社にはいくつかの内部的な問題があり解決が必要だった。"},{"id":3397,"en":"internationally","ja":"国際的に\n国境を越えた規模で。globallyより国家間の関係を強調","level":6,"lnum":1,"ex":"Her music became famous internationally after the concert.","exja":"彼女の音楽はコンサートの後、国際的に有名になった。"},{"id":3398,"en":"interrupt","ja":"遮る\n話や作業を途中で止める。相手の行為を中断させる","level":6,"lnum":1,"ex":"Please do not interrupt me while I am speaking.","exja":"私が話しているときに口を挟まないでください。"},{"id":3399,"en":"interval","ja":"間隔\n時間や空間の隔たり。定期的な繰り返しの間の期間","level":6,"lnum":1,"ex":"There was a short interval between the two halves of the match.","exja":"試合の前半と後半の間に短い休憩があった。"},{"id":3400,"en":"interviewee","ja":"面接を受ける人\n面接・インタビューを受ける側の人。interviewer（する側）と対比","level":6,"lnum":1,"ex":"The interviewee answered all the questions confidently.","exja":"面接を受けた人はすべての質問に自信を持って答えた。"},{"id":3401,"en":"introduction","ja":"紹介\n人や概念を初めて提示すること。本の序文にも使う","level":6,"lnum":1,"ex":"The teacher gave a brief introduction before starting the lesson.","exja":"先生は授業を始める前に簡単な紹介をした。"},{"id":3402,"en":"invasion","ja":"侵略\n武力で他国や他者の領域に入り込む行為","level":6,"lnum":1,"ex":"The invasion of the country led to many years of conflict.","exja":"その国への侵略は何年もの紛争を引き起こした。"},{"id":3403,"en":"invest","ja":"投資する\n利益を期待してお金や時間を使う。将来の見返りを意識した行動","level":6,"lnum":1,"ex":"She decided to invest her savings in stocks.","exja":"彼女は貯金を株式に投資することにした。"},{"id":3404,"en":"investigation","ja":"調査\n事実を明らかにする体系的な調査。犯罪・事故などで使用","level":6,"lnum":1,"ex":"The police launched an investigation into the missing person case.","exja":"警察は行方不明者の事件の調査を開始した。"},{"id":3405,"en":"invitation","ja":"招待\n人を来るよう求めること。正式・非公式どちらにも使う","level":6,"lnum":1,"ex":"He received an invitation to the graduation party.","exja":"彼は卒業パーティーへの招待状を受け取った。"},{"id":3406,"en":"involuntarily","ja":"無意識に\n意志に反して行うさま。自分の意思ではなくという強調","level":6,"lnum":1,"ex":"She involuntarily gasped when she heard the surprising news.","exja":"彼女は驚くべきニュースを聞いて思わず息をのんだ。"},{"id":3407,"en":"involve","ja":"含む\n何かが関係・参加していること。includeより関与の度合いが高い","level":6,"lnum":1,"ex":"The project will involve many different departments working together.","exja":"そのプロジェクトは多くの異なる部署が協力することになる。"},{"id":3408,"en":"involved","ja":"関わっている\n複雑に絡み合っている状態。complicated（複雑）の意味でも使う","level":6,"lnum":1,"ex":"The situation was more involved than we first thought.","exja":"状況は最初に思っていたよりも複雑だった。"},{"id":3409,"en":"ironing","ja":"アイロンがけ\n衣類のしわをアイロンで伸ばす家事","level":6,"lnum":1,"ex":"She spent her Sunday afternoon ironing her clothes.","exja":"彼女は日曜日の午後、衣類にアイロンをかけて過ごした。"},{"id":3410,"en":"irregular","ja":"不規則な\n一定のパターンがない状態。regularの反対","level":6,"lnum":1,"ex":"The bus service on weekends is irregular, so check the schedule.","exja":"週末のバスの便は不規則なので、時刻表を確認してください。"},{"id":3411,"en":"irritate","ja":"苛立たせる\n軽度の怒りや不快感を引き起こす。angerより軽い不満","level":6,"lnum":1,"ex":"The loud music from next door began to irritate him.","exja":"隣からの大きな音楽が彼をイライラさせ始めた。"},{"id":3412,"en":"isle","ja":"小島\n比較的小さな島。poeticな文脈で使われることが多い","level":6,"lnum":1,"ex":"The small isle was surrounded by clear blue water.","exja":"その小さな島は澄んだ青い水に囲まれていた。"},{"id":3413,"en":"isolation","ja":"孤立\n人や物が切り離された状態。loneliness（孤独感）より客観的","level":6,"lnum":1,"ex":"Long-term isolation can have a negative effect on mental health.","exja":"長期間の孤立は精神的な健康に悪影響を与えることがある。"},{"id":3414,"en":"ivory","ja":"象牙\n象の牙から取れる白い素材。色名としても「アイボリー色」","level":6,"lnum":1,"ex":"The piano keys were once made of ivory.","exja":"かつてピアノの鍵盤は象牙でできていた。"},{"id":3415,"en":"jade","ja":"翡翠\n緑色の宝石。アジア文化で特に重視される装飾素材","level":6,"lnum":1,"ex":"She wore a beautiful jade bracelet on her wrist.","exja":"彼女は手首に美しい翡翠のブレスレットをつけていた。"},{"id":3416,"en":"jar","ja":"瓶\n口の広いガラス・陶器の容器。bottleより口が広い","level":6,"lnum":1,"ex":"She opened a jar of strawberry jam for breakfast.","exja":"彼女は朝食のためにイチゴジャムの瓶を開けた。"},{"id":3417,"en":"jealous","ja":"嫉妬した\n他人の持つものを欲しがる感情。envious（羨む）より強く感情的","level":6,"lnum":1,"ex":"He was jealous of his friend's new bicycle.","exja":"彼は友人の新しい自転車を羨ましく思っていた。"},{"id":3418,"en":"jogging","ja":"ジョギング\nゆっくりとしたペースで走る運動","level":6,"lnum":1,"ex":"She goes jogging in the park every morning before work.","exja":"彼女は毎朝仕事前に公園でジョギングをする。"},{"id":3419,"en":"joint","ja":"共同の\n複数の人や組織が一緒に行う。「joint effort」で共同の努力","level":6,"lnum":1,"ex":"The two companies made a joint decision to expand the business.","exja":"二つの会社はビジネスを拡大するという共同決定を下した。"},{"id":3420,"en":"journal","ja":"日記・専門誌\n個人の日記または学術・専門的な定期刊行物","level":6,"lnum":1,"ex":"He wrote about his experiences in a travel journal.","exja":"彼は旅行日記に自分の経験を書いた。"},{"id":3421,"en":"judgment/judgement","ja":"判断\n物事を評価・決定する行為。法的な「判決」にも使用","level":6,"lnum":1,"ex":"Good judgment is essential when making important decisions.","exja":"重要な決断を下す際には優れた判断力が不可欠だ。"},{"id":3422,"en":"jug","ja":"水差し\n液体を注ぐための持ち手付き容器。jugよりpitcherは大型","level":6,"lnum":1,"ex":"She poured lemonade from the jug into everyone's glass.","exja":"彼女は水差しからレモネードをみんなのグラスに注いだ。"},{"id":3423,"en":"juicy","ja":"汁気の多い\n果物や肉など水分が豊富な状態。比喩的に「興味深い」にも","level":6,"lnum":1,"ex":"The peach was so juicy that the juice ran down her chin.","exja":"桃はとても汁気が多く、果汁が彼女のあごを伝った。"},{"id":3424,"en":"jumper","ja":"セーター\n英国英語でのセーター・プルオーバー。米語ではsweater","level":6,"lnum":1,"ex":"She put on a warm jumper because it was cold outside.","exja":"外が寒かったので、彼女は暖かいセーターを着た。"},{"id":3425,"en":"justice","ja":"正義\n公正さ・公平な扱い。法的な「司法」の意味も持つ","level":6,"lnum":1,"ex":"Everyone deserves to be treated with justice and fairness.","exja":"すべての人は公正かつ公平に扱われる権利がある。"},{"id":3426,"en":"keyboard","ja":"キーボード\nコンピューターや楽器の鍵盤・入力装置","level":6,"lnum":1,"ex":"She learned to type faster by practicing on the keyboard every day.","exja":"彼女は毎日キーボードで練習することで打つのが早くなった。"},{"id":3427,"en":"killing","ja":"殺害\n生き物の命を奪う行為。murderより法的判断を含まない広い語","level":6,"lnum":1,"ex":"The documentary discussed the killing of wildlife due to habitat loss.","exja":"そのドキュメンタリーは生息地の喪失による野生動物の殺害について論じた。"},{"id":3428,"en":"kiss","ja":"キスする\n唇で触れる愛情・挨拶の表現","level":6,"lnum":1,"ex":"He kissed his daughter goodnight before she went to bed.","exja":"彼は娘が寝る前におやすみのキスをした。"},{"id":3429,"en":"kitten","ja":"子猫\n成長前の小さな猫。cat（猫）より幼さ・かわいらしさを強調","level":6,"lnum":1,"ex":"The kitten curled up on the warm blanket and fell asleep.","exja":"子猫は暖かい毛布の上で丸くなって眠りについた。"},{"id":3430,"en":"lab","ja":"実験室\nlaboratoryの略。科学実験を行う場所","level":6,"lnum":1,"ex":"The students conducted their chemistry experiment in the lab.","exja":"生徒たちは実験室で化学実験を行った。"},{"id":3431,"en":"laboratory","ja":"実験室\n科学的研究・実験を行う正式な施設","level":6,"lnum":1,"ex":"Scientists in the laboratory are working on a new vaccine.","exja":"実験室の科学者たちは新しいワクチンに取り組んでいる。"},{"id":3432,"en":"ladder","ja":"はしご\n段を登るための道具。比喩的に「出世の階段」にも使用","level":6,"lnum":1,"ex":"He climbed the ladder to fix the roof of the house.","exja":"彼は家の屋根を修理するためにはしごを登った。"},{"id":3433,"en":"lamb","ja":"子羊\n生後1年未満の羊。肉としても使う（ラム肉）","level":6,"lnum":1,"ex":"The farmer watched the newborn lamb take its first steps.","exja":"農家の人は生まれたばかりの子羊が初めて歩くのを見守った。"},{"id":3434,"en":"landlord","ja":"家主\n不動産を賃貸する所有者。tenantの反対側の立場","level":6,"lnum":1,"ex":"The landlord agreed to repair the broken heating system.","exja":"家主は壊れた暖房システムを修理することに同意した。"},{"id":3435,"en":"largely","ja":"主に\n大部分において・ほとんど。mainlyとほぼ同義だが形式的","level":6,"lnum":1,"ex":"The success of the event was largely due to the volunteers.","exja":"そのイベントの成功は主にボランティアのおかげだった。"},{"id":3436,"en":"lasting","ja":"長続きする\n長期間続く状態。temporaryの反対で永続性を強調","level":6,"lnum":1,"ex":"They hoped to build a lasting friendship after the trip.","exja":"彼らは旅行の後も長続きする友情を築きたいと思っていた。"},{"id":3437,"en":"latecomer","ja":"遅刻者\n決められた時間より遅れて来る人","level":6,"lnum":1,"ex":"The latecomer quietly found an empty seat at the back of the room.","exja":"遅刻した人はそっと部屋の後ろの空席を見つけた。"},{"id":3438,"en":"lately","ja":"最近\n比較的近い過去の期間。recentlyとほぼ同義","level":6,"lnum":1,"ex":"She has been feeling very tired lately.","exja":"彼女は最近とても疲れを感じている。"},{"id":3439,"en":"launch","ja":"開始する\n新製品・事業・活動などを正式に始める。starより公式感がある","level":6,"lnum":1,"ex":"The company will launch its new product next month.","exja":"その会社は来月新製品を発売する予定だ。"},{"id":3440,"en":"lawful","ja":"合法的な\n法律に従った・法に反しない。legalとほぼ同義だが道徳的含意も","level":6,"lnum":1,"ex":"It is not lawful to drive without a valid license.","exja":"有効な免許証なしで運転することは合法ではない。"},{"id":3441,"en":"lay","ja":"置く\n物を水平な面に置く。lieと混同しやすい（layは他動詞）","level":6,"lnum":1,"ex":"She laid the book on the table and went to make tea.","exja":"彼女は本をテーブルの上に置いてお茶を入れに行った。"},{"id":3442,"en":"layer","ja":"層\n重なった構造の一枚。地層・塗装・服の重ね着に使用","level":6,"lnum":1,"ex":"Add another layer of paint to make the color brighter.","exja":"色をより鮮やかにするためにもう一層ペンキを塗ってください。"},{"id":3443,"en":"leadership","ja":"リーダーシップ\n集団を導く能力・立場。managershipより人心掌握の側面が強い","level":6,"lnum":1,"ex":"Strong leadership is needed to guide the team through difficult times.","exja":"困難な時期にチームを導くためには強いリーダーシップが必要だ。"},{"id":3444,"en":"leading","ja":"一流の\n最も重要・優れた存在。主役級・先頭を行く意味","level":6,"lnum":1,"ex":"She played the leading role in the school play.","exja":"彼女は学校の劇で主役を演じた。"},{"id":3445,"en":"league","ja":"リーグ\n同レベルの団体・人の集まり。スポーツ連盟や品質レベルを示す","level":6,"lnum":1,"ex":"The team finished at the top of the league this season.","exja":"そのチームは今シーズン、リーグの首位でフィニッシュした。"},{"id":3446,"en":"lean","ja":"痩せた\n脂肪が少ない・細い体型。thinより健康的なニュアンス","level":6,"lnum":1,"ex":"He leaned against the wall while waiting for the bus.","exja":"彼はバスを待ちながら壁にもたれかかった。"},{"id":3447,"en":"leap","ja":"跳躍する\n大きく跳び上がる。jumpより距離・高さを強調した動作","level":6,"lnum":1,"ex":"The cat leaped onto the table and knocked over the cup.","exja":"猫はテーブルに飛び乗り、カップをひっくり返した。"},{"id":3448,"en":"lecture","ja":"講義\n大学などでの公式な授業・講演。lesssonより形式的・大規模","level":6,"lnum":1,"ex":"The professor gave a lecture on climate change to a large audience.","exja":"教授は大勢の聴衆に気候変動についての講義を行った。"},{"id":3449,"en":"legal","ja":"法的な\n法律に関係する・法律上認められた","level":6,"lnum":1,"ex":"It is legal to ride a bicycle on the road in this country.","exja":"この国では道路で自転車に乗ることは合法だ。"},{"id":3450,"en":"legally","ja":"法的に\n法律の観点から・法律に従って","level":6,"lnum":1,"ex":"You are legally required to wear a seatbelt while driving.","exja":"運転中はシートベルトを着用することが法律で義務付けられている。"},{"id":3451,"en":"length","ja":"長さ\n一方の端からもう一方までの距離","level":6,"lnum":1,"ex":"What is the length of the swimming pool?","exja":"プールの長さはどのくらいですか？"},{"id":3452,"en":"lessen","ja":"減らす\n量・程度を小さくする。reduceとほぼ同義だが自動詞にもなる","level":6,"lnum":1,"ex":"Taking a short walk can help lessen stress after work.","exja":"短い散歩は仕事後のストレスを軽減するのに役立つ。"},{"id":3453,"en":"liar","ja":"嘘をつく人\n意図的に虚偽を言う人。一時的な行為でなく習慣的特性を指す","level":6,"lnum":1,"ex":"Nobody trusted him because he had a reputation as a liar.","exja":"彼は嘘をつく人として知られていたので、誰も信用しなかった。"},{"id":3454,"en":"liberate","ja":"解放する\n束縛・抑圧から自由にする。freeより政治的・劇的な文脈で使用","level":6,"lnum":1,"ex":"The soldiers worked hard to liberate the prisoners from the camp.","exja":"兵士たちは収容所から囚人を解放するために懸命に働いた。"},{"id":3455,"en":"liberation","ja":"解放\n抑圧・支配からの自由を得ること。政治・社会運動でよく使われる","level":6,"lnum":1,"ex":"The liberation of the city was celebrated by its residents.","exja":"都市の解放は住民たちによって祝われた。"},{"id":3456,"en":"lifeguard","ja":"ライフガード\n水難事故から人を救助する監視員","level":6,"lnum":1,"ex":"The lifeguard kept a close watch on the swimmers at the beach.","exja":"ライフガードはビーチで泳ぐ人々を注意深く見守った。"},{"id":3457,"en":"lifelong","ja":"生涯にわたる\n一生続く・生涯を通じての。permanentより人の一生に焦点","level":6,"lnum":1,"ex":"Learning is a lifelong process that never truly ends.","exja":"学ぶことは真に終わることのない生涯にわたるプロセスだ。"},{"id":3458,"en":"lighter","ja":"ライター\n火を起こす小型器具。副詞的に「より軽い」の比較級でもある","level":6,"lnum":1,"ex":"He used a lighter to start the campfire.","exja":"彼はキャンプファイヤーをつけるためにライターを使った。"},{"id":3459,"en":"lightly","ja":"軽く\n重くなく・ほんの少し。softlyより物理的な重さを強調","level":6,"lnum":1,"ex":"She lightly touched his shoulder to get his attention.","exja":"彼女は彼の注意を引こうと肩を軽く触れた。"},{"id":3460,"en":"lightning","ja":"稲妻\n雷雨時に空に走る電光。thunderは音、lightningは光","level":6,"lnum":1,"ex":"Lightning struck the old tree during the storm.","exja":"嵐の中、稲妻が古い木に落ちた。"},{"id":3461,"en":"likeness","ja":"類似\n外見や性質の似ている点。similarityより外見に焦点を当てる","level":6,"lnum":1,"ex":"The painting showed a strong likeness to the original subject.","exja":"その絵画は本物の被写体に非常よく似ていた。"},{"id":3462,"en":"limitation","ja":"限界\n能力・範囲の境界線。restrictionは外から課される制限","level":6,"lnum":1,"ex":"Everyone has their own strengths and limitations.","exja":"誰もが自分の長所と限界を持っている。"},{"id":3463,"en":"limited","ja":"限られた\n量・範囲が少ない・制限された状態","level":6,"lnum":1,"ex":"There are only a limited number of seats available for the concert.","exja":"コンサートの席は限られた数しか用意されていない。"},{"id":3464,"en":"limp","ja":"引きずって歩く\n足を痛めてびっこを引く歩き方","level":6,"lnum":1,"ex":"After twisting his ankle, he had to limp home slowly.","exja":"足首をくじいた後、彼はびっこを引きながらゆっくり家に帰らなければならなかった。"},{"id":3465,"en":"link","ja":"つながり\n物事や人を結ぶ接続点。connectionより具体的な結びつき","level":6,"lnum":1,"ex":"Scientists found a link between lack of sleep and poor health.","exja":"科学者たちは睡眠不足と健康悪化の間につながりを発見した。"},{"id":3466,"en":"liquid","ja":"液体の\n流れる性質を持つ状態。solidとgasの間の物質状態","level":6,"lnum":1,"ex":"Water changes from liquid to ice when the temperature drops below zero.","exja":"気温が0度を下回ると、水は液体から氷に変わる。"},{"id":3467,"en":"literary","ja":"文学の\n文学に関係する・文学的な。書き言葉・芸術性を強調","level":6,"lnum":1,"ex":"She has always been interested in literary works from the 19th century.","exja":"彼女はいつも19世紀の文学作品に興味を持っていた。"},{"id":3468,"en":"literature","ja":"文学\n芸術的価値を持つ書かれた作品の総称","level":6,"lnum":1,"ex":"She studied English literature at university.","exja":"彼女は大学で英文学を学んだ。"},{"id":3469,"en":"liver","ja":"肝臓\n体内で解毒などを行う重要な臓器。食材としても使う","level":6,"lnum":1,"ex":"The doctor said his liver was healthy after the checkup.","exja":"医師は検査の後、彼の肝臓は健康だと言った。"},{"id":3470,"en":"loaf","ja":"パンの一斤\n一個単位の食パン。「a loaf of bread」で一斤のパン","level":6,"lnum":1,"ex":"She bought a loaf of bread at the bakery on her way home.","exja":"彼女は帰り道にパン屋でパンを一斤買った。"},{"id":3471,"en":"locate","ja":"位置を特定する\n何かがどこにあるかを見つける。findより場所の特定に焦点","level":6,"lnum":1,"ex":"Can you locate the nearest hospital on this map?","exja":"この地図で最寄りの病院の場所を特定できますか？"},{"id":3472,"en":"location","ja":"場所\n何かが存在する・起こる地点。placeより正確な位置を指す","level":6,"lnum":1,"ex":"The hotel is in a perfect location near the beach.","exja":"そのホテルはビーチのすぐそばという絶好の場所にある。"},{"id":3473,"en":"lodge","ja":"山小屋\n山や森の中の小さな宿泊施設。動詞では「下宿する」の意味も","level":6,"lnum":1,"ex":"They stayed in a cozy lodge near the ski resort.","exja":"彼らはスキーリゾートの近くにある居心地のよい山小屋に泊まった。"},{"id":3474,"en":"log","ja":"丸太\n切り倒した木の幹。コンピュータの記録（ログ）にも使う","level":6,"lnum":1,"ex":"He carried a heavy log to add to the campfire.","exja":"彼はキャンプファイヤーに追加するために重い丸太を運んだ。"},{"id":3475,"en":"logic","ja":"論理\n正しい推論の原則・筋道立てた考え方","level":6,"lnum":1,"ex":"His argument had no logic and was hard to follow.","exja":"彼の議論には論理がなく、理解しにくかった。"},{"id":3476,"en":"logo","ja":"ロゴ\n企業・団体を表す図案・マーク","level":6,"lnum":1,"ex":"The company changed its logo to attract younger customers.","exja":"その会社は若い顧客を引き付けるためにロゴを変更した。"},{"id":3477,"en":"lorry","ja":"トラック\n英国英語で大型貨物自動車。米語ではtruck","level":6,"lnum":1,"ex":"A large lorry was blocking the road, causing a traffic jam.","exja":"大型トラックが道路をふさいでいて、渋滞を引き起こしていた。"},{"id":3478,"en":"lottery","ja":"宝くじ\n番号を引いて当たりを決める賭け。運任せの選択にも比喩的に使用","level":6,"lnum":1,"ex":"He won a small prize in the national lottery last week.","exja":"彼は先週、国の宝くじで少額の賞金を当てた。"},{"id":3479,"en":"loudspeaker","ja":"拡声器\n音を増幅して広範囲に届ける機器","level":6,"lnum":1,"ex":"The announcement was made through the loudspeaker at the station.","exja":"駅の拡声器を通じてアナウンスが流れた。"},{"id":3480,"en":"lovingly","ja":"愛情を込めて\n深い愛情・優しさをもって行うさま","level":6,"lnum":1,"ex":"She lovingly prepared a meal for her grandmother's birthday.","exja":"彼女は祖母の誕生日のために愛情を込めて食事を準備した。"},{"id":3481,"en":"loyal","ja":"忠実な\n特定の人・組織・信念に変わらず従う。faithfulより個人的な関係","level":6,"lnum":1,"ex":"A loyal friend will support you even in difficult times.","exja":"忠実な友人は困難な時でもあなたを支えてくれる。"},{"id":3482,"en":"loyalty","ja":"忠誠心\n変わらない献身・誠実さ。特定の対象への長期的なコミットメント","level":6,"lnum":1,"ex":"The employees showed great loyalty to the company during the crisis.","exja":"従業員たちは危機の際に会社への強い忠誠心を示した。"},{"id":3483,"en":"lung","ja":"肺\n呼吸を担う胸部の臓器。通常複数形（lungs）で使用","level":6,"lnum":1,"ex":"Smoking can cause serious damage to the lungs over time.","exja":"喫煙は時間が経つにつれて肺に深刻なダメージを与える可能性がある。"},{"id":3484,"en":"luxury","ja":"贅沢\n必要以上の豊かさ・快適さ。necessityの反対","level":6,"lnum":1,"ex":"They stayed in a luxury hotel during their trip to Paris.","exja":"彼らはパリへの旅行中、高級ホテルに宿泊した。"},{"id":3485,"en":"magical","ja":"魔法のような\n魔法に関係する・不思議な魅力を持つ","level":6,"lnum":1,"ex":"The fireworks display was a magical experience for the children.","exja":"花火大会は子どもたちにとって魔法のような体験だった。"},{"id":3486,"en":"magician","ja":"魔術師\n手品や魔法を行う人。illusionist（手品師）とほぼ同義","level":6,"lnum":1,"ex":"The magician amazed the audience with his disappearing trick.","exja":"手品師は消えるマジックで観客を驚かせた。"},{"id":3487,"en":"magnificent","ja":"壮大な\n非常に印象的で素晴らしい外観・規模。grandeurを強調","level":6,"lnum":1,"ex":"The view from the top of the mountain was truly magnificent.","exja":"山頂からの景色は本当に壮大だった。"},{"id":3488,"en":"mail","ja":"郵送する\n郵便で送る。英国ではpost、米国ではmailが一般的","level":6,"lnum":1,"ex":"She mailed a birthday card to her grandmother.","exja":"彼女は祖母に誕生日カードを郵送した。"},{"id":3489,"en":"maintain","ja":"維持する\n状態を保ち続ける。keepより意識的な努力を含む","level":6,"lnum":1,"ex":"It is important to maintain a healthy diet and exercise regularly.","exja":"健康的な食事を維持し定期的に運動することが大切だ。"},{"id":3490,"en":"maintenance","ja":"維持管理\n良い状態を保つための定期的な作業","level":6,"lnum":1,"ex":"Regular maintenance of the car is necessary to keep it running well.","exja":"車をよい状態で走らせ続けるには定期的な整備が必要だ。"},{"id":3491,"en":"majority","ja":"大多数\n全体の半分以上。minorityの反対","level":6,"lnum":1,"ex":"The majority of students passed the final exam.","exja":"大多数の生徒が期末試験に合格した。"},{"id":3492,"en":"management","ja":"管理\n組織・事業・人を統括・運営すること","level":6,"lnum":1,"ex":"Good management is key to the success of any business.","exja":"よい経営はどんなビジネスの成功にとっても鍵となる。"},{"id":3493,"en":"mankind","ja":"人類\n人間全体。humankindが性別中立的でより現代的な表現","level":6,"lnum":1,"ex":"Throughout history, mankind has always sought to explore the unknown.","exja":"歴史を通じて、人類は常に未知のものを探求しようとしてきた。"},{"id":3494,"en":"maple","ja":"カエデ\n秋に紅葉するカエデの木。メープルシロップの原料","level":6,"lnum":1,"ex":"The maple tree in the garden turns bright red in autumn.","exja":"庭のカエデは秋に鮮やかな赤に色づく。"},{"id":3495,"en":"marble","ja":"大理石\n建築・彫刻に使う高級石材。子どもの遊び「ビー玉」にも使う","level":6,"lnum":1,"ex":"The floor of the palace was made of beautiful white marble.","exja":"宮殿の床は美しい白い大理石でできていた。"},{"id":3496,"en":"marine","ja":"海の\n海・海洋に関係する。oceanicより生物・生態系に焦点を当てる","level":6,"lnum":1,"ex":"Marine biologists study the creatures that live in the ocean.","exja":"海洋生物学者は海に生息する生き物を研究する。"},{"id":3497,"en":"marked","ja":"顕著な\nはっきりと目立つ・著しい違い。noticeableより改まった表現","level":6,"lnum":1,"ex":"There was a marked improvement in her grades after she started studying harder.","exja":"より一生懸命勉強し始めた後、彼女の成績に顕著な改善が見られた。"},{"id":3498,"en":"marriage","ja":"結婚\n法的・社会的な婚姻関係。weddingは式、marriageは制度・状態","level":6,"lnum":1,"ex":"Their marriage ceremony was held in a beautiful garden.","exja":"彼らの結婚式は美しい庭園で行われた。"},{"id":3499,"en":"mash","ja":"つぶす\n食物をつぶしてペースト状にする。「mashed potatoes」がよく知られる","level":6,"lnum":1,"ex":"He mashed the potatoes until they were smooth and creamy.","exja":"彼はなめらかでクリーミーになるまでジャガイモをつぶした。"},{"id":3500,"en":"mass","ja":"大規模な\n大量の・多数の。「mass production」で大量生産","level":6,"lnum":1,"ex":"The earthquake caused mass destruction throughout the region.","exja":"地震はその地域全体に大規模な破壊をもたらした。"},{"id":3501,"en":"massive","ja":"巨大な\n非常に大きい・重い。hugeより重量感・圧迫感がある","level":6,"lnum":1,"ex":"The construction workers moved a massive rock out of the way.","exja":"建設作業員たちは邪魔になっている巨大な岩を動かした。"},{"id":3502,"en":"mathematician","ja":"数学者\n数学を専門的に研究する人","level":6,"lnum":1,"ex":"The famous mathematician solved a problem that had puzzled experts for years.","exja":"その有名な数学者は何年も専門家を悩ませてきた問題を解いた。"},{"id":3503,"en":"mathematics","ja":"数学\n数・量・形を研究する学問。口語ではmaths（英）/math（米）","level":6,"lnum":1,"ex":"She has always loved mathematics and hopes to become an engineer.","exja":"彼女はいつも数学が好きで、エンジニアになりたいと思っている。"},{"id":3504,"en":"maximum","ja":"最大の\n可能な最も大きい量・程度。minimumの反対","level":6,"lnum":1,"ex":"The maximum speed on this road is 60 kilometers per hour.","exja":"この道路の最高速度は時速60キロメートルだ。"},{"id":3505,"en":"meaningful","ja":"意味のある\n重要な意義・目的を持つ。meaninglessの反対","level":6,"lnum":1,"ex":"He wanted to have a meaningful conversation with his father.","exja":"彼は父親と意味のある会話をしたいと思っていた。"},{"id":3506,"en":"meanwhile","ja":"その間に\n同時進行の別の出来事を示す。「in the meantime」と同義","level":6,"lnum":1,"ex":"She studied for the exam; meanwhile, her brother watched TV.","exja":"彼女は試験のために勉強していた。その間、弟はテレビを見ていた。"},{"id":3507,"en":"measure","ja":"測定値\n量・程度を数値で表すこと。countに比べより広い概念","level":6,"lnum":1,"ex":"Scientists measure the temperature of the ocean to study climate change.","exja":"科学者たちは気候変動を研究するために海の温度を測定する。"},{"id":3508,"en":"measurement","ja":"測定\n量・大きさを計る行為・その結果","level":6,"lnum":1,"ex":"Please take accurate measurements before cutting the wood.","exja":"木を切る前に正確な測定値を取ってください。"},{"id":3509,"en":"mechanic","ja":"整備士\n機械・車両を修理・整備する技術者","level":6,"lnum":1,"ex":"The mechanic fixed the engine and had the car ready by noon.","exja":"整備士はエンジンを修理し、正午までに車を仕上げた。"},{"id":3510,"en":"mechanical","ja":"機械的な\n機械に関する・自動的で感情のない動作","level":6,"lnum":1,"ex":"The factory uses mechanical arms to assemble the products.","exja":"その工場は製品を組み立てるために機械的なアームを使用している。"},{"id":3511,"en":"meditate","ja":"瞑想する\n心を静めて深く考える・瞑想を行う","level":6,"lnum":1,"ex":"She meditated for twenty minutes every morning to clear her mind.","exja":"彼女は心を整えるために毎朝20分間瞑想をした。"},{"id":3512,"en":"meditation","ja":"瞑想\n精神を集中・内省させる実践。宗教的・健康的な文脈で使用","level":6,"lnum":1,"ex":"Regular meditation can help reduce anxiety and improve focus.","exja":"定期的な瞑想は不安を軽減し集中力を高めるのに役立つ。"},{"id":3513,"en":"Mediterranean","ja":"地中海\nヨーロッパ・アフリカ・中東に囲まれた海。温暖な気候を示す","level":6,"lnum":1,"ex":"They spent their summer vacation sailing in the Mediterranean.","exja":"彼らは地中海でセーリングをして夏休みを過ごした。"},{"id":3514,"en":"membership","ja":"会員資格\n組織・クラブの会員であること・その地位","level":6,"lnum":1,"ex":"She applied for membership at the local sports club.","exja":"彼女は地元のスポーツクラブの会員になるために申し込んだ。"},{"id":3515,"en":"memorable","ja":"忘れられない\n記憶に残るほど印象的な出来事や経験","level":6,"lnum":1,"ex":"The trip to Japan was a truly memorable experience.","exja":"日本への旅行は本当に忘れられない体験だった。"},{"id":3516,"en":"memorize/memorise","ja":"暗記する\n記憶に完全に刻み込む。rememberより意図的な努力を含む","level":6,"lnum":1,"ex":"He spent hours trying to memorize all the vocabulary words.","exja":"彼はすべての語彙を暗記しようと何時間も費やした。"},{"id":3517,"en":"mend","ja":"修繕する\n壊れた物を修理する。fixより縫い物など手作業の修繕に使いやすい","level":6,"lnum":1,"ex":"Could you help me mend this torn jacket?","exja":"この破れたジャケットの修繕を手伝ってくれますか？"},{"id":3518,"en":"mental","ja":"精神的な\n心・思考に関係する。physicalの反対","level":6,"lnum":1,"ex":"Yoga and meditation are good for both physical and mental health.","exja":"ヨガと瞑想は体と心の健康の両方によい。"},{"id":3519,"en":"mentally","ja":"精神的に\n心の面で・頭の中で","level":6,"lnum":1,"ex":"He was mentally prepared for the challenges of the new job.","exja":"彼は新しい仕事の困難に精神的に備えていた。"},{"id":3520,"en":"mention","ja":"言及する\n話の中で軽く触れる。explainより軽い・brief","level":6,"lnum":1,"ex":"She mentioned that she was moving to a new city next month.","exja":"彼女は来月新しい街に引っ越す予定だと言及した。"},{"id":3521,"en":"merchant","ja":"商人\n商品を売買することで生計を立てる人。特に歴史的・中規模の商業","level":6,"lnum":1,"ex":"The merchant sold spices from around the world at the market.","exja":"その商人は市場で世界中のスパイスを売っていた。"},{"id":3522,"en":"mere","ja":"単なる\nそれだけで他に何もない・取るに足らない。onlyを強調する形容詞","level":6,"lnum":1,"ex":"She passed the test with a mere five minutes to spare.","exja":"彼女はわずか5分の余裕でテストに合格した。"},{"id":3523,"en":"merely","ja":"単に\nそれだけ・ほかでもなく。justより書き言葉的","level":6,"lnum":1,"ex":"He merely wanted to help, but his offer was misunderstood.","exja":"彼は単に助けたかっただけだが、申し出は誤解された。"},{"id":3524,"en":"mess","ja":"散らかり\n無秩序な状態・混乱。disorderより日常的な表現","level":6,"lnum":1,"ex":"The children left a big mess in the kitchen after making cookies.","exja":"子どもたちはクッキーを作った後、台所を大散らかりにした。"},{"id":3525,"en":"message board","ja":"掲示板\nメッセージを投稿・共有する場所。物理的・デジタル両方に使う","level":6,"lnum":1,"ex":"Students can post questions on the online message board.","exja":"生徒たちはオンラインの掲示板に質問を投稿できる。"},{"id":3526,"en":"messy","ja":"散らかった\n整理されていない状態。untidyとほぼ同義","level":6,"lnum":1,"ex":"His desk is always messy, but he knows where everything is.","exja":"彼の机はいつも散らかっているが、何がどこにあるかは分かっている。"},{"id":3527,"en":"middle-aged","ja":"中年の\nおよそ40〜60代の年代を指す","level":6,"lnum":1,"ex":"Many middle-aged adults return to school to learn new skills.","exja":"多くの中年の大人は新しいスキルを学ぶために学校に戻る。"},{"id":3528,"en":"mineral","ja":"ミネラル\n地中から採れる自然物質。栄養素としての鉱物にも使用","level":6,"lnum":1,"ex":"Milk is a good source of minerals like calcium and magnesium.","exja":"牛乳はカルシウムやマグネシウムなどのミネラルの良い供給源だ。"},{"id":3529,"en":"minimize/minimise","ja":"最小化する\n量・影響をできる限り小さくする。maximizeの反対","level":6,"lnum":1,"ex":"We should minimize the use of plastic to protect the environment.","exja":"環境を守るためにプラスチックの使用を最小化すべきだ。"},{"id":3530,"en":"minimum","ja":"最小の\n可能な最も小さい量・程度。maximumの反対","level":6,"lnum":1,"ex":"The minimum age to vote in this country is eighteen.","exja":"この国で投票できる最低年齢は18歳だ。"},{"id":3531,"en":"minor","ja":"小さな\n重要でない・比較的小さな問題。majorの反対","level":6,"lnum":1,"ex":"The doctor said the injury was minor and would heal quickly.","exja":"医師は負傷は軽傷で、すぐに治ると言った。"},{"id":3532,"en":"minority","ja":"少数派\n全体の半分未満の集団。majorityの反対","level":6,"lnum":1,"ex":"A minority of students chose to stay after school for extra practice.","exja":"少数の生徒が放課後残って追加練習をすることを選んだ。"},{"id":3533,"en":"minus","ja":"〜を引いた\n引き算を示す・〜がない状態を表す前置詞","level":6,"lnum":1,"ex":"The temperature outside was minus ten degrees last night.","exja":"昨夜、外の気温はマイナス10度だった。"},{"id":3534,"en":"miracle","ja":"奇跡\n自然の法則を超えた不思議な出来事","level":6,"lnum":1,"ex":"It was a miracle that no one was injured in the accident.","exja":"事故で誰も怪我をしなかったのは奇跡だった。"},{"id":3535,"en":"mischief","ja":"いたずら\n軽度の悪ふざけ・害を与えない悪さ。crimeより軽い","level":6,"lnum":1,"ex":"The puppy got into mischief while the owner was away.","exja":"飼い主が留守の間、子犬はいたずらをした。"},{"id":3536,"en":"miserable","ja":"みじめな\n非常に不幸で惨めな状態。unhappyより強い苦しみ","level":6,"lnum":1,"ex":"She felt miserable after failing the exam she had studied hard for.","exja":"一生懸命勉強したのに試験に落ちて、彼女はみじめな気持ちになった。"},{"id":3537,"en":"misery","ja":"苦悩\n深い不幸・苦しみの状態。sadnessより重く持続的","level":6,"lnum":1,"ex":"The refugees lived in great misery without food or shelter.","exja":"難民たちは食料も住む場所もなく、深い苦悩の中で生きていた。"},{"id":3538,"en":"mislead","ja":"誤解させる\n間違った方向に導く・だます。deceiveより無意識の場合も含む","level":6,"lnum":1,"ex":"The advertisement was designed to mislead customers about the product.","exja":"その広告は製品について顧客を誤解させるように作られていた。"},{"id":3539,"en":"misty","ja":"霧がかった\n薄い霧に覆われた状態。foggyより薄く幻想的な印象","level":6,"lnum":1,"ex":"The mountains looked beautiful in the misty morning air.","exja":"霧がかかった朝の空気の中で、山々は美しく見えた。"},{"id":3540,"en":"misunderstanding","ja":"誤解\n意味を間違って理解すること","level":6,"lnum":1,"ex":"The argument was caused by a simple misunderstanding between friends.","exja":"その口論は友人間の単純な誤解から生じた。"},{"id":3541,"en":"mixing bowl","ja":"ミキシングボウル\n料理の材料を混ぜるための大きなボウル","level":6,"lnum":1,"ex":"She poured all the ingredients into the mixing bowl and stirred them together.","exja":"彼女はすべての材料をミキシングボウルに入れてかき混ぜた。"},{"id":3542,"en":"modal verb/modal","ja":"法助動詞\ncan/must/shouldなど可能・義務などを表す助動詞","level":6,"lnum":1,"ex":"\"Must\" is a modal verb that shows obligation.","exja":"\"Must\"は義務を表す法助動詞だ。"},{"id":3543,"en":"modem","ja":"モデム\nデジタル信号を通信回線で送受信する装置","level":6,"lnum":1,"ex":"He connected his computer to the internet using a modem.","exja":"彼はモデムを使ってコンピューターをインターネットに接続した。"},{"id":3544,"en":"moderate","ja":"適度な\n極端でなく中程度の状態。extremeの反対","level":6,"lnum":1,"ex":"The doctor recommended moderate exercise to improve her health.","exja":"医師は健康改善のために適度な運動を勧めた。"},{"id":3545,"en":"modify","ja":"修正する\n細かく変更・調整する。changeより小幅な変更を示す","level":6,"lnum":1,"ex":"The engineer had to modify the design after testing the product.","exja":"エンジニアは製品のテスト後に設計を修正しなければならなかった。"},{"id":3546,"en":"moisture","ja":"湿気\n空気中や物体表面の水分。humidityは空気中の湿度に限定","level":6,"lnum":1,"ex":"The moisture in the air made the room feel warm and comfortable.","exja":"空気中の湿気が部屋を暖かく快適に感じさせた。"},{"id":3547,"en":"molecule","ja":"分子\n物質の化学的性質を持つ最小単位","level":6,"lnum":1,"ex":"A water molecule is made up of two hydrogen atoms and one oxygen atom.","exja":"水分子は2つの水素原子と1つの酸素原子からなる。"},{"id":3548,"en":"monitor","ja":"モニター\n画面表示装置。また「監視する」という動詞でも使用","level":6,"lnum":1,"ex":"The teacher monitored the students during the test.","exja":"先生はテスト中に生徒たちを監視した。"},{"id":3549,"en":"monk","ja":"修道士\n宗教的な誓いを立てて修道院で生活する男性","level":6,"lnum":1,"ex":"The monk spent many hours a day in prayer and meditation.","exja":"修道士は毎日何時間も祈りと瞑想に費やした。"},{"id":3550,"en":"monthly","ja":"月ごとの\n毎月行われる・月に一度の","level":6,"lnum":1,"ex":"She pays a monthly fee for her gym membership.","exja":"彼女はジムの会費を毎月支払っている。"},{"id":3551,"en":"moral","ja":"道徳\n善悪の基準・行動の倫理的教訓","level":6,"lnum":1,"ex":"The story has a clear moral: always be kind to others.","exja":"その物語には明確な教訓がある。常に他者に親切にせよ、というものだ。"},{"id":3552,"en":"mosquito","ja":"蚊\n血を吸う小型昆虫。マラリアなどの病気を媒介する","level":6,"lnum":1,"ex":"She was bitten by a mosquito while sitting in the garden.","exja":"庭に座っていたとき、彼女は蚊に刺された。"},{"id":3553,"en":"moss","ja":"コケ\n湿った場所に生える小型植物。岩や木の表面に生える","level":6,"lnum":1,"ex":"Soft green moss covered the stones along the forest path.","exja":"柔らかい緑色のコケが森の小道に沿って石を覆っていた。"},{"id":3554,"en":"motherland","ja":"母国\n生まれた・愛着を感じる国。homelandより感情的な愛国心を含む","level":6,"lnum":1,"ex":"She felt a deep love for her motherland even after living abroad for years.","exja":"何年も海外で暮らしても、彼女は母国への深い愛情を感じていた。"},{"id":3555,"en":"motionless","ja":"静止した\n全く動かない状態。stillより完全な停止を強調","level":6,"lnum":1,"ex":"The cat sat motionless, watching the bird on the branch.","exja":"猫は枝の上の鳥を見つめながら、じっと動かずに座っていた。"},{"id":3556,"en":"motivate","ja":"動機付ける\n行動を起こす意欲・理由を与える","level":6,"lnum":1,"ex":"The teacher motivated the students by setting achievable goals.","exja":"先生は達成可能な目標を設定することで生徒たちを動機付けた。"},{"id":3557,"en":"motivation","ja":"動機\n行動を起こす意欲・原動力","level":6,"lnum":1,"ex":"His main motivation for studying hard was to make his family proud.","exja":"一生懸命勉強する主な動機は家族を誇りに思わせることだった。"},{"id":3558,"en":"motive","ja":"動機\n特定の行動をとる理由。犯罪捜査でよく使われる","level":6,"lnum":1,"ex":"Police are still trying to determine the motive for the crime.","exja":"警察はまだ犯罪の動機を特定しようとしている。"},{"id":3559,"en":"motor","ja":"モーター\n電気で動く機械の動力源。engineは主に内燃機関","level":6,"lnum":1,"ex":"The small motor in the fan stopped working after many years of use.","exja":"扇風機の小さなモーターは長年の使用の後に動かなくなった。"},{"id":3560,"en":"motorcycle","ja":"オートバイ\n二輪の動力付き乗り物","level":6,"lnum":1,"ex":"He rides a motorcycle to work every day to avoid traffic jams.","exja":"彼は渋滞を避けるために毎日オートバイで通勤する。"},{"id":3561,"en":"motto","ja":"モットー\n信条・行動指針を表す短い言葉・句","level":6,"lnum":1,"ex":"The school's motto is \"Learning for life.\"","exja":"その学校のモットーは「生涯のための学び」だ。"},{"id":3562,"en":"mount","ja":"山\n登山対象の山（固有名詞でMount Everestなど）。動詞では「登る」","level":6,"lnum":1,"ex":"They began to mount the steep hill just before sunrise.","exja":"彼らは日の出直前に急な丘を登り始めた。"},{"id":3563,"en":"mountaintop","ja":"山頂\n山の最も高い頂上部分","level":6,"lnum":1,"ex":"They finally reached the mountaintop after a long and tiring climb.","exja":"長く疲れる登山の末、彼らはついに山頂に到達した。"},{"id":3564,"en":"mourn","ja":"悲しむ\n死や喪失を深く悲しむ。grieveとほぼ同義で正式な葬儀的文脈","level":6,"lnum":1,"ex":"The whole town mourned the death of the beloved teacher.","exja":"町全体が愛された教師の死を悲しんだ。"},{"id":3565,"en":"mud","ja":"泥\n水と土が混ざったどろどろした物質","level":6,"lnum":1,"ex":"After the heavy rain, the trail was covered in thick mud.","exja":"大雨の後、小道は厚い泥で覆われていた。"},{"id":3566,"en":"mule","ja":"ラバ\n馬とロバの交配種。頑固な人を比喩的に指すこともある","level":6,"lnum":1,"ex":"The farmer used a mule to carry goods across the rocky path.","exja":"農家の人は岩だらけの道を荷物を運ぶためにラバを使った。"},{"id":3567,"en":"murder","ja":"殺害する\n意図的に人を殺す。killより計画性・違法性を強調","level":6,"lnum":1,"ex":"The detective investigated the murder in the old mansion.","exja":"探偵は古い屋敷での殺害を調査した。"},{"id":3568,"en":"murderer","ja":"殺人犯\n意図的に人を殺した人","level":6,"lnum":1,"ex":"The murderer was sentenced to life in prison by the court.","exja":"殺人犯は裁判所によって終身刑を宣告された。"},{"id":3569,"en":"muscle","ja":"筋肉\n体を動かす繊維状の組織。比喩的に「力・影響力」にも使用","level":6,"lnum":1,"ex":"Regular exercise helps build strong muscles and improve health.","exja":"定期的な運動は強い筋肉をつけ、健康を改善するのに役立つ。"},{"id":3570,"en":"mutual","ja":"相互の\n双方が同様に感じる・行う状態。「mutual respect」で相互尊重","level":6,"lnum":1,"ex":"The two companies had a mutual agreement to share resources.","exja":"二社は資源を共有する相互合意を結んでいた。"},{"id":3571,"en":"myth","ja":"神話\n古代から伝わる物語。根拠のない俗説にも使用","level":6,"lnum":1,"ex":"Many ancient cultures have their own myths about the creation of the world.","exja":"多くの古代文化には世界の創造についての独自の神話がある。"},{"id":3572,"en":"naked","ja":"裸の\n衣服を着ていない状態。bareより全身に使う","level":6,"lnum":1,"ex":"The baby ran naked across the living room after her bath.","exja":"赤ちゃんはお風呂の後、リビングを裸で走り回った。"},{"id":3573,"en":"narrate","ja":"語る\n物語・出来事を順序立てて話す・書く","level":6,"lnum":1,"ex":"He narrated the story in such a vivid way that everyone was captivated.","exja":"彼はとても生き生きとした方法で物語を語り、全員が引き込まれた。"},{"id":3574,"en":"narrative","ja":"物語の\n語りや物語に関係する。ストーリーテリングのスタイルを指す","level":6,"lnum":1,"ex":"The film uses a unique narrative style to tell the story from different viewpoints.","exja":"その映画は異なる視点から物語を伝えるユニークな語り方のスタイルを使っている。"},{"id":3575,"en":"nasty","ja":"不快な\n非常に嫌な・意地悪な。unpleasantより強い嫌悪感","level":6,"lnum":1,"ex":"The nasty smell from the garbage made it hard to breathe.","exja":"ゴミからの不快な臭いは息をするのが辛くなるほどだった。"},{"id":3576,"en":"nationalist","ja":"民族主義者\n自国・自民族の優位性を強く主張する人","level":6,"lnum":1,"ex":"The nationalist party won a large number of seats in the election.","exja":"民族主義政党は選挙で多数の議席を獲得した。"},{"id":3577,"en":"naturally","ja":"自然に\n当然のこととして・人工的でなく。「of course」に近い使い方も","level":6,"lnum":1,"ex":"She naturally took the lead when the team had no clear direction.","exja":"チームに明確な方向性がなかったとき、彼女は自然にリーダーシップを取った。"},{"id":3578,"en":"navy blue","ja":"紺色の\n濃い青色。海軍の制服の色に由来する","level":6,"lnum":1,"ex":"She wore a navy blue dress to the formal dinner.","exja":"彼女は正式なディナーに紺色のドレスを着ていった。"},{"id":3579,"en":"nectar","ja":"花の蜜\n花が分泌する甘い液体。「神々の飲み物」の意味でも使う","level":6,"lnum":1,"ex":"Bees collect nectar from flowers to make honey.","exja":"ミツバチは花から蜜を集めてはちみつを作る。"},{"id":3580,"en":"negotiate","ja":"交渉する\n合意に達するために話し合う。妥協点を探る過程を含む","level":6,"lnum":1,"ex":"The two countries agreed to negotiate a peace treaty.","exja":"二国は平和条約を交渉することに合意した。"},{"id":3581,"en":"negotiation","ja":"交渉\n合意を目指した話し合い・折衝のプロセス","level":6,"lnum":1,"ex":"After long negotiation, both sides finally reached an agreement.","exja":"長い交渉の末、両者はついに合意に達した。"},{"id":3582,"en":"nervousness","ja":"緊張\n不安・心配による落ち着かない状態","level":6,"lnum":1,"ex":"She tried to hide her nervousness before giving the speech.","exja":"彼女はスピーチをする前に緊張を隠そうとした。"},{"id":3583,"en":"ness","ja":"岬\n海や湖に突き出た陸地の先端（地名に使われる接尾辞）","level":6,"lnum":1,"ex":"Skegness is a small town located on a ness on the east coast of England.","exja":"スケグネスはイングランド東海岸の岬に位置する小さな町だ。"},{"id":3584,"en":"network","ja":"ネットワーク\n相互につながったシステム・人の集まり","level":6,"lnum":1,"ex":"She built a strong professional network during her years in the industry.","exja":"彼女は業界での年月の中で強力なプロフェッショナルネットワークを築いた。"},{"id":3585,"en":"neutral","ja":"中立の\nどちらの側にも偏らない立場。biasedの反対","level":6,"lnum":1,"ex":"Switzerland is known for remaining neutral during many conflicts.","exja":"スイスは多くの紛争においても中立を保つことで知られている。"},{"id":3586,"en":"nevertheless","ja":"それにもかかわらず\n前述の事実に反するが。howeverより書き言葉的・強調的","level":6,"lnum":1,"ex":"The weather was terrible; nevertheless, they decided to go hiking.","exja":"天気はひどかったが、それにもかかわらず彼らはハイキングに行くことにした。"},{"id":3587,"en":"newborn","ja":"生まれたばかりの\n出生直後の赤ちゃんや動物を指す","level":6,"lnum":1,"ex":"The hospital had a special ward for newborn babies.","exja":"病院には生まれたばかりの赤ちゃんのための特別な病棟があった。"},{"id":3588,"en":"newcomer","ja":"新参者\n新しく来た・加わった人。beginnerより「場所への新参」を強調","level":6,"lnum":1,"ex":"The newcomer quickly adapted to the school's daily routine.","exja":"新参者は学校の日課にすぐに慣れた。"},{"id":3589,"en":"newly","ja":"新たに\n最近・新しく。「newly married」で新婚の","level":6,"lnum":1,"ex":"The newly built bridge opened to traffic last week.","exja":"新しく建設された橋は先週、通行のために開通した。"},{"id":3590,"en":"next door","ja":"隣に\n隣の建物・部屋に（副詞として使用）","level":6,"lnum":1,"ex":"My best friend lives next door, so we see each other every day.","exja":"親友が隣に住んでいるので、毎日顔を合わせる。"},{"id":3591,"en":"next-door","ja":"隣の\n隣接した建物や部屋を修飾する形容詞","level":6,"lnum":1,"ex":"My next-door neighbor always waters the flowers in his garden.","exja":"隣の人はいつも庭の花に水をやっている。"},{"id":3592,"en":"nickname","ja":"あだ名\n本名の代わりに使う非公式の呼び名","level":6,"lnum":1,"ex":"His friends gave him the nickname \"Flash\" because he ran so fast.","exja":"彼がとても速く走るので、友人たちは彼に「フラッシュ」というあだ名をつけた。"},{"id":3593,"en":"nightlife","ja":"夜の娯楽\n夜間のバー・クラブなどの娯楽活動の総称","level":6,"lnum":1,"ex":"The city is well known for its exciting nightlife and restaurants.","exja":"その街は刺激的な夜の娯楽とレストランで広く知られている。"},{"id":3594,"en":"noisily","ja":"騒がしく\nうるさい音を立てながら。quietlyの反対","level":6,"lnum":1,"ex":"The children played noisily in the park all afternoon.","exja":"子どもたちは午後中、公園で騒がしく遊んだ。"},{"id":3595,"en":"none","ja":"誰も〜ない\n三人以上または不可算名詞に対して使う否定。nobodyは人のみ","level":6,"lnum":1,"ex":"None of the students had finished the assignment by the deadline.","exja":"締め切りまでに課題を終えた生徒は誰もいなかった。"},{"id":3596,"en":"nonetheless","ja":"それでもなお\n前述を認めつつ反論する。neverthelessとほぼ同義","level":6,"lnum":1,"ex":"The movie received mixed reviews; nonetheless, it was a huge hit.","exja":"その映画は賛否両論だったが、それでもなお大ヒットとなった。"},{"id":3597,"en":"nonsense","ja":"ばかげたこと\n意味をなさない言葉・行動。absurdityより日常的な表現","level":6,"lnum":1,"ex":"Stop talking nonsense and tell me what really happened.","exja":"ばかげたことを言うのをやめて、実際に何が起きたか教えてください。"},{"id":3598,"en":"nor","ja":"〜もない\n否定の並列を示す接続詞。「neither A nor B」で使う","level":6,"lnum":1,"ex":"She neither called nor sent a message after the argument.","exja":"口論の後、彼女は電話もメッセージも送らなかった。"},{"id":3599,"en":"normally","ja":"通常は\n普通の状況では。usuallyとほぼ同義だが習慣の正常性を強調","level":6,"lnum":1,"ex":"The store normally opens at nine, but it was closed today.","exja":"その店は通常9時に開くが、今日は閉まっていた。"},{"id":3600,"en":"northeast","ja":"北東の\n北と東の中間方向","level":6,"lnum":1,"ex":"The storm is moving slowly toward the northeast.","exja":"嵐はゆっくりと北東の方向に向かって移動している。"},{"id":3601,"en":"northeastern","ja":"北東部の\n北東方向に位置する地域を指す形容詞","level":6,"lnum":1,"ex":"The northeastern part of the country receives heavy snowfall in winter.","exja":"その国の北東部は冬に大量の積雪がある。"},{"id":3602,"en":"northwest","ja":"北西の\n北と西の中間方向","level":6,"lnum":1,"ex":"They drove northwest for several hours to reach the national park.","exja":"彼らは国立公園に到達するために数時間北西に向かって車を走らせた。"},{"id":3603,"en":"northwestern","ja":"北西部の\n北西方向に位置する地域を指す形容詞","level":6,"lnum":1,"ex":"The northwestern region of the country is famous for its beautiful forests.","exja":"その国の北西部は美しい森で有名だ。"},{"id":3604,"en":"noticeable","ja":"目立つ\n容易に気づかれる・見てわかる変化","level":6,"lnum":1,"ex":"There was a noticeable difference in her attitude after the holiday.","exja":"休暇後、彼女の態度に目立った変化があった。"},{"id":3605,"en":"noticeboard","ja":"掲示板\n情報を貼り出す板。英国英語でbulletin boardに相当","level":6,"lnum":1,"ex":"The job offers were posted on the noticeboard in the hallway.","exja":"求人情報は廊下の掲示板に貼り出されていた。"},{"id":3606,"en":"notion","ja":"概念\n漠然とした考え・見解。conceptより曖昧で非公式","level":6,"lnum":1,"ex":"He had no notion of how difficult the project would be.","exja":"そのプロジェクトがどれほど難しいか、彼にはまったく見当もつかなかった。"},{"id":3607,"en":"notorious","ja":"悪名高い\n悪いことで広く知られている。famousの否定的バージョン","level":6,"lnum":1,"ex":"The region is notorious for its extreme weather conditions.","exja":"その地域は極端な気象条件で悪名高い。"},{"id":3608,"en":"novelist","ja":"小説家\n長編フィクションを書く作家","level":6,"lnum":1,"ex":"The novelist spent three years writing her latest book.","exja":"その小説家は最新の本を書くのに3年を費やした。"},{"id":3609,"en":"nowhere","ja":"どこにも〜ない\nどの場所にも存在しないことを示す副詞","level":6,"lnum":1,"ex":"I looked everywhere for my keys but found them nowhere.","exja":"鍵をあちこち探したが、どこにも見つからなかった。"},{"id":3610,"en":"nucleus","ja":"核\n原子の中心部分・細胞の中核。比喩的に「中心」の意味","level":6,"lnum":1,"ex":"The nucleus of the atom contains protons and neutrons.","exja":"原子の核には陽子と中性子が含まれている。"},{"id":3611,"en":"numerous","ja":"多数の\n非常に数が多い。manyより書き言葉的・強調的","level":6,"lnum":1,"ex":"She received numerous messages of support after her speech.","exja":"スピーチの後、彼女は多数の支持メッセージを受け取った。"},{"id":3612,"en":"nutrient","ja":"栄養素\n体に必要な栄養成分。vitaminやmineralを含む上位概念","level":6,"lnum":1,"ex":"Fruits and vegetables are full of essential nutrients.","exja":"果物と野菜は必須栄養素が豊富だ。"},{"id":3613,"en":"nutrition","ja":"栄養\n食物から得る栄養素・栄養学の分野","level":6,"lnum":1,"ex":"Good nutrition is important for children's growth and development.","exja":"よい栄養は子どもの成長と発達にとって重要だ。"},{"id":3614,"en":"nutritious","ja":"栄養価の高い\n体に必要な栄養を豊富に含む食品の性質","level":6,"lnum":1,"ex":"Whole grains and fresh vegetables make a nutritious meal.","exja":"全粒穀物と新鮮な野菜は栄養価の高い食事を作る。"},{"id":3615,"en":"objection","ja":"異議\n反対意見・不服の申し立て。法廷での「異議あり」でも使用","level":6,"lnum":1,"ex":"The lawyer raised an objection during the trial.","exja":"弁護士は裁判中に異議を申し立てた。"},{"id":3616,"en":"objective","ja":"目標\n達成しようとする具体的な目的。goalより具体的・測定可能","level":6,"lnum":1,"ex":"The main objective of the project is to reduce carbon emissions.","exja":"そのプロジェクトの主な目標は炭素排出量を削減することだ。"},{"id":3617,"en":"observation","ja":"観察\n注意深く見ること・その結果の所見","level":6,"lnum":1,"ex":"Her careful observation of the birds helped her identify the rare species.","exja":"鳥を注意深く観察したことで、彼女はその希少種を識別することができた。"},{"id":3618,"en":"obstacle","ja":"障害\n前進を妨げるもの・困難。barrierより具体的な障害物","level":6,"lnum":1,"ex":"The fallen tree was a major obstacle on the hiking trail.","exja":"倒れた木はハイキングコースの大きな障害となっていた。"},{"id":3619,"en":"obtain","ja":"入手する\n努力して手に入れる。getより公式・書き言葉的","level":6,"lnum":1,"ex":"She worked hard to obtain a scholarship to study abroad.","exja":"彼女は留学の奨学金を得るために一生懸命努力した。"},{"id":3620,"en":"obvious","ja":"明らかな\n誰の目にも明らかな・疑いの余地がない","level":6,"lnum":1,"ex":"It was obvious that he had not prepared for the presentation.","exja":"彼がプレゼンテーションの準備をしていなかったことは明らかだった。"},{"id":3621,"en":"obviously","ja":"明らかに\n誰でも分かるほど明白に","level":6,"lnum":1,"ex":"She was obviously tired after working all night on the project.","exja":"プロジェクトに一晩中取り組んだ後、彼女は明らかに疲れていた。"},{"id":3622,"en":"occasion","ja":"機会\n特定の出来事が起こる時・機会。eventより一般的・広い概念","level":6,"lnum":1,"ex":"A birthday is a special occasion worth celebrating with family.","exja":"誕生日は家族と一緒にお祝いする価値のある特別な機会だ。"},{"id":3623,"en":"occasional","ja":"時々の\n不定期に起こる・まれな。rareより頻度が高い","level":6,"lnum":1,"ex":"She took an occasional break from studying to rest her eyes.","exja":"彼女は目を休めるために、時々勉強から小休憩をとった。"},{"id":3624,"en":"occasionally","ja":"時々\n不定期に・まれに。sometimesよりやや頻度が少ない印象","level":6,"lnum":1,"ex":"He occasionally stays up late to watch football on television.","exja":"彼は時々遅くまで起きてテレビでサッカーを見る。"},{"id":3625,"en":"occupy","ja":"占める\n空間・時間・地位を占有する。空間的または比喩的に使用","level":6,"lnum":1,"ex":"The students occupied the library all afternoon studying for exams.","exja":"生徒たちは試験勉強のために午後中図書館を占有した。"},{"id":3626,"en":"occur","ja":"起こる\n出来事が発生する。happenより書き言葉的・正式な文脈","level":6,"lnum":1,"ex":"Natural disasters can occur at any time without warning.","exja":"自然災害はいつでも予告なく起こる可能性がある。"},{"id":3627,"en":"offensive","ja":"不快な\n攻撃的・侮辱的な言動。「on the offensive」で攻撃側に","level":6,"lnum":1,"ex":"The comment was considered offensive by many people in the room.","exja":"その発言は部屋にいる多くの人が不快だと感じた。"},{"id":3628,"en":"officially","ja":"公式に\n正式な権限・手続きに従って","level":6,"lnum":1,"ex":"The new bridge was officially opened by the mayor last month.","exja":"新しい橋は先月、市長によって公式に開通された。"},{"id":3629,"en":"oily","ja":"油っこい\n油分が多い・べとべとした感触","level":6,"lnum":1,"ex":"After a long day outdoors, her skin felt oily and in need of washing.","exja":"一日中外にいた後、彼女の肌は油っぽく感じ、洗顔が必要だった。"},{"id":3630,"en":"old-fashioned","ja":"時代遅れの\n現代のスタイル・考え方に合わない古いもの","level":6,"lnum":1,"ex":"Some people prefer old-fashioned cooking methods over modern ones.","exja":"現代の方法よりも昔ながらの料理法を好む人もいる。"},{"id":3631,"en":"oneself","ja":"自分自身\n再帰代名詞。自分で行うことを強調する","level":6,"lnum":1,"ex":"It is important to take care of oneself before helping others.","exja":"他者を助ける前に自分自身の面倒を見ることが大切だ。"},{"id":3632,"en":"onstage","ja":"舞台上の\n劇場の舞台の上にいる・演技中の状態","level":6,"lnum":1,"ex":"The actor was nervous the first time he performed onstage in front of a large audience.","exja":"俳優は初めて大勢の観客の前で舞台に立ったとき、緊張した。"},{"id":3633,"en":"opening","ja":"開口部\n穴・入口・機会。「job opening」で求人の意味も","level":6,"lnum":1,"ex":"There was a small opening in the fence that the cat squeezed through.","exja":"猫がすり抜けたフェンスの小さな隙間があった。"},{"id":3634,"en":"opposite","ja":"反対側に\n向かい合った位置に。「sit opposite」で向かいに座る","level":6,"lnum":1,"ex":"The two sisters have completely opposite personalities.","exja":"その二人の姉妹はまったく反対の性格を持っている。"},{"id":3635,"en":"opposition","ja":"反対\n対抗する立場・勢力。resistanceより組織的な反対","level":6,"lnum":1,"ex":"There was strong opposition from the public against the new law.","exja":"新しい法律に対して市民からの強い反対があった。"},{"id":3636,"en":"oppress","ja":"抑圧する\n権力で人を不当に支配・苦しめる","level":6,"lnum":1,"ex":"The government tried to oppress any voices that disagreed with its policies.","exja":"政府は自国の政策に反対するどんな声も抑圧しようとした。"},{"id":3637,"en":"oppression","ja":"抑圧\n権力による不当な支配・苦しめる状態","level":6,"lnum":1,"ex":"The people rose up against the years of oppression by the regime.","exja":"人々は政権による長年の抑圧に対して立ち上がった。"},{"id":3638,"en":"option","ja":"選択肢\n選ぶことができる可能性の一つ。choiceより多数から選ぶ印象","level":6,"lnum":1,"ex":"You have the option to pay in cash or by credit card.","exja":"現金またはクレジットカードで支払うという選択肢がある。"},{"id":3639,"en":"oral","ja":"口頭の\n口で話す・書かれていない形式","level":6,"lnum":1,"ex":"The students were required to give an oral report in front of the class.","exja":"生徒たちはクラスの前で口頭報告をするよう求められた。"},{"id":3640,"en":"orbit","ja":"軌道\n惑星・衛星が天体の周りを回る経路","level":6,"lnum":1,"ex":"The satellite takes ninety minutes to complete one orbit around the Earth.","exja":"その衛星は地球を一周する軌道を完成させるのに90分かかる。"},{"id":3641,"en":"orderly","ja":"整然とした\nきちんと整理された・規律ある状態。neatより規律性を強調","level":6,"lnum":1,"ex":"The soldiers lined up in an orderly manner before the ceremony.","exja":"兵士たちは式典の前に整然と並んだ。"},{"id":3642,"en":"organ","ja":"臓器\n心臓・肺などの体内の機能的組織。パイプオルガンにも使う","level":6,"lnum":1,"ex":"The heart is the most important organ in the human body.","exja":"心臓は人体で最も重要な臓器だ。"},{"id":3643,"en":"organic","ja":"有機的な\n農薬不使用の・生物由来の。化学的でない自然なものを示す","level":6,"lnum":1,"ex":"She prefers to buy organic vegetables at the local farmers' market.","exja":"彼女は地元のファーマーズマーケットで有機野菜を買うことを好む。"},{"id":3644,"en":"organism","ja":"生物\n生命活動を行う生き物の総称","level":6,"lnum":1,"ex":"A bacterium is a single-celled organism that can be found everywhere.","exja":"細菌はどこにでも見られる単細胞生物だ。"},{"id":3645,"en":"otherwise","ja":"さもなければ\n違う状況では・別の方法で。条件の結果を示す","level":6,"lnum":1,"ex":"Study hard now; otherwise, you might regret it later.","exja":"今一生懸命勉強しなさい、さもなければ後で後悔するかもしれない。"},{"id":3646,"en":"ought to","ja":"〜すべきだ\n義務・期待を示す法助動詞。shouldより強い道徳的含意","level":6,"lnum":1,"ex":"You ought to apologize to her for what you said yesterday.","exja":"昨日言ったことについて彼女に謝るべきだ。"},{"id":3647,"en":"outer","ja":"外側の\n中心・内側から離れた位置の。innerの反対","level":6,"lnum":1,"ex":"The outer walls of the castle were thick and hard to break through.","exja":"城の外壁は厚く、突破するのは難しかった。"},{"id":3648,"en":"outlaw","ja":"無法者\n法律に反して生活する人。歴史的に「法的保護を剥奪された人」","level":6,"lnum":1,"ex":"In the old West, outlaws often robbed banks and escaped into the mountains.","exja":"西部開拓時代、無法者はよく銀行を襲い山に逃げ込んだ。"},{"id":3649,"en":"outline","ja":"概説する\n主要な点を簡単に述べる。detailより要点のみ","level":6,"lnum":1,"ex":"The teacher asked the students to outline their essay before writing it.","exja":"先生は生徒たちにエッセイを書く前に概要をまとめるよう求めた。"},{"id":3650,"en":"out-of-date","ja":"時代遅れの\n現在の状況に合わなくなった情報・スタイル","level":6,"lnum":1,"ex":"The information in this book is out-of-date and needs to be updated.","exja":"この本の情報は時代遅れで、更新する必要がある。"},{"id":3651,"en":"outstanding","ja":"傑出した\n他と比べて際立って優れている。excellentより突出度が高い","level":6,"lnum":1,"ex":"Her performance in the play was outstanding and earned a standing ovation.","exja":"劇での彼女の演技は傑出しており、スタンディングオベーションを受けた。"},{"id":3652,"en":"outward","ja":"外向きの\n内側から外側に向かう方向。inwardの反対","level":6,"lnum":1,"ex":"He kept an outward appearance of calm even though he was nervous inside.","exja":"内心は緊張していたが、彼は外向きには落ち着いた様子を保った。"},{"id":3653,"en":"outweigh","ja":"上回る\n重要性・価値が他を超える。より重要であることを示す","level":6,"lnum":1,"ex":"The benefits of the new policy outweigh the risks.","exja":"新しい方針の利点はリスクを上回る。"},{"id":3654,"en":"overcome","ja":"克服する\n困難・問題を乗り越える。defeatより自分の内的障害に使いやすい","level":6,"lnum":1,"ex":"She worked hard to overcome her fear of public speaking.","exja":"彼女は人前で話すことへの恐怖を克服するために一生懸命努力した。"},{"id":3655,"en":"overjoyed","ja":"大喜びの\n非常に嬉しい・喜びで満ちあふれた状態","level":6,"lnum":1,"ex":"She was overjoyed when she found out she had been accepted to her dream school.","exja":"夢の学校に合格したと知ったとき、彼女は大喜びだった。"},{"id":3656,"en":"overnight","ja":"一晩の\n夜通しの・一夜で起こる。「overnight success」で急な成功","level":6,"lnum":1,"ex":"He took an overnight train to arrive in the city by morning.","exja":"彼は朝までに都市に到着するため夜行列車に乗った。"},{"id":3657,"en":"overwhelm","ja":"圧倒する\n感情・数量が処理しきれないほど強い。surpriseより強烈","level":6,"lnum":1,"ex":"The amount of homework began to overwhelm him at the end of the term.","exja":"学期末に膨大な宿題の量が彼を圧倒し始めた。"},{"id":3658,"en":"overwhelming","ja":"圧倒的な\n対処しきれないほど強い・量が多い状態","level":6,"lnum":1,"ex":"The team felt an overwhelming sense of pride after winning the championship.","exja":"チームは優勝した後、圧倒的な誇りを感じた。"},{"id":3659,"en":"overwork","ja":"過労\n能力以上に働きすぎること・その状態","level":6,"lnum":1,"ex":"He began to overwork himself and eventually became ill.","exja":"彼は働きすぎるようになり、最終的に病気になった。"},{"id":3660,"en":"owe","ja":"借りている\nお金や感謝などを誰かに返す義務がある","level":6,"lnum":1,"ex":"I owe my success to my parents who always supported me.","exja":"私の成功はいつも支えてくれた両親のおかげだ。"},{"id":3661,"en":"owing","ja":"負債のある\n借りがある状態。「owing to」で「〜のせいで」の意味","level":6,"lnum":1,"ex":"She had a large bill owing at the end of the month.","exja":"月末に彼女には多額の請求書の負債があった。"},{"id":3662,"en":"oxygen","ja":"酸素\n生物が呼吸に必要な無色無臭の気体","level":6,"lnum":1,"ex":"Plants produce oxygen through the process of photosynthesis.","exja":"植物は光合成のプロセスを通じて酸素を生産する。"},{"id":3663,"en":"pace","ja":"ペース\n移動・作業の速さ・速度。speedより規則性・リズムを含む","level":6,"lnum":1,"ex":"He set a steady pace from the start and won the race easily.","exja":"彼は最初から安定したペースを維持し、レースを楽に制した。"},{"id":3664,"en":"packing","ja":"荷造り\n旅行や引越しのために荷物をまとめる行為","level":6,"lnum":1,"ex":"She spent the evening packing her suitcase for the trip.","exja":"彼女は旅行のために夜にスーツケースに荷造りをして過ごした。"},{"id":3665,"en":"paddle","ja":"パドル\nカヌーなどを漕ぐための短いオール","level":6,"lnum":1,"ex":"He used a paddle to steer the canoe along the river.","exja":"彼はパドルを使って川沿いにカヌーを操った。"},{"id":3666,"en":"paid","ja":"有給の\n給与が支払われる・賃金を受けた状態","level":6,"lnum":1,"ex":"She took a paid vacation to travel to Europe.","exja":"彼女はヨーロッパに旅行するために有給休暇を取った。"},{"id":3667,"en":"painful","ja":"痛い\n体または心に苦痛をもたらす。hurtfulより身体的痛みを重視","level":6,"lnum":1,"ex":"The dentist warned that the procedure might be a bit painful.","exja":"歯科医は処置が少し痛いかもしれないと警告した。"},{"id":3668,"en":"parachute","ja":"パラシュート\n高所から安全に降下するための傘状の装置","level":6,"lnum":1,"ex":"The soldier jumped from the plane and opened his parachute at the right moment.","exja":"兵士は飛行機から飛び降り、適切なタイミングでパラシュートを開いた。"},{"id":3669,"en":"paradise","ja":"楽園\n完全な幸せと美しさの場所・状態。heavenより地上的なイメージ","level":6,"lnum":1,"ex":"The island with its white beaches and clear water felt like paradise.","exja":"白いビーチと澄んだ水を持つその島は楽園のように感じた。"},{"id":3670,"en":"paralyze/paralyse","ja":"麻痺させる\n体を動けなくする・活動を停止させる","level":6,"lnum":1,"ex":"The accident left him unable to walk and paralyzed from the waist down.","exja":"事故により彼は歩けなくなり、腰から下が麻痺した。"},{"id":3671,"en":"parcel","ja":"小包\n郵送するために包まれた荷物。英国英語でpackageに相当","level":6,"lnum":1,"ex":"She received a parcel in the mail containing a birthday gift.","exja":"彼女は誕生日プレゼントが入った小包を郵便で受け取った。"},{"id":3672,"en":"parental","ja":"親の\n親としての役割・責任に関する","level":6,"lnum":1,"ex":"Parental support is crucial for a child's emotional development.","exja":"親のサポートは子どもの情緒的な発達にとって非常に重要だ。"},{"id":3673,"en":"parking","ja":"駐車\n車を一時的に止めておく行為・場所","level":6,"lnum":1,"ex":"Finding parking in the city center can be very difficult on weekdays.","exja":"平日に市の中心部で駐車場を見つけるのはとても難しい。"},{"id":3674,"en":"parrot","ja":"オウム\n人の言葉を真似る色鮮やかな鳥。動詞で「おうむ返しにする」も","level":6,"lnum":1,"ex":"The parrot in the pet shop could say hello in three different languages.","exja":"ペットショップのオウムは3つの異なる言語で「こんにちは」と言えた。"},{"id":3675,"en":"partial","ja":"部分的な\n全体ではなく一部の。また「えこひいきする」の意味も持つ","level":6,"lnum":1,"ex":"She has a partial understanding of the topic and needs to study more.","exja":"彼女はそのトピックの部分的な理解しかなく、もっと勉強する必要がある。"},{"id":3676,"en":"participant","ja":"参加者\n活動・イベントに加わっている人","level":6,"lnum":1,"ex":"Every participant in the competition received a certificate.","exja":"大会のすべての参加者は証明書を受け取った。"},{"id":3677,"en":"participate","ja":"参加する\n活動に積極的に加わる。joinより継続的・積極的な関与","level":6,"lnum":1,"ex":"Students are encouraged to participate actively in class discussions.","exja":"生徒たちはクラスの討論に積極的に参加することが奨励されている。"},{"id":3678,"en":"participle","ja":"分詞\n動詞から派生した形容詞的・副詞的な動詞形（文法用語）","level":6,"lnum":1,"ex":"In English, the past participle is often used in perfect tenses.","exja":"英語では、過去分詞は完了形でよく使われる。"},{"id":3679,"en":"particularly","ja":"特に\n他と比べて際立って。especiallyとほぼ同義","level":6,"lnum":1,"ex":"I particularly enjoyed the dessert at last night's dinner.","exja":"昨夜のディナーのデザートが特に気に入った。"},{"id":3680,"en":"part-time","ja":"パートタイムの\nフルタイムより少ない時間で働く・学ぶ状態","level":6,"lnum":1,"ex":"She worked part-time at a café while studying at university.","exja":"彼女は大学で勉強しながら、カフェでパートタイムで働いた。"},{"id":3681,"en":"passive","ja":"受け身の\n行動せず受け入れる態度。activeの反対。文法の受動態にも使用","level":6,"lnum":1,"ex":"His passive attitude made it hard for the team to move forward.","exja":"彼の受け身な態度がチームの前進を難しくした。"},{"id":3682,"en":"password","ja":"パスワード\n認証に使う秘密の文字列","level":6,"lnum":1,"ex":"Make sure to use a strong password that includes numbers and symbols.","exja":"数字と記号を含む強いパスワードを使用するようにしてください。"},{"id":3683,"en":"patience","ja":"忍耐\n苛立ちを感じずに待てる能力。impatience（焦り）の反対","level":6,"lnum":1,"ex":"Teaching young children requires a great deal of patience.","exja":"幼い子どもたちを教えることは非常に大きな忍耐を必要とする。"},{"id":3684,"en":"patrol","ja":"巡回\n安全確認のために定期的に見回ること","level":6,"lnum":1,"ex":"Security guards patrol the building every hour throughout the night.","exja":"警備員は夜間を通じて毎時間建物を巡回する。"},{"id":3685,"en":"pattern","ja":"パターン\n繰り返す規則的な形・行動の傾向","level":6,"lnum":1,"ex":"The wallpaper had a repeating pattern of flowers and leaves.","exja":"壁紙には花と葉の繰り返しのパターンがあった。"},{"id":3686,"en":"peanut","ja":"ピーナッツ\n地中に育つ豆科の食用植物の実","level":6,"lnum":1,"ex":"She made a sandwich with peanut butter and banana for lunch.","exja":"彼女は昼食にピーナッツバターとバナナのサンドイッチを作った。"},{"id":3687,"en":"peculiar","ja":"奇妙な\n通常と異なる・風変わりな。strangeより個人的な奇妙さ","level":6,"lnum":1,"ex":"There was a peculiar smell coming from the old building.","exja":"その古い建物から奇妙な臭いがしていた。"},{"id":3688,"en":"penniless","ja":"一文無しの\nお金が全くない状態。poorより完全な無一文を示す","level":6,"lnum":1,"ex":"After losing his job, he found himself penniless and unable to pay the rent.","exja":"仕事を失った後、彼は一文無しになり家賃を払えない状況になった。"},{"id":3689,"en":"penny","ja":"ペニー\n英国・米国の最小硬貨単位","level":6,"lnum":1,"ex":"She found a penny on the sidewalk and picked it up for good luck.","exja":"彼女は歩道でペニーを見つけ、幸運を願って拾い上げた。"},{"id":3690,"en":"per","ja":"〜につき\n単位あたりを示す前置詞。「per hour」で「1時間につき」","level":6,"lnum":1,"ex":"The speed limit on the highway is 100 kilometers per hour.","exja":"高速道路の制限速度は時速100キロメートルだ。"},{"id":3691,"en":"permanent","ja":"永続的な\n変わらず長く続く状態。temporaryの反対","level":6,"lnum":1,"ex":"She finally found a permanent job after months of searching.","exja":"何か月もの求職活動の末、彼女はついに正社員の仕事を見つけた。"},{"id":3692,"en":"permanently","ja":"永久に\n永続的な形で・ずっと変わらずに","level":6,"lnum":1,"ex":"The factory was permanently closed after the fire.","exja":"工場は火事の後、永久に閉鎖された。"},{"id":3693,"en":"permit","ja":"許可する\n公式に認める・許す。allowより正式な権限を含む","level":6,"lnum":1,"ex":"Visitors are not permitted to take photographs inside the museum.","exja":"訪問者は博物館内での写真撮影を許可されていない。"},{"id":3694,"en":"personally","ja":"個人的に\n自分自身として・一個人として。「I personally think」で個人的意見","level":6,"lnum":1,"ex":"I personally think that honesty is the most important value.","exja":"個人的には、誠実さが最も重要な価値だと思う。"},{"id":3695,"en":"persuade","ja":"説得する\n論理や感情で意見・行動を変えさせる","level":6,"lnum":1,"ex":"She managed to persuade her parents to let her study abroad.","exja":"彼女はなんとか両親を説得して留学を許可してもらった。"},{"id":3696,"en":"persuasive","ja":"説得力のある\n人を納得させる力がある。convincingとほぼ同義","level":6,"lnum":1,"ex":"His persuasive speech convinced the committee to approve the proposal.","exja":"彼の説得力のあるスピーチが委員会に提案を承認させた。"},{"id":3697,"en":"phantom","ja":"幽霊の\n実体のない・幻の存在を指す。ghostより神秘的・文学的","level":6,"lnum":1,"ex":"In the old legend, a phantom was said to haunt the castle at night.","exja":"古い伝説では、夜に幽霊が城に出没すると言われていた。"},{"id":3698,"en":"pharmacy","ja":"薬局\n処方箋薬や一般薬を販売する店","level":6,"lnum":1,"ex":"She stopped at the pharmacy to pick up her prescription.","exja":"彼女は処方薬を受け取るために薬局に立ち寄った。"},{"id":3699,"en":"phenomenon","ja":"現象\n観察できる出来事・事実。eventより科学的・学術的な文脈","level":6,"lnum":1,"ex":"The northern lights are a natural phenomenon that attracts tourists worldwide.","exja":"オーロラは世界中から観光客を引き寄せる自然現象だ。"},{"id":3700,"en":"philosopher","ja":"哲学者\n人生・存在・知識などを深く探求する人","level":6,"lnum":1,"ex":"The famous philosopher wrote about the meaning of happiness and a good life.","exja":"その有名な哲学者は幸福と良い人生の意味について書いた。"},{"id":3701,"en":"philosophy","ja":"哲学\n存在・知識・価値などを探求する学問","level":6,"lnum":1,"ex":"She studied philosophy to better understand human nature and ethics.","exja":"彼女は人間の本性と倫理をよりよく理解するために哲学を学んだ。"},{"id":3702,"en":"phoenix/phenix","ja":"不死鳥\n灰から蘇る伝説の鳥。再生・復活の象徴として比喩的に使用","level":6,"lnum":1,"ex":"After the company nearly collapsed, it rose like a phoenix with a new strategy.","exja":"会社は倒産寸前だったが、新しい戦略で不死鳥のように蘇った。"},{"id":3703,"en":"photocopy","ja":"コピー\n書類などを複写機で複製したもの","level":6,"lnum":1,"ex":"She made a photocopy of the document before sending the original.","exja":"彼女は原本を送る前に書類のコピーを取った。"},{"id":3704,"en":"phrasal verb","ja":"句動詞\n動詞＋前置詞/副詞で構成される慣用表現（文法用語）","level":6,"lnum":1,"ex":"\"Give up\" is a common phrasal verb that means to stop trying.","exja":"\"Give up\"は諦めることを意味する一般的な句動詞だ。"},{"id":3705,"en":"physics","ja":"物理学\n物質・エネルギーの性質を研究する自然科学","level":6,"lnum":1,"ex":"He decided to major in physics because he loved studying how the universe works.","exja":"宇宙の仕組みを学ぶことが好きだったので、彼は物理学を専攻することにした。"},{"id":3706,"en":"piety","ja":"信心深さ\n宗教的な敬虔さ・義務への従順。religiosityより行動的な側面","level":6,"lnum":1,"ex":"Her piety was evident in how she devoted herself to prayer every morning.","exja":"毎朝祈りに身を捧げる姿から、彼女の信心深さが伝わってきた。"},{"id":3707,"en":"pipe","ja":"パイプ\n液体・気体を運ぶ管。または喫煙用パイプ","level":6,"lnum":1,"ex":"The plumber fixed the leaking pipe under the kitchen sink.","exja":"配管工は台所のシンクの下の水漏れしているパイプを修理した。"},{"id":3708,"en":"pit","ja":"穴\n地面を掘った深い穴。果物の種にも使う（cherry pit）","level":6,"lnum":1,"ex":"The children dug a deep pit in the sand at the beach.","exja":"子どもたちはビーチの砂に深い穴を掘った。"},{"id":3709,"en":"plain","ja":"質素な\n装飾がない・シンプルな。simpleより地味さを強調","level":6,"lnum":1,"ex":"She preferred plain food without too many spices or sauces.","exja":"彼女はスパイスやソースが多すぎない質素な食事を好んでいた。"},{"id":3710,"en":"pleasantly","ja":"心地よく\n楽しく・気持ちよく。agreeablyとほぼ同義","level":6,"lnum":1,"ex":"The afternoon passed pleasantly with music and good conversation.","exja":"午後は音楽と楽しい会話で心地よく過ぎた。"},{"id":3711,"en":"plenty","ja":"十分な量\n必要以上に十分な量。「plenty of」で「十分な〜」","level":6,"lnum":1,"ex":"There is plenty of food for everyone, so please help yourself.","exja":"皆に行き渡るほど十分な食べ物があるので、ご自由にどうぞ。"},{"id":3712,"en":"plug","ja":"プラグ\n電気コンセントに差し込む接続器具。穴を塞ぐものにも使用","level":6,"lnum":1,"ex":"She plugged in the laptop to charge the battery before the meeting.","exja":"彼女は会議の前にラップトップのバッテリーを充電するためにプラグを差し込んだ。"},{"id":3713,"en":"plus","ja":"さらに\n加えて・〜に加えて。andより追加の強調","level":6,"lnum":1,"ex":"The job offers a good salary plus free health insurance.","exja":"その仕事は良い給料に加えて無料の健康保険も提供している。"},{"id":3714,"en":"pocket money","ja":"小遣い\n親が子どもに与える少額のお金","level":6,"lnum":1,"ex":"His parents gave him a small amount of pocket money each week.","exja":"両親は毎週少額の小遣いを彼に与えた。"},{"id":3715,"en":"poisonous","ja":"有毒な\n毒を含む・摂取すると有害な物質","level":6,"lnum":1,"ex":"Some mushrooms in the forest are poisonous and should not be eaten.","exja":"森の中のキノコには有毒なものがあり、食べるべきではない。"},{"id":3716,"en":"policy","ja":"方針\n組織・政府の行動指針・規則","level":6,"lnum":1,"ex":"The school has a strict policy against the use of mobile phones in class.","exja":"学校には授業中の携帯電話使用に対する厳格な方針がある。"},{"id":3717,"en":"politely","ja":"丁寧に\n礼儀正しく・失礼のないよう","level":6,"lnum":1,"ex":"She politely declined the offer without hurting his feelings.","exja":"彼女は彼の気持ちを傷つけることなく、丁寧に申し出を断った。"},{"id":3718,"en":"politics","ja":"政治\n国家・政府の統治に関する活動・学問","level":6,"lnum":1,"ex":"She became interested in politics after studying history at school.","exja":"学校で歴史を学んだ後、彼女は政治に興味を持つようになった。"},{"id":3719,"en":"pollutant","ja":"汚染物質\n環境を汚染する化学物質や廃棄物","level":6,"lnum":1,"ex":"Factory waste is a major pollutant that harms rivers and wildlife.","exja":"工場廃棄物は川や野生動物に害を与える主要な汚染物質だ。"},{"id":3720,"en":"positively","ja":"積極的に\n前向きに・肯定的に。negativelyの反対","level":6,"lnum":1,"ex":"She tried to think positively despite the challenges she faced.","exja":"直面した困難にもかかわらず、彼女は積極的に考えようとした。"},{"id":3721,"en":"possess","ja":"所有する\n自分のものとして持つ。haveより強い所有権を示す","level":6,"lnum":1,"ex":"He did not possess enough money to buy the new laptop.","exja":"彼は新しいラップトップを買うのに十分なお金を持っていなかった。"},{"id":3722,"en":"possession","ja":"所有物\n所有していること・所有している物","level":6,"lnum":1,"ex":"She carefully packed her most precious possessions into the suitcase.","exja":"彼女は最も大切な所有物をスーツケースに丁寧に詰め込んだ。"},{"id":3723,"en":"possessive","ja":"所有格の\n文法の所有格を示す。また「独占欲が強い」の意味も","level":6,"lnum":1,"ex":"He became too possessive and controlling in the relationship.","exja":"彼は関係の中で過度に独占欲が強くコントロールするようになった。"},{"id":3724,"en":"possibility","ja":"可能性\n起こりうる可能性・確率。probabilityより広い概念","level":6,"lnum":1,"ex":"There is a possibility that school will be cancelled due to the storm.","exja":"嵐のために学校が休校になる可能性がある。"},{"id":3725,"en":"postman","ja":"郵便配達員\n郵便物を届ける職員。英国英語でmail carrierに相当","level":6,"lnum":1,"ex":"The postman delivered a large package to the wrong address by mistake.","exja":"郵便配達員は誤って大きな荷物を間違った住所に届けてしまった。"},{"id":3726,"en":"potential","ja":"可能性\n将来発展しうる能力・未実現の力","level":6,"lnum":1,"ex":"She showed great potential as a musician from a very young age.","exja":"彼女は幼い頃から音楽家としての大きな可能性を示していた。"},{"id":3727,"en":"pottery","ja":"陶芸\n粘土を焼いて作る工芸品・その技術","level":6,"lnum":1,"ex":"She joined a pottery class to learn how to make bowls and vases.","exja":"彼女は茶碗や花瓶の作り方を学ぶために陶芸クラスに参加した。"},{"id":3728,"en":"pound","ja":"ポンド\n英国の通貨単位。重さの単位（約453g）にも使用","level":6,"lnum":1,"ex":"Could you lend me a pound to buy a snack from the vending machine?","exja":"自動販売機でお菓子を買うために1ポンド貸してくれますか？"},{"id":3729,"en":"poverty","ja":"貧困\n基本的な生活に必要なものが足りない状態","level":6,"lnum":1,"ex":"The charity organization works hard to help people living in poverty.","exja":"その慈善団体は貧困の中で生活する人々を助けるために懸命に取り組んでいる。"},{"id":3730,"en":"powder","ja":"粉末\n細かく砕かれた乾燥した粒子状の物質","level":6,"lnum":1,"ex":"She added a spoonful of cocoa powder to the warm milk.","exja":"彼女は温かいミルクにカカオパウダーをスプーン一杯加えた。"},{"id":3731,"en":"practical","ja":"実用的な\n実際の使用に役立つ。theoreticalの反対","level":6,"lnum":1,"ex":"She gave some practical advice on how to save money each month.","exja":"彼女は毎月お金を節約する方法について実用的なアドバイスをした。"},{"id":3732,"en":"praise","ja":"称賛\n優れた点を認めて褒めること。complimentより公的・強い表現","level":6,"lnum":1,"ex":"The teacher praised the student for her excellent work on the essay.","exja":"先生はエッセイの素晴らしい出来を褒めて生徒を称賛した。"},{"id":3733,"en":"prayer","ja":"祈り\n神や高次の存在に向けた言葉・行為","level":6,"lnum":1,"ex":"She said a short prayer before the meal.","exja":"彼女は食事の前に短い祈りを唱えた。"},{"id":3734,"en":"preference","ja":"好み\n複数の選択肢の中で特定のものを好むこと","level":6,"lnum":1,"ex":"His preference for working in the morning made him more productive.","exja":"午前中に働くことへの彼の好みが、より生産的にさせた。"},{"id":3735,"en":"prefix","ja":"接頭辞\n単語の前に付けて意味を変える文字列（文法用語）","level":6,"lnum":1,"ex":"Adding the prefix \"un-\" to \"happy\" creates the word \"unhappy.\"","exja":"「happy」に接頭辞「un-」を追加すると「unhappy」という単語ができる。"},{"id":3736,"en":"pregnant","ja":"妊娠した\n胎内に子どもを宿している状態","level":6,"lnum":1,"ex":"She found out she was pregnant and shared the news with her family.","exja":"妊娠していることが分かり、家族にその知らせを伝えた。"},{"id":3737,"en":"prejudice","ja":"偏見\n根拠のない否定的な先入観。biasより感情的・差別的","level":6,"lnum":1,"ex":"It is important to treat everyone fairly and without prejudice.","exja":"誰もを公平に、偏見なく扱うことが大切だ。"},{"id":3738,"en":"preparation","ja":"準備\n何かをする前に整える行為","level":6,"lnum":1,"ex":"Careful preparation is the key to giving a successful presentation.","exja":"入念な準備が成功するプレゼンテーションの鍵だ。"},{"id":3739,"en":"prepared","ja":"準備できた\n前もって整えた状態・覚悟ができた状態","level":6,"lnum":1,"ex":"Are you prepared for the questions they might ask at the interview?","exja":"面接で聞かれるかもしれない質問に準備できていますか？"},{"id":3740,"en":"preposition","ja":"前置詞\n名詞の前に置いて関係を示す語（文法用語）","level":6,"lnum":1,"ex":"In the phrase \"on the table,\" the word \"on\" is a preposition.","exja":"「on the table」というフレーズでは、「on」という語が前置詞だ。"},{"id":3741,"en":"preschool","ja":"就学前の\n小学校入学前の年齢・教育に関する","level":6,"lnum":1,"ex":"Many children attend preschool before starting primary school.","exja":"多くの子どもたちは小学校に入学する前に就学前教育施設に通う。"},{"id":3742,"en":"prescription","ja":"処方箋\n医師が薬を指定した文書。「by prescription only」で処方箋必須","level":6,"lnum":1,"ex":"The doctor wrote a prescription for the medicine she needed.","exja":"医師は彼女が必要とする薬の処方箋を書いた。"},{"id":3743,"en":"presence","ja":"存在\nその場にいること・出席していること。absenceの反対","level":6,"lnum":1,"ex":"Her presence at the meeting made everyone feel more comfortable.","exja":"会議での彼女の存在が全員をより居心地よくさせた。"},{"id":3744,"en":"preservation","ja":"保存\n劣化・破壊から守って維持すること","level":6,"lnum":1,"ex":"The preservation of old buildings is important for cultural heritage.","exja":"古い建物の保存は文化遺産にとって重要だ。"},{"id":3745,"en":"preserve","ja":"保存する\n状態を保ちながら守る。saveより継続的な努力を含む","level":6,"lnum":1,"ex":"The national park was created to preserve the natural environment.","exja":"国立公園は自然環境を保全するために設立された。"},{"id":3746,"en":"press","ja":"報道機関\n新聞・メディアの総称。動詞では「押す・主張する」","level":6,"lnum":1,"ex":"The journalist asked tough questions to the politician at the press conference.","exja":"ジャーナリストは記者会見で政治家に厳しい質問をした。"},{"id":3747,"en":"previous","ja":"前の\n今よりも以前の・直前の。「previous experience」で過去の経験","level":6,"lnum":1,"ex":"She learned from her previous mistake and avoided the same problem.","exja":"彼女は以前の失敗から学び、同じ問題を避けた。"},{"id":3748,"en":"priest","ja":"聖職者\nキリスト教などの宗教的儀式を行う人","level":6,"lnum":1,"ex":"The priest gave a speech about forgiveness and kindness.","exja":"聖職者は許しと親切についてのスピーチをした。"},{"id":3749,"en":"primarily","ja":"主に\n最も重要な点として・第一に。mainlyとほぼ同義だが強調が強い","level":6,"lnum":1,"ex":"The program is designed primarily for beginners who have no experience.","exja":"そのプログラムは主に経験のない初心者向けに設計されている。"},{"id":3750,"en":"primary school","ja":"小学校\n基礎教育を行う学校。英国英語でelementary schoolに相当","level":6,"lnum":1,"ex":"She made many lifelong friends when she attended primary school.","exja":"小学校に通っていたとき、彼女は多くの生涯の友人を作った。"},{"id":3751,"en":"primitive","ja":"原始的な\n発達段階が初期の・洗練されていない。ancientより未発達を強調","level":6,"lnum":1,"ex":"Archaeologists discovered primitive tools used by early humans.","exja":"考古学者は初期の人間が使用した原始的な道具を発見した。"},{"id":3752,"en":"principle","ja":"原則\n行動の基本的なルール・信条。ruleより概念的・道徳的","level":6,"lnum":1,"ex":"He refused to lie, as it went against his personal principles.","exja":"嘘をつくことは個人の原則に反するため、彼は拒否した。"},{"id":3753,"en":"prison","ja":"刑務所\n犯罪者を収監する施設。jailより長期収容の施設","level":6,"lnum":1,"ex":"He was sent to prison for committing a serious crime.","exja":"彼は重大な犯罪を犯したため刑務所に送られた。"},{"id":3754,"en":"prisoner","ja":"囚人\n刑務所に収監された人・捕虜","level":6,"lnum":1,"ex":"The prisoner was released after serving five years of his sentence.","exja":"囚人は刑期の5年間を務めた後に釈放された。"},{"id":3755,"en":"privacy","ja":"プライバシー\n個人情報・生活を他人から守る権利","level":6,"lnum":1,"ex":"She values her privacy and rarely shares personal information online.","exja":"彼女はプライバシーを大切にしており、個人情報をオンラインで共有することはほとんどない。"},{"id":3756,"en":"probability","ja":"確率\n起こる可能性の数学的な度合い。possibilityより数値的","level":6,"lnum":1,"ex":"The probability of rain tomorrow is very high according to the forecast.","exja":"予報によると、明日の雨が降る確率は非常に高い。"},{"id":3757,"en":"proceed","ja":"続ける\n計画通りに前進する・続行する。continueより公式な文脈","level":6,"lnum":1,"ex":"Despite the delay, the concert proceeded as planned.","exja":"遅れにもかかわらず、コンサートは計画通りに続行された。"},{"id":3758,"en":"proclaim","ja":"宣言する\n公式に・大声で宣告する。announceより劇的・公的","level":6,"lnum":1,"ex":"The king proclaimed a national holiday to celebrate the victory.","exja":"国王は勝利を祝うために国民の祝日を宣言した。"},{"id":3759,"en":"procrastination","ja":"先延ばし\nすべき事を後回しにする行動・習慣","level":6,"lnum":1,"ex":"Procrastination often leads to stress when deadlines approach.","exja":"先延ばしは締め切りが近づくとよくストレスを引き起こす。"},{"id":3760,"en":"producer","ja":"製作者\n映画・音楽などを製作する人。manufacturerは工業製品の製造者","level":6,"lnum":1,"ex":"The film producer raised enough money to start shooting next month.","exja":"映画プロデューサーは来月撮影を開始するのに十分な資金を調達した。"},{"id":3761,"en":"productive","ja":"生産的な\n多くの成果・結果を生み出す。efficientより成果に焦点","level":6,"lnum":1,"ex":"She had a very productive day and finished all her tasks before noon.","exja":"彼女は非常に生産的な一日を過ごし、正午前にすべての仕事を終えた。"},{"id":3762,"en":"profession","ja":"職業\n専門的な資格・訓練を要する仕事。jobより専門性が高い","level":6,"lnum":1,"ex":"Teaching is a profession that requires patience and dedication.","exja":"教えることは忍耐と献身を必要とする職業だ。"},{"id":3763,"en":"prohibition","ja":"禁止\n特定の行為を法律・規則で禁じること","level":6,"lnum":1,"ex":"The prohibition of alcohol in the 1920s led to many illegal activities.","exja":"1920年代のアルコール禁止は多くの違法活動を引き起こした。"},{"id":3764,"en":"prominent","ja":"著名な\n重要で目立つ・有名な。famousより社会的な認知度を強調","level":6,"lnum":1,"ex":"She became a prominent figure in the world of science after her discovery.","exja":"発見の後、彼女は科学の世界で著名な人物となった。"},{"id":3765,"en":"promote","ja":"促進する\n支持・普及させる。advertiseより広い活動全般を指す","level":6,"lnum":1,"ex":"The company launched a campaign to promote its new product.","exja":"その会社は新製品を宣伝するためのキャンペーンを始めた。"},{"id":3766,"en":"promotion","ja":"昇進\n職位が上がること。製品の「プロモーション活動」にも使用","level":6,"lnum":1,"ex":"He received a promotion after years of hard work and dedication.","exja":"何年もの懸命な努力と献身の後、彼は昇進した。"},{"id":3767,"en":"pronoun","ja":"代名詞\n名詞の代わりに使う語（文法用語）","level":6,"lnum":1,"ex":"\"She\" is a personal pronoun used to refer to a female person.","exja":"「She」は女性を指すために使われる人称代名詞だ。"},{"id":3768,"en":"proof","ja":"証拠\n事実を示す証拠・根拠。evidenceより確実性が高い","level":6,"lnum":1,"ex":"The scientist needed more proof before publishing her research results.","exja":"科学者は研究結果を発表する前にさらに多くの証拠が必要だった。"},{"id":3769,"en":"properly","ja":"適切に\n正しい方法で・きちんと。correctlyとほぼ同義","level":6,"lnum":1,"ex":"Make sure to wash your hands properly before eating.","exja":"食事の前に手を適切に洗うようにしてください。"},{"id":3770,"en":"property","ja":"財産\n所有物・不動産。legalに「財産権」の意味も持つ","level":6,"lnum":1,"ex":"He invested his savings in property and bought a small apartment.","exja":"彼は貯金を不動産に投資し、小さなアパートを購入した。"},{"id":3771,"en":"proportion","ja":"割合\n全体に対する部分の比率。ratioより抽象的","level":6,"lnum":1,"ex":"A large proportion of the students passed the exam on their first attempt.","exja":"大きな割合の生徒が初回の受験で試験に合格した。"},{"id":3772,"en":"proposal","ja":"提案\n承認を求めて示す計画・案。suggestionより正式・詳細","level":6,"lnum":1,"ex":"She presented a detailed proposal to improve the school's facilities.","exja":"彼女は学校の施設を改善するための詳細な提案を提出した。"},{"id":3773,"en":"propose","ja":"提案する\n計画や考えを正式に提示する。suggestより改まった場面","level":6,"lnum":1,"ex":"He proposed a new plan that would save the company money.","exja":"彼は会社のコストを削減できる新しい計画を提案した。"},{"id":3774,"en":"prosperity","ja":"繁栄\n経済的・社会的に豊かで成功している状態","level":6,"lnum":1,"ex":"Many immigrants came to the country in search of prosperity.","exja":"多くの移民が繁栄を求めてその国にやってきた。"},{"id":3775,"en":"prosperous","ja":"繁栄した\n豊かで成功している状態。wealthyより幸福感・活力を含む","level":6,"lnum":1,"ex":"The town became prosperous after the new factory opened nearby.","exja":"新しい工場が近くにオープンした後、町は繁栄するようになった。"},{"id":3776,"en":"protection","ja":"保護\n危険・損害から守ること","level":6,"lnum":1,"ex":"Wearing sunscreen provides protection against harmful UV rays.","exja":"日焼け止めを塗ることで有害な紫外線から守られる。"},{"id":3777,"en":"protective","ja":"保護する\n守ろうとする性質・過度に心配する親のニュアンスも","level":6,"lnum":1,"ex":"She felt protective of her younger sister and always looked out for her.","exja":"彼女は妹のことを守りたいと感じ、いつも気にかけていた。"},{"id":3778,"en":"protest","ja":"抗議\n反対意見を公に表明する行為","level":6,"lnum":1,"ex":"Hundreds of people gathered to protest against the new policy.","exja":"何百人もの人々が新しい方針に抗議するために集まった。"},{"id":3779,"en":"prove","ja":"証明する\n事実であることを根拠で示す。demonstrateより論理的","level":6,"lnum":1,"ex":"She worked hard to prove that her theory was correct.","exja":"彼女は自分の理論が正しいことを証明するために一生懸命努力した。"},{"id":3780,"en":"proverb","ja":"ことわざ\n長年伝わる教訓を含む短い言葉","level":6,"lnum":1,"ex":"The proverb \"actions speak louder than words\" is well known around the world.","exja":"「行動は言葉より雄弁だ」ということわざは世界中でよく知られている。"},{"id":3781,"en":"provided","ja":"〜を条件として\n条件を示す接続詞。「provided that」で「〜の場合に限り」","level":6,"lnum":1,"ex":"You can borrow the book provided that you return it within a week.","exja":"1週間以内に返す条件で、その本を借りることができる。"},{"id":3782,"en":"psychological","ja":"心理的な\n心・精神に関係する。mentalより学術的・専門的","level":6,"lnum":1,"ex":"The soldiers received psychological support after returning from the war.","exja":"兵士たちは戦争から戻った後、心理的なサポートを受けた。"},{"id":3783,"en":"pub","ja":"パブ\n英国のアルコール飲料を提供する飲食店","level":6,"lnum":1,"ex":"After work, they all went to the local pub for a drink.","exja":"仕事の後、彼らは全員で地元のパブに飲みに行った。"},{"id":3784,"en":"public transport","ja":"公共交通機関\nバス・鉄道など公共の交通システム","level":6,"lnum":1,"ex":"Many people use public transport to commute to work in the city.","exja":"多くの人が都市での通勤に公共交通機関を利用する。"},{"id":3785,"en":"publicly","ja":"公に\n社会全体に向けて・公開の場で","level":6,"lnum":1,"ex":"The mayor publicly apologized for the mistake during a press conference.","exja":"市長は記者会見で誤りについて公に謝罪した。"},{"id":3786,"en":"publisher","ja":"出版社\n書籍・雑誌などを出版する会社・人","level":6,"lnum":1,"ex":"She sent her manuscript to several publishers before it was accepted.","exja":"彼女は原稿が受け入れられる前に複数の出版社に送った。"},{"id":3787,"en":"pullover","ja":"プルオーバー\n頭からかぶる上着・セーター。英国英語でsweaterに相当","level":6,"lnum":1,"ex":"She grabbed her favorite pullover before heading out into the cold.","exja":"寒い中に出かける前に、彼女はお気に入りのプルオーバーをつかんだ。"},{"id":3788,"en":"pump","ja":"ポンプ\n液体・気体を圧力で移動させる装置","level":6,"lnum":1,"ex":"He used a pump to inflate the flat tire on his bicycle.","exja":"彼はパンクした自転車のタイヤを膨らませるためにポンプを使った。"},{"id":3789,"en":"punish","ja":"罰する\n悪い行為に対して苦痛・不利益を与える","level":6,"lnum":1,"ex":"The school decided to punish the student for cheating on the test.","exja":"学校はテストでカンニングをした生徒を罰することにした。"},{"id":3790,"en":"punishment","ja":"罰\n悪い行為に対して与えられる不利益・苦痛","level":6,"lnum":1,"ex":"The punishment for breaking the rule was staying after school for one hour.","exja":"ルールを破った場合の罰は1時間放課後に残ることだった。"},{"id":3791,"en":"pupil","ja":"生徒\n学校で学ぶ子ども。英国でよく使われ、studentより低年齢向け","level":6,"lnum":1,"ex":"Every pupil in the class was asked to read a paragraph aloud.","exja":"クラスの生徒全員が一段落を声に出して読むよう求められた。"},{"id":3792,"en":"pure","ja":"純粋な\n混じり気のない・汚れのない状態","level":6,"lnum":1,"ex":"The mountain spring water was so pure that you could drink it directly.","exja":"山の湧き水はとても純粋で、直接飲むことができた。"},{"id":3793,"en":"purify","ja":"浄化する\n不純物・汚染を取り除いてきれいにする","level":6,"lnum":1,"ex":"Scientists developed a new method to purify drinking water in remote areas.","exja":"科学者たちは僻地の飲料水を浄化する新しい方法を開発した。"},{"id":3794,"en":"quake","ja":"地震\n大地が激しく揺れる現象。earthquakeの短縮形","level":6,"lnum":1,"ex":"A strong quake hit the coastal city early in the morning.","exja":"強い地震が早朝に沿岸都市を直撃した。"},{"id":3795,"en":"qualified","ja":"資格のある\n必要な能力・資格を持つ。「qualified doctor」で資格を持つ医師","level":6,"lnum":1,"ex":"Only qualified teachers are allowed to lead the advanced course.","exja":"資格のある教師だけが上級コースを担当することが許されている。"},{"id":3796,"en":"qualify","ja":"資格を得る\n条件を満たして資格を得る・適格となる","level":6,"lnum":1,"ex":"You need to pass three exams to qualify as a nurse.","exja":"看護師として資格を得るには3つの試験に合格する必要がある。"},{"id":3797,"en":"question mark","ja":"疑問符\n疑問文の末尾に使う「?」の記号","level":6,"lnum":1,"ex":"There was a question mark at the end of the sentence, so it must be a question.","exja":"文末に疑問符があったので、それは疑問文に違いない。"},{"id":3798,"en":"questionnaire","ja":"アンケート\n情報収集のための質問一覧表","level":6,"lnum":1,"ex":"Students were asked to fill out a questionnaire about their study habits.","exja":"生徒たちは勉強習慣についてのアンケートに記入するよう求められた。"},{"id":3799,"en":"queue","ja":"列\n順番待ちの列。英国英語でlineに相当。動詞で「並ぶ」","level":6,"lnum":1,"ex":"A long queue formed outside the concert hall hours before the show.","exja":"公演の何時間も前にコンサートホールの外に長い列ができた。"},{"id":3800,"en":"racial","ja":"人種の\n人種に関係する。「racial discrimination」で人種差別","level":6,"lnum":1,"ex":"The school adopted a new policy to prevent racial discrimination.","exja":"学校は人種差別を防ぐための新しい方針を採用した。"},{"id":3801,"en":"radiation","ja":"放射線\nエネルギーが波や粒子として放出される現象","level":6,"lnum":1,"ex":"Workers at the plant wear special suits to protect themselves from radiation.","exja":"プラントの作業員は放射線から身を守るために特別なスーツを着用する。"},{"id":3802,"en":"rage","ja":"激怒\n非常に強い怒り。angerより激しく制御が難しい感情","level":6,"lnum":1,"ex":"His face turned red with rage when he heard the unfair decision.","exja":"不公平な決定を聞いて、彼の顔は激怒で真っ赤になった。"},{"id":3803,"en":"rail","ja":"レール\n鉄道の線路・手すり。「by rail」で電車で","level":6,"lnum":1,"ex":"Tourists can travel across the country by rail at a reasonable price.","exja":"旅行者は手頃な価格で電車を使って全国を旅することができる。"},{"id":3804,"en":"railway","ja":"鉄道\n線路と列車による交通システム。英国英語でrailroadに相当","level":6,"lnum":1,"ex":"The new railway line connects the two cities in just thirty minutes.","exja":"新しい鉄道路線が2つの都市をわずか30分でつないでいる。"},{"id":3805,"en":"rainfall","ja":"降雨量\nある期間・場所の雨の量","level":6,"lnum":1,"ex":"The region receives very little rainfall during the summer months.","exja":"その地域は夏の間、降雨量がとても少ない。"},{"id":3806,"en":"rainforest","ja":"熱帯雨林\n高温多湿で雨が多い密生した森林地帯","level":6,"lnum":1,"ex":"Thousands of species of animals live in the Amazon rainforest.","exja":"アマゾンの熱帯雨林には何千種もの動物が生息している。"},{"id":3807,"en":"rank","ja":"ランク\n序列・地位・等級。「top rank」で最高位","level":6,"lnum":1,"ex":"She finished the race in third rank, which was her best result ever.","exja":"彼女はレースを3位で終え、それは彼女の自己最高記録だった。"},{"id":3808,"en":"rap","ja":"ラップする\nリズムに乗って言葉を話す音楽スタイル。軽くたたく意味も","level":6,"lnum":1,"ex":"He began to rap his own lyrics at the school talent show.","exja":"彼は学校のタレントショーで自分の歌詞をラップし始めた。"},{"id":3809,"en":"rapid","ja":"急速な\n速度が非常に速い変化・動き。quickより変化・進行を強調","level":6,"lnum":1,"ex":"The rapid growth of the city surprised even the local residents.","exja":"その都市の急速な成長は地元の住民さえも驚かせた。"},{"id":3810,"en":"rarely","ja":"めったに〜ない\nほとんど起こらない・非常にまれな頻度","level":6,"lnum":1,"ex":"She rarely eats fast food because she prefers home-cooked meals.","exja":"彼女は自炊した料理が好きなので、ファストフードをめったに食べない。"},{"id":3811,"en":"raspberry","ja":"ラズベリー\n赤い小粒の酸味のある果実","level":6,"lnum":1,"ex":"She picked fresh raspberries from the garden and made a smoothie.","exja":"彼女は庭から新鮮なラズベリーを摘んでスムージーを作った。"},{"id":3812,"en":"ration","ja":"配給量\n一定期間の公正な分配量。食料・燃料の制限配分に使用","level":6,"lnum":1,"ex":"During the war, each family received a weekly ration of bread and sugar.","exja":"戦時中、各家族はパンと砂糖の週ごとの配給量を受け取った。"},{"id":3813,"en":"rational","ja":"合理的な\n論理・理性に基づく。emotionalの反対","level":6,"lnum":1,"ex":"It is important to make rational decisions rather than emotional ones in a crisis.","exja":"危機の際には感情的ではなく合理的な判断を下すことが重要だ。"},{"id":3814,"en":"razor","ja":"かみそり\n毛を剃るための刃物","level":6,"lnum":1,"ex":"He bought a new razor because the old one was too dull to shave with.","exja":"古いものが切れ味が悪すぎて使えなくなったので、彼は新しいかみそりを買った。"},{"id":3815,"en":"react","ja":"反応する\n刺激・状況に対して応答する。respondより感情的・即座の反応","level":6,"lnum":1,"ex":"How did the audience react when the singer appeared on stage?","exja":"歌手がステージに現れたとき、観客はどう反応しましたか？"},{"id":3816,"en":"realistic","ja":"現実的な\n実際の状況に即した・実現可能な。idealisticの反対","level":6,"lnum":1,"ex":"We need to set realistic goals that we can actually achieve this year.","exja":"私たちは今年実際に達成できる現実的な目標を設定する必要がある。"},{"id":3817,"en":"rearrange","ja":"並べ直す\n順序・配置を変える。reorganizeとほぼ同義","level":6,"lnum":1,"ex":"She decided to rearrange the furniture to make the room feel larger.","exja":"彼女は部屋を広く感じさせるために家具の配置を変えることにした。"},{"id":3818,"en":"reasonable","ja":"合理的な\n理にかなった・手頃な価格。fairとほぼ同義で両方に使える","level":6,"lnum":1,"ex":"The hotel offered a comfortable stay at a very reasonable price.","exja":"そのホテルはとても合理的な価格で快適な滞在を提供した。"},{"id":3819,"en":"rebuild","ja":"再建する\n壊れたものを建て直す・組み立て直す","level":6,"lnum":1,"ex":"The community came together to rebuild the houses damaged by the flood.","exja":"地域の人々が集まって洪水で被害を受けた家を再建した。"},{"id":3820,"en":"recall","ja":"思い出す\n記憶から引き出す。rememberより意図的な努力を含む","level":6,"lnum":1,"ex":"I could not recall where I had put my keys that morning.","exja":"その朝どこに鍵を置いたか思い出せなかった。"},{"id":3821,"en":"reception","ja":"受付\nホテル・オフィスの受付カウンター。歓迎会の意味も持つ","level":6,"lnum":1,"ex":"Please check in at the reception when you arrive at the hotel.","exja":"ホテルに到着したら受付でチェックインしてください。"},{"id":3822,"en":"recite","ja":"暗唱する\n記憶した文章・詩を声に出して言う","level":6,"lnum":1,"ex":"The students were asked to recite the poem in front of the class.","exja":"生徒たちはクラスの前で詩を暗唱するよう求められた。"},{"id":3823,"en":"reclaim","ja":"取り戻す\n以前持っていたものを取り返す・土地を回収する","level":6,"lnum":1,"ex":"After years abroad, he returned to reclaim his place on the team.","exja":"何年もの海外生活の後、彼はチームでの地位を取り戻すために戻ってきた。"},{"id":3824,"en":"recording","ja":"録音・録画\n音や映像を記録したもの・その行為","level":6,"lnum":1,"ex":"The teacher played a recording of a native speaker to help students with pronunciation.","exja":"先生は発音の練習のためにネイティブスピーカーの録音を再生した。"},{"id":3825,"en":"recovery","ja":"回復\n病気・損失・困難からの立ち直り","level":6,"lnum":1,"ex":"Her recovery from the illness was faster than the doctors expected.","exja":"彼女の病気からの回復は医師が予想していたよりも早かった。"},{"id":3826,"en":"recycled","ja":"再利用の\n廃棄物を加工して再び使用できるようにした状態","level":6,"lnum":1,"ex":"The bags are made from recycled plastic bottles collected from the ocean.","exja":"そのバッグは海から集めたリサイクルプラスチックボトルで作られている。"},{"id":3827,"en":"reduction","ja":"削減\n量・程度を減らすこと。decreaseより意図的な行為","level":6,"lnum":1,"ex":"The company announced a reduction in working hours to improve employee health.","exja":"会社は従業員の健康改善のために労働時間の削減を発表した。"},{"id":3828,"en":"reef","ja":"礁\n海面近くの岩や珊瑚の列。「coral reef」でサンゴ礁","level":6,"lnum":1,"ex":"The coral reef near the island is home to hundreds of colorful fish.","exja":"島近くのサンゴ礁には何百種類もの色鮮やかな魚が生息している。"},{"id":3829,"en":"referee","ja":"審判\n試合のルール遵守を管理する人。umpireはテニスなどで使用","level":6,"lnum":1,"ex":"The referee blew the whistle to stop the game after the foul.","exja":"審判はファウルの後、試合を止めるために笛を吹いた。"},{"id":3830,"en":"reflection","ja":"反射・反省\n光の反射または自己を振り返る思考","level":6,"lnum":1,"ex":"The clear lake showed a perfect reflection of the mountains.","exja":"澄んだ湖は山々の完璧な反射を映し出していた。"},{"id":3831,"en":"refreshments","ja":"軽食\n軽い飲み食い物。snacksより公式な場の飲食物","level":6,"lnum":1,"ex":"Refreshments will be served after the ceremony in the main hall.","exja":"式典の後、メインホールで軽食が提供されます。"},{"id":3832,"en":"refund","ja":"返金\n支払ったお金を返すこと","level":6,"lnum":1,"ex":"The store gave her a full refund because the product was damaged.","exja":"商品が損傷していたので、店は彼女に全額返金した。"},{"id":3833,"en":"refusal","ja":"拒否\n要求・申し出を断ること。rejectionより意志的な断り","level":6,"lnum":1,"ex":"His refusal to apologize made the situation much worse.","exja":"謝罪を拒否したことで状況はさらに悪化した。"},{"id":3834,"en":"regain","ja":"取り戻す\n失ったものを再び得る。recoverより積極的な取り返しの印象","level":6,"lnum":1,"ex":"The patient worked hard to regain her strength after the surgery.","exja":"患者は手術後に体力を取り戻すために懸命に努力した。"},{"id":3835,"en":"regard","ja":"みなす\n〜として考える・「regard A as B」で「AをBとみなす」","level":6,"lnum":1,"ex":"Most people regard honesty as one of the most important qualities.","exja":"ほとんどの人は誠実さを最も重要な資質の一つとみなしている。"},{"id":3836,"en":"regarding","ja":"〜に関して\n話題・テーマを示す前置詞。aboutより書き言葉的・改まった表現","level":6,"lnum":1,"ex":"She sent an email regarding the change in the meeting schedule.","exja":"彼女は会議スケジュールの変更に関してメールを送った。"},{"id":3837,"en":"region","ja":"地域\n地理的または行政的な区域。areaより広い範囲を示すことが多い","level":6,"lnum":1,"ex":"The northern region of the country is known for its cold winters.","exja":"その国の北部地域は寒い冬で知られている。"},{"id":3838,"en":"regional","ja":"地域の\n特定の地域に関係する・地域限定の","level":6,"lnum":1,"ex":"The regional competition will be held next Saturday in the city gymnasium.","exja":"地域大会は来週の土曜日に市の体育館で開催される。"},{"id":3839,"en":"register","ja":"名簿・登録\n公式に記録すること・その記録帳","level":6,"lnum":1,"ex":"All new students must register for classes by the end of this week.","exja":"新入生は全員、今週末までに授業登録をしなければならない。"},{"id":3840,"en":"registration","ja":"登録\n公式な記録・申し込みを行うこと","level":6,"lnum":1,"ex":"Online registration for the summer camp opens on the first of next month.","exja":"サマーキャンプのオンライン登録は来月1日に始まる。"},{"id":3841,"en":"regulation","ja":"規制\n行動を管理するための公式なルール","level":6,"lnum":1,"ex":"The new regulation requires all drivers to wear seat belts at all times.","exja":"新しい規制はすべてのドライバーに常時シートベルト着用を義務付けている。"},{"id":3842,"en":"reject","ja":"拒絶する\n受け入れを断る・却下する。refuseより強い否定感","level":6,"lnum":1,"ex":"The committee decided to reject the proposal because of the high cost.","exja":"委員会はコストが高すぎるという理由で提案を拒絶することを決定した。"},{"id":3843,"en":"relation","ja":"関係\n人や物事のつながり・関連性","level":6,"lnum":1,"ex":"There is a clear relation between exercise and good mental health.","exja":"運動と良好なメンタルヘルスの間には明確な関係がある。"},{"id":3844,"en":"relative","ja":"相対的な\n他との比較で決まる・相対的な。absoluteの反対","level":6,"lnum":1,"ex":"The success of the event was relative to the amount of effort put in.","exja":"そのイベントの成功は注ぎ込まれた努力の量に比例していた。"},{"id":3845,"en":"relatively","ja":"比較的\n他と比べて・相対的に。comparativelyとほぼ同義","level":6,"lnum":1,"ex":"The test was relatively easy compared to last year's exam.","exja":"そのテストは昨年の試験と比較して比較的簡単だった。"},{"id":3846,"en":"relaxing","ja":"リラックスさせる\n緊張をほぐす・気持ちを楽にする性質","level":6,"lnum":1,"ex":"Listening to soft music in the evening is very relaxing for her.","exja":"夕方に静かな音楽を聴くことは彼女にとってとてもリラックスになる。"},{"id":3847,"en":"reliable","ja":"信頼できる\n頼りになる・一貫して期待通りの。dependableとほぼ同義","level":6,"lnum":1,"ex":"A reliable friend is someone you can count on in difficult times.","exja":"信頼できる友人とは困難な時に頼れる人のことだ。"},{"id":3848,"en":"religion","ja":"宗教\n神や超自然的存在への信仰体系","level":6,"lnum":1,"ex":"People of different religion gathered to celebrate peace together.","exja":"異なる宗教の人々が平和を祝うために集まった。"},{"id":3849,"en":"religious","ja":"宗教的な\n宗教に関係する・信仰心が強い","level":6,"lnum":1,"ex":"The community holds a religious festival every spring at the local temple.","exja":"地域の人々は毎年春に地元の寺院で宗教的な祭りを行う。"},{"id":3850,"en":"rely","ja":"頼る\n信頼・依存して当てにする。depend onとほぼ同義","level":6,"lnum":1,"ex":"You cannot always rely on others to solve your problems for you.","exja":"問題を解決するためにいつも他人に頼ることはできない。"},{"id":3851,"en":"remainder","ja":"残り\n全体から取り除いた後に残る部分","level":6,"lnum":1,"ex":"She finished most of the homework and saved the remainder for after dinner.","exja":"彼女は宿題の大部分を終え、残りを夕食後のためにとっておいた。"},{"id":3852,"en":"remark","ja":"述べる\n考え・意見を口に出す。commentとほぼ同義だが短い発言","level":6,"lnum":1,"ex":"The teacher made a kind remark about the student's presentation.","exja":"先生は生徒の発表についての優しいコメントを述べた。"},{"id":3853,"en":"remarkable","ja":"注目すべき\n特に印象的で普通でない。noteworthyより感情的な驚き","level":6,"lnum":1,"ex":"The young pianist gave a remarkable performance that left the audience speechless.","exja":"その若いピアニストは観客を言葉を失わせるほど注目すべき演奏を披露した。"},{"id":3854,"en":"remedy","ja":"治療法\n問題・病気を解決する手段。cureより広い解決策を指す","level":6,"lnum":1,"ex":"Drinking warm honey tea is a traditional remedy for a sore throat.","exja":"温かいはちみつティーを飲むことは喉の痛みに対する伝統的な治療法だ。"},{"id":3855,"en":"remembrance","ja":"追悼\n亡くなった人・過去の出来事への記憶・追悼。memoryより感情的","level":6,"lnum":1,"ex":"A ceremony was held in remembrance of those who lost their lives in the disaster.","exja":"災害で命を落とした人々への追悼式が行われた。"},{"id":3856,"en":"remote control","ja":"リモコン\n距離を置いて機器を操作する装置","level":6,"lnum":1,"ex":"He could not find the remote control and had to change the channel manually.","exja":"彼はリモコンを見つけられず、手動でチャンネルを変えなければならなかった。"},{"id":3857,"en":"renew","ja":"更新する\n有効期限を延長する・新しくする","level":6,"lnum":1,"ex":"She went to the city office to renew her driver's license before it expired.","exja":"彼女は免許証が期限切れになる前に市役所に更新しに行った。"},{"id":3858,"en":"repay","ja":"返済する\n借りたお金・恩を返す。paybackより丁寧で正式","level":6,"lnum":1,"ex":"He worked overtime every weekend to repay the money he had borrowed.","exja":"彼は借りたお金を返済するために毎週末残業した。"},{"id":3859,"en":"repeatedly","ja":"繰り返し\n何度も・反復して行うさま","level":6,"lnum":1,"ex":"The teacher had to explain the rule repeatedly before the students understood.","exja":"生徒たちが理解するまで、先生は繰り返しルールを説明しなければならなかった。"},{"id":3860,"en":"representative","ja":"代表者\n集団を代表して行動する人。delegateより広い役割","level":6,"lnum":1,"ex":"Each class chose a representative to speak at the student council meeting.","exja":"各クラスは生徒会会議で発言するための代表者を選んだ。"},{"id":3861,"en":"reproduce","ja":"再現する\nコピーを作る・生物が子孫を産む。copyより生物学的文脈も含む","level":6,"lnum":1,"ex":"The machine can reproduce exact copies of any document in seconds.","exja":"その機械は任意の書類の正確なコピーを数秒で再現できる。"},{"id":3862,"en":"republic","ja":"共和国\n市民・代表者が統治する国家形態","level":6,"lnum":1,"ex":"France is a republic where the president is elected by the people.","exja":"フランスは大統領が国民によって選ばれる共和国だ。"},{"id":3863,"en":"reputation","ja":"評判\n他人が持つその人・組織への評価・名声","level":6,"lnum":1,"ex":"The school has a strong reputation for producing talented athletes.","exja":"その学校は才能あるアスリートを輩出することで強い評判を持っている。"},{"id":3864,"en":"require","ja":"必要とする\n不可欠として求める。needより公式・強制的なニュアンス","level":6,"lnum":1,"ex":"All participants are required to submit their application form by Friday.","exja":"全参加者は金曜日までに申込書を提出することが必要とされている。"},{"id":3865,"en":"requirement","ja":"必要条件\n満たすべき条件・要件","level":6,"lnum":1,"ex":"A minimum score of 70 is a requirement for passing the final exam.","exja":"最終試験に合格するための必要条件は最低70点だ。"},{"id":3866,"en":"resemble","ja":"似ている\n外見・性質が似ている。look likeより書き言葉的","level":6,"lnum":1,"ex":"The twins resemble each other so much that even their friends get confused.","exja":"その双子はとてもよく似ているので友人でさえも混乱する。"},{"id":3867,"en":"reservation","ja":"予約\n席・部屋などを事前に確保すること。bookingとほぼ同義","level":6,"lnum":1,"ex":"He made a reservation at the restaurant for their anniversary dinner.","exja":"彼は記念日ディナーのためにレストランに予約を入れた。"},{"id":3868,"en":"reserve","ja":"予備\n緊急時のために取っておくもの。動詞では「予約する」の意味も","level":6,"lnum":1,"ex":"The coach kept a few strong players in reserve for the second half.","exja":"コーチは後半のために数名の強い選手を予備としてとっておいた。"},{"id":3869,"en":"residential","ja":"住宅の\n住居に使われる・居住区の。「residential area」で住宅地","level":6,"lnum":1,"ex":"The city plans to build a new park in the residential area near the school.","exja":"市は学校近くの住宅地に新しい公園を作る計画を持っている。"},{"id":3870,"en":"resist","ja":"抵抗する\n圧力・誘惑に逆らう。「resist temptation」で誘惑に抵抗する","level":6,"lnum":1,"ex":"It was hard to resist eating the delicious cake on the table.","exja":"テーブルの上のおいしいケーキを食べるのに抵抗するのは難しかった。"},{"id":3871,"en":"resolve","ja":"解決する\n問題・対立を最終的に解決する。solveより決意・努力を含む","level":6,"lnum":1,"ex":"The two countries finally resolved their conflict through peaceful talks.","exja":"2つの国はついに平和的な交渉を通じて紛争を解決した。"},{"id":3872,"en":"resort","ja":"リゾート\n休暇を過ごす観光地。「last resort」で最後の手段","level":6,"lnum":1,"ex":"The family spent a week at a beach resort during the summer holiday.","exja":"家族は夏休みの間、ビーチリゾートで1週間過ごした。"},{"id":3873,"en":"resource","ja":"資源\n目的を達成するために利用できる物・人・金","level":6,"lnum":1,"ex":"Libraries are an important resource for students who want to study deeply.","exja":"図書館は深く学びたい学生にとって重要な資源だ。"},{"id":3874,"en":"respectable","ja":"立派な\n社会的に尊敬される・品位ある。respectfulは「敬意を示す」","level":6,"lnum":1,"ex":"She worked hard to build a respectable career as a journalist.","exja":"彼女はジャーナリストとして立派なキャリアを築くために懸命に働いた。"},{"id":3875,"en":"respond","ja":"応答する\n刺激・質問に反応・答える。replyより幅広い反応を含む","level":6,"lnum":1,"ex":"The teacher asked the students to respond to each other's questions politely.","exja":"先生は生徒たちがお互いの質問に礼儀正しく応答するよう求めた。"},{"id":3876,"en":"responsibility","ja":"責任\n義務・役割を果たすべき立場・負うべき責め","level":6,"lnum":1,"ex":"It is the responsibility of every citizen to vote in the election.","exja":"選挙で投票することはすべての市民の責任だ。"},{"id":3877,"en":"restore","ja":"修復する\n元の状態に戻す・回復させる","level":6,"lnum":1,"ex":"The old painting was carefully restored to its original condition by experts.","exja":"古い絵画は専門家によって元の状態に丁寧に修復された。"},{"id":3878,"en":"restrict","ja":"制限する\n量・範囲・行動を限定する。limitより外から課される制約","level":6,"lnum":1,"ex":"The doctor restricted the patient's diet to help him recover faster.","exja":"医師は患者がより早く回復できるように食事を制限した。"},{"id":3879,"en":"retail","ja":"小売り\n消費者に直接商品を販売すること。wholesaleの反対","level":6,"lnum":1,"ex":"The retail price of this jacket is much higher than the wholesale price.","exja":"このジャケットの小売価格は卸売価格よりもはるかに高い。"},{"id":3880,"en":"retain","ja":"保持する\n失わずに持ち続ける。keepより意図的な保持の努力","level":6,"lnum":1,"ex":"The team worked hard to retain their championship title for another year.","exja":"チームはもう一年チャンピオンの地位を保持するために懸命に努力した。"},{"id":3881,"en":"retell","ja":"語り直す\n以前話した・読んだ物語を別の言葉で再び話す","level":6,"lnum":1,"ex":"The children were asked to retell the story in their own words.","exja":"子どもたちは自分の言葉で物語を語り直すよう求められた。"},{"id":3882,"en":"retrospect","ja":"回顧\n過去を振り返ること。「in retrospect」で「振り返ってみると」","level":6,"lnum":1,"ex":"In retrospect, she realized that studying harder would have been the right choice.","exja":"振り返ってみると、彼女はもっと一生懸命勉強することが正しい選択だったと気づいた。"},{"id":3883,"en":"reunification","ja":"再統一\n分裂していた国・組織を再び一つにすること","level":6,"lnum":1,"ex":"The reunification of the divided country brought joy to millions of people.","exja":"分断された国の再統一は何百万人もの人々に喜びをもたらした。"},{"id":3884,"en":"reunify","ja":"再統一する\n分裂したものを再び一つにまとめる","level":6,"lnum":1,"ex":"The leaders signed an agreement to reunify the two separated regions.","exja":"指導者たちは2つの分断された地域を再統一する協定に署名した。"},{"id":3885,"en":"revise","ja":"改訂する\n内容を見直して変更・修正する。editより包括的な見直し","level":6,"lnum":1,"ex":"He stayed up late to revise his essay before submitting it to the teacher.","exja":"彼は先生に提出する前に論文を改訂するために夜更かしした。"},{"id":3886,"en":"revision","ja":"改訂\n内容を修正・見直すこと。試験勉強の「復習」の意味も（英国）","level":6,"lnum":1,"ex":"She spent the weekend doing revision for the history exam on Monday.","exja":"彼女は月曜日の歴史の試験のために週末に復習した。"},{"id":3887,"en":"reward","ja":"報酬\n良い行動・成果に対して与えられるもの。punishmentの反対","level":6,"lnum":1,"ex":"The students received a reward for collecting the most cans for the recycling drive.","exja":"生徒たちはリサイクル活動で最も多くの缶を集めた報酬を受け取った。"},{"id":3888,"en":"rewrite","ja":"書き直す\n文章を最初から新しく書き直す","level":6,"lnum":1,"ex":"The editor asked the author to rewrite the ending of the novel.","exja":"編集者は著者に小説の結末を書き直すよう求めた。"},{"id":3889,"en":"rid","ja":"取り除く\n不要なものをなくす。「get rid of」で「〜を処分する」","level":6,"lnum":1,"ex":"She finally got rid of all the old magazines she had kept for years.","exja":"彼女はついに何年も保管していた古い雑誌をすべて処分した。"},{"id":3890,"en":"riddle","ja":"なぞなぞ\n答えを当てる謎かけ・難問","level":6,"lnum":1,"ex":"The teacher gave the class a riddle to solve at the beginning of the lesson.","exja":"先生は授業の最初にクラスに解くなぞなぞを出した。"},{"id":3891,"en":"ridiculous","ja":"ばかげた\n非常に不合理・おかしくて笑える。absurdより軽蔑的","level":6,"lnum":1,"ex":"It was ridiculous to wait three hours just to get a table at the restaurant.","exja":"レストランのテーブルを確保するだけのために3時間待つのはばかげていた。"},{"id":3892,"en":"ripe","ja":"熟した\n果物が食べごろの状態。「ripe for change」で変化の機が熟した","level":6,"lnum":1,"ex":"The farmer picked the tomatoes when they were perfectly ripe.","exja":"農家は完全に熟したときにトマトを収穫した。"},{"id":3893,"en":"roadside","ja":"道路沿い\n道路のわきの場所・路肩","level":6,"lnum":1,"ex":"The family stopped at a roadside café to eat lunch during the long drive.","exja":"家族は長いドライブの途中で昼食を食べるために道路沿いのカフェに立ち寄った。"},{"id":3894,"en":"rolling","ja":"起伏のある\n緩やかな丘が続く地形。「rolling hills」で緩やかな丘陵地帯","level":6,"lnum":1,"ex":"The countryside was covered with rolling green hills as far as the eye could see.","exja":"田園地帯には見渡す限り起伏のある緑の丘が広がっていた。"},{"id":3895,"en":"rotten","ja":"腐った\n有機物が腐敗した状態。比喩的に「とても悪い」にも使用","level":6,"lnum":1,"ex":"They threw away the fruit because it had already gone rotten.","exja":"果物はすでに腐っていたので捨てた。"},{"id":3896,"en":"routine","ja":"日課\n決まった順序で繰り返す行動・習慣","level":6,"lnum":1,"ex":"Morning exercise has become part of her daily routine before going to work.","exja":"朝の運動は仕事に行く前の彼女の日課の一部になった。"},{"id":3897,"en":"rubber","ja":"ゴム\n弾力性のある材料。英国英語で「消しゴム」の意味も","level":6,"lnum":1,"ex":"The children played with rubber balls in the schoolyard after lunch.","exja":"子どもたちは昼食後、校庭でゴムのボールで遊んだ。"},{"id":3898,"en":"rubbish","ja":"ごみ\n不要な廃棄物。英国英語でgarbageに相当。「くだらない」の意味も","level":6,"lnum":1,"ex":"Please put all the rubbish in the bin before you leave the classroom.","exja":"教室を出る前にごみをすべてごみ箱に入れてください。"},{"id":3899,"en":"rudely","ja":"無礼に\n礼儀を欠いた・失礼な態度で","level":6,"lnum":1,"ex":"He rudely interrupted the speaker in the middle of the presentation.","exja":"彼はプレゼンテーションの途中で無礼にも発表者の話を遮った。"},{"id":3900,"en":"ruin","ja":"廃墟\n崩壊した建物の残骸。動詞では「台無しにする」","level":6,"lnum":1,"ex":"The unexpected rain ruined their plans for an outdoor picnic.","exja":"突然の雨が屋外ピクニックの計画を台無しにした。"},{"id":3901,"en":"runaway","ja":"逃亡者\n家や施設から逃げ出した人。形容詞で「暴走した」の意味も","level":6,"lnum":1,"ex":"The police were searching for a runaway teenager who left home three days ago.","exja":"警察は3日前に家を出た逃亡中の10代の若者を探していた。"},{"id":3902,"en":"runway","ja":"滑走路\n飛行機が離着陸するための舗装された道","level":6,"lnum":1,"ex":"The pilot carefully guided the plane down the icy runway during the snowstorm.","exja":"パイロットは吹雪の中、凍った滑走路に丁寧に飛行機を誘導した。"},{"id":3903,"en":"rush","ja":"急ぐ\n素早く・慌てて移動する。hurrかより混雑・殺到のニュアンスも","level":6,"lnum":1,"ex":"She was in such a rush to catch the train that she forgot her lunch.","exja":"電車に乗り遅れまいと急いでいたため、昼食を忘れてしまった。"},{"id":3904,"en":"safari","ja":"サファリ\nアフリカの野生動物を観察する旅行","level":6,"lnum":1,"ex":"Going on a safari in Africa was the most exciting experience of his life.","exja":"アフリカへのサファリに行くことは彼の人生で最もわくわくする体験だった。"},{"id":3905,"en":"safeguard","ja":"保護手段\n危険から守るための措置・手段","level":6,"lnum":1,"ex":"Wearing a helmet is an important safeguard against head injuries when cycling.","exja":"自転車に乗るときにヘルメットをかぶることは頭部外傷に対する重要な保護手段だ。"},{"id":3906,"en":"salesman","ja":"セールスマン\n商品を販売する営業担当者","level":6,"lnum":1,"ex":"The salesman explained the features of the new laptop very clearly.","exja":"セールスマンは新しいノートパソコンの機能をとてもわかりやすく説明した。"},{"id":3907,"en":"salmon","ja":"サーモン\n川で産まれ海で育つ食用魚。ピンクオレンジ色の肉","level":6,"lnum":1,"ex":"Grilled salmon with vegetables is one of the most popular dishes at the restaurant.","exja":"野菜を添えた焼きサーモンはそのレストランで最も人気のある料理の一つだ。"},{"id":3908,"en":"sand","ja":"砂\n海岸・砂漠に見られる細かい粒の堆積物","level":6,"lnum":1,"ex":"The children built a large sandcastle on the beach with wet sand.","exja":"子どもたちは濡れた砂でビーチに大きな砂のお城を作った。"},{"id":3909,"en":"sandal","ja":"サンダル\nひもで足に固定するオープントゥの履き物","level":6,"lnum":1,"ex":"She wore comfortable sandals during the summer trip to the seaside.","exja":"彼女は海辺への夏の旅行中に快適なサンダルを履いた。"},{"id":3910,"en":"satellite","ja":"衛星\n惑星の周りを回る天体・人工衛星。「satellite TV」で衛星放送","level":6,"lnum":1,"ex":"Scientists launched a new satellite to study weather patterns from space.","exja":"科学者たちは宇宙から天気のパターンを研究するための新しい衛星を打ち上げた。"},{"id":3911,"en":"satisfaction","ja":"満足\n期待や欲求が満たされた状態。dissatisfactionの反対","level":6,"lnum":1,"ex":"He felt a deep sense of satisfaction after finishing the long project.","exja":"長いプロジェクトを終えた後、彼は深い満足感を覚えた。"},{"id":3912,"en":"saucepan","ja":"片手鍋\n柄のついた深めの鍋","level":6,"lnum":1,"ex":"She heated the soup in a small saucepan on the stove.","exja":"彼女はコンロの上の小さな片手鍋でスープを温めた。"},{"id":3913,"en":"saucer","ja":"受け皿\nカップの下に置く小皿","level":6,"lnum":1,"ex":"He placed the teacup carefully back on its saucer after drinking.","exja":"彼は飲み終えた後、ティーカップを丁寧に受け皿に戻した。"},{"id":3914,"en":"scan","ja":"スキャン\n全体をざっと見る・機械で読み取る行為","level":6,"lnum":1,"ex":"The doctor used a machine to scan the patient's brain for any abnormalities.","exja":"医師は患者の脳に異常がないかスキャンするために機械を使用した。"},{"id":3915,"en":"scare","ja":"怖がらせる\n突然の恐怖を与える。frightenより瞬間的な恐怖","level":6,"lnum":1,"ex":"The loud thunder in the middle of the night scared the young children.","exja":"夜中の大きな雷鳴が幼い子どもたちを怖がらせた。"},{"id":3916,"en":"scatter","ja":"散らす\nあちこちに広げる・ばら撒く。spreadより無秩序な広がり","level":6,"lnum":1,"ex":"Strong winds scattered the fallen leaves all over the garden.","exja":"強風が落ち葉を庭中に散らした。"},{"id":3917,"en":"scenic","ja":"景色の美しい\n眺めが素晴らしい自然の風景。「scenic route」で景色の良い道","level":6,"lnum":1,"ex":"They chose the scenic route along the coast instead of the highway.","exja":"彼らは高速道路の代わりに海岸沿いの景色の美しいルートを選んだ。"},{"id":3918,"en":"scholar","ja":"学者\n特定分野を深く研究する人。studentより高度な専門性を持つ","level":6,"lnum":1,"ex":"The professor is a leading scholar in the field of ancient history.","exja":"その教授は古代史の分野を代表する学者だ。"},{"id":3919,"en":"scholarship","ja":"奨学金\n優秀な学生に与えられる学費補助。学問的な知識の意味も","level":6,"lnum":1,"ex":"She received a full scholarship to study at one of the best universities.","exja":"彼女は最良の大学の一つで学ぶための全額奨学金を受け取った。"},{"id":3920,"en":"schoolmate","ja":"同級生\n同じ学校に通う仲間。classmateは同じクラスに限定","level":6,"lnum":1,"ex":"He stayed in touch with his old schoolmates through social media.","exja":"彼はソーシャルメディアを通じて旧同級生たちと連絡を取り続けた。"},{"id":3921,"en":"schoolteacher","ja":"学校教師\n学校で教える職業の人","level":6,"lnum":1,"ex":"The schoolteacher encouraged every student to do their best on the exam.","exja":"学校教師はすべての生徒に試験で全力を尽くすよう励ました。"},{"id":3922,"en":"science fiction","ja":"SF\n科学技術を基にした架空の物語ジャンル","level":6,"lnum":1,"ex":"Her favorite science fiction novel imagines humans living on Mars in 2200.","exja":"彼女のお気に入りのSF小説は2200年に人間が火星に住む様子を描いている。"},{"id":3923,"en":"scope","ja":"範囲\n活動・研究が及ぶ範囲・広さ","level":6,"lnum":1,"ex":"The scope of the research project expanded beyond the original plan.","exja":"研究プロジェクトの範囲は元の計画を超えて広がった。"},{"id":3924,"en":"scratch","ja":"引っかき傷\n爪や鋭いものでできた表面の傷。「from scratch」で最初から","level":6,"lnum":1,"ex":"The cat left a deep scratch on the wooden table.","exja":"猫は木製のテーブルに深い引っかき傷を残した。"},{"id":3925,"en":"scream","ja":"叫ぶ\n恐怖・痛み・興奮から大声を出す。shoutより甲高い声","level":6,"lnum":1,"ex":"She let out a loud scream when she saw a spider on the wall.","exja":"壁にクモを見たとき、彼女は大きな悲鳴を上げた。"},{"id":3926,"en":"sculpture","ja":"彫刻\n石・金属・木などを削って作る立体芸術作品","level":6,"lnum":1,"ex":"The museum displayed a beautiful marble sculpture from ancient Greece.","exja":"その博物館は古代ギリシャの美しい大理石の彫刻を展示していた。"},{"id":3927,"en":"seawater","ja":"海水\n塩分を含む海の水","level":6,"lnum":1,"ex":"Scientists are studying ways to turn seawater into safe drinking water.","exja":"科学者たちは海水を安全な飲料水に変える方法を研究している。"},{"id":3928,"en":"secondary school","ja":"中学・高校\n小学校の後の中等教育機関。英国で11〜18歳が対象","level":6,"lnum":1,"ex":"She made many close friends during her years at secondary school.","exja":"彼女は中学・高校時代に多くの親友を作った。"},{"id":3929,"en":"second-hand","ja":"中古の\n以前に別の人が使用した物。used（使用済み）とほぼ同義","level":6,"lnum":1,"ex":"He bought a second-hand bicycle to save money for college.","exja":"彼は大学費用のために節約しようと中古の自転車を買った。"},{"id":3930,"en":"secretly","ja":"ひそかに\n他人に知られないよう隠れて行うさま","level":6,"lnum":1,"ex":"She secretly practiced the piano every night to surprise her parents.","exja":"彼女は両親を驚かせようと毎晩こっそりピアノを練習した。"},{"id":3931,"en":"secure","ja":"安全な\n危険・不安がない状態。safeより積極的な保護のニュアンス","level":6,"lnum":1,"ex":"The school took measures to make sure all students felt secure on campus.","exja":"学校はすべての生徒がキャンパスで安全を感じられるよう対策を講じた。"},{"id":3932,"en":"security","ja":"安全\n危険・脅威からの保護・安心感","level":6,"lnum":1,"ex":"The museum has strong security cameras installed throughout the building.","exja":"その博物館は建物全体に強力なセキュリティカメラを設置している。"},{"id":3933,"en":"seize","ja":"掴む\n素早く・力強く取る。grabより決定的・緊急な行動","level":6,"lnum":1,"ex":"The police managed to seize a large amount of stolen goods from the warehouse.","exja":"警察は倉庫から大量の盗品を押収することに成功した。"},{"id":3934,"en":"self-service","ja":"セルフサービスの\n客が自分で商品を選び・取る形式のサービス","level":6,"lnum":1,"ex":"The new self-service checkout at the supermarket made shopping much faster.","exja":"スーパーマーケットの新しいセルフサービスレジで買い物がずっと早くなった。"},{"id":3935,"en":"sensation","ja":"感覚\n体で感じる感覚・社会的に大きな反響を呼ぶ出来事","level":6,"lnum":1,"ex":"The icy water gave her a sharp sensation of cold throughout her body.","exja":"氷のように冷たい水が彼女の全身に鋭い冷たさの感覚を与えた。"},{"id":3936,"en":"separation","ja":"分離\nつながっていたものが離れること","level":6,"lnum":1,"ex":"The long separation from his family was the hardest part of working abroad.","exja":"家族からの長い分離が海外での仕事で最もつらい部分だった。"},{"id":3937,"en":"sequence","ja":"順序\n物事が続く順番・連続。orderより時間的な順序を強調","level":6,"lnum":1,"ex":"The teacher explained the sequence of events that led to the war.","exja":"先生は戦争につながった出来事の順序を説明した。"},{"id":3938,"en":"series","ja":"シリーズ\n同じテーマで連続する複数のもの","level":6,"lnum":1,"ex":"She watched the entire series of the documentary in just two days.","exja":"彼女はそのドキュメンタリーのシリーズ全体をわずか2日間で見た。"},{"id":3939,"en":"server","ja":"サーバー\nデータを管理・提供するコンピューター。飲食店の接客係にも使用","level":6,"lnum":1,"ex":"The restaurant server recommended the chef's special dish of the day.","exja":"レストランのサーバーはその日のシェフのスペシャルメニューを勧めた。"},{"id":3940,"en":"session","ja":"セッション\n特定の目的のための活動期間・回","level":6,"lnum":1,"ex":"The students had a study session at the library to prepare for finals.","exja":"生徒たちは期末試験の準備のために図書館で勉強セッションを行った。"},{"id":3941,"en":"setting","ja":"設定\n物語の背景・場所・時代。また機器の設定値","level":6,"lnum":1,"ex":"The novel is set in a small village in the countryside during the 1800s.","exja":"その小説は1800年代の田舎の小さな村を舞台にしている。"},{"id":3942,"en":"settle","ja":"落ち着く\n新しい場所に定住する・問題を解決する","level":6,"lnum":1,"ex":"After living in several cities, she finally settled in Kyoto.","exja":"いくつかの都市に住んだ後、彼女はついに京都に落ち着いた。"},{"id":3943,"en":"settlement","ja":"和解\n紛争の合意による解決。植民地時代の「入植地」の意味も","level":6,"lnum":1,"ex":"The two companies reached a settlement outside of court over the dispute.","exja":"2つの会社は争いについて法廷外で和解に達した。"},{"id":3944,"en":"settler","ja":"入植者\n新しい地域に移住して定住した人","level":6,"lnum":1,"ex":"The early settlers built their homes near the river for fresh water.","exja":"初期の入植者たちは真水を得るために川の近くに家を建てた。"},{"id":3945,"en":"severe","ja":"深刻な\n非常に厳しい・重大な。seriousより客観的な重さを示す","level":6,"lnum":1,"ex":"The severe storm caused major damage to buildings across the region.","exja":"深刻な嵐が地域全体の建物に大きな被害をもたらした。"},{"id":3946,"en":"severely","ja":"厳しく\n非常に深刻に・厳格に","level":6,"lnum":1,"ex":"The athlete was severely injured during the game and had to leave the field.","exja":"その選手は試合中に厳しく負傷してフィールドを離れなければならなかった。"},{"id":3947,"en":"sex","ja":"性\n生物学的な性別。また性行為の意味も持つ","level":6,"lnum":1,"ex":"The biology class discussed the different biological roles of each sex.","exja":"生物学の授業では各性の異なる生物学的役割について議論した。"},{"id":3948,"en":"shadowy","ja":"薄暗い\n影が多く・はっきり見えない状態。謎めいたイメージも","level":6,"lnum":1,"ex":"A shadowy figure appeared at the end of the dark hallway.","exja":"暗い廊下の奥に薄暗い人影が現れた。"},{"id":3949,"en":"shallow","ja":"浅い\n深さが少ない。比喩的に「表面的・内容がない」にも使用","level":6,"lnum":1,"ex":"The stream was so shallow that the children could walk across it safely.","exja":"小川はとても浅かったので子どもたちが安全に渡ることができた。"},{"id":3950,"en":"shame","ja":"恥\n自分の行動や状況への恥ずかしさ・後悔","level":6,"lnum":1,"ex":"He felt deep shame when he realized he had copied the wrong answer.","exja":"間違った答えをコピーしていたと気づいたとき、彼は深い恥を感じた。"},{"id":3951,"en":"shameful","ja":"恥ずべき\n道徳的に非難に値する・恥ずかしい行動","level":6,"lnum":1,"ex":"It was shameful behavior to cheat on the exam when others studied honestly.","exja":"他の人が正直に勉強しているのに試験でカンニングするのは恥ずべき行為だった。"},{"id":3952,"en":"shave","ja":"ひげを剃る\nカミソリで毛を取り除く","level":6,"lnum":1,"ex":"He shaved his beard before the job interview to make a good impression.","exja":"就職面接の前に良い印象を与えるために彼はひげを剃った。"},{"id":3953,"en":"sheer","ja":"純粋な\n他の何も混じらない・まったくの。「sheer luck」で純粋な運","level":6,"lnum":1,"ex":"They won the championship through sheer hard work and determination.","exja":"彼らは純粋な努力と決意だけでチャンピオンシップを制覇した。"},{"id":3954,"en":"sheriff","ja":"保安官\n米国の郡の治安を維持する法執行官","level":6,"lnum":1,"ex":"The sheriff warned the strangers not to cause trouble in the small town.","exja":"保安官は見知らぬ人たちに小さな町で騒ぎを起こさないよう警告した。"},{"id":3955,"en":"shift","ja":"交代勤務\n仕事の時間帯・当番。動詞では「移動する・変える」","level":6,"lnum":1,"ex":"She took the night shift at the hospital so her colleague could rest.","exja":"同僚が休めるように彼女は病院で夜間の交代勤務を引き受けた。"},{"id":3956,"en":"shiny","ja":"輝く\n光を反射してつやつやした状態","level":6,"lnum":1,"ex":"The child was excited to wear his shiny new shoes to the school ceremony.","exja":"子どもは学校の式典に新しい輝く靴を履いていけることに興奮した。"},{"id":3957,"en":"shiver","ja":"震える\n寒さや恐怖で体が小刻みに震える","level":6,"lnum":1,"ex":"She started to shiver as the temperature dropped suddenly after sunset.","exja":"日没後に気温が急に下がり、彼女は震え始めた。"},{"id":3958,"en":"shopper","ja":"買い物客\n店で商品を選んで買う人","level":6,"lnum":1,"ex":"The busy shopper rushed through the mall to finish buying gifts before closing time.","exja":"忙しい買い物客は閉店時間前にプレゼントの購入を終えようとショッピングモールを急いで歩いた。"},{"id":3959,"en":"shortage","ja":"不足\n必要な量が足りない状態。「food shortage」で食料不足","level":6,"lnum":1,"ex":"The shortage of clean water in the village became a serious health problem.","exja":"村での清潔な水の不足は深刻な健康問題になった。"},{"id":3960,"en":"shortly","ja":"まもなく\nすぐに・少しの時間の後に。soonとほぼ同義だが直前を強調","level":6,"lnum":1,"ex":"The train will arrive at the next station shortly, so please prepare to exit.","exja":"列車はまもなく次の駅に到着しますので、降車の準備をしてください。"},{"id":3961,"en":"shrimp","ja":"エビ\n小型の食用甲殻類。米語でprawnより小さいものを指す","level":6,"lnum":1,"ex":"She ordered a bowl of shrimp soup at the seafood restaurant by the beach.","exja":"彼女はビーチ近くの海鮮レストランでエビのスープを注文した。"},{"id":3962,"en":"sickness","ja":"病気\n体の具合が悪い状態。illnessとほぼ同義だが吐き気にも使う","level":6,"lnum":1,"ex":"Many passengers experienced sickness during the rough boat ride.","exja":"激しい船の揺れの間、多くの乗客が船酔いを経験した。"},{"id":3963,"en":"sidewalk","ja":"歩道\n米国英語で歩行者用の道。英国英語ではpavement","level":6,"lnum":1,"ex":"Children were told to walk on the sidewalk and not on the busy road.","exja":"子どもたちは交通量の多い道路ではなく歩道を歩くよう言われた。"},{"id":3964,"en":"sigh","ja":"ため息\n感情（疲れ・安堵など）を表す深い呼吸音","level":6,"lnum":1,"ex":"He let out a long sigh of relief after hearing that he had passed the exam.","exja":"試験に合格したと聞いて、彼は長い安堵のため息をついた。"},{"id":3965,"en":"signal","ja":"信号\n情報を伝える指示・合図。signより動的・電子的な合図","level":6,"lnum":1,"ex":"The traffic signal turned red just as she was about to cross the street.","exja":"信号が赤に変わったのはちょうど彼女が道路を渡ろうとしていたときだった。"},{"id":3966,"en":"signature","ja":"署名\n本人確認のための独自の書き方のサイン","level":6,"lnum":1,"ex":"Please write your signature at the bottom of the form to confirm your agreement.","exja":"同意を確認するために書類の下部に署名を書いてください。"},{"id":3967,"en":"significance","ja":"重要性\n重要であること・意味・意義","level":6,"lnum":1,"ex":"The teacher explained the significance of the battle in shaping the history.","exja":"先生は歴史を形成するうえでのその戦いの重要性を説明した。"},{"id":3968,"en":"signpost","ja":"道標\n道案内のための標識・柱","level":6,"lnum":1,"ex":"There was a large signpost at the crossroads showing the way to the city center.","exja":"交差点には市の中心部への道を示す大きな道標があった。"},{"id":3969,"en":"silk","ja":"絹\n蚕が作る滑らかで光沢のある高級繊維","level":6,"lnum":1,"ex":"The bride wore a beautiful gown made of pure white silk.","exja":"花嫁は純白の絹で作られた美しいガウンを着ていた。"},{"id":3970,"en":"similarity","ja":"類似点\n似ている点・共通する特徴。differenceの反対","level":6,"lnum":1,"ex":"The researchers noted the similarity between the two species of birds.","exja":"研究者たちは2種の鳥の間の類似点に注目した。"},{"id":3971,"en":"similarly","ja":"同様に\n同じような方法で・同じように","level":6,"lnum":1,"ex":"He studied mathematics every day, and similarly, he practiced piano regularly.","exja":"彼は毎日数学を勉強し、同様に定期的にピアノも練習した。"},{"id":3972,"en":"simplify","ja":"単純化する\n複雑なものをわかりやすくする","level":6,"lnum":1,"ex":"The teacher tried to simplify the complex grammar rule for the beginners.","exja":"先生は初心者のために複雑な文法ルールを単純化しようとした。"},{"id":3973,"en":"simultaneously","ja":"同時に\n二つ以上のことが全く同じ時に起こるさま","level":6,"lnum":1,"ex":"The students took out their books and opened them simultaneously.","exja":"生徒たちは同時に本を取り出して開いた。"},{"id":3974,"en":"skeleton","ja":"骨格\n体の骨の全体的な構造。「skeleton key」で合鍵の意味も","level":6,"lnum":1,"ex":"The science class studied the human skeleton and the function of each bone.","exja":"科学の授業で人体の骨格とそれぞれの骨の機能を学んだ。"},{"id":3975,"en":"skyscraper","ja":"超高層ビル\n非常に高い建物。「空をかすめるもの」の意","level":6,"lnum":1,"ex":"The new skyscraper in the city center can be seen from miles away.","exja":"市の中心部にある新しい超高層ビルは何マイルも先から見える。"},{"id":3976,"en":"slavery","ja":"奴隷制\n人を財産として所有・使役する制度","level":6,"lnum":1,"ex":"The history class discussed the terrible conditions of slavery in the 1800s.","exja":"歴史の授業で1800年代の奴隷制の悲惨な状況について議論した。"},{"id":3977,"en":"slight","ja":"わずかな\n量・程度が少ない。minorより小さな差を示す","level":6,"lnum":1,"ex":"There was a slight delay in the flight due to bad weather conditions.","exja":"悪天候のために飛行機にわずかな遅延があった。"},{"id":3978,"en":"slightly","ja":"少し\nわずかに・ほんの少しだけ。a littleとほぼ同義","level":6,"lnum":1,"ex":"The temperature today is slightly lower than it was yesterday.","exja":"今日の気温は昨日よりも少し低い。"},{"id":3979,"en":"slip","ja":"滑り\n不意に足を滑らせること。比喩的に「うっかりミス」にも","level":6,"lnum":1,"ex":"She was careful not to slip on the wet floor after mopping.","exja":"モップがけの後、彼女は濡れた床で滑らないように注意した。"},{"id":3980,"en":"slogan","ja":"スローガン\n団体・運動の理念を表す短い印象的な言葉","level":6,"lnum":1,"ex":"The environmental group came up with a catchy slogan for their campaign.","exja":"環境団体はキャンペーンのためにキャッチーなスローガンを考え出した。"},{"id":3981,"en":"slope","ja":"坂\n傾斜した面・斜面。「ski slope」でスキーの斜面","level":6,"lnum":1,"ex":"The children enjoyed sledding down the snowy slope in the park.","exja":"子どもたちは公園の雪の坂をソリで滑り下りることを楽しんだ。"},{"id":3982,"en":"slot","ja":"スロット\n特定の目的のための細い穴・時間帯","level":6,"lnum":1,"ex":"Insert your coin into the slot at the top of the vending machine.","exja":"自動販売機の上部のスロットにコインを入れてください。"},{"id":3983,"en":"smoker","ja":"喫煙者\nタバコを吸う人","level":6,"lnum":1,"ex":"The restaurant has a separate area for smokers outside the building.","exja":"そのレストランは建物の外に喫煙者のための別のエリアを設けている。"},{"id":3984,"en":"sneeze","ja":"くしゃみ\n鼻・口から空気が突然排出される反射","level":6,"lnum":1,"ex":"He sneezed several times during the spring because of his pollen allergy.","exja":"彼は花粉のアレルギーのために春の間何度もくしゃみをした。"},{"id":3985,"en":"snowboard","ja":"スノーボード\n雪の上を滑るための一枚板の器具・スポーツ","level":6,"lnum":1,"ex":"She learned to snowboard during a winter vacation in the mountains.","exja":"彼女は山での冬の休暇の間にスノーボードを学んだ。"},{"id":3986,"en":"snowstorm","ja":"吹雪\n強風を伴う激しい雪。blizzardより一般的な表現","level":6,"lnum":1,"ex":"Schools were closed for two days because of the heavy snowstorm.","exja":"激しい吹雪のために学校は2日間休校となった。"},{"id":3987,"en":"soap opera","ja":"メロドラマ\n感情的な人間関係を扱うテレビ連続ドラマ","level":6,"lnum":1,"ex":"She watches a soap opera every evening after finishing her homework.","exja":"彼女は宿題を終えた後、毎晩メロドラマを見る。"},{"id":3988,"en":"social networking","ja":"ソーシャルネットワーキング\nオンラインで人とつながり交流すること","level":6,"lnum":1,"ex":"Social networking sites allow people to share photos and ideas with friends.","exja":"ソーシャルネットワーキングサイトは人々が友人と写真やアイデアを共有することを可能にする。"},{"id":3989,"en":"socially","ja":"社会的に\n社会・人間関係の観点から","level":6,"lnum":1,"ex":"She became more socially confident after joining the school drama club.","exja":"学校の演劇クラブに入ってから彼女は社会的に自信がついた。"},{"id":3990,"en":"solid","ja":"固体の\n形が固定された物質の状態。liquidとgasの反対","level":6,"lnum":1,"ex":"The table is made of solid oak wood and is very durable.","exja":"そのテーブルは固いオークの木で作られていてとても頑丈だ。"},{"id":3991,"en":"someplace","ja":"どこかに\n米国英語でsomewhereに相当する副詞","level":6,"lnum":1,"ex":"Let's go someplace quiet where we can talk without being interrupted.","exja":"邪魔されずに話せるどこか静かな場所に行きましょう。"},{"id":3992,"en":"soothe","ja":"なだめる\n痛み・不安・怒りを和らげる。calmより優しく癒す印象","level":6,"lnum":1,"ex":"She sang a soft lullaby to soothe the crying baby to sleep.","exja":"彼女は泣いている赤ちゃんをなだめて眠りに誘うために優しい子守唄を歌った。"},{"id":3993,"en":"sophomore","ja":"2年生\n米国の高校・大学の2年生を指す用語","level":6,"lnum":1,"ex":"As a sophomore, he had already joined three clubs and the student council.","exja":"2年生として、彼はすでに3つのクラブと生徒会に入っていた。"},{"id":3994,"en":"sorrow","ja":"悲しみ\n深い悲しみ・苦しみ。sadnessより重く格式的な表現","level":6,"lnum":1,"ex":"She felt great sorrow when she heard that her childhood friend had moved abroad.","exja":"幼なじみが海外に引っ越したと聞いて、彼女は大きな悲しみを感じた。"},{"id":3995,"en":"sort","ja":"種類\n同じ性質を持つグループ。typeとほぼ同義。動詞で「分類する」","level":6,"lnum":1,"ex":"What sort of music do you enjoy listening to on the way to school?","exja":"あなたは学校への道でどんな種類の音楽を聴くのが好きですか？"},{"id":3996,"en":"soul","ja":"魂\n体と区別される精神的・霊的な存在","level":6,"lnum":1,"ex":"The old song touched her soul and brought tears to her eyes.","exja":"その古い歌は彼女の魂に触れ、目に涙を浮かばせた。"},{"id":3997,"en":"southeast","ja":"南東の\n南と東の中間方向","level":6,"lnum":1,"ex":"The ferry departs from the southeast corner of the harbor every morning.","exja":"フェリーは毎朝港の南東の角から出発する。"},{"id":3998,"en":"southwest","ja":"南西の\n南と西の中間方向","level":6,"lnum":1,"ex":"Heavy rain is expected in the southwest region of the country tonight.","exja":"今夜、国の南西部地域で大雨が予想されている。"},{"id":3999,"en":"sparkle","ja":"輝き\n光がきらきらと反射する様子","level":6,"lnum":1,"ex":"Her eyes sparkled with excitement as she unwrapped the birthday gift.","exja":"誕生日プレゼントを開けながら、彼女の目は興奮で輝いた。"},{"id":4000,"en":"specialist","ja":"専門家\n特定分野の深い知識・技能を持つ人","level":6,"lnum":1,"ex":"He was referred to a specialist after the general doctor found a problem.","exja":"一般の医師が問題を見つけた後、彼は専門家に紹介された。"},{"id":4001,"en":"specialize/specialise","ja":"専門とする\n特定の分野に集中して取り組む","level":6,"lnum":1},{"id":4002,"en":"specially","ja":"特別に\n特定の目的のために・特別に。especiallyは程度を強調","level":6,"lnum":1,"ex":"The gift was specially made for her birthday by a local craftsman.","exja":"そのプレゼントは地元の職人によって彼女の誕生日のために特別に作られた。"},{"id":4003,"en":"spectacular","ja":"壮観な\n見事で印象的な見た目・出来事","level":6,"lnum":1,"ex":"The fireworks display on New Year's Eve was truly spectacular.","exja":"大晦日の花火大会はまさに壮観だった。"},{"id":4004,"en":"spectator","ja":"観客\nスポーツや公演を見る人。audienceより屋外・スポーツに使いやすい","level":6,"lnum":1,"ex":"Thousands of spectators cheered as the athletes crossed the finish line.","exja":"アスリートたちがゴールラインを越えると何千人もの観客が歓声を上げた。"},{"id":4005,"en":"spelling","ja":"つづり\n単語の文字の並び・正しい書き方","level":6,"lnum":1,"ex":"Her spelling improved greatly after she started reading books every day.","exja":"毎日本を読み始めてから、彼女のつづりは大きく向上した。"},{"id":4006,"en":"sphere","ja":"球体\n完全に丸い三次元の形。比喩的に「分野・領域」の意味も","level":6,"lnum":1,"ex":"The earth is not a perfect sphere, but it is close to one in shape.","exja":"地球は完全な球体ではないが、形はそれに近い。"},{"id":4007,"en":"spinach","ja":"ほうれん草\n鉄分が豊富な濃い緑色の葉野菜","level":6,"lnum":1,"ex":"The doctor advised her to eat more spinach to increase her iron levels.","exja":"医師は鉄分を増やすためにほうれん草をもっと食べるよう彼女に勧めた。"},{"id":4008,"en":"spiral","ja":"らせん状の\n中心から広がるコイル状の形・運動","level":6,"lnum":1,"ex":"The staircase in the old library wound in a graceful spiral to the top floor.","exja":"古い図書館の階段は優雅ならせん状に最上階まで続いていた。"},{"id":4009,"en":"spiritual","ja":"精神的な\n宗教・魂に関係する。mentalより宗教的・超自然的","level":6,"lnum":1,"ex":"She found spiritual peace through daily meditation and quiet reflection.","exja":"彼女は毎日の瞑想と静かな内省を通じて精神的な平和を見つけた。"},{"id":4010,"en":"split","ja":"分裂\n一つのものを複数に分けること・亀裂","level":6,"lnum":1,"ex":"The class was split into two groups for the science experiment.","exja":"科学実験のためにクラスは2つのグループに分割された。"},{"id":4011,"en":"spoil","ja":"台無しにする\n楽しみや食物を損なう。ruinより軽度の損傷","level":6,"lnum":1,"ex":"The argument between them spoiled what had been a perfect evening.","exja":"彼らの口論は完璧な夜を台無しにした。"},{"id":4012,"en":"sponge","ja":"スポンジ\n液体を吸収する多孔質の素材。「スポンジケーキ」にも使用","level":6,"lnum":1,"ex":"She used a damp sponge to clean the whiteboard after the lesson.","exja":"彼女は授業の後に白板を拭くために濡れたスポンジを使った。"},{"id":4013,"en":"sponsor","ja":"スポンサー\n資金・支援を提供する人・企業","level":6,"lnum":1,"ex":"A local business agreed to sponsor the school's annual sports event.","exja":"地元の企業が学校の年間スポーツイベントのスポンサーになることに同意した。"},{"id":4014,"en":"sports","ja":"スポーツの\n運動競技に関係する形容詞。「sports car」でスポーツカー","level":6,"lnum":1,"ex":"He wears his sports shoes even when he is not exercising because they are comfortable.","exja":"彼は運動していないときでも快適なのでスポーツシューズを履く。"},{"id":4015,"en":"sportsmanship","ja":"スポーツマンシップ\n公正・誠実さでスポーツに取り組む姿勢","level":6,"lnum":1,"ex":"The winning team showed great sportsmanship by shaking hands with their opponents.","exja":"優勝チームは相手と握手することで素晴らしいスポーツマンシップを見せた。"},{"id":4016,"en":"stable","ja":"安定した\n変化がなく一定の状態。unstableの反対","level":6,"lnum":1,"ex":"The patient's condition became stable after receiving emergency treatment.","exja":"患者の状態は緊急処置を受けた後、安定した。"},{"id":4017,"en":"stall","ja":"屋台\n市場の小さな売り場。動詞では「失速する・引き延ばす」","level":6,"lnum":1,"ex":"The market was full of colorful stalls selling fruits, vegetables, and crafts.","exja":"市場には果物、野菜、工芸品を売る色鮮やかな屋台が並んでいた。"},{"id":4018,"en":"stare","ja":"じっと見つめる\n長時間・集中して視線を向ける。lookより固定した視線","level":6,"lnum":1,"ex":"It is considered rude to stare at someone in public places.","exja":"公共の場で人をじっと見つめることは無礼だと考えられている。"},{"id":4019,"en":"status","ja":"地位\n社会的な立場・状況。positionより社会的評価を含む","level":6,"lnum":1,"ex":"Her professional status improved greatly after she earned her PhD.","exja":"博士号を取得してから彼女の職業的地位は大きく向上した。"},{"id":4020,"en":"steadily","ja":"着実に\n一定のペースで継続的に。graduallyより安定性を強調","level":6,"lnum":1,"ex":"He practiced guitar every day and steadily improved over the months.","exja":"彼は毎日ギターを練習し、数ヶ月かけて着実に上達した。"},{"id":4021,"en":"steady","ja":"安定した\n揺れずに一定した状態。stableより動的な安定感","level":6,"lnum":1,"ex":"Keep your hand steady when you use a knife to cut the vegetables.","exja":"野菜を切るためにナイフを使うときは手を安定させてください。"},{"id":4022,"en":"steel","ja":"鋼鉄\n鉄を強化した合金。hardnessと強さの象徴として使われる","level":6,"lnum":1,"ex":"The bridge is made of strong steel beams that can handle heavy traffic.","exja":"その橋は大量の交通に耐えられる強い鋼鉄の梁で作られている。"},{"id":4023,"en":"steep","ja":"急勾配の\n傾きが非常に急な坂。比喩的に「値段が高すぎる」にも","level":6,"lnum":1,"ex":"The hikers found it difficult to climb the steep slope in the rain.","exja":"登山者たちは雨の中、急勾配の坂を登るのが困難だとわかった。"},{"id":4024,"en":"stem","ja":"茎\n植物の葉・花を支える部分。動詞で「〜に起因する」の意味も","level":6,"lnum":1,"ex":"She carefully cut the stem of the rose before placing it in the vase.","exja":"花瓶に入れる前に、彼女はバラの茎を丁寧に切った。"},{"id":4025,"en":"sticker","ja":"シール\n粘着性のある小さな印刷物","level":6,"lnum":1,"ex":"The children decorated their notebooks with colorful animal stickers.","exja":"子どもたちはカラフルな動物のシールでノートを飾った。"},{"id":4026,"en":"stir","ja":"かき混ぜる\nスプーンなどで液体・材料を混ぜる。比喩的に「感情を掻き立てる」","level":6,"lnum":1,"ex":"She stirred the batter gently until all the ingredients were well mixed.","exja":"すべての材料がよく混ざるまで、彼女は生地をそっとかき混ぜた。"},{"id":4027,"en":"storage","ja":"保管\n物を保存しておく場所・行為","level":6,"lnum":1,"ex":"The apartment has a large storage room under the stairs for extra items.","exja":"そのアパートには余分な荷物のための階段下に広い保管室がある。"},{"id":4028,"en":"stormy","ja":"嵐の\n強風と雨を伴う荒れた天気。比喩的に「激動の」にも","level":6,"lnum":1,"ex":"It was a stormy night, and the heavy rain kept everyone inside.","exja":"嵐の夜で、激しい雨がみんなを屋内に閉じ込めた。"},{"id":4029,"en":"storyteller","ja":"語り手\n物語を人に話す・書く人","level":6,"lnum":1,"ex":"The old man was a wonderful storyteller who kept the children listening for hours.","exja":"その老人は何時間も子どもたちを聞き入らせる素晴らしい語り手だった。"},{"id":4030,"en":"strain","ja":"緊張\n精神的・肉体的な緊張・過度な負担","level":6,"lnum":1,"ex":"The long hours at work put a lot of strain on his eyes and shoulders.","exja":"長時間の仕事が彼の目と肩に大きな緊張をもたらした。"},{"id":4031,"en":"strangely","ja":"奇妙に\n普通とは異なる方法で・不思議なことに","level":6,"lnum":1,"ex":"The cat behaved strangely before the earthquake, which worried the family.","exja":"地震の前に猫が奇妙に振る舞い、家族を心配させた。"},{"id":4032,"en":"strategic","ja":"戦略的な\n長期的な計画・目標に基づく。tacticalより大局的","level":6,"lnum":1,"ex":"The company made a strategic decision to expand into Asian markets.","exja":"その会社はアジア市場に進出するという戦略的な決定を下した。"},{"id":4033,"en":"strengthen","ja":"強化する\n強さ・力を増す。weakenの反対","level":6,"lnum":1,"ex":"Regular exercise will help strengthen the muscles in your legs and back.","exja":"定期的な運動は脚と背中の筋肉を強化するのに役立つ。"},{"id":4034,"en":"stressed","ja":"ストレスを感じた\n強いプレッシャーや不安を感じた状態","level":6,"lnum":1,"ex":"She was feeling very stressed because of the amount of homework she had.","exja":"彼女は宿題の量でとてもストレスを感じていた。"},{"id":4035,"en":"stressful","ja":"ストレスの多い\n精神的緊張を引き起こす状況や状態","level":6,"lnum":1,"ex":"Working under a tight deadline every day is stressful for most people.","exja":"毎日きついデッドラインの下で働くことはほとんどの人にとってストレスが多い。"},{"id":4036,"en":"stricken","ja":"打ちのめされた\n病気・悲しみ・災害に深く見舞われた状態","level":6,"lnum":1,"ex":"The small town was stricken by a flood that destroyed many homes.","exja":"その小さな町は多くの家を破壊した洪水に打ちのめされた。"},{"id":4037,"en":"strike","ja":"打つ\n強く当たる・印象を与える。hitより劇的・意図的な打撃","level":6,"lnum":1,"ex":"The clock struck twelve just as the new year began.","exja":"新年が始まるとちょうど時計が12時を打った。"},{"id":4038,"en":"strip","ja":"細長い切れ\n長く細い帯状の部分。動詞で「剥ぎ取る」の意味も","level":6,"lnum":1,"ex":"The electrician carefully removed a strip of rubber from the wire.","exja":"電気工は丁寧にワイヤーからゴムの細長い切れを取り除いた。"},{"id":4039,"en":"stripe","ja":"縞\n色の異なる帯状の線。stripより装飾的なデザインを示す","level":6,"lnum":1,"ex":"The school uniform has a blue and white stripe along the collar.","exja":"学校の制服には首元に青と白の縞がある。"},{"id":4040,"en":"struggle","ja":"苦闘\n困難に対して懸命に戦う・努力する行為","level":6,"lnum":1,"ex":"She struggled to balance her studies and her part-time job every week.","exja":"彼女は毎週勉強とアルバイトのバランスを取ることに苦闘した。"},{"id":4041,"en":"stubborn","ja":"頑固な\n意見や行動を変えようとしない。persistentは良い意味もある","level":6,"lnum":1,"ex":"He was too stubborn to admit that he had made a mistake.","exja":"彼は間違いを犯したことを認めるには頑固すぎた。"},{"id":4042,"en":"stuck","ja":"行き詰まった\n動けない・解決できない状態","level":6,"lnum":1,"ex":"The car got stuck in the mud on the unpaved country road.","exja":"車は舗装されていない田舎道で泥にはまってしまった。"},{"id":4043,"en":"studio","ja":"スタジオ\n芸術家の作業場・録音・撮影のための部屋","level":6,"lnum":1,"ex":"The artist rented a small studio in the city where she could paint every day.","exja":"その芸術家は毎日絵が描ける市内に小さなスタジオを借りた。"},{"id":4044,"en":"stuffed","ja":"詰め込まれた\n中に物が一杯詰められた状態。「I'm stuffed」で満腹を表す","level":6,"lnum":1,"ex":"After the large dinner, everyone felt too stuffed to move.","exja":"大きな夕食の後、みんなは動けないほど食べすぎた状態だった。"},{"id":4045,"en":"stumble","ja":"つまずく\n歩行中に足を引っかけてよろける。tripとほぼ同義","level":6,"lnum":1,"ex":"He stumbled on the broken step at the entrance and nearly fell down.","exja":"彼は入り口の壊れた段につまずき、もう少しで転びそうになった。"},{"id":4046,"en":"stun","ja":"仰天させる\n驚きや衝撃で一時的に反応できなくする","level":6,"lnum":1,"ex":"The unexpected announcement stunned the entire audience into silence.","exja":"予想外の発表は聴衆全員を仰天させて沈黙させた。"},{"id":4047,"en":"stunning","ja":"息をのむほど美しい\n驚くほど素晴らしい・衝撃的なほど美しい","level":6,"lnum":1,"ex":"The view from the top of the mountain was absolutely stunning.","exja":"山の頂上からの眺めは息をのむほど素晴らしかった。"},{"id":4048,"en":"stylish","ja":"おしゃれな\n流行のセンスがある・格好いい。fashionableとほぼ同義","level":6,"lnum":1,"ex":"She always looks stylish no matter what she wears to school.","exja":"彼女は学校に何を着てきても常においしゃれに見える。"},{"id":4049,"en":"subconscious","ja":"潜在意識の\n意識されていないが行動に影響を与える心の層","level":6,"lnum":1,"ex":"Our subconscious mind often influences decisions without us realizing it.","exja":"私たちの潜在意識はしばしば私たちが気づかないうちに決断に影響を与える。"},{"id":4050,"en":"submarine","ja":"潜水艦\n水中を航行できる船舶","level":6,"lnum":1,"ex":"The navy's submarine traveled deep beneath the ocean for weeks without surfacing.","exja":"海軍の潜水艦は何週間も水面に出ることなく海の深くを旅した。"},{"id":4051,"en":"substantial","ja":"かなりの\n量・程度が大きい・重要な。considerableとほぼ同義","level":6,"lnum":1,"ex":"There was a substantial difference in price between the two models.","exja":"2つのモデルの間にはかなりの価格差があった。"},{"id":4052,"en":"substitute","ja":"代替品\n別のものの代わりに使う人・物","level":6,"lnum":1,"ex":"When the teacher was ill, a substitute came to lead the class.","exja":"先生が病気のとき、代替の先生がクラスを担当しに来た。"},{"id":4053,"en":"sufficient","ja":"十分な\n必要な量・程度を満たしている。enoughより書き言葉的","level":6,"lnum":1,"ex":"Make sure you have sufficient time to review your answers before the exam ends.","exja":"試験が終わる前に答えを見直すのに十分な時間があることを確認してください。"},{"id":4054,"en":"suffix","ja":"接尾辞\n単語の後に付けて意味を変える文字列（文法用語）","level":6,"lnum":1,"ex":"Adding the suffix \"-ful\" to \"care\" gives us the word \"careful.\"","exja":"\"care\"に接尾辞「-ful」を加えると「careful」という単語になる。"},{"id":4055,"en":"suicide","ja":"自殺\n自ら命を絶つ行為","level":6,"lnum":1,"ex":"The school provided counseling services to help students dealing with stress and depression.","exja":"学校はストレスやうつに悩む生徒を支援するためにカウンセリングサービスを提供した。"},{"id":4056,"en":"summarize/summarise","ja":"要約する\n長い内容の主要点を短くまとめる","level":6,"lnum":1},{"id":4057,"en":"summit","ja":"山頂・首脳会議\n山の最高点。国家指導者間の最高レベル会議にも使用","level":6,"lnum":1,"ex":"After hours of climbing, they finally reached the summit and enjoyed the view.","exja":"何時間も登った後、彼らはついに山頂に到達して景色を楽しんだ。"},{"id":4058,"en":"sunbathe","ja":"日光浴する\n太陽の光を浴びて横になる","level":6,"lnum":1,"ex":"She loves to sunbathe on the beach during her summer vacation.","exja":"彼女は夏休みの間、ビーチで日光浴するのが大好きだ。"},{"id":4059,"en":"sundial","ja":"日時計\n太陽の影で時刻を示す装置","level":6,"lnum":1,"ex":"The old sundial in the garden still shows the correct time on sunny days.","exja":"庭の古い日時計は晴れた日には今でも正確な時間を示す。"},{"id":4060,"en":"superior","ja":"優れた\n質・地位が他より高い。inferiorの反対","level":6,"lnum":1,"ex":"The quality of this product is clearly superior to the cheaper version.","exja":"この製品の品質は安価なバージョンよりも明らかに優れている。"},{"id":4061,"en":"superstition","ja":"迷信\n科学的根拠のない不合理な信仰・慣習","level":6,"lnum":1,"ex":"It is just a superstition that breaking a mirror brings seven years of bad luck.","exja":"鏡を割ると7年間不幸が続くというのは単なる迷信だ。"},{"id":4062,"en":"supply","ja":"供給\n必要なものを提供すること・在庫","level":6,"lnum":1,"ex":"The aid organization was working hard to supply food and water to the refugees.","exja":"支援団体は難民に食料と水を供給するために懸命に活動していた。"},{"id":4063,"en":"supporter","ja":"支持者\n特定の人・団体・考えを応援する人","level":6,"lnum":1,"ex":"She has been a loyal supporter of the local football team for many years.","exja":"彼女は何年もの間、地元のサッカーチームの忠実な支持者だ。"},{"id":4064,"en":"supportive","ja":"支援的な\n精神的・実際的な助けを提供する性質","level":6,"lnum":1,"ex":"Her friends were very supportive when she was going through a difficult time.","exja":"友人たちは彼女が困難な時期を過ごしているとき、とても支援的だった。"},{"id":4065,"en":"suppose","ja":"思う・仮定する\n〜だと思う・仮定する。thinkより不確かなニュアンス","level":6,"lnum":1,"ex":"I suppose the meeting will be rescheduled since the manager is away.","exja":"マネージャーが不在なので、会議は再スケジュールされると思う。"},{"id":4066,"en":"supposedly","ja":"おそらく\nそう言われているが確かではない。allegedlyより日常的","level":6,"lnum":1,"ex":"This old recipe is supposedly the secret behind the bakery's amazing bread.","exja":"この古いレシピがそのパン屋の素晴らしいパンの秘密だとされている。"},{"id":4067,"en":"surely","ja":"きっと\n確実に・疑いなく。certainlyより話し手の確信度を表す","level":6,"lnum":1,"ex":"If you practice every day, you will surely see improvement in your skills.","exja":"毎日練習すれば、きっとスキルの向上がわかるはずだ。"},{"id":4068,"en":"surface","ja":"表面\n物の外側・上面。insideの反対の外側","level":6,"lnum":1,"ex":"She wiped the surface of the table clean before setting out the plates.","exja":"皿を並べる前に彼女はテーブルの表面をきれいに拭いた。"},{"id":4069,"en":"surgeon","ja":"外科医\n手術を行う医師専門家","level":6,"lnum":1,"ex":"The surgeon performed a successful operation on the patient's heart.","exja":"外科医は患者の心臓の手術を成功させた。"},{"id":4070,"en":"surgery","ja":"手術\n体を切開して行う医療行為","level":6,"lnum":1,"ex":"He needed surgery to repair the broken bone in his leg after the accident.","exja":"事故の後、彼は足の折れた骨を修復するための手術が必要だった。"},{"id":4071,"en":"surrounding","ja":"周囲の\nある物・場所の周りにある。nearby とほぼ同義","level":6,"lnum":1,"ex":"The surrounding mountains are covered with colorful flowers every spring.","exja":"周囲の山々は毎年春に色とりどりの花で覆われる。"},{"id":4072,"en":"survival","ja":"生存\n危険・困難な状況を生き抜くこと","level":6,"lnum":1,"ex":"Learning basic first aid skills can be crucial for survival in emergencies.","exja":"基本的な応急処置のスキルを学ぶことは緊急時の生存にとって重要だ。"},{"id":4073,"en":"suspect","ja":"容疑者\n犯罪を行ったと疑われている人","level":6,"lnum":1,"ex":"The police questioned the suspect for several hours at the station.","exja":"警察は警察署で何時間も容疑者を尋問した。"},{"id":4074,"en":"suspicion","ja":"疑い\n証拠なしに何かを疑う気持ち","level":6,"lnum":1,"ex":"She had a suspicion that something was wrong when she saw the empty box.","exja":"空の箱を見たとき、彼女は何かがおかしいという疑いを持った。"},{"id":4075,"en":"swarm","ja":"群れ\n昆虫などの大きな集団。「a swarm of bees」でミツバチの群れ","level":6,"lnum":1,"ex":"A swarm of bees gathered around the flowers in the garden.","exja":"ミツバチの群れが庭の花の周りに集まった。"},{"id":4076,"en":"swear","ja":"誓う・悪態をつく\n強く誓う。または不快な言葉を使う","level":6,"lnum":1,"ex":"She swore that she had never seen the missing document before.","exja":"彼女は紛失した書類を一度も見たことがないと誓った。"},{"id":4077,"en":"sweatshirt","ja":"スウェットシャツ\n厚手の綿素材の長袖トップス","level":6,"lnum":1,"ex":"He put on a warm sweatshirt before heading out for his morning jog.","exja":"朝のジョギングに出かける前に、彼は暖かいスウェットシャツを着た。"},{"id":4078,"en":"swell","ja":"膨らむ\n大きさが増す・腫れる。比喩的に感情が高まる場面にも","level":6,"lnum":1,"ex":"Her ankle began to swell after she twisted it during the soccer match.","exja":"サッカーの試合中に足首を捻った後、腫れ始めた。"},{"id":4079,"en":"swollen","ja":"腫れた\n炎症や怪我で大きくなった状態","level":6,"lnum":1,"ex":"Her foot was swollen and painful after she accidentally kicked the wall.","exja":"誤って壁を蹴った後、彼女の足は腫れて痛かった。"},{"id":4080,"en":"sword","ja":"剣\n刃のある長い武器","level":6,"lnum":1,"ex":"The museum displayed an ancient sword that was used by a famous samurai.","exja":"博物館は有名な侍が使った古い剣を展示していた。"},{"id":4081,"en":"sympathy","ja":"同情\n他人の苦しみに対する感情的な理解。empathyは実際に感情を共有","level":6,"lnum":1,"ex":"The teacher expressed sympathy for the student who had lost a family member.","exja":"先生は家族を亡くした生徒に対して同情を示した。"},{"id":4082,"en":"symptom","ja":"症状\n病気・問題の外から見えるサイン","level":6,"lnum":1,"ex":"A high fever and a sore throat are common symptoms of the flu.","exja":"高熱と喉の痛みはインフルエンザの一般的な症状だ。"},{"id":4083,"en":"syndrome","ja":"症候群\n特定の症状が組み合わさった医学的状態","level":6,"lnum":1,"ex":"The doctor explained that the child had a rare syndrome that affected her balance.","exja":"医師はその子どもが彼女のバランスに影響する珍しい症候群を持っていると説明した。"},{"id":4084,"en":"systematic","ja":"体系的な\n計画・規則に基づいた秩序ある方法。haphazardの反対","level":6,"lnum":1,"ex":"The scientist followed a systematic approach to conduct the experiment carefully.","exja":"科学者は実験を注意深く行うための体系的なアプローチに従った。"},{"id":4085,"en":"takeaway","ja":"持ち帰り\n店から持ち帰って食べる食事。英国英語でtakeoutに相当","level":6,"lnum":1,"ex":"She ordered a takeaway from a local restaurant because she was too tired to cook.","exja":"料理するには疲れすぎていたので、彼女は地元のレストランに持ち帰り料理を注文した。"},{"id":4086,"en":"takeoff/take-off","ja":"離陸\n飛行機が地面を離れる瞬間・行為","level":6,"lnum":1},{"id":4087,"en":"talented","ja":"才能のある\n生まれ持った優れた能力を持つ。skilledは習得した技術","level":6,"lnum":1,"ex":"She is a talented musician who can play five instruments fluently.","exja":"彼女は5つの楽器を流暢に演奏できる才能のある音楽家だ。"},{"id":4088,"en":"talkative","ja":"おしゃべりな\nよく話す・話し好きな性格","level":6,"lnum":1,"ex":"He became much more talkative after he gained confidence in speaking English.","exja":"英語を話す自信がついてから、彼はずっとおしゃべりになった。"},{"id":4089,"en":"tasteless","ja":"味がない\n風味がない・センスが悪い。「tasteless joke」で下品なジョーク","level":6,"lnum":1,"ex":"The soup was tasteless because she had forgotten to add salt and seasoning.","exja":"塩と調味料を入れ忘れたため、スープは味がなかった。"},{"id":4090,"en":"teaching","ja":"教育\n知識・技術を教える行為・職業","level":6,"lnum":1,"ex":"Teaching young children to read is one of the most rewarding jobs.","exja":"幼い子どもたちに読み方を教えることは最もやりがいのある仕事の一つだ。"},{"id":4091,"en":"tease","ja":"からかう\n軽くいじる・ちょっかいを出す。bullying（いじめ）より軽い","level":6,"lnum":1,"ex":"Her older brother would often tease her about her love of cartoon shows.","exja":"兄はアニメ番組への彼女の好みをよくからかっていた。"},{"id":4092,"en":"technique","ja":"技術\n特定の作業を行うための専門的な方法","level":6,"lnum":1,"ex":"The coach taught the players a new technique for passing the ball more accurately.","exja":"コーチは選手たちにボールをより正確にパスするための新しい技術を教えた。"},{"id":4093,"en":"technological","ja":"技術的な\nテクノロジー・科学技術に関係する","level":6,"lnum":1,"ex":"Many technological advances have made daily life much easier in the past decade.","exja":"多くの技術的な進歩が過去10年間で日常生活をずっと楽にした。"},{"id":4094,"en":"teen","ja":"10代\n13〜19歳の若者。teenagerの短縮形","level":6,"lnum":1,"ex":"The program was designed to help teens develop healthy study habits.","exja":"そのプログラムは10代の若者が健全な学習習慣を身につけるのを助けるために設計された。"},{"id":4095,"en":"telecommunications","ja":"電気通信\n電話・インターネットなどの遠距離通信技術の総称","level":6,"lnum":1,"ex":"The telecommunications industry has grown rapidly with the rise of smartphones.","exja":"電気通信産業はスマートフォンの台頭とともに急速に成長した。"},{"id":4096,"en":"telegram","ja":"電報\n電信で送る短いメッセージ。現代ではほぼ廃れた通信手段","level":6,"lnum":1,"ex":"In the old days, people sent a telegram to announce important news quickly.","exja":"昔、人々は重要なニュースを素早く伝えるために電報を送った。"},{"id":4097,"en":"teller","ja":"窓口係\n銀行の窓口でお金を扱う人","level":6,"lnum":1,"ex":"The bank teller helped the customer deposit cash into her account.","exja":"銀行の窓口係は顧客が口座に現金を入金するのを手助けした。"},{"id":4098,"en":"temper","ja":"気性\n感情のコントロール傾向。「lose one's temper」で怒りを爆発させる","level":6,"lnum":1,"ex":"He lost his temper during the argument and said things he later regretted.","exja":"口論中に彼は怒りを爆発させ、後で後悔することを言ってしまった。"},{"id":4099,"en":"temporary","ja":"一時的な\n限られた期間だけ続く。permanentの反対","level":6,"lnum":1,"ex":"The school set up temporary classrooms in the gym while the building was repaired.","exja":"建物が修理される間、学校は体育館に一時的な教室を設けた。"},{"id":4100,"en":"tempt","ja":"誘惑する\n魅力的なものを提示して引きつける・悪いことへ誘う","level":6,"lnum":1,"ex":"The smell of fresh cookies from the kitchen tempted everyone in the house.","exja":"台所からの新鮮なクッキーの香りが家中の全員を誘惑した。"},{"id":4101,"en":"tend","ja":"傾向がある\nある行動・状態になりがちである","level":6,"lnum":1,"ex":"He tends to stay up late when he has a lot of homework to finish.","exja":"彼は終わらせる宿題がたくさんあると夜更かしする傾向がある。"},{"id":4102,"en":"tendency","ja":"傾向\n特定の方向に向かいやすい性質","level":6,"lnum":1,"ex":"She has a tendency to overthink simple decisions.","exja":"彼女はシンプルな決断を考えすぎる傾向がある。"},{"id":4103,"en":"tense","ja":"緊張した\nストレスや不安で筋肉・精神が張り詰めた。文法の「時制」にも","level":6,"lnum":1,"ex":"The atmosphere in the room became tense as the game entered its final minutes.","exja":"試合が残り数分になると、部屋の雰囲気は緊張した。"},{"id":4104,"en":"tension","ja":"緊張感\n対立や不安から生まれる精神的な張りつめ","level":6,"lnum":1,"ex":"There was a lot of tension between the two teams before the final match.","exja":"最終戦の前に2つのチームの間には多くの緊張感があった。"},{"id":4105,"en":"terminal","ja":"終着駅\n交通機関の最終地点。医学では「末期の」の意味も","level":6,"lnum":1,"ex":"The new airport terminal is spacious and has many shops and restaurants.","exja":"新しい空港の終着駅は広々としていて多くの店とレストランがある。"},{"id":4106,"en":"terribly","ja":"ひどく\n非常に・とても（否定的な文脈）。awfullyとほぼ同義","level":6,"lnum":1,"ex":"She felt terribly sorry for forgetting her friend's birthday.","exja":"友人の誕生日を忘れたことで彼女はとても申し訳なく感じた。"},{"id":4107,"en":"terrific","ja":"素晴らしい\n非常に良い・素晴らしい。口語では肯定的な驚きを表す","level":6,"lnum":1,"ex":"The band gave a terrific performance that the crowd will never forget.","exja":"バンドは観客が決して忘れない素晴らしいパフォーマンスを披露した。"},{"id":4108,"en":"terrified","ja":"恐怖した\n非常に怖い・恐怖で震えている状態","level":6,"lnum":1,"ex":"The little boy was terrified of the dark and always slept with the light on.","exja":"小さな男の子は暗闇を恐怖し、いつも電気をつけて寝ていた。"},{"id":4109,"en":"terror","ja":"恐怖\n強烈な恐れ・テロ行為の意味も持つ","level":6,"lnum":1,"ex":"The passengers on the shaking plane felt a sudden surge of terror.","exja":"揺れる飛行機の乗客は突然の恐怖を感じた。"},{"id":4110,"en":"terrorism","ja":"テロリズム\n政治的目的のための暴力・脅迫行為","level":6,"lnum":1,"ex":"World leaders agreed to work together to fight terrorism and protect civilians.","exja":"世界の指導者たちはテロリズムと戦い市民を守るために協力することに合意した。"},{"id":4111,"en":"terrorist","ja":"テロリスト\nテロ行為を行う人・組織","level":6,"lnum":1,"ex":"The police arrested the terrorist before he could carry out his plan.","exja":"警察は計画を実行する前にテロリストを逮捕した。"},{"id":4112,"en":"thankful","ja":"感謝した\n感謝の気持ちを持つ。gratefulとほぼ同義","level":6,"lnum":1,"ex":"She was very thankful to her mentor who helped her through difficult times.","exja":"彼女は困難な時期を乗り越えるのを助けてくれたメンターにとても感謝した。"},{"id":4113,"en":"theft","ja":"窃盗\n他人の財物を盗む行為・罪","level":6,"lnum":1,"ex":"The theft of the painting from the gallery shocked the entire art community.","exja":"ギャラリーからの絵画の窃盗はアート界全体を驚かせた。"},{"id":4114,"en":"theory","ja":"理論\n事実を説明するための体系的な考え方","level":6,"lnum":1,"ex":"Einstein's theory of relativity changed the way scientists understand the universe.","exja":"アインシュタインの相対性理論は科学者たちが宇宙を理解する方法を変えた。"},{"id":4115,"en":"thirst","ja":"渇望する\n水・何かを強く欲する","level":6,"lnum":1,"ex":"After the long hike, she had a desperate thirst and drank two bottles of water.","exja":"長いハイキングの後、彼女はひどく水が飲みたくて2本のペットボトルの水を飲んだ。"},{"id":4116,"en":"thorough","ja":"徹底的な\n完全で細部まで注意を払った。partialの反対","level":6,"lnum":1,"ex":"The mechanic did a thorough check of the car before the long road trip.","exja":"長距離ドライブの前に、整備士は車の徹底的な点検を行った。"},{"id":4117,"en":"threat","ja":"脅威\n危害を加えると警告すること・危険な存在","level":6,"lnum":1,"ex":"The rising sea level is a serious threat to low-lying coastal cities.","exja":"上昇する海面は低地の沿岸都市にとって深刻な脅威だ。"},{"id":4118,"en":"threatening","ja":"脅迫的な\n脅しや危険を示す言動・態度","level":6,"lnum":1,"ex":"The coach's threatening tone made the players feel nervous during practice.","exja":"コーチの脅迫的な口調は練習中に選手たちを緊張させた。"},{"id":4119,"en":"thriller","ja":"スリラー\n緊張・興奮をもたらすジャンルの映画・小説","level":6,"lnum":1,"ex":"She stayed up until midnight to finish reading the thriller she had borrowed.","exja":"彼女は借りたスリラーを読み終えるために深夜まで起きていた。"},{"id":4120,"en":"throughout","ja":"〜を通じて\n期間・範囲の全体にわたって","level":6,"lnum":1,"ex":"She worked hard throughout the year and earned the highest grade in her class.","exja":"彼女は一年を通じて懸命に働き、クラスで最高の成績を収めた。"},{"id":4121,"en":"thumb","ja":"親指\n手の最も太い指","level":6,"lnum":1,"ex":"She gave a thumbs-up to show that everything was going well.","exja":"彼女はすべてがうまくいっていることを示すために親指を立てた。"},{"id":4122,"en":"thump","ja":"どんとたたく\n重いものが落ちる・強く打つ鈍い音や動作","level":6,"lnum":1,"ex":"He heard a loud thump from upstairs and rushed up to check what had happened.","exja":"上階からどんという大きな音が聞こえ、何が起きたか確かめに急いで上がった。"},{"id":4123,"en":"thunder","ja":"雷鳴\n稲妻に伴う大きな音。lightningは光でthunderは音","level":6,"lnum":1,"ex":"The children ran inside when they heard the first crack of thunder.","exja":"最初の雷鳴を聞いたとき、子どもたちは家の中へ走って入った。"},{"id":4124,"en":"thunderous","ja":"雷のような\n非常に大きな轟くような音","level":6,"lnum":1,"ex":"The thunderous applause from the audience showed how much they enjoyed the show.","exja":"観客の雷のような拍手はショーをいかに楽しんだかを示していた。"},{"id":4125,"en":"thus","ja":"したがって\n論理的な帰結を示す。thereforeより書き言葉的・古風","level":6,"lnum":1,"ex":"She studied every night and thus managed to pass the difficult exam.","exja":"彼女は毎晩勉強し、したがって難しい試験に合格することができた。"},{"id":4126,"en":"tick","ja":"チェック印\n完了・正解を示す印（✓）。虫のマダニにも使う","level":6,"lnum":1,"ex":"She put a tick next to each completed task on her to-do list.","exja":"彼女はやることリストの完了したタスクの横にチェック印を付けた。"},{"id":4127,"en":"tide","ja":"潮\n月の引力による海水の干満の変化","level":6,"lnum":1,"ex":"The tide came in quickly and covered most of the beach by afternoon.","exja":"潮が素早く満ちてきて、午後までに浜辺の大部分を覆った。"},{"id":4128,"en":"tighten","ja":"締める\nゆるみをなくして固くする。loosenの反対","level":6,"lnum":1,"ex":"Please tighten the screws on the chair to make sure it does not wobble.","exja":"椅子がぐらつかないようにネジを締めてください。"},{"id":4129,"en":"tightly","ja":"きつく\nしっかりと・緩みなく締めた状態で","level":6,"lnum":1,"ex":"She held tightly to her mother's hand as they walked through the crowded market.","exja":"混雑した市場を歩く間、彼女は母親の手をきつく握った。"},{"id":4130,"en":"tile","ja":"タイル\n床・壁に敷く平らな焼き物・石材","level":6,"lnum":1,"ex":"The kitchen floor was covered with white and blue tiles in a classic pattern.","exja":"台所の床は古典的なパターンの白と青のタイルで覆われていた。"},{"id":4131,"en":"timely","ja":"時宜を得た\n適切なタイミングで行われる・時機に合った","level":6,"lnum":1,"ex":"The timely arrival of the rescue team saved many lives after the earthquake.","exja":"救助隊の時機を得た到着が地震後に多くの命を救った。"},{"id":4132,"en":"tin","ja":"缶\n金属製の密閉容器。英国英語でcanに相当","level":6,"lnum":1,"ex":"She opened a tin of biscuits and offered some to her guests.","exja":"彼女はビスケットの缶を開けてゲストに勧めた。"},{"id":4133,"en":"tire","ja":"疲れさせる\nエネルギーを消耗させる。動詞として「飽きる」の意味も","level":6,"lnum":1,"ex":"Long hours of studying began to tire her out by the end of the week.","exja":"週の終わりには長時間の勉強で彼女は疲れ果て始めた。"},{"id":4134,"en":"tiring","ja":"疲れさせる\n体力・精神力を消耗させる性質","level":6,"lnum":1,"ex":"The long flight across the ocean was exhausting and tiring for everyone.","exja":"海を越える長い飛行はみんなにとって消耗して疲れさせるものだった。"},{"id":4135,"en":"tobacco","ja":"タバコ\nタバコの葉・喫煙用の製品","level":6,"lnum":1,"ex":"The government launched a campaign to discourage young people from using tobacco.","exja":"政府は若者がタバコを使用することを思いとどまらせるキャンペーンを始めた。"},{"id":4136,"en":"toothpaste","ja":"歯磨き粉\n歯を磨くためのペースト状の洗浄剤","level":6,"lnum":1,"ex":"She always uses mint-flavored toothpaste because it leaves her mouth feeling fresh.","exja":"彼女はいつも口がすっきりするミント味の歯磨き粉を使う。"},{"id":4137,"en":"tornado","ja":"竜巻\n高速で回転する破壊的な風の渦","level":6,"lnum":1,"ex":"The tornado destroyed several houses and uprooted many trees in the area.","exja":"竜巻はその地域でいくつかの家を破壊し、多くの木を根こそぎにした。"},{"id":4138,"en":"toss","ja":"投げる\n軽く・無造作に投げる。throwより軽い動作","level":6,"lnum":1,"ex":"He tossed the ball gently to the young child standing nearby.","exja":"彼は近くに立っている幼い子どもに軽くボールを投げた。"},{"id":4139,"en":"totally","ja":"完全に\n全体的に・例外なく。completelyとほぼ同義","level":6,"lnum":1,"ex":"She was totally focused on her studies and did not notice the time passing.","exja":"彼女は勉強に完全に集中していて時間が過ぎることに気づかなかった。"},{"id":4140,"en":"tourism","ja":"観光業\n観光を目的とした旅行とその産業全体","level":6,"lnum":1,"ex":"The beautiful scenery has made tourism the main industry of the island.","exja":"美しい景色がその島で観光業を主要産業にした。"},{"id":4141,"en":"trace","ja":"痕跡\n以前あったことを示すわずかな証拠・跡","level":6,"lnum":1,"ex":"The detectives found no trace of the suspect at the scene of the crime.","exja":"探偵たちは犯罪現場で容疑者の痕跡を全く見つけられなかった。"},{"id":4142,"en":"tracksuit","ja":"トレーニングウェア\n運動用の上下セットの服","level":6,"lnum":1,"ex":"She wore her blue tracksuit during the morning run in the park.","exja":"彼女は公園での朝のランニング中に青いトレーニングウェアを着た。"},{"id":4143,"en":"traditionally","ja":"伝統的に\n長年受け継がれた慣習に従って","level":6,"lnum":1,"ex":"Families traditionally gather for a large meal during the New Year holiday.","exja":"伝統的に、家族は正月休みに大きな食事のために集まる。"},{"id":4144,"en":"traffic jam","ja":"交通渋滞\n車が込んで動けない状態","level":6,"lnum":1,"ex":"She was late for work because she got stuck in a terrible traffic jam.","exja":"ひどい交通渋滞にはまったため、彼女は仕事に遅刻した。"},{"id":4145,"en":"tragedy","ja":"悲劇\n非常に不幸な出来事・悲劇的な芸術作品","level":6,"lnum":1,"ex":"The sudden loss of their beloved teacher was a tragedy for the whole school.","exja":"愛する先生の突然の喪失はその学校全体にとって悲劇だった。"},{"id":4146,"en":"trail","ja":"小道\n森や山の中の踏み分け道","level":6,"lnum":1,"ex":"The hikers followed the forest trail for three hours to reach the waterfall.","exja":"ハイカーたちは滝に到達するために3時間、森の小道をたどった。"},{"id":4147,"en":"transfer","ja":"移動する\n場所・所有者・役割を別のものに移す","level":6,"lnum":1,"ex":"She decided to transfer to a new school that was closer to her home.","exja":"彼女は家に近い新しい学校に転校することを決めた。"},{"id":4148,"en":"transform","ja":"変容させる\n本質的に変える・大きく変化させる。changeより劇的な変化","level":6,"lnum":1,"ex":"The renovation completely transformed the old factory into a modern art gallery.","exja":"改修工事は古い工場を現代的なアートギャラリーに完全に変容させた。"},{"id":4149,"en":"transformation","ja":"変容\n大きく本質的に変わること・変化の過程","level":6,"lnum":1,"ex":"The transformation of the abandoned park into a community garden was impressive.","exja":"廃れた公園がコミュニティガーデンへと変容したのは印象的だった。"},{"id":4150,"en":"transitional","ja":"移行期の\nある状態から別の状態への変化の途中にある","level":6,"lnum":1,"ex":"The new policy is a transitional measure until the permanent system is in place.","exja":"新しい方針は恒久的なシステムが整うまでの移行期の措置だ。"},{"id":4151,"en":"transport","ja":"輸送\n人や物を一か所から別の場所へ運ぶこと","level":6,"lnum":1,"ex":"The city built new bike lanes to transport more people without using cars.","exja":"市は自動車を使わずにより多くの人を輸送するための新しい自転車レーンを作った。"},{"id":4152,"en":"transportation","ja":"交通機関\n移動のための手段・システムの総称（主に米語）","level":6,"lnum":1,"ex":"Public transportation in this city is fast, cheap, and easy to use.","exja":"この都市の公共交通機関は速くて安くて使いやすい。"},{"id":4153,"en":"travel agent","ja":"旅行代理店\n旅行の手配・予約を行う業者","level":6,"lnum":1,"ex":"She visited a travel agent to book a two-week trip to Europe for the summer.","exja":"彼女は夏にヨーロッパへの2週間の旅を予約するために旅行代理店を訪れた。"},{"id":4154,"en":"treatment","ja":"治療\n病気・怪我の医療的対処。「get treatment」で治療を受ける","level":6,"lnum":1,"ex":"The doctor started a new treatment that helped reduce the patient's pain quickly.","exja":"医師は患者の痛みを素早く軽減するのに役立つ新しい治療を始めた。"},{"id":4155,"en":"tremble","ja":"震える\n恐怖・寒さ・興奮で体が震える。shiverより全身の震えを示す","level":6,"lnum":1,"ex":"His hands began to tremble with excitement as he opened the acceptance letter.","exja":"合格通知を開けるとき、彼の手は興奮で震え始めた。"},{"id":4156,"en":"tremendous","ja":"とてつもない\n非常に大きい・素晴らしい。enormousより感情的な強調","level":6,"lnum":1,"ex":"Cleaning up the park took a tremendous amount of effort from all the volunteers.","exja":"公園の清掃には全ボランティアのとてつもない量の努力が必要だった。"},{"id":4157,"en":"trend","ja":"傾向・流行\n特定の方向への動き・流行のスタイル","level":6,"lnum":1,"ex":"There is a growing trend among young people to shop online rather than in stores.","exja":"若者の間で店舗ではなくオンラインで買い物する傾向が高まっている。"},{"id":4158,"en":"trigger","ja":"引き金\n反応・出来事を引き起こすきっかけ","level":6,"lnum":1,"ex":"Loud noises can trigger a stress response in some people with anxiety.","exja":"大きな音は不安を抱える一部の人々にストレス反応を引き起こすことがある。"},{"id":4159,"en":"trim","ja":"整える\n余分な部分を切り取って整える。cutより少量の調整","level":6,"lnum":1,"ex":"She trimmed the edges of the paper neatly before pasting it in her notebook.","exja":"ノートに貼る前に、彼女は紙の端をきれいに整えた。"},{"id":4160,"en":"triumph","ja":"勝利\n困難を乗り越えての大きな成功。successより劇的な勝利","level":6,"lnum":1,"ex":"Winning the championship after years of hard training was a great triumph.","exja":"何年もの厳しいトレーニングの後にチャンピオンシップを制覇したことは大きな勝利だった。"},{"id":4161,"en":"tropical","ja":"熱帯の\n熱帯地方の高温多湿な気候・植物に関係する","level":6,"lnum":1,"ex":"The garden has many tropical plants that need a warm and humid environment.","exja":"その庭には暖かく湿った環境を必要とする多くの熱帯の植物がある。"},{"id":4162,"en":"trustworthy","ja":"信頼できる\n信頼に値する誠実さを持つ。reliableより人格への信頼","level":6,"lnum":1,"ex":"A good leader should be trustworthy and honest with their team members.","exja":"良いリーダーはチームメンバーに対して信頼できる誠実な人物であるべきだ。"},{"id":4163,"en":"tumble","ja":"転倒する\n突然バランスを崩して転ぶ・滑り落ちる","level":6,"lnum":1,"ex":"The toddler tumbled off the low step but was not hurt.","exja":"幼児は低い段から転倒したが怪我はしなかった。"},{"id":4164,"en":"turbulence","ja":"乱気流\n飛行機が揺れる不安定な大気の状態。比喩的に「混乱」にも","level":6,"lnum":1,"ex":"The plane shook violently due to turbulence over the mountains.","exja":"飛行機は山の上空での乱気流のために激しく揺れた。"},{"id":4165,"en":"turning","ja":"曲がり角\n道路が方向を変える箇所","level":6,"lnum":1,"ex":"Take the first turning on the left after the traffic lights to reach the station.","exja":"駅に着くには信号の後の最初の曲がり角を左に曲がってください。"},{"id":4166,"en":"twist","ja":"ねじる\n回転させながら曲げる・予想外の展開","level":6,"lnum":1,"ex":"The story had an unexpected twist at the end that surprised all the readers.","exja":"その物語は最後に予想外のねじれがあり、読者全員を驚かせた。"},{"id":4167,"en":"typical","ja":"典型的な\nそのカテゴリーを代表するような。「typical example」で典型例","level":6,"lnum":1,"ex":"A typical school day in Japan starts at around eight in the morning.","exja":"日本の典型的な学校の1日は朝8時頃に始まる。"},{"id":4168,"en":"typically","ja":"通常は\n普通・一般的に。usuallyとほぼ同義だが特徴的な性質を強調","level":6,"lnum":1,"ex":"She typically spends her lunch break reading a book in the library.","exja":"彼女は通常、昼休みを図書館で本を読んで過ごす。"},{"id":4169,"en":"unable","ja":"できない\n能力・状況的に不可能な状態。「unable to」で〜できない","level":6,"lnum":1,"ex":"He was unable to finish the project on time because he got sick.","exja":"病気になったので、彼はプロジェクトを時間通りに終えることができなかった。"},{"id":4170,"en":"unafraid","ja":"恐れない\n危険・困難に対して怖がらない状態","level":6,"lnum":1,"ex":"She was unafraid to speak her opinion even when others disagreed.","exja":"他の人が反対意見を持っていても、彼女は自分の意見を言うことを恐れなかった。"},{"id":4171,"en":"uncertainty","ja":"不確実性\n確かでない状態・疑問や迷いがある状況","level":6,"lnum":1,"ex":"There was great uncertainty about whether the event would be held outdoors.","exja":"イベントが屋外で開催されるかどうかに多くの不確実性があった。"},{"id":4172,"en":"unclear","ja":"不明確な\nはっきりしない・理解しにくい状態","level":6,"lnum":1,"ex":"The instructions were unclear, so students asked the teacher to explain again.","exja":"指示が不明確だったので、生徒たちは先生にもう一度説明するよう求めた。"},{"id":4173,"en":"uncontrollable","ja":"制御不能な\n抑えることができない状態","level":6,"lnum":1,"ex":"The puppy's excitement was uncontrollable when it saw its owner return home.","exja":"子犬は飼い主が帰宅するのを見て興奮が制御不能になった。"},{"id":4174,"en":"uncover","ja":"明らかにする\n隠れていた事実・物を発見する。revealより積極的な発見","level":6,"lnum":1,"ex":"The investigation helped uncover the truth behind the mysterious disappearance.","exja":"調査は謎の失踪の背後にある真実を明らかにするのに役立った。"},{"id":4175,"en":"underage","ja":"未成年の\n法定年齢に達していない状態","level":6,"lnum":1,"ex":"The store refused to sell alcohol to underage customers.","exja":"その店は未成年の客にアルコールを販売することを断った。"},{"id":4176,"en":"undergo","ja":"経験する\n困難な過程・変化を経る。experienceより受け身的な含意","level":6,"lnum":1,"ex":"The old hospital is undergoing major renovations to improve its facilities.","exja":"古い病院は施設を改善するための大規模な改修を経験している。"},{"id":4177,"en":"underline","ja":"下線を引く\n重要な部分に線を引く・強調する","level":6,"lnum":1,"ex":"The teacher asked students to underline the key words in the paragraph.","exja":"先生は生徒たちに段落の中のキーワードに下線を引くよう求めた。"},{"id":4178,"en":"underneath","ja":"〜の下に\n物の直下の位置を示す。belowより密着した下を示す","level":6,"lnum":1,"ex":"She found her lost pen underneath the pile of books on her desk.","exja":"彼女は机の本の山の下に失くしたペンを見つけた。"},{"id":4179,"en":"underpants","ja":"下着\n体の下半身を覆う肌着","level":6,"lnum":1,"ex":"He packed clean underpants and socks in his bag before the camping trip.","exja":"キャンプ旅行の前に、彼は清潔な下着と靴下をバッグに詰めた。"},{"id":4180,"en":"undo","ja":"取り消す\n行った行為を元に戻す。コンピューターの「元に戻す」に対応","level":6,"lnum":1,"ex":"She pressed the undo button to restore the text she had accidentally deleted.","exja":"誤って削除したテキストを元に戻すために、彼女は取り消しボタンを押した。"},{"id":4181,"en":"undress","ja":"服を脱ぐ\n衣服を取り除く。dressの反対","level":6,"lnum":1,"ex":"He undressed quickly and changed into his sports uniform for the game.","exja":"彼は素早く服を脱いで試合のためにスポーツユニフォムに着替えた。"},{"id":4182,"en":"unemployed","ja":"失業した\n仕事を持っていない状態","level":6,"lnum":1,"ex":"After the factory closed, many workers became unemployed and struggled to find new jobs.","exja":"工場が閉鎖した後、多くの労働者が失業し新しい仕事を見つけるのに苦労した。"},{"id":4183,"en":"unemployment","ja":"失業\n雇用されていない状態・社会現象としての失業","level":6,"lnum":1,"ex":"The government introduced new programs to reduce unemployment in rural areas.","exja":"政府は農村地域の失業を減らすための新しいプログラムを導入した。"},{"id":4184,"en":"unexpected","ja":"予想外の\n予期しなかった・驚くような出来事","level":6,"lnum":1,"ex":"The unexpected snowfall in spring surprised everyone in the city.","exja":"春の予想外の降雪は市内の全員を驚かせた。"},{"id":4185,"en":"unexpectedly","ja":"予想外に\n誰も予期しなかった形で起こるさま","level":6,"lnum":1,"ex":"He arrived unexpectedly at the party and surprised all of his old friends.","exja":"彼は予想外にパーティーに到着し、古い友人全員を驚かせた。"},{"id":4186,"en":"unfairly","ja":"不公平に\n公正でない方法で・えこひいきして","level":6,"lnum":1,"ex":"Some students felt that the test results had been graded unfairly.","exja":"一部の生徒はテストの結果が不公平に採点されたと感じた。"},{"id":4187,"en":"unfit","ja":"不適切な\n目的・基準に合わない・体が弱っている","level":6,"lnum":1,"ex":"The recruits who were unfit for the physical training were sent to a different group.","exja":"体力訓練に不適切な新兵たちは別のグループに送られた。"},{"id":4188,"en":"unfold","ja":"展開する\n折りたたまれたものを広げる・出来事が徐々に明らかになる","level":6,"lnum":1,"ex":"As the story unfolded, the mystery became more and more interesting.","exja":"物語が展開するにつれて、謎はますます面白くなった。"},{"id":4189,"en":"unfortunate","ja":"不運な\n幸運に恵まれない・残念な状況","level":6,"lnum":1,"ex":"It was unfortunate that the star player was injured before the championship game.","exja":"チャンピオンシップの試合前にスター選手が怪我をしたのは不運だった。"},{"id":4190,"en":"unfriendly","ja":"不親切な\n温かみがなく冷たい態度の。friendlyの反対","level":6,"lnum":1,"ex":"The new student felt uncomfortable because some classmates were unfriendly at first.","exja":"最初のうち一部のクラスメートが不親切だったので、新しい生徒は不快に感じた。"},{"id":4191,"en":"unheard","ja":"聞かれていない\n声・主張が認識・注目されていない状態","level":6,"lnum":1,"ex":"The quiet student's ideas often went unheard in the noisy classroom debates.","exja":"静かな生徒のアイデアは騒がしいクラスのディベートでしばしば聞かれなかった。"},{"id":4192,"en":"unify","ja":"統一する\n別々のものを一つにまとめる","level":6,"lnum":1,"ex":"The new captain worked hard to unify the team after a difficult season.","exja":"新しいキャプテンは厳しいシーズンの後にチームを統一するために懸命に働いた。"},{"id":4193,"en":"uninterested","ja":"興味のない\n関心を持っていない。disinterestedは「公平な」を意味する","level":6,"lnum":1,"ex":"He seemed completely uninterested in the lecture and kept looking out the window.","exja":"彼は講義に全く興味がないようで、窓の外をずっと見ていた。"},{"id":4194,"en":"uninteresting","ja":"面白くない\n関心を引かない・退屈な","level":6,"lnum":1,"ex":"The documentary was so uninteresting that half the class fell asleep.","exja":"そのドキュメンタリーはとても面白くなく、クラスの半分が眠ってしまった。"},{"id":4195,"en":"union","ja":"組合・連合\n共通の目的のために集まった人・組織の集合体","level":6,"lnum":1,"ex":"The workers formed a union to negotiate better pay and working conditions.","exja":"労働者たちはより良い賃金と労働条件を交渉するために組合を結成した。"},{"id":4196,"en":"unite","ja":"団結する\n共通の目的のために一つになる","level":6,"lnum":1,"ex":"The disaster united the community and brought neighbors closer together.","exja":"その災害はコミュニティを団結させ、近隣の人々を互いに近づけた。"},{"id":4197,"en":"universe","ja":"宇宙\n存在するすべての物質・空間・時間の総体","level":6,"lnum":1,"ex":"Scientists are still trying to understand how the universe began.","exja":"科学者たちはまだ宇宙がどのように始まったかを理解しようとしている。"},{"id":4198,"en":"unless","ja":"〜でない限り\n条件の否定を示す接続詞。「if not」に相当","level":6,"lnum":1,"ex":"You cannot enter the museum unless you show a valid student ID card.","exja":"有効な学生証を見せない限り、博物館に入ることはできない。"},{"id":4199,"en":"unlikely","ja":"ありそうにない\n起こる可能性が低い。probableの反対","level":6,"lnum":1,"ex":"It is unlikely that school will be canceled unless there is a severe snowstorm.","exja":"激しい吹雪でない限り、学校が休校になる可能性は低い。"},{"id":4200,"en":"unpack","ja":"荷物を解く\n詰め込まれた荷物を取り出す。packの反対","level":6,"lnum":1,"ex":"After arriving at the hotel, she unpacked her suitcase and put everything away neatly.","exja":"ホテルに到着した後、彼女はスーツケースの荷物を解いてすべてをきれいに片付けた。"},{"id":4201,"en":"unpredictable","ja":"予測不可能な\n何が起こるか分からない・気まぐれな","level":6,"lnum":1,"ex":"Spring weather can be very unpredictable, so always carry an umbrella.","exja":"春の天気はとても予測不可能なので、いつも傘を持ち歩いてください。"},{"id":4202,"en":"unrelated","ja":"無関係な\nつながりや関係がない状態","level":6,"lnum":1,"ex":"The two incidents seemed similar at first, but were actually completely unrelated.","exja":"2つの事件は最初は似ているように見えたが、実際には全く無関係だった。"},{"id":4203,"en":"untidy","ja":"散らかった\n整理されていない・乱雑な状態","level":6,"lnum":1,"ex":"His room was so untidy that he could not find his homework anywhere.","exja":"彼の部屋はとても散らかっていたので、宿題がどこにも見つからなかった。"},{"id":4204,"en":"unusually","ja":"異常に\n普通とは異なって・際立って。remarkablyに近い","level":6,"lnum":1,"ex":"The winter this year was unusually warm, with very little snow.","exja":"今年の冬は雪がほとんどなく、異常に暖かかった。"},{"id":4205,"en":"unwanted","ja":"不要な\n求められていない・邪魔な存在","level":6,"lnum":1,"ex":"She donated all her unwanted clothes to a local charity organization.","exja":"彼女は不要な服をすべて地元の慈善団体に寄付した。"},{"id":4206,"en":"unwell","ja":"体調が悪い\n病気や不調を感じている状態。sickより穏やかな表現","level":6,"lnum":1,"ex":"She stayed home from school because she was feeling unwell in the morning.","exja":"朝体調が悪かったので、彼女は学校を休んで家にいた。"},{"id":4207,"en":"update","ja":"更新する\n最新の情報・状態にする","level":6,"lnum":1,"ex":"The teacher asked students to update their research notes before the next class.","exja":"先生は次の授業の前にリサーチノートを更新するよう生徒に求めた。"},{"id":4208,"en":"uplifted","ja":"気持ちが高揚した\n精神的に元気づけられた・励まされた状態","level":6,"lnum":1,"ex":"She felt uplifted after listening to the inspiring speech at the assembly.","exja":"全校集会の感動的なスピーチを聞いた後、彼女は気持ちが高揚した。"},{"id":4209,"en":"upload","ja":"アップロードする\nデータをネットワーク上に転送する。downloadの反対","level":6,"lnum":1,"ex":"Please upload your completed assignment to the school website before midnight.","exja":"深夜12時前に学校のウェブサイトに完成した課題をアップロードしてください。"},{"id":4210,"en":"upper","ja":"上の\n位置・地位が高い方の。lowerの反対","level":6,"lnum":1,"ex":"She moved to the upper floor of the library where it was quieter.","exja":"彼女はより静かな図書館の上の階に移動した。"},{"id":4211,"en":"up-to-date","ja":"最新の\n現在の状況・情報を反映した状態","level":6,"lnum":1,"ex":"It is important to keep your knowledge up-to-date by reading the latest research.","exja":"最新の研究を読んで知識を最新の状態に保つことが重要だ。"},{"id":4212,"en":"upward","ja":"上向きの\n上方向に向かう・増加傾向の","level":6,"lnum":1,"ex":"Housing prices have been moving in an upward direction for the past few years.","exja":"住宅価格はここ数年上向きの方向に動いている。"},{"id":4213,"en":"urge","ja":"衝動\n強くしたいという内側からの欲求。動詞では「強く勧める」","level":6,"lnum":1,"ex":"She felt a sudden urge to call her grandmother and check how she was doing.","exja":"彼女は突然、祖母に電話して様子を確認したいという衝動を感じた。"},{"id":4214,"en":"urgent","ja":"緊急の\nすぐに対処が必要な重要性がある状態","level":6,"lnum":1,"ex":"She sent an urgent message to her teacher asking for help with the assignment.","exja":"彼女は課題について助けを求める緊急のメッセージを先生に送った。"},{"id":4215,"en":"usage","ja":"使用法・用法\n文法の「用法」や言語の「使い方」に使う。in useとの違いに注意","level":6,"lnum":1,"ex":"Proper usage of words is important in writing.","exja":"文章を書くときは言葉の正しい使い方が大切です。"},{"id":4216,"en":"used to","ja":"〜したものだった・かつては〜だった\n過去の習慣や状態を表す。「今はもうしない」という含意がある","level":6,"lnum":1,"ex":"She used to walk to school every day when she was young.","exja":"彼女は子どもの頃、毎日歩いて学校に通っていました。"},{"id":4217,"en":"useless","ja":"役に立たない・無駄な\n強い否定。「まったく使えない」というニュアンス。pointlessに近い","level":6,"lnum":1,"ex":"It is useless to argue about something that cannot be changed.","exja":"変えられないことについて口論しても無駄です。"},{"id":4218,"en":"vacancy","ja":"空き・欠員・空室\n仕事の「求人」や宿の「空き部屋」に使う。No vacancyは「満室」","level":6,"lnum":1,"ex":"There is no vacancy at this hotel tonight.","exja":"今夜このホテルに空き部屋はありません。"},{"id":4219,"en":"vague","ja":"曖昧な・漠然とした\n明確でない状態。vaguelyの副詞形もよく使われる","level":6,"lnum":1,"ex":"His explanation was too vague to understand.","exja":"彼の説明は曖昧すぎて理解できなかった。"},{"id":4220,"en":"vain","ja":"うぬぼれた・無駄な\nin vainで「無駄に」。自分を高く評価しすぎる人にも使う","level":6,"lnum":1,"ex":"She spent hours in front of the mirror, which made her seem vain.","exja":"彼女は何時間も鏡の前で過ごし、うぬぼれた人に見えた。"},{"id":4221,"en":"vary","ja":"異なる・変化する\n場所や状況によって「差がある」ときに使う。variesと三単現に注意","level":6,"lnum":1,"ex":"The price of vegetables varies depending on the season.","exja":"野菜の値段は季節によって異なります。"},{"id":4222,"en":"vast","ja":"広大な・膨大な\n空間・数量ともに「非常に大きい」ときに使う強調語","level":6,"lnum":1,"ex":"The explorers crossed a vast desert to reach the coast.","exja":"探検家たちは海岸に辿り着くために広大な砂漠を横断した。"},{"id":4223,"en":"vegetarian","ja":"菜食主義の\n名詞形と同じスペル。ベジタリアン食・ベジタリアン向けに使う","level":6,"lnum":1,"ex":"She ordered a vegetarian pizza with mushrooms and peppers.","exja":"彼女はきのことピーマンの入ったベジタリアンピザを注文した。"},{"id":4224,"en":"vegetarian","ja":"菜食主義者・ベジタリアン\n肉・魚を食べない人。veganよりゆるやかな食習慣を指す","level":6,"lnum":1},{"id":4225,"en":"vehicle","ja":"乗り物・車両\n自動車に限らず乗り物全般。比喩的に「手段・媒体」にも使う","level":6,"lnum":1,"ex":"The police stopped the vehicle for a routine check.","exja":"警察は定期検問のためにその車両を停止させた。"},{"id":4226,"en":"vein","ja":"静脈・血管\n動脈はartery。比喩的に「傾向・気質」の意味でも使われる","level":6,"lnum":1,"ex":"The nurse had difficulty finding a vein to take blood from.","exja":"看護師は採血するための静脈を見つけるのに苦労した。"},{"id":4227,"en":"vessel","ja":"船・容器・血管\n文脈によって意味が変わる。医学では「血管」、海事では「船」","level":6,"lnum":1,"ex":"A large vessel entered the harbor early in the morning.","exja":"早朝、大きな船が港に入ってきた。"},{"id":4228,"en":"via","ja":"〜を経由して・〜を通じて\n経路や手段を示す前置詞。via emailで「メールで」","level":6,"lnum":1,"ex":"We traveled from Tokyo to Osaka via Nagoya.","exja":"私たちは名古屋を経由して東京から大阪へ旅した。"},{"id":4229,"en":"vice","ja":"副〜・代理の\nvice presidentのように複合語で使うことが多い接頭辞的形容詞","level":6,"lnum":1,"ex":"The vice president will attend the meeting in place of the president.","exja":"副社長が社長の代わりに会議に出席します。"},{"id":4230,"en":"vice president","ja":"副大統領・副社長\nviceが「副」の意味。組織の2番手の役職を指す","level":6,"lnum":1,"ex":"The vice president gave a speech at the annual company dinner.","exja":"副社長は会社の年次ディナーでスピーチをした。"},{"id":4231,"en":"video clip","ja":"動画クリップ・短い動画\nSNSでよく使う短い映像のこと。clipは「切り抜き」の意味","level":6,"lnum":1,"ex":"She posted a short video clip of her cat on social media.","exja":"彼女はSNSに猫の短い動画クリップを投稿した。"},{"id":4232,"en":"viewpoint","ja":"視点・観点\npoint of viewと同義。意見や考え方の「立場」を表す","level":6,"lnum":1,"ex":"From my viewpoint, online learning has many advantages.","exja":"私の視点では、オンライン学習には多くの利点があります。"},{"id":4233,"en":"violently","ja":"激しく・暴力的に\n強い力や感情を伴う行動に使う。violenceの副詞形","level":6,"lnum":1,"ex":"The storm hit the coast violently, damaging many buildings.","exja":"嵐は海岸を激しく襲い、多くの建物に被害を与えた。"},{"id":4234,"en":"virtual","ja":"仮想の・事実上の\nコンピューター用語としても日常語としても頻出。virtuallyは「ほぼ」","level":6,"lnum":1,"ex":"Our school held a virtual graduation ceremony last year.","exja":"私たちの学校は昨年、バーチャル卒業式を行いました。"},{"id":4235,"en":"virus","ja":"ウイルス\n医学・コンピューター両方で使う。複数形はviruses","level":6,"lnum":1,"ex":"The computer was infected by a virus that deleted important files.","exja":"そのコンピューターは重要なファイルを削除するウイルスに感染した。"},{"id":4236,"en":"visible","ja":"見える・目に見える\ninvisibleの反対。「肉眼で確認できる」状態を指す","level":6,"lnum":1,"ex":"The mountain peak was clearly visible from the town below.","exja":"山頂は麓の町からはっきりと見えた。"},{"id":4237,"en":"vision","ja":"視力・ビジョン・展望\n「目が見える能力」と「将来像・構想」の両方の意味がある","level":6,"lnum":1,"ex":"She had a clear vision of what she wanted to achieve in life.","exja":"彼女は人生で達成したいことについて明確なビジョンを持っていた。"},{"id":4238,"en":"visual","ja":"視覚の・視覚的な\n視覚に関わること全般。visual aidで「視覚教材」","level":6,"lnum":1,"ex":"The teacher used visual aids to help students understand the lesson.","exja":"先生は生徒が授業を理解しやすいように視覚教材を使った。"},{"id":4239,"en":"visually","ja":"視覚的に\n見た目・映像的な表現を修飾する副詞。visually impairedは「視覚障害」","level":6,"lnum":1,"ex":"The movie was visually stunning, with beautiful scenery throughout.","exja":"その映画は美しい風景が随所にあり、視覚的に素晴らしかった。"},{"id":4240,"en":"vivid","ja":"鮮やかな・生き生きとした\n色・記憶・描写が「はっきりして印象的」なときに使う","level":6,"lnum":1,"ex":"She had a vivid memory of the first time she met her best friend.","exja":"彼女は親友に初めて会った時の鮮明な記憶を持っていた。"},{"id":4241,"en":"vividly","ja":"鮮やかに・生き生きと\nremember vividlyで「鮮明に覚えている」。印象の強さを表す","level":6,"lnum":1,"ex":"He could still remember vividly the day he won the championship.","exja":"彼は優勝した日のことを今でも鮮明に覚えていた。"},{"id":4242,"en":"volcano","ja":"火山\n複数形はvolcanoesまたはvolcanos。active volcanoは「活火山」","level":6,"lnum":1,"ex":"The volcano erupted and sent ash high into the sky.","exja":"火山が噴火し、灰を空高く噴き上げた。"},{"id":4243,"en":"volume","ja":"音量・量・巻\n「本の巻」「量」「音量」と多義語。turn up the volumeは頻出表現","level":6,"lnum":1,"ex":"Please turn down the volume of the television a little.","exja":"テレビの音量を少し下げてください。"},{"id":4244,"en":"vote","ja":"投票する・票を投じる\nvote forで「〜に賛成票を投じる」。名詞形もvote","level":6,"lnum":1,"ex":"Everyone over eighteen has the right to vote in elections.","exja":"18歳以上のすべての人は選挙で投票する権利があります。"},{"id":4245,"en":"vowel","ja":"母音\na・i・u・e・oが英語の母音。子音はconsonant","level":6,"lnum":1,"ex":"English has five vowels: a, e, i, o, and u.","exja":"英語にはa、e、i、o、uの5つの母音があります。"},{"id":4246,"en":"voyage","ja":"航海・長旅\n主に船旅を指す。journeyより格式ばった・冒険的なニュアンス","level":6,"lnum":1,"ex":"The ship set off on a long voyage across the Pacific Ocean.","exja":"その船は太平洋を横断する長い航海に出発した。"},{"id":4247,"en":"wagon/waggon","ja":"荷馬車・ワゴン\n米英でスペルが異なる。station wagonは「ステーションワゴン車」","level":6,"lnum":1},{"id":4248,"en":"ward","ja":"病棟・区・後見\n病院の「病棟」や行政の「区」。ward offで「撃退する」の意味も","level":6,"lnum":1,"ex":"The patient was moved to a private ward after the operation.","exja":"患者は手術後、個室病棟に移された。"},{"id":4249,"en":"wardrobe","ja":"衣装箪笥・クローゼット\n洋服を収納する家具。「所有する衣服一式」の意味でも使う","level":6,"lnum":1,"ex":"She opened the wardrobe and chose a dress for the party.","exja":"彼女はワードローブを開け、パーティー用のドレスを選んだ。"},{"id":4250,"en":"warmly","ja":"温かく・親切に\n物理的な温かさにも感情的な温かさにも使う副詞","level":6,"lnum":1,"ex":"The host welcomed the guests warmly at the front door.","exja":"ホストは玄関で客を温かく迎えた。"},{"id":4251,"en":"warmth","ja":"温かさ・温情\nwarmの名詞形。気温の「暖かさ」と人柄の「温かみ」の両方","level":6,"lnum":1,"ex":"The warmth of the fire made everyone feel comfortable and relaxed.","exja":"暖炉の温かさが皆を心地よくリラックスさせた。"},{"id":4252,"en":"warn","ja":"警告する・注意する\n危険を事前に知らせる行為。warn A about Bの形が頻出","level":6,"lnum":1,"ex":"The teacher warned the students not to cheat on the exam.","exja":"先生は生徒たちに試験でカンニングしないよう警告した。"},{"id":4253,"en":"warning","ja":"警告・注意\nwarnの名詞形。without warningで「突然」「予告なく」","level":6,"lnum":1,"ex":"The weather warning told people to stay indoors during the storm.","exja":"気象警報は嵐の間は屋内にいるよう人々に伝えた。"},{"id":4254,"en":"warranty","ja":"保証・保証書\n商品の品質・修理保証。guaranteeと似るが契約的ニュアンスが強い","level":6,"lnum":1,"ex":"The new laptop comes with a one-year warranty.","exja":"その新しいノートパソコンには1年間の保証が付いています。"},{"id":4255,"en":"warrior","ja":"戦士・武士\n過去や文学的な文脈でよく使う。modern warriorは比喩的表現","level":6,"lnum":1,"ex":"The ancient warrior fought bravely to protect his village.","exja":"その古代の戦士は村を守るために勇敢に戦った。"},{"id":4256,"en":"washbowl","ja":"洗面台・洗面ボウル\n主に英国英語。米語ではwashbasinまたはsinkが一般的","level":6,"lnum":1,"ex":"She rinsed her hands in the washbowl before eating.","exja":"彼女は食事の前に洗面台で手をすすいだ。"},{"id":4257,"en":"wasteful","ja":"無駄遣いの・もったいない\n資源やお金を無駄にする様子。wasteの形容詞形","level":6,"lnum":1,"ex":"Leaving the lights on all night is wasteful of electricity.","exja":"一晩中電気をつけたままにしておくのは電力の無駄遣いです。"},{"id":4258,"en":"waterfall","ja":"滝\n水が落ちる地形。比喩的に「滝のように流れ落ちる」にも使う","level":6,"lnum":1,"ex":"They hiked through the forest and discovered a beautiful waterfall.","exja":"彼らは森を歩いて、美しい滝を発見した。"},{"id":4259,"en":"wax","ja":"ろう・ワックス\nキャンドルやつや出し剤に使う物質。wax and waneは「消長する」","level":6,"lnum":1,"ex":"He used wax to polish his shoes until they shone.","exja":"彼はワックスを使って靴が輝くまで磨いた。"},{"id":4260,"en":"wax","ja":"ワックスをかける・磨く\n表面を磨いてつやを出す行為。wax a carで「車をワックスがけする」","level":6,"lnum":1},{"id":4261,"en":"weakness","ja":"弱さ・弱点\nweakの名詞形。have a weakness forで「〜に目がない」の意味も","level":6,"lnum":1,"ex":"His greatest weakness is that he gives up too easily.","exja":"彼の最大の弱点は、あまりにも簡単にあきらめてしまうことです。"},{"id":4262,"en":"weapon","ja":"武器・兵器\n物理的な武器から比喩的な「手段・武器」まで使える","level":6,"lnum":1,"ex":"The police found a weapon hidden under the floor.","exja":"警察は床の下に隠された武器を発見した。"},{"id":4263,"en":"weather forecast","ja":"天気予報\nforecastは「予報」。weather reportとも言う。よく使う複合名詞","level":6,"lnum":1,"ex":"According to the weather forecast, it will rain tomorrow afternoon.","exja":"天気予報によると、明日の午後は雨が降るそうです。"},{"id":4264,"en":"webcam","ja":"ウェブカメラ\nインターネット接続されたカメラ。ビデオ通話に必須のデバイス","level":6,"lnum":1,"ex":"She set up her webcam before joining the online meeting.","exja":"彼女はオンライン会議に参加する前にウェブカメラをセットした。"},{"id":4265,"en":"weird","ja":"奇妙な・変わった\nstrangeより口語的でカジュアル。良い意味でも悪い意味でも使う","level":6,"lnum":1,"ex":"It was weird that no one showed up to the party.","exja":"パーティーに誰も来なかったのは奇妙なことでした。"},{"id":4266,"en":"well-dressed","ja":"身なりのよい・おしゃれな\n服装が整っている様子を表す。ハイフンに注意","level":6,"lnum":1,"ex":"The interviewer was well-dressed in a neat suit and tie.","exja":"面接官はきちんとしたスーツとネクタイで身なりがよかった。"},{"id":4267,"en":"westward/westwards","ja":"西へ・西の方向に\n方角の副詞。英米でスペルが異なることがある。eastwardと対","level":6,"lnum":1},{"id":4268,"en":"wetland","ja":"湿地・湿原\n湿った地帯の総称。環境・生態系の話題でよく登場する","level":6,"lnum":1,"ex":"Many rare birds make their home in this wetland area.","exja":"多くの希少な鳥がこの湿地帯に生息しています。"},{"id":4269,"en":"whatever","ja":"何でも・どんな〜でも\n強調・譲歩の接続詞・代名詞。Whatever happens...の形が頻出","level":6,"lnum":1,"ex":"Whatever happens, I will always be there to support you.","exja":"何が起きても、私はいつもあなたをサポートするためにいます。"},{"id":4270,"en":"whenever","ja":"〜するときはいつでも\n時の副詞。whenever you likeで「好きなときに」","level":6,"lnum":1,"ex":"You can call me whenever you need help with your homework.","exja":"宿題で助けが必要なときはいつでも電話してください。"},{"id":4271,"en":"whenever","ja":"〜するときはいつでも（接続詞）\n接続詞として節を導く。副詞用法と意味は同じだが文構造が異なる","level":6,"lnum":1},{"id":4272,"en":"wherever","ja":"どこへ行っても・どこでも\n場所の譲歩節を導く。wherever you goは定番表現","level":6,"lnum":1,"ex":"She carried her sketchbook wherever she went.","exja":"彼女はどこへ行くときもスケッチブックを持ち歩いていた。"},{"id":4273,"en":"whether","ja":"〜かどうか・〜であれ\n間接疑問文やwhether A or Bの形で使う。ifと使い分けに注意","level":6,"lnum":1,"ex":"I am not sure whether I should accept the job offer or not.","exja":"その仕事のオファーを受けるべきかどうか分かりません。"},{"id":4274,"en":"whichever","ja":"どちらでも・どれでも\n選択肢があるなかで「どれを選んでも」という意味を表す","level":6,"lnum":1,"ex":"You can choose whichever color you like for your new room.","exja":"新しい部屋の色はどれでも好きなものを選んでいいですよ。"},{"id":4275,"en":"whisper","ja":"ささやき・ひそひそ声\n動詞形も同じwhisper。静かに秘密を話すイメージ","level":6,"lnum":1,"ex":"She leaned over and whispered the answer into his ear.","exja":"彼女は身を乗り出して、彼の耳に答えをささやいた。"},{"id":4276,"en":"whistle","ja":"笛・口笛\n楽器の笛も口笛も指す。動詞「口笛を吹く」としても使う","level":6,"lnum":1,"ex":"The referee blew his whistle to signal the end of the game.","exja":"審判は試合終了を知らせるために笛を吹いた。"},{"id":4277,"en":"whoever","ja":"誰でも・誰が〜しても\n人を指す譲歩節を導く。whoever calls meで「誰が電話しても」","level":6,"lnum":1,"ex":"Whoever arrives first should wait by the entrance.","exja":"最初に到着した人は入口のそばで待つべきです。"},{"id":4278,"en":"widespread","ja":"広く普及した・広範囲の\nwide + spreadの複合語。問題や現象が広い範囲に及ぶとき","level":6,"lnum":1,"ex":"The use of smartphones has become widespread among teenagers.","exja":"スマートフォンの使用は10代の若者に広く普及しています。"},{"id":4279,"en":"wildlife","ja":"野生生物・野生動植物\n野生の動植物全体を指す集合名詞。不可算名詞に注意","level":6,"lnum":1,"ex":"The national park protects a wide variety of wildlife.","exja":"その国立公園は多種多様な野生生物を保護しています。"},{"id":4280,"en":"wildly","ja":"激しく・荒々しく・大いに\n感情・行動が「制御されずに激しい」様子。wildの副詞形","level":6,"lnum":1,"ex":"The crowd cheered wildly when the band came on stage.","exja":"バンドがステージに現れると、観客は激しく歓声を上げた。"},{"id":4281,"en":"willingness","ja":"意欲・進んでやる気持ち\nwillingの名詞形。willingness to doで「〜する意欲」","level":6,"lnum":1,"ex":"Her willingness to help others made her popular with everyone.","exja":"他者を助けようとする彼女の意欲は、周囲の人々に好かれる理由でした。"},{"id":4282,"en":"windscreen","ja":"フロントガラス\n主に英国英語。米語ではwindshield。車の前面ガラス","level":6,"lnum":1,"ex":"The wiper cleaned the rain off the windscreen quickly.","exja":"ワイパーがフロントガラスの雨を素早く拭き取った。"},{"id":4283,"en":"windsurfing","ja":"ウインドサーフィン\n帆付きのサーフボードで風を利用して水上を進むスポーツ","level":6,"lnum":1,"ex":"He took up windsurfing last summer and loves it.","exja":"彼は昨年の夏にウインドサーフィンを始め、すっかりはまっています。"},{"id":4284,"en":"wire","ja":"針金・電線・ワイヤー\n金属の細い線。電気の配線にも使う。wirelessの対義語にもなる","level":6,"lnum":1,"ex":"The electrician replaced the old wire to make the house safer.","exja":"電気工事士は家をより安全にするために古い電線を交換した。"},{"id":4285,"en":"wither","ja":"しおれる・枯れる・衰える\n植物が枯れる様子から、人・組織が衰退するときにも使う","level":6,"lnum":1,"ex":"The flowers withered quickly without enough water.","exja":"花は十分な水がなく、すぐに枯れてしまった。"},{"id":4286,"en":"witness","ja":"目撃する・証言する\n名詞「目撃者」としても使う。witness a crimeで「犯罪を目撃する」","level":6,"lnum":1,"ex":"She witnessed the accident from the window of her apartment.","exja":"彼女はアパートの窓から事故を目撃した。"},{"id":4287,"en":"wizard","ja":"魔法使いの・達人の\n形容詞として「驚くほど巧みな」。名詞の「魔法使い」は別品詞","level":6,"lnum":1,"ex":"He is a wizard at solving math problems in his head.","exja":"彼は暗算で数学の問題を解くのが驚くほど得意です。"},{"id":4288,"en":"working","ja":"稼働中の・実用的な\n現在機能している状態。working knowledgeで「実用的な知識」","level":6,"lnum":1,"ex":"The mechanic checked that all parts were in working condition.","exja":"整備士はすべての部品が稼働できる状態にあるか確認した。"},{"id":4289,"en":"workout","ja":"トレーニング・運動\ndo a workoutの形が基本。特に体を鍛える運動セッション","level":6,"lnum":1,"ex":"She does a thirty-minute workout every morning before breakfast.","exja":"彼女は毎朝朝食前に30分のトレーニングをしています。"},{"id":4290,"en":"workplace","ja":"職場・仕事場\nworkとplaceの複合語。workplace environmentで「職場環境」","level":6,"lnum":1,"ex":"A positive atmosphere in the workplace improves everyone's performance.","exja":"職場のポジティブな雰囲気は全員のパフォーマンスを向上させます。"},{"id":4291,"en":"workshop","ja":"ワークショップ・作業場\n参加型の研修会・学習会。また工作・修理をする作業部屋","level":6,"lnum":1,"ex":"The students attended a writing workshop to improve their skills.","exja":"生徒たちはスキルを向上させるためにライティングワークショップに参加した。"},{"id":4292,"en":"worn","ja":"すり切れた・使い古した\nwearの過去分詞が形容詞化。worn outはさらに「疲れ果てた」","level":6,"lnum":1,"ex":"The worn carpet in the hallway needs to be replaced soon.","exja":"廊下のすり切れたカーペットはもうすぐ交換が必要です。"},{"id":4293,"en":"worth","ja":"〜の価値がある\nbe worth doingで「〜する価値がある」。名詞「価値」としても使う","level":6,"lnum":1,"ex":"The museum is definitely worth visiting when you are in the city.","exja":"市内に来た際には、その博物館は絶対に訪れる価値があります。"},{"id":4294,"en":"worthwhile","ja":"やりがいのある・価値のある\n時間や努力をかけるだけの価値があること。worthとwhileから","level":6,"lnum":1,"ex":"Volunteering at the local shelter is a truly worthwhile experience.","exja":"地元のシェルターでボランティアをすることは、本当にやりがいのある経験です。"},{"id":4295,"en":"worthy","ja":"値する・立派な\nbe worthy ofで「〜に値する」。worthyは格式ばった表現","level":6,"lnum":1,"ex":"She worked hard to be worthy of the scholarship she received.","exja":"彼女は受け取った奨学金に値するよう、一生懸命努力した。"},{"id":4296,"en":"wound","ja":"傷・けが\n発音注意（/wuːnd/）。woundは名詞・動詞どちらも。injuryより深刻なニュアンス","level":6,"lnum":1,"ex":"The soldier received a deep wound on his arm during the battle.","exja":"兵士は戦闘中に腕に深い傷を受けた。"},{"id":4297,"en":"wrapping","ja":"包装・梱包材\nwrapの動名詞・名詞形。wrapping paperで「包装紙」","level":6,"lnum":1,"ex":"She used colorful wrapping to make the birthday gift look special.","exja":"彼女は誕生日プレゼントを特別に見せるために、カラフルな包装紙を使った。"},{"id":4298,"en":"wristwatch","ja":"腕時計\nwrist（手首）+ watch（時計）の複合語。単にwatchとも言う","level":6,"lnum":1,"ex":"His grandfather gave him a beautiful wristwatch as a graduation gift.","exja":"祖父が卒業祝いに美しい腕時計をプレゼントしてくれた。"},{"id":4299,"en":"written","ja":"書かれた・文書の\nwriteの過去分詞が形容詞化。written examで「筆記試験」","level":6,"lnum":1,"ex":"The written exam will be held next Monday morning.","exja":"筆記試験は来週の月曜日の午前中に実施されます。"},{"id":4300,"en":"yell","ja":"叫び声・怒鳴り声\n大声で叫ぶ様子。shoutより感情的・怒りのニュアンスが強い","level":6,"lnum":1,"ex":"He yelled at the top of his voice to get everyone's attention.","exja":"彼は全員の注意を引こうと、声を限りに叫んだ。"},{"id":4301,"en":"yoga","ja":"ヨガ\nインド発祥の心身鍛錬法。do yogaの形が基本。不可算名詞","level":6,"lnum":1,"ex":"She practices yoga every evening to relax after a busy day.","exja":"彼女は忙しい1日のあとリラックスするために、毎晩ヨガをしています。"},{"id":4302,"en":"abandoned","ja":"捨てられた・廃墟の\nabandon(動詞)の形容詞形。場所・人・物すべてに使える","level":7,"lnum":1,"ex":"The abandoned factory has been empty for decades.","exja":"その廃工場は何十年もの間空っぽのままだ。"},{"id":4303,"en":"abnormally","ja":"異常に・普通でなく\n基準や平均から大きく外れていることを強調する副詞","level":7,"lnum":1,"ex":"The temperature was abnormally high for this time of year.","exja":"この時期にしては異常に気温が高かった。"},{"id":4304,"en":"abolish","ja":"廃止する\n法律・制度・慣習を正式に終わらせる。比較的フォーマルな語","level":7,"lnum":1,"ex":"The government decided to abolish the old tax system.","exja":"政府は古い税制を廃止することを決めた。"},{"id":4305,"en":"aboriginal","ja":"先住民の・原住民の\nオーストラリア先住民(Aboriginal)と特定して使うことも多い","level":7,"lnum":1,"ex":"The museum has a large collection of aboriginal art from Australia.","exja":"その博物館にはオーストラリア先住民の美術品が多数収蔵されている。"},{"id":4306,"en":"abruptly","ja":"突然・不意に\n予告なく急に起こるさまを強調。abrupt(形容詞)の副詞形","level":7,"lnum":1,"ex":"The meeting ended abruptly when the fire alarm went off.","exja":"火災警報が鳴り、会議は突然終了した。"},{"id":4307,"en":"absentee","ja":"欠席者・不在者\n学校・選挙・職場など義務がある場に来ない人を指す","level":7,"lnum":1,"ex":"There were several absentees on the day of the final exam.","exja":"期末試験の当日、何人かの欠席者がいた。"},{"id":4308,"en":"absurd","ja":"ばかげた・不合理な\n理屈に合わない・笑えるほどおかしいときに使う","level":7,"lnum":1,"ex":"It is absurd to think that money can solve all problems.","exja":"お金ですべての問題が解決できると考えるのはばかげている。"},{"id":4309,"en":"abuse","ja":"虐待・乱用・悪用\n身体的・言語的・薬物的など幅広い文脈で使われる名詞","level":7,"lnum":1,"ex":"The report revealed widespread abuse of power within the organization.","exja":"その報告書は組織内での権力の乱用が広範囲に及ぶことを明らかにした。"},{"id":4310,"en":"accessibility","ja":"アクセスしやすさ・利用可能性\n障害者対応・情報へのアクセスなど社会的文脈でよく使われる","level":7,"lnum":1,"ex":"The new building was designed with accessibility for wheelchair users in mind.","exja":"新しい建物は車椅子利用者のアクセスしやすさを考慮して設計された。"},{"id":4311,"en":"accommodation","ja":"宿泊施設・住居・調整\n「宿」と「妥協・調整」の両義がある重要名詞","level":7,"lnum":1,"ex":"We need to book accommodation before the conference begins.","exja":"会議が始まる前に宿泊施設を予約する必要がある。"},{"id":4312,"en":"accordingly","ja":"それに応じて・したがって\n前述の状況に合わせて行動するときに使う接続副詞","level":7,"lnum":1,"ex":"The situation has changed, so we must act accordingly.","exja":"状況が変わったため、それに応じて行動しなければならない。"},{"id":4313,"en":"accumulate","ja":"蓄積する・積み重なる\n少しずつ増えていくプロセスを表す。財産・データ・ストレスなど","level":7,"lnum":1,"ex":"Dust tends to accumulate on shelves if they are not cleaned regularly.","exja":"棚を定期的に掃除しないと、埃が積もりやすい。"},{"id":4314,"en":"accusation","ja":"告発・非難\n誰かが悪いと主張すること。まだ有罪とは決まっていないニュアンス","level":7,"lnum":1,"ex":"He denied the accusation that he had stolen company funds.","exja":"会社の資金を横領したという告発を彼は否定した。"},{"id":4315,"en":"ache","ja":"疼く・うずく\n鈍い継続的な痛みを表す動詞。headache・stomachacheなどの動詞形","level":7,"lnum":1,"ex":"Her legs began to ache after the long hike up the mountain.","exja":"長い山道を登った後、彼女の足が痛み始めた。"},{"id":4316,"en":"achievable","ja":"達成可能な\n努力すれば届く目標に使う。feasibleより日常的な語","level":7,"lnum":1,"ex":"With careful planning, our goal is achievable within six months.","exja":"慎重に計画すれば、6ヶ月以内に目標を達成することは可能だ。"},{"id":4317,"en":"acid","ja":"酸・酸性の\n化学用語として使う名詞。acid rain(酸性雨)などの複合語も重要","level":7,"lnum":1,"ex":"The scientist added a small amount of acid to the solution to change its pH.","exja":"科学者はpHを変えるために溶液に少量の酸を加えた。"},{"id":4318,"en":"acquisition","ja":"取得・習得・買収\n語学習得(language acquisition)やM&A(企業買収)で頻出","level":7,"lnum":1,"ex":"The company's acquisition of a rival firm surprised many investors.","exja":"競合他社の買収は多くの投資家を驚かせた。"},{"id":4319,"en":"actively","ja":"積極的に・能動的に\n受け身でなく自ら動いているさまを強調する副詞","level":7,"lnum":1,"ex":"Students are encouraged to actively participate in class discussions.","exja":"生徒たちは授業の議論に積極的に参加するよう促されている。"},{"id":4320,"en":"actual","ja":"実際の・現実の\n「実際には…」と事実を強調するときに使う形容詞","level":7,"lnum":1,"ex":"The actual cost of the project was much higher than we had expected.","exja":"プロジェクトの実際のコストは予想をはるかに上回っていた。"},{"id":4321,"en":"acute","ja":"鋭い・深刻な・急性の\n痛みや問題が強烈・急激であることを表す。chronic(慢性)の対義語","level":7,"lnum":1,"ex":"She suffered from acute pain in her back after the accident.","exja":"事故の後、彼女は背中に急性の痛みを感じた。"},{"id":4322,"en":"adaptable","ja":"適応力のある\n変化に柔軟に対応できる人・システムに使う形容詞","level":7,"lnum":1,"ex":"Employees who are adaptable tend to thrive in rapidly changing work environments.","exja":"適応力のある従業員は急速に変化する職場環境でよく活躍する。"},{"id":4323,"en":"addict","ja":"依存症者・中毒者\n薬物・ゲームなど何かに強く依存している人を指す名詞","level":7,"lnum":1,"ex":"The clinic provides support for addicts trying to overcome their dependency.","exja":"そのクリニックは依存症を克服しようとしている人々を支援している。"},{"id":4324,"en":"addicted","ja":"依存している・中毒の\nbe addicted to〜の形で使う。習慣的に引き込まれているさま","level":7,"lnum":1,"ex":"He became addicted to online games and spent hours playing every night.","exja":"彼はオンラインゲームに依存するようになり、毎晩何時間もプレイするようになった。"},{"id":4325,"en":"addiction","ja":"依存症・中毒\n意思に反してやめられない状態。薬物以外(SNS依存等)にも使う","level":7,"lnum":1,"ex":"The documentary explored the causes and effects of social media addiction.","exja":"そのドキュメンタリーはSNS依存症の原因と影響を探った。"},{"id":4326,"en":"additionally","ja":"さらに・加えて\n情報を追加するときに使う接続副詞。in additionと同義","level":7,"lnum":1,"ex":"The hotel offers free breakfast; additionally, guests have access to a rooftop pool.","exja":"ホテルは無料朝食を提供しており、さらに屋上プールも利用できる。"},{"id":4327,"en":"adequate","ja":"十分な・適切な\n最低限の基準を満たしているさま。excellentほどではないニュアンス","level":7,"lnum":1,"ex":"The food supply was adequate for the three-day camping trip.","exja":"3日間のキャンプに十分な食料が用意されていた。"},{"id":4328,"en":"adequately","ja":"十分に・適切に\nadequate(形容詞)の副詞形。必要条件を満たす程度の意味","level":7,"lnum":1,"ex":"The instructions were not adequately explained, so many students were confused.","exja":"説明が十分に行われなかったため、多くの生徒が混乱した。"},{"id":4329,"en":"adjustment","ja":"調整・適応\nわずかな変化や慣れを表す名詞。make an adjustmentの形が頻出","level":7,"lnum":1,"ex":"Moving to a new country requires a period of adjustment to different customs.","exja":"新しい国への移住には、異なる習慣への適応期間が必要だ。"},{"id":4330,"en":"administrative","ja":"行政の・管理の\n政府や組織の管理・運営に関わる形容詞","level":7,"lnum":1,"ex":"The administrative staff handled all the paperwork for the event.","exja":"事務スタッフがイベントのすべての書類作業を担当した。"},{"id":4331,"en":"admirable","ja":"称賛に値する\nadmire(動詞)の形容詞形。人格・行動・業績を褒めるときに使う","level":7,"lnum":1,"ex":"Her dedication to helping others in the community is truly admirable.","exja":"地域の人々を助けることへの彼女の献身は本当に称賛に値する。"},{"id":4332,"en":"admiringly","ja":"称賛の気持ちで・感心して\n相手を高く評価するまなざしで行動するさまを表す副詞","level":7,"lnum":1,"ex":"The crowd watched admiringly as the gymnast performed a perfect routine.","exja":"体操選手が完璧な演技を披露するのを観客は称賛の眼差しで見つめた。"},{"id":4333,"en":"admittedly","ja":"確かに・認めるべきことに\n相手の主張を一部認めつつ反論するときに使う副詞","level":7,"lnum":1,"ex":"Admittedly, the plan has some flaws, but it is the best option we have.","exja":"確かにそのプランにはいくつか欠点があるが、今の私たちには最善の選択肢だ。"},{"id":4334,"en":"adopted","ja":"養子の・採用された\nadopt(動詞)の形容詞形。adopted child(養子)などでよく使う","level":7,"lnum":1,"ex":"The adopted child grew up in a loving and supportive family.","exja":"養子は愛情深く支え合う家族の中で育った。"},{"id":4335,"en":"adoption","ja":"養子縁組・採用・導入\n人・政策・技術などを「取り入れる」行為を表す名詞","level":7,"lnum":1,"ex":"The adoption of new technology helped the company increase its productivity.","exja":"新技術の導入が会社の生産性向上に役立った。"},{"id":4336,"en":"adore","ja":"崇拝する・大好きだ\nloveより強い愛情・熱狂を表す動詞。やや感情的な語","level":7,"lnum":1,"ex":"She absolutely adores her younger brother and spends every weekend with him.","exja":"彼女は弟を本当に大好きで、毎週末一緒に過ごしている。"},{"id":4337,"en":"adorn","ja":"飾る・美しく彩る\n場所・人を美しいもので装飾するときに使う。装飾的な文脈で多用","level":7,"lnum":1,"ex":"The wedding hall was adorned with thousands of white flowers.","exja":"結婚式場は無数の白い花で飾られていた。"},{"id":4338,"en":"advance","ja":"進歩・前進\n名詞として「技術の進歩・事前の」などの意味で幅広く使う","level":7,"lnum":1,"ex":"Recent advances in medical research have led to new treatments for cancer.","exja":"医学研究の最近の進歩は、がんの新しい治療法につながった。"},{"id":4339,"en":"advancement","ja":"前進・昇進・発展\nadvanceの名詞形。技術革新やキャリアアップの文脈で頻出","level":7,"lnum":1,"ex":"The advancement of artificial intelligence is changing the way we live and work.","exja":"人工知能の発展は私たちの生活や働き方を変えつつある。"},{"id":4340,"en":"advent","ja":"出現・到来\n重要な人物・時代・出来事の始まりを告げるやや格式のある語","level":7,"lnum":1,"ex":"The advent of smartphones revolutionized the way people communicate.","exja":"スマートフォンの登場は人々のコミュニケーション方法を一変させた。"},{"id":4341,"en":"adventurous","ja":"冒険好きの・大胆な\nリスクを楽しめる積極的な人・活動に使う形容詞","level":7,"lnum":1,"ex":"He is an adventurous traveler who prefers exploring remote areas over luxury resorts.","exja":"彼は高級リゾートよりも未開の地を探索することを好む冒険好きの旅行者だ。"},{"id":4342,"en":"adverse","ja":"不利な・有害な\n条件・影響・反応が好ましくないときに使う。フォーマルな語","level":7,"lnum":1,"ex":"The cold weather had an adverse effect on the crops this season.","exja":"今シーズンは寒い気候が作物に悪影響を与えた。"},{"id":4343,"en":"adversely","ja":"不利に・悪影響を与えて\nadverse(形容詞)の副詞形。affect adversely(悪影響を与える)が頻出","level":7,"lnum":1,"ex":"Stress can adversely affect both physical and mental health.","exja":"ストレスは身体的・精神的な健康の両方に悪影響を与えることがある。"},{"id":4344,"en":"adversity","ja":"逆境・苦難\n困難な状況に立ち向かうときに使う名詞。overcome adversityが典型表現","level":7,"lnum":1,"ex":"She showed incredible strength in the face of adversity.","exja":"彼女は逆境に直面しても驚くべき強さを示した。"},{"id":4345,"en":"affectionate","ja":"愛情深い・優しい\n家族・友人・ペットへの温かい感情を表す形容詞","level":7,"lnum":1,"ex":"The dog is very affectionate and loves being petted by everyone.","exja":"その犬はとても愛情深く、みんなに撫でてもらうのが大好きだ。"},{"id":4346,"en":"affectionately","ja":"愛情を込めて・優しく\naffectionate(形容詞)の副詞形。手紙の結びにも使われる","level":7,"lnum":1,"ex":"She affectionately called her grandmother \"Nana\" since childhood.","exja":"彼女は幼い頃からおばあちゃんを愛情を込めて「ナナ」と呼んでいた。"},{"id":4347,"en":"affordable","ja":"手頃な価格の\n収入に見合う価格であることを表す。affordable housingなどで頻出","level":7,"lnum":1,"ex":"The new housing project aims to provide affordable homes for low-income families.","exja":"新しい住宅プロジェクトは低所得家族に手頃な価格の家を提供することを目指している。"},{"id":4348,"en":"ageless","ja":"年齢を感じさせない・永遠の\n時代・年齢に左右されない魅力や価値を表す形容詞","level":7,"lnum":1,"ex":"Her ageless beauty continued to inspire younger generations.","exja":"彼女の年齢を感じさせない美しさは若い世代を刺激し続けた。"},{"id":4349,"en":"aggressively","ja":"攻撃的に・積極的に\n否定的な攻撃性と肯定的な積極性の両方に使われる副詞","level":7,"lnum":1,"ex":"The company aggressively expanded its market share by lowering prices.","exja":"その会社は価格を下げることで積極的にシェア拡大を図った。"},{"id":4350,"en":"agonize/agonise","ja":"苦悩する・もがき苦しむ\nagony(苦悩)の動詞形。agonize over〜(〜に苦悩する)の形が多い","level":7,"lnum":1,"ex":"She agonized over whether to accept the job offer abroad.","exja":"彼女は海外の仕事の申し出を受け入れるかどうか悩み苦しんだ。"},{"id":4351,"en":"agony","ja":"激しい苦しみ・苦悩\n身体的・精神的な激痛を表す。in agonyの形で頻出","level":7,"lnum":1,"ex":"He was in agony after twisting his ankle during the race.","exja":"レース中に足首を捻挫し、彼は激しい苦しみの中にあった。"},{"id":4352,"en":"aim","ja":"狙う・目指す\n目標に向かって行動するときの動詞。aim at/for〜の形が基本","level":7,"lnum":1,"ex":"The organization aims to reduce poverty in rural areas by 2030.","exja":"その組織は2030年までに農村地域の貧困を減らすことを目指している。"},{"id":4353,"en":"aircraft","ja":"航空機・飛行機\n飛行機・ヘリコプター等を総称する集合名詞。複数形も同形","level":7,"lnum":1,"ex":"The aircraft landed safely despite the strong crosswind.","exja":"強い横風にもかかわらず、航空機は無事に着陸した。"},{"id":4354,"en":"aircrew","ja":"航空機乗組員\nパイロット・客室乗務員を含む航空機スタッフ全体を指す語","level":7,"lnum":1,"ex":"The aircrew prepared for the long international flight by reviewing safety procedures.","exja":"航空機乗組員は安全手順を確認して長距離国際フライトに備えた。"},{"id":4355,"en":"alcoholic","ja":"アルコール依存症の人\n形容詞でも使うが名詞として「依存症者」を指すことが多い","level":7,"lnum":1,"ex":"The support group was open to anyone who identified as an alcoholic.","exja":"そのサポートグループはアルコール依存症だと自認する人なら誰でも参加できた。"},{"id":4356,"en":"alcoholism","ja":"アルコール依存症\nアルコール依存の状態・疾患を表す医学・社会的用語","level":7,"lnum":1,"ex":"Alcoholism is a serious disease that requires medical treatment and community support.","exja":"アルコール依存症は医療的治療と地域社会の支援を必要とする深刻な病気だ。"},{"id":4357,"en":"alert","ja":"警告する・注意させる\n危険を知らせ注意を促す動詞。alert A to B(AにBを警告する)が頻出","level":7,"lnum":1,"ex":"The warning system was designed to alert residents when flood levels rise dangerously.","exja":"警報システムは洪水が危険なレベルに達した際に住民に警告するよう設計されていた。"},{"id":4358,"en":"allegation","ja":"申し立て・疑惑\n証明前の「〜と言われている」主張。法律・報道で多用","level":7,"lnum":1,"ex":"The politician denied all allegations of corruption.","exja":"その政治家は汚職に関するすべての疑惑を否定した。"},{"id":4359,"en":"alliance","ja":"同盟・連合\n国家・組織・政党などが共通目的で結ぶ協力関係を表す名詞","level":7,"lnum":1,"ex":"The two countries formed a military alliance to protect their shared borders.","exja":"両国は共有する国境を守るために軍事同盟を結んだ。"},{"id":4360,"en":"ally","ja":"同盟国・味方\n共通の目的で協力する国・人。allianceより具体的な個体を指す","level":7,"lnum":1,"ex":"During the crisis, Japan worked closely with its allies to coordinate a response.","exja":"危機の際、日本は対応策を調整するために同盟国と緊密に連携した。"},{"id":4361,"en":"alongside","ja":"〜と並んで・〜のそばに\n物理的な並置と比喩的な「〜とともに」の両方に使う前置詞","level":7,"lnum":1,"ex":"The small bookstore has survived alongside the large online retailers.","exja":"その小さな書店は大手オンライン小売業者と並びながら生き残ってきた。"},{"id":4362,"en":"alphabetical","ja":"アルファベット順の\n辞書・リスト等の並び方を説明するときに使う形容詞","level":7,"lnum":1,"ex":"The names on the list are arranged in alphabetical order.","exja":"リストの名前はアルファベット順に並んでいる。"},{"id":4363,"en":"altar","ja":"祭壇\n宗教的儀式を行う台。教会・神殿などで使われる語","level":7,"lnum":1,"ex":"The couple exchanged vows at the altar in front of their family and friends.","exja":"2人は家族と友人の前で祭壇で誓いを交わした。"},{"id":4364,"en":"alter","ja":"変える・変わる\nchangeより限定的な「部分的に変える」ニュアンスが強い動詞","level":7,"lnum":1,"ex":"The tailor offered to alter the jacket so it would fit perfectly.","exja":"仕立て屋はジャケットをぴったりに直すことを申し出た。"},{"id":4365,"en":"alternate","ja":"交互にする・代わる代わる\n二つのものが入れ替わるパターンを表す動詞","level":7,"lnum":1,"ex":"The two teachers alternate teaching duties each week.","exja":"2人の教師は毎週交互に授業を担当している。"},{"id":4366,"en":"alternatively","ja":"あるいは・別の方法として\n別の選択肢を提示するときに使う接続副詞","level":7,"lnum":1,"ex":"You can take the train to the city, or alternatively, you can drive.","exja":"市内へは電車で行くこともできるし、あるいは車で行くこともできる。"},{"id":4367,"en":"altitude","ja":"高度・標高\n海面や地面からの高さを表す。at high altitude(高地で)が頻出","level":7,"lnum":1,"ex":"Climbers must acclimatize to the high altitude before reaching the summit.","exja":"登山者は頂上に到達する前に高地に順応しなければならない。"},{"id":4368,"en":"aluminum/aluminium","ja":"アルミニウム\n軽い金属元素。米英でつづりが異なる典型語","level":7,"lnum":1,"ex":"Aluminum is widely used in the aerospace industry because of its light weight.","exja":"アルミニウムはその軽さから航空宇宙産業で広く使われている。"},{"id":4369,"en":"amaze","ja":"驚かせる・びっくりさせる\n非常に驚かせるときに使う動詞。be amazed at〜が頻出","level":7,"lnum":1,"ex":"The young pianist's performance amazed the entire audience.","exja":"若いピアニストの演奏は聴衆全員を驚かせた。"},{"id":4370,"en":"amazement","ja":"驚き・驚嘆\nin amazement(驚いて)の形でよく使う。positive な驚きのニュアンス","level":7,"lnum":1,"ex":"She stared in amazement at the size of the ancient temple.","exja":"彼女は古代の神殿の大きさに驚きの目を向けた。"},{"id":4371,"en":"amazingly","ja":"驚くほど・信じられないほど\n期待以上の結果に驚くさまを強調する副詞","level":7,"lnum":1,"ex":"Amazingly, the marathon runner finished the race despite injuring his knee midway.","exja":"驚くほどに、そのマラソン選手は途中で膝を怪我したにもかかわらずレースを完走した。"},{"id":4372,"en":"ambiguity","ja":"曖昧さ・多義性\n二通り以上に解釈できる不明瞭さを表す名詞","level":7,"lnum":1,"ex":"The legal contract contained some ambiguity that needed to be clarified.","exja":"その法律契約書には明確にする必要のある曖昧さがいくつか含まれていた。"},{"id":4373,"en":"ambiguous","ja":"曖昧な・多義的な\n意味が明確でなく解釈が分かれるときに使う形容詞","level":7,"lnum":1,"ex":"The politician gave an ambiguous answer that satisfied no one.","exja":"その政治家は誰も満足させない曖昧な回答をした。"},{"id":4374,"en":"ammonia","ja":"アンモニア\n刺激臭のある化学物質。工業・農業・清掃で使われる","level":7,"lnum":1,"ex":"The smell of ammonia in the cleaning products irritated her eyes.","exja":"清掃用品に含まれるアンモニアの臭いが彼女の目を刺激した。"},{"id":4375,"en":"amongst","ja":"〜の中で・〜の間で\namongのやや格式ある表現。英国英語で多く使われる","level":7,"lnum":1,"ex":"He was well known amongst his classmates for his sense of humor.","exja":"彼はユーモアのセンスでクラスメートの間でよく知られていた。"},{"id":4376,"en":"ample","ja":"十分な・豊富な\n必要量を十分に上回る量があることを表す形容詞","level":7,"lnum":1,"ex":"There is ample evidence to suggest that regular exercise improves mental health.","exja":"定期的な運動が精神的な健康を改善することを示す十分な証拠がある。"},{"id":4377,"en":"amplifier","ja":"アンプ・増幅器\n音声・電気信号を増幅する装置。音楽や電子工学の文脈で使う","level":7,"lnum":1,"ex":"The guitarist connected his instrument to a powerful amplifier before the concert.","exja":"ギタリストはコンサートの前に強力なアンプに楽器を接続した。"},{"id":4378,"en":"amplify","ja":"増幅する・拡大する\n音・信号・効果を大きくすることを表す動詞","level":7,"lnum":1,"ex":"The microphone was used to amplify the speaker's voice so everyone could hear clearly.","exja":"スピーカーの声を全員がはっきり聞こえるようにするためにマイクが使われた。"},{"id":4379,"en":"amuse","ja":"楽しませる・おかしがらせる\n軽く楽しませることを表す。be amused by〜(〜がおかしい)が頻出","level":7,"lnum":1,"ex":"The comedian's jokes never failed to amuse the crowd.","exja":"そのコメディアンのジョークは常に観衆を楽しませた。"},{"id":4380,"en":"analogy","ja":"類比・たとえ\n二つのものを比較して説明するときに使う名詞。by analogy(類比で)","level":7,"lnum":1,"ex":"The teacher used the analogy of a computer to explain how the human brain works.","exja":"先生は人間の脳の仕組みを説明するためにコンピューターのたとえを使った。"},{"id":4381,"en":"analyst","ja":"分析家・アナリスト\nデータ・市場・政策などを専門的に分析する人を指す名詞","level":7,"lnum":1,"ex":"The financial analyst predicted that the stock price would rise next quarter.","exja":"金融アナリストは来四半期に株価が上がると予測した。"},{"id":4382,"en":"anchor","ja":"錨・アンカー\n船を固定する装置。比喩的に「よりどころ」の意味でも使う名詞","level":7,"lnum":1,"ex":"The anchor was dropped to prevent the boat from drifting during the storm.","exja":"嵐の間、船が流されないように錨が下ろされた。"},{"id":4383,"en":"anchorage","ja":"停泊地・停泊料\n船が錨を下ろして停泊できる場所または料金を表す名詞","level":7,"lnum":1,"ex":"The small bay provided a safe anchorage for the fishing boats.","exja":"小さな湾は漁船の安全な停泊地となっていた。"},{"id":4384,"en":"anchorman","ja":"ニュースキャスター(男性)\nテレビニュースを仕切る男性アナウンサー。性中立はanchorperson","level":7,"lnum":1,"ex":"The anchorman delivered the evening news with his characteristic calm voice.","exja":"ニュースキャスターは特有の落ち着いた声で夕方のニュースを伝えた。"},{"id":4385,"en":"anchorperson","ja":"ニュースキャスター\n性別を問わないニュース番組の進行役を指す中立的な語","level":7,"lnum":1,"ex":"The anchorperson introduced the panel of experts who would debate the issue.","exja":"ニュースキャスターは問題を議論する専門家のパネルを紹介した。"},{"id":4386,"en":"anguish","ja":"苦悩・激しい悲しみ\n精神的な激しい痛みや苦しみを表す。agonyより感情的なニュアンス","level":7,"lnum":1,"ex":"The mother's anguish was clear when she heard about her son's accident.","exja":"息子の事故を聞いたとき、母親の苦悩は明らかだった。"},{"id":4387,"en":"animate","ja":"生き生きとさせる・アニメ化する\n命や活気を与えることを表す動詞。animated(活気ある)の原形","level":7,"lnum":1,"ex":"The coach tried to animate the team with an inspiring speech before the match.","exja":"コーチは試合前に鼓舞するスピーチでチームを活気づけようとした。"},{"id":4388,"en":"anonymous","ja":"匿名の・無名の\n名前が明かされていない人・文書に使う形容詞","level":7,"lnum":1,"ex":"The donation was made by an anonymous supporter of the charity.","exja":"その寄付は慈善団体の匿名の支援者によって行われた。"},{"id":4389,"en":"antiaircraft","ja":"対空の\n航空機を攻撃・防衛するための装備・システムに使う形容詞","level":7,"lnum":1,"ex":"The military deployed antiaircraft missiles along the border.","exja":"軍は国境沿いに対空ミサイルを配備した。"},{"id":4390,"en":"antibacterial","ja":"抗菌の・殺菌の\n細菌の増殖を抑える性質を持つ製品・物質に使う形容詞","level":7,"lnum":1,"ex":"She used an antibacterial soap to wash her hands before cooking.","exja":"彼女は料理の前に手を洗うために抗菌石鹸を使った。"},{"id":4391,"en":"anticancer","ja":"抗がんの\nがんを抑制・治療するための薬・治療法に使われる名詞・形容詞","level":7,"lnum":1,"ex":"Researchers are developing a new anticancer drug that targets specific tumor cells.","exja":"研究者たちは特定のがん細胞を標的とする新しい抗がん剤を開発している。"},{"id":4392,"en":"anticipate","ja":"予測する・期待する\n事前に予想して準備するときに使う動詞。expect より積極的なニュアンス","level":7,"lnum":1,"ex":"We did not anticipate the level of difficulty involved in the project.","exja":"私たちはプロジェクトに関わる困難のレベルを予測していなかった。"},{"id":4393,"en":"anticipation","ja":"予期・期待\nin anticipation of〜(〜を見越して)の形で頻出するフォーマルな名詞","level":7,"lnum":1,"ex":"The children waited in anticipation of the presents they would receive.","exja":"子供たちはもらえるプレゼントを楽しみに待っていた。"},{"id":4394,"en":"antipollution","ja":"反公害の・環境汚染対策の\n環境汚染を防ぐための取り組みや規制に使われる形容詞的名詞","level":7,"lnum":1,"ex":"The city introduced new antipollution regulations to improve air quality.","exja":"市は大気質を改善するための新しい環境汚染対策規制を導入した。"},{"id":4395,"en":"antique","ja":"骨董の・古い・骨董品\n100年以上前の価値ある品や様式に使う形容詞・名詞","level":7,"lnum":1,"ex":"She found a beautiful antique vase at the market and bought it immediately.","exja":"彼女は市場で美しい骨董の花瓶を見つけ、すぐに購入した。"},{"id":4396,"en":"antistatic","ja":"帯電防止の\n静電気の蓄積を防ぐ素材・製品に使われる形容詞","level":7,"lnum":1,"ex":"The technician used an antistatic wristband to prevent damage to the computer parts.","exja":"技術者はコンピューター部品の損傷を防ぐために帯電防止リストバンドを使った。"},{"id":4397,"en":"antivirus","ja":"ウイルス対策の・ウイルス対策ソフト\nコンピューターウイルスを検出・除去するソフトウェアや機能を指す","level":7,"lnum":1,"ex":"It is important to keep your antivirus software updated to protect your computer.","exja":"コンピューターを守るためにウイルス対策ソフトを最新の状態に保つことが重要だ。"},{"id":4398,"en":"apostrophe","ja":"アポストロフィ\nit'sやdon'tなど省略・所有格を示す記号(')のこと","level":7,"lnum":1,"ex":"Students often make mistakes when placing an apostrophe in possessive nouns.","exja":"生徒は所有格の名詞にアポストロフィを置くとき、よく間違いを犯す。"},{"id":4399,"en":"appeal","ja":"訴える・魅力を持つ\nappeal to〜(〜に訴える/〜の心を引く)の形で幅広く使う動詞","level":7,"lnum":1,"ex":"The charity campaign appealed to people's sense of compassion.","exja":"その慈善キャンペーンは人々の思いやりの心に訴えかけた。"},{"id":4400,"en":"applicant","ja":"応募者・申請者\n仕事・大学・プログラムなどに申し込んでいる人を指す名詞","level":7,"lnum":1,"ex":"Over three hundred applicants applied for the single job opening.","exja":"一つの求人に300人以上の応募者が応募した。"},{"id":4401,"en":"appreciative","ja":"感謝している・鑑賞力のある\nappreciate(感謝する)の形容詞形。be appreciative of〜が基本形","level":7,"lnum":1,"ex":"She was very appreciative of all the help she received from her colleagues.","exja":"彼女は同僚からのすべての助けに非常に感謝していた。"},{"id":4402,"en":"appropriately","ja":"適切に・ふさわしく\n状況に合った方法で行動するさまを表す副詞","level":7,"lnum":1,"ex":"Students are expected to dress appropriately for the school ceremony.","exja":"生徒は学校の式典に適切な服装をすることが求められている。"},{"id":4403,"en":"approximate","ja":"おおよその・近似の\n正確でなく大まかな数値・量を表す。approximately(副詞)と合わせて覚える","level":7,"lnum":1,"ex":"The approximate number of attendees at the festival was ten thousand.","exja":"フェスティバルの参加者のおおよその人数は一万人だった。"},{"id":4404,"en":"arch","ja":"アーチ・弓形\n建築の弓型構造物を表す名詞。arch enemy(宿敵)などの複合語にも使われる","level":7,"lnum":1,"ex":"The old stone arch at the entrance to the village has stood for centuries.","exja":"村の入り口にある古い石のアーチは何世紀にもわたって立ち続けている。"},{"id":4405,"en":"archaeologist/archeologist","ja":"考古学者\n遺跡や遺物を研究する専門家。米英でつづりが異なる","level":7,"lnum":1,"ex":"The archaeologist carefully uncovered ancient pottery buried in the ground.","exja":"考古学者は地中に埋まった古代の陶器を丁寧に発掘した。"},{"id":4406,"en":"arctic","ja":"北極の・極寒の\n北極地方または非常に寒い状態を表す形容詞","level":7,"lnum":1,"ex":"The expedition team faced harsh arctic conditions during their journey to the North Pole.","exja":"探検隊は北極点への旅の途中で過酷な北極の状況に直面した。"},{"id":4407,"en":"arena","ja":"競技場・舞台・分野\nスポーツ会場のほか「政治の場・活躍の舞台」比喩的にも使う","level":7,"lnum":1,"ex":"The concert was held in a large indoor arena that could seat twenty thousand people.","exja":"コンサートは2万人収容できる大きな屋内競技場で開催された。"},{"id":4408,"en":"aristocracy","ja":"貴族階級・上流社会\n社会的上位層を指す。aristocrat(貴族)と合わせて覚えたい","level":7,"lnum":1,"ex":"In the nineteenth century, the aristocracy held most of the land in England.","exja":"19世紀、イングランドでは貴族階級が土地のほとんどを所有していた。"},{"id":4409,"en":"armful","ja":"両腕いっぱい\n両腕で抱えられる量を表す名詞。an armful of〜の形で使う","level":7,"lnum":1,"ex":"She carried an armful of books from the library to her study.","exja":"彼女は図書館から勉強部屋へ両腕いっぱいの本を運んだ。"},{"id":4410,"en":"arouse","ja":"呼び起こす・刺激する\n感情・興味・疑惑などを引き起こすときに使う動詞","level":7,"lnum":1,"ex":"The documentary aroused public interest in environmental issues.","exja":"そのドキュメンタリーは環境問題への市民の関心を呼び起こした。"},{"id":4411,"en":"arrogant","ja":"傲慢な・横柄な\n自分が他者より優れていると過信して見下す態度を表す形容詞","level":7,"lnum":1,"ex":"His arrogant attitude made it difficult for others to work with him.","exja":"彼の傲慢な態度は他の人が一緒に働くのを難しくした。"},{"id":4412,"en":"artery","ja":"動脈・幹線道路\n血管の動脈を指す医学用語。比喩的に「主要道路」にも使う","level":7,"lnum":1,"ex":"Plaque buildup in the arteries can lead to serious heart problems.","exja":"動脈内のプラーク蓄積は深刻な心臓問題につながる可能性がある。"},{"id":4413,"en":"articulate","ja":"明確に話す・はっきり表現する\n考えを言葉で明確に表現する動詞。形容詞では「言葉が達者な」の意","level":7,"lnum":1,"ex":"She is very articulate and can explain complex ideas in simple terms.","exja":"彼女は言葉がとても達者で、複雑なアイデアを分かりやすく説明できる。"},{"id":4414,"en":"artificially","ja":"人工的に・不自然に\n自然でなく人の手で作られた・操作されたさまを表す副詞","level":7,"lnum":1,"ex":"The flavors in the candy were artificially created in a laboratory.","exja":"そのキャンディーのフレーバーは実験室で人工的に作られた。"},{"id":4415,"en":"artistry","ja":"芸術的技巧・職人の技\n高い芸術的技術や才能を表す抽象名詞","level":7,"lnum":1,"ex":"The chef's artistry was evident in the beautifully presented dishes.","exja":"シェフの芸術的技巧は美しく盛り付けられた料理に明らかだった。"},{"id":4416,"en":"ash","ja":"灰・遺灰\n燃えた後に残る灰。volcanic ash(火山灰)や cremation ash(遺灰)など","level":7,"lnum":1,"ex":"Volcanic ash covered the entire town after the eruption.","exja":"噴火後、火山灰が町全体を覆った。"},{"id":4417,"en":"aspiration","ja":"志望・夢・抱負\n高い目標への強い望みを表す名詞。aspirations(複数形)でよく使う","level":7,"lnum":1,"ex":"Her lifelong aspiration was to become a concert pianist.","exja":"生涯の夢はコンサートピアニストになることだった。"},{"id":4418,"en":"aspire","ja":"熱望する・志す\naspire to〜(〜を目指す)の形で使う。目標が高いニュアンスを含む","level":7,"lnum":1,"ex":"He aspires to become a doctor and help people in his community.","exja":"彼は医師になって地域の人々を助けることを志している。"},{"id":4419,"en":"assault","ja":"暴行・攻撃\n身体的攻撃を指す法律・軍事用語としての名詞","level":7,"lnum":1,"ex":"The soldier was charged with assault after attacking a fellow officer.","exja":"その兵士は同僚の士官を攻撃したとして暴行罪で起訴された。"},{"id":4420,"en":"assemble","ja":"集める・組み立てる\n人を集合させる・部品を組み立てるの両方に使う動詞","level":7,"lnum":1,"ex":"The workers assembled the car engine piece by piece on the factory floor.","exja":"工場の床で作業員はエンジンを一つ一つ組み立てた。"},{"id":4421,"en":"assert","ja":"主張する・断言する\n自信を持って主張・宣言するときに使う。assert oneself(自己主張する)も頻出","level":7,"lnum":1,"ex":"The union leader asserted that the workers deserved better wages and conditions.","exja":"労働組合のリーダーは労働者がより良い賃金と条件に値すると主張した。"},{"id":4422,"en":"assess","ja":"評価する・査定する\n状況・価値・能力を客観的に判断する動詞。試験でもよく問われる","level":7,"lnum":1,"ex":"The teacher assessed the students' performance using a variety of methods.","exja":"教師はさまざまな方法を使って生徒のパフォーマンスを評価した。"},{"id":4423,"en":"assessment","ja":"評価・査定・アセスメント\nassessの名詞形。学校の成績評価から医療診断まで幅広く使われる","level":7,"lnum":1,"ex":"The final assessment will account for fifty percent of the total grade.","exja":"最終評価は総成績の50パーセントを占める。"},{"id":4424,"en":"assumption","ja":"仮定・思い込み\n証拠なく正しいと思い込んでいること。make an assumption(仮定する)が頻出","level":7,"lnum":1,"ex":"His assumption that everyone enjoyed team sports turned out to be wrong.","exja":"全員がチームスポーツを楽しんでいるという彼の思い込みは間違っていたことが分かった。"},{"id":4425,"en":"assurance","ja":"保証・確信・安心感\n確かめること・安心させること。insurance(保険)との混同に注意","level":7,"lnum":1,"ex":"The manager gave her assurance that the project would be completed on time.","exja":"マネージャーはプロジェクトが期日通りに完了するという保証を彼女に与えた。"},{"id":4426,"en":"assure","ja":"保証する・確信させる\nassure A that〜(AにSVを保証する)の形で使う動詞","level":7,"lnum":1,"ex":"The doctor assured the patient that the operation was completely safe.","exja":"医師は患者に手術が完全に安全であることを保証した。"},{"id":4427,"en":"astonish","ja":"びっくり仰天させる\namazeより驚きの程度が強いときに使う動詞","level":7,"lnum":1,"ex":"The magician's tricks continued to astonish the audience throughout the show.","exja":"マジシャンのトリックはショーの間中、観衆を驚かせ続けた。"},{"id":4428,"en":"astonished","ja":"驚愕した\nbe astonished at/by〜の形で使う。非常に強い驚きを表す形容詞","level":7,"lnum":1,"ex":"We were astonished by the amount of damage caused by the storm.","exja":"私たちは嵐によって引き起こされた被害の大きさに驚愕した。"},{"id":4429,"en":"astonishing","ja":"驚くべき・衝撃的な\n事実・結果が信じがたいほど驚かせる場合に使う形容詞","level":7,"lnum":1,"ex":"It is astonishing that she memorized the entire script in just two days.","exja":"彼女がたった2日間で台本全体を暗記したのは驚くべきことだ。"},{"id":4430,"en":"astonishment","ja":"驚愕・仰天\nto one's astonishment(驚いたことに)の形でよく使う名詞","level":7,"lnum":1,"ex":"He looked on in astonishment as the building crumbled before his eyes.","exja":"建物が目の前で崩れ落ちるのを、彼は驚愕して見つめた。"},{"id":4431,"en":"astronomy","ja":"天文学\n宇宙・星・天体を研究する学問。astrology(占星術)と混同しないこと","level":7,"lnum":1,"ex":"She developed a passion for astronomy after seeing her first solar eclipse.","exja":"初めての皆既日食を見て以来、彼女は天文学への情熱を持つようになった。"},{"id":4432,"en":"athletics","ja":"陸上競技・スポーツ競技\n陸上種目の総称。英国では陸上競技、米国ではスポーツ全般を指す","level":7,"lnum":1,"ex":"The school's athletics program has produced several national champions.","exja":"その学校の陸上競技プログラムは複数の全国チャンピオンを生み出している。"},{"id":4433,"en":"attached","ja":"くっついた・添付された・愛着を持った\nbe attached to〜で「〜に愛着がある」の意味も重要","level":7,"lnum":1,"ex":"She has always been deeply attached to her childhood home.","exja":"彼女は幼少期の家に常に強い愛着を持っていた。"},{"id":4434,"en":"attainable","ja":"達成できる・到達可能な\n努力や努力次第で手が届く目標・結果に使う形容詞","level":7,"lnum":1,"ex":"With consistent effort, fluency in a foreign language is attainable within a few years.","exja":"継続的な努力があれば、外国語の流暢さは数年以内に達成できる。"},{"id":4435,"en":"attainment","ja":"達成・到達・学力\n目標を達成することや達成した水準を表す名詞","level":7,"lnum":1,"ex":"The attainment of educational qualifications opened many doors for her career.","exja":"学歴の取得が彼女のキャリアにとって多くの扉を開いた。"},{"id":4436,"en":"attendance","ja":"出席・参加・来場者数\nat〜の出席状況や来場者数を表す名詞。take attendance(出席を取る)","level":7,"lnum":1,"ex":"Attendance at the weekly team meetings is required for all staff members.","exja":"毎週のチームミーティングへの出席は全スタッフに求められている。"},{"id":4437,"en":"attentive","ja":"注意深い・気遣いのある\n細かい点に気を配る・相手の気持ちに敏感な形容詞","level":7,"lnum":1,"ex":"A good nurse is attentive to the needs of every patient in their care.","exja":"良い看護師は担当するすべての患者のニーズに気を配っている。"},{"id":4438,"en":"attentively","ja":"注意深く・熱心に\nattentive(形容詞)の副詞形。listen attentively(熱心に聞く)が頻出","level":7,"lnum":1,"ex":"The students listened attentively to the guest speaker's presentation.","exja":"生徒たちはゲストスピーカーのプレゼンテーションを注意深く聞いた。"},{"id":4439,"en":"attractiveness","ja":"魅力・引力\nattractive(形容詞)の名詞形。外見や性質の魅力を表す","level":7,"lnum":1,"ex":"The attractiveness of the job offer was hard to ignore.","exja":"その求人の魅力は無視しがたかった。"},{"id":4440,"en":"attribute","ja":"特性・属性\n名詞として人・物が本来持つ性質・特徴を表す","level":7,"lnum":1,"ex":"Her success was widely attributed to her hard work and determination.","exja":"彼女の成功は努力と決意のおかげだと広く言われていた。"},{"id":4441,"en":"attribute","ja":"〜のせいにする・帰属させる\nattribute A to B(AをBのせいにする)の形が最重要の動詞用法","level":7,"lnum":1,"ex":"She attributed her success to hard work and determination.","exja":"彼女は自分の成功を努力と決意のおかげだとした。"},{"id":4442,"en":"atypical","ja":"典型的でない・異常な\n典型例から外れていることを表す。typicalの反意語","level":7,"lnum":1,"ex":"The patient displayed atypical symptoms that made diagnosis difficult.","exja":"その患者は診断を困難にする典型的でない症状を示した。"},{"id":4443,"en":"aubergine","ja":"ナス\n主に英国英語で使う。米国英語ではeggplant。色の名前としても使われる","level":7,"lnum":1,"ex":"The recipe called for a large aubergine, sliced thinly and grilled.","exja":"レシピには大きなナスを薄切りにして焼くよう書いてあった。"},{"id":4444,"en":"audit","ja":"監査・会計検査\n財務や業務を公式に調査・検査すること。名詞・動詞両方で使う","level":7,"lnum":1,"ex":"The company underwent an internal audit to check its financial records.","exja":"会社は財務記録を確認するために内部監査を受けた。"},{"id":4445,"en":"audition","ja":"オーディション\n役者・音楽家などが演技・演奏を披露して選考を受けること","level":7,"lnum":1,"ex":"She was nervous before her audition for the lead role in the musical.","exja":"ミュージカルの主役オーディションの前、彼女は緊張していた。"},{"id":4446,"en":"authoritative","ja":"権威のある・信頼できる\ninformation source(情報源)を評価するときによく使う形容詞","level":7,"lnum":1,"ex":"The professor's authoritative book on climate change is widely used in universities.","exja":"気候変動に関するその教授の権威ある著書は大学で広く使われている。"},{"id":4447,"en":"authorize/authorise","ja":"権限を与える・許可する\n正式に許可・認可を与えるフォーマルな動詞","level":7,"lnum":1,"ex":"The manager authorized the transfer of funds to the new account.","exja":"マネージャーは新しい口座への資金移動を許可した。"},{"id":4448,"en":"availability","ja":"利用可能性・入手可能性\n人・物・情報がいつ使えるかを表す名詞。check availability(空き確認)が頻出","level":7,"lnum":1,"ex":"Please check the availability of the room before making a booking.","exja":"予約する前に部屋の空き状況を確認してください。"},{"id":4449,"en":"await","ja":"〜を待つ\nwaitより格式のある語。主語+awaitの形で使い、for は付けない点に注意","level":7,"lnum":1,"ex":"Thousands of fans were awaiting the release of the new album.","exja":"何千人ものファンが新しいアルバムのリリースを待ち望んでいた。"},{"id":4450,"en":"awe","ja":"畏敬の念・圧倒されるような感動\nin awe of〜(〜に圧倒されて)の形でよく使う。aweしばしば fear と敬意の混合","level":7,"lnum":1,"ex":"The tourists stood in awe before the massive stone statues.","exja":"観光客は巨大な石の彫像の前に畏敬の念を持って立っていた。"},{"id":4451,"en":"ax/axe","ja":"斧\n木を切る道具。比喩的に「削減・解雇」(budget axe)の意味でも使う","level":7,"lnum":1,"ex":"He used an ax to chop the fallen tree into firewood.","exja":"彼は斧を使って倒れた木を薪に割った。"},{"id":4452,"en":"axis","ja":"軸・中心線\n地球の自転軸や座標軸を表す名詞。複数形はaxes","level":7,"lnum":1,"ex":"The Earth rotates on its axis once approximately every twenty-four hours.","exja":"地球は約24時間ごとに自転軸を中心に一回転する。"},{"id":4453,"en":"backup","ja":"バックアップ・予備\nデータの複製や代替手段を表す名詞。形容詞としても使う","level":7,"lnum":1,"ex":"It is important to keep a backup of all important files on an external drive.","exja":"重要なファイルはすべて外付けドライブにバックアップしておくことが重要だ。"},{"id":4454,"en":"backward/backwards","ja":"後ろへ・後退して\n方向・順序が逆であることを表す副詞。形容詞backwardは「遅れた」の意も","level":7,"lnum":1,"ex":"The car rolled backward down the steep hill.","exja":"車は急な坂を後ろ向きに転がり落ちた。"},{"id":4455,"en":"backyard","ja":"裏庭\n家の裏にある庭。in one's own backyard(自分の身近なところで)の比喩も重要","level":7,"lnum":1,"ex":"The children spent the whole afternoon playing in the backyard.","exja":"子供たちは午後中ずっと裏庭で遊んでいた。"},{"id":4456,"en":"badge","ja":"バッジ・記章\n身分・所属・達成を示すために付ける記章・シール","level":7,"lnum":1,"ex":"Every employee is required to wear a badge with their name and department.","exja":"すべての従業員は名前と部署が書いてあるバッジを着用することが義務付けられている。"},{"id":4457,"en":"bad-tempered","ja":"短気な・怒りっぽい\nすぐに怒りを見せる性格を表す形容詞。ill-temperedと同義","level":7,"lnum":1,"ex":"He becomes very bad-tempered when he does not get enough sleep.","exja":"十分な睡眠が取れないと、彼はとても短気になる。"},{"id":4458,"en":"balanced","ja":"バランスの取れた・均衡のある\n栄養・意見・生活など様々な面での均衡を表す形容詞","level":7,"lnum":1,"ex":"A balanced diet includes plenty of vegetables, protein, and whole grains.","exja":"バランスの取れた食事には、野菜・タンパク質・全粒穀物が豊富に含まれる。"},{"id":4459,"en":"balky","ja":"頑固に動かない・強情な\n馬や機械・人が言うことを聞かないときに使う形容詞","level":7,"lnum":1,"ex":"The old printer was balky and often jammed at the most inconvenient times.","exja":"古いプリンターは頑固に動かず、一番困る場面でよく紙詰まりを起こした。"},{"id":4460,"en":"ballad","ja":"バラード・叙情詩\nゆっくりした感情的な歌や民話的な詩を指す名詞","level":7,"lnum":1,"ex":"The singer performed a beautiful ballad that moved everyone in the room to tears.","exja":"歌手は美しいバラードを披露し、部屋にいた全員を涙させた。"},{"id":4461,"en":"ballet","ja":"バレエ\nクラシックの舞踊形式。go to the ballet(バレエを観に行く)のように使う","level":7,"lnum":1,"ex":"She has been studying ballet since she was four years old.","exja":"彼女は4歳の頃からバレエを習っている。"},{"id":4462,"en":"ballot","ja":"投票・投票用紙\n選挙・決議における秘密投票の手続きや用紙を表す名詞","level":7,"lnum":1,"ex":"The members cast their ballot to elect a new chairperson.","exja":"メンバーたちは新しい議長を選ぶために投票を行った。"},{"id":4463,"en":"banker","ja":"銀行家・銀行員\n銀行で上位職に就く人。teller(窓口係)より上位のニュアンス","level":7,"lnum":1,"ex":"The banker advised his clients to diversify their investment portfolio.","exja":"銀行家は顧客に投資ポートフォリオを多様化するよう助言した。"},{"id":4464,"en":"bankrupt","ja":"破産させる\n企業・個人を財政破綻させること。形容詞go bankrupt(破産する)も重要","level":7,"lnum":1,"ex":"The company went bankrupt after losing several major contracts.","exja":"その会社はいくつかの主要な契約を失った後、倒産した。"},{"id":4465,"en":"bankruptcy","ja":"破産・倒産\n財政的に支払い不能になった状態。file for bankruptcy(破産申請する)が頻出","level":7,"lnum":1,"ex":"Filing for bankruptcy was the only option left for the struggling business.","exja":"破産申請は苦境に立たされた事業者に残された唯一の選択肢だった。"},{"id":4466,"en":"barbershop","ja":"理髪店\n男性向けの散髪店。barber's shopとも言う","level":7,"lnum":1,"ex":"He goes to the barbershop every three weeks to keep his hair neatly trimmed.","exja":"彼は3週間ごとに理髪店に行って髪をきれいに整えている。"},{"id":4467,"en":"bare","ja":"むき出しにする・裸にする\n覆いを取り去って見せることを表す動詞","level":7,"lnum":1,"ex":"The wind was so strong that it bared the branches of all the trees.","exja":"風が非常に強く、すべての木の枝がむき出しになった。"},{"id":4468,"en":"bargain","ja":"交渉する・値切る\n価格や条件を有利に取り決めるための交渉を表す動詞","level":7,"lnum":1,"ex":"She managed to bargain the price down at the antique market.","exja":"彼女はアンティーク市場で値段を交渉して下げることができた。"},{"id":4469,"en":"bark","ja":"吠える・叫ぶ\n犬の鳴き声や人が怒鳴るときに使う動詞。名詞では「樹皮」の意も","level":7,"lnum":1,"ex":"The dog barked loudly at the stranger approaching the gate.","exja":"犬は門に近づいてくる見知らぬ人に向かって大きな声で吠えた。"},{"id":4470,"en":"barley","ja":"大麦\nビール・ウイスキーの原料となる穀物。rye(ライ麦)と区別して覚える","level":7,"lnum":1,"ex":"Barley is one of the main ingredients used in the production of beer.","exja":"大麦はビールの製造に使われる主な原料の一つだ。"},{"id":4471,"en":"barn","ja":"納屋・barn\n農場の大型倉庫。barn dance(農村の踊り)などの文化的表現にも登場","level":7,"lnum":1,"ex":"The farmer stored hay and farming equipment in the large red barn.","exja":"農家は大きな赤い納屋に干し草と農機具を保管していた。"},{"id":4472,"en":"barometer","ja":"気圧計・指標\n大気圧を測る器具。比喩的に「経済の指標」など状況を示すものを指す","level":7,"lnum":1,"ex":"The stock market is often used as a barometer of the overall economy.","exja":"株式市場はしばしば経済全体の指標として使われる。"},{"id":4473,"en":"barren","ja":"不毛の・不妊の\n土地が痩せている・植物が育たない状態。比喩的に「成果のない」も表す","level":7,"lnum":1,"ex":"The desert landscape was completely barren, with nothing growing for miles.","exja":"砂漠の景観は完全に不毛で、何マイルにもわたって何も育っていなかった。"},{"id":4474,"en":"bartender","ja":"バーテンダー\nバーで飲み物を作り提供するスタッフ。英国ではbarmanとも言う","level":7,"lnum":1,"ex":"The bartender mixed the cocktail with impressive speed and precision.","exja":"バーテンダーは驚くほどの速さと正確さでカクテルを作った。"},{"id":4475,"en":"bathhouse","ja":"浴場・銭湯\n公衆が入浴できる建物。温泉・サウナ施設を含む場合も","level":7,"lnum":1,"ex":"The ancient Roman bathhouse was discovered during construction of a new building.","exja":"建設工事中に古代ローマの浴場が発見された。"},{"id":4476,"en":"battlefield","ja":"戦場・戦地\n実際の戦闘が行われる場所。比喩的に激しい争いの場を指すことも","level":7,"lnum":1,"ex":"The old battlefield has been turned into a memorial park for fallen soldiers.","exja":"かつての戦場は戦没した兵士のための記念公園に転換された。"},{"id":4477,"en":"beagle","ja":"ビーグル犬\n小型の猟犬の品種。鼻が利くことで知られ、実験動物としても言及される","level":7,"lnum":1,"ex":"The beagle trotted ahead of its owner, following a trail of interesting scents.","exja":"ビーグル犬は飼い主の前をトコトコと歩き、興味深い匂いの跡を追っていた。"},{"id":4478,"en":"beam","ja":"光線・梁・満面の笑み\n光・建築材・笑顔など複数の意味を持つ多義語の名詞","level":7,"lnum":1,"ex":"A beam of sunlight broke through the clouds and lit up the garden.","exja":"雲の間から太陽の光線が差し込み、庭を照らした。"},{"id":4479,"en":"bearing","ja":"関係・方位・態度\nhave a bearing on〜(〜に関係がある)の形が最重要。方位の意味も持つ","level":7,"lnum":1,"ex":"The research has no direct bearing on the outcome of the legal case.","exja":"その調査は訴訟の結果に直接の関係はない。"},{"id":4480,"en":"beautify","ja":"美しくする・美化する\nbeauty(美)の動詞形。景観・建物・外見などを美しくすること","level":7,"lnum":1,"ex":"The volunteers worked together to beautify the local park by planting flowers.","exja":"ボランティアたちは花を植えて地域の公園を美しくするために協力した。"},{"id":4481,"en":"bellow","ja":"怒鳴る・大声で叫ぶ\n牛の鳴き声のように大きな声で叫ぶときに使う動詞","level":7,"lnum":1,"ex":"The coach bellowed instructions from the sideline during the match.","exja":"コーチは試合中に側線から大声で指示を怒鳴った。"},{"id":4482,"en":"belongings","ja":"所持品・持ち物\n個人が所有する物の総称。常に複数形で使う点に注意","level":7,"lnum":1,"ex":"She packed all her belongings into two suitcases before moving abroad.","exja":"海外に引っ越す前に、彼女はすべての所持品を2つのスーツケースに詰めた。"},{"id":4483,"en":"bend","ja":"曲がり・カーブ\n道路や川の曲がった部分を表す名詞。動詞bendの名詞形","level":7,"lnum":1,"ex":"There is a sharp bend in the road ahead, so please slow down.","exja":"この先、道路に急カーブがあるのでスピードを落としてください。"},{"id":4484,"en":"beneficial","ja":"有益な・ためになる\nbenefit(利益)の形容詞形。be beneficial to〜(〜に有益な)が頻出","level":7,"lnum":1,"ex":"Regular physical exercise is beneficial to both mental and physical health.","exja":"定期的な運動は精神的・身体的健康の両方にとって有益だ。"},{"id":4485,"en":"benefit","ja":"利益を得る・恩恵を受ける\nbenefit from〜(〜から利益を得る)の形で使う動詞","level":7,"lnum":1,"ex":"Students can benefit greatly from studying abroad for a semester.","exja":"学生は一学期留学することで大きな恩恵を受けることができる。"},{"id":4486,"en":"benevolence","ja":"善意・慈善\n他者への思いやりと親切な行動を表す格式のある名詞","level":7,"lnum":1,"ex":"The king was known for his benevolence toward the poor people of his kingdom.","exja":"その王は王国の貧しい人々への善意で知られていた。"},{"id":4487,"en":"benevolent","ja":"親切な・慈善的な\n見返りを求めず他者の幸福を願う性格や行動に使う形容詞","level":7,"lnum":1,"ex":"The benevolent founder donated most of his wealth to education and healthcare.","exja":"その慈善的な創業者は財産のほとんどを教育と医療に寄付した。"},{"id":4488,"en":"berry","ja":"ベリー・小さな果実\nいちご・ブルーベリーなど小さな果実の総称名詞","level":7,"lnum":1,"ex":"Wild berries can be delicious, but some are toxic and should never be eaten.","exja":"野生のベリーは美味しいこともあるが、有毒なものもあり絶対に食べてはならない。"},{"id":4489,"en":"bestow","ja":"授ける・与える\n名誉・贈り物・称号などを正式に贈るときのフォーマルな動詞","level":7,"lnum":1,"ex":"The university bestowed an honorary degree upon the celebrated author.","exja":"大学はその著名な作家に名誉博士号を授けた。"},{"id":4490,"en":"bestseller","ja":"ベストセラー\n最も売れている本や商品を指す名詞。形容詞的にも使う","level":7,"lnum":1,"ex":"Her debut novel became a bestseller within weeks of its publication.","exja":"彼女のデビュー小説は出版から数週間でベストセラーになった。"},{"id":4491,"en":"betray","ja":"裏切る・暴露する\n信頼を裏切る・秘密を漏らすときに使う動詞","level":7,"lnum":1,"ex":"He was arrested for betraying military secrets to a foreign government.","exja":"彼は軍事機密を外国政府に漏らしたとして逮捕された。"},{"id":4492,"en":"bewilder","ja":"당惑させる・混乱させる\n理解できないほど複雑な状況に困惑させることを表す動詞","level":7,"lnum":1,"ex":"The complex instructions bewildered many of the participants.","exja":"複雑な指示は参加者の多くを当惑させた。"},{"id":4493,"en":"bewilderment","ja":"当惑・困惑\nin bewilderment(困惑して)の形でよく使う名詞","level":7,"lnum":1,"ex":"She stared in bewilderment at the unexpected results of the experiment.","exja":"彼女は実験の予想外の結果を困惑して見つめた。"},{"id":4494,"en":"bid","ja":"入札する・申し出る\n競売での値付けや仕事の受注申込みを表す動詞","level":7,"lnum":1,"ex":"Several construction companies bid for the contract to build the new hospital.","exja":"複数の建設会社が新病院建設の契約に入札した。"},{"id":4495,"en":"bidding","ja":"入札・命令\n入札行為や人の指示に従うこと(do A's bidding)を表す名詞","level":7,"lnum":1,"ex":"The auctioneer began the bidding at five hundred dollars.","exja":"競売人は500ドルから入札を開始した。"},{"id":4496,"en":"bikini","ja":"ビキニ\n女性用二点式水着。ビキニ環礁の核実験が語源の名詞","level":7,"lnum":1,"ex":"She wore a colorful bikini while relaxing by the resort pool.","exja":"彼女はリゾートのプールのそばでくつろぎながら、カラフルなビキニを着ていた。"},{"id":4497,"en":"bind","ja":"縛る・束縛する\n物理的に縛る・法的に拘束するの両方に使う動詞","level":7,"lnum":1,"ex":"The contract binds both parties to fulfill their agreed-upon obligations.","exja":"その契約は両当事者に合意した義務を果たすことを縛り付けている。"},{"id":4498,"en":"bio","ja":"略歴・バイオ\nbiography(伝記)の短縮形。SNSのプロフィール欄にもよく使われる","level":7,"lnum":1,"ex":"She updated her social media bio to reflect her new job title.","exja":"彼女は新しい肩書きを反映するためにSNSの略歴を更新した。"},{"id":4499,"en":"biological","ja":"生物学的な・生物学の\n生命科学に関する形容詞。biological clock(体内時計)などでも頻出","level":7,"lnum":1,"ex":"The virus spreads through direct contact with biological fluids.","exja":"そのウイルスは体液との直接接触を通じて広がる。"},{"id":4500,"en":"biotechnology","ja":"バイオテクノロジー・生命工学\n生物の機能を工学的に応用する科学技術分野を指す名詞","level":7,"lnum":1,"ex":"Biotechnology has made it possible to develop crops that resist disease.","exja":"バイオテクノロジーは病気に強い農作物の開発を可能にした。"},{"id":4501,"en":"birdcage","ja":"鳥かご\n鳥を飼うための金属製の檻。比喩的に「閉じ込めた状況」にも使う","level":7,"lnum":1,"ex":"The parrot sat quietly in its birdcage, watching the people walk by.","exja":"オウムは鳥かごの中で静かに座り、通り過ぎる人々を見つめていた。"},{"id":4502,"en":"birthplace","ja":"生まれ故郷・発祥地\n人が生まれた場所や何かが始まった場所を表す名詞","level":7,"lnum":1,"ex":"Kyoto is often considered the birthplace of traditional Japanese culture.","exja":"京都はしばしば伝統的な日本文化の発祥地と見なされている。"},{"id":4503,"en":"bitterly","ja":"激しく・つらく・苦く\n感情の激しさを強調する副詞。bitterly cold(凍えるほど寒い)も頻出","level":7,"lnum":1,"ex":"She bitterly regretted not apologizing to her friend before he moved away.","exja":"友人が引っ越す前に謝らなかったことを彼女は激しく後悔した。"},{"id":4504,"en":"bizarre","ja":"奇妙な・ひどく変な\n常識から大きく外れた奇妙さを表す形容詞。strangeより強い語","level":7,"lnum":1,"ex":"The artist was known for creating bizarre sculptures out of everyday objects.","exja":"そのアーティストは日用品から奇妙な彫刻を作ることで知られていた。"},{"id":4505,"en":"blade","ja":"刃・ブレード\n刃物の刃の部分。blade of grass(草の葉)など他の意味も持つ","level":7,"lnum":1,"ex":"The chef sharpened the blade of his knife before slicing the vegetables.","exja":"シェフは野菜を切る前にナイフの刃を研いだ。"},{"id":4506,"en":"blast","ja":"爆発・突風\n名詞として爆発音や強い風を表す。at full blast(全開で)も慣用表現","level":7,"lnum":1,"ex":"Workers blasted through the rock to create a tunnel for the new railway.","exja":"作業員は新しい鉄道のトンネルを作るために岩を爆破した。"},{"id":4507,"en":"blast","ja":"爆破する・激しく吹く\n爆発させる・強い批判を加えるときに使う動詞","level":7,"lnum":1,"ex":"The workers blasted through the rock to build the tunnel.","exja":"作業員たちはトンネルを建設するために岩盤を爆破した。"},{"id":4508,"en":"blaze","ja":"炎・火事\n名詞として勢いよく燃える炎や輝きを表す。in a blaze(炎に包まれて)","level":7,"lnum":1,"ex":"The bonfire blazed brightly in the darkness of the forest clearing.","exja":"森の開けた場所の暗闇の中で、焚き火が明るく燃え盛っていた。"},{"id":4509,"en":"blaze","ja":"燃え盛る・輝く\n火が勢いよく燃えている・光が強く輝いているときに使う動詞","level":7,"lnum":1,"ex":"A fire was blazing in the fireplace, keeping the room warm.","exja":"暖炉で火が燃え盛り、部屋を温かく保っていた。"},{"id":4510,"en":"blend","ja":"混合・ブレンド\n名詞として異なる要素を混ぜ合わせたものを指す","level":7,"lnum":1,"ex":"The smoothie was a delicious blend of tropical fruits and yogurt.","exja":"そのスムージーは熱帯の果物とヨーグルトの美味しい混合物だった。"},{"id":4511,"en":"blindly","ja":"盲目的に・無分別に\n考えなしに従うときに使う副詞。blindly follow(盲目的に従う)が頻出","level":7,"lnum":1,"ex":"He blindly followed his boss's instructions without questioning their purpose.","exja":"彼はその目的を疑わずに盲目的に上司の指示に従った。"},{"id":4512,"en":"blindness","ja":"失明・盲目\n視覚を失った状態。比喩的に「無知・気づかない状態」も表す","level":7,"lnum":1,"ex":"His blindness was caused by a rare genetic condition that ran in his family.","exja":"彼の失明は家族に遺伝する稀な遺伝的疾患によって引き起こされた。"},{"id":4513,"en":"blink","ja":"まばたきする・点滅する\n目をパチパチさせること、または光が点滅することを表す動詞","level":7,"lnum":1,"ex":"She blinked rapidly as she stepped out of the dark theater into bright sunlight.","exja":"暗い映画館から明るい日差しの中に出ると、彼女は素早くまばたきをした。"},{"id":4514,"en":"bloodstream","ja":"血流・血液循環\n体内を循環する血液の流れを表す名詞。医学文脈で頻出","level":7,"lnum":1,"ex":"The medicine is absorbed into the bloodstream within minutes of being taken.","exja":"薬は服用してから数分以内に血流に吸収される。"},{"id":4515,"en":"bloody","ja":"血まみれの・激しい\n血が付いた・残酷な状態を表す形容詞","level":7,"lnum":1,"ex":"It was a bloody difficult exam, and most students were completely exhausted afterward.","exja":"それはひどく難しい試験で、ほとんどの学生はその後完全にへとへとだった。"},{"id":4516,"en":"bloody","ja":"ひどく・非常に\n英国英語の強意副詞。damn と同様の意味を持つ俗語表現","level":7,"lnum":1,"ex":"It was a bloody difficult exam that most students failed.","exja":"それはほとんどの生徒が落ちた本当にひどく難しい試験だった。"},{"id":4517,"en":"blooming","ja":"花が咲いている・繁栄している\n植物の開花と比喩的な繁栄の両方を表す形容詞","level":7,"lnum":1,"ex":"The garden was blooming with roses and tulips throughout the spring.","exja":"春の間中、庭はバラとチューリップが咲き乱れていた。"},{"id":4518,"en":"blur","ja":"ぼかす・不明瞭にする\n輪郭を不鮮明にすること。blur the line(境界線をあいまいにする)が頻出","level":7,"lnum":1,"ex":"Years of heavy drinking had caused his memories of that period to blur.","exja":"長年の大量飲酒により、その時期の記憶が曖昧になっていた。"},{"id":4519,"en":"blurt","ja":"思わず口に出す\n考えずに突然しゃべること。blurt out〜(〜をうっかり言う)の形が基本","level":7,"lnum":1,"ex":"She blurted out the surprise before anyone could stop her.","exja":"彼女は誰も止める間もなくサプライズを思わず口に出してしまった。"},{"id":4520,"en":"blush","ja":"顔を赤らめる・赤面する\n恥ずかしさや照れで顔が赤くなる状態を表す動詞","level":7,"lnum":1,"ex":"He blushed deeply when the teacher praised him in front of the whole class.","exja":"クラス全員の前で先生に褒められたとき、彼は深く顔を赤らめた。"},{"id":4521,"en":"boiling","ja":"沸騰した・非常に熱い\n水が沸騰している状態や非常に暑い状態を表す形容詞","level":7,"lnum":1,"ex":"Be careful — the water in the pot is boiling and could burn you.","exja":"気をつけて — 鍋の水が沸騰していて、やけどするかもしれない。"},{"id":4522,"en":"bold","ja":"太字・太字の文字\n印刷における太字のフォントを指す名詞","level":7,"lnum":1,"ex":"The designer chose to print the title in bold to make it stand out.","exja":"デザイナーは目立つようにタイトルを太字で印刷することにした。"},{"id":4523,"en":"bolt","ja":"ボルト・閂\nナットと組み合わせる金属のねじや扉の鍵を表す名詞","level":7,"lnum":1,"ex":"Startled by the loud noise, the horse bolted across the field.","exja":"大きな音に驚いて、馬は野原を一目散に駆け抜けた。"},{"id":4524,"en":"bolt","ja":"急いで逃げる・固定する\n素早く逃げること・ボルトで固定することを表す動詞","level":7,"lnum":1,"ex":"The suspect bolted out of the back door when he heard the police.","exja":"容疑者は警察の声を聞いて裏口から急いで逃げ出した。"},{"id":4525,"en":"bombard","ja":"爆撃する・質問攻めにする\n大量の爆弾・質問・批判を浴びせることを表す動詞・名詞","level":7,"lnum":1,"ex":"Reporters bombarded the minister with questions about the new policy.","exja":"記者たちは大臣に新しい政策についての質問を浴びせかけた。"},{"id":4526,"en":"bomber","ja":"爆撃機・爆弾犯\n爆弾を投下する航空機や爆弾を仕掛ける人物を指す名詞","level":7,"lnum":1,"ex":"The police identified the bomber using security camera footage.","exja":"警察は防犯カメラの映像を使って爆弾犯を特定した。"},{"id":4527,"en":"bombing","ja":"爆撃・爆弾テロ\n爆弾を使った攻撃や事件を表す名詞","level":7,"lnum":1,"ex":"The bombing of the city center caused widespread destruction and panic.","exja":"市街地中心部への爆撃は広範囲にわたる破壊と混乱をもたらした。"},{"id":4528,"en":"bony","ja":"骨ばった・痩せ細った\n骨が目立つほど痩せている状態を表す形容詞","level":7,"lnum":1,"ex":"The stray dog was thin and bony from months of not having enough food.","exja":"野良犬は何ヶ月もの食糧不足から痩せ細っていた。"},{"id":4529,"en":"bookish","ja":"本好きの・本ばかり読む\n勉強・読書が好きでやや非社交的なイメージを持つ形容詞","level":7,"lnum":1,"ex":"She was always considered a bookish child who preferred reading to playing sports.","exja":"彼女はスポーツよりも読書を好む本好きの子供だといつも思われていた。"},{"id":4530,"en":"booklet","ja":"小冊子・パンフレット\n情報をまとめた薄い冊子を指す名詞","level":7,"lnum":1,"ex":"The health department distributed a booklet on how to prevent common diseases.","exja":"保健局は一般的な病気を予防する方法についての小冊子を配布した。"},{"id":4531,"en":"bookmark","ja":"ブックマーク・しおり\n本のしおりやウェブブラウザの保存したURLを指す名詞","level":7,"lnum":1,"ex":"He bookmarked several useful websites for his research on climate change.","exja":"彼は気候変動の調査のためにいくつかの有益なウェブサイトをブックマークした。"},{"id":4532,"en":"bookmark","ja":"ブックマークする・しおりを挟む\nウェブページや本にブックマークをつける動詞","level":7,"lnum":1,"ex":"She bookmarked the page so she could continue reading later.","exja":"彼女は後で読み続けられるようにそのページをブックマークした。"},{"id":4533,"en":"boost","ja":"後押し・増加\n力・効果・生産量などを高める名詞。a boost to〜(〜への後押し)が頻出","level":7,"lnum":1,"ex":"The coach's encouraging words gave the team a much-needed boost before the final.","exja":"コーチの励ましの言葉は決勝前にチームに必要な後押しを与えた。"},{"id":4534,"en":"boost","ja":"高める・促進する\nパフォーマンス・士気・経済などを向上させる動詞","level":7,"lnum":1,"ex":"The new marketing campaign boosted sales by twenty percent.","exja":"新しいマーケティングキャンペーンにより売上が20パーセント増加した。"},{"id":4535,"en":"booth","ja":"ブース・小さな区画\n電話ボックス・投票ブース・屋台などの仕切られた小空間を指す","level":7,"lnum":1,"ex":"The students set up a booth at the entrance to sell tickets for the festival.","exja":"生徒たちはフェスティバルのチケットを販売するために入り口にブースを設置した。"},{"id":4536,"en":"bossy","ja":"威張る・支配的な\n他人に命令したがる気質を表す否定的な形容詞","level":7,"lnum":1,"ex":"Her younger sister was quite bossy and always wanted to be in charge.","exja":"彼女の妹はとても威張り屋で、いつも仕切りたがっていた。"},{"id":4537,"en":"botany","ja":"植物学\n植物を研究する学問分野を表す名詞","level":7,"lnum":1,"ex":"She studied botany at university and went on to work in plant conservation.","exja":"彼女は大学で植物学を学び、その後植物保護の仕事に就いた。"},{"id":4538,"en":"bothered","ja":"悩まされた・気にした\nbe bothered by〜(〜に悩まされる)の形で使う形容詞","level":7,"lnum":1,"ex":"He wasn't bothered by the negative comments left on his video.","exja":"彼は自分の動画に寄せられた否定的なコメントを気にしなかった。"},{"id":4539,"en":"bothersome","ja":"面倒な・厄介な\n手間や不快感を引き起こす状況・物・人に使う形容詞","level":7,"lnum":1,"ex":"The constant noise from the construction site was bothersome to local residents.","exja":"建設現場からの絶え間ない騒音は地域住民にとって厄介だった。"},{"id":4540,"en":"bounce","ja":"弾む・はね返る\nボールやアイデアが弾む・反響するときに使う名詞","level":7,"lnum":1,"ex":"The rubber ball bounced high off the concrete floor.","exja":"ゴムボールはコンクリートの床で高く弾んだ。"},{"id":4541,"en":"bourbon","ja":"バーボン・バーボンウイスキー\nケンタッキー産のとうもろこし主体のウイスキーを指す名詞","level":7,"lnum":1,"ex":"He ordered a glass of bourbon on the rocks at the hotel bar.","exja":"彼はホテルのバーでバーボンのロックを注文した。"},{"id":4542,"en":"bow","ja":"お辞儀をする・頭を下げる\n敬意・謝罪・降参の意を示して頭を下げる動詞","level":7,"lnum":1,"ex":"The performers bowed deeply after the final act of the play.","exja":"出演者たちは劇の最後の幕の後、深くお辞儀をした。"},{"id":4543,"en":"boxer","ja":"ボクサー・ボクシング犬\nボクシングの選手または犬の品種を指す名詞","level":7,"lnum":1,"ex":"The boxer trained for six months before his championship bout.","exja":"ボクサーはチャンピオン戦の前に6ヶ月間トレーニングを積んだ。"},{"id":4544,"en":"bracket","ja":"括弧・区分\n丸括弧や角括弧などの記号、または収入・年齢の区分を表す名詞","level":7,"lnum":1,"ex":"Make sure to close every opening bracket in your programming code.","exja":"プログラミングコードで開き括弧はすべて閉じるようにしてください。"},{"id":4545,"en":"brag","ja":"自慢する・吹聴する\n誇らしげに自己アピールする行為。名詞としても使える","level":7,"lnum":1,"ex":"He always brags about his exam scores whenever he sees his classmates.","exja":"彼はクラスメートに会うたびに試験の点数を自慢する。"},{"id":4546,"en":"brake","ja":"ブレーキをかける\n車・自転車などを減速・停止させる動詞","level":7,"lnum":1,"ex":"The driver had to brake suddenly to avoid hitting the dog on the road.","exja":"ドライバーは道路にいる犬をはねないように急ブレーキをかけなければならなかった。"},{"id":4547,"en":"bravery","ja":"勇気・勇敢さ\n恐怖を感じながらも行動する強さを表す名詞。courageの類義語","level":7,"lnum":1,"ex":"The firefighter was awarded a medal for her bravery during the rescue operation.","exja":"消防士は救助活動中の勇敢さに対してメダルを授与された。"},{"id":4548,"en":"breakable","ja":"壊れやすい・割れやすい\nfragileと同義の形容詞。割れ物に使われる表現","level":7,"lnum":1,"ex":"Please handle the box with care as the items inside are breakable.","exja":"中身は壊れやすいので、箱は丁寧に扱ってください。"},{"id":4549,"en":"breakdown","ja":"故障・崩壊・内訳\n機械の故障・精神的崩壊・詳細な分析の3つの意味を持つ名詞","level":7,"lnum":1,"ex":"The sudden breakdown of the machine caused a long delay in production.","exja":"機械の突然の故障により、生産に長い遅延が生じた。"},{"id":4550,"en":"breakup","ja":"別れ・解散\n恋人関係の終わりや組織の解体を指す名詞","level":7,"lnum":1,"ex":"She was devastated by the breakup but eventually moved on with her life.","exja":"彼女は別れに打ちひしがれたが、最終的に立ち直って前に進んだ。"},{"id":4551,"en":"breathtaking","ja":"息をのむほどの・圧巻の\nあまりの素晴らしさや驚きで息が止まるような場面に使う形容詞","level":7,"lnum":1,"ex":"The view from the top of the mountain was absolutely breathtaking.","exja":"山頂からの眺めは本当に息をのむほど素晴らしかった。"},{"id":4552,"en":"breed","ja":"品種・種類\n動物の種類を表す名詞。a breed of dog(犬の品種)のように使う","level":7,"lnum":1,"ex":"The Golden Retriever is one of the most popular dog breeds in the world.","exja":"ゴールデンレトリバーは世界で最も人気のある犬の品種の一つだ。"},{"id":4553,"en":"breezy","ja":"そよ風の吹く・軽快な\n風が心地よく吹いている状態や気軽な雰囲気を表す形容詞","level":7,"lnum":1,"ex":"It was a warm and breezy afternoon, perfect for sitting outside.","exja":"暖かくそよ風の吹く午後で、外に座るには最高だった。"},{"id":4554,"en":"brewery","ja":"醸造所・ビール工場\nビールを製造する施設を指す名詞","level":7,"lnum":1,"ex":"The city is famous for its craft brewery, which produces over twenty types of beer.","exja":"その市はクラフトビール醸造所で有名で、20種類以上のビールを製造している。"},{"id":4555,"en":"brilliantly","ja":"見事に・輝かしく\n優れた才能・能力・結果を称えるときに使う副詞","level":7,"lnum":1,"ex":"The student answered the most difficult questions brilliantly during the debate.","exja":"その生徒はディベート中に最も難しい質問に見事に答えた。"},{"id":4556,"en":"broadband","ja":"ブロードバンド\n高速インターネット接続の通信方式を指す名詞・形容詞","level":7,"lnum":1,"ex":"Many remote villages still lack access to reliable broadband internet.","exja":"多くの過疎地ではまだ信頼できるブロードバンドインターネットへのアクセスがない。"},{"id":4557,"en":"broadcast","ja":"放送する・広める\nラジオ・テレビで情報を発信する、または広く知らせる動詞","level":7,"lnum":1,"ex":"The speech was broadcast live to millions of viewers around the country.","exja":"そのスピーチは全国の数百万人の視聴者にライブで放送された。"},{"id":4558,"en":"broadcaster","ja":"放送局・放送員\nテレビ・ラジオの放送機関や番組を担当する人物を指す名詞","level":7,"lnum":1,"ex":"The veteran broadcaster has reported on major events for over thirty years.","exja":"その大ベテランの放送員は30年以上にわたって主要な出来事を報道してきた。"},{"id":4559,"en":"broadly","ja":"広く・おおむね\n広い範囲で・大まかに言えばを表す副詞。broadly speaking(大まかに言えば)","level":7,"lnum":1,"ex":"Broadly speaking, the students were satisfied with the new curriculum.","exja":"おおむね言えば、生徒たちは新しいカリキュラムに満足していた。"},{"id":4560,"en":"brochure","ja":"パンフレット・ちらし\n商品・旅行・イベントの情報を掲載した薄い印刷物","level":7,"lnum":1,"ex":"The travel agency sent her a brochure with photos of popular holiday destinations.","exja":"旅行代理店は人気の休暇先の写真が載ったパンフレットを彼女に送った。"},{"id":4561,"en":"brother-in-law","ja":"義兄弟・義理の兄弟\n配偶者の兄弟または姉妹の夫を指す名詞","level":7,"lnum":1,"ex":"Her brother-in-law helped them move into their new apartment last weekend.","exja":"彼女の義兄弟は先週末、彼らが新しいアパートに引越すのを手伝ってくれた。"},{"id":4562,"en":"browse","ja":"閲覧する・拾い読みする\nインターネット・本・店を気ままに見て回ることを表す動詞","level":7,"lnum":1,"ex":"She spent an hour browsing the internet for information about her new topic.","exja":"彼女は新しいトピックについての情報をインターネットで1時間閲覧した。"},{"id":4563,"en":"browser","ja":"ブラウザ・閲覧者\nウェブサイトを閲覧するソフトウェアまたは見て回る人を指す名詞","level":7,"lnum":1,"ex":"The website may not display correctly on older browser versions.","exja":"そのウェブサイトは古いブラウザのバージョンでは正しく表示されないかもしれない。"},{"id":4564,"en":"bruise","ja":"打撲傷・あざ\n皮膚の下に血が滲んで変色した傷を指す名詞","level":7,"lnum":1,"ex":"He had a large bruise on his arm after falling off his bicycle.","exja":"自転車から落ちた後、彼の腕に大きなあざができていた。"},{"id":4565,"en":"bud","ja":"芽・つぼみ\n植物の成長初期の小さな芽やつぼみを表す名詞","level":7,"lnum":1,"ex":"The cherry trees are just beginning to show their first buds of spring.","exja":"桜の木々は春の最初のつぼみをつけ始めたところだ。"},{"id":4566,"en":"budget","ja":"格安の・低コストの\n低価格帯の製品・旅行・ホテルを表す形容詞","level":7,"lnum":1,"ex":"The family chose a budget hotel to keep their travel costs low.","exja":"家族は旅費を抑えるために格安ホテルを選んだ。"},{"id":4567,"en":"bulimia","ja":"過食症・過食嘔吐症\n食べて吐くことを繰り返す摂食障害。医学・健康文脈で使われる","level":7,"lnum":1,"ex":"Bulimia is a serious eating disorder that requires professional medical treatment.","exja":"過食症は専門的な医療治療を必要とする深刻な摂食障害だ。"},{"id":4568,"en":"bully","ja":"いじめる・脅して〜させる\n弱い立場の人を恐怖・強制で支配しようとする動詞","level":7,"lnum":1,"ex":"The older students were caught bullying a younger student on school grounds.","exja":"年上の生徒たちは学校の敷地内で年下の生徒をいじめているところを見つかった。"},{"id":4569,"en":"bum","ja":"浮浪者・怠け者\n米国英語で仕事も家もない人または怠ける人を指すくだけた語","level":7,"lnum":1,"ex":"He was often seen hanging around the park, considered a bum by many locals.","exja":"彼はよく公園をぶらついているのが見かけられ、多くの地元の人々には怠け者だと思われていた。"},{"id":4570,"en":"bumper","ja":"バンパー\n車の前後に付いた衝撃吸収部品を指す名詞","level":7,"lnum":1,"ex":"The car's bumper was slightly dented after the parking lot accident.","exja":"駐車場での事故の後、車のバンパーがわずかに凹んだ。"},{"id":4571,"en":"bun","ja":"バン・お団子ヘア\n丸いパンや髪を丸くまとめたスタイルを指す名詞","level":7,"lnum":1,"ex":"She twisted her long hair into a neat bun before the interview.","exja":"面接前に、彼女は長い髪をきれいなお団子ヘアにまとめた。"},{"id":4572,"en":"burden","ja":"負担をかける・重荷を負わせる\n誰かに重い責任や義務を課すときに使う動詞","level":7,"lnum":1,"ex":"The new regulations placed a heavy burden on small business owners.","exja":"新しい規制は中小企業の経営者に重い負担を課した。"},{"id":4573,"en":"burdensome","ja":"重荷な・やっかいな\nburden(負担)の形容詞形。処理が大変な義務・状況に使う","level":7,"lnum":1,"ex":"Filling out the same forms repeatedly was burdensome and time-consuming.","exja":"同じ書類を何度も記入することは重荷で時間のかかる作業だった。"},{"id":4574,"en":"bureaucracy","ja":"官僚制度・お役所仕事\n複雑なルールと手続きを持つ行政組織。否定的ニュアンスも強い","level":7,"lnum":1,"ex":"The amount of bureaucracy involved in applying for the permit was frustrating.","exja":"許可証申請に関わる官僚主義的な手続きの多さはうんざりするものだった。"},{"id":4575,"en":"burglary","ja":"住居侵入窃盗\n建物に不法侵入して盗む犯罪。robbery(強盗)との区別が重要","level":7,"lnum":1,"ex":"The police were called after a burglary was discovered at the jewelry store.","exja":"宝石店で住居侵入窃盗が発覚した後、警察が呼ばれた。"},{"id":4576,"en":"burgle","ja":"住居侵入窃盗をする\nburglary(住居侵入窃盗)の動詞形。be burgled(被害に遭う)の形で頻出","level":7,"lnum":1,"ex":"Their house was burgled while they were away on holiday.","exja":"彼らが休暇で不在の間に家に押し入られた。"},{"id":4577,"en":"burial","ja":"埋葬・埋葬式\n遺体を土に埋めること。burial ground(埋葬地)などの複合語も重要","level":7,"lnum":1,"ex":"The burial took place on a hilltop overlooking the ocean the family loved.","exja":"埋葬は家族が愛した海を見渡す丘の上で行われた。"},{"id":4578,"en":"bustle","ja":"せわしなく動く・バタバタする\nあわただしく動き回ることを表す動詞。bustle about(あちこち走り回る)","level":7,"lnum":1,"ex":"The streets of the city bustle with activity from early morning to midnight.","exja":"その都市の通りは早朝から深夜まで活動でせわしなく動いている。"},{"id":4579,"en":"bustling","ja":"にぎやかな・活気あふれる\n人や活動で活発な場所・街の様子を表す形容詞","level":7,"lnum":1,"ex":"The bustling market was filled with the smells of fresh food and spices.","exja":"活気あふれる市場は新鮮な食べ物やスパイスの香りで満ちていた。"},{"id":4580,"en":"butcher","ja":"屠殺する・台無しにする\n動物を食肉加工するまたは残酷に殺すことを表す動詞","level":7,"lnum":1,"ex":"The cook carefully butchered the whole fish before preparing the dish.","exja":"料理人は料理を準備する前に丸ごとの魚を丁寧にさばいた。"},{"id":4581,"en":"buzz","ja":"ざわめき・うわさ\n昆虫の羽音のような音・話題になるうわさを表す名詞","level":7,"lnum":1,"ex":"A bee buzzed past her ear and disappeared into the garden.","exja":"蜂が耳元をブーンとかすめて庭の中へ消えていった。"},{"id":4582,"en":"buzz","ja":"ブーンと鳴る・飛び回る\n蜂のような音を出す・慌ただしく動き回る動詞","level":7,"lnum":1,"ex":"The bees were buzzing around the flowers in the garden.","exja":"庭の花の周りでミツバチがブーンと飛び回っていた。"},{"id":4583,"en":"cabinet","ja":"内閣・戸棚\n政府の内閣や収納家具の両方を指す多義語","level":7,"lnum":1,"ex":"The new cabinet was formed after months of difficult coalition negotiations.","exja":"新しい内閣は数ヶ月に及ぶ困難な連立交渉の末に組閣された。"},{"id":4584,"en":"cable","ja":"ケーブル・電線\n電気・通信用の太いひも状配線、またはケーブルテレビを指す名詞","level":7,"lnum":1,"ex":"The technician replaced the damaged cable to restore the internet connection.","exja":"技術者はインターネット接続を回復するために損傷したケーブルを交換した。"},{"id":4585,"en":"calmly","ja":"落ち着いて・穏やかに\ncalm(静かな)の副詞形。興奮せず穏やかに行動するさまを表す","level":7,"lnum":1,"ex":"She calmly explained the situation to the worried parents.","exja":"彼女は心配している保護者たちに落ち着いて状況を説明した。"},{"id":4586,"en":"candidate","ja":"候補者・志願者\n選挙・採用・試験など選ばれる立場にある人を指す名詞","level":7,"lnum":1,"ex":"Three candidates are running for the position of student council president.","exja":"3人の候補者が生徒会長の座を争っている。"},{"id":4587,"en":"cane","ja":"杖・藤・砂糖黍\n歩行補助の杖・植物の茎・砂糖の原料など複数の意味を持つ名詞","level":7,"lnum":1,"ex":"After breaking his leg, he relied on a cane to help him walk.","exja":"足を骨折した後、彼は歩くために杖に頼っていた。"},{"id":4588,"en":"cannonball","ja":"砲弾・大砲の弾\n大砲で発射する鉄の球。比喩的に「突進する」にも使われる","level":7,"lnum":1,"ex":"The historical museum displayed an actual cannonball recovered from the old battlefield.","exja":"歴史博物館には旧戦場から回収された実際の砲弾が展示されていた。"},{"id":4589,"en":"canon","ja":"規範・正典・カノン\n文学・芸術・宗教における権威ある基準作品群を指す名詞","level":7,"lnum":1,"ex":"Shakespeare's works are considered part of the literary canon taught in schools worldwide.","exja":"シェイクスピアの作品は世界中の学校で教えられる文学の正典の一部と見なされている。"},{"id":4590,"en":"capability","ja":"能力・能力の有無\n実際に何かを実行できる力を表す名詞。abilityより実践的なニュアンス","level":7,"lnum":1,"ex":"The new fighter jet has the capability to travel at twice the speed of sound.","exja":"新しい戦闘機は音速の2倍の速度で飛行する能力を持っている。"},{"id":4591,"en":"caption","ja":"キャプション・字幕\n写真の説明文や動画の字幕を表す名詞","level":7,"lnum":1,"ex":"The photograph was published with a caption explaining who was in the picture.","exja":"写真は写っている人物を説明するキャプション付きで掲載された。"},{"id":4592,"en":"captive","ja":"捕虜・囚人\n捕らえられて閉じ込められている人を指す名詞","level":7,"lnum":1,"ex":"The captive was held in a small cell for several days before being released.","exja":"捕虜は釈放される前の数日間、小さな房に拘置された。"},{"id":4593,"en":"caravan","ja":"キャラバン・幌馬車\n砂漠を旅する隊商や牽引式移動住居を指す名詞","level":7,"lnum":1,"ex":"The caravan of traders crossed the desert, carrying spices and silk.","exja":"商人のキャラバンはスパイスと絹を運びながら砂漠を横断した。"},{"id":4594,"en":"carbon","ja":"炭素\n全有機化合物の基礎となる化学元素。carbon cycle(炭素循環)など","level":7,"lnum":1,"ex":"All living organisms are made up of compounds that contain carbon.","exja":"すべての生き物は炭素を含む化合物から成り立っている。"},{"id":4595,"en":"carbon dioxide","ja":"二酸化炭素\n温室効果ガスの主成分。CO2の正式名称として環境文脈で必須語","level":7,"lnum":1,"ex":"Burning fossil fuels releases large amounts of carbon dioxide into the atmosphere.","exja":"化石燃料を燃やすと大量の二酸化炭素が大気中に放出される。"},{"id":4596,"en":"carbon footprint","ja":"カーボンフットプリント\n個人・組織が排出するCO2量の総量。環境問題で頻出の概念語","level":7,"lnum":1,"ex":"Many companies are working to reduce their carbon footprint by using renewable energy.","exja":"多くの企業が再生可能エネルギーを使ってカーボンフットプリントを削減しようとしている。"},{"id":4597,"en":"carbon monoxide","ja":"一酸化炭素\n不完全燃焼で発生する有毒ガス。COとも略される","level":7,"lnum":1,"ex":"Carbon monoxide is a colorless and odorless gas that can be deadly in enclosed spaces.","exja":"一酸化炭素は無色無臭のガスで、密閉空間では致命的になり得る。"},{"id":4598,"en":"cardigan","ja":"カーディガン\n前開きのボタン付きニットウェアを指す名詞","level":7,"lnum":1,"ex":"She put on a cardigan to keep warm while working in the air-conditioned office.","exja":"彼女はエアコンの効いたオフィスで作業しながら温まるためにカーディガンを羽織った。"},{"id":4599,"en":"carefree","ja":"気楽な・のんきな\n心配事や責任がなく自由な状態を表す形容詞","level":7,"lnum":1,"ex":"She spent a carefree summer at her grandparents' house in the countryside.","exja":"彼女は田舎の祖父母の家で気楽な夏を過ごした。"},{"id":4600,"en":"caring","ja":"思いやりのある・気遣いのできる\n他者の気持ちを大切にする優しい性格を表す形容詞","level":7,"lnum":1,"ex":"He is a caring father who always makes time for his children despite his busy schedule.","exja":"彼は忙しいスケジュールにもかかわらず、常に子供たちのために時間を作る思いやりのある父親だ。"},{"id":4601,"en":"carnival","ja":"カーニバル・祭り\n音楽・仮装・パレードを伴う大規模な祝祭を指す名詞","level":7,"lnum":1,"ex":"The city held its annual carnival with parades, music, and colorful costumes.","exja":"市では毎年恒例のカーニバルが行われ、パレード・音楽・カラフルな衣装が登場した。"},{"id":4602,"en":"carpool","ja":"カープール・相乗り\n複数人が一台の車で通勤・通学を共有する仕組みを指す名詞","level":7,"lnum":1,"ex":"To save money and reduce emissions, three colleagues decided to carpool to work.","exja":"お金を節約し排出ガスを減らすために、3人の同僚は職場まで相乗りすることにした。"},{"id":4603,"en":"carve","ja":"彫る・切り分ける\n木・石・肉などを彫刻したり切り分けたりする動詞","level":7,"lnum":1,"ex":"The craftsman spent hours carefully carving a dragon into the wooden door.","exja":"職人は木製のドアに竜を丁寧に彫るために何時間も費やした。"},{"id":4604,"en":"cascade","ja":"流れ落ちる・連鎖する\n滝のように流れ落ちることや連鎖的に起こることを表す名詞","level":7,"lnum":1,"ex":"Water cascaded down the rocky cliff in a series of small waterfalls.","exja":"水は岩だらけの崖を小さな滝の連続となって流れ落ちた。"},{"id":4605,"en":"cast","ja":"配役・出演者\n映画・演劇の出演者全体を指す名詞","level":7,"lnum":1,"ex":"The angler cast his line into the calm river and waited patiently.","exja":"釣り人は穏やかな川に釣り糸を投げ込み、辛抱強く待った。"},{"id":4606,"en":"cast","ja":"投げる・配役する\n釣り糸を投げる・役者を選ぶなど幅広い意味を持つ動詞","level":7,"lnum":1,"ex":"The director cast a young actress in the lead role.","exja":"監督は若い女優を主役に配役した。"},{"id":4607,"en":"casually","ja":"気軽に・何気なく\n重要でないかのようにさりげなく行動するさまを表す副詞","level":7,"lnum":1,"ex":"She mentioned casually that she had met the famous author at a bookstore.","exja":"彼女は書店で有名な作家に会ったことを何気なく話した。"},{"id":4608,"en":"catalog/catalogue","ja":"カタログ・目録\n商品や情報を一覧にまとめた資料を指す名詞","level":7,"lnum":1,"ex":"The store published a new catalog with this season's products.","exja":"その店は今シーズンの商品を掲載した新しいカタログを発行した。"},{"id":4609,"en":"catalyst","ja":"触媒・きっかけ\n化学反応を促進する物質。比喩的に変化を引き起こすきっかけも指す","level":7,"lnum":1,"ex":"The oil crisis in the 1970s acted as a catalyst for the development of alternative energy sources.","exja":"1970年代の石油危機は代替エネルギー源の開発のきっかけとなった。"},{"id":4610,"en":"catastrophe","ja":"大惨事・大災害\n非常に大きな被害をもたらす出来事を表す格式のある名詞","level":7,"lnum":1,"ex":"The earthquake was one of the worst natural catastrophes the region had ever seen.","exja":"その地震はその地域がこれまでに経験した最悪の自然大惨事の一つだった。"},{"id":4611,"en":"catastrophic","ja":"壊滅的な・大惨事の\n被害や結果が非常に深刻であることを表す形容詞","level":7,"lnum":1,"ex":"The explosion had a catastrophic impact on the surrounding neighborhoods.","exja":"爆発は周辺の地区に壊滅的な影響を与えた。"},{"id":4612,"en":"catchy","ja":"耳に残る・覚えやすい\nメロディーやフレーズがすぐに記憶に残る魅力を表す形容詞","level":7,"lnum":1,"ex":"The advertising team came up with a catchy slogan that everyone remembered.","exja":"広告チームは誰もが覚えられるキャッチーなスローガンを考え出した。"},{"id":4613,"en":"categorization/categorisation","ja":"分類・カテゴリー分け\n情報やものをグループ分けするプロセスを表す名詞","level":7,"lnum":1,"ex":"The categorization of species helps scientists study biodiversity.","exja":"種の分類は科学者が生物多様性を研究するのに役立つ。"},{"id":4614,"en":"catering","ja":"ケータリング・食事提供サービス\nイベントや施設向けに食事を準備・提供する事業を指す名詞","level":7,"lnum":1,"ex":"The wedding reception catering was handled by a well-known local restaurant.","exja":"結婚披露宴のケータリングは地元の有名レストランが担当した。"},{"id":4615,"en":"cathedral","ja":"大聖堂・カテドラル\n司教が管轄する大型キリスト教教会を指す名詞","level":7,"lnum":1,"ex":"The Gothic cathedral took over two hundred years to complete.","exja":"そのゴシック様式の大聖堂は完成までに200年以上かかった。"},{"id":4616,"en":"cease","ja":"止まる・やめる\n活動・行為が完全に終わることを表すフォーマルな動詞","level":7,"lnum":1,"ex":"The factory was ordered to cease production until safety issues were resolved.","exja":"工場は安全上の問題が解決されるまで生産を停止するよう命じられた。"},{"id":4617,"en":"cellar","ja":"地下室・貯蔵室\n建物の地下にある部屋。wine cellar(ワイン貯蔵庫)が典型例","level":7,"lnum":1,"ex":"The old farmhouse had a cool cellar where vegetables were stored throughout winter.","exja":"古い農家には冬の間中野菜を保存する涼しい地下室があった。"},{"id":4618,"en":"cellist","ja":"チェロ奏者\nチェロという弦楽器を演奏する音楽家を指す名詞","level":7,"lnum":1,"ex":"The cellist played a deeply moving solo piece at the chamber music concert.","exja":"チェロ奏者は室内楽コンサートで深く心を動かすソロ曲を演奏した。"},{"id":4619,"en":"cello","ja":"チェロ\nヴァイオリン族の大型弦楽器。低音を担当するオーケストラの主要楽器","level":7,"lnum":1,"ex":"The mellow sound of the cello filled the concert hall with warm, rich tones.","exja":"チェロの柔らかな音色がコンサートホールを温かく豊かな響きで満たした。"},{"id":4620,"en":"cemetery","ja":"墓地\n遺体が埋葬されている場所。churchyard(教会付属の墓地)より広い概念","level":7,"lnum":1,"ex":"The soldiers who fell in the war are buried in a national cemetery nearby.","exja":"戦争で倒れた兵士たちは近くの国立墓地に埋葬されている。"},{"id":4621,"en":"centigrade","ja":"摂氏\n温度の単位。Celsius(セルシウス)と同義。0℃が水の氷点","level":7,"lnum":1,"ex":"Water boils at one hundred degrees centigrade at sea level.","exja":"水は海面では摂氏100度で沸騰する。"},{"id":4622,"en":"certificate","ja":"証明書・資格証\n資格・修了・事実を公式に証明する文書を指す名詞","level":7,"lnum":1,"ex":"Students who complete the course will receive a certificate of completion.","exja":"コースを修了した学生には修了証明書が授与される。"},{"id":4623,"en":"certification","ja":"認定・認証\n資格や基準を満たしていることを公式に認定するプロセスを表す名詞","level":7,"lnum":1,"ex":"She earned a professional certification in project management after completing the course.","exja":"コースを修了した後、彼女はプロジェクトマネジメントの専門認定資格を取得した。"},{"id":4624,"en":"certify","ja":"証明する・認定する\n公式に正しいまたは資格があると証明する動詞","level":7,"lnum":1,"ex":"The laboratory is certified to conduct food safety testing.","exja":"その研究所は食品安全検査を実施する認定を受けている。"},{"id":4625,"en":"chancellor","ja":"首相・大臣・学長\nドイツ首相・英財務大臣・大学の学長など役職を指す名詞","level":7,"lnum":1,"ex":"The chancellor announced a series of new economic policies in his budget speech.","exja":"首相は予算演説で一連の新しい経済政策を発表した。"},{"id":4626,"en":"chaotic","ja":"混乱した・無秩序な\nchaos(混乱)の形容詞形。秩序が全くない状況を表す","level":7,"lnum":1,"ex":"The situation in the disaster zone was chaotic, with thousands of people in need of help.","exja":"災害地域の状況は混乱しており、何千人もの人々が助けを必要としていた。"},{"id":4627,"en":"characteristic","ja":"特有の・独特の\n形容詞として特定の人・物・場所に典型的な性質を表す","level":7,"lnum":1,"ex":"Punctuality is characteristic of Japanese culture and is highly valued in the workplace.","exja":"時間厳守は日本文化に特有であり、職場でも高く評価されている。"},{"id":4628,"en":"charming","ja":"魅力的な・素敵な\n人・場所・物が心地よい魅力を持つときに使う形容詞","level":7,"lnum":1,"ex":"The small coastal village was absolutely charming, with its colorful boats and seafood restaurants.","exja":"その小さな沿岸の村はカラフルなボートとシーフードレストランで本当に魅力的だった。"},{"id":4629,"en":"chase","ja":"追いかける・追跡する\n人・動物・目標を素早く後を追うことを表す動詞","level":7,"lnum":1,"ex":"The police chased the suspect through the crowded market before finally catching him.","exja":"警察は混雑した市場を通って容疑者を追いかけ、ようやく捕まえた。"},{"id":4630,"en":"cheat","ja":"ずるをする・だます\n試験での不正行為や人を欺く行為を表す動詞","level":7,"lnum":1,"ex":"Students who cheat on exams risk being expelled from the university.","exja":"試験でずるをする学生は大学から退学させられる危険を冒している。"},{"id":4631,"en":"checkpoint","ja":"検問所・チェックポイント\n通過者を確認・管理する地点。ゲームのセーブポイントにも使う","level":7,"lnum":1,"ex":"All vehicles must stop at the checkpoint for inspection before entering the secure area.","exja":"すべての車両は安全区域に入る前に検問所で検査のために停車しなければならない。"},{"id":4632,"en":"cheeky","ja":"生意気な・ずうずうしい\n軽く失礼だが愛嬌のある行動に使う形容詞。英国英語で多用","level":7,"lnum":1,"ex":"He gave a cheeky grin when the teacher caught him passing notes in class.","exja":"授業中に先生にメモを回しているのを見つかったとき、彼は生意気な笑みを浮かべた。"},{"id":4633,"en":"cheerfulness","ja":"陽気さ・快活さ\ncheerful(陽気な)の名詞形。喜びにあふれた性質を表す","level":7,"lnum":1,"ex":"Her natural cheerfulness made her popular with everyone she met.","exja":"彼女の生まれ持った陽気さは彼女が会う全員に好かれる理由になった。"},{"id":4634,"en":"chemotherapy","ja":"化学療法・抗がん剤治療\nがん治療で使われる薬物療法を指す医学用語","level":7,"lnum":1,"ex":"She underwent six months of chemotherapy to treat her cancer.","exja":"彼女はがんを治療するために6ヶ月間の化学療法を受けた。"},{"id":4635,"en":"cherished","ja":"大切にされている・愛しい\n大切に保存・愛されている思い出・物・人を表す形容詞","level":7,"lnum":1,"ex":"That old photograph is one of her most cherished possessions.","exja":"その古い写真は彼女の最も大切にしている思い出の品の一つだ。"},{"id":4636,"en":"chief","ja":"長・トップ・主要な\n組織の最高責任者または形容詞として「最も重要な」の意","level":7,"lnum":1,"ex":"The chief concern of the board was maintaining the company's financial stability.","exja":"取締役会の主な懸念事項は会社の財政的安定を維持することだった。"},{"id":4637,"en":"childish","ja":"子供っぽい・幼稚な\n大人がすべきでないような未熟な行動を批判するときに使う形容詞","level":7,"lnum":1,"ex":"His childish behavior at the meeting embarrassed his colleagues.","exja":"会議での彼の子供っぽい行動は同僚たちを恥ずかしくさせた。"},{"id":4638,"en":"chimney","ja":"煙突\n燃焼した煙を外に出す縦型の筒状構造物を指す名詞","level":7,"lnum":1,"ex":"Smoke rose from every chimney in the village on the cold winter morning.","exja":"寒い冬の朝、村のすべての煙突から煙が上がっていた。"},{"id":4639,"en":"chop","ja":"叩き切る・みじん切りにする\n包丁や斧で勢いよく切ることを表す動詞","level":7,"lnum":1,"ex":"She chopped the vegetables finely before adding them to the soup.","exja":"彼女は野菜をスープに加える前に細かく刻んだ。"},{"id":4640,"en":"chunk","ja":"塊・大きな断片\n比較的大きな不規則な形の部分を表す名詞。a chunk of〜が頻出","level":7,"lnum":1,"ex":"He spent a large chunk of his savings on a new laptop for university.","exja":"彼は大学用の新しいノートパソコンに貯金のかなりの部分を使った。"},{"id":4641,"en":"circuit","ja":"回路・サーキット\n電気回路や自動車レースのコースを指す名詞","level":7,"lnum":1,"ex":"An electrician was called to repair the short circuit in the building's wiring.","exja":"ビルの配線のショートした回路を修理するために電気技師が呼ばれた。"},{"id":4642,"en":"circuitry","ja":"回路網・電子回路\n回路の集合体または電子システム全体を指す名詞","level":7,"lnum":1,"ex":"The advanced circuitry in the device allowed it to process data at incredible speed.","exja":"その機器の高度な回路網は信じられないほどの速さでデータを処理することを可能にした。"},{"id":4643,"en":"circumstance","ja":"状況・事情・境遇\nunder the circumstances(その状況では)など熟語表現が多い名詞","level":7,"lnum":1,"ex":"Under the current circumstances, it would be unwise to make any major decisions.","exja":"現在の状況下では、大きな決断を下すことは賢明ではないだろう。"},{"id":4644,"en":"citywide","ja":"市全体の・全市的な\n都市全体に及ぶ政策・イベント・問題を表す形容詞","level":7,"lnum":1,"ex":"The mayor announced a citywide ban on single-use plastic bags.","exja":"市長は使い捨てプラスチック袋の市全体での禁止を発表した。"},{"id":4645,"en":"clam","ja":"蛤・二枚貝\n砂浜に住む二枚貝。clam up(黙り込む)という慣用表現も重要","level":7,"lnum":1,"ex":"They collected fresh clams along the beach and cooked them for dinner.","exja":"彼らは浜辺で新鮮な蛤を採集し、夕食に調理した。"},{"id":4646,"en":"clarify","ja":"明確にする・はっきりさせる\n曖昧な点を分かりやすく説明するときに使う動詞","level":7,"lnum":1,"ex":"Could you clarify what you meant by your earlier comment?","exja":"先ほどのコメントの意味をもう少し明確にしてもらえますか？"},{"id":4647,"en":"classification","ja":"分類・区分\nものを種類別に整理するシステムまたは行為を表す名詞","level":7,"lnum":1,"ex":"The classification of the documents made it easier for staff to locate specific files.","exja":"書類の分類により、スタッフが特定のファイルを見つけやすくなった。"},{"id":4648,"en":"clause","ja":"節・条項\n文法の節(主語+動詞を含む単位)または法律・契約の条項を指す名詞","level":7,"lnum":1,"ex":"The final clause of the contract stated that disputes would be settled by arbitration.","exja":"契約の最終条項は、紛争は仲裁によって解決されると述べていた。"},{"id":4649,"en":"clearness","ja":"明確さ・透明性\nclarity より日常的な「はっきりしている状態」を表す名詞","level":7,"lnum":1,"ex":"The clearness of the instructions made it easy for everyone to follow the procedure.","exja":"指示の明確さのおかげで、全員が手順に従いやすかった。"},{"id":4650,"en":"clerical","ja":"事務の・聖職者の\n事務作業に関するまたは聖職者(神父・牧師)に関係する形容詞","level":7,"lnum":1,"ex":"She took on a clerical role at the office while waiting to be promoted.","exja":"昇進を待つ間、彼女はオフィスで事務職を担当した。"},{"id":4651,"en":"client","ja":"顧客・依頼人\nサービスや専門家の助けを受ける人を指す名詞。customerより専門的","level":7,"lnum":1,"ex":"The lawyer advised her client to remain silent until they arrived at the police station.","exja":"弁護士は依頼人に警察署に到着するまで黙秘するよう助言した。"},{"id":4652,"en":"climate change","ja":"気候変動\n地球規模の気温・気象パターンの長期的変化を指す環境用語","level":7,"lnum":1,"ex":"Scientists agree that climate change poses one of the greatest threats to humanity.","exja":"科学者たちは気候変動が人類にとって最大の脅威の一つであることに同意している。"},{"id":4653,"en":"clog","ja":"詰まらせる・妨げる\n水道や道路が詰まって流れなくなることを表す動詞","level":7,"lnum":1,"ex":"Fallen leaves had clogged the drainpipes, causing the garden to flood.","exja":"落ち葉が排水管を詰まらせ、庭が浸水した。"},{"id":4654,"en":"closure","ja":"閉鎖・終結・心の区切り\n施設の永久閉鎖・話の終わり・心の整理を表す多義語の名詞","level":7,"lnum":1,"ex":"The closure of the factory left hundreds of workers without jobs.","exja":"工場の閉鎖で何百人もの労働者が職を失った。"},{"id":4655,"en":"clothing","ja":"衣類・衣料品\n着るものの総称。clothesより少し格式がある集合名詞","level":7,"lnum":1,"ex":"She donated a bag of clothing she no longer needed to the local charity shop.","exja":"彼女はもう必要なくなった衣類の袋を地元のチャリティショップに寄付した。"},{"id":4656,"en":"clumsy","ja":"不器用な・ぶきっちょな\n動きが不器用で物を落としやすい様子を表す形容詞","level":7,"lnum":1,"ex":"He was always considered clumsy as a child because he often knocked things over.","exja":"子供の頃、彼はよく物を倒してしまうのでいつも不器用だと思われていた。"},{"id":4657,"en":"coaching","ja":"コーチング・指導\nスキル向上のために個別指導を行うことを表す名詞","level":7,"lnum":1,"ex":"The company hired a business coach to provide coaching for its senior managers.","exja":"会社はシニアマネージャーにコーチングを提供するためにビジネスコーチを雇った。"},{"id":4658,"en":"coalition","ja":"連立・連合\n異なるグループが共通目的で結ぶ一時的な連合体を表す名詞","level":7,"lnum":1,"ex":"The opposition parties formed a coalition to challenge the ruling government.","exja":"野党はその連立政権に対抗するために連合を結成した。"},{"id":4659,"en":"coarse","ja":"粗い・粗雑な\n質感が粗い・言動が下品なことを表す形容詞。course と混同しないこと","level":7,"lnum":1,"ex":"The coarse fabric of the sack made his hands itch when he carried it.","exja":"袋の粗い布地は彼が持ち運ぶ際に手がかゆくなった。"},{"id":4660,"en":"coastline","ja":"海岸線\n海と陸が接する線の形状や全体を表す名詞","level":7,"lnum":1,"ex":"The rocky coastline stretches for hundreds of kilometers along the northern shore.","exja":"岩だらけの海岸線は北岸に沿って何百キロにもわたって続いている。"},{"id":4661,"en":"cocktail","ja":"カクテル・混合物\n複数の酒を混ぜた飲み物。比喩的に「混ぜ合わさったもの」にも使う","level":7,"lnum":1,"ex":"She sipped a refreshing cocktail by the pool while reading her book.","exja":"彼女はプールのそばで本を読みながらさわやかなカクテルを少しずつ飲んだ。"},{"id":4662,"en":"cocoa","ja":"ココア・カカオ\nチョコレートの原料カカオの粉末または飲み物を指す名詞","level":7,"lnum":1,"ex":"She made a warm cup of cocoa to comfort herself on the cold winter evening.","exja":"寒い冬の夜、彼女は気分を和らげるために温かいカップ一杯のコーヒーを作った。"},{"id":4663,"en":"coconut","ja":"ヤシの実・ococonut\n熱帯のヤシの木に実る果実を指す名詞","level":7,"lnum":1,"ex":"He cracked open a coconut and enjoyed the refreshing water inside.","exja":"彼はヤシの実を割り、中の爽やかな水を楽しんだ。"},{"id":4664,"en":"coherence","ja":"一貫性・まとまり\n論理・文章・計画がひとつにまとまっている状態を表す名詞","level":7,"lnum":1,"ex":"The essay lacked coherence because the ideas were not logically connected.","exja":"そのエッセイはアイデアが論理的に結びついていないため、一貫性に欠けていた。"},{"id":4665,"en":"coherent","ja":"一貫した・筋の通った\n論理・議論・文章が整然として理解しやすいことを表す形容詞","level":7,"lnum":1,"ex":"The politician struggled to give a coherent explanation of the new policy.","exja":"その政治家は新しい政策の一貫した説明をしようとするのに苦労した。"},{"id":4666,"en":"coincide","ja":"一致する・同時に起こる\n時間・場所・考えが重なることを表す動詞。coincide with〜が基本形","level":7,"lnum":1,"ex":"Her birthday happened to coincide with the opening of the new art gallery.","exja":"彼女の誕生日はちょうど新しいアートギャラリーのオープンと重なった。"},{"id":4667,"en":"coincidence","ja":"偶然の一致\n計画なく同時に似たことが起こること。what a coincidence!(なんと偶然)が定型表現","level":7,"lnum":1,"ex":"What a coincidence that we both chose the same destination for our holiday!","exja":"同じ休暇先を選んだとは何という偶然の一致だろう！"},{"id":4668,"en":"collapse","ja":"崩れる・倒れる・崩壊する\n建物・体制・体力が一気に倒れる・失敗することを表す動詞","level":7,"lnum":1,"ex":"The old bridge collapsed under the weight of the heavy truck.","exja":"古い橋は重いトラックの重さに耐えられず崩れ落ちた。"},{"id":4669,"en":"colleague","ja":"同僚・同期\n同じ職場や専門分野で働く仲間を指す名詞","level":7,"lnum":1,"ex":"She discussed the project proposal with her colleague over lunch.","exja":"彼女は昼食を取りながら同僚とプロジェクト提案について話し合った。"},{"id":4670,"en":"collector","ja":"コレクター・収集家\n趣味や職業として物を集める人を指す名詞","level":7,"lnum":1,"ex":"He is an avid collector of vintage coins from around the world.","exja":"彼は世界中のヴィンテージコインの熱心なコレクターだ。"},{"id":4671,"en":"collocation","ja":"コロケーション・語の共起\n自然に一緒に使われる単語の組み合わせを指す言語学用語","level":7,"lnum":1,"ex":"Learning collocations is essential for sounding natural in a foreign language.","exja":"コロケーションを学ぶことは外国語で自然に聞こえるために不可欠だ。"},{"id":4672,"en":"colon","ja":"コロン・結腸\n文法の記号(:)または消化器官の大腸の一部を指す多義語","level":7,"lnum":1,"ex":"The teacher reminded the students to use a colon before a list of items.","exja":"教師は項目のリストの前にコロンを使うよう生徒たちに注意した。"},{"id":4673,"en":"colonial","ja":"植民地の・植民地時代の\n植民地支配に関わる歴史・文化・建築に使う形容詞","level":7,"lnum":1,"ex":"The building's colonial architecture reflects the history of the island.","exja":"その建物の植民地時代の建築様式は島の歴史を反映している。"},{"id":4674,"en":"coma","ja":"昏睡状態\n意識を失った深い眠りのような状態。in a coma(昏睡状態で)が頻出","level":7,"lnum":1,"ex":"The accident victim remained in a coma for two weeks before regaining consciousness.","exja":"事故の被害者は意識を取り戻す前の2週間、昏睡状態のままだった。"},{"id":4675,"en":"comfortably","ja":"快適に・楽々と\n身体的・経済的に余裕がある状態で行動するさまを表す副詞","level":7,"lnum":1,"ex":"The apartment is large enough to comfortably house a family of four.","exja":"そのアパートは4人家族が快適に暮らせるほど広い。"},{"id":4676,"en":"commander","ja":"指揮官・司令官\n軍や組織を指揮する立場にある人を指す名詞","level":7,"lnum":1,"ex":"The army commander ordered his troops to advance at dawn.","exja":"軍の指揮官は夜明けに軍を前進させるよう命令した。"},{"id":4677,"en":"commemorate","ja":"記念する・追悼する\n重要な出来事・人物を記念行事で祝ったり悼んだりする動詞","level":7,"lnum":1,"ex":"A ceremony was held to commemorate the hundredth anniversary of the battle.","exja":"戦いの100周年を記念する式典が開催された。"},{"id":4678,"en":"commerce","ja":"商業・通商\n商品・サービスの売買全般を指すやや格式のある名詞","level":7,"lnum":1,"ex":"The development of the internet has transformed global commerce significantly.","exja":"インターネットの発展は世界の商業を大きく変えた。"},{"id":4679,"en":"commercial","ja":"コマーシャル・広告放送\nテレビ・ラジオの広告番組を指す名詞","level":7,"lnum":1,"ex":"The new commercial aired during the game and became an instant hit.","exja":"試合中に流された新しいコマーシャルはすぐに人気を呼んだ。"},{"id":4680,"en":"commission","ja":"委託・委員会・手数料\n仕事の依頼・組織・報酬など複数の意味を持つ重要名詞","level":7,"lnum":1,"ex":"The artist received a commission to create a mural for the city hall.","exja":"芸術家は市庁舎のための壁画を制作する依頼を受けた。"},{"id":4681,"en":"commonwealth","ja":"連邦・共同体\n英連邦(Commonwealth of Nations)や共同利益で結ぶ国家連合を指す","level":7,"lnum":1,"ex":"Several former British colonies are now members of the Commonwealth.","exja":"いくつかの旧イギリス植民地は現在、英連邦の加盟国となっている。"},{"id":4682,"en":"communicative","ja":"話し好きな・意思疎通が得意な\n自分の考えを積極的に伝えようとする性質を表す形容詞","level":7,"lnum":1,"ex":"A communicative teacher encourages students to speak up and share ideas in class.","exja":"話し好きな教師は生徒たちが授業で発言し考えを共有することを促す。"},{"id":4683,"en":"commute","ja":"通勤する・通学する\n職場・学校へ毎日往復する行為を表す動詞","level":7,"lnum":1,"ex":"She commutes to work by train every day, which takes about forty minutes.","exja":"彼女は毎日電車で通勤しており、約40分かかる。"},{"id":4684,"en":"compassion","ja":"思いやり・同情心\n他者の苦しみを理解し助けようとする感情を表す名詞","level":7,"lnum":1,"ex":"The relief workers showed great compassion toward the victims of the flood.","exja":"救援活動員たちは洪水の被害者に大きな思いやりを示した。"},{"id":4685,"en":"compassionate","ja":"思いやりのある\ncompassion(思いやり)の形容詞形。苦しむ人への共感と優しさを表す","level":7,"lnum":1,"ex":"The compassionate nurse held the patient's hand and offered words of comfort.","exja":"思いやりのある看護師は患者の手を握り、慰めの言葉をかけた。"},{"id":4686,"en":"compatible","ja":"相性のいい・互換性のある\n二つのものが共存・協力できる適合性を表す形容詞","level":7,"lnum":1,"ex":"Check that the software is compatible with your operating system before installing it.","exja":"インストールする前にソフトウェアがお使いのオペレーティングシステムと互換性があるか確認してください。"},{"id":4687,"en":"compensate","ja":"補償する・埋め合わせる\n損失・不利益に対して補いをする動詞。compensate for〜が基本形","level":7,"lnum":1,"ex":"The airline offered vouchers to compensate passengers for the long delay.","exja":"航空会社は長時間の遅延の補償として乗客にクーポン券を提供した。"},{"id":4688,"en":"compensation","ja":"補償・賠償金・報酬\n損害を補う金銭や代替を表す名詞","level":7,"lnum":1,"ex":"Workers injured on the job are entitled to financial compensation from their employer.","exja":"仕事中に負傷した労働者は雇用主から財政的な補償を受ける権利がある。"},{"id":4689,"en":"competence","ja":"能力・コンピテンス\n特定の仕事を適切にこなせる技能と知識の総体を表す名詞","level":7,"lnum":1,"ex":"Her years of experience gave her the competence needed to lead the team effectively.","exja":"長年の経験が彼女にチームを効果的にリードするために必要な能力を与えた。"},{"id":4690,"en":"competent","ja":"有能な・適切な\n必要な能力・知識を持つ人に使う形容詞。incompetentの対義語","level":7,"lnum":1,"ex":"He is a competent engineer who has successfully managed many large-scale projects.","exja":"彼は多くの大規模なプロジェクトを成功裏に管理してきた有能なエンジニアだ。"},{"id":4691,"en":"compile","ja":"まとめる・編集する\n情報・データ・法律などを収集して整理する動詞","level":7,"lnum":1,"ex":"She compiled a list of useful resources for her students to use during the research project.","exja":"彼女はリサーチプロジェクト中に生徒たちが使える有用なリソースのリストをまとめた。"},{"id":4692,"en":"completion","ja":"完成・修了\n仕事・コース・工事が最後まで終わることを表す名詞","level":7,"lnum":1,"ex":"Upon completion of the course, participants will be awarded a professional certificate.","exja":"コース修了後、参加者には専門資格証明書が授与される。"},{"id":4693,"en":"complexion","ja":"肌の色・顔色\n肌の色合いや質感を表す名詞。change the complexion of〜(様相を変える)の比喩も","level":7,"lnum":1,"ex":"The actor's fair complexion made him stand out in the crowd.","exja":"その俳優の色白の肌色は人混みの中でも目立っていた。"},{"id":4694,"en":"compute","ja":"計算する\ncomputerの語源。大規模な数値計算に使うフォーマルな語","level":7,"lnum":1,"ex":"Modern computers can compute complex equations in milliseconds.","exja":"現代のコンピューターは複雑な方程式をミリ秒単位で計算できる。"},{"id":4695,"en":"conceal","ja":"隠す・秘密にする\nhideより意図的なニュアンス。真実・感情・物を隠す場面で使う","level":7,"lnum":1,"ex":"She tried to conceal her disappointment with a smile.","exja":"彼女は笑顔で失望を隠そうとした。"},{"id":4696,"en":"concede","ja":"認める・譲歩する\n渋々認めるニュアンス。議論・選挙での敗北認定に頻出","level":7,"lnum":1,"ex":"After a long debate, he finally conceded that his opponent had a point.","exja":"長い議論の末、彼はついに相手にも一理あると認めた。"},{"id":4697,"en":"conceit","ja":"うぬぼれ\n自分の能力を過大評価する態度。形容詞はconceited","level":7,"lnum":1,"ex":"His conceit made it impossible for him to accept criticism.","exja":"うぬぼれのせいで、彼は批判を受け入れることができなかった。"},{"id":4698,"en":"conceivable","ja":"考えられる・想像できる\nevery conceivable wayのように「あらゆる」の強調でよく使う","level":7,"lnum":1,"ex":"The team explored every conceivable solution to the problem.","exja":"チームはその問題に対してあらゆる考えられる解決策を探った。"},{"id":4699,"en":"conceive","ja":"思いつく・妊娠する\n抽象的なアイデアを「生み出す」感覚。品詞に注意","level":7,"lnum":1,"ex":"It is hard to conceive of a world without the internet.","exja":"インターネットのない世界を想像するのは難しい。"},{"id":4700,"en":"conception","ja":"概念・妊娠\nabstractやbasic conception（基本概念）の形で使われやすい","level":7,"lnum":1,"ex":"His conception of justice was very different from hers.","exja":"正義についての彼の概念は彼女のものとは大きく異なっていた。"},{"id":4701,"en":"concern","ja":"関係する・心配させる\n名詞のconcernも重要。as far as ... is concernedは頻出表現","level":7,"lnum":1,"ex":"The rising unemployment rate concerns many economists.","exja":"失業率の上昇は多くの経済学者を心配させている。"},{"id":4702,"en":"concerning","ja":"〜に関して\n前置詞用法。aboutより書き言葉的・フォーマルな表現","level":7,"lnum":1,"ex":"The doctor had some questions concerning the patient's medical history.","exja":"医師は患者の病歴に関していくつかの質問をした。"},{"id":4703,"en":"concession","ja":"譲歩・特許権\nmake a concessionで「譲歩する」。交渉場面で頻出","level":7,"lnum":1,"ex":"The union made a concession on wages to reach a settlement.","exja":"組合は和解に達するために賃金について譲歩した。"},{"id":4704,"en":"concrete","ja":"具体的な\n名詞の「コンクリート」と区別。in concrete termsで「具体的には」","level":7,"lnum":1,"ex":"The bridge was built with reinforced concrete to withstand earthquakes.","exja":"その橋は地震に耐えられるよう鉄筋コンクリートで建設された。"},{"id":4705,"en":"concrete","ja":"コンクリート\n建築材料。形容詞と同形なので品詞に注意して文脈で判断する","level":7,"lnum":1,"ex":"We need concrete evidence before making any decision.","exja":"何か決断する前に具体的な証拠が必要だ。"},{"id":4706,"en":"condemn","ja":"非難する・刑を宣告する\n強い否定的評価を示す語。condemnation（非難）も覚える","level":7,"lnum":1,"ex":"World leaders condemned the attack as an act of terrorism.","exja":"世界のリーダーたちはその攻撃をテロ行為として非難した。"},{"id":4707,"en":"conduct","ja":"行う・指揮する\nconduct a survey（調査を行う）など名詞との区別も重要","level":7,"lnum":1,"ex":"The university will conduct a survey on students' mental health.","exja":"大学は学生のメンタルヘルスに関する調査を実施する予定だ。"},{"id":4708,"en":"conductor","ja":"指揮者・車掌\nオーケストラの指揮者と電車の車掌の両義に注意する","level":7,"lnum":1,"ex":"The conductor raised her baton and the orchestra began to play.","exja":"指揮者が指揮棒を上げ、オーケストラが演奏を始めた。"},{"id":4709,"en":"cone","ja":"円錐・松かさ\n数学用語と自然物の両方で使う。ice cream coneも日常的","level":7,"lnum":1,"ex":"The children ate ice cream cones while walking through the park.","exja":"子どもたちは公園を歩きながらアイスクリームコーンを食べた。"},{"id":4710,"en":"conference","ja":"会議・学会\npress conferenceなど複合語も多い。大規模な会議を指す","level":7,"lnum":1,"ex":"More than 500 scientists attended the international conference on climate change.","exja":"500人以上の科学者が気候変動に関する国際会議に参加した。"},{"id":4711,"en":"conferencing","ja":"テレビ会議\nvideo conferencingの形で現代ビジネス英語に頻出","level":7,"lnum":1,"ex":"Our team uses video conferencing to hold meetings with overseas partners.","exja":"私たちのチームは海外のパートナーとの会議にテレビ会議を利用している。"},{"id":4712,"en":"confess","ja":"告白する・自白する\n罪や秘密を認める行為。confession（告白）とセットで覚える","level":7,"lnum":1,"ex":"He confessed that he had been cheating on the exam.","exja":"彼は試験でカンニングをしていたと告白した。"},{"id":4713,"en":"confession","ja":"告白・自白\nmake a confessionの形が定番。宗教的な意味もある","level":7,"lnum":1,"ex":"The suspect's confession was the key piece of evidence in the trial.","exja":"容疑者の自白が裁判における重要な証拠となった。"},{"id":4714,"en":"confidently","ja":"自信を持って\nconfident→confidenceとの関連で覚える。行動を修飾することが多い","level":7,"lnum":1,"ex":"She walked into the interview room confidently and shook the interviewer's hand.","exja":"彼女は自信を持って面接室に入り、面接官と握手した。"},{"id":4715,"en":"confine","ja":"閉じ込める・限定する\nbe confined toで「〜に限定される」。制限のニュアンスが強い","level":7,"lnum":1,"ex":"Due to the injury, he was confined to bed for two weeks.","exja":"けがのために、彼は2週間ベッドに閉じ込められた。"},{"id":4716,"en":"confront","ja":"直面する・対立する\n問題や困難に正面から向き合うこと。confrontation（対立）も重要","level":7,"lnum":1,"ex":"We must confront the challenges of climate change head-on.","exja":"気候変動の課題に正面から向き合わなければならない。"},{"id":4717,"en":"conjunction","ja":"接続詞・結合\nin conjunction withで「〜と連携して」という表現が頻出","level":7,"lnum":1,"ex":"The festival was held in conjunction with the city's founding anniversary.","exja":"その祭りは市の創立記念日に合わせて開催された。"},{"id":4718,"en":"conquest","ja":"征服・克服\nmilitaryやterritorialと組み合わせて使われることが多い","level":7,"lnum":1,"ex":"Alexander the Great is known for his conquest of much of the ancient world.","exja":"アレクサンダー大王は古代世界の多くを征服したことで知られている。"},{"id":4719,"en":"conscience","ja":"良心\nhave a clear conscienceで「やましいことがない」。発音注意","level":7,"lnum":1,"ex":"She couldn't sleep because her conscience was troubled by what she had done.","exja":"彼女は自分がしたことに良心が痛んで眠れなかった。"},{"id":4720,"en":"consciousness","ja":"意識・意識的状態\nlose/regain consciousnessで医療文脈にも頻出する重要語","level":7,"lnum":1,"ex":"The patient slowly regained consciousness after the surgery.","exja":"患者は手術後、徐々に意識を取り戻した。"},{"id":4721,"en":"consensus","ja":"合意・総意\nreach a consensusで「合意に達する」。民主的決定を表す","level":7,"lnum":1,"ex":"The committee reached a consensus on the new policy after hours of discussion.","exja":"委員会は何時間もの議論の末、新しい政策について合意に達した。"},{"id":4722,"en":"consent","ja":"同意・承諾\ngive consentまたはby mutual consentの形で頻出する","level":7,"lnum":1,"ex":"You must obtain informed consent from participants before conducting the experiment.","exja":"実験を行う前に参加者から十分な説明に基づく同意を得なければならない。"},{"id":4723,"en":"considerably","ja":"かなり・相当に\n程度を強調する副詞。significantlyと同義だがやや口語的","level":7,"lnum":1,"ex":"The number of students enrolling in online courses has grown considerably.","exja":"オンラインコースに登録する学生の数はかなり増えている。"},{"id":4724,"en":"considering","ja":"〜を考慮すると\n接続詞・前置詞の両用法。Considering that...の形が最頻出","level":7,"lnum":1,"ex":"She did an excellent job, considering it was her first attempt.","exja":"初めての挑戦であることを考えると、彼女は素晴らしい仕事をした。"},{"id":4725,"en":"considering","ja":"〜を考えると\n前置詞用法。Considering his age（年齢を考えれば）などで使う","level":7,"lnum":1,"ex":"Considering his age, he performed remarkably well in the competition.","exja":"年齢を考えると、彼は大会で目覚ましい活躍をした。"},{"id":4726,"en":"consistent","ja":"一貫した・矛盾のない\nbe consistent withで「〜と一致する」。論文でも頻出","level":7,"lnum":1,"ex":"Her grades have been consistent throughout the year.","exja":"彼女の成績は1年を通じて一貫していた。"},{"id":4727,"en":"consolation","ja":"慰め\nconsolation prize（残念賞）という複合語が試験に出やすい","level":7,"lnum":1,"ex":"Winning second place was little consolation after training so hard.","exja":"あれほど懸命に練習した後では、2位入賞はほとんど慰めにならなかった。"},{"id":4728,"en":"console","ja":"慰める\n悲しんでいる人に寄り添うイメージ。名詞の「コンソール」とは別語","level":7,"lnum":1,"ex":"He tried to console his friend after the loss of her dog.","exja":"彼は友人が犬を亡くした後、彼女を慰めようとした。"},{"id":4729,"en":"constant","ja":"絶え間ない・一定の\nconstantlyとセットで覚える。変化しないことを強調する","level":7,"lnum":1,"ex":"The constant noise from the construction site made it hard to concentrate.","exja":"工事現場からの絶え間ない騒音のせいで集中するのが難しかった。"},{"id":4730,"en":"consult","ja":"相談する・参照する\nconsult a doctorのようにwithなしで使えることに注意","level":7,"lnum":1,"ex":"If your symptoms persist, you should consult a doctor immediately.","exja":"症状が続く場合は、すぐに医師に相談すべきだ。"},{"id":4731,"en":"consultant","ja":"コンサルタント\n専門的アドバイスを提供する職業人。business consultantが典型","level":7,"lnum":1,"ex":"The company hired a management consultant to improve efficiency.","exja":"会社は効率を改善するために経営コンサルタントを雇った。"},{"id":4732,"en":"contaminate","ja":"汚染する\n水・食品・空気の汚染に使う。pollutionより化学的汚染に近い","level":7,"lnum":1,"ex":"The factory's waste contaminated the nearby river.","exja":"工場の廃棄物が近くの川を汚染した。"},{"id":4733,"en":"contemporary","ja":"現代の・同時代の\n名詞でも使い「同時代の人」の意味になる点に注意","level":7,"lnum":1,"ex":"The museum focuses on contemporary art from around the world.","exja":"その美術館は世界各地の現代アートを専門に扱っている。"},{"id":4734,"en":"contempt","ja":"軽蔑\ncontempt for〜で「〜を見下す気持ち」。強い否定的感情","level":7,"lnum":1,"ex":"He made no effort to hide his contempt for dishonest politicians.","exja":"彼は不誠実な政治家への軽蔑を隠そうともしなかった。"},{"id":4735,"en":"contract","ja":"契約・収縮する\n名詞と動詞（縮む）でアクセント位置が変わることに注意","level":7,"lnum":1,"ex":"Both parties signed the contract before work began.","exja":"作業が始まる前に、両者が契約書に署名した。"},{"id":4736,"en":"contradict","ja":"矛盾する・否定する\ncontradict oneselfで「言葉が矛盾する」という表現が頻出","level":7,"lnum":1,"ex":"His actions often contradict what he says.","exja":"彼の行動はしばしば自分の言葉と矛盾する。"},{"id":4737,"en":"contradiction","ja":"矛盾\na contradiction in termsで「言葉の矛盾」という慣用表現がある","level":7,"lnum":1,"ex":"There is a clear contradiction between his words and his behavior.","exja":"彼の言葉と行動の間には明らかな矛盾がある。"},{"id":4738,"en":"contradictory","ja":"矛盾した\n論理的に両立しない状態を表す。論文・ディベートで頻出語","level":7,"lnum":1,"ex":"The two witnesses gave contradictory accounts of the accident.","exja":"2人の目撃者が事故について矛盾した証言をした。"},{"id":4739,"en":"controversy","ja":"論争・物議\ncontroversial（論争的な）とセット。sensitive topicに伴う","level":7,"lnum":1,"ex":"The new law sparked considerable controversy among citizens.","exja":"新しい法律は市民の間でかなりの論争を引き起こした。"},{"id":4740,"en":"conveniently","ja":"都合よく・便利に\n皮肉な意味でも使われる。Conveniently, he forgot...（都合よく忘れた）","level":7,"lnum":1,"ex":"Conveniently, he forgot to mention the deadline to his team.","exja":"都合よく、彼はチームに締め切りのことを伝えるのを忘れた。"},{"id":4741,"en":"convention","ja":"慣習・会議\nsocial conventionで「社会的慣習」。unconventionalの反意語","level":7,"lnum":1,"ex":"It is a social convention to shake hands when meeting someone for the first time.","exja":"初めて人に会うときに握手するのは社会的な慣習だ。"},{"id":4742,"en":"conventional","ja":"従来の・慣習的な\nunconventionalと対比して使われることが多い重要形容詞","level":7,"lnum":1,"ex":"He rejected conventional approaches and found a creative solution.","exja":"彼は従来のやり方を拒否して、創造的な解決策を見つけた。"},{"id":4743,"en":"converse","ja":"逆・逆に話す\n名詞で「逆のこと」の意味。converselyと組み合わせて論文頻出","level":7,"lnum":1,"ex":"The converse of this argument is also true.","exja":"この議論の逆もまた真実だ。"},{"id":4744,"en":"conversely","ja":"逆に言えば\n論文の逆接表現として最重要。On the other hand と同義","level":7,"lnum":1,"ex":"Some people prefer working alone; conversely, others are more productive in teams.","exja":"一人で働くことを好む人もいる。逆に言えば、チームの方が生産性が上がる人もいる。"},{"id":4745,"en":"conversion","ja":"転換・改宗\nenergy conversion（エネルギー変換）など理系文脈でも重要","level":7,"lnum":1,"ex":"The conversion of the old factory into apartments took two years.","exja":"古い工場をアパートに転換するのに2年かかった。"},{"id":4746,"en":"convert","ja":"変換する・改宗する\nconvert A into Bの形で「AをBに変える」という使い方が頻出","level":7,"lnum":1,"ex":"The solar panels convert sunlight into electricity.","exja":"ソーラーパネルは太陽光を電気に変換する。"},{"id":4747,"en":"convinced","ja":"確信した\nbe convinced thatの形で使う。convincingとの区別に注意","level":7,"lnum":1,"ex":"After reading the report, she was convinced that the project would succeed.","exja":"報告書を読んで、彼女はプロジェクトが成功すると確信した。"},{"id":4748,"en":"cooperate","ja":"協力する\ncooperate withの形で使う。co-operateとも書く","level":7,"lnum":1,"ex":"All departments need to cooperate with each other to meet the deadline.","exja":"締め切りに間に合わせるためには、すべての部門が互いに協力する必要がある。"},{"id":4749,"en":"cooperative","ja":"協力的な・協同組合\n名詞でも使い「協同組合」の意味になる。発音に注意","level":7,"lnum":1,"ex":"The students were cooperative and finished the group project ahead of schedule.","exja":"生徒たちは協力的で、グループプロジェクトを予定より早く終えた。"},{"id":4750,"en":"cope","ja":"対処する\ncope withの形で「〜に対処する」。deal withとほぼ同義","level":7,"lnum":1,"ex":"It can be hard to cope with the stress of exam season.","exja":"試験シーズンのストレスに対処するのは難しいことがある。"},{"id":4751,"en":"copper","ja":"銅\n金属の中でも色から「銅色」の形容詞的な使い方もある","level":7,"lnum":1,"ex":"The old building had beautiful copper pipes running along the ceiling.","exja":"その古い建物には、天井に沿って美しい銅のパイプが走っていた。"},{"id":4752,"en":"coral","ja":"サンゴ\ncoral reef（サンゴ礁）。環境問題の文脈で頻出する語","level":7,"lnum":1,"ex":"Rising ocean temperatures are destroying coral reefs around the world.","exja":"海水温の上昇が世界中のサンゴ礁を破壊している。"},{"id":4753,"en":"core","ja":"核心・中心部\nat the core of〜で「〜の本質に」。core value（核心的価値）も重要","level":7,"lnum":1,"ex":"Trust is the core of any successful relationship.","exja":"信頼はあらゆる成功した人間関係の核心だ。"},{"id":4754,"en":"cornerstone","ja":"礎・基礎\nthe cornerstone of〜で「〜の礎」という比喩表現が頻出","level":7,"lnum":1,"ex":"Education is often described as the cornerstone of a healthy democracy.","exja":"教育は健全な民主主義の礎としてしばしば語られる。"},{"id":4755,"en":"cornet","ja":"コルネット・円錐形のもの\n楽器名と食べ物の容器（ice cream cornet）の両義がある","level":7,"lnum":1,"ex":"She played a beautiful melody on the cornet at the school concert.","exja":"彼女は学校のコンサートでコルネットを使って美しいメロディーを演奏した。"},{"id":4756,"en":"corona","ja":"コロナ・光冠\n太陽のコロナや最近はウイルス名としても認知度が高い","level":7,"lnum":1,"ex":"Scientists study the sun's corona to better understand solar activity.","exja":"科学者たちは太陽活動をより深く理解するために太陽のコロナを研究している。"},{"id":4757,"en":"corporal","ja":"肉体の・上等兵\ncorporal punishment（体罰）という複合語が試験に頻出する","level":7,"lnum":1,"ex":"Corporal punishment in schools has been banned in many countries.","exja":"学校での体罰は多くの国で禁止されている。"},{"id":4758,"en":"corporate","ja":"企業の・法人の\ncorporate culture（企業文化）など現代ビジネス英語で頻出","level":7,"lnum":1,"ex":"The company's corporate culture encourages creativity and teamwork.","exja":"その会社の企業文化は創造性とチームワークを奨励している。"},{"id":4759,"en":"corporation","ja":"株式会社・法人\nmultinational corporationで「多国籍企業」。略称corp.","level":7,"lnum":1,"ex":"The multinational corporation operates in more than 50 countries.","exja":"その多国籍企業は50カ国以上で事業を展開している。"},{"id":4760,"en":"correctness","ja":"正確さ・正しさ\npolitical correctness（政治的正しさ）という表現で現代的に重要","level":7,"lnum":1,"ex":"The correctness of the data must be verified before publishing the results.","exja":"結果を発表する前にデータの正確さを検証しなければならない。"},{"id":4761,"en":"correspond","ja":"対応する・文通する\ncorrespond toで「〜に対応する」、correspond withで「文通する」","level":7,"lnum":1,"ex":"The map symbols correspond to specific features in the landscape.","exja":"地図の記号は地形の具体的な特徴に対応している。"},{"id":4762,"en":"correspondence","ja":"文通・対応関係\nin correspondence withで「〜と連絡を取り合って」の意味","level":7,"lnum":1,"ex":"She kept all her correspondence with the famous author in a special folder.","exja":"彼女はその有名な作家との文通をすべて特別なフォルダに保管していた。"},{"id":4763,"en":"correspondent","ja":"特派員・文通相手\nforeign correspondentで「海外特派員」。ジャーナリズム用語","level":7,"lnum":1,"ex":"The news channel sent its foreign correspondent to cover the conflict.","exja":"ニュースチャンネルは紛争を取材するために海外特派員を派遣した。"},{"id":4764,"en":"corresponding","ja":"対応する・相応の\ncorresponding toの形で「〜に対応する」という形容詞的用法","level":7,"lnum":1,"ex":"Each chapter has a corresponding set of exercises at the end of the book.","exja":"各章には、本の末尾に対応する演習問題が用意されている。"},{"id":4765,"en":"corridor","ja":"廊下\n長い通路を指す。political corridors of power（権力の中枢）も重要","level":7,"lnum":1,"ex":"The school corridor was crowded with students between classes.","exja":"授業の合間、学校の廊下は生徒たちで混雑していた。"},{"id":4766,"en":"corrupt","ja":"腐敗した・汚職の\n動詞でも使い「腐敗させる」の意味。corruption（腐敗）とセット","level":7,"lnum":1,"ex":"The corrupt official was arrested after accepting bribes.","exja":"その腐敗した官僚は贈賄を受け取った後に逮捕された。"},{"id":4767,"en":"corruption","ja":"腐敗・汚職\npolitical corruptionで「政治腐敗」。社会問題の文脈で頻出","level":7,"lnum":1,"ex":"The government launched an investigation into corruption within the police force.","exja":"政府は警察内部の腐敗について調査を開始した。"},{"id":4768,"en":"costly","ja":"高価な・損失の大きい\nexpensiveより「コストがかかりすぎる」という否定的ニュアンスが強い","level":7,"lnum":1,"ex":"The delay in the project proved to be very costly for the company.","exja":"プロジェクトの遅延は会社にとって非常に損失の大きいものとなった。"},{"id":4769,"en":"cottage","ja":"コテージ・小屋\ncottage industryで「家内工業」という表現が試験に出やすい","level":7,"lnum":1,"ex":"They spent the weekend in a cozy cottage by the lake.","exja":"彼らは湖のほとりの居心地のよいコテージで週末を過ごした。"},{"id":4770,"en":"counter","ja":"カウンター・反論する\n動詞で「反論する」、前置詞でcounter toが使える多義語","level":7,"lnum":1,"ex":"The politician countered the criticism with clear evidence.","exja":"その政治家は明確な証拠で批判に反論した。"},{"id":4771,"en":"countryman","ja":"同国人・田舎の人\nfellow countrymanで「同胞」。やや古風な表現","level":7,"lnum":1,"ex":"He was happy to meet a fellow countryman while traveling abroad.","exja":"海外旅行中に同国人に出会えて彼は嬉しかった。"},{"id":4772,"en":"countrywide","ja":"全国的な\nnationwide と同義。国全体に及ぶ規模を表す形容詞","level":7,"lnum":1,"ex":"The government launched a countrywide campaign to promote recycling.","exja":"政府はリサイクルを推進する全国的なキャンペーンを開始した。"},{"id":4773,"en":"courtesy","ja":"礼儀・好意\nout of courtesyで「礼儀として」。courteous（礼儀正しい）と同根","level":7,"lnum":1,"ex":"She held the door open for the elderly man out of courtesy.","exja":"彼女は礼儀として老人のためにドアを開けておいた。"},{"id":4774,"en":"coward","ja":"臆病者\ncowardlyとセットで覚える。勇気のなさを示す否定的な語","level":7,"lnum":1,"ex":"He was called a coward for refusing to stand up for his friend.","exja":"友人をかばうことを拒んだため、彼は臆病者と呼ばれた。"},{"id":4775,"en":"cowardly","ja":"臆病な\n行動・人を修飾。a cowardly actで「臆病な行為」と使う","level":7,"lnum":1,"ex":"Attacking someone from behind is considered a cowardly act.","exja":"背後から人を攻撃することは臆病な行為とみなされる。"},{"id":4776,"en":"coziness/cosiness","ja":"居心地の良さ\ncozy（居心地が良い）の名詞形。温かみのある雰囲気を表す","level":7,"lnum":1,"ex":"The coziness of the little cafe made it a popular spot for locals.","exja":"その小さなカフェの居心地の良さが、地元の人たちに人気のスポットにした。"},{"id":4777,"en":"cozy/cosy","ja":"居心地のよい・くつろいだ\n米国式cozy、英国式cosyと綴りが異なる点に注意","level":7,"lnum":1,"ex":"She decorated her room to make it feel cozy and warm.","exja":"彼女は部屋を居心地よく温かく感じられるように飾り付けた。"},{"id":4778,"en":"crab","ja":"カニ\n海産物。crabbyで「気難しい」という派生的意味もある","level":7,"lnum":1,"ex":"The children caught a small crab in the rock pool at the beach.","exja":"子どもたちはビーチの岩場のたまり水で小さなカニを捕まえた。"},{"id":4779,"en":"crack","ja":"ひび・亀裂\n名詞と動詞の両方で使う。crack down on〜で「〜を取り締まる」","level":7,"lnum":1,"ex":"The detective cracked the case after finding a crucial piece of evidence.","exja":"刑事は重要な証拠を見つけてその事件を解決した。"},{"id":4780,"en":"crack","ja":"ひびが入る・割る\ncrack open（こじ開ける）など動詞用法が多様。慣用表現に注意","level":7,"lnum":1,"ex":"The dry ground cracked under the intense summer heat.","exja":"激しい夏の暑さで乾いた地面にひびが入った。"},{"id":4781,"en":"craftsman","ja":"職人\ncraftsmanshipで「職人技」。熟練した手仕事を指す敬称","level":7,"lnum":1,"ex":"The furniture was made by a skilled craftsman using traditional methods.","exja":"その家具は伝統的な手法を用いた熟練した職人によって作られた。"},{"id":4782,"en":"crater","ja":"クレーター・火口\n月や火山の「くぼみ」。disaster後の地形描写でも使われる","level":7,"lnum":1,"ex":"Astronauts studied the deep crater on the surface of the moon.","exja":"宇宙飛行士は月面の深いクレーターを調査した。"},{"id":4783,"en":"crawl","ja":"這う・のろのろ進む\n赤ちゃんが這うイメージ。traffic crawlで「渋滞」の比喩も頻出","level":7,"lnum":1,"ex":"The baby began to crawl before she could walk.","exja":"その赤ちゃんは歩けるようになる前に這い始めた。"},{"id":4784,"en":"crease","ja":"しわ・折り目\n名詞と動詞の両方で使う。衣類やペーパーのしわを指す","level":7,"lnum":1,"ex":"He tried to iron out the crease in his shirt before the meeting.","exja":"彼は会議の前にシャツのしわをアイロンで伸ばそうとした。"},{"id":4785,"en":"creation","ja":"創造・作品\nthe Creation（神の天地創造）という固有名詞的用法もある","level":7,"lnum":1,"ex":"The creation of new jobs is a top priority for the government.","exja":"新しい雇用の創出は政府の最優先事項だ。"},{"id":4786,"en":"creatively","ja":"創造的に\ncreative→creativity→creativelyとセットで覚える副詞","level":7,"lnum":1,"ex":"The students solved the problem creatively by combining different methods.","exja":"生徒たちは様々な方法を組み合わせて創造的に問題を解決した。"},{"id":4787,"en":"creek","ja":"小川・入り江\nup the creek（without a paddle）は「困った状況」の慣用表現","level":7,"lnum":1,"ex":"The children built a small dam across the creek in the woods.","exja":"子どもたちは森の小川に小さなダムを作った。"},{"id":4788,"en":"creepy","ja":"気味悪い・不気味な\n口語的表現。略式のcreepとも関連する口語的形容詞","level":7,"lnum":1,"ex":"The old house at the end of the road always gave her a creepy feeling.","exja":"通りの突き当たりにある古い家はいつも彼女に不気味な感じを与えた。"},{"id":4789,"en":"crew","ja":"乗組員・クルー\n集合名詞。film crew（撮影スタッフ）など様々な分野で使う","level":7,"lnum":1,"ex":"The film crew worked long hours to finish the production on schedule.","exja":"撮影クルーは予定通りに制作を終えるために長時間働いた。"},{"id":4790,"en":"criminal","ja":"犯罪の・犯人\n形容詞・名詞の両方で使う。criminal record（前科）が頻出表現","level":7,"lnum":1,"ex":"He had no criminal record before he was arrested for theft.","exja":"窃盗で逮捕される前、彼には前科がなかった。"},{"id":4791,"en":"cripple","ja":"障害者・機能不全にする\n現代では障害者への使用は不適切とされる。比喩的に「麻痺させる」が主流","level":7,"lnum":1,"ex":"The sudden power outage crippled the city's transportation system.","exja":"突然の停電が市の交通システムを機能不全に陥らせた。"},{"id":4792,"en":"critically","ja":"批判的に・重大に\ncritically ill（重篤な）とcritically important（非常に重要な）の両義","level":7,"lnum":1,"ex":"The patient was critically ill and was taken to the intensive care unit.","exja":"患者は重篤な状態にあり、集中治療室に運ばれた。"},{"id":4793,"en":"criticism","ja":"批判・批評\nliterary criticism（文芸批評）とunder criticism（批判を受けている）","level":7,"lnum":1,"ex":"The film received harsh criticism from reviewers but was loved by audiences.","exja":"その映画はレビュアーから厳しい批評を受けたが、観客には愛された。"},{"id":4794,"en":"crocodile","ja":"ワニ\ncrocodile tearsで「うそ泣き・ワニの涙」という慣用表現が重要","level":7,"lnum":1,"ex":"The wildlife documentary showed a crocodile waiting patiently at the water's edge.","exja":"その自然ドキュメンタリーは、水辺で辛抱強く待つワニを映し出した。"},{"id":4795,"en":"crossly","ja":"怒って・腹立たしげに\ncross（怒った）の副詞形。angry/annoyedより口語的な語感","level":7,"lnum":1,"ex":"\"Stop making that noise!\" she said crossly.","exja":"「その音をやめなさい！」と彼女は怒って言った。"},{"id":4796,"en":"crucial","ja":"非常に重要な\nit is crucial thatの構文が頻出。criticalとほぼ同義だが強調が強い","level":7,"lnum":1,"ex":"It is crucial that students understand the basics before moving to advanced topics.","exja":"応用的な内容に進む前に、基礎を理解することが非常に重要だ。"},{"id":4797,"en":"cruelly","ja":"残酷に\ncruel→cruelty→cruellyとセットで押さえる道徳・文学の重要語","level":7,"lnum":1,"ex":"The animals were cruelly treated at the illegal farm.","exja":"その違法な農場では動物が残酷に扱われていた。"},{"id":4798,"en":"cruelty","ja":"残酷さ\ncruelty to animals（動物虐待）など社会問題の文脈に頻出","level":7,"lnum":1,"ex":"The charity works to prevent cruelty to animals across the country.","exja":"その慈善団体は全国の動物虐待を防ぐために活動している。"},{"id":4799,"en":"cruise","ja":"航行する・クルーズする\ncruise ship（客船）と cruise control（定速走行）の両義","level":7,"lnum":1,"ex":"They decided to cruise along the Mediterranean coast for their honeymoon.","exja":"彼らはハネムーンに地中海沿岸をクルーズすることにした。"},{"id":4800,"en":"crystallize/crystallise","ja":"結晶化する・明確になる\nIdeas crystallizeで「考えがまとまる」という比喩的用法が重要","level":7,"lnum":1,"ex":"His ideas about the project began to crystallize after the meeting.","exja":"会議後、プロジェクトに関する彼のアイデアが明確になってきた。"},{"id":4801,"en":"cube","ja":"立方体・キューブ\nice cubeや数学的な「3乗」の意味もある多義的な語","level":7,"lnum":1,"ex":"She dropped an ice cube into her glass of water.","exja":"彼女はコップの水に氷を一つ入れた。"},{"id":4802,"en":"cubism","ja":"キュビスム\nピカソが代表する美術運動。文化・芸術の文脈で頻出する語","level":7,"lnum":1,"ex":"Picasso is one of the most famous artists associated with cubism.","exja":"ピカソはキュビスムと関連して最も有名な芸術家の一人だ。"},{"id":4803,"en":"cuff","ja":"カフス・手錠\noff the cuffで「即席の・準備なしに」という慣用表現が重要","level":7,"lnum":1,"ex":"He spoke off the cuff without preparing any notes.","exja":"彼はメモを何も用意せず即席でスピーチした。"},{"id":4804,"en":"culmination","ja":"頂点・集大成\nthe culmination of〜で「〜の集大成」。努力の結果を表す","level":7,"lnum":1,"ex":"The award ceremony was the culmination of years of hard work and dedication.","exja":"授賞式は何年にもわたる努力と献身の集大成だった。"},{"id":4805,"en":"culturally","ja":"文化的に\nculturally sensitive（文化的に敏感な）など多文化の文脈で頻出","level":7,"lnum":1,"ex":"We need to be culturally sensitive when working in an international environment.","exja":"国際的な環境で働く際は、文化的に敏感である必要がある。"},{"id":4806,"en":"cure","ja":"治す・治療する\n名詞と動詞の両方で使う。cure for〜で「〜の治療法・解決策」","level":7,"lnum":1,"ex":"Scientists are working hard to find a cure for the disease.","exja":"科学者たちはその病気の治療法を見つけるために懸命に研究している。"},{"id":4807,"en":"curl","ja":"カール・巻き毛\n名詞と動詞の両方で使う。curl up（丸まる）という表現も重要","level":7,"lnum":1,"ex":"She sat by the fire and watched the smoke curl upward.","exja":"彼女は暖炉のそばに座り、煙が上へと巻き上がるのを眺めた。"},{"id":4808,"en":"cursor","ja":"カーソル\nコンピュータ用語。mouseやkeyboardとセットで覚える","level":7,"lnum":1,"ex":"Move the cursor to the right side of the screen and click on the icon.","exja":"カーソルを画面の右側に動かして、アイコンをクリックしてください。"},{"id":4809,"en":"cyberaddict","ja":"ネット依存症の人\ncyber-の接頭語に注意。インターネット過剰使用を表す現代語","level":7,"lnum":1,"ex":"A cyberaddict may spend hours online, neglecting sleep and meals.","exja":"ネット依存症の人は睡眠や食事をおろそかにして、何時間もオンラインで過ごすことがある。"},{"id":4810,"en":"cybercafe/cybercafé","ja":"インターネットカフェ\n世界各地にある公共のネット利用施設を指す比較的新しい語","level":7,"lnum":1,"ex":"We stopped at a cybercafe to check our emails while traveling.","exja":"旅行中、私たちはメールを確認するためにインターネットカフェに立ち寄った。"},{"id":4811,"en":"cybercrime","ja":"サイバー犯罪\nオンライン上の不法行為全般。cybersecurityとセットで頻出","level":7,"lnum":1,"ex":"Governments around the world are strengthening laws to combat cybercrime.","exja":"世界中の政府がサイバー犯罪に対抗するための法律を強化している。"},{"id":4812,"en":"cyberpet","ja":"デジタルペット\nたまごっちなど仮想的なペット。現代的なテクノロジー語彙","level":7,"lnum":1,"ex":"As a child, she spent hours taking care of her cyberpet on a handheld device.","exja":"子どもの頃、彼女は携帯デバイスでデジタルペットの世話をして何時間も過ごした。"},{"id":4813,"en":"cyberschool","ja":"オンライン学校\nインターネットを通じた教育機関。e-learningと関連する語","level":7,"lnum":1,"ex":"The cyberschool offered flexible schedules for students who couldn't attend in person.","exja":"そのオンライン学校は対面で通えない生徒のために柔軟なスケジュールを提供した。"},{"id":4814,"en":"cyberspace","ja":"サイバースペース\nインターネット上の仮想空間全体を指す重要現代語彙","level":7,"lnum":1,"ex":"Personal information shared in cyberspace can be vulnerable to hackers.","exja":"サイバースペースで共有された個人情報はハッカーに狙われやすい。"},{"id":4815,"en":"cyclist","ja":"サイクリスト・自転車乗り\ncycle→cyclist。環境問題や健康の文脈でも頻出する語","level":7,"lnum":1,"ex":"The cyclist wore a bright helmet for safety during the race.","exja":"そのサイクリストはレース中の安全のために明るい色のヘルメットをかぶっていた。"},{"id":4816,"en":"daft","ja":"馬鹿げた・ばかな\n主に英国英語。silly/foolishより口語的で軽い否定のニュアンス","level":7,"lnum":1,"ex":"It was a daft idea to go hiking without checking the weather first.","exja":"天気を確認せずにハイキングに行くのは馬鹿げた考えだった。"},{"id":4817,"en":"damn","ja":"ひどい・まったく\n感嘆詞・形容詞・副詞と多品詞。damn it!で「くそ！」","level":7,"lnum":1,"ex":"\"Damn!\" she muttered when she realized she had missed the train.","exja":"電車に乗り遅れたと気づいたとき、「ちくしょう！」と彼女はつぶやいた。"},{"id":4818,"en":"damn","ja":"まったく・本当に\n強調副詞。damn good（本当によい）など口語でよく使われる","level":7,"lnum":1,"ex":"It was damn cold outside, so he put on an extra coat.","exja":"外は本当に寒かったので、彼はもう一枚コートを着た。"},{"id":4819,"en":"damn","ja":"ちくしょう！\n感嘆詞。怒りや失望を表す口語表現。丁寧な場面では避ける","level":7,"lnum":1,"ex":"\"Damn!\" she cried when she realized she had missed her train.","exja":"「ちくしょう！」と彼女は電車に乗り遅れたと気づいて叫んだ。"},{"id":4820,"en":"dandelion","ja":"タンポポ\n植物名。make a wish on a dandelionという表現も覚えておく","level":7,"lnum":1,"ex":"The child blew on a dandelion and watched the seeds float away.","exja":"子どもはタンポポに息を吹きかけ、種が飛んでいくのを眺めた。"},{"id":4821,"en":"darling","ja":"愛しい・大好きな\n愛情を示す形容詞。my darling（愛しい人）という呼びかけでも使う","level":7,"lnum":1,"ex":"She was the darling of the fashion world after winning the prestigious award.","exja":"その権威ある賞を受賞して、彼女はファッション界のお気に入りになった。"},{"id":4822,"en":"darling","ja":"愛する人・お気に入り\n呼びかけの名詞としてよく使う。darling of the pressで「マスコミの寵児」","level":7,"lnum":1,"ex":"\"Come on, darling, let's go home,\" she said to her child.","exja":"「さあ、かわいい子、家に帰りましょう」と彼女は子供に言った。"},{"id":4823,"en":"dash","ja":"ダッシュ・突進\n名詞と動詞の両方で使う。100-meter dash（100m走）が典型用法","level":7,"lnum":1,"ex":"He dashed out of the classroom when the bell rang.","exja":"ベルが鳴ると、彼は教室から急いで飛び出した。"},{"id":4824,"en":"dash","ja":"急いで行く・素早く動く\ndash out（飛び出す）のように副詞と組み合わせて使う動詞","level":7,"lnum":1,"ex":"She dashed across the street to catch the bus.","exja":"彼女はバスに乗るために通りを急いで横切った。"},{"id":4825,"en":"database","ja":"データベース\n現代のIT用語として必須。database management（DB管理）が頻出","level":7,"lnum":1,"ex":"The hospital uses a secure database to store patient records.","exja":"病院は患者の記録を保存するために安全なデータベースを使用している。"},{"id":4826,"en":"dated","ja":"時代遅れの・日付が記された\nout-of-dateと同義の「古くなった」の意味が現代では主流","level":7,"lnum":1,"ex":"Some of the teaching methods in the textbook seemed rather dated.","exja":"教科書にある指導法のいくつかはかなり時代遅れに見えた。"},{"id":4827,"en":"daughter-in-law","ja":"義理の娘・嫁\nin-lawシリーズ（mother-in-lawなど）で家族関係語彙をまとめて覚える","level":7,"lnum":1,"ex":"His daughter-in-law helped organize the family reunion.","exja":"彼の義理の娘は家族の集まりの企画を手伝った。"},{"id":4828,"en":"dawn","ja":"夜明け・始まり\nat dawn（夜明けに）。It dawns on meで「〜に気づく」も重要","level":7,"lnum":1,"ex":"The hikers set off at dawn to reach the summit before noon.","exja":"ハイカーたちは正午前に山頂に着くために夜明けに出発した。"},{"id":4829,"en":"daytime","ja":"昼間・日中\nnighttimeと対比して使う。during the daytimeが定番表現","level":7,"lnum":1,"ex":"The library is only open during daytime hours on weekends.","exja":"図書館は週末は昼間のみ開館している。"},{"id":4830,"en":"de facto","ja":"事実上の\nラテン語起源。de facto leaderで「事実上のリーダー」。法律・政治用語","level":7,"lnum":1,"ex":"Although he had no official title, he was the de facto leader of the group.","exja":"公式な肩書きはなかったが、彼はそのグループの事実上のリーダーだった。"},{"id":4831,"en":"dearly","ja":"深く・心から\nlove dearly（深く愛する）、pay dearlyで「高い代償を払う」の両義","level":7,"lnum":1,"ex":"She dearly missed her grandmother who had passed away the previous winter.","exja":"彼女は前の冬に亡くなった祖母を深く恋しく思っていた。"},{"id":4832,"en":"debit","ja":"引き落とし・借方\ncredit（貸方・信用）の対義語。debit cardと合わせて覚える","level":7,"lnum":1,"ex":"The bank statement showed several debit transactions from last week.","exja":"銀行の明細書には先週の複数の引き落とし取引が示されていた。"},{"id":4833,"en":"debit","ja":"引き落とす\n銀行口座から金額を引き落とす動詞用法。creditの逆操作","level":7,"lnum":1,"ex":"The monthly fee is automatically debited from your bank account.","exja":"月額料金は自動的に銀行口座から引き落とされます。"},{"id":4834,"en":"debit card","ja":"デビットカード\n即時引き落としカード。credit cardとの違いを理解して覚える","level":7,"lnum":1,"ex":"She paid for the groceries using her debit card at the checkout.","exja":"彼女はレジでデビットカードを使って食料品の代金を支払った。"},{"id":4835,"en":"decade","ja":"10年間\nin the next decadeで「今後10年で」。for decadesで「何十年もの間」","level":7,"lnum":1,"ex":"The company has grown significantly over the past decade.","exja":"その会社はこの10年間で著しく成長した。"},{"id":4836,"en":"decay","ja":"腐敗する・衰退する\n名詞と動詞の両方で使う。tooth decayで「虫歯」という複合語も重要","level":7,"lnum":1,"ex":"The abandoned building had fallen into a state of decay over the years.","exja":"廃屋は長年にわたって腐朽した状態に陥っていた。"},{"id":4837,"en":"deceive","ja":"だます・欺く\n意図的に偽る行為。deceive oneselfで「自分をだます」も頻出","level":7,"lnum":1,"ex":"He deceived his colleagues by pretending to be an expert in the field.","exja":"彼はその分野の専門家のふりをして同僚たちを欺いた。"},{"id":4838,"en":"decent","ja":"まともな・適切な\na decent salaryで「まともな給料」。poorとの対比で使われやすい","level":7,"lnum":1,"ex":"She earned a decent salary working as an engineer at the tech company.","exja":"彼女はテクノロジー企業でエンジニアとして働き、まともな給料を得ていた。"},{"id":4839,"en":"deceptive","ja":"人を惑わせる・偽りの\n外見が実態と異なる場合に使う。appearances can be deceptiveが慣用表現","level":7,"lnum":1,"ex":"The calm appearance of the river was deceptive, as the current was strong.","exja":"川の穏やかな見た目は人を惑わせるもので、流れは強かった。"},{"id":4840,"en":"decisive","ja":"決定的な・決断力のある\na decisive momentで「決定的な瞬間」。indecisiveの対義語","level":7,"lnum":1,"ex":"The coach made a decisive move that changed the outcome of the game.","exja":"コーチは試合の結果を変えた決定的な判断を下した。"},{"id":4841,"en":"deck","ja":"デッキ・甲板\non deckで「甲板に」。deck of cardsで「トランプ一組」も覚える","level":7,"lnum":1,"ex":"The passengers gathered on the deck to watch the sunset over the ocean.","exja":"乗客たちは海に沈む夕日を眺めるためにデッキに集まった。"},{"id":4842,"en":"decline","ja":"断る・減少する\n名詞と動詞の両方で使う。decline an invitation（招待を断る）が頻出","level":7,"lnum":1,"ex":"The company's profits have been declining steadily for the past three years.","exja":"その会社の利益はここ3年間、着実に減少している。"},{"id":4843,"en":"decomposition","ja":"分解・腐敗\n生物・化学の文脈に頻出。decompose（分解する）の名詞形","level":7,"lnum":1,"ex":"The decomposition of organic matter is an essential part of the ecosystem.","exja":"有機物の分解は生態系の重要な一部だ。"},{"id":4844,"en":"decorative","ja":"装飾的な\n機能より見た目を目的とするものに使う。purely decorativeが定番","level":7,"lnum":1,"ex":"The vase was purely decorative and was never used to hold flowers.","exja":"その花瓶は純粋に装飾的なもので、花を生けるために使われることはなかった。"},{"id":4845,"en":"dedication","ja":"献身・献呈\nwith dedication（献身的に）。本の謝辞ページの「dedication」も重要","level":7,"lnum":1,"ex":"His dedication to improving the lives of others inspired everyone around him.","exja":"他者の生活を向上させることへの彼の献身は、周りのすべての人を鼓舞した。"},{"id":4846,"en":"deduce","ja":"推論する・推定する\ndeductive reasoning（演繹的推論）とセットで論理的思考に使う","level":7,"lnum":1,"ex":"From the clues found at the scene, the detective was able to deduce what had happened.","exja":"現場で見つかった手がかりから、刑事は何が起きたかを推論できた。"},{"id":4847,"en":"deduction","ja":"推論・控除\n税金の控除（tax deduction）と論理的推論の二つの意味を区別","level":7,"lnum":1,"ex":"The tax deduction allowed her to reduce the amount she owed to the government.","exja":"税控除によって、彼女は政府への納税額を減らすことができた。"},{"id":4848,"en":"deem","ja":"〜とみなす\nbe deemed to beの形で「〜とみなされる」。やや書き言葉的・フォーマル","level":7,"lnum":1,"ex":"The judge deemed the evidence insufficient to support a conviction.","exja":"判事は証拠が有罪判決を支持するには不十分とみなした。"},{"id":4849,"en":"defeat","ja":"敗北・打ち破ること\n名詞と動詞の両用。admit defeatで「敗北を認める」が頻出表現","level":7,"lnum":1,"ex":"The team suffered a painful defeat in the final match of the season.","exja":"チームはシーズン最後の試合で痛い敗北を喫した。"},{"id":4850,"en":"deficit","ja":"赤字・不足\nbudget deficitで「財政赤字」。経済・財政の文脈で必須語彙","level":7,"lnum":1,"ex":"The government announced plans to reduce the budget deficit over the next five years.","exja":"政府は今後5年間で財政赤字を削減する計画を発表した。"},{"id":4851,"en":"deforestation","ja":"森林破壊\nde-（否定）+forest+ation。環境問題の文脈で最重要語彙の一つ","level":7,"lnum":1,"ex":"Deforestation in the Amazon has accelerated at an alarming rate in recent years.","exja":"近年、アマゾンの森林破壊は憂慮すべき速さで加速している。"},{"id":4852,"en":"defy","ja":"無視する・反抗する\ndefy the lawで「法律に反する」。defy descriptionで「言葉にならない」","level":7,"lnum":1,"ex":"She chose to defy convention by starting her own business at the age of 20.","exja":"彼女は20歳で自分のビジネスを始め、慣習に反することを選んだ。"},{"id":4853,"en":"dehumanize/dehumanise","ja":"非人間的に扱う\nde-（除去）+human+ize。人間性を奪う行為を批判する文脈で使う","level":7,"lnum":1,"ex":"The prisoners were dehumanized by the harsh conditions in the camp.","exja":"囚人たちは収容所の過酷な環境によって非人道的な扱いを受けた。"},{"id":4854,"en":"delegate","ja":"代表者・委任する\n名詞（代表者）と動詞（権限を委ねる）の両方で使う重要語","level":7,"lnum":1,"ex":"The manager decided to delegate some tasks to junior staff members.","exja":"マネージャーはいくつかの業務を若手スタッフに委任することにした。"},{"id":4855,"en":"deliberate","ja":"意図的な・慎重に考える\n形容詞（わざとの）と動詞（熟考する）でアクセント位置が変わる","level":7,"lnum":1,"ex":"It was a deliberate attempt to mislead the public about the company's finances.","exja":"それは会社の財務状況について大衆を誤解させる意図的な試みだった。"},{"id":4856,"en":"deliberately","ja":"わざと・故意に\naccidentally（偶然に）の対義語。intentionallyとほぼ同義","level":7,"lnum":1,"ex":"She deliberately left early to avoid getting caught in traffic.","exja":"彼女は渋滞に巻き込まれないよう、わざと早めに出発した。"},{"id":4857,"en":"delicacy","ja":"繊細さ・珍味\na local delicacyで「郷土の珍味」。扱いの難しさも表す多義語","level":7,"lnum":1,"ex":"Fugu is considered a great delicacy in Japan, despite its potential danger.","exja":"ふぐは潜在的な危険にもかかわらず、日本では最高の珍味とされている。"},{"id":4858,"en":"delicately","ja":"繊細に・慎重に\na delicately balanced situationで「微妙なバランスの状況」","level":7,"lnum":1,"ex":"The surgeon delicately removed the tumor without damaging surrounding tissue.","exja":"外科医は周囲の組織を傷つけることなく腫瘍を繊細に取り除いた。"},{"id":4859,"en":"delight","ja":"喜ばせる・喜び\nto someone's delightで「〜が喜んだことに」。take delight in〜も重要","level":7,"lnum":1,"ex":"The children's faces were filled with delight when they saw the fireworks.","exja":"花火を見たとき、子どもたちの顔は喜びで満ちあふれていた。"},{"id":4860,"en":"demanding","ja":"要求の厳しい・骨の折れる\na demanding jobで「きつい仕事」。人と仕事の両方を修飾する","level":7,"lnum":1,"ex":"Nursing is one of the most demanding jobs in the healthcare industry.","exja":"看護は医療業界で最も要求の厳しい仕事の一つだ。"},{"id":4861,"en":"demolish","ja":"取り壊す・論破する\n建物を壊すことと、議論を完全否定する意味の両方がある","level":7,"lnum":1,"ex":"The old stadium was demolished to make way for a new sports complex.","exja":"新しいスポーツ複合施設のために古いスタジアムが取り壊された。"},{"id":4862,"en":"denim","ja":"デニム・ジーンズ生地\n素材名。denim jeans / a denim jacket（デニムジャケット）が典型","level":7,"lnum":1,"ex":"She wore a denim jacket over her summer dress on cool evenings.","exja":"涼しい夕方は彼女はサマードレスの上にデニムジャケットを羽織った。"},{"id":4863,"en":"dense","ja":"密集した・濃い\ndense forestで「深い森」、dense fogで「濃い霧」。頭が鈍いの口語も","level":7,"lnum":1,"ex":"The expedition team struggled to move through the dense jungle.","exja":"探検隊は密林の中を進むのに苦労した。"},{"id":4864,"en":"densely","ja":"密集して\ndensely populatedで「人口密度が高い」。地理・都市の文脈で頻出","level":7,"lnum":1,"ex":"Tokyo is one of the most densely populated cities in the world.","exja":"東京は世界で最も人口密度が高い都市の一つだ。"},{"id":4865,"en":"dental","ja":"歯の・歯科の\ndental care（歯のケア）、dental clinic（歯科医院）が頻出表現","level":7,"lnum":1,"ex":"Regular dental check-ups can help prevent serious tooth problems.","exja":"定期的な歯科検診は深刻な歯の問題を予防するのに役立つ。"},{"id":4866,"en":"dependable","ja":"信頼できる\nreliable と同義だがよりくだけた感じ。人・物の両方を修飾できる","level":7,"lnum":1,"ex":"She is a dependable team member who always meets her deadlines.","exja":"彼女は常に期限を守る信頼できるチームメンバーだ。"},{"id":4867,"en":"deposit","ja":"預金する・堆積させる\n銀行の預金（名詞・動詞）と地質の堆積物（名詞）の両方を覚える","level":7,"lnum":1,"ex":"She deposited her paycheck into her savings account every month.","exja":"彼女は毎月給与を貯蓄口座に入金していた。"},{"id":4868,"en":"deputy","ja":"副〜・代理人\ndeputy mayor（副市長）のように「副・代理」を示す接頭詞的な使い方","level":7,"lnum":1,"ex":"The deputy mayor represented the city at the international summit.","exja":"副市長は国際サミットで市を代表した。"},{"id":4869,"en":"descend","ja":"降りる・下降する\nascend（上る）の対義語。descend from〜で「〜の子孫である」も重要","level":7,"lnum":1,"ex":"The hikers descended the steep mountain path as the sun began to set.","exja":"日が沈み始めると、ハイカーたちは急な山道を下り始めた。"},{"id":4870,"en":"descriptive","ja":"描写的な・説明的な\ndescriptive writing（描写的な文章）。prescriptiveと対比される","level":7,"lnum":1,"ex":"Her writing was highly descriptive, painting a vivid picture of the landscape.","exja":"彼女の文章は非常に描写的で、その風景を生き生きと描き出していた。"},{"id":4871,"en":"desirable","ja":"望ましい・魅力的な\nit is desirable that〜の構文が論文・試験で頻出する","level":7,"lnum":1,"ex":"Living close to public transportation is highly desirable for most city dwellers.","exja":"公共交通機関の近くに住むことは、ほとんどの都市住民にとって非常に望ましいことだ。"},{"id":4872,"en":"desire","ja":"望む・欲求する\n名詞と動詞の両方で使う。a strong desire for〜で「〜への強い欲求」","level":7,"lnum":1,"ex":"She had a strong desire to travel the world before settling down.","exja":"落ち着く前に世界を旅したいという強い欲求が彼女にはあった。"},{"id":4873,"en":"desktop","ja":"デスクトップ\nコンピュータ用語として必須。desktop computer（デスクトップPC）","level":7,"lnum":1,"ex":"He set up a powerful desktop computer in his home office for video editing.","exja":"彼は動画編集のために自宅のオフィスに高性能なデスクトップコンピューターを設置した。"},{"id":4874,"en":"desolation","ja":"荒廃・孤独感\na scene of desolationで「荒廃した光景」。感情的孤独にも使う","level":7,"lnum":1,"ex":"After the hurricane, the town was left in a state of complete desolation.","exja":"ハリケーンの後、町は完全な荒廃状態に取り残された。"},{"id":4875,"en":"desperately","ja":"必死に・絶望的に\ndesperately need〜で「〜を切実に必要とする」。強調の意味合い","level":7,"lnum":1,"ex":"The rescue team desperately searched the rubble for survivors.","exja":"救助隊は生存者を求めてがれきの中を必死に捜索した。"},{"id":4876,"en":"desperation","ja":"絶望・自暴自棄\nin desperationで「やけになって」。hopelessness（絶望）とは少し違う","level":7,"lnum":1,"ex":"In his desperation to pass the exam, he stayed up all night studying.","exja":"試験に合格しようと必死になって、彼は一晩中勉強し続けた。"},{"id":4877,"en":"despise","ja":"軽蔑する・憎む\ncontemptと近い意味だが動詞形。despise oneselfで自己嫌悪も表す","level":7,"lnum":1,"ex":"She came to despise the corrupt system that favored the wealthy.","exja":"彼女は富裕層を優遇する腐敗したシステムを軽蔑するようになった。"},{"id":4878,"en":"destiny","ja":"運命・宿命\nfateと類義だが「使命感」を伴うことが多い。manifest destinyが有名","level":7,"lnum":1,"ex":"He believed it was his destiny to become a great musician.","exja":"偉大な音楽家になることが自分の運命だと彼は信じていた。"},{"id":4879,"en":"detach","ja":"切り離す・離れる\ndetach from〜で「〜から切り離す」。emotionally detachedで「感情移入しない」","level":7,"lnum":1,"ex":"She tried to detach herself emotionally from the difficult situation.","exja":"彼女はその困難な状況から感情的に距離を置こうとした。"},{"id":4880,"en":"detachment","ja":"分離・超然とした態度\n感情的な距離感を表すことが多い。military detachment（分遣隊）も重要","level":7,"lnum":1,"ex":"His emotional detachment made it difficult for others to connect with him.","exja":"感情的な超然とした態度のせいで、他者が彼と関わりを持つのが難しかった。"},{"id":4881,"en":"detailed","ja":"詳細な\na detailed account/report（詳細な報告書）。in detailと合わせて覚える","level":7,"lnum":1,"ex":"The report provided a detailed analysis of the company's financial situation.","exja":"その報告書は会社の財政状況の詳細な分析を提供した。"},{"id":4882,"en":"detect","ja":"発見する・感知する\n探偵（detective）の語源。detect a problemで「問題を察知する」","level":7,"lnum":1,"ex":"The smoke detector was able to detect the fire before it spread.","exja":"煙感知器は火が広がる前に火災を感知することができた。"},{"id":4883,"en":"determined","ja":"決意した・断固たる\nbe determined to doで「〜しようと決意している」の構文が頻出","level":7,"lnum":1,"ex":"She was determined to finish the marathon, even when her legs were aching.","exja":"足が痛くても、彼女はマラソンを完走しようと決意していた。"},{"id":4884,"en":"determiner","ja":"限定詞\n文法用語。the/a/this/myなどの冠詞・代名詞的な品詞を指す","level":7,"lnum":1,"ex":"In English grammar, words like \"the,\" \"a,\" and \"this\" are called determiners.","exja":"英文法では、「the」「a」「this」のような語を限定詞と呼ぶ。"},{"id":4885,"en":"devil","ja":"悪魔\nthe devil is in the detailsで「細部に落とし穴がある」という慣用句","level":7,"lnum":1,"ex":"The devil is in the details, so make sure to review every part of the contract.","exja":"細部に落とし穴があるから、契約書のすべての箇所をしっかり確認してください。"},{"id":4886,"en":"devote","ja":"ささげる・専念する\ndevote oneself to〜またはbe devoted toで「〜に専念する」","level":7,"lnum":1,"ex":"She devoted her entire career to helping disadvantaged children.","exja":"彼女はキャリア全体を不遇な子どもたちを支援することにささげた。"},{"id":4887,"en":"devoted","ja":"献身的な・熱心な\na devoted fan（熱烈なファン）。be devoted to〜の形で頻出する","level":7,"lnum":1,"ex":"He was a devoted father who never missed his children's school events.","exja":"彼は子どもたちの学校行事に欠かさず参加する献身的な父親だった。"},{"id":4888,"en":"diarrhea/diarrhoea","ja":"下痢\n医療・健康の文脈で必要な語彙。米国式diarrhea、英国式diarrhoea","level":7,"lnum":1,"ex":"The traveler caught diarrhea after eating street food in a foreign country.","exja":"その旅行者は外国で屋台の食べ物を口にした後、下痢になった。"},{"id":4889,"en":"dictator","ja":"独裁者\ndictate（命令する）の派生語。政治・歴史の文脈で頻出する語","level":7,"lnum":1,"ex":"The country suffered for decades under the rule of a brutal dictator.","exja":"その国は残忍な独裁者の支配下で何十年も苦しんだ。"},{"id":4890,"en":"digest","ja":"消化する・要約\n名詞（ダイジェスト）と動詞（消化する・理解する）の両方で使う","level":7,"lnum":1,"ex":"It took her a few minutes to digest all the information she had just received.","exja":"受け取ったばかりの情報をすべて消化するのに、彼女は数分かかった。"},{"id":4891,"en":"dignify","ja":"威厳を与える・高める\ndignify with a responseで「返答するに値する」という皮肉表現も重要","level":7,"lnum":1,"ex":"She refused to dignify the rude comment with a response.","exja":"彼女はその失礼なコメントに返答するに値しないと思い、無視した。"},{"id":4892,"en":"dignity","ja":"尊厳・品位\nwith dignityで「威厳を持って」。human dignityが人権文脈で頻出","level":7,"lnum":1,"ex":"Even in the most difficult circumstances, she maintained her dignity.","exja":"最も困難な状況でも、彼女は品位を保ち続けた。"},{"id":4893,"en":"dilemma","ja":"ジレンマ・板挟み\nbe in a dilemmaで「ジレンマに陥っている」。moral dilemmaも重要","level":7,"lnum":1,"ex":"She faced a moral dilemma when asked to keep a colleague's mistake secret.","exja":"同僚のミスを秘密にするよう求められ、彼女は道徳的ジレンマに直面した。"},{"id":4894,"en":"dim","ja":"薄暗い・鈍い\ndim lightで「薄暗い光」。take a dim view ofで「〜を否定的に見る」","level":7,"lnum":1,"ex":"The dim light in the hallway made it hard to read the room numbers.","exja":"廊下の薄暗い明かりのせいで、部屋番号を読むのが難しかった。"},{"id":4895,"en":"dime","ja":"ダイム（10セント硬貨）\n米国の10セント硬貨。dime a dozen（ありふれた）の慣用表現が重要","level":7,"lnum":1,"ex":"In the United States, a dime is a ten-cent coin.","exja":"アメリカでは、ダイムは10セント硬貨だ。"},{"id":4896,"en":"dimension","ja":"次元・側面\nthree-dimensional（三次元の）。add a new dimensionで「新たな側面を加える」","level":7,"lnum":1,"ex":"The new technology added an exciting dimension to the learning experience.","exja":"その新しい技術は学習体験に刺激的な側面を加えた。"},{"id":4897,"en":"dip","ja":"浸す・下がる\ndip into（少し手をつける）など多様な表現。一時的な下落にも使う","level":7,"lnum":1,"ex":"She dipped her brush into the paint and started to draw on the canvas.","exja":"彼女は絵の具に筆を浸し、キャンバスに描き始めた。"},{"id":4898,"en":"diphtheria","ja":"ジフテリア\n伝染病の名前。発音注意（ディフ-スィリア）。歴史・医療文脈で使う","level":7,"lnum":1,"ex":"Vaccination campaigns have nearly eliminated diphtheria in developed countries.","exja":"ワクチン接種キャンペーンにより、先進国ではジフテリアがほぼ根絶されている。"},{"id":4899,"en":"diploma","ja":"卒業証書・ディプロマ\nhigh school diploma（高校卒業証書）。資格・学位証明書を広く指す","level":7,"lnum":1,"ex":"After four years of hard work, she finally received her high school diploma.","exja":"4年間の努力の末、彼女はついに高校の卒業証書を受け取った。"},{"id":4900,"en":"diplomat","ja":"外交官\ndiplomacy（外交）の派生語。diplomatic（外交的な・如才ない）も重要","level":7,"lnum":1,"ex":"The diplomat worked tirelessly to negotiate a peace agreement between the two nations.","exja":"その外交官は2国間の和平協定を交渉するために精力的に取り組んだ。"},{"id":4901,"en":"disappearance","ja":"消失・行方不明\nthe disappearance of〜で「〜の消滅」。人・物・現象に広く使う","level":7,"lnum":1,"ex":"The sudden disappearance of the wildlife in the area alarmed conservationists.","exja":"その地域での野生動物の突然の消滅は自然保護主義者たちを驚愕させた。"},{"id":4902,"en":"disapproval","ja":"不承認・非難\nexpress disapprovalで「不満を示す」。approvalの反意語","level":7,"lnum":1,"ex":"Her parents expressed their disapproval of her decision to drop out of college.","exja":"両親は彼女の大学中退という決断への不承認を表明した。"},{"id":4903,"en":"disapprove","ja":"承認しない・反対する\ndisapprove of〜の形で使う。approveの対義語として覚える","level":7,"lnum":1,"ex":"Many residents disapprove of the plan to build a highway through the park.","exja":"多くの住民が公園を通る高速道路建設計画に反対している。"},{"id":4904,"en":"discharge","ja":"放出・解放・退院\ndischarge from hospital（退院）など文脈によって意味が大きく変わる","level":7,"lnum":1,"ex":"After three days in the hospital, the patient was discharged and allowed to go home.","exja":"入院3日後、患者は退院して帰宅が許可された。"},{"id":4905,"en":"disciple","ja":"弟子・信者\nキリスト教の「12使徒」でよく使われる。広く師に従う学徒を指す","level":7,"lnum":1,"ex":"The philosopher gathered a group of devoted disciples who followed his teachings.","exja":"その哲学者は、自分の教えに従う熱心な弟子たちのグループを集めた。"},{"id":4906,"en":"discipline","ja":"規律・訓練・分野\nself-discipline（自己規律）。academic discipline（学問分野）も重要","level":7,"lnum":1,"ex":"Success in any field requires discipline and consistent effort over time.","exja":"どの分野での成功も、規律と継続的な努力を必要とする。"},{"id":4907,"en":"disconnect","ja":"切断する・関係を断つ\nfeel disconnected（疎外感がある）のような感情的な意味でも使う","level":7,"lnum":1,"ex":"She felt disconnected from her classmates after being absent for so long.","exja":"長期欠席の後、彼女はクラスメートから切り離されたように感じた。"},{"id":4908,"en":"discredit","ja":"信用を傷つける・不名誉\ndiscredit someone（人の信用を落とす）。名詞・動詞の両方で使う","level":7,"lnum":1,"ex":"The journalist's investigation discredited the minister's claims.","exja":"ジャーナリストの調査が大臣の主張の信用を傷つけた。"},{"id":4909,"en":"discriminate","ja":"差別する・区別する\ndiscriminate against〜で「〜を差別する」。differentiate（区別）より否定的","level":7,"lnum":1,"ex":"It is illegal to discriminate against employees based on their gender or age.","exja":"性別や年齢に基づいて従業員を差別することは違法だ。"},{"id":4910,"en":"disgrace","ja":"不名誉・恥\nit's a disgraceで「恥ずかしいことだ」。fall from graceと関連する語","level":7,"lnum":1,"ex":"It was a disgrace that the children had to study in such poor conditions.","exja":"子どもたちがそのような劣悪な環境で勉強しなければならないのは恥ずかしいことだった。"},{"id":4911,"en":"disguise","ja":"変装・偽装\nin disguise（変装して）。a blessing in disguise（不幸中の幸い）が重要","level":7,"lnum":1,"ex":"He disguised himself as a security guard to enter the building.","exja":"彼は建物に入るために警備員に変装した。"},{"id":4912,"en":"disguise","ja":"変装する・隠す\ndisguise oneself as〜で「〜に変装する」。感情を隠す比喩にも使う","level":7,"lnum":1,"ex":"He disguised himself as a security guard to enter the building.","exja":"彼はビルに入るために警備員に変装した。"},{"id":4913,"en":"dishonesty","ja":"不誠実・不正直\nhonesty（誠実さ）の対義語。moral character（道徳性）の文脈で使う","level":7,"lnum":1,"ex":"The candidate's dishonesty was revealed when the investigation found forged documents.","exja":"調査で偽造文書が見つかり、候補者の不誠実さが明らかになった。"},{"id":4914,"en":"disillusion","ja":"幻滅させる\nbe disillusioned with〜で「〜に幻滅する」。期待が裏切られた気持ち","level":7,"lnum":1,"ex":"She became disillusioned with politics after years of broken promises.","exja":"何年にもわたる約束の不履行の後、彼女は政治に幻滅した。"},{"id":4915,"en":"dismiss","ja":"解雇する・却下する\ndismiss an idea（考えを却下）、dismiss an employee（解雇）の両用法","level":7,"lnum":1,"ex":"The manager dismissed the idea without even considering its potential benefits.","exja":"マネージャーは潜在的な利点を考慮することさえなく、そのアイデアを却下した。"},{"id":4916,"en":"disorder","ja":"無秩序・障害\nmental disorder（精神障害）、in disorderで「乱雑な状態で」が頻出","level":7,"lnum":1,"ex":"The protesters threw the city into disorder during the demonstration.","exja":"デモ中、抗議者たちは市を無秩序状態に陥れた。"},{"id":4917,"en":"disorderly","ja":"無秩序な・乱暴な\ndisorderly conduct（迷惑行為）は法律用語としても使われる","level":7,"lnum":1,"ex":"The audience became disorderly after the concert was suddenly cancelled.","exja":"コンサートが突然キャンセルされた後、観客は乱暴になった。"},{"id":4918,"en":"disorganized/disorganised","ja":"まとまりのない・雑然とした\norganizedの反義語。人の性格と場所・出来事の両方に使う","level":7,"lnum":1,"ex":"His desk was so disorganized that he could never find anything.","exja":"彼の机はとても雑然としていて、何も見つけられなかった。"},{"id":4919,"en":"dispensable","ja":"なくても済む・不要な\nindispensable（不可欠）の反意語。重要度が低い存在に使う","level":7,"lnum":1,"ex":"In a time of budget cuts, luxuries are often considered dispensable.","exja":"予算削減の時期、贅沢品はしばしばなくても済むものとみなされる。"},{"id":4920,"en":"displace","ja":"取って代わる・避難させる\ndisplaced people（難民・避難民）として現代の社会問題で頻出","level":7,"lnum":1,"ex":"The flood displaced thousands of families from their homes.","exja":"洪水が何千もの家族を自宅から避難させた。"},{"id":4921,"en":"displeasure","ja":"不満・不快感\nexpress one's displeasureで「不満を示す」。書き言葉的な表現","level":7,"lnum":1,"ex":"She made no effort to hide her displeasure at the way the meeting was handled.","exja":"会議の進め方への不満を彼女は隠そうともしなかった。"},{"id":4922,"en":"disposal","ja":"処理・廃棄\nwaste disposal（廃棄物処理）。at someone's disposalで「〜の自由になる」","level":7,"lnum":1,"ex":"The city needs better systems for the disposal of household waste.","exja":"市は家庭ごみの処理のためのより良いシステムを必要としている。"},{"id":4923,"en":"disposition","ja":"気質・傾向・配置\na cheerful disposition（明るい気質）。a disposition toward〜（〜への傾向）","level":7,"lnum":1,"ex":"She has a cheerful disposition that makes her popular with everyone.","exja":"彼女は明るい気質を持ち、それがみんなに好かれる理由となっている。"},{"id":4924,"en":"dispute","ja":"論争・異議を唱える\nbeyond dispute（議論の余地なく）。in dispute（係争中の）が頻出","level":7,"lnum":1,"ex":"The two countries are in dispute over the ownership of the small island.","exja":"2国はその小さな島の領有権をめぐって争っている。"},{"id":4925,"en":"disqualify","ja":"失格にする・資格を剥奪する\nbe disqualified from〜で「〜の資格を失う」。スポーツ・試験で頻出","level":7,"lnum":1,"ex":"The athlete was disqualified from the race for using a banned substance.","exja":"その選手は禁止薬物を使用したとして競技から失格にされた。"},{"id":4926,"en":"disregard","ja":"無視する・無視\nhave a total disregard forで「〜を全く顧みない」という強い表現","level":7,"lnum":1,"ex":"He had a total disregard for the safety rules, which put others at risk.","exja":"彼は安全規則をまったく無視しており、それが他者を危険にさらした。"},{"id":4927,"en":"disrupt","ja":"妨害する・混乱させる\ndisrupt a meeting（会議を妨害）。テクノロジー分野のdisruptive innovation","level":7,"lnum":1,"ex":"A sudden power failure disrupted the live broadcast.","exja":"突然の停電が生放送を妨害した。"},{"id":4928,"en":"dissatisfaction","ja":"不満・不平\nexpress dissatisfactionで「不満を述べる」。satisfactionの反意語","level":7,"lnum":1,"ex":"Employees expressed their dissatisfaction with the new working conditions.","exja":"従業員たちは新しい労働条件への不満を表明した。"},{"id":4929,"en":"dissatisfied","ja":"不満な\nbe dissatisfied with〜の形で使う。satisfiedの対義語として覚える","level":7,"lnum":1,"ex":"Customers were dissatisfied with the slow delivery service.","exja":"顧客たちは遅い配送サービスに不満を持っていた。"},{"id":4930,"en":"dissident","ja":"反体制者・反対意見の\npolitical dissident（政治的反体制派）。权威に反対する人を指す","level":7,"lnum":1,"ex":"The government silenced political dissidents who spoke out against the regime.","exja":"政府は体制に反対を唱えた政治的反体制者を沈黙させた。"},{"id":4931,"en":"distinguished","ja":"著名な・優れた\na distinguished professor（著名な教授）。distinguishとの関連で覚える","level":7,"lnum":1,"ex":"The university honored its most distinguished alumni at the annual ceremony.","exja":"大学は年次式典で最も著名な卒業生たちを称えた。"},{"id":4932,"en":"distortion","ja":"歪曲・歪み\na distortion of the factsで「事実の歪曲」。音響や映像の歪みにも使う","level":7,"lnum":1,"ex":"The article was full of distortions of the facts.","exja":"その記事は事実の歪曲に満ちていた。"},{"id":4933,"en":"distract","ja":"気を散らす\nbe distracted by〜で「〜に気を取られる」。concentrate（集中）の反対","level":7,"lnum":1,"ex":"Loud music can distract students from focusing on their studies.","exja":"大きな音楽は学生が勉強に集中するのを妨げる可能性がある。"},{"id":4934,"en":"distraction","ja":"気晴らし・注意散漫\na welcome distractionで「ありがたい気分転換」。無駄な干渉も指す","level":7,"lnum":1,"ex":"He found cooking to be a welcome distraction from the pressures of work.","exja":"彼は料理が仕事のプレッシャーからのありがたい気晴らしになると感じた。"},{"id":4935,"en":"distressing","ja":"苦しい・悲痛な\na distressing situation（辛い状況）。distress（苦悩）の形容詞形","level":7,"lnum":1,"ex":"The news of the accident was deeply distressing for everyone in the community.","exja":"事故のニュースは地域の全員にとって非常に苦しいものだった。"},{"id":4936,"en":"distributor","ja":"販売業者・配給会社\nmanufacturer（製造者）→distributor（流通業者）→retailer（小売）の流れ","level":7,"lnum":1,"ex":"The company signed a deal with a major distributor to sell its products nationwide.","exja":"その会社は製品を全国販売するための大手販売業者と契約を結んだ。"},{"id":4937,"en":"diversion","ja":"迂回・気晴らし・転換\ncreate a diversion（陽動作戦）。道路迂回と娯楽の両方の意味がある","level":7,"lnum":1,"ex":"The road construction created a diversion that added 20 minutes to the commute.","exja":"道路工事が迂回路を作り、通勤時間が20分増えた。"},{"id":4938,"en":"divert","ja":"迂回させる・そらす\ndivert attention from〜で「〜から注意をそらす」が頻出表現","level":7,"lnum":1,"ex":"The pilot had to divert the plane to another airport due to bad weather.","exja":"悪天候のために、パイロットは別の空港に飛行機を迂回させなければならなかった。"},{"id":4939,"en":"divided","ja":"分かれた・意見が割れた\nbe divided over〜で「〜について意見が割れている」という政治用語","level":7,"lnum":1,"ex":"Public opinion is divided on whether the new law should be passed.","exja":"新しい法律を通過させるべきかどうかについて世論は割れている。"},{"id":4940,"en":"division","ja":"分割・部門・割り算\ndivision of labor（分業）。数学の割り算と企業の部門の両方で使う","level":7,"lnum":1,"ex":"There is a clear division of responsibilities within the team.","exja":"チーム内では責任の明確な分担がある。"},{"id":4941,"en":"divorce","ja":"離婚\nget a divorce（離婚する）。divorce rateで「離婚率」が社会問題文脈で頻出","level":7,"lnum":1,"ex":"She divorced her husband after discovering he had lied to her repeatedly.","exja":"彼が繰り返し嘘をついていたことがわかり、彼女は夫と離婚した。"},{"id":4942,"en":"divorce","ja":"離婚する\ndivorce someone / get divorced from〜の使い方に注意する動詞用法","level":7,"lnum":1,"ex":"The couple decided to divorce after years of unhappiness.","exja":"そのカップルは長年の不幸の末、離婚することを決めた。"},{"id":4943,"en":"DNA","ja":"DNA・遺伝子\nDeoxyribonucleic Acidの略。genetic information（遺伝情報）とセット","level":7,"lnum":1,"ex":"A DNA test confirmed that the two fossils belonged to the same species.","exja":"DNA検査により、2つの化石が同じ種に属することが確認された。"},{"id":4944,"en":"dock","ja":"ドック・係留する\nship docksで「船が入港する」。dry dockで「乾ドック」も重要","level":7,"lnum":1,"ex":"The ship docked at the port early in the morning to unload its cargo.","exja":"船は貨物を降ろすために早朝に港に入港した。"},{"id":4945,"en":"domestic","ja":"国内の・家庭の\ndomestic violence（家庭内暴力）、domestic policy（国内政策）が頻出","level":7,"lnum":1,"ex":"The rise in domestic violence cases prompted the government to launch a new program.","exja":"家庭内暴力の件数の増加が、政府に新しいプログラムを開始させた。"},{"id":4946,"en":"dominate","ja":"支配する・占める\ndominate the market（市場を支配）。be dominated byで受け身も頻出","level":7,"lnum":1,"ex":"One country should not be allowed to dominate the global economy.","exja":"一国が世界経済を支配することは許されるべきではない。"},{"id":4947,"en":"donate","ja":"寄付する\ndonate to a charityで「慈善団体に寄付する」。donationとセットで覚える","level":7,"lnum":1,"ex":"She donated half of her prize money to a local children's hospital.","exja":"彼女は賞金の半分を地元の小児病院に寄付した。"},{"id":4948,"en":"donation","ja":"寄付・献金\nmake a donationで「寄付する」。organ donation（臓器提供）も重要","level":7,"lnum":1,"ex":"The organization received a large donation from an anonymous supporter.","exja":"その組織は匿名の支援者から多額の寄付を受け取った。"},{"id":4949,"en":"donkey","ja":"ロバ\ndonkey work（骨の折れる単調な作業）という慣用表現が試験に出る","level":7,"lnum":1,"ex":"The farmer used a donkey to carry supplies up the steep mountain trail.","exja":"農夫は急な山道で物資を運ぶためにロバを使った。"},{"id":4950,"en":"doom","ja":"破滅・不吉な運命\ndoom and gloom（暗澹たる見通し）。doomedで「運命づけられた」","level":7,"lnum":1,"ex":"Many scientists warn that continued pollution could spell doom for future generations.","exja":"多くの科学者は、汚染が続けば将来の世代に破滅をもたらす恐れがあると警告している。"},{"id":4951,"en":"doorkeeper","ja":"門番・扉の番人\n古風な表現。現代ではdoormansやsecurity guardが一般的","level":7,"lnum":1,"ex":"The doorkeeper greeted every guest with a warm smile at the entrance.","exja":"門番は入口でにこやかな笑顔ですべての来客を迎えた。"},{"id":4952,"en":"doorway","ja":"戸口・出入り口\nstand in the doorwayで「戸口に立つ」。空間・機会への入口の比喩も","level":7,"lnum":1,"ex":"She stood in the doorway, unsure whether to enter the room.","exja":"彼女は部屋に入るべきか迷いながら、戸口に立っていた。"},{"id":4953,"en":"dorm","ja":"寮（dormitoryの略）\n口語的な略語。university dormで「大学の寮」という表現が頻出","level":7,"lnum":1,"ex":"Living in a dorm during the first year of university was a great experience.","exja":"大学1年目の寮生活はとても良い経験だった。"},{"id":4954,"en":"dormitory","ja":"寮・学生寮\ndormitory lifeで「寮生活」。dormとの違いは正式度（dormが口語）","level":7,"lnum":1,"ex":"The new dormitory can accommodate up to 300 students.","exja":"新しい寮は最大300人の学生を収容できる。"},{"id":4955,"en":"dose","ja":"投与量・一服\na dose of medicine（薬の一服）。dose of realityで「現実の洗礼」も使う","level":7,"lnum":1,"ex":"The doctor prescribed a low dose of medicine to start with.","exja":"医師はまず低用量の薬を処方した。"},{"id":4956,"en":"double","ja":"二倍・倍増する\n名詞・動詞・形容詞の多品詞語。double check（ダブルチェック）も重要","level":7,"lnum":1,"ex":"They doubled the recipe to make enough food for the entire family.","exja":"家族全員分の食事を用意するために、彼らはレシピの分量を倍にした。"},{"id":4957,"en":"double","ja":"二倍にする・倍増する\ndoubleの動詞用法。The population doubledで「人口が二倍になった」","level":7,"lnum":1,"ex":"The company plans to double its workforce over the next three years.","exja":"その会社は今後3年間で従業員数を2倍にする計画だ。"},{"id":4958,"en":"doubly","ja":"二重に\ndoubly importantで「二重に重要な」。強調するときに便利な副詞","level":7,"lnum":1,"ex":"It is doubly important to check your work carefully on an exam.","exja":"試験では自分の解答を注意深く確認することが二重に重要だ。"},{"id":4959,"en":"doubtful","ja":"疑わしい・不確かな\nit is doubtful whether〜という構文が論文・試験に頻出する","level":7,"lnum":1,"ex":"It is doubtful whether the project can be completed within the budget.","exja":"プロジェクトが予算内で完了できるかどうかは疑わしい。"},{"id":4960,"en":"dove","ja":"ハト・平和の象徴\npigeonと区別。平和の象徴として政治的文脈でも使われる重要語","level":7,"lnum":1,"ex":"The release of a white dove symbolized the beginning of the peace talks.","exja":"白いハトを放つことは、和平交渉の始まりを象徴した。"},{"id":4961,"en":"downfall","ja":"失脚・崩壊\nsomeone's downfallで「〜の失脚の原因」という使い方が典型","level":7,"lnum":1,"ex":"His arrogance was ultimately the cause of his downfall.","exja":"傲慢さが最終的に彼の失脚の原因となった。"},{"id":4962,"en":"downsize","ja":"縮小する・人員削減する\n企業の人員削減（リストラ）の意味がビジネス文脈で最頻出","level":7,"lnum":1,"ex":"The company had to downsize its workforce due to declining sales.","exja":"売上の低下に伴い、会社は従業員数を削減しなければならなかった。"},{"id":4963,"en":"dowry","ja":"持参金・嫁入り道具\n花嫁の持参金を指す文化的語彙。国際文化・人権の文脈で重要","level":7,"lnum":1,"ex":"The tradition of paying a dowry has been abolished in many countries.","exja":"持参金を支払う慣習は多くの国で廃止されている。"},{"id":4964,"en":"draft/draught","ja":"草稿・下書き・すきま風\ndraft（米）/draught（英）。first draftで「初稿」、on draft（生ビール）","level":7,"lnum":1,"ex":"She submitted the first draft of her essay for feedback.","exja":"彼女はフィードバックをもらうために小論文の最初の草稿を提出した。"},{"id":4965,"en":"drain","ja":"排水溝・排水する\nbrain drain（頭脳流出）という重要な慣用表現がある。水を抜くことも","level":7,"lnum":1,"ex":"Running a business can drain your energy if you don't take time to rest.","exja":"休息を取らなければ、ビジネスを運営することはあなたの活力を消耗させる可能性がある。"},{"id":4966,"en":"drain","ja":"排水する・消耗させる\ndrain someone's energy（活力を奪う）のような比喩的用法が重要","level":7,"lnum":1,"ex":"The long meeting completely drained her energy.","exja":"長い会議で彼女のエネルギーは完全に消耗した。"},{"id":4967,"en":"dramatically","ja":"劇的に・大幅に\nincrease dramaticallyで「劇的に増加する」。強調表現として頻出","level":7,"lnum":1,"ex":"The number of electric vehicles on the road has increased dramatically.","exja":"道路上の電気自動車の数は劇的に増加した。"},{"id":4968,"en":"drapery","ja":"ドレープ・布地\nカーテンや垂れ下がる布を指す。室内装飾や美術の文脈で使われる","level":7,"lnum":1,"ex":"The stage was decorated with rich drapery that added elegance to the performance.","exja":"舞台は豪華な布地で飾られ、パフォーマンスに優雅さを加えた。"},{"id":4969,"en":"dread","ja":"ひどく恐れる・恐怖\na sense of dreadで「恐怖感」。dreadful（恐ろしい）とセットで覚える","level":7,"lnum":1,"ex":"She had always dreaded public speaking, so she joined a debate club to overcome it.","exja":"彼女は常に人前での発言を恐れていたので、それを克服するためにディベートクラブに入った。"},{"id":4970,"en":"dreadful","ja":"ひどい・恐ろしい\na dreadful mistakeで「ひどい間違い」。口語では「とてもひどい」の強調","level":7,"lnum":1,"ex":"The weather was absolutely dreadful during our camping trip.","exja":"キャンプ旅行中、天気はとてもひどかった。"},{"id":4971,"en":"dreamy","ja":"夢見がちな・ぼんやりした\na dreamy expressionで「夢見るような表情」。現実から離れた様子を表す","level":7,"lnum":1,"ex":"He had a dreamy expression on his face as he stared out the window.","exja":"窓の外を見つめながら、彼は夢見るような表情を浮かべていた。"},{"id":4972,"en":"drinkable","ja":"飲める・飲料に適した\nIs the water drinkable?（この水は飲めますか？）。-ableで可能を表す","level":7,"lnum":1,"ex":"After boiling the water, it should be drinkable for a short period.","exja":"水を沸騰させた後は、しばらくの間は飲める状態になる。"},{"id":4973,"en":"droop","ja":"垂れ下がる・しょんぼりする\n花や気力が萎えて垂れる様子。sagging（弛む）と近い意味","level":7,"lnum":1,"ex":"The flowers began to droop after being left without water for too long.","exja":"水がなさすぎて、花が垂れ下がり始めた。"},{"id":4974,"en":"dropout","ja":"中退者・脱落者\nschool dropoutで「学校中退者」。社会問題の文脈で頻出する語","level":7,"lnum":1,"ex":"The program was designed to help school dropouts get back into education.","exja":"そのプログラムは学校中退者が再び教育を受けられるよう支援するために設計された。"},{"id":4975,"en":"drought","ja":"干ばつ\nsevere drought（深刻な干ばつ）。気候変動・農業問題の文脈で必須語彙","level":7,"lnum":1,"ex":"The severe drought destroyed most of the crops in the region.","exja":"深刻な干ばつがその地域の農作物のほとんどを破壊した。"},{"id":4976,"en":"duel","ja":"決闘・競い合い\nfight a duelで「決闘する」。精神的な対立の比喩としても使われる","level":7,"lnum":1,"ex":"The two rivals agreed to settle their dispute in a duel at dawn.","exja":"2人のライバルは夜明けの決闘で争いを解決することに同意した。"},{"id":4977,"en":"dumb","ja":"口のきけない・馬鹿な\n元は「話せない」の意味だが、現代の口語では「馬鹿な」の意味が主","level":7,"lnum":1,"ex":"It was a dumb mistake to leave the keys inside the locked car.","exja":"鍵をかかった車の中に置き忘れるのは馬鹿げたミスだった。"},{"id":4978,"en":"duplicate","ja":"複製・コピー\nin duplicate（二部作成して）。duplicate effortで「無駄な重複作業」","level":7,"lnum":1,"ex":"Please duplicate the document and keep one copy for your records.","exja":"書類を複製して、記録のために1部手元に保管してください。"},{"id":4979,"en":"duplication","ja":"複製・重複\navoid duplicationで「重複を避ける」。業務効率の文脈で頻出する","level":7,"lnum":1,"ex":"The new system was designed to avoid duplication of work across departments.","exja":"新しいシステムは部門をまたいだ業務の重複を避けるために設計された。"},{"id":4980,"en":"dwarf","ja":"小人・矮小化する\n動詞で「〜を小さく見せる」という比喩が重要。Snow White and the 7 Dwarfs","level":7,"lnum":1,"ex":"The enormous skyscraper dwarfed all the surrounding buildings.","exja":"巨大な超高層ビルは周囲のすべての建物を矮小に見せた。"},{"id":4981,"en":"dye","ja":"染料・染める\n名詞と動詞の両方で使う。dye-free（染料なし）という表示でも頻出","level":7,"lnum":1,"ex":"She dyed her hair a deep red color for the school festival.","exja":"彼女は学校のお祭りのために髪を深みのある赤色に染めた。"},{"id":4982,"en":"dynamic","ja":"活力のある・力学\na dynamic personality（活発な個性）。dynamics（力学・動態）も重要","level":7,"lnum":1,"ex":"The new CEO brought a dynamic energy to the company that motivated the staff.","exja":"新しいCEOは活力のあるエネルギーを会社にもたらし、スタッフを刺激した。"},{"id":4983,"en":"eagerly","ja":"熱心に・待ち望んで\neagerly awaitedで「待ち望まれた」。eagernessとセットで覚える副詞","level":7,"lnum":1,"ex":"The students eagerly raised their hands to answer the teacher's question.","exja":"生徒たちは先生の質問に答えようと熱心に手を挙げた。"},{"id":4984,"en":"eagle","ja":"ワシ・鷹の目\neagle-eyed（鋭い目を持つ）という形容詞表現が慣用的に使われる","level":7,"lnum":1,"ex":"The eagle soared high above the mountains, scanning the valley below.","exja":"ワシは山々の高くを舞い、眼下の谷を見渡した。"},{"id":4985,"en":"earnings","ja":"収入・利益\nannual earnings（年収）。earningsは複数形で使うことが多い名詞","level":7,"lnum":1,"ex":"His annual earnings increased significantly after he was promoted to manager.","exja":"マネージャーに昇進した後、彼の年収は大幅に増加した。"},{"id":4986,"en":"ease","ja":"容易さ・楽にする\nwith ease（楽に）。ease the pain（痛みを和らげる）の動詞用法も重要","level":7,"lnum":1,"ex":"The new guidelines were designed to ease the process of applying for a visa.","exja":"新しいガイドラインはビザ申請のプロセスを楽にするために設計された。"},{"id":4987,"en":"ease","ja":"和らげる・楽にする\nease tensions（緊張を和らげる）という政治的な文脈での頻出表現","level":7,"lnum":1,"ex":"The medicine helped to ease the pain in her back.","exja":"その薬は彼女の背中の痛みを和らげるのに役立った。"},{"id":4988,"en":"eastward/eastwards","ja":"東方へ\n方向を表す副詞。westward/northward/southwardと合わせて覚える","level":7,"lnum":1,"ex":"The expedition team marched eastward through the desert for three days.","exja":"探検隊は3日間、砂漠を東に向かって行進した。"},{"id":4989,"en":"ecologically","ja":"生態学的に\necologically sustainable（生態学的に持続可能な）。環境科学の文脈で頻出","level":7,"lnum":1,"ex":"We must develop energy sources that are ecologically sustainable.","exja":"私たちは生態学的に持続可能なエネルギー源を開発しなければならない。"},{"id":4990,"en":"ecologist","ja":"生態学者\necology（生態学）の専門家。環境問題の文脈で科学者として登場する","level":7,"lnum":1,"ex":"The ecologist spent years studying the effects of pollution on river ecosystems.","exja":"その生態学者は川の生態系への汚染の影響を長年研究した。"},{"id":4991,"en":"economical","ja":"経済的な・節約の\neconomicと区別する。economical car（燃費の良い車）のように「節約」の意味","level":7,"lnum":1,"ex":"Driving at a steady speed is more economical than accelerating and braking frequently.","exja":"一定速度で走ることは、頻繁に加速・制動を繰り返すよりも経済的だ。"},{"id":4992,"en":"economist","ja":"経済学者\neconomy→economics→economistと派生を覚える。経済分析の専門家","level":7,"lnum":1,"ex":"The economist predicted that inflation would decrease by the end of the year.","exja":"その経済学者は年末までにインフレが低下すると予測した。"},{"id":4993,"en":"ecstatic","ja":"有頂天の・狂喜した\nbe ecstatic about〜で「〜に狂喜する」。extremely happy の強調表現","level":7,"lnum":1,"ex":"She was ecstatic when she found out she had been accepted to her dream university.","exja":"志望大学に合格したと知り、彼女は有頂天になった。"},{"id":4994,"en":"edit","ja":"編集・校正\n名詞と動詞の両方で使う。edit a video（動画を編集する）が現代で頻出","level":7,"lnum":1,"ex":"She edited the short film by cutting unnecessary scenes and adding music.","exja":"彼女は不要なシーンをカットし音楽を加えて短編映画を編集した。"},{"id":4995,"en":"edit","ja":"編集する・修正する\nedit a manuscript（原稿を編集する）。editor（編集者）とセット","level":7,"lnum":1,"ex":"She spent the afternoon editing her report before the deadline.","exja":"彼女は締め切り前にレポートを編集しながら午後を過ごした。"},{"id":4996,"en":"editorial","ja":"社説・編集の\neditorial board（編集委員会）。newspaper editorialで「新聞の社説」","level":7,"lnum":1,"ex":"The newspaper's editorial criticized the government's handling of the crisis.","exja":"その新聞の社説は政府による危機への対応を批判した。"},{"id":4997,"en":"educated","ja":"教育を受けた・知識がある\nwell-educated（高い教育を受けた）。educated guessで「根拠ある推測」","level":7,"lnum":1,"ex":"She was highly educated, having studied at three different universities.","exja":"彼女は3つの異なる大学で学んだ、非常に高い教育を受けた人だった。"},{"id":4998,"en":"educator","ja":"教育者\nteacher より広い概念で、教育に携わる人全般を指すフォーマルな語","level":7,"lnum":1,"ex":"As an educator, she believed every student had the potential to succeed.","exja":"教育者として、彼女はすべての生徒が成功する可能性を持っていると信じていた。"},{"id":4999,"en":"effectively","ja":"効果的に・事実上\neffectively worksで「効果的に機能する」。more effectivelyが比較で頻出","level":7,"lnum":1,"ex":"The new drug effectively reduced symptoms in over 80 percent of patients.","exja":"新薬は患者の80%以上で症状を効果的に軽減した。"},{"id":5000,"en":"effectiveness","ja":"有効性・効果\nthe effectiveness of〜で「〜の有効性」。efficacyとほぼ同義","level":7,"lnum":1,"ex":"Researchers are studying the effectiveness of the new vaccine.","exja":"研究者たちは新しいワクチンの有効性を研究している。"},{"id":5001,"en":"elect","ja":"選出する\nelect A as B（AをBに選ぶ）。the president-elect（次期大統領）も重要","level":7,"lnum":1,"ex":"The students elected a new class president at the beginning of the semester.","exja":"学期始めに、生徒たちは新しいクラス委員長を選出した。"},{"id":5002,"en":"elective","ja":"選択科目・選挙の\nan elective courseで「選択授業」。elective surgery（選択的手術）も頻出","level":7,"lnum":1,"ex":"She chose history and drama as her elective courses for the year.","exja":"彼女はその年の選択科目として歴史とドラマを選んだ。"},{"id":5003,"en":"electrician","ja":"電気技師\n-icianは職業を表す接尾語。technicianやmusician と同じパターン","level":7,"lnum":1,"ex":"The electrician repaired the faulty wiring before it could cause a fire.","exja":"電気技師は火災を引き起こす前に欠陥のある配線を修理した。"},{"id":5004,"en":"electronically","ja":"電子的に\nelectronically submitで「電子提出する」。現代のデジタル文脈で頻出","level":7,"lnum":1,"ex":"All applications must be submitted electronically through the school's website.","exja":"すべての申請は学校のウェブサイトを通じて電子的に提出しなければならない。"},{"id":5005,"en":"electronics","ja":"電子機器・電子工学\nthe electronics industry（電子産業）。家電製品全般を指すことも多い","level":7,"lnum":1,"ex":"The rapid development of electronics has transformed everyday life.","exja":"電子機器の急速な発展が日常生活を一変させた。"},{"id":5006,"en":"elegance","ja":"優雅さ・上品さ\nwith eleganceで「優雅に」。elegant（優雅な）の名詞形として覚える","level":7,"lnum":1,"ex":"The dancer moved across the stage with remarkable elegance and grace.","exja":"ダンサーは見事な優雅さと気品を持って舞台を横切った。"},{"id":5007,"en":"elegant","ja":"優雅な・洗練された\nan elegant solution（エレガントな解決策）。外見と論理の両方に使う","level":7,"lnum":1,"ex":"The architect designed an elegant solution that was both functional and beautiful.","exja":"建築家は機能的でありながら美しいエレガントな解決策を設計した。"},{"id":5008,"en":"elegantly","ja":"優雅に・洗練されて\nelegantly dressedで「エレガントに着飾った」。文体描写でも使う","level":7,"lnum":1,"ex":"The guests were all elegantly dressed for the formal dinner party.","exja":"フォーマルなディナーパーティーに、ゲスト全員が優雅に着飾っていた。"},{"id":5009,"en":"elemental","ja":"根本的な・元素の\nelemental forces（根本的な力）。elementary（基礎的な）と混同しないこと","level":7,"lnum":1,"ex":"The novel explores the elemental forces of love, death, and nature.","exja":"その小説は愛、死、自然という根本的な力を探求している。"},{"id":5010,"en":"eligible","ja":"資格がある・適格な\nbe eligible for〜で「〜の資格がある」。eligible voterで「有権者」","level":7,"lnum":1,"ex":"Only students who have completed all required courses are eligible to graduate.","exja":"すべての必修科目を修了した学生のみが卒業する資格がある。"},{"id":5011,"en":"elite","ja":"エリート・精鋭\nthe elite（エリート層）という意味で社会的階層を示す。形容詞でも使う","level":7,"lnum":1,"ex":"Only the elite few were invited to attend the exclusive ceremony.","exja":"限られたエリートだけが、その特別な式典に招待された。"},{"id":5012,"en":"eloquence","ja":"雄弁さ・表現の豊かさ\nwith great eloquenceで「見事な雄弁で」。eloquent（雄弁な）の名詞形","level":7,"lnum":1,"ex":"His eloquence in debates earned him a reputation as a powerful speaker.","exja":"ディベートでの雄弁さが彼に力強いスピーカーとしての評判をもたらした。"},{"id":5013,"en":"eloquent","ja":"雄弁な・表現豊かな\nan eloquent speech（雄弁なスピーチ）。感情や考えを巧みに表現できる","level":7,"lnum":1,"ex":"She gave an eloquent speech that moved the entire audience to tears.","exja":"彼女は観客全員を涙させる雄弁なスピーチをした。"},{"id":5014,"en":"embassy","ja":"大使館\nthe British Embassy in Tokyo（東京の英国大使館）。外交文脈で必須語","level":7,"lnum":1,"ex":"The Japanese embassy provided assistance to citizens stranded abroad.","exja":"日本大使館は海外で足止めされた市民に支援を提供した。"},{"id":5015,"en":"embrace","ja":"抱擁・受け入れる\nembrace a new idea（新しいアイデアを受け入れる）。名詞・動詞の両方で","level":7,"lnum":1,"ex":"The country decided to embrace renewable energy as part of its climate strategy.","exja":"その国は気候戦略の一環として再生可能エネルギーを受け入れることにした。"},{"id":5016,"en":"emergence","ja":"出現・台頭\nthe emergence of〜で「〜の出現・台頭」。emerge（出現する）の名詞形","level":7,"lnum":1,"ex":"The emergence of social media changed the way people communicate.","exja":"ソーシャルメディアの出現は人々のコミュニケーション方法を変えた。"},{"id":5017,"en":"emphatically","ja":"強調して・断固として\nemphatically deny（断固として否定する）。empha ticの副詞形","level":7,"lnum":1,"ex":"The spokesperson emphatically denied that the company had broken any laws.","exja":"スポークスパーソンは会社が法律を破ったという主張を断固として否定した。"},{"id":5018,"en":"employ","ja":"雇用する・使用する\nemploy 200 workers（200人を雇う）。employ a strategy（戦略を使う）も重要","level":7,"lnum":1,"ex":"The new factory will employ over 500 workers from the local community.","exja":"新しい工場は地域社会から500人以上の労働者を雇用する予定だ。"},{"id":5019,"en":"employee","ja":"従業員・社員\nemployer（雇用者）とemployee（被雇用者）をセットで区別して覚える","level":7,"lnum":1,"ex":"Every employee was given a bonus at the end of the year.","exja":"すべての従業員が年末にボーナスをもらった。"},{"id":5020,"en":"employer","ja":"雇用者・会社\nemployee（従業員）の対義語。employer's obligations（雇用者の義務）","level":7,"lnum":1,"ex":"The employer is responsible for providing a safe working environment.","exja":"雇用者は安全な労働環境を提供する責任がある。"},{"id":5021,"en":"encounter","ja":"出会う・遭遇する\nencounter difficulties（困難に遭遇する）。名詞でも使い「遭遇」の意味","level":7,"lnum":1,"ex":"During her trip to Africa, she encountered many challenges she hadn't expected.","exja":"アフリカへの旅の途中、彼女は予想していなかった多くの困難に遭遇した。"},{"id":5022,"en":"endeavor/endeavour","ja":"努力・試み\nmake every endeavor（あらゆる努力をする）。attemptよりフォーマルな語","level":7,"lnum":1,"ex":"She made every endeavor to complete the project on time.","exja":"彼女はプロジェクトを期限内に完成させるためにあらゆる努力をした。"},{"id":5023,"en":"endlessly","ja":"果てしなく・延々と\nendlessly debating（延々と議論する）。infinitely（無限に）と類義","level":7,"lnum":1,"ex":"The politicians debated endlessly without reaching any conclusion.","exja":"政治家たちはいかなる結論にも達することなく、延々と議論を続けた。"},{"id":5024,"en":"endorse","ja":"支持する・承認する\nendorse a candidate（候補者を支持する）。credi cardのendorsementも重要","level":7,"lnum":1,"ex":"Several celebrities endorsed the charity campaign to raise awareness.","exja":"数人の著名人が啓発のためのチャリティーキャンペーンを支持した。"},{"id":5025,"en":"endurance","ja":"持久力・忍耐力\nendurance running（持久走）。endure（耐える）の名詞形として覚える","level":7,"lnum":1,"ex":"Long-distance running tests both physical strength and mental endurance.","exja":"長距離走は身体的な強さと精神的な持久力の両方を試す。"},{"id":5026,"en":"enduring","ja":"永続的な・長続きする\nan enduring friendship（永続的な友情）。lasting（長続きする）と同義","level":7,"lnum":1,"ex":"Their enduring friendship survived even the most difficult times.","exja":"彼らの永続的な友情は最も困難な時さえも乗り越えた。"},{"id":5027,"en":"enforce","ja":"施行する・強制する\nenforce a law（法律を施行する）。enforcement（施行）とセットで覚える","level":7,"lnum":1,"ex":"The police were called in to enforce the new regulations on public gatherings.","exja":"警察は公共の集まりに関する新しい規制を施行するために呼ばれた。"},{"id":5028,"en":"engagement","ja":"婚約・関与・契約\nengagement ring（婚約指輪）。public engagement（社会参画）も重要","level":7,"lnum":1,"ex":"The couple announced their engagement at a family dinner.","exja":"カップルは家族のディナーで婚約を発表した。"},{"id":5029,"en":"engulf","ja":"飲み込む・包む\nengulfed in flames（炎に包まれた）という火災描写で典型的に使われる","level":7,"lnum":1,"ex":"The wildfire engulfed hundreds of acres of forest within hours.","exja":"山火事は数時間以内に何百エーカーもの森林を飲み込んだ。"},{"id":5030,"en":"enhance","ja":"高める・強化する\nenhance the quality（質を高める）。improve（向上させる）よりフォーマル","level":7,"lnum":1,"ex":"Regular exercise can significantly enhance your overall health and well-being.","exja":"定期的な運動は全体的な健康と幸福を大幅に高める可能性がある。"},{"id":5031,"en":"enroll/enrol","ja":"登録する・入学する\nenroll in a courseで「コースに登録する」。enrollment（登録）とセット","level":7,"lnum":1,"ex":"He enrolled in a night school to improve his English skills.","exja":"彼は英語力を向上させるために夜学に入学した。"},{"id":5032,"en":"enterprise","ja":"企業・事業・進取の精神\nfree enterprise（自由企業）。entrepreneurと語源が同じ冒険的精神も含む","level":7,"lnum":1,"ex":"Starting a new enterprise requires both courage and careful planning.","exja":"新しい事業を始めるには、勇気と慎重な計画の両方が必要だ。"},{"id":5033,"en":"entertaining","ja":"楽しい・面白い\nan entertaining speech（楽しいスピーチ）。entertainmentの形容詞形","level":7,"lnum":1,"ex":"The magician's show was so entertaining that the children didn't want it to end.","exja":"マジシャンのショーはとても楽しく、子どもたちは終わってほしくなかった。"},{"id":5034,"en":"enthusiastically","ja":"熱狂的に\nrespond enthusiasticallyで「熱狂的に反応する」。enthusiasmとセット","level":7,"lnum":1,"ex":"The crowd cheered enthusiastically when the home team scored a goal.","exja":"ホームチームがゴールを決めると、観客は熱狂的に歓声を上げた。"},{"id":5035,"en":"entitle","ja":"権利を与える・題名をつける\nbe entitled to〜で「〜する権利がある」。また本のタイトルをつける意味も","level":7,"lnum":1,"ex":"All full-time employees are entitled to 20 days of paid vacation per year.","exja":"すべてのフルタイム従業員は年間20日間の有給休暇を取る権利がある。"},{"id":5036,"en":"entrepreneur","ja":"起業家\nenterprise（企業）と同じフランス語源。innovation（革新）とセットで現代必須語","level":7,"lnum":1,"ex":"The young entrepreneur launched a successful app while still in college.","exja":"その若い起業家は大学在学中に成功したアプリを立ち上げた。"},{"id":5037,"en":"environmentally","ja":"環境的に\nenvironmentally friendly（環境にやさしい）。エコ関連の文脈で頻出","level":7,"lnum":1,"ex":"The company is committed to operating in an environmentally responsible way.","exja":"その会社は環境的に責任ある方法で事業を運営することを約束している。"},{"id":5038,"en":"environmentally friendly","ja":"環境にやさしい\neco-friendlyとほぼ同義。製品・行動の環境への影響を表す重要表現","level":7,"lnum":1,"ex":"The government encouraged citizens to choose environmentally friendly products.","exja":"政府は市民に環境にやさしい製品を選ぶよう奨励した。"},{"id":5039,"en":"envy","ja":"うらやむ・羨望する\nenvy someone their success（成功を羨む）。名詞でも使い「羨望」の意味","level":7,"lnum":1,"ex":"She couldn't help but envy her friend's confidence and natural talent.","exja":"友人の自信と生まれ持った才能をうらやまずにはいられなかった。"},{"id":5040,"en":"equal","ja":"等しい者・対等な人\n名詞用法。treat someone as an equal（対等に扱う）という使い方が重要","level":7,"lnum":1,"ex":"Three times four equals twelve.","exja":"3かける4は12に等しい。"},{"id":5041,"en":"equal","ja":"等しい・匹敵する\n動詞用法。2 plus 2 equals 4（2＋2は4）。equalの動詞は試験で頻出","level":7,"lnum":1,"ex":"Two plus two equals four in basic arithmetic.","exja":"基本的な算数では2足す2は4になる。"},{"id":5042,"en":"equation","ja":"方程式・等式\nmathematical equation（数式）。come into the equationで「考慮に入れる」","level":7,"lnum":1,"ex":"The physics teacher wrote a complex equation on the board.","exja":"物理の教師は黒板に複雑な方程式を書いた。"},{"id":5043,"en":"equip","ja":"装備する・備えさせる\nequip someone with skills（スキルを身につけさせる）。be equipped withが頻出","level":7,"lnum":1,"ex":"The school equipped its science labs with the latest research technology.","exja":"学校は理科の実験室に最新の研究技術を装備した。"},{"id":5044,"en":"equity","ja":"公平性・株式\nequity and fairness（公平性）。home equity（住宅株式）も金融で重要","level":7,"lnum":1,"ex":"The new policy aims to promote equity in access to education for all students.","exja":"新しい政策はすべての学生にとって教育へのアクセスの公平性を促進することを目指している。"},{"id":5045,"en":"erect","ja":"まっすぐ立った・建てる\nstand erectで「直立する」。erect a building（建物を建てる）の動詞も重要","level":7,"lnum":1,"ex":"Workers erected a temporary fence around the construction site.","exja":"作業員たちは建設現場の周りに仮囲いを立てた。"},{"id":5046,"en":"erupt","ja":"噴火する・爆発する\nthe volcano erupted（火山が噴火した）。violence erupted（暴力が勃発）も使う","level":7,"lnum":1,"ex":"The volcano erupted without warning, sending ash high into the sky.","exja":"火山は警告なしに噴火し、空高く灰を吹き上げた。"},{"id":5047,"en":"eruption","ja":"噴火・勃発\nvolcanic eruption（火山噴火）。an eruption of anger（怒りの爆発）の比喩も重要","level":7,"lnum":1,"ex":"The volcanic eruption forced thousands of residents to evacuate their homes.","exja":"火山の噴火により、何千人もの住民が自宅から避難を余儀なくされた。"},{"id":5048,"en":"essayist","ja":"随筆家・エッセイスト\nessayを書くことを専門とする作家。文学・ライティングの文脈で使う","level":7,"lnum":1,"ex":"The famous essayist is known for her insightful writing on modern society.","exja":"その有名な随筆家は現代社会に関する洞察に富む文章で知られている。"},{"id":5049,"en":"essentially","ja":"本質的に・要するに\nessentially means（要するに意味する）。in essenceとほぼ同義の副詞","level":7,"lnum":1,"ex":"The two plans are essentially the same, with only minor differences.","exja":"2つの計画は本質的に同じで、わずかな違いしかない。"},{"id":5050,"en":"estate","ja":"不動産・農園・遺産\nreal estate（不動産）。estate agent（不動産業者）が頻出複合語","level":7,"lnum":1,"ex":"He inherited a large estate, including a farmhouse and several acres of land.","exja":"彼は農家と数エーカーの土地を含む広大な不動産を相続した。"},{"id":5051,"en":"estimate","ja":"推定・見積もり\n名詞と動詞の両方で使う。rough estimate（大まかな見積もり）が典型","level":7,"lnum":1,"ex":"The engineer gave a rough estimate of the cost for repairing the bridge.","exja":"エンジニアは橋の修理費用の大まかな見積もりを出した。"},{"id":5052,"en":"estimated","ja":"推定の・おおよその\nan estimated 1,000 people（推定1000人）。at an estimated cost（推定費用）","level":7,"lnum":1,"ex":"An estimated 10,000 people attended the outdoor music festival.","exja":"推定1万人が野外音楽フェスティバルに参加した。"},{"id":5053,"en":"eternally","ja":"永遠に・いつまでも\neternally grateful（永遠に感謝する）。forever（永遠に）のフォーマル版","level":7,"lnum":1,"ex":"She was eternally grateful to the doctor who had saved her life.","exja":"命を救ってくれた医師に彼女は永遠に感謝していた。"},{"id":5054,"en":"ethic","ja":"倫理・道徳的原則\nwork ethic（労働倫理）が頻出。ethics（複数形）で「倫理学」を指す","level":7,"lnum":1,"ex":"A strong work ethic is essential for achieving long-term success in any career.","exja":"強い労働倫理は、どのようなキャリアでも長期的な成功を収めるために不可欠だ。"},{"id":5055,"en":"ethnic","ja":"民族の・民族的な\nethnic group（民族グループ）。ethnic minority（少数民族）が社会文脈で頻出","level":7,"lnum":1,"ex":"The city has a diverse population made up of many different ethnic groups.","exja":"その都市は多くの異なる民族グループからなる多様な人口を持っている。"},{"id":5056,"en":"evacuate","ja":"避難する・避難させる\nevacuate the building（建物から避難する）。disaster文脈で必須語彙","level":7,"lnum":1,"ex":"Residents were ordered to evacuate the area as the floodwaters rose.","exja":"洪水の水位が上昇するにつれ、住民はその地域から避難するよう命じられた。"},{"id":5057,"en":"evaluate","ja":"評価する・査定する\nevaluate performance（業績を評価する）。assessment（査定）と類義","level":7,"lnum":1,"ex":"Teachers need to evaluate each student's progress regularly throughout the year.","exja":"教師は年間を通じて各生徒の進歩を定期的に評価する必要がある。"},{"id":5058,"en":"evaluation","ja":"評価・査定\nconduct an evaluation（評価を実施する）。evaluateの名詞形として覚える","level":7,"lnum":1,"ex":"The annual evaluation helped identify areas where the team needed improvement.","exja":"年次評価はチームが改善を必要とする部分を特定するのに役立った。"},{"id":5059,"en":"everlasting","ja":"永続的な・永遠の\neverlasting love（永遠の愛）。eternalとほぼ同義だが詩的な語感","level":7,"lnum":1,"ex":"The couple exchanged vows of everlasting love at their wedding.","exja":"カップルは結婚式で永遠の愛を誓い合った。"},{"id":5060,"en":"evidently","ja":"明らかに・見たところ\nevidently mistake（明らかに間違い）。apparently（どうやら〜らしい）と区別","level":7,"lnum":1,"ex":"Evidently, someone had forgotten to lock the door before leaving.","exja":"明らかに、誰かが出発前にドアに鍵をかけるのを忘れていた。"},{"id":5061,"en":"evil","ja":"邪悪な・有害な\nevil plan（邪悪な計画）。形容詞・名詞の両方で使う重要な道徳用語","level":7,"lnum":1,"ex":"Greed is often described as the root of all evil.","exja":"強欲はしばしばすべての悪の根源として語られる。"},{"id":5062,"en":"evil","ja":"悪・邪悪なもの\nthe lesser of two evils（2つの悪のうちの小さい方）という慣用表現が重要","level":7,"lnum":1,"ex":"The villain in the story represents pure evil with no redeeming qualities.","exja":"物語の悪役は救いようのない純粋な悪を体現している。"},{"id":5063,"en":"evolution","ja":"進化・発展\nDarwin's theory of evolution（ダーウィンの進化論）。evolutionaryも重要","level":7,"lnum":1,"ex":"Darwin's theory of evolution changed the way scientists understood life on Earth.","exja":"ダーウィンの進化論は、科学者が地球上の生命を理解する方法を変えた。"},{"id":5064,"en":"evolve","ja":"進化する・発展する\nevolve over time（時間をかけて進化する）。evolvedで「高度に発達した」","level":7,"lnum":1,"ex":"Language constantly evolves to reflect changes in society and culture.","exja":"言語は社会や文化の変化を反映して常に進化する。"},{"id":5065,"en":"exactness","ja":"正確さ\nexactの名詞形。with exactnessで「正確に」。precision（精度）とほぼ同義","level":7,"lnum":1,"ex":"The exactness of the measurements was crucial for the experiment's success.","exja":"実験の成功には測定の正確さが不可欠だった。"},{"id":5066,"en":"exaggerate","ja":"誇張する\n動詞の品詞表記があるが単語自体は動詞的。exaggerationとセットで覚える","level":7,"lnum":1,"ex":"He tends to exaggerate the difficulties of his job when talking to his friends.","exja":"友人と話すとき、彼は仕事の困難さを誇張する傾向がある。"},{"id":5067,"en":"exaggeration","ja":"誇張\nThat's an exaggeration（それは言い過ぎだ）。without exaggeration（誇張なしに）","level":7,"lnum":1,"ex":"Saying the whole city was flooded is a bit of an exaggeration.","exja":"都市全体が浸水したというのは少し誇張だ。"},{"id":5068,"en":"exalt","ja":"高める・称える\nexalt someone to a position（地位に就かせる）。フォーマルな書き言葉的語彙","level":7,"lnum":1,"ex":"The poem exalts the beauty of nature and the power of human imagination.","exja":"その詩は自然の美しさと人間の想像力の偉大さを称えている。"},{"id":5069,"en":"examinee","ja":"受験者・被験者\nexaminer（試験官）と対になる語。exam taker（受験者）とも言い換えられる","level":7,"lnum":1,"ex":"Each examinee was given three hours to complete the written test.","exja":"各受験者には筆記試験を完了するために3時間が与えられた。"},{"id":5070,"en":"exceed","ja":"超える・上回る\nexceed expectations（期待を超える）。exceed the speed limit（制限速度超過）","level":7,"lnum":1,"ex":"The demand for the product exceeded the company's expectations.","exja":"その製品への需要は会社の予想を上回った。"},{"id":5071,"en":"excel","ja":"優れている・卓越する\nexcel at〜で「〜が得意である」。Excel（表計算ソフト）と同語源","level":7,"lnum":1,"ex":"She has always excelled at mathematics since elementary school.","exja":"彼女は小学校からずっと数学が得意だった。"},{"id":5072,"en":"exception","ja":"例外\nwith the exception of〜で「〜を除いて」。make an exception（例外を設ける）","level":7,"lnum":1,"ex":"With the exception of one student, everyone passed the final exam.","exja":"1人の生徒を除いて、全員が期末試験に合格した。"},{"id":5073,"en":"exceptional","ja":"例外的な・並外れた\nan exceptional student（優秀な生徒）。exceptionに由来する形容詞","level":7,"lnum":1,"ex":"Her performance in the competition was truly exceptional.","exja":"コンペティションでの彼女のパフォーマンスは本当に並外れたものだった。"},{"id":5074,"en":"exceptionally","ja":"例外的に・特別に\nexceptionally talented（特別に才能がある）。unusually と同義の強調副詞","level":7,"lnum":1,"ex":"The summer this year was exceptionally hot, breaking several temperature records.","exja":"今年の夏は例外的に暑く、いくつかの気温記録を更新した。"},{"id":5075,"en":"excessive","ja":"過剰な・度を超えた\nexcessive drinking（過度の飲酒）。in excess of〜（〜を超えて）と関連","level":7,"lnum":1,"ex":"Excessive use of social media can have a negative effect on mental health.","exja":"ソーシャルメディアの過剰な使用はメンタルヘルスに悪影響を及ぼすことがある。"},{"id":5076,"en":"exclaim","ja":"叫ぶ・感嘆する\nShe exclaimed, \"Wonderful!\"のように直接話法と組み合わせてよく使う","level":7,"lnum":1,"ex":"\"What a beautiful painting!\" she exclaimed when she entered the gallery.","exja":"「なんて美しい絵だろう！」と彼女はギャラリーに入ったとき叫んだ。"},{"id":5077,"en":"exclamation mark","ja":"感嘆符\n!のこと。exclamation point（米）とも言う。文法・ライティングの文脈で使う","level":7,"lnum":1,"ex":"In English, an exclamation mark is used to express strong emotion or emphasis.","exja":"英語では、感嘆符は強い感情や強調を表すために使われる。"},{"id":5078,"en":"exclude","ja":"除外する\ninclude（含める）の反対。from と組み合わせて使う","level":7,"lnum":1,"ex":"Students who break the rules may be excluded from the event.","exja":"規則を破った生徒はイベントから除外されることがある。"},{"id":5079,"en":"exclusion","ja":"排除\n特定グループを意図的に外す行為","level":7,"lnum":1,"ex":"The exclusion of certain groups from the decision-making process caused widespread criticism.","exja":"意思決定プロセスから特定のグループを排除したことが広範な批判を招いた。"},{"id":5080,"en":"exclusively","ja":"もっぱら\n他を完全に除いて、その一つだけに限定","level":7,"lnum":1,"ex":"This lounge is exclusively for members of the club.","exja":"このラウンジはクラブ会員専用です。"},{"id":5081,"en":"excursion","ja":"小旅行\n日帰り・短期の観光旅行。tourより気軽","level":7,"lnum":1,"ex":"The school organized a day excursion to the science museum.","exja":"学校は科学博物館への日帰り小旅行を企画した。"},{"id":5082,"en":"execute","ja":"実行する\n計画や命令を実際にやり遂げる。doより硬い","level":7,"lnum":1,"ex":"The team executed the plan flawlessly during the final presentation.","exja":"チームは最終プレゼンで計画を完璧に実行した。"},{"id":5083,"en":"execution","ja":"実行/処刑\n計画の遂行、または死刑執行の両義あり","level":7,"lnum":1,"ex":"The execution of the new policy will begin next month.","exja":"新しい方針の実行は来月から始まる。"},{"id":5084,"en":"executive","ja":"経営幹部の\n会社の上位管理職に関わる形容詞","level":7,"lnum":1,"ex":"The executives met to discuss the company's future strategy.","exja":"経営幹部たちは会社の将来的な戦略を話し合うために集まった。"},{"id":5085,"en":"executive","ja":"経営幹部\nCEOや役員など会社の意思決定者","level":7,"lnum":1,"ex":"The company's top executives met to discuss the merger.","exja":"会社の上層部の経営幹部たちが合併について話し合うために集まった。"},{"id":5086,"en":"exhaust","ja":"排気ガス\nエンジンから出る廃気。動詞「疲弊させる」とは別","level":7,"lnum":1,"ex":"The old car emitted dark exhaust that filled the street with smoke.","exja":"その古い車は黒い排気ガスを吐き出し、通りを煙で満たした。"},{"id":5087,"en":"exhausting","ja":"消耗する\n体や気力をひどく消耗させる様子","level":7,"lnum":1,"ex":"Taking care of three young children all day is absolutely exhausting.","exja":"一日中3人の幼い子供たちの世話をするのは本当に消耗する。"},{"id":5088,"en":"exhaustion","ja":"極度の疲労\n力を使い果たした状態。tiredより深刻","level":7,"lnum":1,"ex":"After the marathon, the runner collapsed from exhaustion.","exja":"マラソンの後、ランナーは極度の疲労で倒れた。"},{"id":5089,"en":"exhibit","ja":"展示する\n美術館などで作品を公開・展示する","level":7,"lnum":1,"ex":"The museum will exhibit a collection of ancient Japanese pottery next month.","exja":"博物館は来月、古代日本の陶器のコレクションを展示する。"},{"id":5090,"en":"exile","ja":"追放/亡命\n国や故郷から強制的に追われた状態","level":7,"lnum":1,"ex":"The political leader was forced into exile after the coup.","exja":"クーデター後、その政治的指導者は亡命を余儀なくされた。"},{"id":5091,"en":"existing","ja":"現存する\n今すでにある・存在しているという意味","level":7,"lnum":1,"ex":"The engineers improved the existing system rather than building a new one.","exja":"エンジニアたちは新しいシステムを作る代わりに、現存するシステムを改良した。"},{"id":5092,"en":"exotic","ja":"異国情緒の\n外国的で珍しく魅力的な雰囲気を持つ","level":7,"lnum":1,"ex":"The market sold a variety of exotic fruits that she had never seen before.","exja":"その市場では彼女が見たことのない様々な異国の果物を売っていた。"},{"id":5093,"en":"expansion","ja":"拡大\n規模・範囲が広がること。growthより計画的","level":7,"lnum":1,"ex":"The rapid expansion of the city led to a shortage of affordable housing.","exja":"都市の急速な拡大により、手頃な価格の住宅不足が生じた。"},{"id":5094,"en":"expectation","ja":"期待/予想\nこうなるだろうという見込みや望み","level":7,"lnum":1,"ex":"The student exceeded everyone's expectations by winning first place.","exja":"その生徒は1位を獲得し、全員の期待を超えた。"},{"id":5095,"en":"expected","ja":"予想された\nあらかじめ想定されていた。surprisingの反対","level":7,"lnum":1,"ex":"The expected arrival time of the train is 3:15 in the afternoon.","exja":"電車の予想到着時刻は午後3時15分だ。"},{"id":5096,"en":"expedition","ja":"探検\n目的を持った長距離の旅・調査遠征","level":7,"lnum":1,"ex":"The scientists set out on a research expedition to the Arctic.","exja":"科学者たちは北極への研究探検に出発した。"},{"id":5097,"en":"explode","ja":"爆発する\n激しく破裂する。感情の爆発にも使う","level":7,"lnum":1,"ex":"The pressure inside the pipe became so great that it finally exploded.","exja":"パイプ内の圧力が非常に高くなり、ついに爆発した。"},{"id":5098,"en":"exploit","ja":"利用する\n人や状況を不当に利用する。悪い意味が強い","level":7,"lnum":1,"ex":"The documentary exposed how some companies exploit cheap labor overseas.","exja":"そのドキュメンタリーは一部の企業が海外の安い労働力を搾取している実態を明らかにした。"},{"id":5099,"en":"explorer","ja":"探検家\n未知の地を調査・発見する人","level":7,"lnum":1,"ex":"The famous explorer charted unknown rivers deep in the rainforest.","exja":"その有名な探検家は熱帯雨林の奥深くにある未知の川を地図に記した。"},{"id":5100,"en":"explosive","ja":"爆発的な\n急激で激しい変化や力を表す形容詞","level":7,"lnum":1,"ex":"The police safely removed the explosive found near the station.","exja":"警察は駅の近くで発見された爆発物を安全に撤去した。"},{"id":5101,"en":"explosive","ja":"爆発物\n爆弾など爆発を起こす物質","level":7,"lnum":1,"ex":"The police found a large amount of explosives hidden in the warehouse.","exja":"警察は倉庫に大量の爆発物が隠されているのを発見した。"},{"id":5102,"en":"export","ja":"輸出品\n外国に売り出す商品・データ","level":7,"lnum":1,"ex":"Japan exports large quantities of cars to countries around the world.","exja":"日本は世界各国に大量の自動車を輸出している。"},{"id":5103,"en":"export","ja":"輸出する\n国内の物を外国に送り出す","level":7,"lnum":1,"ex":"Japan exports large quantities of cars to countries around the world.","exja":"日本は世界各国に大量の自動車を輸出している。"},{"id":5104,"en":"expressive","ja":"表情豊かな\n感情や意図をよく表している。顔や芸術に使う","level":7,"lnum":1,"ex":"The dancer's movements were so expressive that the audience was moved to tears.","exja":"そのダンサーの動きは非常に表情豊かで、観客は涙を流した。"},{"id":5105,"en":"exquisite","ja":"精巧な\n細部まで美しく完璧。非常に上品な感じ","level":7,"lnum":1,"ex":"The jeweler crafted an exquisite necklace decorated with tiny diamonds.","exja":"宝石職人は小さなダイヤモンドで飾られた精巧なネックレスを作った。"},{"id":5106,"en":"extension","ja":"延長/拡張\n期間・機能・建物などを伸ばすこと","level":7,"lnum":1,"ex":"The professor granted a two-day extension for students to submit their essays.","exja":"教授は学生たちがエッセイを提出するために2日間の延長を認めた。"},{"id":5107,"en":"extensive","ja":"広範囲な\n範囲や量が非常に広い・多い","level":7,"lnum":1,"ex":"The researcher conducted extensive studies on the effects of sleep deprivation.","exja":"その研究者は睡眠不足の影響について広範囲な研究を行った。"},{"id":5108,"en":"external","ja":"外部の\n内側でなく外側に関わる。internalの反対","level":7,"lnum":1,"ex":"External pressure from investors forced the company to change its strategy.","exja":"投資家からの外部圧力が会社に戦略の変更を迫った。"},{"id":5109,"en":"extract","ja":"抽出物\n植物などから取り出したエッセンス","level":7,"lnum":1,"ex":"Scientists were able to extract valuable data from the old experiment records.","exja":"科学者たちは古い実験記録から貴重なデータを抽出することができた。"},{"id":5110,"en":"extract","ja":"抽出する\n必要な部分だけを取り出す。removeより精密","level":7,"lnum":1,"ex":"Scientists extracted DNA from the ancient fossil for analysis.","exja":"科学者たちは分析のために古代の化石からDNAを抽出した。"},{"id":5111,"en":"extraordinarily","ja":"並外れて\n通常の基準をはるかに超えて。remarkablyより強い","level":7,"lnum":1,"ex":"The athlete performed extraordinarily well despite recovering from an injury.","exja":"そのアスリートは怪我から回復中にもかかわらず、並外れた活躍を見せた。"},{"id":5112,"en":"exultant","ja":"大喜びの\n勝利や成功への強い喜びを示す。jubilantに近い","level":7,"lnum":1,"ex":"The team was exultant after winning the championship for the first time.","exja":"チームは初めて優勝を果たし、大喜びだった。"},{"id":5113,"en":"eyelash","ja":"まつ毛\n目のふちに生える細い毛","level":7,"lnum":1,"ex":"She carefully applied mascara to make her eyelashes look longer.","exja":"彼女はまつ毛を長く見せるために丁寧にマスカラを塗った。"},{"id":5114,"en":"fabric","ja":"生地/布地\n衣服などを作る素材。clothより製品向け","level":7,"lnum":1,"ex":"The dress was made from a soft, lightweight fabric imported from Italy.","exja":"そのドレスはイタリアから輸入された柔らかく軽い生地で作られていた。"},{"id":5115,"en":"fabulous","ja":"すばらしい\n口語で「最高！」の意味。誇張気味の称賛","level":7,"lnum":1,"ex":"The fireworks display on New Year's Eve was absolutely fabulous.","exja":"大晦日の花火は本当にすばらしかった。"},{"id":5116,"en":"facilitate","ja":"促進する\n物事がスムーズに進むよう助ける役割","level":7,"lnum":1,"ex":"The new app is designed to facilitate communication between teachers and parents.","exja":"その新しいアプリは教師と保護者の間のコミュニケーションを促進するよう設計されている。"},{"id":5117,"en":"facilities","ja":"施設\n設備・建物・サービスのまとまり（複数形）","level":7,"lnum":1,"ex":"The sports center has excellent facilities, including a pool and a gym.","exja":"そのスポーツセンターにはプールやジムを含む優れた施設がある。"},{"id":5118,"en":"factor","ja":"要因\n結果に影響を与える原因のひとつ","level":7,"lnum":1,"ex":"Lack of sleep is a major factor contributing to poor academic performance.","exja":"睡眠不足は学業成績の低下に寄与する主要な要因だ。"},{"id":5119,"en":"faculty","ja":"学部/能力\n大学の学部、または知的・身体的能力","level":7,"lnum":1,"ex":"She joined the faculty of law at one of the most prestigious universities in the country.","exja":"彼女はその国で最も権威ある大学の一つの法学部に加わった。"},{"id":5120,"en":"faint","ja":"気絶する\n血や貧血などで意識を失う。動詞として使う","level":7,"lnum":1,"ex":"He felt dizzy and fainted after standing in the sun for too long.","exja":"彼は長時間日光の下に立っていたためめまいを感じ、気絶した。"},{"id":5121,"en":"faith","ja":"信頼/信仰\n証拠がなくても信じる力。宗教的にも使う","level":7,"lnum":1,"ex":"She had complete faith in her doctor's ability to treat her illness.","exja":"彼女は自分の病気を治す医師の能力を完全に信頼していた。"},{"id":5122,"en":"falter","ja":"よろめく\n歩みや声が乱れ躊躇する。hesitateより動的","level":7,"lnum":1,"ex":"His voice began to falter as he described the difficult experience.","exja":"困難な体験を語るにつれて、彼の声がよろめき始めた。"},{"id":5123,"en":"fame","ja":"名声\n広く世間に知られた評判・有名さ","level":7,"lnum":1,"ex":"The young singer rose to fame after her song went viral online.","exja":"その若い歌手は曲がオンラインで拡散した後、名声を得た。"},{"id":5124,"en":"familiarize/familiarise","ja":"慣れさせる\n新しい環境・情報に慣れさせる。with と組み合わせる","level":7,"lnum":1,"ex":"New employees need time to familiarize themselves with the company's rules.","exja":"新入社員は会社のルールに慣れるための時間が必要だ。"},{"id":5125,"en":"fantastically","ja":"すばらしく\n非常に良い・想像を超えるほど。口語的に使う","level":7,"lnum":1,"ex":"The team performed fantastically in their first international competition.","exja":"チームは初の国際大会ですばらしい活躍をした。"},{"id":5126,"en":"fascinated","ja":"魅了された\n強い興味で引きつけられた状態","level":7,"lnum":1,"ex":"She was fascinated by the way ancient cultures built such massive structures.","exja":"彼女は古代文明がどのように巨大な建造物を作ったかに魅了された。"},{"id":5127,"en":"fascination","ja":"魅了\n強く惹かれること。interestより感情的","level":7,"lnum":1,"ex":"His fascination with space exploration began when he first saw a rocket launch on television.","exja":"宇宙探査への魅了は、テレビで初めてロケット打ち上げを見た時から始まった。"},{"id":5128,"en":"fatal","ja":"致命的な\n死や重大な結果をもたらす。deadlyより硬い","level":7,"lnum":1,"ex":"The driver made a fatal mistake by ignoring the stop sign.","exja":"その運転手は一時停止標識を無視するという致命的な間違いを犯した。"},{"id":5129,"en":"fate","ja":"運命\n避けられない定め。destinyより暗い響き","level":7,"lnum":1,"ex":"She believed that fate brought the two of them together at just the right moment.","exja":"彼女は運命がちょうどよいタイミングで二人を引き合わせてくれたと信じていた。"},{"id":5130,"en":"father-in-law","ja":"義理の父\n配偶者の父親。in-law系は義理の親族","level":7,"lnum":1,"ex":"Her father-in-law welcomed her warmly into the family from the very beginning.","exja":"義理の父は最初から温かく彼女を家族に迎え入れてくれた。"},{"id":5131,"en":"faulty","ja":"欠陥のある\n設計や動作に問題がある。defectiveより日常的","level":7,"lnum":1,"ex":"The technician discovered that the faulty wiring had caused the power outage.","exja":"技術者は欠陥のある配線が停電の原因だったことを発見した。"},{"id":5132,"en":"fear","ja":"恐れる\n危険なものを恐ろしいと思う。be afraid of に近い","level":7,"lnum":1,"ex":"Many people fear public speaking more than they fear death.","exja":"多くの人は死よりも人前で話すことを恐れている。"},{"id":5133,"en":"fearsome","ja":"恐ろしい\n見た目や力が恐怖を感じさせるほど強大な","level":7,"lnum":1,"ex":"The boxer had a fearsome reputation that intimidated most of his opponents.","exja":"そのボクサーは恐ろしい評判を持っており、ほとんどの対戦相手を脅かした。"},{"id":5134,"en":"feat","ja":"偉業\n困難を乗り越えた注目すべき達成","level":7,"lnum":1,"ex":"Climbing all seven of the world's highest peaks is an incredible feat.","exja":"世界の最高峰七座すべてに登頂することは信じられない偉業だ。"},{"id":5135,"en":"fed up","ja":"うんざりした\n繰り返しに嫌気がさした口語的な表現","level":7,"lnum":1,"ex":"After waiting for over an hour, she was completely fed up and left without ordering.","exja":"1時間以上待った後、彼女は完全にうんざりし、注文せずに出て行った。"},{"id":5136,"en":"federal","ja":"連邦の\n複数の州・国家が統合した政府に関わる","level":7,"lnum":1,"ex":"The federal government announced new policies to address climate change.","exja":"連邦政府は気候変動に対処するための新しい政策を発表した。"},{"id":5137,"en":"feedback","ja":"フィードバック\n行動・作品への評価や反応。批判と賞賛の両方","level":7,"lnum":1,"ex":"The teacher gave constructive feedback to help students improve their writing.","exja":"教師は生徒の文章力向上を助けるために建設的なフィードバックをした。"},{"id":5138,"en":"fellow","ja":"仲間の\n同じ立場・グループに属する人への形容詞","level":7,"lnum":1,"ex":"He enjoyed discussing philosophy with his fellow students in the library.","exja":"彼は図書館で仲間の学生たちと哲学について議論するのを楽しんだ。"},{"id":5139,"en":"ferryboat","ja":"フェリー\n人や車を運ぶ渡し船。水上交通機関","level":7,"lnum":1,"ex":"We crossed the river on a small ferryboat that carried about twenty passengers.","exja":"私たちは約20人の乗客を運ぶ小さなフェリーで川を渡った。"},{"id":5140,"en":"fiber/fibre","ja":"繊維\n細い糸状の素材。食物繊維・光ファイバーにも使う","level":7,"lnum":1,"ex":"Dietary fiber helps maintain a healthy digestive system.","exja":"食物繊維は健康的な消化器系を維持するのに役立つ。"},{"id":5141,"en":"fictional","ja":"架空の\n現実でなく作り話の。realの反対","level":7,"lnum":1,"ex":"The story is set in a fictional city loosely based on Tokyo.","exja":"その物語は東京をゆるやかにモデルにした架空の都市を舞台にしている。"},{"id":5142,"en":"fierce","ja":"激しい\n攻撃的で圧倒的な力・強さを持つ","level":7,"lnum":1,"ex":"A fierce storm hit the coast and caused widespread damage.","exja":"激しい嵐が海岸を直撃し、広範囲にわたる被害をもたらした。"},{"id":5143,"en":"fighting","ja":"戦闘/戦い\n争い・格闘の行為・状態（名詞）","level":7,"lnum":1,"ex":"The fighting between the two rival groups lasted for several hours.","exja":"二つの対立するグループの間の戦闘は数時間続いた。"},{"id":5144,"en":"figurative","ja":"比喩的な\n文字通りでなく比喩・象徴として使う表現","level":7,"lnum":1,"ex":"In a figurative sense, she carried the weight of the whole team on her shoulders.","exja":"比喩的な意味で、彼女はチーム全体の重荷を一人で背負っていた。"},{"id":5145,"en":"filial","ja":"親への\n子が親に対して持つ愛情・義務に関わる","level":7,"lnum":1,"ex":"Filial devotion is deeply valued in many Asian cultures.","exja":"親への献身は多くのアジア文化において深く重んじられている。"},{"id":5146,"en":"finance","ja":"財政/金融\nお金の管理・運用に関する分野","level":7,"lnum":1,"ex":"She studied finance at university and now works at an investment bank.","exja":"彼女は大学で財政・金融を学び、今は投資銀行で働いている。"},{"id":5147,"en":"financially","ja":"経済的に\nお金の面から見て。financially stable など","level":7,"lnum":1,"ex":"The scholarship allowed him to become financially independent from his parents.","exja":"奨学金のおかげで彼は親から経済的に自立することができた。"},{"id":5148,"en":"finely","ja":"精細に\n詳細・細かく丁寧に。細かく刻む意味にも使う","level":7,"lnum":1,"ex":"The chef finely chopped the herbs and added them to the sauce.","exja":"シェフはハーブを細かく刻んでソースに加えた。"},{"id":5149,"en":"fingernail","ja":"爪（手の）\n指先の爪。toenailは足の爪","level":7,"lnum":1,"ex":"She broke her fingernail while trying to open the package.","exja":"彼女は荷物を開けようとして爪を折ってしまった。"},{"id":5150,"en":"fire brigade","ja":"消防隊\n火災を消火する組織。英式英語。米式はfire department","level":7,"lnum":1,"ex":"The fire brigade arrived within minutes and quickly brought the blaze under control.","exja":"消防隊は数分以内に到着し、すぐに火災を鎮圧した。"},{"id":5151,"en":"firearm","ja":"銃器\n銃などの射撃武器の総称。gunより公式・法律的","level":7,"lnum":1,"ex":"The law requires all firearm owners to store their weapons in a locked cabinet.","exja":"法律はすべての銃器所持者が施錠したキャビネットに武器を保管することを義務付けている。"},{"id":5152,"en":"fireplace","ja":"暖炉\n室内に設けた薪・ガスで暖を取る設備","level":7,"lnum":1,"ex":"On cold winter evenings, the family gathered around the fireplace to tell stories.","exja":"寒い冬の夜、家族は暖炉の周りに集まって話をした。"},{"id":5153,"en":"firmness","ja":"固さ/断固さ\n物理的な硬さ、または意志・態度の揺るぎなさ","level":7,"lnum":1,"ex":"The coach's firmness in upholding the rules earned him the respect of all the players.","exja":"ルールを守り通す監督の断固さが全選手の尊敬を勝ち取った。"},{"id":5154,"en":"first language","ja":"母語\n最初に習得した言語。mother tongueと同義","level":7,"lnum":1,"ex":"Her first language is Korean, but she speaks English fluently as well.","exja":"彼女の母語は韓国語だが、英語も流暢に話す。"},{"id":5155,"en":"first person","ja":"一人称\n「私」を主語にした語り・文法的人称","level":7,"lnum":1,"ex":"The novel is written in first person, which makes the story feel more personal.","exja":"その小説は一人称で書かれており、物語がより個人的な感じを与える。"},{"id":5156,"en":"firstly","ja":"まず第一に\n順序を示す列挙の最初。firstと同義だがやや硬い","level":7,"lnum":1,"ex":"Firstly, you need to create an account before you can access the service.","exja":"まず第一に、サービスにアクセスする前にアカウントを作成する必要がある。"},{"id":5157,"en":"fiscal","ja":"財政の\n国や企業の財政・会計に関わる。financial より専門的","level":7,"lnum":1,"ex":"The government introduced new measures to address the growing fiscal deficit.","exja":"政府は拡大する財政赤字に対処するための新しい措置を導入した。"},{"id":5158,"en":"fixed","ja":"固定された\n変えられない・しっかり固定された状態","level":7,"lnum":1,"ex":"The schedule is fixed, so no changes can be made at this point.","exja":"スケジュールは固定されているため、現時点では変更はできない。"},{"id":5159,"en":"flame","ja":"炎\n燃える火の発光部分。fire より詩的・比喩的","level":7,"lnum":1,"ex":"The candle flame flickered in the breeze coming through the open window.","exja":"開いた窓から吹き込む風でろうそくの炎がちらちらと揺れた。"},{"id":5160,"en":"flap","ja":"羽ばたく\n翼やフラップが上下に動く。パタパタする動作","level":7,"lnum":1,"ex":"The bird flapped its wings rapidly and disappeared into the sky.","exja":"鳥は翼を素早く羽ばたかせて空へと消えた。"},{"id":5161,"en":"flash","ja":"閃光\n一瞬の強い光。カメラのフラッシュにも使う","level":7,"lnum":1,"ex":"The emergency lights flashed to warn drivers of the accident ahead.","exja":"緊急灯が前方の事故を運転手に警告するために閃光を発した。"},{"id":5162,"en":"flash","ja":"閃光する\n一瞬ぱっと光る・素早く動く","level":7,"lnum":1,"ex":"A camera flashed as the celebrity walked down the red carpet.","exja":"有名人がレッドカーペットを歩くとカメラが閃光を放った。"},{"id":5163,"en":"flat","ja":"平らに\n高低差なく水平に。completely flat（完全に平ら）","level":7,"lnum":1,"ex":"He had a flat tire on the way to the airport and nearly missed his flight.","exja":"彼は空港に向かう途中でタイヤがパンクし、危うくフライトに乗り遅れるところだった。"},{"id":5164,"en":"flaw","ja":"欠点\n完璧でない部分。人・物・計画に使う","level":7,"lnum":1,"ex":"The otherwise perfect diamond had a tiny flaw that reduced its value significantly.","exja":"それ以外は完璧なダイヤモンドに小さな欠点があり、価値が大幅に下がった。"},{"id":5165,"en":"flawless","ja":"完璧な\n傷や欠点が一切ない理想的な状態","level":7,"lnum":1,"ex":"The gymnast delivered a flawless performance and received a perfect score.","exja":"体操選手は完璧な演技を披露し、満点を獲得した。"},{"id":5166,"en":"flax","ja":"亜麻\nリネン繊維の原料となる植物","level":7,"lnum":1,"ex":"Linen cloth is woven from fibers of the flax plant.","exja":"リネンの布は亜麻の繊維から織られている。"},{"id":5167,"en":"flee","ja":"逃げる\n危険から急いで逃げる。runより緊迫感が強い","level":7,"lnum":1,"ex":"Thousands of people were forced to flee their homes due to the flooding.","exja":"数千人の人々が洪水のために家から逃げることを余儀なくされた。"},{"id":5168,"en":"fleet","ja":"艦隊/車両群\nまとまった船・飛行機・車のグループ","level":7,"lnum":1,"ex":"The shipping company operates a fleet of more than fifty cargo vessels.","exja":"その船会社は50隻以上の貨物船からなる艦隊を運営している。"},{"id":5169,"en":"flesh","ja":"肉/皮膚\n体の軟らかい部分。bodyより生々しい感触","level":7,"lnum":1,"ex":"The wound was deep enough to cut through the flesh, so he needed stitches.","exja":"傷は肉まで達するほど深く、縫合が必要だった。"},{"id":5170,"en":"flexibility","ja":"柔軟性\n状況に応じて変えられる適応力","level":7,"lnum":1,"ex":"One of the advantages of working from home is the flexibility it offers.","exja":"在宅勤務の利点の一つは、それが与える柔軟性だ。"},{"id":5171,"en":"flexible","ja":"柔軟な\n変化に対応できる。人・計画・素材に使う","level":7,"lnum":1,"ex":"The company introduced a flexible work schedule to improve employee well-being.","exja":"会社は従業員の幸福を向上させるために柔軟な勤務スケジュールを導入した。"},{"id":5172,"en":"flexibly","ja":"柔軟に\n状況に合わせて融通をきかせて対応する様子","level":7,"lnum":1,"ex":"The new system can be configured flexibly to meet each client's specific needs.","exja":"新しいシステムは各クライアントの具体的なニーズに合わせて柔軟に設定できる。"},{"id":5173,"en":"flip","ja":"ひっくり返す\n素早く裏返す・スイッチを入れる","level":7,"lnum":1,"ex":"She flipped through the magazine quickly, looking for the article she wanted.","exja":"彼女は読みたい記事を探して雑誌をさっとめくった。"},{"id":5174,"en":"fluency","ja":"流暢さ\n言語をスムーズに使いこなせる能力","level":7,"lnum":1,"ex":"Her fluency in three languages gave her a significant advantage in international business.","exja":"3か国語の流暢さは国際ビジネスで大きなアドバンテージになった。"},{"id":5175,"en":"fluid","ja":"流動的な\n固定されず変わりやすい。状況・計画に使う","level":7,"lnum":1,"ex":"The situation remains fluid, and the plans could change at any moment.","exja":"状況は流動的で、計画はいつでも変わる可能性がある。"},{"id":5176,"en":"flutter","ja":"ひらひら\n羽や旗などが軽く震えて動く様子・音","level":7,"lnum":1,"ex":"Dozens of butterflies fluttered around the colorful flowers in the garden.","exja":"庭の色とりどりの花々の周りで何十頭もの蝶がひらひらと舞っていた。"},{"id":5177,"en":"follower","ja":"支持者/フォロワー\n人やSNSアカウントを追う人","level":7,"lnum":1,"ex":"The politician's growing number of followers showed how popular his ideas were.","exja":"その政治家の支持者が増えていることは、彼の考えがどれほど人気があるかを示していた。"},{"id":5178,"en":"folly","ja":"愚行\n非常に愚かな行動・判断。foolishnessより書き言葉的","level":7,"lnum":1,"ex":"It would be sheer folly to invest all your savings in a single risky venture.","exja":"すべての貯蓄を一つのリスクの高い事業に投資するのは全くの愚行だろう。"},{"id":5179,"en":"fondly","ja":"懐かしく\n温かい愛着や思い出とともに。愛情のある副詞","level":7,"lnum":1,"ex":"She fondly remembered the summers she spent at her grandmother's house as a child.","exja":"彼女は子供の頃祖母の家で過ごした夏を懐かしく思い出した。"},{"id":5180,"en":"foolishly","ja":"愚かにも\n考えが足りず愚かな行動をとった様子","level":7,"lnum":1,"ex":"He foolishly forgot to save his work before the computer crashed.","exja":"彼はコンピュータがクラッシュする前に仕事を保存するのを愚かにも忘れてしまった。"},{"id":5181,"en":"footnote","ja":"脚注\nページ下部の補足説明。比喩的にも使う","level":7,"lnum":1,"ex":"The author included a footnote to explain the historical context of the quote.","exja":"著者はその引用の歴史的背景を説明するために脚注を加えた。"},{"id":5182,"en":"force","ja":"強制する\n力や権力で無理やりさせる。makeより強制感が強い","level":7,"lnum":1,"ex":"The police were forced to use barriers to control the large crowd.","exja":"警察は大勢の群衆を制御するためにバリケードを使わざるを得なかった。"},{"id":5183,"en":"forcefully","ja":"力強く\n強い力や意志を持って。assertivelyに近い","level":7,"lnum":1,"ex":"She argued forcefully that the new policy would harm low-income families.","exja":"彼女は新しい政策が低所得家庭に害を与えると力強く主張した。"},{"id":5184,"en":"foreman","ja":"現場監督\n工事・工場などで作業員を管理する責任者","level":7,"lnum":1,"ex":"The foreman checked that all safety procedures were followed before starting the project.","exja":"現場監督はプロジェクトを開始する前にすべての安全手順が守られているか確認した。"},{"id":5185,"en":"foresee","ja":"予見する\n将来のことを事前に見通す。predictより直感的","level":7,"lnum":1,"ex":"No one could have foreseen how quickly the technology would spread worldwide.","exja":"その技術が世界中にどれほど素早く広まるかを予見できた人は誰もいなかった。"},{"id":5186,"en":"forestry","ja":"林業\n森林の管理・育成・伐採に関わる産業","level":7,"lnum":1,"ex":"The government invested heavily in forestry to restore areas damaged by wildfires.","exja":"政府は山火事で被害を受けた地域を回復するために林業に多額の投資をした。"},{"id":5187,"en":"formation","ja":"形成/隊形\n作り上げる過程、または並び方の形","level":7,"lnum":1,"ex":"The students watched in amazement as the planes flew in a perfect V-formation.","exja":"学生たちは飛行機が完璧なV字隊形を飛ぶのを驚いて見ていた。"},{"id":5188,"en":"formerly","ja":"以前は\n今とは違う過去の状態を示す。previouslyに近い","level":7,"lnum":1,"ex":"The building was formerly a factory but has been converted into luxury apartments.","exja":"その建物はかつて工場だったが、高級アパートに改装された。"},{"id":5189,"en":"formidable","ja":"強大な\n恐れるほど強力・印象的。intimidatingに近い","level":7,"lnum":1,"ex":"The young athlete faced a formidable opponent in the final round of the tournament.","exja":"その若いアスリートはトーナメントの最終ラウンドで強大な対戦相手と向き合った。"},{"id":5190,"en":"forthcoming","ja":"まもなくの\n近い将来に予定されている。upcomingより硬め","level":7,"lnum":1,"ex":"Details about the forthcoming album will be announced at next week's press conference.","exja":"まもなくリリースされるアルバムの詳細は来週の記者会見で発表される。"},{"id":5191,"en":"foul","ja":"ひどい/汚い\n臭い・不正・ルール違反など幅広く使う","level":7,"lnum":1,"ex":"The kitchen smelled foul because no one had taken out the garbage for days.","exja":"何日もゴミを出していなかったため、台所はひどい臭いがした。"},{"id":5192,"en":"found","ja":"設立する\n組織や会社を新しく作る。findとは別の動詞","level":7,"lnum":1,"ex":"The organization was founded in 1985 to support children in need.","exja":"その組織は1985年に困っている子供たちを支援するために設立された。"},{"id":5193,"en":"fragrance","ja":"香り\n心地よい匂い。scentより上品でポジティブ","level":7,"lnum":1,"ex":"The fragrance of freshly baked bread filled the entire house.","exja":"焼きたてのパンの香りが家中に広がった。"},{"id":5194,"en":"frame","ja":"組み立てる\n枠・構造を作る。意見・質問を組み立てる意味も","level":7,"lnum":1,"ex":"The architect framed the new housing plan around the needs of the local community.","exja":"建築家は地域住民のニーズを中心に新しい住宅計画を組み立てた。"},{"id":5195,"en":"frankly","ja":"率直に\n思ったことをそのまま言う。honestly に近い","level":7,"lnum":1,"ex":"Frankly, I think the proposal needs significant improvement before it can be approved.","exja":"率直に言って、その提案は承認される前に大幅な改善が必要だと思う。"},{"id":5196,"en":"frantically","ja":"必死に\nパニック気味で焦りながら行動する様子","level":7,"lnum":1,"ex":"She searched frantically through her bag for her passport at the airport.","exja":"彼女は空港でパスポートを探してバッグを必死にかき回した。"},{"id":5197,"en":"fraud","ja":"詐欺\n意図的に人を騙して利益を得る行為","level":7,"lnum":1,"ex":"The accountant was arrested for committing financial fraud against the company.","exja":"その会計士は会社に対して財務詐欺を行ったとして逮捕された。"},{"id":5198,"en":"freak","ja":"慌てる\n突然パニックになる・驚いて取り乱す（口語）","level":7,"lnum":1,"ex":"He freaked out when he heard that his flight had been cancelled.","exja":"フライトがキャンセルになったと聞いて、彼は慌てふためいた。"},{"id":5199,"en":"frigate","ja":"フリゲート艦\n中型の軍用艦船。護衛任務に使われる","level":7,"lnum":1,"ex":"The navy deployed a frigate to patrol the waters near the disputed islands.","exja":"海軍は係争中の島々近くの海域を哨戒するためにフリゲート艦を配備した。"},{"id":5200,"en":"frontier","ja":"フロンティア\n未開拓の境界・最前線。比喩的にも使う","level":7,"lnum":1,"ex":"Space exploration represents one of the final frontiers of human discovery.","exja":"宇宙探査は人類の発見における最後のフロンティアの一つだ。"},{"id":5201,"en":"frugal","ja":"質素な\n無駄遣いせず倹約的。cheapより肯定的","level":7,"lnum":1,"ex":"He lived a frugal lifestyle in his youth, which allowed him to retire early.","exja":"彼は若い頃質素な生活を送り、それによって早期退職が可能になった。"},{"id":5202,"en":"fulfill/fulfil","ja":"果たす\n義務・夢・条件などを実現・完遂する","level":7,"lnum":1,"ex":"She fulfilled her dream of becoming a professional musician.","exja":"彼女はプロの音楽家になるという夢を果たした。"},{"id":5203,"en":"fume","ja":"煙/ガス\n有害な煙やガス（複数形fumeが多い）","level":7,"lnum":1,"ex":"Workers at the factory were required to wear masks to protect them from the toxic fumes.","exja":"工場の労働者は有毒な煙から身を守るためにマスクを着用することが義務付けられた。"},{"id":5204,"en":"functional","ja":"機能的な\n実際に機能している・実用的な。decorativeの反対","level":7,"lnum":1,"ex":"The kitchen may not look stylish, but all the appliances are fully functional.","exja":"台所はスタイリッシュに見えないかもしれないが、すべての電化製品は完全に機能している。"},{"id":5205,"en":"functionality","ja":"機能性\nシステムや製品が持つ機能の総体","level":7,"lnum":1,"ex":"The latest software update added new functionality that users had been requesting.","exja":"最新のソフトウェアアップデートでユーザーが要望していた新しい機能性が追加された。"},{"id":5206,"en":"fundamental","ja":"根本的な\n最も基本となる重要な部分。basicより硬い","level":7,"lnum":1,"ex":"A strong understanding of mathematics is fundamental to studying engineering.","exja":"数学の深い理解は工学を学ぶために根本的に重要だ。"},{"id":5207,"en":"funk","ja":"憂うつ/ファンク\n気分の落ち込み、またはファンク音楽のジャンル","level":7,"lnum":1,"ex":"He has been in a bit of a funk ever since he failed his driving test.","exja":"運転免許試験に落ちて以来、彼はちょっと憂うつな状態が続いている。"},{"id":5208,"en":"funky","ja":"個性的な\n独特のリズム・スタイルを持つ。ファンキーな","level":7,"lnum":1,"ex":"The café had a funky interior decorated with vintage furniture and street art.","exja":"そのカフェはヴィンテージ家具とストリートアートで飾られた個性的なインテリアだった。"},{"id":5209,"en":"furious","ja":"激怒した\n非常に激しく怒った状態。angryの強い版","level":7,"lnum":1,"ex":"The manager was furious when he found out that the project had been delayed again.","exja":"プロジェクトがまた遅延したと知って、マネージャーは激怒した。"},{"id":5210,"en":"furiously","ja":"激しく\n猛烈な怒りや速さで。angrily より強烈","level":7,"lnum":1,"ex":"The students worked furiously to finish their assignments before the midnight deadline.","exja":"学生たちは深夜の締め切り前に課題を終わらせようと激しく取り組んだ。"},{"id":5211,"en":"furor/furore","ja":"大騒動\n怒りや興奮による騒ぎ。scandalize的な出来事","level":7,"lnum":1,"ex":"The politician's scandal caused a furor among the public.","exja":"その政治家のスキャンダルは国民の間に大騒動を引き起こした。"},{"id":5212,"en":"gaiety","ja":"陽気さ\n軽やかで楽しい雰囲気。cheerfulnessより古風","level":7,"lnum":1,"ex":"The gaiety of the festival filled the town with music, laughter, and color.","exja":"祭りの陽気さが音楽、笑い声、色彩で町を満たした。"},{"id":5213,"en":"gambling","ja":"賭け事\nお金をかけてゲームや競技に賭ける行為","level":7,"lnum":1,"ex":"He lost a large amount of money through gambling and was left in serious debt.","exja":"彼は賭け事で多額のお金を失い、深刻な借金を抱えた。"},{"id":5214,"en":"gang","ja":"ギャング団\n犯罪などを行う仲間集団。groupより危険な響き","level":7,"lnum":1,"ex":"A gang of teenagers was caught vandalizing the park late at night.","exja":"10代の若者のグループが深夜に公園を荒らしているのを捕まえられた。"},{"id":5215,"en":"gangster","ja":"暴力団員\n組織犯罪に関わる人。mafiaメンバーを含む","level":7,"lnum":1,"ex":"The film tells the story of a young man who gets drawn into the life of a gangster.","exja":"その映画は暴力団員の生活に引き込まれる若者の物語を描いている。"},{"id":5216,"en":"gardener","ja":"庭師\n庭の手入れ・植物の管理を職業とする人","level":7,"lnum":1,"ex":"The gardener planted dozens of colorful flowers along the garden path.","exja":"庭師は庭の小道に沿って色とりどりの花を何十本も植えた。"},{"id":5217,"en":"gasp","ja":"息をのむ\n驚きや苦しさで息を吸い込む音・動作","level":7,"lnum":1,"ex":"The audience gasped in surprise when the magician made the rabbit disappear.","exja":"マジシャンがウサギを消した時、観客は驚いて息をのんだ。"},{"id":5218,"en":"gateway","ja":"入口/玄関口\n何かへの入り方・アクセス手段。比喩にも使う","level":7,"lnum":1,"ex":"The city's international airport serves as a major gateway to Southeast Asia.","exja":"その都市の国際空港は東南アジアへの主要な玄関口となっている。"},{"id":5219,"en":"gaudy","ja":"けばけばしい\n趣味が悪く派手すぎる色彩・装飾","level":7,"lnum":1,"ex":"The tourists were surprised by the gaudy decorations covering every wall of the souvenir shop.","exja":"観光客はお土産屋の壁全体を覆うけばけばしい装飾に驚いた。"},{"id":5220,"en":"gaze","ja":"じっと見つめること\n長く真剣に見つめること。glanceの反対","level":7,"lnum":1,"ex":"She stood at the window and gazed at the snow-covered mountains in the distance.","exja":"彼女は窓際に立ち、遠くに雪を被った山々をじっと見つめた。"},{"id":5221,"en":"gear","ja":"歯車/用具\n機械の歯車、または特定目的の道具一式","level":7,"lnum":1,"ex":"The hikers checked all their gear before setting out on the three-day trail.","exja":"ハイカーたちは3日間のトレイルに出発する前にすべての用具を確認した。"},{"id":5222,"en":"generalization/generalisation","ja":"一般化\n個別の事例から広い結論を出すこと","level":7,"lnum":1,"ex":"The generalization that all teenagers are rebellious is not always true.","exja":"すべての10代が反抗的だという一般化は必ずしも正しくない。"},{"id":5223,"en":"generalize/generalise","ja":"一般化する\n特定の事例から広い結論を導き出す","level":7,"lnum":1,"ex":"It is dangerous to generalize from just a few examples.","exja":"ほんのいくつかの例から一般化するのは危険だ。"},{"id":5224,"en":"generosity","ja":"寛大さ\n惜しみなく与える心の広さ","level":7,"lnum":1,"ex":"His generosity toward the local community was well known throughout the town.","exja":"地域社会に対する彼の寛大さは町全体でよく知られていた。"},{"id":5225,"en":"generously","ja":"寛大に\n気前よく・惜しみなく。量が多い場合にも使う","level":7,"lnum":1,"ex":"The company generously donated a large sum to support disaster relief efforts.","exja":"会社は災害救助活動を支援するために多額の寄付を気前よくした。"},{"id":5226,"en":"genius","ja":"天才\n並外れた知性や才能を持つ人","level":7,"lnum":1,"ex":"Einstein is widely regarded as one of the greatest scientific geniuses in history.","exja":"アインシュタインは歴史上最も偉大な科学的天才の一人として広く認められている。"},{"id":5227,"en":"genre","ja":"ジャンル\n芸術・音楽・文学などの種類・分類","level":7,"lnum":1,"ex":"Mystery is her favorite genre, and she reads at least one novel a month.","exja":"ミステリーは彼女のお気に入りのジャンルで、月に少なくとも1冊は小説を読む。"},{"id":5228,"en":"gently","ja":"やさしく\n穏やかに・丁寧に。人・動物・行動に使う","level":7,"lnum":1,"ex":"The nurse gently held the patient's hand to comfort her during the procedure.","exja":"看護師は処置中に患者を慰めようとやさしく手を握った。"},{"id":5229,"en":"genuine","ja":"本物の\n偽りのない真正な。authenticに近い","level":7,"lnum":1,"ex":"The expert confirmed that the painting was a genuine work by Rembrandt.","exja":"専門家はその絵画がレンブラントの本物の作品であることを確認した。"},{"id":5230,"en":"genuinely","ja":"心から\n本当に・偽りなく。reallyより誠実な響き","level":7,"lnum":1,"ex":"She was genuinely surprised when her coworkers threw her a surprise birthday party.","exja":"同僚たちがサプライズ誕生日パーティーを開いてくれた時、彼女は心から驚いた。"},{"id":5231,"en":"geographic","ja":"地理的な\n地理・場所・地形に関わる","level":7,"lnum":1,"ex":"The geographic diversity of Japan includes mountains, forests, and coastal plains.","exja":"日本の地理的多様性には山、森林、沿岸平野が含まれる。"},{"id":5232,"en":"germ","ja":"細菌/病原体\n病気を引き起こす微生物。bacteriaより日常的","level":7,"lnum":1,"ex":"Children are often told to wash their hands to avoid spreading germs.","exja":"子供たちは細菌の拡散を防ぐために手を洗うよう言われることが多い。"},{"id":5233,"en":"getaway","ja":"逃走/小旅行\n犯罪後の逃げ、または短い休暇旅行","level":7,"lnum":1,"ex":"The couple booked a relaxing weekend getaway at a resort in the mountains.","exja":"カップルは山のリゾートで週末のリラックスした小旅行を予約した。"},{"id":5234,"en":"ghetto","ja":"ゲットー\n特定の民族・貧困層が集住する地区","level":7,"lnum":1,"ex":"The novel describes life in a crowded ghetto where poverty and crime were rampant.","exja":"その小説は貧困と犯罪が蔓延する混雑したゲットーでの生活を描いている。"},{"id":5235,"en":"giveaway","ja":"無料配布/うっかり暴露\n無料プレゼント、または思わず本音が出ること","level":7,"lnum":1,"ex":"The free sample was a giveaway that attracted hundreds of customers to the store.","exja":"無料サンプルの配布が何百人もの顧客を店に引き寄せた。"},{"id":5236,"en":"glacis","ja":"緩斜面\n要塞前の傾斜地・軍事建築用語","level":7,"lnum":1,"ex":"The castle's defensive glacis made it extremely difficult for attackers to approach the walls.","exja":"城の緩斜面は攻撃者が城壁に近づくのを非常に難しくした。"},{"id":5237,"en":"glamorous/glamourous","ja":"華やかな\n魅力的でファッショナブルな印象","level":7,"lnum":1,"ex":"She looked glamorous in her red evening dress at the party.","exja":"パーティーで彼女は赤いイブニングドレスを着て華やかに見えた。"},{"id":5238,"en":"glare","ja":"にらみつけること\n怒りや不快感を持ってじっと見る行為","level":7,"lnum":1,"ex":"She glared at the student who kept talking during the lecture.","exja":"彼女は講義中ずっと話し続けている学生をにらみつけた。"},{"id":5239,"en":"gleam","ja":"輝き\n弱いがきれいな光。flashより柔らかい","level":7,"lnum":1,"ex":"A gleam of sunlight broke through the clouds and lit up the valley below.","exja":"雲の切れ間から一筋の輝きが差し込み、下の谷を照らした。"},{"id":5240,"en":"glee","ja":"歓喜\n純粋で無邪気な喜び。joyより軽やかな感じ","level":7,"lnum":1,"ex":"The children squealed with glee when they saw the pile of presents under the Christmas tree.","exja":"子供たちはクリスマスツリーの下にプレゼントの山を見て歓喜の声を上げた。"},{"id":5241,"en":"globally","ja":"世界規模で\n地球全体のレベルで。internationallyに近い","level":7,"lnum":1,"ex":"The company operates globally, with offices in over thirty countries.","exja":"その会社は世界規模で事業を展開しており、30か国以上にオフィスを持つ。"},{"id":5242,"en":"glocal","ja":"グローカルな\nグローバルとローカルを組み合わせた概念","level":7,"lnum":1,"ex":"The restaurant's menu reflects a glocal approach by combining local ingredients with international recipes.","exja":"そのレストランのメニューは地元の食材と国際的なレシピを組み合わせたグローカルなアプローチを反映している。"},{"id":5243,"en":"gloomy","ja":"陰鬱な\n暗くて気分が沈む。sadよりも重い雰囲気","level":7,"lnum":1,"ex":"The sky turned gloomy just before the storm hit the town.","exja":"嵐が町を直撃する直前に空は陰鬱になった。"},{"id":5244,"en":"glorify","ja":"美化する\n実際より良く見せる・称える。過度な場合も","level":7,"lnum":1,"ex":"Some critics argue that the film glorifies violence instead of showing its real consequences.","exja":"その映画は暴力を美化しており、現実の結果を描いていないと批判する人もいる。"},{"id":5245,"en":"glow","ja":"柔らかな輝き\n温かみのある光・顔色。shineより柔らかい","level":7,"lnum":1,"ex":"The fireflies created a soft glow in the darkness of the forest.","exja":"蛍が森の暗闇の中で柔らかな輝きを作り出した。"},{"id":5246,"en":"goat","ja":"ヤギ\n山羊。比喩的にスケープゴート（scapegoat）でも使う","level":7,"lnum":1,"ex":"The farmer kept a herd of goats on the hillside to produce milk and cheese.","exja":"農家は牛乳とチーズを生産するために丘の斜面にヤギの群れを飼っていた。"},{"id":5247,"en":"godly","ja":"神聖な\n神のような・非常に敬虔な。holy に近い","level":7,"lnum":1,"ex":"The congregation admired the godly manner in which their pastor lived his life.","exja":"会衆は牧師が送る神聖な生き方を尊敬した。"},{"id":5248,"en":"goodwill","ja":"善意/好意\n親切な気持ちや企業の無形資産","level":7,"lnum":1,"ex":"The charity event was organized to promote goodwill between the two communities.","exja":"その慈善イベントは二つのコミュニティ間の善意を促進するために企画された。"},{"id":5249,"en":"gook","ja":"軽蔑語\n特定民族への差別的俗語。使用禁止","level":7,"lnum":1,"ex":"This word is a harmful racial slur and should never be used.","exja":"この言葉は差別的な俗語であり、決して使用すべきではない。"},{"id":5250,"en":"gorge","ja":"峡谷\n切り立った崖の間の深い谷。canyonより狭い","level":7,"lnum":1,"ex":"The hikers descended into the gorge and followed the river to the waterfall.","exja":"ハイカーたちは峡谷に下り、川に沿って滝まで進んだ。"},{"id":5251,"en":"gossip","ja":"うわさ話をする\n他人の私的なことを話す。negativeな響き","level":7,"lnum":1,"ex":"She found it uncomfortable when her coworkers started to gossip about a colleague.","exja":"同僚たちが同僚のうわさ話を始めたとき、彼女は居心地が悪く感じた。"},{"id":5252,"en":"governmental","ja":"政府の\n国の行政機関に関する。officialより範囲が広い","level":7,"lnum":1,"ex":"The new regulations were part of a broader governmental effort to reduce pollution.","exja":"新しい規制は汚染を減らすための政府のより広い取り組みの一部だった。"},{"id":5253,"en":"gracefulness","ja":"優雅さ\n動作や外見の優雅で美しい質","level":7,"lnum":1,"ex":"The gracefulness of the ballet dancer captivated everyone in the audience.","exja":"バレエダンサーの優雅さは観客全員を魅了した。"},{"id":5254,"en":"gradual","ja":"段階的な\nゆっくり少しずつ変化する。suddenの反対","level":7,"lnum":1,"ex":"The patient made a gradual recovery over several months following the surgery.","exja":"患者は手術後数か月かけて段階的に回復した。"},{"id":5255,"en":"grain","ja":"穀物/粒\n米・麦などの穀物、または小さな粒","level":7,"lnum":1,"ex":"Wheat and rice are the most widely consumed grains in the world.","exja":"小麦と米は世界で最も広く消費されている穀物だ。"},{"id":5256,"en":"grand","ja":"壮大な\n規模・印象が大きく立派。magnificentに近い","level":7,"lnum":1,"ex":"The hotel lobby had a grand staircase decorated with crystal chandeliers.","exja":"ホテルのロビーにはクリスタルのシャンデリアで飾られた壮大な階段があった。"},{"id":5257,"en":"graphically","ja":"生々しく\nリアルで視覚的に強烈な描写をする様子","level":7,"lnum":1,"ex":"The documentary graphically depicted the destruction caused by the war.","exja":"そのドキュメンタリーは戦争によって引き起こされた破壊を生々しく描写した。"},{"id":5258,"en":"grasp","ja":"把握すること\n物を掴む、または概念を理解する両方に使う","level":7,"lnum":1,"ex":"She had a strong grasp of the complex concepts after studying them for weeks.","exja":"彼女は何週間も学んだ後、複雑な概念をしっかり把握していた。"},{"id":5259,"en":"gravestone","ja":"墓石\n墓に立てられた石。tombstoneとほぼ同義","level":7,"lnum":1,"ex":"Moss had grown over the old gravestone, making the inscription hard to read.","exja":"古い墓石に苔が生えており、刻まれた文字を読むのが難しくなっていた。"},{"id":5260,"en":"gravitation","ja":"引力\n物体を引き寄せる力。gravitationよりgravityが一般的","level":7,"lnum":1,"ex":"The scientist explained how gravitation keeps the planets in orbit around the sun.","exja":"科学者は引力がどのように惑星を太陽の周りの軌道に保つかを説明した。"},{"id":5261,"en":"greatness","ja":"偉大さ\n卓越した質・能力・影響力の高さ","level":7,"lnum":1,"ex":"The coach believed that true greatness comes from consistent hard work over many years.","exja":"コーチは真の偉大さは何年もの継続的な努力から生まれると信じていた。"},{"id":5262,"en":"grief","ja":"深い悲しみ\n特に死別による強い悲嘆。sadnessより深刻","level":7,"lnum":1,"ex":"He was overwhelmed by grief after the sudden death of his closest friend.","exja":"親友の突然の死後、彼は深い悲しみに圧倒された。"},{"id":5263,"en":"grieve","ja":"悲しむ\n死別などで深く嘆き悲しむ。mournに近い","level":7,"lnum":1,"ex":"It is important to allow yourself to grieve when you lose someone you love.","exja":"愛する人を失った時、自分自身が悲しむことを許すことが大切だ。"},{"id":5264,"en":"grim","ja":"厳しい/暗い\n状況や表情が険しく希望のない感じ","level":7,"lnum":1,"ex":"The doctor's grim expression told them that the news was not going to be good.","exja":"医師の厳しい表情は、良い知らせではないことを彼らに伝えた。"},{"id":5265,"en":"grin","ja":"にっこり笑うこと\n口を大きく開けた笑い。smileより歯が見える","level":7,"lnum":1,"ex":"He couldn't help but grin when his team scored the winning goal in the final minute.","exja":"最終分に自分のチームが決勝ゴールを決めたとき、彼はにっこり笑わずにはいられなかった。"},{"id":5266,"en":"grip","ja":"握り/掌握すること\nしっかり掴む力。比喩的に支配・影響にも使う","level":7,"lnum":1,"ex":"The climber gripped the rock face tightly to avoid slipping on the wet surface.","exja":"登山者は濡れた岩面で滑らないよう岩壁をしっかり握った。"},{"id":5267,"en":"grip","ja":"握る\nしっかり掴む。hold tightlyに近い","level":7,"lnum":1,"ex":"He gripped the handrail tightly as he climbed the icy steps.","exja":"彼は凍った階段を上りながら手すりをしっかりと握った。"},{"id":5268,"en":"gross","ja":"総計の/ひどい\n税引き前の合計、または非常に不快な様子","level":7,"lnum":1,"ex":"The company reported a gross profit of ten million dollars before taxes were deducted.","exja":"会社は税金が控除される前に1000万ドルの総利益を報告した。"},{"id":5269,"en":"growing","ja":"成長中の\n増加・発展している状態を示す形容詞","level":7,"lnum":1,"ex":"There is growing concern among scientists about the effects of plastic pollution on the oceans.","exja":"プラスチック汚染が海洋に与える影響について科学者の間で懸念が高まっている。"},{"id":5270,"en":"grown-up","ja":"大人の\n子供でなく成熟した大人の（形容詞）","level":7,"lnum":1,"ex":"She wanted to prove to her parents that she was mature enough to be treated as a grown-up.","exja":"彼女は大人として扱われるほど成熟していることを両親に証明したかった。"},{"id":5271,"en":"grown-up","ja":"大人\n子供に対して大人を指す日常的な言葉","level":7,"lnum":1,"ex":"The grown-ups talked about politics while the children played outside.","exja":"大人たちが政治について話す間、子供たちは外で遊んでいた。"},{"id":5272,"en":"guarantee","ja":"保証する\n確実に約束・保証する。promiseより強い","level":7,"lnum":1,"ex":"The manufacturer guarantees that the product will last for at least five years.","exja":"製造業者は製品が少なくとも5年間持続することを保証している。"},{"id":5273,"en":"guard","ja":"守る\n危険から保護する。protectよりも番をする感じ","level":7,"lnum":1,"ex":"Security guards were stationed at every entrance to the stadium during the concert.","exja":"コンサート中、スタジアムのすべての入口に警備員が配置されていた。"},{"id":5274,"en":"guerrilla","ja":"ゲリラ\n非正規の小規模武装グループ・その戦術","level":7,"lnum":1,"ex":"The guerrilla fighters used the dense forest to avoid detection by government troops.","exja":"ゲリラ戦士は政府軍に発見されないよう密林を利用した。"},{"id":5275,"en":"guideline","ja":"ガイドライン\n行動・判断の基準となる指針","level":7,"lnum":1,"ex":"The health ministry issued new guidelines on diet and exercise for school-age children.","exja":"保健省は学齢期の子供の食事と運動に関する新しいガイドラインを発表した。"},{"id":5276,"en":"gulp","ja":"一口飲み\n慌てて飲み込む動作・音","level":7,"lnum":1,"ex":"He was so nervous before his speech that he gulped down a glass of water.","exja":"スピーチの前に彼はとても緊張していたので、コップ一杯の水を一気に飲み干した。"},{"id":5277,"en":"gunshot","ja":"銃声/銃撃\n銃が発射されたときの音や行為","level":7,"lnum":1,"ex":"Residents heard a gunshot in the middle of the night and called the police.","exja":"住民は真夜中に銃声を聞き、警察に通報した。"},{"id":5278,"en":"guts","ja":"度胸/根性\n困難に立ち向かう勇気。courageより口語的","level":7,"lnum":1,"ex":"It takes real guts to stand up and speak the truth when everyone else stays silent.","exja":"他の全員が黙っている時に立ち上がって真実を語るには本当の度胸が必要だ。"},{"id":5279,"en":"gymnastic","ja":"体操の\n体操競技・柔軟な動きに関わる形容詞","level":7,"lnum":1,"ex":"The gymnastic performance by the young athletes amazed the crowd at the championship.","exja":"若いアスリートたちによる体操の演技は選手権で観衆を驚かせた。"},{"id":5280,"en":"habitant","ja":"住民\nある地域に住む人。inhabitantの古い形","level":7,"lnum":1,"ex":"The habitats of many long-term habitants of the island have been damaged by rising sea levels.","exja":"島の多くの長年の住民の生活環境が海面上昇によって損なわれている。"},{"id":5281,"en":"hail","ja":"称賛する\n大きな声で称える・歓迎する。praiseより感動的","level":7,"lnum":1,"ex":"The crowd hailed the returning athletes as national heroes after their Olympic victory.","exja":"群衆はオリンピック優勝後に帰国したアスリートたちを国民的英雄として称えた。"},{"id":5282,"en":"hairy","ja":"毛深い\n体毛が多い。または危険で困難な状況（口語）","level":7,"lnum":1,"ex":"Fixing the leaking pipe in such a small space was a hairy job, but the plumber managed it.","exja":"そのような狭い場所での漏れたパイプの修理は困難な仕事だったが、配管工はやり遂げた。"},{"id":5283,"en":"hammer","ja":"叩く\n強く繰り返し打つ。hitより激しい動作","level":7,"lnum":1,"ex":"The carpenter hammered the nails into the wooden frame to build the wall.","exja":"大工は壁を作るために木枠に釘を打ち込んだ。"},{"id":5284,"en":"handicap","ja":"ハンデ/障害\n競争での不利条件、または身体的制限","level":7,"lnum":1,"ex":"His lack of experience in the field was a significant handicap during the job interview.","exja":"その分野での経験不足が就職面接での大きなハンデとなった。"},{"id":5285,"en":"handicraft","ja":"手工芸\n手作りの工芸品・手仕事","level":7,"lnum":1,"ex":"The market sold beautiful handicrafts made by local artisans from natural materials.","exja":"市場では地元の職人が天然素材で作った美しい手工芸品を販売していた。"},{"id":5286,"en":"handrail","ja":"手すり\n階段などで掴む安全用の手すり","level":7,"lnum":1,"ex":"Please hold onto the handrail as you go down the stairs to avoid slipping.","exja":"滑らないように、階段を下りる際は手すりをつかんでください。"},{"id":5287,"en":"hard drive","ja":"ハードドライブ\nコンピュータのデータ記録装置","level":7,"lnum":1,"ex":"He backed up all his important files on an external hard drive before the system update.","exja":"システムのアップデート前に彼は重要なファイルをすべて外付けハードドライブにバックアップした。"},{"id":5288,"en":"hardware","ja":"ハードウェア\nコンピュータの物理的な機器・部品","level":7,"lnum":1,"ex":"The technician replaced the faulty hardware and the computer started working again.","exja":"技術者は故障したハードウェアを交換し、コンピュータは再び動き始めた。"},{"id":5289,"en":"harmless","ja":"無害な\n危険や害を与えない。safe より弱い否定","level":7,"lnum":1,"ex":"Although the spider looks frightening, it is actually completely harmless to humans.","exja":"そのクモは怖そうに見えるが、実際には人間に対して全く無害だ。"},{"id":5290,"en":"harrow","ja":"馬鍬/苦しめる\n農具（土ならし）、または深く苦しめる（動詞）","level":7,"lnum":1,"ex":"The documentary about the famine was truly harrowing to watch.","exja":"飢饉についてのドキュメンタリーは見るのが本当に苦しかった。"},{"id":5291,"en":"haste","ja":"急ぎ\nあわてて急ぐ状態。hurryより書き言葉的","level":7,"lnum":1,"ex":"In his haste to catch the train, he left his wallet on the kitchen table.","exja":"電車に乗ろうと急ぐあまり、彼は財布を台所のテーブルに置き忘れた。"},{"id":5292,"en":"hastily","ja":"急いで\n考えずに慌てて。hurriedly より軽率な響き","level":7,"lnum":1,"ex":"She hastily packed a bag and left the house before the argument could continue.","exja":"彼女は言い争いが続く前に急いでバッグに荷物を詰めて家を出た。"},{"id":5293,"en":"hatching","ja":"孵化/ハッチング\n卵から孵る過程、または絵の細い平行線による陰影","level":7,"lnum":1,"ex":"The biology teacher explained the hatching process of a chick emerging from its egg.","exja":"生物の先生はひよこが卵から孵化するプロセスを説明した。"},{"id":5294,"en":"haunt","ja":"取り憑く\n幽霊が出る、または記憶がつきまとう","level":7,"lnum":1,"ex":"Memories of the accident continued to haunt him for years afterward.","exja":"事故の記憶は何年もの間彼につきまとい続けた。"},{"id":5295,"en":"haunting","ja":"忘れられない\n美しくも消えない印象を残す。記憶に残る感じ","level":7,"lnum":1,"ex":"The singer's haunting melody lingered in the audience's minds long after the concert ended.","exja":"歌手の忘れられないメロディーはコンサートが終わった後も長く観客の頭に残った。"},{"id":5296,"en":"hay","ja":"干し草\n乾燥させた牧草。make hay while the sun shines など","level":7,"lnum":1,"ex":"The farmer stored large bales of hay in the barn to feed the animals during winter.","exja":"農家は冬の間動物に餌を与えるために納屋に大きな干し草の束を保管した。"},{"id":5297,"en":"hazardous","ja":"危険な\n健康・安全を脅かす。dangerousより技術的","level":7,"lnum":1,"ex":"The chemical plant was fined for improperly disposing of hazardous waste.","exja":"化学工場は危険な廃棄物を不適切に処分したとして罰金を課された。"},{"id":5298,"en":"headquarters","ja":"本社/本部\n組織の中心となる主要施設（複数形扱い）","level":7,"lnum":1,"ex":"The company's headquarters are located in the financial district of the capital city.","exja":"会社の本社は首都の金融地区に位置している。"},{"id":5299,"en":"health care","ja":"医療/ヘルスケア\n健康管理・医療サービス全般","level":7,"lnum":1,"ex":"Improving access to affordable health care is one of the government's top priorities.","exja":"手頃な価格の医療へのアクセスを改善することが政府の最優先課題の一つだ。"},{"id":5300,"en":"heap","ja":"山積み\n乱雑に積み重なった大きな量（名詞）","level":7,"lnum":1,"ex":"She heaped praise on her students after they gave excellent presentations.","exja":"学生たちが素晴らしいプレゼンをした後、彼女は彼らに惜しみない賞賛を与えた。"},{"id":5301,"en":"heap","ja":"積み上げる\n大量に積む・与える（動詞）","level":7,"lnum":1,"ex":"She heaped praise on her student for his excellent performance.","exja":"彼女は生徒の優れた演技を惜しみなく称えた。"},{"id":5302,"en":"heartbreaking","ja":"胸が痛む\n深い悲しみや同情を感じさせる状況","level":7,"lnum":1,"ex":"It was heartbreaking to watch the family lose their home in the fire.","exja":"家族が火事で家を失うのを見るのは胸が痛む出来事だった。"},{"id":5303,"en":"heartwarming/heart-warming","ja":"心温まる\n温かく優しい気持ちにさせる場面","level":7,"lnum":1,"ex":"The video of the dog rescuing a child was truly heartwarming.","exja":"子供を救う犬の動画は本当に心温まるものだった。"},{"id":5304,"en":"hedge","ja":"生け垣\n庭の境界に植えた低木の垣根","level":7,"lnum":1,"ex":"The old house was surrounded by a tall hedge that gave it complete privacy.","exja":"古い家は完全なプライバシーを与える高い生け垣に囲まれていた。"},{"id":5305,"en":"helicopter","ja":"ヘリコプター\nプロペラで垂直に離着陸できる航空機","level":7,"lnum":1,"ex":"The rescue team used a helicopter to reach the hikers stranded on the mountain.","exja":"救助隊は山に立ち往生したハイカーに到達するためにヘリコプターを使用した。"},{"id":5306,"en":"hell","ja":"地獄\n宗教的な地獄、または非常につらい状況","level":7,"lnum":1,"ex":"The summer heat in the desert was absolute hell for those not used to such temperatures.","exja":"砂漠の夏の暑さはそのような気温に慣れていない人々には地獄のようだった。"},{"id":5307,"en":"helper","ja":"助手/手伝う人\n支援・補助をする人。assistantより非公式","level":7,"lnum":1,"ex":"She worked as a classroom helper to assist students who struggled with reading.","exja":"彼女は読書が苦手な生徒を助けるために教室の助手として働いた。"},{"id":5308,"en":"hemp","ja":"大麻/麻\n繊維原料となる植物。大麻とも呼ばれる","level":7,"lnum":1,"ex":"Hemp is increasingly being used as a sustainable material for clothing and construction.","exja":"大麻は衣服や建設のための持続可能な材料として次第に使われるようになっている。"},{"id":5309,"en":"herb","ja":"ハーブ\n料理・薬用に使う植物。英式はhで発音しない","level":7,"lnum":1,"ex":"She added fresh herbs from her garden to give the dish a more intense flavor.","exja":"彼女は料理により豊かな風味を与えるために庭の新鮮なハーブを加えた。"},{"id":5310,"en":"hesitation","ja":"ためらい\n迷って動けない状態。doubtより行動面での停止","level":7,"lnum":1,"ex":"After a moment of hesitation, she decided to accept the job offer abroad.","exja":"しばらくのためらいの後、彼女は海外の仕事のオファーを受け入れることにした。"},{"id":5311,"en":"highlight","ja":"見せ場/強調\n最も注目すべき部分や場面","level":7,"lnum":1,"ex":"The coach pointed out the highlights of the game during the post-match analysis.","exja":"コーチは試合後の分析で試合の見せ場を指摘した。"},{"id":5312,"en":"high-tech/hi-tech","ja":"最先端の\n高度な技術を使った。cutting-edgeに近い","level":7,"lnum":1,"ex":"The factory uses high-tech equipment to improve production efficiency.","exja":"その工場は生産効率を向上させるために最先端の設備を使っている。"},{"id":5313,"en":"hijack","ja":"乗っ取り\n飛行機・計画などを強制的に奪う行為（名詞）","level":7,"lnum":1,"ex":"The sudden hijack of the cargo ship made international headlines.","exja":"貨物船の突然の乗っ取りは国際的なニュースになった。"},{"id":5314,"en":"hijack","ja":"乗っ取る\n飛行機・車・計画などを強制的に奪う（動詞）","level":7,"lnum":1,"ex":"The pilot managed to land the plane safely after it was hijacked.","exja":"パイロットは飛行機が乗っ取られた後、無事に着陸させることができた。"},{"id":5315,"en":"hilarious","ja":"爆笑の\n非常に面白くて笑いが止まらない","level":7,"lnum":1,"ex":"The comedian's impression of the president was so hilarious that everyone burst out laughing.","exja":"コメディアンの大統領のものまねはとても爆笑ものだったので、全員が爆笑した。"},{"id":5316,"en":"holder","ja":"保持者/ホルダー\n物を持つ道具、または権利・地位を持つ人","level":7,"lnum":1,"ex":"The trophy holder kept the award safely displayed on a shelf in the meeting room.","exja":"トロフィーの保持者は賞を会議室の棚に安全に展示していた。"},{"id":5317,"en":"hollow","ja":"空洞の\n中が空っぽな。比喩的に「中身のない」にも使う","level":7,"lnum":1,"ex":"The squirrel made its home inside a hollow tree trunk in the middle of the park.","exja":"リスは公園の真ん中にある空洞になった木の幹の中を巣にした。"},{"id":5318,"en":"holocaust","ja":"大虐殺\n特にナチスによるユダヤ人虐殺。大文字で固有名詞","level":7,"lnum":1,"ex":"The museum was established to ensure that the Holocaust is never forgotten by future generations.","exja":"その博物館は大虐殺が将来の世代に決して忘れられないよう設立された。"},{"id":5319,"en":"homeward","ja":"帰宅方向の\n家に向かう方向・旅路の","level":7,"lnum":1,"ex":"After months of traveling, she finally turned homeward and began the long journey back.","exja":"何か月もの旅の後、彼女はついに帰路に就き、長い帰り旅を始めた。"},{"id":5320,"en":"hone","ja":"研ぎ澄ます\n技術・能力を磨いて高める。鋭くする","level":7,"lnum":1,"ex":"He spent years honing his guitar skills before performing in front of a live audience.","exja":"彼は生の観客の前で演奏する前に、何年もかけてギターの腕を磨いた。"},{"id":5321,"en":"honor/honour","ja":"称える\n尊敬や敬意を示す。respectより公式・儀礼的","level":7,"lnum":1,"ex":"The president honored the soldiers for their bravery in battle.","exja":"大統領は戦場での勇敢さに対して兵士たちを称えた。"},{"id":5322,"en":"honorable/honourable","ja":"名誉ある\n尊敬に値する誠実な行い・人物","level":7,"lnum":1,"ex":"She was praised for her honorable behavior during the difficult situation.","exja":"彼女は困難な状況での名誉ある行動を称えられた。"},{"id":5323,"en":"hood","ja":"フード/覆い\n頭部を覆うもの、または車のボンネット（米）","level":7,"lnum":1,"ex":"He pulled up his hood to protect his face from the cold rain.","exja":"彼は冷たい雨から顔を守るためにフードを被った。"},{"id":5324,"en":"hook","ja":"フック\n物を引っかける道具、または興味を引く仕掛け（名詞）","level":7,"lnum":1,"ex":"The fishing line got hooked on a branch sticking out of the water.","exja":"釣り糸が水から突き出た枝に引っかかってしまった。"},{"id":5325,"en":"hook","ja":"引っかける\nフックで固定する・興味を引きつける（動詞）","level":7,"lnum":1,"ex":"He hooked the fish and slowly reeled it toward the boat.","exja":"彼は魚を引っかけてゆっくりとボートの方に巻き取った。"},{"id":5326,"en":"hospice","ja":"ホスピス\n終末期患者のための緩和ケア施設","level":7,"lnum":1,"ex":"She spent her final weeks in a hospice, surrounded by family and caring staff.","exja":"彼女は最後の数週間を家族と献身的なスタッフに囲まれてホスピスで過ごした。"},{"id":5327,"en":"hospitable","ja":"もてなし好きな\n客を温かく迎える性質。friendlyより正式","level":7,"lnum":1,"ex":"The locals were so hospitable that the tourists felt at home immediately.","exja":"地元の人々がとても温かくもてなし好きで、観光客はすぐに家にいるような気分になった。"},{"id":5328,"en":"hospitality","ja":"おもてなし\n客への温かい対応・歓迎の気持ち","level":7,"lnum":1,"ex":"Japanese hospitality, known as omotenashi, is famous around the world for its attention to detail.","exja":"おもてなしとして知られる日本のもてなしは、細部への気配りで世界的に有名だ。"},{"id":5329,"en":"hospitalize/hospitalise","ja":"入院させる\n病院に患者を入院させる","level":7,"lnum":1,"ex":"The patient was hospitalized after suffering a severe allergic reaction.","exja":"患者は重篤なアレルギー反応を起こした後、入院させられた。"},{"id":5330,"en":"hourly","ja":"毎時の\n1時間ごとに繰り返される。hourly wageは時給","level":7,"lnum":1,"ex":"The bus service runs hourly from six in the morning until midnight.","exja":"バスのサービスは朝6時から深夜まで毎時運行している。"},{"id":5331,"en":"housekeeper","ja":"家政婦\n家事全般を担当する職業","level":7,"lnum":1,"ex":"The housekeeper cleaned the rooms and prepared the meals while the family was away.","exja":"家政婦は家族が留守の間、部屋を掃除して食事を準備した。"},{"id":5332,"en":"housemaster","ja":"寄宿舎監\n寄宿学校で生徒の生活を管理する教師","level":7,"lnum":1,"ex":"The housemaster was responsible for the welfare of all students living in the dormitory.","exja":"寄宿舎監は寮に住む全ての生徒の福祉に責任を持っていた。"},{"id":5333,"en":"housewife","ja":"主婦\n家事を主な役割とする女性","level":7,"lnum":1,"ex":"She chose to be a housewife so that she could focus on raising her children.","exja":"彼女は子育てに集中できるよう主婦になることを選んだ。"},{"id":5334,"en":"hover","ja":"浮遊する\n空中に静止する、またはそばをうろつく","level":7,"lnum":1,"ex":"The drone hovered silently above the crowd, capturing footage from the air.","exja":"ドローンは群衆の上空に静かに浮遊し、空中からの映像を撮影した。"},{"id":5335,"en":"hugely","ja":"非常に\n規模や程度がとても大きい。enormouslyに近い","level":7,"lnum":1,"ex":"The new product was hugely popular among teenagers across the country.","exja":"新製品は全国の10代の若者の間で非常に人気を博した。"},{"id":5336,"en":"human rights","ja":"人権\nすべての人が持つ基本的な権利","level":7,"lnum":1,"ex":"The organization works to protect human rights in regions where freedoms are restricted.","exja":"その組織は自由が制限されている地域で人権を守るために活動している。"},{"id":5337,"en":"humane","ja":"人道的な\n思いやりがあり残酷でない。humanとは別語","level":7,"lnum":1,"ex":"The animal shelter promotes humane treatment of all pets and abandoned animals.","exja":"動物シェルターはすべてのペットと捨てられた動物への人道的な扱いを推進している。"},{"id":5338,"en":"humanist","ja":"ヒューマニスト\n人間の尊厳・理性を重視する人","level":7,"lnum":1,"ex":"As a humanist, she believed that education and reason were the foundations of a good society.","exja":"ヒューマニストとして、彼女は教育と理性が良い社会の基盤であると信じていた。"},{"id":5339,"en":"humanize/humanise","ja":"人道的にする\nより人間らしく・思いやりある状態にする","level":7,"lnum":1,"ex":"The documentary humanized the refugees by showing their personal stories.","exja":"そのドキュメンタリーは難民の個人的な物語を映し出すことで彼らを人間的に描いた。"},{"id":5340,"en":"humble","ja":"謙虚な\n自分を誇らない控えめな態度・性格","level":7,"lnum":1,"ex":"Despite his many achievements, he remained humble and always praised the efforts of his team.","exja":"多くの業績にもかかわらず、彼は謙虚であり続け、常にチームの努力を称えた。"},{"id":5341,"en":"humbug","ja":"偽り/たわごと\n欺瞞・インチキ・ナンセンス。口語的に使う","level":7,"lnum":1,"ex":"The salesman's claims about his miracle product turned out to be pure humbug.","exja":"その営業マンの奇跡の商品についての主張は全くのでたらめだということが分かった。"},{"id":5342,"en":"humiliate","ja":"屈辱を与える\n人前で恥をかかせ自尊心を傷つける","level":7,"lnum":1,"ex":"The manager humiliated the employee by criticizing his work in front of the whole office.","exja":"マネージャーは従業員の仕事をオフィス全員の前で批判し、彼に屈辱を与えた。"},{"id":5343,"en":"humiliating","ja":"屈辱的な\n非常に恥ずかしく自尊心を傷つける体験","level":7,"lnum":1,"ex":"Forgetting your speech in the middle of a presentation is a truly humiliating experience.","exja":"プレゼンの途中でスピーチを忘れることは本当に屈辱的な体験だ。"},{"id":5344,"en":"humiliation","ja":"屈辱\n自尊心が深く傷つけられた体験・状態","level":7,"lnum":1,"ex":"The scandal caused deep public humiliation for the politician and his family.","exja":"スキャンダルはその政治家と家族に深い公的な屈辱をもたらした。"},{"id":5345,"en":"hush","ja":"静かにさせる\n声や音を静めさせる。shh！と同じ意図","level":7,"lnum":1,"ex":"The teacher hushed the noisy classroom with a single look.","exja":"先生は一つの視線でうるさい教室を静かにさせた。"},{"id":5346,"en":"hybrid","ja":"ハイブリッドの\n二つの異なる要素を組み合わせた","level":7,"lnum":1,"ex":"The company launched a new hybrid vehicle that runs on both electricity and gasoline.","exja":"会社は電気とガソリンの両方で走る新しいハイブリッド車を発売した。"},{"id":5347,"en":"hygiene","ja":"衛生\n清潔を保ち病気を防ぐための習慣・状態","level":7,"lnum":1,"ex":"Good personal hygiene is essential for preventing the spread of infectious diseases.","exja":"良好な個人衛生は感染症の拡大を防ぐために不可欠だ。"},{"id":5348,"en":"hyperbole","ja":"誇張法\n意図的に大げさな表現をする修辞技法","level":7,"lnum":1,"ex":"Saying \"I've told you a million times\" is a classic example of hyperbole in everyday speech.","exja":"「何百万回も言ったでしょう」と言うのは、日常会話における誇張法の典型的な例だ。"},{"id":5349,"en":"hyphen","ja":"ハイフン\n単語をつなぐ記号「-」。合成語や改行に使う","level":7,"lnum":1,"ex":"The word \"self-confident\" requires a hyphen to connect the two parts correctly.","exja":"\"self-confident\" という単語は二つの部分を正しくつなぐためにハイフンが必要だ。"},{"id":5350,"en":"iceman","ja":"氷屋/冷静な人\n氷を運ぶ人、または感情を見せない冷静な人","level":7,"lnum":1,"ex":"In the old days, the iceman would deliver blocks of ice to homes before refrigerators were invented.","exja":"昔は冷蔵庫が発明される前、氷屋が家々に氷の塊を届けていた。"},{"id":5351,"en":"icon","ja":"象徴/アイコン\n時代や分野を代表する人・物・画像","level":7,"lnum":1,"ex":"She became a fashion icon whose style was copied by millions of people worldwide.","exja":"彼女は世界中の何百万人もの人々にスタイルを真似られるファッションの象徴になった。"},{"id":5352,"en":"icy","ja":"凍った/冷たい\n氷のように冷たい・または態度が冷淡な","level":7,"lnum":1,"ex":"The roads became icy overnight, causing several accidents in the morning rush hour.","exja":"道路は夜の間に凍り付き、朝のラッシュアワーにいくつかの事故を引き起こした。"},{"id":5353,"en":"ideally","ja":"理想的には\n最善の状況ならば。現実とのギャップを示す","level":7,"lnum":1,"ex":"Ideally, we would finish the project by the end of next week, but it depends on the team's progress.","exja":"理想的には来週末までにプロジェクトを終わらせたいが、チームの進捗次第だ。"},{"id":5354,"en":"identical","ja":"まったく同じ\n完全に一致している。similarより強い同一性","level":7,"lnum":1,"ex":"The twins were so identical that even their teacher had trouble telling them apart.","exja":"双子はあまりにも全く同じで、先生でさえ見分けるのが難しかった。"},{"id":5355,"en":"identification","ja":"身元確認\n身分・同一性を確認すること。ID提示など","level":7,"lnum":1,"ex":"You will need to show valid identification before you can enter the restricted area.","exja":"制限区域に入る前に有効な身元確認書類を提示する必要がある。"},{"id":5356,"en":"identify","ja":"特定する\n誰・何かを正しく見分ける。recognizeより分析的","level":7,"lnum":1,"ex":"Scientists were able to identify the rare species of bird from just a few feathers.","exja":"科学者たちはわずかな羽から希少種の鳥を特定することができた。"},{"id":5357,"en":"ideology","ja":"イデオロギー\n社会・政治に関する体系的な思想・信念","level":7,"lnum":1,"ex":"The political party's ideology is based on the principles of social equality and economic freedom.","exja":"その政党のイデオロギーは社会的平等と経済的自由の原則に基づいている。"},{"id":5358,"en":"idiot","ja":"馬鹿\n知能が低い・愚かな人を指す侮辱的な言葉","level":7,"lnum":1,"ex":"He called himself an idiot for locking his keys inside the car.","exja":"彼は車の中に鍵を閉じ込めてしまったことで自分を馬鹿と呼んだ。"},{"id":5359,"en":"idle","ja":"怠けている\n働かず活動しない状態。lazyより状況的","level":7,"lnum":1,"ex":"The machine sat idle for months because there was no demand for its products.","exja":"その機械は製品への需要がなかったため、何か月も稼働しない状態が続いた。"},{"id":5360,"en":"idolize/idolise","ja":"崇拝する\n偶像のように崇め愛する。worship に近い","level":7,"lnum":1,"ex":"Teenagers often idolize famous singers and athletes.","exja":"10代の若者はしばしば有名な歌手や選手を崇拝する。"},{"id":5361,"en":"ignorance","ja":"無知\n知識・情報の欠如。知らないことへの批判的ニュアンス","level":7,"lnum":1,"ex":"His ignorance of local customs caused several awkward situations during his visit.","exja":"地元の習慣への無知が訪問中にいくつかの気まずい状況を引き起こした。"},{"id":5362,"en":"ignorant","ja":"無知な\n知識・教養がない。rudeの意味で使うことも","level":7,"lnum":1,"ex":"She was embarrassed to admit that she was ignorant of such a basic historical fact.","exja":"彼女はそのような基本的な歴史的事実を知らないと認めることが恥ずかしかった。"},{"id":5363,"en":"illustrate","ja":"説明する\n例や図を使って分かりやすく示す","level":7,"lnum":1,"ex":"The teacher used diagrams to illustrate how the heart pumps blood around the body.","exja":"教師は心臓がどのように体中に血液を送るかを説明するために図を使った。"},{"id":5364,"en":"illustration","ja":"挿絵/説明\n本の絵、または具体例による説明","level":7,"lnum":1,"ex":"The children's book was brought to life by its colorful illustrations on every page.","exja":"その児童書はすべてのページの色鮮やかな挿絵によって生き生きとした。"},{"id":5365,"en":"imagery","ja":"心象/イメージ\n文学・芸術における描写・比喩的表現の総称","level":7,"lnum":1,"ex":"The poem was rich in vivid imagery that painted a clear picture of the autumn landscape.","exja":"その詩は秋の風景を鮮明に描く生き生きとした心象で豊かだった。"},{"id":5366,"en":"imitation","ja":"模倣\n本物をまねること。真似は偽物感を含む","level":7,"lnum":1,"ex":"The cheap imitation of the famous watch looked real but fell apart within a week.","exja":"有名な時計の安い模倣品は本物のように見えたが、1週間以内に壊れた。"},{"id":5367,"en":"immerse","ja":"没入する\n液体に沈める、または完全に集中する","level":7,"lnum":1,"ex":"She immersed herself in Japanese culture by living in Tokyo for a year.","exja":"彼女は1年間東京に住むことで日本の文化に没入した。"},{"id":5368,"en":"immigrant","ja":"移民\n他国から移り住んできた人。emigrantは去る側","level":7,"lnum":1,"ex":"Many immigrants worked hard to build a new life in their adopted country.","exja":"多くの移民が養子となった国で新しい生活を築くために懸命に働いた。"},{"id":5369,"en":"immoral","ja":"不道徳な\n社会的・倫理的に正しくない行為","level":7,"lnum":1,"ex":"The community strongly condemned the immoral behavior of the public official.","exja":"地域社会はその公務員の不道徳な行動を強く非難した。"},{"id":5370,"en":"immortal","ja":"不死の\n死なない・永遠に生き続ける存在","level":7,"lnum":1,"ex":"The poet hoped that her words would make her immortal long after her death.","exja":"詩人は自分の言葉が死後も長く自分を不死の存在にしてくれることを願った。"},{"id":5371,"en":"immortality","ja":"不死\n永遠に生き続けること・死なない性質","level":7,"lnum":1,"ex":"Ancient Egyptians believed that the pharaoh could achieve immortality through the rituals performed after death.","exja":"古代エジプト人はファラオが死後の儀式を通じて不死を達成できると信じていた。"},{"id":5372,"en":"impartial","ja":"公平な\nどちらにも偏らない中立的な立場","level":7,"lnum":1,"ex":"The judge was known for being completely impartial in all of his rulings.","exja":"その裁判官はすべての判決において完全に公平であることで知られていた。"},{"id":5373,"en":"impatiently","ja":"じれったそうに\n待ちきれずイライラしながら行動する様子","level":7,"lnum":1,"ex":"The children waited impatiently outside the theater for the doors to open.","exja":"子供たちは劇場の外でドアが開くのをじれったそうに待っていた。"},{"id":5374,"en":"imperative","ja":"絶対必要なこと\n必ずしなければならない義務・命令","level":7,"lnum":1,"ex":"It is imperative that all passengers fasten their seat belts before the plane takes off.","exja":"飛行機が離陸する前に全乗客がシートベルトを締めることが絶対に必要だ。"},{"id":5375,"en":"impermanent","ja":"無常の\n永続しない・変わりやすい性質","level":7,"lnum":1,"ex":"All things in nature are impermanent; nothing lasts forever.","exja":"自然のすべてのものは無常であり、何も永遠には続かない。"},{"id":5376,"en":"implement","ja":"道具/手段\nある目的に使う具体的な器具（名詞）","level":7,"lnum":1,"ex":"The garden implement she needed most was a simple hand trowel for planting seeds.","exja":"彼女が最も必要としていた園芸道具は種を植えるためのシンプルな手持ちコテだった。"},{"id":5377,"en":"implement","ja":"実施する\n計画・方針を実際の行動に移す（動詞）","level":7,"lnum":1,"ex":"The government plans to implement new environmental policies next year.","exja":"政府は来年、新しい環境政策を実施する計画だ。"},{"id":5378,"en":"implication","ja":"含意\n直接言わないが示される意味・影響","level":7,"lnum":1,"ex":"The scientist explained the implications of the new discovery for medical research.","exja":"科学者は新しい発見が医療研究に持つ含意を説明した。"},{"id":5379,"en":"imply","ja":"暗示する\nはっきり言わずに示唆する。suggestより間接的","level":7,"lnum":1,"ex":"His tone implied that he was not satisfied with the results, even though he said nothing directly.","exja":"彼は直接何も言わなかったが、その口調は結果に満足していないことを暗示していた。"},{"id":5380,"en":"impolite","ja":"失礼な\n礼儀に反する行動・言葉。rudeより書き言葉的","level":7,"lnum":1,"ex":"It is considered impolite to use your phone during a formal dinner in many cultures.","exja":"多くの文化では正式なディナー中に携帯電話を使うことは失礼だと見なされる。"},{"id":5381,"en":"impolitely","ja":"失礼に\n礼儀を欠いた態度・言動で","level":7,"lnum":1,"ex":"He responded impolitely when the customer service representative asked for his name.","exja":"カスタマーサービスの担当者が名前を尋ねた時、彼は失礼な態度で答えた。"},{"id":5382,"en":"import","ja":"輸入する\n外国から商品・データを取り入れる","level":7,"lnum":1,"ex":"The country imports most of its oil from overseas because it has limited domestic resources.","exja":"その国は国内資源が限られているため、石油のほとんどを海外から輸入している。"},{"id":5383,"en":"impose","ja":"課す\n義務・税・ルールを強制的に与える","level":7,"lnum":1,"ex":"The government decided to impose stricter penalties for driving under the influence.","exja":"政府は飲酒運転に対してより厳しい罰則を課すことを決定した。"},{"id":5384,"en":"impossibility","ja":"不可能性\n実現できないこと・不可能であること","level":7,"lnum":1,"ex":"With the technology available at the time, a moon landing seemed like an impossibility.","exja":"当時利用可能な技術では、月面着陸は不可能に思えた。"},{"id":5385,"en":"impractical","ja":"非現実的な\n実際には使えない・実用的でない","level":7,"lnum":1,"ex":"Wearing high heels on a hiking trail is completely impractical and potentially dangerous.","exja":"ハイキングコースでハイヒールを履くのは全く非現実的で、危険性もある。"},{"id":5386,"en":"impressionism","ja":"印象主義\n19世紀フランスで生まれた絵画運動","level":7,"lnum":1,"ex":"Impressionism changed the art world by focusing on light and color rather than precise details.","exja":"印象主義は正確なディテールよりも光と色彩に焦点を当てることで美術界を変えた。"},{"id":5387,"en":"impressionist","ja":"印象派の画家\n印象主義スタイルの芸術家","level":7,"lnum":1,"ex":"Claude Monet is perhaps the most famous impressionist painter in history.","exja":"クロード・モネはおそらく歴史上最も有名な印象派の画家だ。"},{"id":5388,"en":"imprison","ja":"投獄する\n刑務所に閉じ込める。imprisonはjailより硬い","level":7,"lnum":1,"ex":"The court decided to imprison him for five years for his role in the fraud.","exja":"裁判所は詐欺への関与を理由に彼を5年間投獄することを決定した。"},{"id":5389,"en":"imprisonment","ja":"投獄\n刑務所に入れられている状態・刑罰","level":7,"lnum":1,"ex":"He faced imprisonment for tax evasion after years of trying to hide his income.","exja":"彼は何年もの間、収入を隠し続けた末に脱税で投獄に直面した。"},{"id":5390,"en":"improbable","ja":"ありそうにない\n起こる可能性が低い。unlikelyより書き言葉的","level":7,"lnum":1,"ex":"It seemed improbable that the underdog team would win the championship, but they did.","exja":"弱小チームが優勝するのはありそうにないことに思えたが、実際に優勝した。"},{"id":5391,"en":"improperly","ja":"不適切に\n正しい方法・基準に従わずに行動する様子","level":7,"lnum":1,"ex":"The machine failed because it had been improperly installed by an untrained technician.","exja":"機械は訓練を受けていない技術者によって不適切に設置されたため故障した。"},{"id":5392,"en":"improved","ja":"改善された\n以前より良くなった状態","level":7,"lnum":1,"ex":"The new model comes with an improved battery that lasts twice as long as the previous version.","exja":"新モデルは以前のバージョンの2倍長持ちする改善されたバッテリーを搭載している。"},{"id":5393,"en":"impulse","ja":"衝動\n突然の強い感情・行動への駆り立て","level":7,"lnum":1,"ex":"On an impulse, she bought a ticket to Paris without telling anyone in advance.","exja":"衝動的に、彼女は誰にも事前に告げずにパリへのチケットを買った。"},{"id":5394,"en":"impulsive","ja":"衝動的な\n考えず感情のまま行動する。spontaneousより軽率","level":7,"lnum":1,"ex":"His impulsive decision to quit his job without a backup plan worried his family.","exja":"バックアッププランなしに仕事を辞めるという衝動的な決断は家族を心配させた。"},{"id":5395,"en":"inaccurate","ja":"不正確な\n事実と合わない・間違いを含む状態","level":7,"lnum":1,"ex":"The report contained inaccurate information that misled many readers.","exja":"その報告書には多くの読者を誤解させた不正確な情報が含まれていた。"},{"id":5396,"en":"inadequate","ja":"不十分な\n必要な基準に達していない。insufficientに近い","level":7,"lnum":1,"ex":"The shelter provided inadequate protection from the cold, and the family struggled through the night.","exja":"その避難所は寒さから不十分な保護しか提供できず、家族は一晩中苦しんだ。"},{"id":5397,"en":"inanimate","ja":"無生物の\n生きていない・命のない状態","level":7,"lnum":1,"ex":"In the story, the inanimate objects in the toy store come to life at midnight.","exja":"その物語では、おもちゃ屋の無生物の物体が深夜に命を持って動き出す。"},{"id":5398,"en":"inborn","ja":"生まれつきの\n生まれながらに持っている。innateとほぼ同義","level":7,"lnum":1,"ex":"She had an inborn talent for music that amazed her teachers from an early age.","exja":"彼女は幼い頃から先生たちを驚かせた生まれつきの音楽の才能を持っていた。"},{"id":5399,"en":"incense","ja":"お香/激怒させる\n香を焚く棒・粉（名詞）。または激怒させる（動詞）","level":7,"lnum":1,"ex":"The temple was filled with the rich smell of incense burning near the altar.","exja":"寺院は祭壇の近くで燃えるお香の豊かな香りで満ちていた。"},{"id":5400,"en":"incentive","ja":"動機/インセンティブ\n行動を促す報酬・刺激・理由","level":7,"lnum":1,"ex":"The company offered a cash incentive to employees who achieved their sales targets.","exja":"会社は売上目標を達成した従業員に現金インセンティブを提供した。"},{"id":5401,"en":"inch","ja":"じりじり進む\nほんの少しずつゆっくり動く（動詞）","level":7,"lnum":1,"ex":"The snail inched slowly across the wet road after the rain stopped.","exja":"雨が止んだ後、カタツムリは濡れた道をじりじりとゆっくり進んだ。"},{"id":5402,"en":"incur","ja":"負う/招く\n損失・借金・批判などを自ら招く","level":7,"lnum":1,"ex":"By missing the payment deadline, she incurred a large fine that was difficult to pay.","exja":"支払い期限を過ぎたことで、彼女は支払うのが難しい多額の罰金を招いた。"},{"id":5403,"en":"incurable","ja":"治癒不能な\n治す手段がない病気・問題に使う","level":7,"lnum":1,"ex":"The doctor told him that the disease was incurable, but could be managed with medication.","exja":"医師は病気は治癒不能だが、薬で管理できると彼に告げた。"},{"id":5404,"en":"indebted","ja":"恩義を感じる\n助けてもらって感謝や義務を感じる状態","level":7,"lnum":1,"ex":"She felt deeply indebted to the teacher who had helped her pass the difficult exam.","exja":"彼女は難しい試験に合格させてくれた先生に深く恩義を感じた。"},{"id":5405,"en":"indent","ja":"字下げする\n段落の最初を下げて書く。コードのインデントにも","level":7,"lnum":1,"ex":"Remember to indent the first line of each new paragraph when writing a formal essay.","exja":"正式なエッセイを書く際は各段落の最初の行を字下げすることを忘れないでください。"},{"id":5406,"en":"independently","ja":"独立して\n他に頼らず自分で。aloneより自立の意味が強い","level":7,"lnum":1,"ex":"After years of training, she was finally able to manage the project independently.","exja":"何年もの訓練の後、彼女はついに独立してプロジェクトを管理できるようになった。"},{"id":5407,"en":"indescribable","ja":"言葉にできない\nあまりに強烈・美しく言葉で表せないほど","level":7,"lnum":1,"ex":"The view from the mountaintop was so beautiful that it was almost indescribable.","exja":"山頂からの景色はあまりに美しく、ほとんど言葉にできないほどだった。"},{"id":5408,"en":"index","ja":"索引/指数\n本の索引、または経済・価格の指数","level":7,"lnum":1,"ex":"The index at the back of the textbook helped students quickly locate the information they needed.","exja":"教科書の巻末の索引は学生が必要な情報をすばやく見つけるのに役立った。"},{"id":5409,"en":"indifferent","ja":"無関心な\n興味・関心がない。apathetic に近い","level":7,"lnum":1,"ex":"He seemed completely indifferent to the outcome of the election, which surprised his friends.","exja":"彼は選挙の結果に完全に無関心に見え、それが友人たちを驚かせた。"},{"id":5410,"en":"indignity","ja":"屈辱的な扱い\n尊厳を傷つける扱い・状況","level":7,"lnum":1,"ex":"Having to beg for basic necessities was a daily indignity for the homeless residents.","exja":"基本的な必需品を乞わなければならないことはホームレスの住民にとって毎日の屈辱的な扱いだった。"},{"id":5411,"en":"indispensable","ja":"不可欠な\n絶対に必要で欠かせない。essentialより強調的","level":7,"lnum":1,"ex":"The translator proved indispensable during the international negotiations.","exja":"翻訳者は国際交渉の際に不可欠であることが証明された。"},{"id":5412,"en":"individual","ja":"個人\n集団の中の一人一人。personalityより客観的","level":7,"lnum":1,"ex":"Each individual in the class was given the opportunity to present their research.","exja":"クラスの各個人が自分の研究を発表する機会を与えられた。"},{"id":5413,"en":"indulge","ja":"耽る\n好きなことを自由に楽しむ。しばしば過剰に","level":7,"lnum":1,"ex":"After weeks of dieting, she decided to indulge in a slice of chocolate cake.","exja":"何週間もダイエットした後、彼女はチョコレートケーキを一切れ食べることに耽ることにした。"},{"id":5414,"en":"indulgent","ja":"甘やかす\n規律より快楽や欲求を優先させる","level":7,"lnum":1,"ex":"The grandparents were quite indulgent and always bought the children whatever they asked for.","exja":"祖父母はかなり甘やかしており、子供たちが求めるものを何でも買ってあげた。"},{"id":5415,"en":"industrialize/industrialise","ja":"工業化する\n農業・手工業から工業生産中心へ移行させる","level":7,"lnum":1,"ex":"The country began to industrialize rapidly during the nineteenth century.","exja":"その国は19世紀に急速に工業化し始めた。"},{"id":5416,"en":"ineffective","ja":"効果のない\n望む結果を生まない。uselessよりマイルド","level":7,"lnum":1,"ex":"The medication proved ineffective for most patients in the clinical trial.","exja":"その薬は臨床試験でほとんどの患者に効果がないことが証明された。"},{"id":5417,"en":"inert","ja":"不活性の/動かない\n化学的に反応しない・動きがない状態","level":7,"lnum":1,"ex":"Noble gases such as helium and neon are chemically inert and do not react with other elements.","exja":"ヘリウムやネオンなどの希ガスは化学的に不活性で、他の元素と反応しない。"},{"id":5418,"en":"inexperienced","ja":"未経験の\n十分な経験・訓練がない。novice に近い","level":7,"lnum":1,"ex":"The inexperienced driver was nervous during his first time driving on the highway.","exja":"未経験の運転者は初めて高速道路を運転する際に緊張していた。"},{"id":5419,"en":"infant","ja":"乳幼児\n生後2歳未満程度の赤ちゃん。babyより医療的","level":7,"lnum":1,"ex":"The infant reached out and grabbed the colorful toy hanging above her crib.","exja":"乳幼児は手を伸ばして、ベビーベッドの上に吊るされた色とりどりのおもちゃを掴んだ。"},{"id":5420,"en":"infect","ja":"感染させる\n病原体を他の人・物に移す","level":7,"lnum":1,"ex":"A single infected person can infect dozens of others if proper precautions are not taken.","exja":"適切な予防策が取られなければ、一人の感染者が何十人もの人々に感染させることがある。"},{"id":5421,"en":"infected","ja":"感染した\n病原体に侵された状態","level":7,"lnum":1,"ex":"The wound became infected because it was not cleaned and bandaged properly.","exja":"傷口は適切に洗浄して包帯で巻かれなかったため、感染した。"},{"id":5422,"en":"infectious","ja":"感染性の\n他に広がりやすい病気・感情に使う","level":7,"lnum":1,"ex":"Her laughter was so infectious that everyone in the room started laughing too.","exja":"彼女の笑い声は非常に感染性で、部屋にいる全員も笑い始めた。"},{"id":5423,"en":"infer","ja":"推論する\n証拠をもとに結論を導き出す。guessより論理的","level":7,"lnum":1,"ex":"From the tone of the email, we can infer that she was not happy with the decision.","exja":"メールのトーンから、彼女がその決定に満足していなかったことを推論できる。"},{"id":5424,"en":"inference","ja":"推論\n証拠から導いた結論・推理の過程","level":7,"lnum":1,"ex":"The detective's inference that the thief had used the back entrance turned out to be correct.","exja":"泥棒が裏口を使ったという探偵の推論は正しいことが分かった。"},{"id":5425,"en":"inflammation","ja":"炎症\n体の一部が赤く腫れて痛む状態","level":7,"lnum":1,"ex":"The doctor prescribed anti-inflammatory medication to reduce the inflammation in his knee.","exja":"医師は膝の炎症を減らすために抗炎症薬を処方した。"},{"id":5426,"en":"inflammatory","ja":"炎症を起こす/扇動的な\n怒りや争いを引き起こしやすい言動","level":7,"lnum":1,"ex":"The politician's inflammatory remarks about immigrants stirred up anger across the country.","exja":"政治家の移民に関する扇動的な発言が国中に怒りを引き起こした。"},{"id":5427,"en":"inflate","ja":"膨らませる\n空気・価格・数値を膨らます。deflateの反対","level":7,"lnum":1,"ex":"The children helped inflate the balloons for the birthday party decorations.","exja":"子供たちは誕生日パーティーの飾りのために風船を膨らませる手伝いをした。"},{"id":5428,"en":"inflation","ja":"インフレ\n物価が継続的に上がり貨幣価値が下がること","level":7,"lnum":1,"ex":"High inflation caused the prices of everyday goods to rise dramatically over the past year.","exja":"高いインフレが過去1年間で日用品の価格を劇的に上昇させた。"},{"id":5429,"en":"influential","ja":"影響力のある\n他者の考えや行動に大きく影響する","level":7,"lnum":1,"ex":"She became one of the most influential scientists of her generation through her groundbreaking research.","exja":"彼女は画期的な研究を通じて自分の世代で最も影響力のある科学者の一人になった。"},{"id":5430,"en":"influenza","ja":"インフルエンザ\n流行性感冒。fluより正式・医療的な呼称","level":7,"lnum":1,"ex":"The hospital was overwhelmed with patients during the influenza outbreak last winter.","exja":"昨冬のインフルエンザの大流行中、病院は患者であふれかえった。"},{"id":5431,"en":"informal","ja":"非公式の\n堅苦しくない・くだけた。casualに近い","level":7,"lnum":1,"ex":"The meeting was kept informal so that everyone could speak freely and openly.","exja":"全員が自由に率直に話せるよう、会議は非公式に保たれた。"},{"id":5432,"en":"infringe","ja":"侵害する\n権利・法律・ルールを犯す。violateより法的","level":7,"lnum":1,"ex":"The new law was criticized for infringing on citizens' right to free speech.","exja":"新しい法律は市民の言論の自由を侵害するとして批判された。"},{"id":5433,"en":"infringement","ja":"侵害\n権利・特許・著作権などを犯す行為","level":7,"lnum":1,"ex":"The court ruled that the company was guilty of copyright infringement.","exja":"裁判所はその会社が著作権侵害の有罪であると判決を下した。"},{"id":5434,"en":"inhabit","ja":"生息する\n動物や人が特定の場所に住む・生息する","level":7,"lnum":1,"ex":"Polar bears inhabit the Arctic region, where they hunt seals on the sea ice.","exja":"ホッキョクグマは北極地方に生息し、海氷の上でアザラシを狩る。"},{"id":5435,"en":"inherit","ja":"受け継ぐ\n親から財産・性質・問題などを引き継ぐ","level":7,"lnum":1,"ex":"She inherited a large house and a considerable amount of money from her grandfather.","exja":"彼女は祖父から大きな家とかなりの額のお金を受け継いだ。"},{"id":5436,"en":"initial","ja":"最初の\n最初の・初期の段階を示す形容詞","level":7,"lnum":1,"ex":"The initial results of the experiment were promising, but further testing was needed.","exja":"実験の最初の結果は期待できるものだったが、さらなる検証が必要だった。"},{"id":5437,"en":"initiative","ja":"主導権/取り組み\n自ら率先して行動すること・新しい施策","level":7,"lnum":1,"ex":"The student took the initiative and organized a fundraising event for the local shelter.","exja":"その学生は主導権を取り、地元のシェルターのための募金活動を企画した。"},{"id":5438,"en":"injection","ja":"注射\n液体を体内に針で入れる医療行為","level":7,"lnum":1,"ex":"The nurse gave the patient an injection to help reduce the pain quickly.","exja":"看護師は痛みをすぐに和らげるために患者に注射を打った。"},{"id":5439,"en":"innate","ja":"生まれつきの\n生まれながらに持っている性質。learnedの反対","level":7,"lnum":1,"ex":"Curiosity seems to be an innate quality in young children who are constantly exploring.","exja":"好奇心は常に探索している幼い子供たちの生まれつきの性質のようだ。"},{"id":5440,"en":"innocently","ja":"無邪気に\n悪意なく純粋に行動する様子","level":7,"lnum":1,"ex":"The child stared innocently at the broken vase without realizing she had knocked it over.","exja":"子供は自分が倒したことに気づかずに、割れた花瓶を無邪気に見つめた。"},{"id":5441,"en":"innovation","ja":"革新\n新しいアイデアや技術による大きな変化","level":7,"lnum":1,"ex":"The company's success was largely driven by its culture of innovation and risk-taking.","exja":"会社の成功は主に革新とリスクを取る文化によって推進されていた。"},{"id":5442,"en":"innovative","ja":"革新的な\n新しく創造的なやり方をとる","level":7,"lnum":1,"ex":"The startup developed an innovative approach to reducing plastic waste in the ocean.","exja":"そのスタートアップは海洋のプラスチック廃棄物を削減するための革新的なアプローチを開発した。"},{"id":5443,"en":"input","ja":"入力/意見\n情報・データを入れること、または意見の提供","level":7,"lnum":1,"ex":"The manager asked all team members to provide input on how to improve the workflow.","exja":"マネージャーはワークフローを改善する方法についてすべてのチームメンバーに意見を求めた。"},{"id":5444,"en":"inquire/enquire","ja":"問い合わせる\n情報を求めて質問する。askより丁寧・正式","level":7,"lnum":1,"ex":"He inquired about the availability of rooms at the front desk.","exja":"彼はフロントデスクで空き部屋について問い合わせた。"},{"id":5445,"en":"inseparable","ja":"切り離せない\n強く結びついていて分けられない","level":7,"lnum":1,"ex":"The two friends were inseparable throughout their school years and remained close as adults.","exja":"二人の友人は学校時代を通じて切り離せない存在で、大人になっても親しい関係を保った。"},{"id":5446,"en":"inspect","ja":"検査する\n問題がないか詳しく調べる。checkより徹底的","level":7,"lnum":1,"ex":"The health inspector came to inspect the kitchen to ensure it met all safety standards.","exja":"衛生検査官はすべての安全基準を満たしているか確認するために台所を検査しに来た。"},{"id":5447,"en":"inspector","ja":"検査官\n公式に調査・監督する役職の人","level":7,"lnum":1,"ex":"The building inspector found several structural problems that needed to be fixed before it could be used.","exja":"建物検査官は使用前に修正が必要ないくつかの構造上の問題を発見した。"},{"id":5448,"en":"inspirational","ja":"感動的な\nやる気や希望を与える。motivationalに近い","level":7,"lnum":1,"ex":"The speech by the Paralympic athlete was truly inspirational and moved many in the audience to tears.","exja":"パラリンピックアスリートのスピーチは本当に感動的で、多くの観客を涙させた。"},{"id":5449,"en":"instantly","ja":"すぐに\n遅れなく即座に。immediatelyとほぼ同じ","level":7,"lnum":1,"ex":"When she pressed the button, the machine instantly responded with a beep.","exja":"彼女がボタンを押すと、機械はすぐにビープ音で反応した。"},{"id":5450,"en":"instill/instil","ja":"植えつける\n価値観・習慣・感情を徐々に植えつける","level":7,"lnum":1,"ex":"Parents try to instill good values in their children from an early age.","exja":"親は幼い頃から子供たちに良い価値観を植えつけようとする。"},{"id":5451,"en":"instinct","ja":"本能\n学ばずに生まれ持った行動の衝動","level":7,"lnum":1,"ex":"Her instinct told her something was wrong before she even entered the room.","exja":"部屋に入る前から、何かがおかしいという本能が彼女に告げていた。"},{"id":5452,"en":"institution","ja":"機関/制度\n社会的な組織や長く続く仕組み","level":7,"lnum":1,"ex":"The university is one of the oldest educational institutions in the country.","exja":"その大学はその国で最も古い教育機関の一つだ。"},{"id":5453,"en":"instruct","ja":"指示する\n具体的な方法を教えて指示する。tellより詳細","level":7,"lnum":1,"ex":"The fitness trainer instructed the beginners on how to use the equipment safely.","exja":"フィットネストレーナーは初心者に器具を安全に使う方法を指示した。"},{"id":5454,"en":"insufficient","ja":"不十分な\n必要量に達していない。enoughでないこと","level":7,"lnum":1,"ex":"The amount of evidence was insufficient to convict the suspect of the crime.","exja":"証拠の量は被疑者をその犯罪で有罪にするには不十分だった。"},{"id":5455,"en":"insult","ja":"侮辱\n相手の尊厳を傷つける言葉・行動（名詞）","level":7,"lnum":1,"ex":"He deeply regretted insulting his friend in the heat of the argument.","exja":"彼は言い争いの勢いで友人を侮辱したことを深く後悔した。"},{"id":5456,"en":"insult","ja":"侮辱する\n言葉や態度で相手を傷つける（動詞）","level":7,"lnum":1,"ex":"It is never acceptable to insult others in public.","exja":"公の場で他人を侮辱することは決して許されない。"},{"id":5457,"en":"integrate","ja":"統合する\n別々のものを一つにまとめる。mergeより包括的","level":7,"lnum":1,"ex":"The school worked hard to integrate new students into the existing social groups.","exja":"学校は新入生を既存の社会的グループに統合するために一生懸命取り組んだ。"},{"id":5458,"en":"intellectual","ja":"知的な\n知識・思考・理性に関わる（形容詞）","level":7,"lnum":1,"ex":"Many great intellectuals throughout history have questioned the assumptions of their time.","exja":"歴史上の多くの偉大な知識人は自分たちの時代の前提を問い直してきた。"},{"id":5459,"en":"intellectual","ja":"知識人\n学問や思想に深く関わる人（名詞）","level":7,"lnum":1,"ex":"The debate brought together some of the finest intellectuals in the country.","exja":"その討論会には国内で最も優れた知識人たちが集まった。"},{"id":5460,"en":"intent","ja":"熱心な\n何かに強く集中している・固く決意した","level":7,"lnum":1,"ex":"She was clearly intent on finishing the assignment before the deadline, no matter what it took.","exja":"彼女は何がかかってでも締め切り前に課題を終わらせることに熱心だった。"},{"id":5461,"en":"interactive","ja":"双方向の\n使う人が参加・操作できる仕組み","level":7,"lnum":1,"ex":"The museum has replaced many of its displays with interactive exhibits for visitors of all ages.","exja":"博物館はあらゆる年齢層の来場者のために多くの展示物を双方向の展示に置き換えた。"},{"id":5462,"en":"interfere","ja":"干渉する\n関係のないことに口を挟む。meddle に近い","level":7,"lnum":1,"ex":"Please do not interfere with the experiment; the results must be recorded objectively.","exja":"実験に干渉しないでください。結果は客観的に記録されなければならない。"},{"id":5463,"en":"interior","ja":"内部/インテリア\n建物・物の内側。exteriorの反対","level":7,"lnum":1,"ex":"The interior of the old cathedral was decorated with stunning mosaics and stained glass.","exja":"古い大聖堂の内部は素晴らしいモザイクとステンドグラスで飾られていた。"},{"id":5464,"en":"interpersonal","ja":"対人の\n人と人との関係に関わる。social skillsに近い","level":7,"lnum":1,"ex":"Good interpersonal skills are essential for anyone working in a customer-facing role.","exja":"顧客に接する役職で働く人にとって、良好な対人スキルは不可欠だ。"},{"id":5465,"en":"interpret","ja":"解釈する\n意味を読み取る・通訳する両方に使う","level":7,"lnum":1,"ex":"Different cultures often interpret the same gesture in completely different ways.","exja":"異なる文化は同じ身振りをしばしば全く異なる方法で解釈する。"},{"id":5466,"en":"interpretation","ja":"解釈\n文章・行動・芸術の意味を読み取ること","level":7,"lnum":1,"ex":"The professor offered a unique interpretation of the poem that challenged traditional views.","exja":"教授はその詩について、従来の見方に疑問を投げかける独自の解釈を提示した。"},{"id":5467,"en":"interruption","ja":"中断\n進行中のことが途切れること。pauseより突然","level":7,"lnum":1,"ex":"Constant interruptions made it almost impossible for her to focus on her work.","exja":"絶え間ない中断が彼女の仕事への集中をほとんど不可能にした。"},{"id":5468,"en":"intimate","ja":"親密な\n非常に近しい関係・プライベートな場面","level":7,"lnum":1,"ex":"The couple shared an intimate dinner at a quiet restaurant to celebrate their anniversary.","exja":"カップルは記念日を祝うために静かなレストランで親密なディナーを楽しんだ。"},{"id":5469,"en":"intransitive","ja":"自動詞の\n目的語を取らない動詞に関わる文法用語","level":7,"lnum":1,"ex":"In the sentence \"She sleeps,\" the verb \"sleeps\" is intransitive because it has no object.","exja":"「She sleeps」という文では、「sleeps」は目的語がないため自動詞だ。"},{"id":5470,"en":"intravenous","ja":"静脈内の\n静脈に直接投与する医療用語。IVとも呼ぶ","level":7,"lnum":1,"ex":"The patient was given intravenous fluids to prevent dehydration after the surgery.","exja":"患者は手術後の脱水を防ぐために静脈内輸液を投与された。"},{"id":5471,"en":"intrude","ja":"侵入する\n許可なく入り込む。trespassより広い意味","level":7,"lnum":1,"ex":"He did not want to intrude on the private conversation taking place in the next room.","exja":"彼は隣の部屋で行われているプライベートな会話に侵入したくなかった。"},{"id":5472,"en":"intruder","ja":"侵入者\n無断で入ってきた人。不法侵入者","level":7,"lnum":1,"ex":"The alarm system went off when an intruder broke through the back window.","exja":"侵入者が裏の窓を破ると警報システムが作動した。"},{"id":5473,"en":"intrusion","ja":"侵入/干渉\n無断で入り込む行為・プライバシーの侵害","level":7,"lnum":1,"ex":"The journalist was accused of intrusion into the family's private life.","exja":"そのジャーナリストは家族のプライベートな生活への侵入で非難された。"},{"id":5474,"en":"invariable","ja":"不変の\n常に同じで変わらない","level":7,"lnum":1,"ex":"His invariable routine of waking up at five o'clock helped him stay productive.","exja":"毎朝5時に起きるという変わらない習慣が彼の生産性を維持するのに役立った。"},{"id":5475,"en":"invariably","ja":"必ず\n例外なく常に。alwaysより強調的","level":7,"lnum":1,"ex":"She invariably arrived at the office before anyone else, no matter what day of the week it was.","exja":"彼女は曜日に関わらず、例外なく誰よりも早くオフィスに到着した。"},{"id":5476,"en":"inverted commas","ja":"引用符\n文章を引用するときに使う「」や\"\"の記号","level":7,"lnum":1,"ex":"In British English, inverted commas are used to mark a quotation.","exja":"英国英語では、引用符は引用を示すために使われる。"},{"id":5477,"en":"investigate","ja":"調査する\n事実・原因を詳しく調べる。checkより本格的","level":7,"lnum":1,"ex":"The police were asked to investigate the suspicious activities reported by local residents.","exja":"警察は地元住民から報告された不審な活動を調査するよう求められた。"},{"id":5478,"en":"investigator","ja":"調査員\n事件や問題を調べる専門家","level":7,"lnum":1,"ex":"The private investigator gathered enough evidence to prove the suspect's guilt.","exja":"私立探偵は被疑者の有罪を証明するのに十分な証拠を集めた。"},{"id":5479,"en":"investment","ja":"投資\n将来の利益のために資金・時間をかけること","level":7,"lnum":1,"ex":"Buying property in a growing city can be a wise long-term investment.","exja":"成長している都市で不動産を購入することは賢明な長期投資となり得る。"},{"id":5480,"en":"investor","ja":"投資家\n株や事業にお金を出す人","level":7,"lnum":1,"ex":"The startup attracted several major investors who believed in its potential for growth.","exja":"そのスタートアップは成長の可能性を信じる複数の大口投資家を引き付けた。"},{"id":5481,"en":"invisible","ja":"見えない\n目に見えない・存在が認識されない","level":7,"lnum":1,"ex":"The bacteria were invisible to the naked eye but could be seen under a microscope.","exja":"その細菌は肉眼では見えなかったが、顕微鏡では見ることができた。"},{"id":5482,"en":"invitingly","ja":"魅力的に\n思わず近づきたくなるような印象で","level":7,"lnum":1,"ex":"The warm fireplace glowed invitingly as the guests arrived from the cold outside.","exja":"外の寒さから到着したゲストを迎えるように、暖かい暖炉が魅力的に輝いていた。"},{"id":5483,"en":"invoke","ja":"呼び起こす\n法律・感情・記憶などを呼び出す。引き起こす","level":7,"lnum":1,"ex":"The lawyer invoked the client's right to remain silent during questioning.","exja":"弁護士は尋問中に依頼人の黙秘権を呼び起こした。"},{"id":5484,"en":"involvement","ja":"関与\n何かに関わっていること。participationより広い","level":7,"lnum":1,"ex":"Her involvement in the charity project made a significant difference in the lives of many children.","exja":"その慈善プロジェクトへの彼女の関与は多くの子供たちの生活に大きな変化をもたらした。"},{"id":5485,"en":"ironically","ja":"皮肉なことに\n予想と逆の結果が出たときに使う副詞","level":7,"lnum":1,"ex":"Ironically, the fire station burned down due to faulty electrical wiring.","exja":"皮肉なことに、消防署は欠陥のある電気配線が原因で焼失した。"},{"id":5486,"en":"irrational","ja":"不合理な\n論理的でない・理屈に合わない","level":7,"lnum":1,"ex":"His fear of flying was completely irrational, but he could not overcome it.","exja":"彼の飛行恐怖症は全く不合理だったが、克服することができなかった。"},{"id":5487,"en":"irresistible","ja":"抗えない\n誘惑や力が強すぎて断れない","level":7,"lnum":1,"ex":"The smell of fresh coffee in the morning is irresistible to most people.","exja":"朝の新鮮なコーヒーの香りはほとんどの人にとって抗えない。"},{"id":5488,"en":"irresistibly","ja":"抗いがたく\nどうしても抵抗できないほど強く","level":7,"lnum":1,"ex":"The movie was irresistibly charming, and she ended up watching it three times.","exja":"その映画は抗いがたく魅力的で、彼女は結局3回も観てしまった。"},{"id":5489,"en":"irresponsible","ja":"無責任な\n責任感がなく結果を考えない行動","level":7,"lnum":1,"ex":"It is irresponsible to leave young children at home alone without supervision.","exja":"幼い子供たちを監督なしに一人で家に残すのは無責任だ。"},{"id":5490,"en":"irritated","ja":"イライラした\n軽い怒りや不満を感じた状態","level":7,"lnum":1,"ex":"She became increasingly irritated by the constant noise coming from the street outside.","exja":"彼女は外の通りから続く絶え間ない騒音にますますイライラするようになった。"},{"id":5491,"en":"irritating","ja":"イライラさせる\n神経をさかなでするような不快な刺激","level":7,"lnum":1,"ex":"The squeaking noise from the old chair was so irritating that no one wanted to sit in it.","exja":"古いイスから出るきしみ音は非常にイライラさせるものだったので、誰も座りたがらなかった。"},{"id":5492,"en":"irritation","ja":"いら立ち\n繰り返す不快なことへの軽い怒り","level":7,"lnum":1,"ex":"He could barely hide his irritation when the meeting ran two hours over schedule.","exja":"会議が予定より2時間も長引いた時、彼はいら立ちをほとんど隠せなかった。"},{"id":5493,"en":"islander","ja":"島民\n島に住む人。島国の住民","level":7,"lnum":1,"ex":"The islanders relied heavily on fishing and farming to sustain their way of life.","exja":"島民は生活を維持するために漁業と農業に大きく依存していた。"},{"id":5494,"en":"italicize/italicise","ja":"斜体にする\nテキストをイタリック体（斜め文字）にする","level":7,"lnum":1,"ex":"The editor asked him to italicize all the book titles in the essay.","exja":"編集者は論文中の本のタイトルすべてをイタリック体にするよう彼に頼んだ。"},{"id":5495,"en":"itch","ja":"かゆい\n皮膚がかゆくなる・強くやりたい気持ちにも使う","level":7,"lnum":1,"ex":"His arm had been itching ever since he was stung by the insect during the hike.","exja":"ハイキング中に虫に刺されて以来、彼の腕はずっとかゆかった。"},{"id":5496,"en":"jaw","ja":"あご\n口の下部・歯がある骨格部分","level":7,"lnum":1,"ex":"Her jaw dropped in surprise when she opened the envelope and saw the letter inside.","exja":"封筒を開けて中の手紙を見たとき、驚きであごが外れそうになった。"},{"id":5497,"en":"jealously","ja":"嫉妬深く\n他人のものを羨み独占しようとする様子","level":7,"lnum":1,"ex":"He jealously guarded his recipe, refusing to share it with even his closest friends.","exja":"彼は最も親しい友人にさえ教えることを拒み、嫉妬深くレシピを守り続けた。"},{"id":5498,"en":"jeopardize/jeopardise","ja":"危険にさらす\n大切なものを危険な状態に置く","level":7,"lnum":1,"ex":"Poor management decisions can jeopardize the future of the entire company.","exja":"経営上の判断ミスは会社全体の将来を危険にさらしかねない。"},{"id":5499,"en":"jeweler/jeweller","ja":"宝石商\n宝石・貴金属を扱う職人・店主","level":7,"lnum":1,"ex":"The jeweler carefully set the diamond into the gold ring.","exja":"宝石商はダイヤモンドをゴールドの指輪に丁寧にはめ込んだ。"},{"id":5500,"en":"joint","ja":"関節/共同の\n体の関節、または共同で行うことを示す形容詞","level":7,"lnum":1,"ex":"The doctors examined the patient's joint to determine whether surgery was necessary.","exja":"医師たちは手術が必要かどうかを判断するために患者の関節を診察した。"},{"id":5501,"en":"journalism","ja":"ジャーナリズム\nニュース取材・報道に関わる職業・活動","level":7,"lnum":1,"ex":"She pursued a career in journalism because she wanted to inform the public about important issues.","exja":"彼女は重要な問題について公衆に知らせたかったため、ジャーナリズムのキャリアを追求した。"},{"id":5502,"en":"judo","ja":"柔道\n日本発祥の武道・格闘技","level":7,"lnum":1,"ex":"He has been practicing judo since the age of seven and recently earned his black belt.","exja":"彼は7歳からずっと柔道を練習しており、最近黒帯を取得した。"},{"id":5503,"en":"junk food","ja":"ジャンクフード\n栄養価が低く脂肪・塩分が多い食品","level":7,"lnum":1,"ex":"Eating too much junk food can lead to serious health problems over time.","exja":"ジャンクフードを食べ過ぎると、時間の経過とともに深刻な健康問題につながる可能性がある。"},{"id":5504,"en":"juror","ja":"陪審員\n裁判で有罪・無罪を判定する一般市民","level":7,"lnum":1,"ex":"Each juror was required to listen carefully to all the evidence before making a decision.","exja":"各陪審員は決定を下す前にすべての証拠を注意深く聞くことが求められた。"},{"id":5505,"en":"jury","ja":"陪審員団\n裁判で有罪・無罪を決める一般市民のグループ","level":7,"lnum":1,"ex":"The jury deliberated for three days before delivering the verdict.","exja":"陪審員団は評決を下す前に3日間評議した。"},{"id":5506,"en":"justify","ja":"正当化する\n行動・判断が正しいと理由をつけて説明する","level":7,"lnum":1,"ex":"She had to justify her decision to leave the company to her colleagues and manager.","exja":"彼女は同僚やマネージャーに会社を去るという決断を正当化しなければならなかった。"},{"id":5507,"en":"karaoke","ja":"カラオケ\n伴奏に合わせて歌う娯楽。日本語由来","level":7,"lnum":1,"ex":"Karaoke is extremely popular in Japan and is enjoyed by people of all ages.","exja":"カラオケは日本で非常に人気があり、あらゆる年齢の人々に楽しまれている。"},{"id":5508,"en":"keen","ja":"熱心な\n強い関心・意欲を持っている。enthusiasticに近い","level":7,"lnum":1,"ex":"She was keen to learn as much as possible before her internship abroad began.","exja":"彼女は海外インターンシップが始まる前にできるだけ多くのことを学びたいと熱心だった。"},{"id":5509,"en":"kerosene","ja":"灯油\n石油から精製した燃料。ランプ・暖房に使う","level":7,"lnum":1,"ex":"The old lamp ran on kerosene, which gave the room a warm, golden light.","exja":"その古いランプは灯油で動いており、部屋に温かい黄金色の光をもたらした。"},{"id":5510,"en":"keystroke","ja":"キー入力\nキーボードのキーを1回押す操作","level":7,"lnum":1,"ex":"Each keystroke is logged by the system to monitor for any unauthorized access attempts.","exja":"システムは不正アクセスの試みを監視するために各キー入力を記録している。"},{"id":5511,"en":"kneel","ja":"ひざまずく\n敬意・祈り・服従のために膝をつく","level":7,"lnum":1,"ex":"The knight was asked to kneel before the queen as she presented him with the award.","exja":"女王が賞を授与する際に、騎士は女王の前にひざまずくよう求められた。"},{"id":5512,"en":"knot","ja":"結び目\n紐などを結んだ部分。nautical mileの速度単位にも","level":7,"lnum":1,"ex":"She tied a tight knot in the rope to make sure the tent would not come loose in the wind.","exja":"彼女はテントが風でほどけないよう、ロープにしっかりした結び目を作った。"},{"id":5513,"en":"knowingly","ja":"承知の上で\n事実を知りながら意図的に行動する様子","level":7,"lnum":1,"ex":"She knowingly signed a false document, which led to her arrest.","exja":"彼女は承知の上で虚偽の書類に署名し、それが逮捕につながった。"},{"id":5514,"en":"known","ja":"知られている\n広く認識されている。well-known（よく知られた）","level":7,"lnum":1,"ex":"This region is known for its stunning natural scenery.","exja":"この地域は息をのむような自然の景色で知られている。"},{"id":5515,"en":"label","ja":"ラベル/レッテル\n分類のための名前や札。否定的レッテルにも使う","level":7,"lnum":1,"ex":"Doctors warned against labeling children based on test scores alone.","exja":"医師たちは、テストの点数だけで子供たちにレッテルを貼ることに警告を発した。"},{"id":5516,"en":"laborer/labourer","ja":"労働者\n肉体労働に従事する人。workerより肉体的","level":7,"lnum":1,"ex":"Many laborers worked long hours building the railway in dangerous conditions.","exja":"多くの労働者が危険な状況の中、長時間働いて鉄道を建設した。"},{"id":5517,"en":"lame","ja":"情けない/足の不自由な\n言い訳が弱い（口語）、または足が不自由な","level":7,"lnum":1,"ex":"His excuse for being late was so lame that nobody believed him.","exja":"彼の遅刻の言い訳はあまりにも情けなく、誰も信じなかった。"},{"id":5518,"en":"lance","ja":"槍/切開する\n長い槍（名詞）。または医療で切開する（動詞）","level":7,"lnum":1,"ex":"The knight charged forward with his lance aimed at the target.","exja":"騎士は槍を標的に向け、突進した。"},{"id":5519,"en":"landing","ja":"着陸/上陸\n飛行機の着陸、または船が陸につくこと","level":7,"lnum":1,"ex":"The pilot performed a smooth landing despite the strong crosswind.","exja":"パイロットは強い横風にもかかわらず、スムーズな着陸を行った。"},{"id":5520,"en":"landlady","ja":"女性大家\nアパートなどを所有・管理する女性","level":7,"lnum":1,"ex":"The landlady reminded her tenants to pay rent by the first of each month.","exja":"女性大家は入居者たちに、毎月1日までに家賃を払うよう念を押した。"},{"id":5521,"en":"landslide","ja":"地滑り/圧勝\n土砂崩れ、または選挙での大差の勝利","level":7,"lnum":1,"ex":"The ruling party won the election by a landslide, securing over 80% of the seats.","exja":"与党は地滑り的な勝利を収め、80%以上の議席を確保した。"},{"id":5522,"en":"lap","ja":"ひざ/一周\n座ったときの太もも上部、またはコース一周","level":7,"lnum":1,"ex":"The cat curled up on her lap and quickly fell asleep.","exja":"猫は彼女のひざの上で丸くなり、すぐに眠り込んだ。"},{"id":5523,"en":"laptop","ja":"ノートPC\n持ち運び可能なポータブルコンピュータ","level":7,"lnum":1,"ex":"He took his laptop to the café to work on his presentation.","exja":"彼はプレゼンの作業をするためにノートPCをカフェに持っていった。"},{"id":5524,"en":"lark","ja":"ひばり/楽しみ\nヒバリという鳥、または気晴らしの楽しみ","level":7,"lnum":1,"ex":"The children went on a lark through the woods, laughing and shouting.","exja":"子供たちは楽しみながら森の中を走り回り、笑い叫んでいた。"},{"id":5525,"en":"laser","ja":"レーザー\n集中した光線。医療・通信・兵器に使用","level":7,"lnum":1,"ex":"Surgeons used a laser to remove the tumor with great precision.","exja":"外科医はレーザーを使って、非常に精密に腫瘍を取り除いた。"},{"id":5526,"en":"last minute","ja":"土壇場\n期限直前のギリギリのタイミング（名詞）","level":7,"lnum":1,"ex":"She made last-minute changes to her speech just before going on stage.","exja":"彼女はステージに上がる直前に、スピーチを土壇場で変更した。"},{"id":5527,"en":"lastly","ja":"最後に\n列挙の最後の項目を示す。finallyに近いが形式的","level":7,"lnum":1,"ex":"Lastly, I would like to thank everyone who supported this project.","exja":"最後に、このプロジェクトを支援してくださった皆様に感謝申し上げます。"},{"id":5528,"en":"last-minute","ja":"土壇場の\n期限ギリギリに行われる（形容詞）","level":7,"lnum":1,"ex":"The team made a last-minute decision to change their strategy.","exja":"チームは土壇場で戦略を変更するという決断をした。"},{"id":5529,"en":"latter","ja":"後者の\n二つのうち後に述べた方。formerの反対","level":7,"lnum":1,"ex":"Of the two proposals, the committee preferred the latter.","exja":"2つの提案のうち、委員会は後者を好んだ。"},{"id":5530,"en":"lava","ja":"溶岩\n火山から流れ出た高温の溶けた岩石","level":7,"lnum":1,"ex":"The lava flowed slowly down the mountainside, destroying everything in its path.","exja":"溶岩はゆっくりと山の斜面を流れ下り、進路上のすべてを破壊した。"},{"id":5531,"en":"lawmaker","ja":"立法者\n法律を制定する議員・政治家","level":7,"lnum":1,"ex":"The lawmaker proposed a new bill to reduce carbon emissions.","exja":"その立法者は、炭素排出量を削減するための新しい法案を提案した。"},{"id":5532,"en":"lawn","ja":"芝生\n整えられた草地。lawn mower は芝刈り機","level":7,"lnum":1,"ex":"He spent the entire Saturday morning mowing the lawn.","exja":"彼は土曜日の午前中をすべて芝刈りに費やした。"},{"id":5533,"en":"lawsuit","ja":"訴訟\n法的手続きで争うこと。legal caseに近い","level":7,"lnum":1,"ex":"The company faced a major lawsuit after the product recall.","exja":"製品の回収後、その会社は重大な訴訟に直面した。"},{"id":5534,"en":"layabout","ja":"なまけ者\n働かずぶらぶらしている人。lazyboneに近い","level":7,"lnum":1,"ex":"His parents were frustrated because he had become a layabout after graduation.","exja":"彼の両親は、彼が卒業後になまけ者になったことに苛立っていた。"},{"id":5535,"en":"leaflet","ja":"チラシ\n折った薄い紙の情報冊子・パンフレット","level":7,"lnum":1,"ex":"Volunteers handed out leaflets about the upcoming community event.","exja":"ボランティアたちは近く行われる地域イベントについてのチラシを配った。"},{"id":5536,"en":"leak","ja":"漏れ\n液体・情報・ガスが外に出ること（名詞）","level":7,"lnum":1,"ex":"The pipe was leaking and caused water damage to the floor below.","exja":"パイプが漏れており、下の階に水による損害をもたらした。"},{"id":5537,"en":"leak","ja":"漏れる\n情報・液体などが外に出る（動詞）","level":7,"lnum":1,"ex":"The news of the scandal leaked to the press before the official announcement.","exja":"スキャンダルのニュースは公式発表の前にマスコミに漏れた。"},{"id":5538,"en":"lean","ja":"もたれる/傾く\n体を何かに預ける、または傾く動作","level":7,"lnum":1,"ex":"She leaned against the wall and waited for the bus to arrive.","exja":"彼女は壁にもたれながら、バスが来るのを待った。"},{"id":5539,"en":"leap","ja":"跳躍\n大きく飛び跳ねること・急激な進歩","level":7,"lnum":1,"ex":"The deer made a great leap over the fence and disappeared into the forest.","exja":"シカは塀を大きく跳び越え、森の中に消えていった。"},{"id":5540,"en":"learning","ja":"学習\n知識や技術を身につけること（名詞）","level":7,"lnum":1,"ex":"Learning a new language takes time, effort, and consistent practice.","exja":"新しい言語を習得するには、時間と努力、そして継続的な練習が必要だ。"},{"id":5541,"en":"lease","ja":"賃貸契約\n一定期間借りる正式な契約","level":7,"lnum":1,"ex":"They signed a two-year lease for the downtown apartment.","exja":"彼らは都心のアパートの2年間の賃貸契約に署名した。"},{"id":5542,"en":"leash","ja":"リード（犬）\n犬を制御するための紐・革ベルト","level":7,"lnum":1,"ex":"You must keep your dog on a leash in this public park.","exja":"この公園ではリードをつけて犬を管理しなければならない。"},{"id":5543,"en":"lecturer","ja":"講師\n大学などで講義をする教員。professorより下位","level":7,"lnum":1,"ex":"The lecturer explained the concept of supply and demand with clear examples.","exja":"講師は具体的な例を使って需要と供給の概念を説明した。"},{"id":5544,"en":"leek","ja":"ネギ\n西洋ネギ。料理に使う野菜","level":7,"lnum":1,"ex":"The soup was made with leeks, potatoes, and cream.","exja":"そのスープはネギ、ジャガイモ、クリームで作られていた。"},{"id":5545,"en":"legend","ja":"伝説\n語り継がれる偉大な人・話。mythより歴史的","level":7,"lnum":1,"ex":"Michael Jordan is a legend in the world of basketball.","exja":"マイケル・ジョーダンはバスケットボール界の伝説だ。"},{"id":5546,"en":"legendary","ja":"伝説的な\n非常に有名で記憶に残るほど偉大な","level":7,"lnum":1,"ex":"The legendary musician performed to a sold-out crowd for the last time.","exja":"その伝説的なミュージシャンは、最後の満員の観客を前に演奏した。"},{"id":5547,"en":"legislate","ja":"立法する\n法律を制定する。正式な議会での手続き","level":7,"lnum":1,"ex":"Parliament met to legislate new rules on environmental protection.","exja":"議会は環境保護に関する新しい規則を制定するために招集された。"},{"id":5548,"en":"legislation","ja":"法律/立法\n制定された法律、またはその制定過程","level":7,"lnum":1,"ex":"The new legislation requires all factories to reduce their waste output.","exja":"新しい法律はすべての工場に廃棄物の排出量削減を義務付けている。"},{"id":5549,"en":"legislative","ja":"立法の\n法律を作ることに関わる。legislative branch など","level":7,"lnum":1,"ex":"The legislative branch is responsible for creating new laws.","exja":"立法府は新しい法律を作る責任を担っている。"},{"id":5550,"en":"legislator","ja":"立法者/議員\n法律を作る立場の政治家・議員","level":7,"lnum":1,"ex":"The legislator argued that the tax reform would benefit working families.","exja":"その議員は、税制改革が働く家族に利益をもたらすと主張した。"},{"id":5551,"en":"legislature","ja":"立法府\n法律を制定する議会・国会","level":7,"lnum":1,"ex":"The state legislature voted to approve the new budget plan.","exja":"州議会は新しい予算計画を承認する投票を行った。"},{"id":5552,"en":"legitimate","ja":"正当な\n法律・規則・道徳的に認められた","level":7,"lnum":1,"ex":"The organization operates as a legitimate business registered with the government.","exja":"その組織は政府に登録された正当な事業として運営されている。"},{"id":5553,"en":"leisurely","ja":"ゆったりと\n急がずのんびりした様子。relaxedより行動的","level":7,"lnum":1,"ex":"They took a leisurely walk along the beach as the sun set.","exja":"彼らは日が沈む中、ビーチをゆったりと散歩した。"},{"id":5554,"en":"lengthen","ja":"伸ばす\n長さ・時間・距離を伸ばす。shortenの反対","level":7,"lnum":1,"ex":"The tailor agreed to lengthen the sleeves of the jacket by two centimeters.","exja":"仕立て屋はジャケットの袖を2センチ伸ばすことに同意した。"},{"id":5555,"en":"lengthy","ja":"長々とした\n時間や長さが必要以上に長い。longより批判的","level":7,"lnum":1,"ex":"The meeting turned into a lengthy discussion that lasted nearly four hours.","exja":"その会議は4時間近くに及ぶ長々とした議論になった。"},{"id":5556,"en":"leopard","ja":"ヒョウ\nアフリカ・アジアに生息する大型ネコ科動物","level":7,"lnum":1,"ex":"The leopard silently stalked its prey through the tall grass.","exja":"ヒョウは長い草の中で獲物をひっそりと追いかけた。"},{"id":5557,"en":"lest","ja":"〜しないように\n否定的な結果を避けるための接続詞。古風で書き言葉","level":7,"lnum":1,"ex":"She double-checked her work lest she make any mistakes.","exja":"彼女はミスをしないように、自分の仕事を二度確認した。"},{"id":5558,"en":"liberal","ja":"自由主義の\n個人の自由・進歩的な考えを支持する","level":7,"lnum":1,"ex":"The new policy was praised by liberal groups as a step toward equality.","exja":"新しい政策は、平等に向けた一歩として自由主義的なグループから称賛された。"},{"id":5559,"en":"lick","ja":"なめる\n舌で表面をなぞる。比喩的に「軽く打ち負かす」も","level":7,"lnum":1,"ex":"The child licked the ice cream before it melted in the summer heat.","exja":"子供は夏の暑さで溶ける前にアイスクリームを舐めた。"},{"id":5560,"en":"lid","ja":"ふた\n容器の蓋。keep a lid on（抑える）の慣用句も重要","level":7,"lnum":1,"ex":"Make sure to put the lid back on the jar to keep the contents fresh.","exja":"中身を新鮮に保つため、瓶のふたを必ず戻してください。"},{"id":5561,"en":"lifeless","ja":"生気のない\n活気や命がない。deadより比喩的に使う","level":7,"lnum":1,"ex":"After the company closed down, the office building looked completely lifeless.","exja":"会社が閉鎖された後、オフィスビルはまったく生気のない様子に見えた。"},{"id":5562,"en":"lifetime","ja":"一生涯\n人が生きている全期間。life spanに近い","level":7,"lnum":1,"ex":"Winning an Olympic gold medal was the achievement of a lifetime for him.","exja":"オリンピックの金メダルを獲得することは、彼にとって生涯の偉業だった。"},{"id":5563,"en":"lighten","ja":"明るくする/軽くする\n重さや暗さを減らす。気分を和らげる意味も","level":7,"lnum":1,"ex":"She told a joke to lighten the mood during the tense meeting.","exja":"彼女は緊張した会議の雰囲気を和らげるために冗談を言った。"},{"id":5564,"en":"lighting","ja":"照明\n場所を照らす光源・照明設備","level":7,"lnum":1,"ex":"The photographer adjusted the lighting to get the perfect shot.","exja":"カメラマンは最高の写真を撮るために照明を調整した。"},{"id":5565,"en":"likewise","ja":"同様に\n同じように・そちらもまた。similarlyに近い","level":7,"lnum":1,"ex":"She was kind to everyone, and they treated her likewise.","exja":"彼女は誰にでも親切で、皆も同様に彼女を扱った。"},{"id":5566,"en":"limb","ja":"手足/枝\n体の腕・脚、または木の枝","level":7,"lnum":1,"ex":"The boy climbed to the highest limb of the oak tree in the yard.","exja":"少年は庭のオークの木の一番高い枝まで登った。"},{"id":5567,"en":"linen","ja":"リネン/麻布\n麻から作られる素材・シーツなどの布製品","level":7,"lnum":1,"ex":"The hotel provided fresh linen and towels every morning.","exja":"ホテルは毎朝新しいリネンとタオルを提供した。"},{"id":5568,"en":"liner","ja":"定期船/ライナー\n定期航路の大型船、またはアイライナー","level":7,"lnum":1,"ex":"The cruise liner carried over two thousand passengers across the Atlantic.","exja":"その定期船は大西洋を渡り2千人以上の乗客を運んだ。"},{"id":5569,"en":"ling","ja":"ヒースの木/タラの一種\n北欧の荒野に生える植物、または魚の一種","level":7,"lnum":1,"ex":"Ling is a common plant found on the heathlands of northern Europe.","exja":"ヒースの木は北ヨーロッパの荒野によく見られる植物だ。"},{"id":5570,"en":"linger","ja":"長居する\n必要以上に長くとどまる。立ち去りたくない感じ","level":7,"lnum":1,"ex":"The smell of the delicious food lingered in the kitchen for hours.","exja":"おいしい料理の香りが何時間もキッチンに漂っていた。"},{"id":5571,"en":"literal","ja":"文字通りの\n比喩でなく言葉の本来の意味通り","level":7,"lnum":1,"ex":"The teacher explained that the phrase should be taken in its literal sense.","exja":"教師はそのフレーズを文字通りの意味で受け取るべきだと説明した。"},{"id":5572,"en":"literally","ja":"文字通りに\n誇張なく本当に。口語で強調にも使われる","level":7,"lnum":1,"ex":"He was so tired that he literally fell asleep standing up on the train.","exja":"彼はあまりにも疲れていて、電車の中で文字通り立ったまま眠ってしまった。"},{"id":5573,"en":"litter","ja":"ごみのポイ捨て\n公共の場にごみを散らかす行為・ごみ","level":7,"lnum":1,"ex":"It is illegal to litter in public places in many countries.","exja":"多くの国で、公共の場にゴミをポイ捨てすることは違法だ。"},{"id":5574,"en":"load","ja":"積む/読み込む\n荷物を積む、またはデータをロードする","level":7,"lnum":1,"ex":"Workers loaded the trucks with supplies before dawn to meet the deadline.","exja":"作業員たちは締め切りに間に合わせるために夜明け前にトラックに荷物を積んだ。"},{"id":5575,"en":"loan","ja":"ローン/貸付\n返済条件付きで貸すお金・借金","level":7,"lnum":1,"ex":"She took out a student loan to pay for her university education.","exja":"彼女は大学の学費を支払うために学生ローンを組んだ。"},{"id":5576,"en":"lobby","ja":"ロビー/陳情する\n建物の玄関ホール、または議員への働きかけ","level":7,"lnum":1,"ex":"Several companies are lobbying the government to lower corporate tax rates.","exja":"いくつかの企業が法人税率の引き下げを求めて政府に陳情している。"},{"id":5577,"en":"loneliness","ja":"孤独感\n一人でいる寂しさ・孤立感","level":7,"lnum":1,"ex":"Living far from family and friends, she began to feel a deep sense of loneliness.","exja":"家族や友人から遠く離れて暮らし、彼女は深い孤独感を感じ始めた。"},{"id":5578,"en":"long-distance","ja":"長距離の\n遠い距離に及ぶ。long-distance callは国際電話","level":7,"lnum":1,"ex":"They maintained a long-distance relationship for two years before finally reuniting.","exja":"彼らはついに再会するまでの2年間、遠距離恋愛を続けた。"},{"id":5579,"en":"long-term","ja":"長期的な\n長い時間をかけた計画・効果に使う","level":7,"lnum":1,"ex":"Regular exercise has significant long-term benefits for both physical and mental health.","exja":"定期的な運動は、身体的・精神的な健康の両方に大きな長期的効果をもたらす。"},{"id":5580,"en":"loosely","ja":"ゆるく\nきつくない状態で・厳密でない意味で","level":7,"lnum":1,"ex":"The term is loosely used to describe any kind of digital communication.","exja":"その言葉は、あらゆるデジタルコミュニケーションを緩やかに指すために使われている。"},{"id":5581,"en":"lousy","ja":"ひどい\n質が低く不快。terrible より口語的","level":7,"lnum":1,"ex":"The weather was lousy all weekend, so they stayed indoors.","exja":"週末ずっと天気がひどく、彼らは室内にいた。"},{"id":5582,"en":"lower","ja":"下げる\n位置・レベル・価格などを下げる（動詞）","level":7,"lnum":1,"ex":"The bank decided to lower interest rates to stimulate the economy.","exja":"銀行は経済を刺激するために金利を下げることを決定した。"},{"id":5583,"en":"lowland","ja":"低地\n山や高地に対して低い平地・湿地","level":7,"lnum":1,"ex":"The lowland areas were prone to flooding during heavy rainfall.","exja":"その低地は大雨の際に洪水が起きやすかった。"},{"id":5584,"en":"lucrative","ja":"もうかる\n利益が多く生じる。profitableより書き言葉的","level":7,"lnum":1,"ex":"Starting an online business proved to be highly lucrative for her.","exja":"オンラインビジネスを始めることは、彼女にとって非常に儲かることが証明された。"},{"id":5585,"en":"lush","ja":"豊かな\n植物が青々と茂る・豊かな緑の様子","level":7,"lnum":1,"ex":"The garden was lush and green after a week of steady rain.","exja":"1週間雨が降り続けた後、庭は豊かな緑に覆われていた。"},{"id":5586,"en":"luxurious","ja":"豪華な\n非常に高価で快適・贅沢な。lavishに近い","level":7,"lnum":1,"ex":"The hotel suite was so luxurious that every guest felt like royalty.","exja":"ホテルのスイートは非常に豪華で、すべてのゲストが王族のように感じた。"},{"id":5587,"en":"luxury","ja":"高級な\n富裕層向けの贅沢品に使う形容詞","level":7,"lnum":1,"ex":"The company launched a luxury version of its most popular product.","exja":"その会社は最も人気のある製品の高級版を発売した。"},{"id":5588,"en":"lyrics","ja":"歌詞\n曲の言葉・テキスト部分（複数形）","level":7,"lnum":1,"ex":"She memorized all the lyrics to her favorite song within a day.","exja":"彼女は1日のうちにお気に入りの曲の歌詞をすべて暗記した。"},{"id":5589,"en":"madam","ja":"奥様/女主人\n女性への丁寧な呼びかけ・店主の女性","level":7,"lnum":1,"ex":"\"Good evening, madam. How may I assist you?\" the receptionist asked politely.","exja":"「こんばんは、奥様。どのようなご用件でしょうか？」と受付係が丁寧に尋ねた。"},{"id":5590,"en":"madame","ja":"マダム\nフランス語由来の既婚女性への敬称","level":7,"lnum":1,"ex":"The performance was introduced by Madame Laurent, the director of the arts center.","exja":"公演はアートセンターの館長、ローランマダムによって紹介された。"},{"id":5591,"en":"madness","ja":"狂気/愚かさ\n正気でない状態、または非常に馬鹿げた行動","level":7,"lnum":1,"ex":"It would be pure madness to drive in such a severe snowstorm.","exja":"このような激しい吹雪の中で運転するのは純粋な狂気だ。"},{"id":5592,"en":"maestro","ja":"名匠\n音楽・芸術分野の大家・巨匠","level":7,"lnum":1,"ex":"The maestro stepped onto the podium and raised his baton to begin the concert.","exja":"名匠は指揮台に上がり、コンサートを始めるためにタクトを上げた。"},{"id":5593,"en":"magnify","ja":"拡大する\n大きく見せる・問題を誇張する両方に使う","level":7,"lnum":1,"ex":"The microscope magnified the bacteria to over a hundred times their actual size.","exja":"顕微鏡は細菌を実際のサイズの100倍以上に拡大した。"},{"id":5594,"en":"malady","ja":"病気\n慢性的な病気や社会問題。illnessより古風","level":7,"lnum":1,"ex":"The doctor diagnosed him with a rare malady that affected his nervous system.","exja":"医師は彼の神経系を侵す珍しい病気と診断した。"},{"id":5595,"en":"malaria","ja":"マラリア\n蚊が媒介する感染症。熱帯地方に多い","level":7,"lnum":1,"ex":"Malaria continues to be a serious public health problem in tropical regions.","exja":"マラリアは熱帯地域で依然として深刻な公衆衛生上の問題であり続けている。"},{"id":5596,"en":"mama/mamma","ja":"ママ\n母親の愛称。子供が使う親しみのある呼び方","level":7,"lnum":1,"ex":"\"Mama, I'm scared,\" the little boy whispered in the dark.","exja":"「ママ、怖い」と小さな男の子は暗闇の中でささやいた。"},{"id":5597,"en":"manipulate","ja":"操る\n自分の都合のために人・状況を巧みに動かす","level":7,"lnum":1,"ex":"The politician was accused of manipulating public opinion through the media.","exja":"その政治家はメディアを通じて世論を操ったとして批判された。"},{"id":5598,"en":"mansion","ja":"大邸宅\n非常に大きく豪華な個人住宅","level":7,"lnum":1,"ex":"The old mansion at the end of the road was rumored to be haunted.","exja":"道の突き当たりにある古い大邸宅は幽霊が出ると噂されていた。"},{"id":5599,"en":"manual","ja":"手動の\n機械でなく手を使う形容詞（手動の）","level":7,"lnum":1,"ex":"Read the manual carefully before operating this machine.","exja":"この機械を操作する前に、マニュアルをよく読んでください。"},{"id":5600,"en":"manual","ja":"マニュアル\n操作方法を記した説明書・手引書","level":7,"lnum":1,"ex":"Please read the manual carefully before operating the machine.","exja":"機械を操作する前にマニュアルをよく読んでください。"},{"id":5601,"en":"manufacture","ja":"製造\n工場で製品を大量に作ること（名詞）","level":7,"lnum":1,"ex":"The local factory manufactures over ten thousand units of the product per day.","exja":"その地元工場は製品を1日1万個以上製造している。"},{"id":5602,"en":"manufacture","ja":"製造する\n工場で製品を大量生産する（動詞）","level":7,"lnum":1,"ex":"The factory manufactures over a thousand cars per day.","exja":"その工場は1日に1000台以上の車を製造している。"},{"id":5603,"en":"manufacturer","ja":"製造業者\n製品を作る会社・企業・工場","level":7,"lnum":1,"ex":"The manufacturer recalled the product after reports of safety issues.","exja":"安全上の問題が報告された後、製造業者は製品を回収した。"},{"id":5604,"en":"manufacturing","ja":"製造業\n大量生産を行う産業分野","level":7,"lnum":1,"ex":"The region's economy depends heavily on manufacturing and export.","exja":"その地域の経済は製造業と輸出に大きく依存している。"},{"id":5605,"en":"margin","ja":"余白/差\nページの余白、または数値の差・利幅","level":7,"lnum":1,"ex":"The candidate won the election by a very small margin.","exja":"その候補者はわずかな差で選挙に勝利した。"},{"id":5606,"en":"marketing","ja":"マーケティング\n商品を売るための戦略・宣伝活動全般","level":7,"lnum":1,"ex":"The company invested heavily in marketing to promote its new product.","exja":"その会社は新製品を宣伝するためにマーケティングに多額の投資をした。"},{"id":5607,"en":"martial art","ja":"武道\n格闘技・武術の総称。柔道・空手など","level":7,"lnum":1,"ex":"He has been practicing a martial art since he was six years old.","exja":"彼は6歳の頃から武道を練習している。"},{"id":5608,"en":"mass","ja":"大量/大衆\n多くの量・人。mass mediaは大衆向け媒体","level":7,"lnum":1,"ex":"Mass transportation systems help reduce traffic congestion in big cities.","exja":"大量輸送システムは大都市の交通渋滞を緩和するのに役立つ。"},{"id":5609,"en":"massacre","ja":"大虐殺\n多くの人を無差別に殺す残虐行為","level":7,"lnum":1,"ex":"The massacre of civilians during the war shocked the entire world.","exja":"戦時中の民間人の大虐殺は世界中を震撼させた。"},{"id":5610,"en":"massage","ja":"マッサージ\n体をもんでほぐす施術","level":7,"lnum":1,"ex":"After the long hike, she booked a massage to relax her sore muscles.","exja":"長いハイキングの後、彼女は痛む筋肉をほぐすためにマッサージを予約した。"},{"id":5611,"en":"masseur","ja":"マッサージ師（男）\nマッサージを行う男性の職業人","level":7,"lnum":1,"ex":"The professional masseur helped athletes recover after their training sessions.","exja":"そのプロのマッサージ師はアスリートが練習後に回復するのを助けた。"},{"id":5612,"en":"masterpiece","ja":"傑作\n芸術家や作家の最高の作品","level":7,"lnum":1,"ex":"Many art critics consider this painting to be the artist's masterpiece.","exja":"多くの美術評論家がこの絵画を画家の傑作とみなしている。"},{"id":5613,"en":"mastery","ja":"習熟/熟達\n技術や分野を完全に使いこなせる高い能力","level":7,"lnum":1,"ex":"Her mastery of the piano was evident from the moment she began to play.","exja":"彼女のピアノの熟達ぶりは、弾き始めた瞬間から明らかだった。"},{"id":5614,"en":"mate","ja":"仲間/配偶者\n友人・同僚（英国口語）、または動物の配偶者","level":7,"lnum":1,"ex":"He called his mate to arrange a game of tennis on Sunday.","exja":"彼は日曜日にテニスの試合をするため仲間に電話した。"},{"id":5615,"en":"mathematical","ja":"数学的な\n数学に関係する・数学の手法を用いた","level":7,"lnum":1,"ex":"Solving this problem requires a mathematical approach and careful calculation.","exja":"この問題を解くには数学的なアプローチと慎重な計算が必要だ。"},{"id":5616,"en":"mature","ja":"成熟した\n年齢・思考が十分に発達した。grownに近い","level":7,"lnum":1,"ex":"By the time she graduated, she had become a very mature and responsible person.","exja":"卒業する頃には、彼女は非常に成熟した責任感のある人になっていた。"},{"id":5617,"en":"mausoleum","ja":"霊廟/大墓所\n偉大な人物を葬った記念建造物","level":7,"lnum":1,"ex":"The emperor was buried in a grand mausoleum built in the center of the capital.","exja":"皇帝は首都の中心に建てられた壮大な霊廟に葬られた。"},{"id":5618,"en":"means","ja":"手段/収入\n目的達成の方法、または生活の収入（複数形）","level":7,"lnum":1,"ex":"Hard work and dedication are the only means to achieve lasting success.","exja":"勤勉さと献身こそが、持続的な成功を収める唯一の手段だ。"},{"id":5619,"en":"mechanize/mechanise","ja":"機械化する\n手作業を機械に置き換える","level":7,"lnum":1,"ex":"The factory mechanized its production line to reduce costs and increase output.","exja":"工場はコスト削減と生産量増加のために生産ラインを機械化した。"},{"id":5620,"en":"medication","ja":"薬/投薬\n医師が処方する薬・薬物療法全般","level":7,"lnum":1,"ex":"The doctor prescribed medication to help manage the patient's chronic pain.","exja":"医師は患者の慢性的な痛みを和らげるために薬を処方した。"},{"id":5621,"en":"medieval/mediaeval","ja":"中世の\n中世（5〜15世紀ごろ）に関する","level":7,"lnum":1,"ex":"The castle was built during the medieval period and still stands today.","exja":"その城は中世に建てられ、今日もなお残っている。"},{"id":5622,"en":"mediocre","ja":"平凡な\n平均的で特に優れていない。okayより否定的","level":7,"lnum":1,"ex":"The film received mediocre reviews from critics and underperformed at the box office.","exja":"その映画は批評家から平凡な評価を受け、興行収入も振るわなかった。"},{"id":5623,"en":"mentor","ja":"師匠/メンター\n経験を活かして指導・助言する年上の人","level":7,"lnum":1,"ex":"She credits her mentor for guiding her through the early years of her career.","exja":"彼女はキャリアの初期を通じて自分を導いてくれたメンターに感謝している。"},{"id":5624,"en":"merchandise","ja":"商品\n販売目的の品物。goodsより商業的","level":7,"lnum":1,"ex":"The store sells a wide range of merchandise, from clothing to electronics.","exja":"その店は衣類から電化製品まで幅広い商品を販売している。"},{"id":5625,"en":"mercy","ja":"慈悲\n罰を与えられる立場の人を許す心の広さ","level":7,"lnum":1,"ex":"The judge showed mercy to the young offender and gave him a lighter sentence.","exja":"裁判官は若い違反者に慈悲を示し、軽い判決を下した。"},{"id":5626,"en":"merge","ja":"合併する\n二つ以上のものが一つになる。joinより大規模","level":7,"lnum":1,"ex":"The two airlines announced plans to merge into one company by next year.","exja":"2つの航空会社は来年までに1社に合併する計画を発表した。"},{"id":5627,"en":"merger","ja":"合併\n会社・組織が一つに統合すること","level":7,"lnum":1,"ex":"The merger between the two tech giants created one of the largest companies in the world.","exja":"2つの大手テクノロジー企業の合併により、世界最大級の会社が誕生した。"},{"id":5628,"en":"mess","ja":"散らかす/台無しにする\n整頓を乱す・物事を台無しにする（動詞）","level":7,"lnum":1,"ex":"He completely messed up the schedule by forgetting to confirm the bookings.","exja":"彼は予約の確認を忘れ、スケジュールを完全に台無しにした。"},{"id":5629,"en":"messenger","ja":"使者/メッセンジャー\nメッセージや荷物を運ぶ人","level":7,"lnum":1,"ex":"The messenger arrived at the palace with an urgent letter from the king.","exja":"使者は国王からの緊急の手紙を持って宮殿に到着した。"},{"id":5630,"en":"metaphor","ja":"比喩\n「AはBだ」と直接たとえる表現技法","level":7,"lnum":1,"ex":"\"Life is a journey\" is a common metaphor used in literature and everyday speech.","exja":"「人生は旅だ」は文学や日常会話でよく使われる比喩だ。"},{"id":5631,"en":"metric","ja":"メートル法の\n十進法のメートル単位系に基づく","level":7,"lnum":1,"ex":"Scientists around the world use the metric system for measurements.","exja":"世界中の科学者が測定にメートル法を使用している。"},{"id":5632,"en":"micro","ja":"マイクロ/微小\n百万分の一を表す接頭語。極めて小さいもの","level":7,"lnum":1,"ex":"The new micro chip is small enough to fit inside a grain of rice.","exja":"その新しいマイクロチップは米粒の中に収まるほど小さい。"},{"id":5633,"en":"microbe","ja":"微生物\n顕微鏡でのみ見える微小な生物","level":7,"lnum":1,"ex":"Researchers discovered a new type of microbe living deep in the ocean.","exja":"研究者たちは深海に生息する新種の微生物を発見した。"},{"id":5634,"en":"microcomputer","ja":"マイコン\n小型コンピュータ。現在のPCの前身","level":7,"lnum":1,"ex":"In the 1980s, the microcomputer revolutionized personal and office computing.","exja":"1980年代、マイコンは個人および職場のコンピューティングに革命をもたらした。"},{"id":5635,"en":"micrometer/micrometre","ja":"マイクロメートル\n百万分の一メートルの長さの単位","level":7,"lnum":1,"ex":"One micrometer is one millionth of a meter, used in precision engineering.","exja":"1マイクロメートルは100万分の1メートルで、精密工学で使われる。"},{"id":5636,"en":"microorganism","ja":"微生物\n顕微鏡でしか見えない極小の生命体","level":7,"lnum":1,"ex":"Some microorganisms are beneficial to humans, while others can cause disease.","exja":"一部の微生物は人間に有益だが、他のものは病気を引き起こす可能性がある。"},{"id":5637,"en":"microphone","ja":"マイク\n音声を電気信号に変える装置","level":7,"lnum":1,"ex":"Please speak into the microphone so that everyone in the room can hear you.","exja":"部屋にいる全員に聞こえるよう、マイクに向かって話してください。"},{"id":5638,"en":"microscope","ja":"顕微鏡\n微小なものを拡大して見る器具","level":7,"lnum":1,"ex":"The student looked through the microscope to observe the cell structure.","exja":"生徒は顕微鏡を覗き込んで細胞の構造を観察した。"},{"id":5639,"en":"microscopic","ja":"顕微鏡的な\n非常に小さく肉眼では見えないほど","level":7,"lnum":1,"ex":"The scientist found microscopic cracks in the material that caused it to fail.","exja":"科学者は材料に破損の原因となった顕微鏡的なひびを発見した。"},{"id":5640,"en":"microscopy","ja":"顕微鏡検査\n顕微鏡を使った観察・分析技術","level":7,"lnum":1,"ex":"Advances in microscopy have allowed scientists to observe living cells in detail.","exja":"顕微鏡技術の進歩により、科学者は生きた細胞を詳細に観察できるようになった。"},{"id":5641,"en":"microwave","ja":"電子レンジ\n電磁波で食品を加熱する調理器具","level":7,"lnum":1,"ex":"She reheated the leftovers in the microwave before sitting down to eat.","exja":"彼女は座って食事をする前に電子レンジで残り物を温め直した。"},{"id":5642,"en":"midst","ja":"真っただ中\n何かの中心・まっただ中にある状態","level":7,"lnum":1,"ex":"In the midst of the chaos, she remained calm and focused on finding a solution.","exja":"混乱の真っただ中で、彼女は落ち着いて解決策を見つけることに集中していた。"},{"id":5643,"en":"mighty","ja":"強大な\n非常に強い力・権力を持つ。powerfulより古風","level":7,"lnum":1,"ex":"The mighty river flooded the surrounding farmland after weeks of heavy rain.","exja":"何週間も続く大雨の後、強大な川が周辺の農地を水没させた。"},{"id":5644,"en":"migration","ja":"移住/渡り\n人や動物が場所を移動する現象","level":7,"lnum":1,"ex":"The annual migration of birds from north to south is a remarkable natural phenomenon.","exja":"鳥が北から南へと毎年行う渡りは、驚くべき自然現象だ。"},{"id":5645,"en":"mill","ja":"製粉所/工場\n穀物を粉に挽く施設、または工場","level":7,"lnum":1,"ex":"The old watermill by the river has been converted into a restaurant.","exja":"川沿いの古い水車小屋がレストランに改装された。"},{"id":5646,"en":"millimeter/millimetre","ja":"ミリメートル\n千分の一メートルの長さの単位","level":7,"lnum":1,"ex":"The doctor said the tumor was only three millimeters in diameter.","exja":"医師は腫瘍の直径はわずか3ミリメートルだと言った。"},{"id":5647,"en":"millionaire","ja":"百万長者\n100万ドル以上の資産を持つ富裕者","level":7,"lnum":1,"ex":"He became a millionaire before the age of thirty through his tech startup.","exja":"彼はテクノロジーのスタートアップを通じて30歳前に百万長者になった。"},{"id":5648,"en":"mimic","ja":"物まね師\n人や動物の動作・声を真似する人（名詞）","level":7,"lnum":1,"ex":"The parrot could mimic human speech with surprising accuracy.","exja":"そのオウムは驚くほど正確に人間の話し声を物まねすることができた。"},{"id":5649,"en":"miniature","ja":"ミニチュアの\n実物より大幅に小さい縮小版","level":7,"lnum":1,"ex":"The artist created a miniature version of the Eiffel Tower using matchsticks.","exja":"芸術家はマッチ棒を使ってエッフェル塔のミニチュア版を作り上げた。"},{"id":5650,"en":"minister","ja":"大臣/牧師\n政府の閣僚、またはキリスト教の聖職者","level":7,"lnum":1,"ex":"The minister of education announced a major reform of the school curriculum.","exja":"文部大臣は学校カリキュラムの大幅な改革を発表した。"},{"id":5651,"en":"mint","ja":"ミント/造幣局\nハーブの一種、または硬貨を作る公的機関","level":7,"lnum":1,"ex":"The government building where coins are produced is called a mint.","exja":"硬貨が製造される政府の建物は造幣局と呼ばれる。"},{"id":5652,"en":"misconception","ja":"誤解\n事実と異なる間違った認識・理解","level":7,"lnum":1,"ex":"There is a common misconception that eating fat always leads to weight gain.","exja":"脂肪を食べると必ず体重が増えるという一般的な誤解がある。"},{"id":5653,"en":"misfortune","ja":"不運\n悪い出来事・運の悪さ。bad luckより書き言葉的","level":7,"lnum":1,"ex":"He had the misfortune of losing his wallet on the very first day of his trip.","exja":"彼は旅行の初日に財布をなくすという不運に見舞われた。"},{"id":5654,"en":"misleading","ja":"誤解を招く\n事実とは異なる印象を与えてしまう情報","level":7,"lnum":1,"ex":"The advertisement was found to be misleading and was pulled from television.","exja":"その広告は誤解を招くと判明し、テレビから取り下げられた。"},{"id":5655,"en":"missile","ja":"ミサイル\n誘導・推進装置付きの飛翔型兵器","level":7,"lnum":1,"ex":"The military test-fired a new missile over the sea.","exja":"軍は海上で新型ミサイルの試験発射を行った。"},{"id":5656,"en":"mist","ja":"霧\n薄い水蒸気が漂う状態。fogより薄い","level":7,"lnum":1,"ex":"A thin mist covered the valley in the early hours of the morning.","exja":"早朝、薄い霧が谷を覆っていた。"},{"id":5657,"en":"mistreat","ja":"虐待する\n不当に扱う・乱暴に扱う","level":7,"lnum":1,"ex":"It is illegal to mistreat animals in this country.","exja":"この国では動物を虐待することは違法だ。"},{"id":5658,"en":"mistrustful","ja":"不信感を持つ\n信頼せず疑いを持つ性質","level":7,"lnum":1,"ex":"After being deceived many times, she became mistrustful of strangers.","exja":"何度も騙された後、彼女は見知らぬ人に不信感を抱くようになった。"},{"id":5659,"en":"mixture","ja":"混合物\n複数のものが混ざった状態・もの","level":7,"lnum":1,"ex":"The cake batter is a mixture of flour, eggs, butter, and sugar.","exja":"ケーキの生地は小麦粉、卵、バター、砂糖の混合物だ。"},{"id":5660,"en":"mobility","ja":"移動性\n動きやすさ・社会的流動性","level":7,"lnum":1,"ex":"Electric scooters have improved urban mobility for thousands of commuters.","exja":"電動スクーターは何千人もの通勤者の都市移動性を向上させた。"},{"id":5661,"en":"mock","ja":"模擬の\n本物でない演習用の・嘲る（形容詞）","level":7,"lnum":1,"ex":"The students held a mock election to practice the democratic process.","exja":"生徒たちは民主主義のプロセスを練習するために模擬選挙を行った。"},{"id":5662,"en":"modernization/modernisation","ja":"近代化\n古い方式から現代的な方式への移行","level":7,"lnum":1,"ex":"The modernization of the city's transport network took over a decade.","exja":"市の交通網の近代化には10年以上かかった。"},{"id":5663,"en":"modernize/modernise","ja":"近代化する\n古い方式を現代的に更新する","level":7,"lnum":1,"ex":"The government plans to modernize the country's healthcare system.","exja":"政府は国の医療制度を近代化する計画だ。"},{"id":5664,"en":"modest","ja":"控えめな\n自分を誇示せず謙虚。humbleより社交的","level":7,"lnum":1,"ex":"Despite winning the award, she remained modest and gave credit to her team.","exja":"賞を受賞したにもかかわらず、彼女は控えめにチームの功績を称えた。"},{"id":5665,"en":"modification","ja":"変更/修正\n元のものに手を加えて変えること","level":7,"lnum":1,"ex":"The engineer suggested a small modification to improve the device's performance.","exja":"エンジニアは装置の性能を向上させるために小さな変更を提案した。"},{"id":5666,"en":"mogul","ja":"大物/ムガル\n映画・ビジネス界の大物、またはスキー競技のモーグル","level":7,"lnum":1,"ex":"The media mogul owned dozens of newspapers and television stations worldwide.","exja":"そのメディアの大物は世界中に数十もの新聞社とテレビ局を所有していた。"},{"id":5667,"en":"mold/mould","ja":"カビ/型\n食品に生えるカビ、または形を作る型","level":7,"lnum":1,"ex":"She found mold growing on the old bread she had left in the bag.","exja":"彼女は袋の中に入れたままにしていた古いパンにカビが生えているのを見つけた。"},{"id":5668,"en":"momentarily","ja":"一時的に\nほんの短い時間だけ。brieflyより瞬間的","level":7,"lnum":1,"ex":"The lights went out momentarily, but quickly came back on.","exja":"照明が一瞬消えたが、すぐに戻った。"},{"id":5669,"en":"momentary","ja":"束の間の\n非常に短い時間だけ続く。一瞬の","level":7,"lnum":1,"ex":"There was a momentary silence in the room before everyone started applauding.","exja":"全員が拍手を始める前に、部屋に束の間の静寂が訪れた。"},{"id":5670,"en":"monastery","ja":"修道院\n修道士が共同生活をする宗教施設","level":7,"lnum":1,"ex":"The monks have lived in the mountain monastery for over five hundred years.","exja":"修道士たちは500年以上にわたってその山の修道院に住んでいる。"},{"id":5671,"en":"moody","ja":"気分屋の\n感情の変化が激しく不機嫌になりやすい","level":7,"lnum":1,"ex":"He became moody when things didn't go according to plan.","exja":"物事が計画通りに進まないと、彼は気分屋になった。"},{"id":5672,"en":"moonlight","ja":"月明かり\n月が発する柔らかな光","level":7,"lnum":1,"ex":"The couple walked along the beach by moonlight after dinner.","exja":"夕食後、2人は月明かりの中をビーチに沿って歩いた。"},{"id":5673,"en":"moonscape","ja":"月の表面\n月の風景・荒涼とした景観","level":7,"lnum":1,"ex":"The volcanic island looked like a moonscape, with nothing but black rock for miles.","exja":"その火山島は何マイルもの黒い岩しかない、まるで月の表面のような景色だった。"},{"id":5674,"en":"moral","ja":"道徳的な\n善悪の基準に関わる・倫理的な","level":7,"lnum":1,"ex":"The story ends with a clear moral: honesty is always the best policy.","exja":"その物語は明確な道徳的教訓で終わる。正直であることが常に最善の策だ。"},{"id":5675,"en":"morality","ja":"道徳性\n善悪を判断する基準・価値観の体系","level":7,"lnum":1,"ex":"The debate raised important questions about the morality of using animals in experiments.","exja":"その議論は動物実験の道徳性について重要な問いを提起した。"},{"id":5676,"en":"morally","ja":"道徳的に\n道徳・倫理の観点から見て","level":7,"lnum":1,"ex":"Using other people's work without permission is morally wrong.","exja":"他人の作品を許可なく使用することは道徳的に間違っている。"},{"id":5677,"en":"mortal","ja":"死すべき運命の\nいつか死ぬ存在としての。immortalの反対","level":7,"lnum":1,"ex":"All living things are mortal; nothing lasts forever in the natural world.","exja":"すべての生き物は死すべき運命にある。自然界では何も永遠には続かない。"},{"id":5678,"en":"mortar","ja":"モルタル/乳鉢\n建材の接合剤、または石臼・臼","level":7,"lnum":1,"ex":"The bricklayer mixed mortar to hold the stones of the wall together.","exja":"煉瓦職人は壁の石を固定するためにモルタルを混ぜた。"},{"id":5679,"en":"mortgage","ja":"住宅ローン\n家を担保にした長期の借金・住宅ローン","level":7,"lnum":1,"ex":"They took out a thirty-year mortgage to buy their first home.","exja":"彼らは初めての家を買うために30年の住宅ローンを組んだ。"},{"id":5680,"en":"mortify","ja":"屈辱を感じる\nひどく恥ずかしく感じる・自尊心が傷つく","level":7,"lnum":1,"ex":"She was mortified when she realized she had called her teacher by the wrong name.","exja":"先生を間違った名前で呼んでいたことに気づき、彼女はひどく恥ずかしく思った。"},{"id":5681,"en":"mother-in-law","ja":"義理の母\n配偶者の母親。in-law系は義理の親族","level":7,"lnum":1,"ex":"His mother-in-law visited them every summer and stayed for two weeks.","exja":"彼の義理の母は毎夏2週間彼らのところを訪れた。"},{"id":5682,"en":"motion","ja":"動き/動議\n物の動き、または会議での提案・動議","level":7,"lnum":1,"ex":"The coach made a motion with his hand to signal the players to slow down.","exja":"コーチは選手たちにペースを落とすよう合図するため、手で動作をした。"},{"id":5683,"en":"motivated","ja":"意欲的な\n目標に向けてやる気が高まった状態","level":7,"lnum":1,"ex":"The students were highly motivated after their teacher praised their hard work.","exja":"教師が彼らの努力を称えた後、生徒たちは非常に意欲的になった。"},{"id":5684,"en":"motorbike","ja":"バイク\n小型オートバイ。motorcycleより口語的（英）","level":7,"lnum":1,"ex":"He rode his motorbike through the countryside to enjoy the fresh air.","exja":"彼はフレッシュな空気を楽しむために、バイクで田舎道を走った。"},{"id":5685,"en":"motorist","ja":"ドライバー\n自動車を運転する人。driverより書き言葉的","level":7,"lnum":1,"ex":"The motorist was fined for driving above the speed limit in a residential area.","exja":"そのドライバーは住宅地でスピード超過をしたとして罰金を科された。"},{"id":5686,"en":"mount","ja":"登る/取り付ける\n山を登る・台に固定する両方に使う","level":7,"lnum":1,"ex":"The expedition team began to mount the steep slope at sunrise.","exja":"探検隊は日の出とともに急な斜面を登り始めた。"},{"id":5687,"en":"mournful","ja":"悲しそうな\n深い悲しみや哀愁を表す雰囲気・様子","level":7,"lnum":1,"ex":"A mournful melody played at the funeral as friends gathered to say goodbye.","exja":"友人たちが別れを告げるために集まった葬儀で、悲しそうなメロディーが流れた。"},{"id":5688,"en":"mover","ja":"引越し業者/推進者\n家具を運ぶ人、または物事を動かす推進者","level":7,"lnum":1,"ex":"The company hired professional movers to transport all the office furniture.","exja":"会社はオフィスの家具をすべて運ぶためにプロの引越し業者を雇った。"},{"id":5689,"en":"moving","ja":"感動的な\n心を動かす・感情を揺さぶる。touchingに近い","level":7,"lnum":1,"ex":"The documentary about the refugees was deeply moving and brought many viewers to tears.","exja":"難民に関するドキュメンタリーは非常に感動的で、多くの視聴者を涙させた。"},{"id":5690,"en":"muddy","ja":"泥だらけの\n泥で汚れた・水で濁った状態","level":7,"lnum":1,"ex":"After playing outside, the children came home with muddy shoes and dirty hands.","exja":"外で遊んだ後、子供たちは泥だらけの靴と汚れた手で帰ってきた。"},{"id":5691,"en":"multiple","ja":"複数の\nたくさんの・いくつもの。manyより数え方が明確","level":7,"lnum":1,"ex":"The scientist conducted multiple experiments to verify the results.","exja":"科学者は結果を確認するために複数の実験を行った。"},{"id":5692,"en":"multiply","ja":"増殖する\n数を増やす・掛け算する。急激な増加に使う","level":7,"lnum":1,"ex":"Bacteria can multiply rapidly in warm and moist environments.","exja":"細菌は温かく湿った環境で急速に増殖する可能性がある。"},{"id":5693,"en":"mumble","ja":"もごもご言うこと\n口を大きく開けずに不明瞭に話す（名詞）","level":7,"lnum":1,"ex":"She could hear him mumble something under his breath but couldn't catch the words.","exja":"彼が何かを口の中でつぶやいているのが聞こえたが、言葉は聞き取れなかった。"},{"id":5694,"en":"mumble","ja":"もごもご言う\n口を大きく開けずに不明瞭に話す（動詞）","level":7,"lnum":1,"ex":"He mumbled something under his breath that nobody could understand.","exja":"彼は誰にも聞き取れないことをもごもごとつぶやいた。"},{"id":5695,"en":"murmur","ja":"つぶやき\n小さく低い声でゴソゴソ言う音・声（名詞）","level":7,"lnum":1,"ex":"She spoke in a soft murmur so as not to wake the sleeping baby.","exja":"眠っている赤ちゃんを起こさないよう、彼女は静かなつぶやき声で話した。"},{"id":5696,"en":"muse","ja":"熟考する\n静かにじっくり考える・思いにふける","level":7,"lnum":1,"ex":"He sat by the window and mused over the conversation he had with her the night before.","exja":"彼は窓際に座り、前夜に彼女と交わした会話についてじっくりと熟考した。"},{"id":5697,"en":"mustache/moustache","ja":"口ひげ\n鼻の下に生やすひげ","level":7,"lnum":1,"ex":"He grew a mustache over the summer and looked quite different.","exja":"彼は夏の間に口ひげを生やし、かなり見た目が変わった。"},{"id":5698,"en":"mutability","ja":"可変性\n変化しやすい性質・変わりうること","level":7,"lnum":1,"ex":"The mutability of fashion trends makes it hard to keep up with what's in style.","exja":"ファッションのトレンドが変わりやすいため、流行についていくのが難しい。"},{"id":5699,"en":"mutable","ja":"変わりやすい\n変更・変化が可能な性質","level":7,"lnum":1,"ex":"Computer software is mutable; it can be updated and changed over time.","exja":"コンピュータソフトウェアは変更可能で、時間とともに更新・変更できる。"},{"id":5700,"en":"mutter","ja":"ぶつぶつつぶやき\n不満を口の中で小さく言う音（名詞）","level":7,"lnum":1,"ex":"She heard a mutter of disapproval from the back of the audience.","exja":"彼女は観客の後ろの方から不満のぶつぶつ声が聞こえた。"},{"id":5701,"en":"mutter","ja":"ぶつぶつ言う\n不満を口の中で小さく言う（動詞）","level":7,"lnum":1,"ex":"She muttered a complaint under her breath but didn't say anything aloud.","exja":"彼女はぶつぶつと不満をつぶやいたが、声に出しては何も言わなかった。"},{"id":5702,"en":"mutton","ja":"羊肉\n成羊の肉。lambより年取った羊から","level":7,"lnum":1,"ex":"The traditional dish was made with slow-cooked mutton and root vegetables.","exja":"その伝統料理はゆっくりと煮込んだ羊肉と根菜で作られていた。"},{"id":5703,"en":"mystify","ja":"当惑させる\n不思議で理解できず困惑させる","level":7,"lnum":1,"ex":"The magician's trick completely mystified the audience.","exja":"そのマジシャンのトリックは観客を完全に当惑させた。"},{"id":5704,"en":"nano","ja":"ナノ\n十億分の一を表す接頭語。nanotechnology など","level":7,"lnum":1,"ex":"Nano technology is being used to develop more efficient drug delivery systems.","exja":"ナノテクノロジーはより効率的なドラッグデリバリーシステムの開発に使われている。"},{"id":5705,"en":"narcissistic","ja":"自己陶酔的な\n自分への強い執着・優越感を持つ性格","level":7,"lnum":1,"ex":"His narcissistic behavior made it difficult for him to maintain long friendships.","exja":"彼の自己陶酔的な行動は、長い友情を維持することを難しくした。"},{"id":5706,"en":"narrator","ja":"語り手\n物語を語る人・小説の一人称話者","level":7,"lnum":1,"ex":"The story is told from the perspective of an unreliable narrator.","exja":"その物語は信頼できない語り手の視点から語られる。"},{"id":5707,"en":"narrowly","ja":"かろうじて\nわずかな差で・ぎりぎりで","level":7,"lnum":1,"ex":"The cyclist narrowly avoided a collision with a car at the intersection.","exja":"自転車の選手は交差点で車との衝突をかろうじて回避した。"},{"id":5708,"en":"nationwide","ja":"全国的な\n国全体に広がる・関わる範囲（形容詞）","level":7,"lnum":1,"ex":"The new regulation applies nationwide, regardless of individual state laws.","exja":"新しい規制は個々の州法に関係なく、全国的に適用される。"},{"id":5709,"en":"nationwide","ja":"全国的に\n国全体にわたる規模で（副詞）","level":7,"lnum":1,"ex":"The new law will be enforced nationwide starting from next month.","exja":"新しい法律は来月から全国的に施行される。"},{"id":5710,"en":"native speaker","ja":"ネイティブスピーカー\nその言語を母語として育った話者","level":7,"lnum":1,"ex":"She improved her language skills significantly by practicing with a native speaker.","exja":"彼女はネイティブスピーカーと練習することで、語学力を大幅に向上させた。"},{"id":5711,"en":"naughty","ja":"いたずらな\n子供が行儀悪い・少し悪ふざけな様子","level":7,"lnum":1,"ex":"The naughty puppy chewed up all the shoes left near the door.","exja":"いたずらな子犬はドア付近に残されていた靴をすべて噛んでしまった。"},{"id":5712,"en":"naval","ja":"海軍の\n国の海上軍事に関わる。navy と同語源","level":7,"lnum":1,"ex":"The naval base was built on a strategic peninsula overlooking the harbor.","exja":"海軍基地は港を見渡す戦略的な半島に建設された。"},{"id":5713,"en":"navigate","ja":"航行する\n道を見つけて進む・操作して進む","level":7,"lnum":1,"ex":"She used her phone to navigate through the unfamiliar streets of the city.","exja":"彼女は慣れない町の道を進むためにスマートフォンを使ってナビゲートした。"},{"id":5714,"en":"navigation","ja":"航法/ナビ\n目的地への経路探索・誘導の技術","level":7,"lnum":1,"ex":"Accurate navigation is critical for ships traveling through narrow and rocky channels.","exja":"狭く岩だらけの水路を航行する船にとって、正確なナビは不可欠だ。"},{"id":5715,"en":"navy","ja":"海軍\n国の海上軍事組織","level":7,"lnum":1,"ex":"The navy was deployed to patrol the coastal waters during the crisis.","exja":"危機の際、海軍は沿岸海域のパトロールに派遣された。"},{"id":5716,"en":"neat","ja":"きちんとした\n整理されて清潔感がある。tidyに近い","level":7,"lnum":1,"ex":"She kept her desk neat and organized even during the busiest times.","exja":"彼女は最も忙しい時でも机をきちんと整理された状態に保った。"},{"id":5717,"en":"necessarily","ja":"必ずしも\n「not necessarily」で「必ずしも〜ではない」の形","level":7,"lnum":1,"ex":"A high salary does not necessarily lead to greater happiness.","exja":"高い給料が必ずしもより大きな幸福につながるわけではない。"},{"id":5718,"en":"necessity","ja":"必需品/必要性\nなくてはならないもの・状況","level":7,"lnum":1,"ex":"Clean water is a basic necessity of life that everyone deserves access to.","exja":"清潔な水は誰もがアクセスできるべき生活の基本的な必需品だ。"},{"id":5719,"en":"needless","ja":"不必要な\n必要でない・余計な。unnecessaryに近い","level":7,"lnum":1,"ex":"All the confusion was caused by needless miscommunication between the departments.","exja":"すべての混乱は部門間の不必要なコミュニケーション不足によって引き起こされた。"},{"id":5720,"en":"needy","ja":"貧しい/依存的な\n経済的に困っている、または感情的に依存しすぎ","level":7,"lnum":1,"ex":"The charity organization provides food and shelter to needy families in the region.","exja":"その慈善団体は地域の貧しい家族に食料と住居を提供している。"},{"id":5721,"en":"negatively","ja":"否定的に\n悪い・反対の方向で物事を見る様子","level":7,"lnum":1,"ex":"Stress can negatively affect your ability to concentrate and make good decisions.","exja":"ストレスは集中力や適切な判断を下す能力に悪影響を与える可能性がある。"},{"id":5722,"en":"neglect","ja":"無視/放置\n注意や世話が必要な対象を怠る行為","level":7,"lnum":1,"ex":"Neglecting regular exercise can lead to serious health problems over time.","exja":"定期的な運動を怠ることは、時間の経過とともに深刻な健康問題につながる可能性がある。"},{"id":5723,"en":"neighboring/neighbouring","ja":"隣接する\nすぐ隣にある・隣接した地域・国の","level":7,"lnum":1,"ex":"The neighboring countries have agreed to reduce border taxes together.","exja":"隣接する国々は共同で国境税を引き下げることに合意した。"},{"id":5724,"en":"nerve","ja":"神経/度胸\n体の神経組織、または大胆な行動力","level":7,"lnum":1,"ex":"It took a lot of nerve to stand up and speak in front of thousands of people.","exja":"何千人もの前に立って話すには、多くの度胸が必要だった。"},{"id":5725,"en":"nerves","ja":"緊張/神経\n不安や緊張状態（複数形で使う）","level":7,"lnum":1,"ex":"She suffered from nerves before every major performance on stage.","exja":"彼女は舞台での主要な公演の前に毎回緊張した。"},{"id":5726,"en":"nervously","ja":"緊張して\n不安や心配から落ち着かない様子","level":7,"lnum":1,"ex":"He smiled nervously as the interviewer asked him the most difficult question.","exja":"面接官が最も難しい質問をすると、彼は緊張して微笑んだ。"},{"id":5727,"en":"netsurfer/net surfer","ja":"ネットサーファー\nインターネットを閲覧・探索する人","level":7,"lnum":1,"ex":"The netsurfer spent hours exploring websites for information on the topic.","exja":"そのネットサーファーは話題に関する情報を求めて何時間もウェブサイトを探し回った。"},{"id":5728,"en":"neurosis","ja":"神経症\n不安・強迫観念などの精神的な障害","level":7,"lnum":1,"ex":"His neurosis about cleanliness made daily life challenging for both him and his family.","exja":"清潔さに対する神経症が、彼自身と家族の日常生活を困難にした。"},{"id":5729,"en":"newscaster","ja":"ニュースキャスター\nテレビ・ラジオでニュースを読む人","level":7,"lnum":1,"ex":"The newscaster reported the breaking story live from outside the parliament building.","exja":"ニュースキャスターは議会議事堂の外から緊急ニュースをライブで報道した。"},{"id":5730,"en":"newsworthy","ja":"ニュース価値のある\n報道する価値があるほど重要・興味深い","level":7,"lnum":1,"ex":"The scientist's discovery was considered highly newsworthy by the media.","exja":"その科学者の発見は、メディアからニュース価値が非常に高いと見なされた。"},{"id":5731,"en":"nicely","ja":"上手に/感じよく\nうまく・きれいに・礼儀正しく","level":7,"lnum":1,"ex":"She asked him nicely to turn down the music, and he agreed immediately.","exja":"彼女が感じよく音楽を小さくするよう頼むと、彼はすぐに了承した。"},{"id":5732,"en":"nightclub","ja":"ナイトクラブ\n夜に音楽・ダンスを楽しむ娯楽施設","level":7,"lnum":1,"ex":"They went to a nightclub to celebrate her birthday late into the night.","exja":"彼女の誕生日を祝うため、彼らは夜遅くまでナイトクラブへ行った。"},{"id":5733,"en":"nightmare","ja":"悪夢\n恐ろしい夢・または非常につらい体験","level":7,"lnum":1,"ex":"The traffic jam turned the two-hour drive into an absolute nightmare.","exja":"渋滞のせいで2時間のドライブが完全な悪夢に変わった。"},{"id":5734,"en":"nobility","ja":"貴族/高潔さ\n貴族階級、または品格ある高い精神性","level":7,"lnum":1,"ex":"The museum displayed paintings of members of the European nobility from the 18th century.","exja":"その博物館は18世紀のヨーロッパ貴族の肖像画を展示していた。"},{"id":5735,"en":"noble","ja":"高貴な\n道徳的に優れた・または貴族出身の","level":7,"lnum":1,"ex":"It was a noble gesture to donate all the prize money to charity.","exja":"賞金のすべてを慈善事業に寄付したことは、高潔な行いだった。"},{"id":5736,"en":"nobleman","ja":"貴族\n高い身分・爵位を持つ男性","level":7,"lnum":1,"ex":"The nobleman owned vast estates in the countryside and lived in great comfort.","exja":"その貴族は田舎に広大な土地を所有し、非常に快適に暮らしていた。"},{"id":5737,"en":"nomad","ja":"遊牧民\n定住せず移動しながら生活する人","level":7,"lnum":1,"ex":"He lived as a nomad for three years, traveling from country to country.","exja":"彼は3年間、国から国へと旅をしながら遊牧民のような生活を送った。"},{"id":5738,"en":"nomination","ja":"指名/ノミネート\n候補として推薦される・されること","level":7,"lnum":1,"ex":"Her nomination for the award came as a great surprise to everyone in the office.","exja":"彼女が賞にノミネートされたことは、社内の全員にとって大きな驚きだった。"},{"id":5739,"en":"nominee","ja":"被指名者\n候補に指名された人。nomin…","level":7,"lnum":1,"ex":"The award ceremony was attended by all five nominees for the best film category.","exja":"授賞式には最優秀映画部門にノミネートされた5人全員が出席した。"},{"id":5740,"en":"nonprofessional","ja":"非専門家の\n職業的な訓練を受けていない素人の","level":7,"lnum":1,"ex":"The play was performed by nonprofessional actors but received excellent reviews.","exja":"その劇は非専門家の俳優によって演じられたが、高い評価を受けた。"},{"id":5741,"en":"non-smoking","ja":"禁煙の\n喫煙を禁止した場所・環境","level":7,"lnum":1,"ex":"We requested a non-smoking room when we made our hotel reservation.","exja":"ホテルを予約した際に禁煙の部屋をリクエストした。"},{"id":5742,"en":"northward/northwards","ja":"北に向かって\n北の方向へ進む様子を示す副詞","level":7,"lnum":1,"ex":"The explorers traveled northward for several days in search of the source.","exja":"探検家たちは源を求めて数日間北に向かって旅した。"},{"id":5743,"en":"nostril","ja":"鼻孔\n鼻の穴。左右で two nostrils","level":7,"lnum":1,"ex":"The doctor examined the inside of each nostril with a small light.","exja":"医師は小さなライトで鼻孔の内部をそれぞれ診察した。"},{"id":5744,"en":"nought","ja":"ゼロ\n英式英語でのゼロ・無の意味","level":7,"lnum":1,"ex":"The final score was five to nought in favor of the home team.","exja":"最終スコアは地元チームが5対ゼロで勝利した。"},{"id":5745,"en":"nourish","ja":"養う\n食物や愛情で成長を支える","level":7,"lnum":1,"ex":"A balanced diet provides the nutrients needed to nourish the body and mind.","exja":"バランスの取れた食事は、体と心を養うのに必要な栄養素を提供する。"},{"id":5746,"en":"nourishment","ja":"栄養/滋養\n体や心を育てるために必要なもの","level":7,"lnum":1,"ex":"Babies need proper nourishment to support healthy growth and development.","exja":"赤ちゃんは健全な成長と発達を支えるために適切な栄養が必要だ。"},{"id":5747,"en":"novelty","ja":"目新しさ\n新鮮で珍しいことの面白さ・珍品","level":7,"lnum":1,"ex":"The novelty of the new device wore off quickly as more advanced products appeared.","exja":"より高度な製品が登場すると、その新しい端末の目新しさはすぐに薄れた。"},{"id":5748,"en":"nuisance","ja":"迷惑なもの\n困らせる人・状況・物。annoyanceより具体的","level":7,"lnum":1,"ex":"The noise from the construction site was a constant nuisance to the residents.","exja":"建設現場からの騒音は住民にとって絶え間ない迷惑だった。"},{"id":5749,"en":"numerical","ja":"数値の\n数字・数量に関わる。numbersに近い","level":7,"lnum":1,"ex":"The report included a numerical analysis of sales data from the past five years.","exja":"報告書には過去5年間の売上データの数値分析が含まれていた。"},{"id":5750,"en":"nutshell","ja":"要点/木の実の殻\nin a nutshell で「要するに」の意味","level":7,"lnum":1,"ex":"In a nutshell, the project failed because of poor planning and communication.","exja":"要するに、そのプロジェクトは計画とコミュニケーションの不備が原因で失敗した。"},{"id":5751,"en":"oath","ja":"誓い\n公式な場での厳粛な約束・宣誓","level":7,"lnum":1,"ex":"The new president took the oath of office in front of thousands of citizens.","exja":"新大統領は何千人もの市民の前で就任の宣誓を行った。"},{"id":5752,"en":"obedience","ja":"従順さ\n命令・規則に素直に従うこと","level":7,"lnum":1,"ex":"Obedience to traffic laws helps prevent accidents and keeps everyone safe.","exja":"交通法規に従うことは事故を防ぎ、全員の安全を保つのに役立つ。"},{"id":5753,"en":"obedient","ja":"従順な\n言われたことに従う。compliantより子供・動物向け","level":7,"lnum":1,"ex":"The dog was very obedient and followed every command its owner gave.","exja":"その犬は非常に従順で、飼い主のあらゆる命令に従った。"},{"id":5754,"en":"obituary","ja":"死亡記事\n亡くなった人の業績を記した新聞記事","level":7,"lnum":1,"ex":"The newspaper published a moving obituary for the well-loved local teacher.","exja":"新聞は地域で愛されていた教師への感動的な死亡記事を掲載した。"},{"id":5755,"en":"objective","ja":"客観的な\n個人の感情に左右されない中立的な見方","level":7,"lnum":1,"ex":"A good journalist should remain objective and report the facts without personal bias.","exja":"優れたジャーナリストは客観的であり続け、個人的な偏見なく事実を報道するべきだ。"},{"id":5756,"en":"obligation","ja":"義務\nしなければならない責任・法的または道徳的","level":7,"lnum":1,"ex":"As a citizen, you have an obligation to follow the laws of the country.","exja":"市民として、あなたにはその国の法律に従う義務がある。"},{"id":5757,"en":"observer","ja":"観察者\n観察・監視する人。witnessより中立的","level":7,"lnum":1,"ex":"International observers were sent to monitor the fairness of the election.","exja":"選挙の公正さを監視するために国際的な観察者が派遣された。"},{"id":5758,"en":"obsess","ja":"執着する\n一つのことが頭から離れない状態になる","level":7,"lnum":1,"ex":"He became obsessed with perfecting his technique and practiced for hours every day.","exja":"彼は自分の技術を完璧にすることに執着し、毎日何時間も練習した。"},{"id":5759,"en":"obsession","ja":"強迫観念\nあることへの過度な執着・思い込み","level":7,"lnum":1,"ex":"Her obsession with organizing everything made her an extremely efficient worker.","exja":"すべてを整理することへの彼女の強迫観念は、彼女を非常に効率的な労働者にした。"},{"id":5760,"en":"obsessive","ja":"執着的な\n一つのことに異常なほど集中・こだわる性質","level":7,"lnum":1,"ex":"His obsessive attention to detail helped him produce flawless work consistently.","exja":"細部への彼の執着的な注意が、一貫して完璧な仕事を生み出す助けとなった。"},{"id":5761,"en":"odd","ja":"奇妙な\n通常と違って変な。strangeより軽いニュアンス","level":7,"lnum":1,"ex":"It was odd that no one showed up to the meeting despite the clear invitation.","exja":"明確な招待状にもかかわらず、誰も会議に来なかったのは奇妙だった。"},{"id":5762,"en":"offend","ja":"気分を害する\n言動で人を傷つける・不快にさせる","level":7,"lnum":1,"ex":"His careless comment offended several people in the audience.","exja":"彼の不注意な発言は聴衆の何人かの気分を害した。"},{"id":5763,"en":"offender","ja":"違反者/加害者\n法律・規則を破った人","level":7,"lnum":1,"ex":"First-time offenders are often given a lighter sentence as a second chance.","exja":"初犯者はセカンドチャンスとして、しばしば軽い判決が下される。"},{"id":5764,"en":"offense/offence","ja":"違反/不快感\n法律違反、または誰かを不快にさせること","level":7,"lnum":1,"ex":"He committed a serious offense by driving while intoxicated.","exja":"彼は飲酒運転という重大な違反を犯した。"},{"id":5765,"en":"offhand","ja":"気軽に\n事前に考えず即座に答える様子","level":7,"lnum":1,"ex":"She didn't know the answer offhand but promised to look it up later.","exja":"彼女はすぐに答えを知らなかったが、後で調べると約束した。"},{"id":5766,"en":"offshore","ja":"沖合いの\n海岸から離れた沖合い・海外の（脱税に使うことも）","level":7,"lnum":1,"ex":"The company set up an offshore account to manage its international funds.","exja":"その会社は国際資金を管理するために海外口座を開設した。"},{"id":5767,"en":"ointment","ja":"軟膏\n皮膚に塗る油性の薬。creamより厚みがある","level":7,"lnum":1,"ex":"The doctor prescribed an ointment to reduce the inflammation on her skin.","exja":"医師は皮膚の炎症を抑えるための軟膏を処方した。"},{"id":5768,"en":"olive","ja":"オリーブ\n地中海原産の実・樹木。olive oilの原料","level":7,"lnum":1,"ex":"The salad was topped with black olives, fresh tomatoes, and feta cheese.","exja":"サラダには黒オリーブ、新鮮なトマト、フェタチーズが乗せられていた。"},{"id":5769,"en":"Olympia","ja":"オリンピア\n古代オリンピックの開催地（ギリシャの地名）","level":7,"lnum":1,"ex":"Ancient athletes traveled to Olympia from all over Greece to compete in the games.","exja":"古代のアスリートたちは競技に参加するためにギリシャ全土からオリンピアへ旅した。"},{"id":5770,"en":"Olympiad","ja":"オリンピアード\n4年ごとのオリンピック開催サイクル","level":7,"lnum":1,"ex":"The city is already preparing to host the next Olympiad four years from now.","exja":"その都市はすでに4年後の次のオリンピアードを開催する準備をしている。"},{"id":5771,"en":"openly","ja":"公然と\n隠さず誰でも見える形で。franklyより行動的","level":7,"lnum":1,"ex":"She openly admitted her mistake and apologized to the entire team.","exja":"彼女は公然と自分のミスを認め、チーム全員に謝罪した。"},{"id":5772,"en":"operator","ja":"オペレーター/操作者\n機械・電話などを操作する人","level":7,"lnum":1,"ex":"The machine operator checked every component before starting the production line.","exja":"機械のオペレーターは生産ラインを起動する前にすべてのコンポーネントを確認した。"},{"id":5773,"en":"opponent","ja":"対戦相手/反対者\n競技や議論で反対側に立つ人","level":7,"lnum":1,"ex":"The chess player studied his opponent's previous games before the tournament.","exja":"チェスプレイヤーはトーナメントの前に対戦相手の過去の試合を研究した。"},{"id":5774,"en":"optimism","ja":"楽観主義\n物事が良くなると信じる前向きな考え方","level":7,"lnum":1,"ex":"Her optimism in the face of difficulty inspired everyone around her.","exja":"困難に直面しても彼女の楽観主義は周囲の全員を鼓舞した。"},{"id":5775,"en":"optimist","ja":"楽観主義者\nいつも明るい見通しを持つ人","level":7,"lnum":1,"ex":"He is a natural optimist who always sees the bright side of every situation.","exja":"彼は生まれつきの楽観主義者で、どんな状況でも明るい側面を見出す。"},{"id":5776,"en":"optimistic","ja":"楽観的な\n良い結果を期待する前向きな姿勢","level":7,"lnum":1,"ex":"Despite the challenges ahead, the team remained optimistic about reaching their goal.","exja":"前途に課題があるにもかかわらず、チームは目標達成について楽観的であり続けた。"},{"id":5777,"en":"optional","ja":"任意の\n必須でなく選べる。compulsoryの反対","level":7,"lnum":1,"ex":"Attending the extra workshop is optional, but most students find it very helpful.","exja":"追加ワークショップへの参加は任意だが、ほとんどの生徒は非常に役立つと感じている。"},{"id":5778,"en":"oral","ja":"口頭の/口の\n話し言葉による、または口に関わる","level":7,"lnum":1,"ex":"The student gave an oral presentation in front of the entire class.","exja":"生徒はクラス全員の前で口頭発表を行った。"},{"id":5779,"en":"orator","ja":"演説家\n人前で雄弁に話す人。speakerより技術が高い","level":7,"lnum":1,"ex":"The famous orator captivated the crowd with his powerful and passionate speech.","exja":"有名な演説家は力強く情熱的なスピーチで聴衆を魅了した。"},{"id":5780,"en":"orchestral","ja":"管弦楽の\nオーケストラに関わる・弦楽合奏の","level":7,"lnum":1,"ex":"The concert featured a mix of orchestral pieces and solo piano performances.","exja":"コンサートでは管弦楽曲とピアノのソロ演奏が組み合わさってフィーチャーされた。"},{"id":5781,"en":"orchid","ja":"ラン\n熱帯・亜熱帯に多い美しい花の総称","level":7,"lnum":1,"ex":"She received a beautiful white orchid as a gift on her graduation day.","exja":"彼女は卒業式の日に美しい白いランをプレゼントとして受け取った。"},{"id":5782,"en":"organizer/organiser","ja":"主催者/整理道具\nイベントを計画する人、または整理用グッズ","level":7,"lnum":1,"ex":"The event organizer coordinated everything from the venue to the catering.","exja":"イベントの主催者は会場からケータリングまでをすべてまとめた。"},{"id":5783,"en":"originality","ja":"独創性\n他にはない新しいアイデアや表現を生む力","level":7,"lnum":1,"ex":"The young designer's originality set her work apart from all the other candidates.","exja":"若いデザイナーの独創性は、他のすべての候補者と彼女の作品を際立たせた。"},{"id":5784,"en":"originate","ja":"生まれる/始まる\nどこかを起源として始まる","level":7,"lnum":1,"ex":"Jazz music originated in New Orleans in the early twentieth century.","exja":"ジャズ音楽は20世紀初頭にニューオーリンズで生まれた。"},{"id":5785,"en":"ornament","ja":"装飾品\n飾りとして置く・使う美的な品物","level":7,"lnum":1,"ex":"The family hung colorful ornaments on the Christmas tree every December.","exja":"その家族は毎年12月に色鮮やかな装飾品をクリスマスツリーに飾り付けた。"},{"id":5786,"en":"ounce","ja":"オンス\n重量の単位（約28g）。oz と略す","level":7,"lnum":1,"ex":"The recipe calls for exactly four ounces of cream cheese.","exja":"そのレシピにはクリームチーズが正確に4オンス必要だ。"},{"id":5787,"en":"outback","ja":"奥地\nオーストラリアの人里離れた内陸地域","level":7,"lnum":1,"ex":"They rented a camper van to explore the vast Australian outback.","exja":"彼らはキャンパーバンを借りてオーストラリアの広大な奥地を探検した。"},{"id":5788,"en":"outbreak","ja":"勃発/感染拡大\n戦争・疾病・暴動などの突然の発生","level":7,"lnum":1,"ex":"Health authorities acted quickly to contain the outbreak of the virus.","exja":"保健当局はウイルスの感染拡大を封じ込めるために迅速に行動した。"},{"id":5789,"en":"outcome","ja":"結果\nある出来事・行動の最終的な成果","level":7,"lnum":1,"ex":"The final outcome of the negotiations was better than anyone had expected.","exja":"交渉の最終的な結果は、誰もが期待していた以上に良かった。"},{"id":5790,"en":"outdistance","ja":"引き離す\n競争相手を大幅に追い越す","level":7,"lnum":1,"ex":"The young runner outdistanced all her competitors and won by a wide margin.","exja":"その若いランナーはすべての競争相手を大幅に引き離し、大差で勝利した。"},{"id":5791,"en":"outdo","ja":"上回る\n他者の業績・能力を超える","level":7,"lnum":1,"ex":"She worked harder than ever, determined to outdo her previous performance.","exja":"彼女はこれまで以上に努力し、以前の成績を上回ることを心に決めた。"},{"id":5792,"en":"outfit","ja":"服装/一式\n特定の場面に合わせた衣服のセット","level":7,"lnum":1,"ex":"She chose a formal outfit for the job interview to make a good impression.","exja":"彼女は就職面接に良い印象を与えるためにフォーマルな服装を選んだ。"},{"id":5793,"en":"outgrow","ja":"成長して合わなくなる\n大きくなりすぎて合わなくなる・卒業する","level":7,"lnum":1,"ex":"Children outgrow their shoes so quickly that buying expensive ones seems wasteful.","exja":"子供たちは靴をすぐに履けなくなるので、高価なものを買うのは無駄に思える。"},{"id":5794,"en":"outing","ja":"外出/遠足\nレクリエーション目的の短い外出","level":7,"lnum":1,"ex":"The school organized a day outing to the science museum for all grade students.","exja":"学校は全学年の生徒のために科学博物館への日帰り遠足を企画した。"},{"id":5795,"en":"outlet","ja":"はけ口/コンセント\n感情・エネルギーを発散する手段・電気差込口","level":7,"lnum":1,"ex":"Exercise is a healthy outlet for stress and pent-up emotions.","exja":"運動はストレスや溜まった感情のための健康的なはけ口だ。"},{"id":5796,"en":"outline","ja":"概要/輪郭\n内容の骨格・主要ポイントのまとめ","level":7,"lnum":1,"ex":"Before writing the essay, she created a detailed outline to organize her thoughts.","exja":"エッセイを書く前に、彼女は考えを整理するために詳細な概要を作成した。"},{"id":5797,"en":"outlive","ja":"長生きする\n他の人や物より長く生き続ける","level":7,"lnum":1,"ex":"She outlived all of her siblings and celebrated her hundredth birthday alone.","exja":"彼女はきょうだい全員より長生きし、100歳の誕生日を一人で迎えた。"},{"id":5798,"en":"outlook","ja":"見通し/視点\n将来の見方、または物の見方・価値観","level":7,"lnum":1,"ex":"The economic outlook for the next quarter appears promising, according to analysts.","exja":"アナリストによると、来四半期の経済見通しは有望に見える。"},{"id":5799,"en":"outpatient","ja":"外来患者\n入院せず通院で治療を受ける患者","level":7,"lnum":1,"ex":"He was treated as an outpatient and did not need to stay in the hospital overnight.","exja":"彼は外来患者として治療を受け、病院に一晩泊まる必要はなかった。"},{"id":5800,"en":"output","ja":"産出量/出力\n生産された量・データ処理の結果","level":7,"lnum":1,"ex":"The factory's daily output increased significantly after the new machines were installed.","exja":"新しい機械が設置された後、工場の1日の産出量は大幅に増加した。"},{"id":5801,"en":"outrage","ja":"激しい怒り\n道徳的に許せない行為への強い憤り","level":7,"lnum":1,"ex":"The unfair verdict caused widespread outrage among the public.","exja":"不公平な判決は国民の間に広範な激しい怒りを引き起こした。"},{"id":5802,"en":"outrageous","ja":"非常識な\n常識を大きく外れた許しがたい行為","level":7,"lnum":1,"ex":"The prices at the airport restaurant were absolutely outrageous.","exja":"空港のレストランの値段はまったく非常識だった。"},{"id":5803,"en":"outshine","ja":"輝かせる\n他より目立って優れている・引き立てる","level":7,"lnum":1,"ex":"Her creative presentation outshone all the other entries in the competition.","exja":"彼女の創造的なプレゼンテーションはコンテストの他のすべてのエントリーを輝かせた。"},{"id":5804,"en":"outsider","ja":"部外者\nグループや社会に属していない人","level":7,"lnum":1,"ex":"As a newcomer to the group, she often felt like an outsider at first.","exja":"グループの新入りとして、彼女は最初よく部外者のように感じた。"},{"id":5805,"en":"outskirts","ja":"郊外/周辺\n都市の中心部から外れた周辺地域","level":7,"lnum":1,"ex":"They moved to a quiet house on the outskirts of the city to escape the noise.","exja":"彼らは騒音を避けるため、街の郊外にある静かな家に引っ越した。"},{"id":5806,"en":"outwardly","ja":"外見上は\n外から見える様子で・表面上は","level":7,"lnum":1,"ex":"He appeared outwardly calm during the crisis, though he was deeply worried inside.","exja":"彼は内心深く心配していたが、危機の間も外見上は穏やかに見えた。"},{"id":5807,"en":"oval","ja":"楕円形の\n卵型・長丸形の形","level":7,"lnum":1,"ex":"The dining table had an oval shape that fit perfectly in the narrow room.","exja":"ダイニングテーブルは楕円形で、狭い部屋にぴったりと収まった。"},{"id":5808,"en":"overall","ja":"全体的な\nすべてを含めた総合的な見方（形容詞）","level":7,"lnum":1,"ex":"The overall cost of the renovation was higher than the original estimate.","exja":"改装の全体的な費用は当初の見積もりより高かった。"},{"id":5809,"en":"overall","ja":"全体的に\nすべてを合わせて考えたとき（副詞）","level":7,"lnum":1,"ex":"Overall, the project was a great success despite some minor setbacks.","exja":"全体的に、いくつかの小さな失敗はあったものの、プロジェクトは大成功だった。"},{"id":5810,"en":"overboard","ja":"過度に\n必要以上に・度が過ぎる（go overboardなど）","level":7,"lnum":1,"ex":"She went a bit overboard decorating the house for the party.","exja":"彼女はパーティーのために家を飾るのに少し度が過ぎた。"},{"id":5811,"en":"overbook","ja":"超過予約する\n収容量を超えて予約を取りすぎる","level":7,"lnum":1,"ex":"The airline overbooked the flight and had to offer compensation to passengers.","exja":"航空会社はフライトを超過予約し、乗客に補償を提供しなければならなかった。"},{"id":5812,"en":"overcoat","ja":"オーバーコート\n外出用の長くて厚いコート","level":7,"lnum":1,"ex":"He put on his thick overcoat before stepping out into the freezing winter air.","exja":"凍るような冬の外に出る前に、彼は分厚いオーバーコートを着込んだ。"},{"id":5813,"en":"overemphasize/overemphasise","ja":"強調しすぎる\n必要以上に重要性を強調する","level":7,"lnum":1,"ex":"We should not overemphasize the role of technology in solving social problems.","exja":"社会問題の解決における技術の役割を強調しすぎるべきではない。"},{"id":5814,"en":"overestimate","ja":"過大評価する\n実際より高く評価する。underestimateの反対","level":7,"lnum":1,"ex":"Don't overestimate how much you can accomplish in a single day.","exja":"1日でどれだけ達成できるかを過大評価しないようにしよう。"},{"id":5815,"en":"overhear","ja":"偶然聞く\n意図せず他人の会話を聞いてしまう","level":7,"lnum":1,"ex":"She accidentally overheard her colleagues talking about the upcoming layoffs.","exja":"彼女は偶然、同僚たちが迫っているレイオフについて話しているのを聞いてしまった。"},{"id":5816,"en":"overlap","ja":"重なり\n二つのものが部分的に重なる部分・状態","level":7,"lnum":1,"ex":"The two departments' responsibilities often overlap, which can cause confusion.","exja":"2つの部門の業務がしばしば重なり、混乱を招くことがある。"},{"id":5817,"en":"overlook","ja":"見落とす\nうっかり気づかない・または見渡す場所","level":7,"lnum":1,"ex":"He overlooked a small but critical error in the report before submitting it.","exja":"彼は報告書を提出する前に小さいが重大なミスを見落とした。"},{"id":5818,"en":"overly","ja":"過度に\n必要以上に。too とほぼ同じだがやや書き言葉的","level":7,"lnum":1,"ex":"The reviewer felt the film was overly long and could have been edited down.","exja":"評者はその映画が過度に長く、編集で短くできたと感じた。"},{"id":5819,"en":"overshadow","ja":"影を落とす\n他より目立ち、良い部分を隠してしまう","level":7,"lnum":1,"ex":"The success of the second album was completely overshadowed by the singer's personal troubles.","exja":"2枚目のアルバムの成功は、歌手の個人的なトラブルによって完全に影を落とされた。"},{"id":5820,"en":"oversize","ja":"特大の\n標準より大きすぎる","level":7,"lnum":1,"ex":"He bought an oversize shirt and wore it as a casual dress.","exja":"彼女は特大のシャツを買い、カジュアルなワンピースとして着た。"},{"id":5821,"en":"overstep","ja":"踏み越える\n許可された範囲・権限を超える","level":7,"lnum":1,"ex":"She realized she had overstepped her authority by making the decision on her own.","exja":"彼女は自分だけで決断を下すことで、権限を踏み越えていたことに気づいた。"},{"id":5822,"en":"overtake","ja":"追い越す\n速度・能力で他者を追い抜く","level":7,"lnum":1,"ex":"The runner overtook her rival in the final stretch and crossed the finish line first.","exja":"そのランナーは最後の直線で競争相手を追い越し、ゴールラインを一番に通過した。"},{"id":5823,"en":"overthrow","ja":"打倒する\n政府・権力者を力で倒す","level":7,"lnum":1,"ex":"The citizens rose up to overthrow the corrupt government that had ruled for decades.","exja":"市民は数十年間支配してきた腐敗した政府を打倒するために立ち上がった。"},{"id":5824,"en":"overtime","ja":"残業して\n規定時間を超えて（副詞）","level":7,"lnum":1,"ex":"The company offered extra pay for all overtime worked during the holiday season.","exja":"会社は休暇シーズン中のすべての残業に対して追加報酬を提供した。"},{"id":5825,"en":"overtime","ja":"残業\n規定労働時間を超えた労働・超過時間（名詞）","level":7,"lnum":1,"ex":"He worked overtime every night for a month to finish the report.","exja":"彼はレポートを仕上げるために1か月間毎晩残業した。"},{"id":5826,"en":"overturn","ja":"覆す\n決定・車・状況などをひっくり返す","level":7,"lnum":1,"ex":"The lawyer succeeded in overturning the original verdict on appeal.","exja":"弁護士は控訴審で元の判決を覆すことに成功した。"},{"id":5827,"en":"ow","ja":"痛い\n痛みを表す感嘆詞（名詞として記載）","level":7,"lnum":1,"ex":"\"Ow!\" she cried as she stubbed her toe on the corner of the table.","exja":"「痛い！」テーブルの角に足の指をぶつけると彼女は叫んだ。"},{"id":5828,"en":"owing to","ja":"〜のために\n原因・理由を示す前置詞。because ofに近い","level":7,"lnum":1,"ex":"The event was cancelled owing to the unexpected severe weather conditions.","exja":"予期しない悪天候のため、イベントは中止された。"},{"id":5829,"en":"owl","ja":"フクロウ\n夜行性の猛禽類。知恵の象徴とされる","level":7,"lnum":1,"ex":"The owl perched silently on the branch and watched the field below with sharp eyes.","exja":"フクロウは枝に静かに止まり、鋭い目で下の野原を見つめていた。"},{"id":5830,"en":"ox","ja":"雄牛\n農業用に使われる去勢した雄牛","level":7,"lnum":1,"ex":"The farmer used an ox to plow the fields before modern machinery was available.","exja":"現代の機械が普及する以前、農家は畑を耕すために雄牛を使っていた。"},{"id":5831,"en":"ozone","ja":"オゾン\n大気中の酸素の同素体。ozone layer（オゾン層）","level":7,"lnum":1,"ex":"Scientists have been monitoring the recovery of the ozone layer for decades.","exja":"科学者たちは数十年間、オゾン層の回復を監視し続けている。"},{"id":5832,"en":"pa","ja":"パパ\n父親の愛称。子供が使う親しみのある呼び方","level":7,"lnum":1,"ex":"\"Pa, can we go fishing at the lake this weekend?\" the boy asked eagerly.","exja":"「パパ、今週末に湖へ釣りに行ける？」と少年は興奮気味に尋ねた。"},{"id":5833,"en":"packed","ja":"満員の/詰まった\nぎっしり詰まった・混雑している状態","level":7,"lnum":1,"ex":"The stadium was packed with fans eager to watch the championship game.","exja":"スタジアムは選手権の試合を観戦しようとするファンで満員だった。"},{"id":5834,"en":"packet","ja":"パケット/小包\n小さな袋・包み、またはデータの送受信単位","level":7,"lnum":1,"ex":"She tore open a packet of sugar and stirred it into her coffee.","exja":"彼女は砂糖の小袋を破り、コーヒーにかき混ぜた。"},{"id":5835,"en":"pad","ja":"パッド/メモ帳\nクッションや保護材、またはメモ用紙の束","level":7,"lnum":1,"ex":"He jotted down her phone number on a small notepad by the telephone.","exja":"彼は電話の横にあった小さなメモ帳に彼女の電話番号を書き留めた。"},{"id":5836,"en":"paintbrush","ja":"絵筆\n絵を描くために使う筆","level":7,"lnum":1,"ex":"The artist carefully cleaned his paintbrush before switching to a different color.","exja":"芸術家は別の色に替える前に、丁寧に絵筆を洗った。"},{"id":5837,"en":"pallet","ja":"パレット\n荷物を積み重ねる木製の台","level":7,"lnum":1,"ex":"The warehouse workers stacked boxes of goods neatly on wooden pallets.","exja":"倉庫の作業員たちは商品の箱を木製パレットの上に整然と積み上げた。"},{"id":5838,"en":"pandemic","ja":"世界的流行の\n感染症が世界規模で広がる状態の","level":7,"lnum":1,"ex":"The government introduced strict measures to slow the spread of the pandemic.","exja":"政府はパンデミックの拡大を遅らせるために厳しい措置を導入した。"},{"id":5839,"en":"panel","ja":"パネル/委員会\n専門家グループ、または平らな板状のもの","level":7,"lnum":1,"ex":"A panel of experts was assembled to review the safety of the new drug.","exja":"新薬の安全性を審査するために専門家のパネルが招集された。"},{"id":5840,"en":"panic","ja":"パニックになる\n突然の恐怖で理性を失い混乱する","level":7,"lnum":1,"ex":"When the fire alarm went off, several people began to panic and ran for the exits.","exja":"火災報知器が鳴ると、数人がパニックになり出口へ走り始めた。"},{"id":5841,"en":"papaya","ja":"パパイヤ\n熱帯産の甘い大型果物","level":7,"lnum":1,"ex":"She added slices of ripe papaya to her fruit salad for a tropical flavor.","exja":"彼女はトロピカルな風味を出すために、熟したパパイヤのスライスをフルーツサラダに加えた。"},{"id":5842,"en":"paperless","ja":"ペーパーレスの\n紙を使わないデジタル化された環境","level":7,"lnum":1,"ex":"The office has gone paperless, and all documents are now stored digitally.","exja":"そのオフィスはペーパーレス化し、すべての書類はデジタルで保存されている。"},{"id":5843,"en":"paperwork","ja":"書類仕事\n記入・提出が必要な書類処理の仕事","level":7,"lnum":1,"ex":"He spent most of the afternoon completing the necessary paperwork for the visa application.","exja":"彼は午後の大半をビザ申請に必要な書類仕事の処理に費やした。"},{"id":5844,"en":"paradox","ja":"逆説\n矛盾しているようで真実を含む命題","level":7,"lnum":1,"ex":"It is a paradox that the busiest people often seem to have the most free time.","exja":"最も忙しい人たちが最も多くの自由時間を持っているように見えることは逆説だ。"},{"id":5845,"en":"paralysis","ja":"麻痺\n体や組織が動けなくなる状態","level":7,"lnum":1,"ex":"The accident caused partial paralysis in his left leg, requiring months of therapy.","exja":"事故により左脚に部分的な麻痺が生じ、数ヶ月のリハビリが必要となった。"},{"id":5846,"en":"paramedic","ja":"救急隊員の\n救急医療の訓練を受けた隊員に関わる","level":7,"lnum":1,"ex":"The paramedic arrived at the scene within minutes and began treating the injured.","exja":"救急隊員は数分以内に現場に到着し、負傷者の治療を始めた。"},{"id":5847,"en":"paratrooper","ja":"落下傘兵\nパラシュートで降下する特殊部隊員","level":7,"lnum":1,"ex":"The paratroopers landed behind enemy lines under the cover of darkness.","exja":"落下傘兵たちは暗闇に乗じて敵の後方に降下した。"},{"id":5848,"en":"parliament","ja":"議会\n国の法律を作る代表者の集まり","level":7,"lnum":1,"ex":"The new bill was passed by parliament after weeks of heated debate.","exja":"何週間にもわたる白熱した討論の末、新しい法案は議会で可決された。"},{"id":5849,"en":"participation","ja":"参加\n活動・討議に加わること。involvementより積極的","level":7,"lnum":1,"ex":"The school encourages full participation from all students in extracurricular activities.","exja":"学校は全生徒が課外活動に積極的に参加することを奨励している。"},{"id":5850,"en":"particle","ja":"粒子\n非常に小さな物質の断片。物理学でも使う","level":7,"lnum":1,"ex":"Dust particles in the air can cause respiratory problems in sensitive individuals.","exja":"空気中の塵粒子は敏感な人に呼吸器系の問題を引き起こす可能性がある。"},{"id":5851,"en":"partisan","ja":"党派の人/偏った\n特定の側に強く肩入れする人・考え方","level":7,"lnum":1,"ex":"The debate became too partisan, with neither side willing to consider the other's view.","exja":"議論はあまりにも党派的になり、どちらの側も相手の意見を考慮しようとしなかった。"},{"id":5852,"en":"partnership","ja":"パートナーシップ\n共同で目標を達成する協力関係","level":7,"lnum":1,"ex":"The two companies formed a partnership to develop new technology together.","exja":"2つの会社は新しい技術を共同開発するためにパートナーシップを結んだ。"},{"id":5853,"en":"passionate","ja":"情熱的な\n強い感情・熱意を持っている様子","level":7,"lnum":1,"ex":"She is passionate about environmental conservation and volunteers every weekend.","exja":"彼女は環境保護に情熱を持ち、毎週末ボランティアをしている。"},{"id":5854,"en":"passionately","ja":"情熱的に\n強い感情と熱意を持って行動する様子","level":7,"lnum":1,"ex":"The professor argued passionately for greater investment in renewable energy.","exja":"教授は再生可能エネルギーへのより大きな投資を熱情的に訴えた。"},{"id":5855,"en":"pastor","ja":"牧師\nプロテスタントの教会指導者","level":7,"lnum":1,"ex":"The pastor delivered a heartfelt sermon that moved many members of the congregation.","exja":"牧師は心のこもった説教を行い、多くの会衆の心を動かした。"},{"id":5856,"en":"pastoral","ja":"田園の/牧歌的な\n田舎の穏やかな生活・自然に関わる","level":7,"lnum":1,"ex":"The artist painted a peaceful pastoral scene with rolling hills and grazing sheep.","exja":"芸術家は緩やかな丘と羊が草を食む牧歌的な場面を描いた。"},{"id":5857,"en":"patch","ja":"パッチ/一区画\n修繕に使う布切れ、または小さな区画・修正プログラム","level":7,"lnum":1,"ex":"She used a patch of leather to repair the hole in her favorite jacket.","exja":"彼女はお気に入りのジャケットの穴を修繕するために革の切れ端を使った。"},{"id":5858,"en":"patiently","ja":"辛抱強く\nイライラせず穏やかに待つ・耐える様子","level":7,"lnum":1,"ex":"He patiently explained the problem to each student until they fully understood.","exja":"彼は生徒たちが完全に理解するまで、一人ひとりに辛抱強く問題を説明した。"},{"id":5859,"en":"patriot","ja":"愛国者\n自国を深く愛し守ろうとする人","level":7,"lnum":1,"ex":"He was remembered as a patriot who devoted his life to protecting his country.","exja":"彼は国を守るために人生を捧げた愛国者として記憶されている。"},{"id":5860,"en":"patriotic","ja":"愛国心のある\n国への強い誇りや愛情を示す","level":7,"lnum":1,"ex":"Singing the national anthem fills many citizens with a patriotic feeling.","exja":"国歌を歌うことは多くの市民を愛国心のある気持ちで満たす。"},{"id":5861,"en":"patriotism","ja":"愛国心\n自国を愛し守ろうとする気持ち・精神","level":7,"lnum":1,"ex":"The soldiers' sacrifice was seen as the highest expression of patriotism.","exja":"兵士たちの犠牲は愛国心の最高の表れとみなされた。"},{"id":5862,"en":"patron","ja":"後援者/常連客\n芸術家などを支援する人、または常連の客","level":7,"lnum":1,"ex":"The gallery was supported by a generous patron who donated a large sum each year.","exja":"ギャラリーは毎年多額の寄付をしてくれる寛大な後援者によって支えられていた。"},{"id":5863,"en":"pave","ja":"舗装する\n道路をアスファルト・石で固める","level":7,"lnum":1,"ex":"The city paved the old dirt road to make it safer for residents.","exja":"市は住民の安全のために古い未舗装道路を舗装した。"},{"id":5864,"en":"pavement","ja":"舗装道路/歩道\nアスファルトで固めた道路・歩道（英式）","level":7,"lnum":1,"ex":"She tripped on the uneven pavement and sprained her ankle.","exja":"彼女はでこぼこの舗装道路でつまずいて足首を捻挫した。"},{"id":5865,"en":"paw","ja":"動物の足\n爪を持つ動物の手足","level":7,"lnum":1,"ex":"The dog gently placed its paw on her hand as if asking for attention.","exja":"犬はまるで注目を求めるかのように、そっと彼女の手に前足を置いた。"},{"id":5866,"en":"pawnbroker","ja":"質屋\n担保に物を預かってお金を貸す人","level":7,"lnum":1,"ex":"The man pawned his watch at the local pawnbroker to raise some quick cash.","exja":"男は急いで現金を用意するため、地元の質屋に時計を入れた。"},{"id":5867,"en":"pawnshop","ja":"質屋の店\n担保で金を貸す店舗","level":7,"lnum":1,"ex":"She found a rare coin at the pawnshop and bought it for a bargain price.","exja":"彼女は質屋でレアコインを見つけ、格安の値段で購入した。"},{"id":5868,"en":"payment","ja":"支払い\nお金を渡す行為・支払った金額","level":7,"lnum":1,"ex":"The monthly payment for the car loan is deducted automatically from his bank account.","exja":"自動車ローンの月々の支払いは彼の銀行口座から自動的に引き落とされる。"},{"id":5869,"en":"peacefully","ja":"平和に\n争いや混乱なく穏やかに","level":7,"lnum":1,"ex":"The two sides agreed to resolve their differences peacefully through negotiation.","exja":"双方は交渉を通じて平和的に意見の相違を解決することに合意した。"},{"id":5870,"en":"peak","ja":"頂点/最高潮\n山の頂上、または最も高い状態","level":7,"lnum":1,"ex":"Tourist numbers reach their peak during the summer holiday season.","exja":"観光客数は夏休みシーズン中に頂点に達する。"},{"id":5871,"en":"pearl","ja":"真珠\n貝が作り出す宝飾品。pearl of wisdom（知恵の言葉）","level":7,"lnum":1,"ex":"The necklace was adorned with a single large pearl that gleamed in the light.","exja":"そのネックレスには光の中で輝く大きな真珠が1つあしらわれていた。"},{"id":5872,"en":"pebble","ja":"小石\n川や海岸にある丸い小石","level":7,"lnum":1,"ex":"She picked up a smooth pebble from the riverbed and skipped it across the water.","exja":"彼女は川底から滑らかな小石を拾い上げ、水面に向かって投げて水切りをした。"},{"id":5873,"en":"pedal","ja":"ペダル\n足で踏んで操作する部品","level":7,"lnum":1,"ex":"She pressed the pedal to the floor to speed up and pass the slow truck.","exja":"彼女はペダルを床まで踏み込んで加速し、遅いトラックを追い越した。"},{"id":5874,"en":"pedantic","ja":"衒学的な\n細かいルールや知識を見せびらかす傾向","level":7,"lnum":1,"ex":"His pedantic corrections during the meeting irritated everyone in the room.","exja":"会議での彼の衒学的な訂正は、その場にいる全員を苛立たせた。"},{"id":5875,"en":"pedestrian","ja":"歩行者\n道を歩いている人。車・自転車以外の通行人","level":7,"lnum":1,"ex":"All pedestrians must use the crosswalk when crossing the road.","exja":"道路を渡る際、すべての歩行者は横断歩道を使用しなければならない。"},{"id":5876,"en":"pee","ja":"おしっこする\n排尿する口語的・子供向けの表現","level":7,"lnum":1,"ex":"The toddler needed to pee urgently, so they stopped at the next rest area.","exja":"幼い子が急いでトイレに行きたがったので、次のサービスエリアに止まった。"},{"id":5877,"en":"peel","ja":"皮/剥いた部分\n果物・野菜の表皮（名詞）","level":7,"lnum":1,"ex":"He collected the orange peel to use as a natural flavoring for the cake.","exja":"彼はケーキの天然フレーバーとして使うためにオレンジの皮を集めた。"},{"id":5878,"en":"peel","ja":"皮をむく\n果物・野菜の皮を取り除く（動詞）","level":7,"lnum":1,"ex":"She peeled the orange slowly and divided it into segments.","exja":"彼女はゆっくりとオレンジの皮をむいて、房に分けた。"},{"id":5879,"en":"peep","ja":"のぞき見/ちらっと見ること\n隙間からこっそり見ること（名詞）","level":7,"lnum":1,"ex":"The child took a peep through the keyhole to see who was inside the room.","exja":"子供は部屋の中に誰がいるか見るために鍵穴からこっそりのぞき見した。"},{"id":5880,"en":"peer","ja":"同輩/仲間\n同じ年齢・立場の人。peer pressureは同調圧力","level":7,"lnum":1,"ex":"She discussed the project with her peers before presenting it to the teacher.","exja":"彼女は教師に発表する前に、同輩たちとプロジェクトについて話し合った。"},{"id":5881,"en":"peg","ja":"ペグ/留め具\n物を固定する杭や洗濯ばさみ","level":7,"lnum":1,"ex":"He used a peg to hang his wet coat on the back of the door.","exja":"彼は濡れたコートをドアの裏に掛けるためにペグを使った。"},{"id":5882,"en":"penalize/penalise","ja":"罰則を与える\n違反に対してペナルティを科す","level":7,"lnum":1,"ex":"The player was penalized for breaking the rules during the match.","exja":"その選手は試合中にルール違反をしてペナルティを受けた。"},{"id":5883,"en":"penalty","ja":"罰則/ペナルティ\nルール違反への制裁・罰。fineより広い","level":7,"lnum":1,"ex":"The company faced a heavy financial penalty for violating environmental regulations.","exja":"その会社は環境規制に違反したとして重い財政的な罰則に直面した。"},{"id":5884,"en":"penetrate","ja":"貫通する\n固い物を通り抜ける・深く入り込む","level":7,"lnum":1,"ex":"The drill was strong enough to penetrate the thick concrete wall.","exja":"そのドリルは厚いコンクリートの壁を貫通するほど強力だった。"},{"id":5885,"en":"penicillin","ja":"ペニシリン\n抗生物質の一種。細菌感染症の治療薬","level":7,"lnum":1,"ex":"The introduction of penicillin in the 1940s revolutionized the treatment of bacterial infections.","exja":"1940年代のペニシリンの導入は細菌感染症の治療に革命をもたらした。"},{"id":5886,"en":"pension","ja":"年金\n退職後に定期的に受け取るお金","level":7,"lnum":1,"ex":"After forty years of service, she retired and began receiving her pension.","exja":"40年の勤務の後、彼女は退職し、年金を受け取り始めた。"},{"id":5887,"en":"pentagon","ja":"五角形/ペンタゴン\n5つの角を持つ形。米国国防総省の建物にも使う","level":7,"lnum":1,"ex":"The children drew shapes including a pentagon and a hexagon in art class.","exja":"子供たちは美術の授業で五角形や六角形を含む形を描いた。"},{"id":5888,"en":"perceive","ja":"知覚する\n感覚や直感で気づく・理解する","level":7,"lnum":1,"ex":"He perceived a slight tension in the room when he walked in late.","exja":"彼が遅れて入室すると、部屋の中にわずかな緊張を感じ取った。"},{"id":5889,"en":"percentage","ja":"パーセント\n全体に対する割合を百分率で示した数値","level":7,"lnum":1,"ex":"A large percentage of the students passed the exam on their first attempt.","exja":"学生の高い割合が初回の試験に合格した。"},{"id":5890,"en":"perception","ja":"認識/知覚\n物事をどう感じ・理解するかの主観的な見方","level":7,"lnum":1,"ex":"Her perception of the situation was very different from everyone else's in the team.","exja":"状況に対する彼女の認識は、チームの他の全員とは大きく異なっていた。"},{"id":5891,"en":"permanence","ja":"永続性\n変わらずに続く性質・状態","level":7,"lnum":1,"ex":"The artist was drawn to photography for its ability to capture a sense of permanence.","exja":"写真家は永続性の感覚を捉えられるという点に引かれて写真に取り組んでいた。"},{"id":5892,"en":"permeate","ja":"浸透する\n液体・考えなどが全体に広がり染み込む","level":7,"lnum":1,"ex":"The smell of fresh bread permeated the entire bakery and the street outside.","exja":"新鮮なパンの香りはベーカリー全体と外の通りにまで浸透した。"},{"id":5893,"en":"perseverance","ja":"忍耐力\n困難でもあきらめず続ける粘り強さ","level":7,"lnum":1,"ex":"Her perseverance through years of hardship finally paid off when she published her novel.","exja":"何年にもわたる苦難を乗り越えた彼女の忍耐力は、小説を出版した時についに報われた。"},{"id":5894,"en":"persist","ja":"持続する\n困難があっても続ける・消えずに残る","level":7,"lnum":1,"ex":"Despite many rejections, he persisted in submitting his work to publishers.","exja":"多くの拒否にもかかわらず、彼は出版社への作品の提出を続けた。"},{"id":5895,"en":"persistence","ja":"粘り強さ\nあきらめずに努力し続ける性質","level":7,"lnum":1,"ex":"His persistence in learning the language paid off when he became fluent in two years.","exja":"2年間で流暢になったとき、言語学習への彼の粘り強さが実を結んだ。"},{"id":5896,"en":"persistent","ja":"しつこい/粘り強い\nやめずに繰り返す。肯定・否定両方に使う","level":7,"lnum":1,"ex":"The persistent rain over the weekend ruined their plans for an outdoor barbecue.","exja":"週末を通じて降り続いた雨が、屋外バーベキューの計画を台無しにした。"},{"id":5897,"en":"personification","ja":"擬人化\n人でないものを人のように表す表現技法","level":7,"lnum":1,"ex":"\"The wind howled with anger\" is an example of personification in literature.","exja":"「風が怒って吠えた」は文学における擬人化の例だ。"},{"id":5898,"en":"personify","ja":"擬人化する\n概念・物を人間として表現する","level":7,"lnum":1,"ex":"The character in the novel personifies the idea of courage and self-sacrifice.","exja":"その小説の登場人物は勇気と自己犠牲の概念を擬人化している。"},{"id":5899,"en":"personnel","ja":"人員/職員\n組織に属するスタッフ全体。staffより公式","level":7,"lnum":1,"ex":"The company hired additional personnel to handle the increased demand during the holidays.","exja":"会社は休暇中の需要増加に対応するため、追加の人員を採用した。"},{"id":5900,"en":"perspective","ja":"視点/観点\n物事を見る角度・立場・見方","level":7,"lnum":1,"ex":"Traveling to different countries can change your perspective on your own culture.","exja":"異なる国々を旅すると、自分の文化に対する視点が変わることがある。"},{"id":5901,"en":"perspiration","ja":"発汗/汗\n体から出る汗。sweatより書き言葉的","level":7,"lnum":1,"ex":"The athlete wiped the perspiration from his forehead during the break.","exja":"アスリートは休憩中に額の汗を拭いた。"},{"id":5902,"en":"persuasion","ja":"説得\n人の意見・行動を変えるよう働きかけること","level":7,"lnum":1,"ex":"It took a lot of persuasion to convince her to try the new activity.","exja":"彼女に新しい活動を試してもらうには多くの説得が必要だった。"},{"id":5903,"en":"pessimist","ja":"悲観主義者\n悪い結果になると思いがちな人","level":7,"lnum":1,"ex":"As a pessimist, he always expected the worst possible outcome from every situation.","exja":"悲観主義者として、彼はどんな状況からも最悪の結果を常に予期していた。"},{"id":5904,"en":"pessimistic","ja":"悲観的な\n悪い結果になると思いがちな考え方","level":7,"lnum":1,"ex":"She was pessimistic about the chances of finding a job in such a tough market.","exja":"彼女はこれほど厳しい市場で就職できる見込みについて悲観的だった。"},{"id":5905,"en":"petrified","ja":"石化した/恐怖で固まった\n極度の恐怖でまったく動けない状態","level":7,"lnum":1,"ex":"The hikers were petrified when they suddenly came face to face with a bear.","exja":"ハイカーたちは突然クマと対面した時、恐怖で固まった。"},{"id":5906,"en":"petty","ja":"些細な/心が狭い\n重要でない細かいこと・器が小さい人","level":7,"lnum":1,"ex":"Don't waste your energy on petty arguments about things that don't really matter.","exja":"本当に重要ではないことについての些細な口論にエネルギーを無駄にしてはいけない。"},{"id":5907,"en":"pH","ja":"ペーハー/pH値\n酸性・アルカリ性の強さを示す尺度","level":7,"lnum":1,"ex":"The pH of pure water is neutral, measuring exactly seven on the scale.","exja":"純水のpHは中性で、測定値はちょうど7だ。"},{"id":5908,"en":"phase","ja":"段階/局面\nプロセスの特定の時期・段階","level":7,"lnum":1,"ex":"The construction project is now entering its final phase before completion.","exja":"建設プロジェクトは今、完成前の最終段階に入っている。"},{"id":5909,"en":"philosophical","ja":"哲学的な\n深く物事の本質を考える思考スタイル","level":7,"lnum":1,"ex":"She took a philosophical approach to failure, seeing it as a chance to learn.","exja":"彼女は失敗を学びのチャンスとして捉え、哲学的なアプローチを取った。"},{"id":5910,"en":"physician","ja":"医師\n内科医・医療の専門家。doctorより正式","level":7,"lnum":1,"ex":"The physician recommended that the patient rest for at least two weeks.","exja":"医師は患者に少なくとも2週間休むよう勧めた。"},{"id":5911,"en":"pi","ja":"円周率\n円の円周と直径の比（約3.14）。πで表す","level":7,"lnum":1,"ex":"The value of pi is approximately 3.14159, and it is used to calculate the area of a circle.","exja":"円周率の値はおよそ3.14159で、円の面積を計算するために使用される。"},{"id":5912,"en":"pickle","ja":"漬物/困った状況\n酢漬けにした食品、またはin a pickleで困った状況","level":7,"lnum":1,"ex":"The restaurant served the burger with a side of pickles and coleslaw.","exja":"レストランはバーガーを漬物とコールスローと一緒に提供した。"},{"id":5913,"en":"picky","ja":"好みがうるさい\n細かい点にこだわり選り好みする。fussyに近い","level":7,"lnum":1,"ex":"He was very picky about the food he ate and refused most vegetables.","exja":"彼は食べる物についてとても好みがうるさく、ほとんどの野菜を断った。"},{"id":5914,"en":"picturesque","ja":"絵のように美しい\nまるで絵画のような美しい景色","level":7,"lnum":1,"ex":"The old fishing village was picturesque, with colorful boats and cobblestone streets.","exja":"古い漁村は色鮮やかなボートと石畳の道があり、絵のように美しかった。"},{"id":5915,"en":"pillowcase","ja":"枕カバー\n枕を覆う布製のカバー","level":7,"lnum":1,"ex":"She washed all the pillowcases and bed sheets on Sunday morning.","exja":"彼女は日曜日の朝に枕カバーとシーツをすべて洗濯した。"},{"id":5916,"en":"pine","ja":"松の木/切望する\nマツ科の常緑樹（名詞）。または強く思い焦がれる","level":7,"lnum":1,"ex":"He stood alone, pining for the days when his children were young.","exja":"彼は子供たちが幼かった頃を切望しながら、一人で立っていた。"},{"id":5917,"en":"pint","ja":"パイント\n液体の体積単位（約473ml米/568ml英）","level":7,"lnum":1,"ex":"He ordered a pint of cold beer at the local pub after a long day of work.","exja":"長い一日の仕事の後、彼は地元のパブで冷たいビールをパイント注文した。"},{"id":5918,"en":"piracy","ja":"海賊行為/著作権侵害\n海での略奪、またはコンテンツの無断コピー","level":7,"lnum":1,"ex":"Online piracy continues to be a major challenge for the music and film industries.","exja":"オンライン海賊行為は音楽・映画業界にとって依然として大きな課題だ。"},{"id":5919,"en":"pirate","ja":"海賊\n船を襲う強盗、または著作権を侵害する人","level":7,"lnum":1,"ex":"The novel tells the story of a young pirate who searches for a legendary treasure.","exja":"その小説は伝説の宝を探す若い海賊の物語を語っている。"},{"id":5920,"en":"pitch","ja":"音程/ピッチ\n音の高低、またはサッカー場・勾配","level":7,"lnum":1,"ex":"The sales team had to pitch their idea to the investors in under ten minutes.","exja":"営業チームは10分以内に投資家にアイデアを売り込まなければならなかった。"},{"id":5921,"en":"pitch","ja":"投げる/売り込む\nボールを投げる、または提案・売り込みをする","level":7,"lnum":1,"ex":"The salesperson pitched their product confidently to the potential clients.","exja":"営業担当者は見込み客に自信を持って商品を売り込んだ。"},{"id":5922,"en":"plague","ja":"疫病/苦しめる\n伝染病（ペスト）、または次々と問題が起こること","level":7,"lnum":1,"ex":"The medieval city was plagued by disease, poverty, and constant political unrest.","exja":"中世の都市は病気、貧困、そして絶え間ない政治的不安に苦しめられていた。"},{"id":5923,"en":"planning","ja":"計画立案\n目標達成のために準備・段取りをすること","level":7,"lnum":1,"ex":"Good planning is essential for the successful execution of any large event.","exja":"どんな大きなイベントを成功させるためにも、十分な計画立案が不可欠だ。"},{"id":5924,"en":"playmate","ja":"遊び仲間\n子供の頃一緒に遊ぶ友達","level":7,"lnum":1,"ex":"She still keeps in touch with her childhood playmate who moved to another city.","exja":"彼女は別の都市に引っ越した幼い頃の遊び仲間と今もつながっている。"},{"id":5925,"en":"playwright","ja":"劇作家\n演劇の脚本・台本を書く人","level":7,"lnum":1,"ex":"The young playwright won the national award for her debut drama.","exja":"その若い劇作家は、彼女の初作品でナショナルアワードを受賞した。"},{"id":5926,"en":"plead","ja":"懇願する\n必死に頼む・法廷で答弁する両方に使う","level":7,"lnum":1,"ex":"The defendant pleaded not guilty to all charges brought against him.","exja":"被告は彼に対して提起されたすべての訴因について無罪を訴えた。"},{"id":5927,"en":"plot","ja":"筋書き/陰謀\n物語の展開、または秘密の悪だくみ","level":7,"lnum":1,"ex":"The novel had such a clever plot that it was impossible to put down.","exja":"その小説はとても巧みな筋書きがあり、読むのをやめることができなかった。"},{"id":5928,"en":"pluck","ja":"引き抜く\n毛・羽・草などを抜く。勇気（名詞）にも使う","level":7,"lnum":1,"ex":"She plucked a few herbs from the garden to add flavor to the soup.","exja":"彼女はスープに風味をつけるために庭からハーブを数本引き抜いた。"},{"id":5929,"en":"plug","ja":"差し込む/宣伝する\nコンセントに差す、または商品を宣伝する","level":7,"lnum":1,"ex":"Remember to plug in the laptop before the battery runs out completely.","exja":"バッテリーが完全に切れる前にノートパソコンのプラグを差し込むことを忘れずに。"},{"id":5930,"en":"plum","ja":"プラム/最高の\nスモモの実、または最高の機会・地位","level":7,"lnum":1,"ex":"She picked a ripe plum from the tree and bit into its sweet, juicy flesh.","exja":"彼女は木から熟したプラムをもぎ取り、甘くてジューシーな果肉に噛みついた。"},{"id":5931,"en":"plumber","ja":"配管工\n水道管の修理・設置をする職人","level":7,"lnum":1,"ex":"They called a plumber to fix the leaking pipe under the kitchen sink.","exja":"彼らはキッチンシンクの下の漏れているパイプを修理するために配管工を呼んだ。"},{"id":5932,"en":"plus","ja":"利点/プラス\n利点・長所（名詞）。加えてという意味も","level":7,"lnum":1,"ex":"One big plus of working from home is the time saved on commuting.","exja":"在宅勤務の大きな利点の一つは、通勤にかかる時間が節約できることだ。"},{"id":5933,"en":"pneumonia","ja":"肺炎\n肺に炎症が起きる感染症","level":7,"lnum":1,"ex":"He developed pneumonia after the flu and had to be hospitalized for a week.","exja":"彼はインフルエンザの後に肺炎を発症し、1週間入院しなければならなかった。"},{"id":5934,"en":"point of view","ja":"観点\n物事を考える立場・視点","level":7,"lnum":1,"ex":"The novel is written from the first-person point of view of a teenage girl.","exja":"その小説は10代の女の子の一人称の観点で書かれている。"},{"id":5935,"en":"pointless","ja":"無意味な\n目的や価値がない。uselessより虚しい感じ","level":7,"lnum":1,"ex":"It seemed pointless to argue about something that could not be changed.","exja":"変えることができないことについて議論するのは無意味に思えた。"},{"id":5936,"en":"polar bear","ja":"ホッキョクグマ\n北極圏に生息する白い大型クマ","level":7,"lnum":1,"ex":"The polar bear is perfectly adapted to survive in the extreme cold of the Arctic.","exja":"ホッキョクグマは北極の極端な寒さの中で生き延びるために完全に適応している。"},{"id":5937,"en":"polio","ja":"ポリオ\n小児麻痺を引き起こすウイルス感染症","level":7,"lnum":1,"ex":"Thanks to global vaccination campaigns, polio has been nearly eradicated worldwide.","exja":"世界規模の予防接種キャンペーンのおかげで、ポリオは世界中でほぼ根絶されている。"},{"id":5938,"en":"polish","ja":"磨くこと/光沢剤\n表面を磨いてきれいにする・光沢剤（名詞）","level":7,"lnum":1,"ex":"He polished the old wooden table until it shone like new.","exja":"彼は古い木製のテーブルが新品のように輝くまで磨いた。"},{"id":5939,"en":"politeness","ja":"礼儀正しさ\n相手への敬意ある言動・マナー","level":7,"lnum":1,"ex":"Her natural politeness made her popular with both customers and colleagues.","exja":"彼女の生来の礼儀正しさは、顧客と同僚の両方に好かれる理由となった。"},{"id":5940,"en":"politically","ja":"政治的に\n政治の観点や文脈において","level":7,"lnum":1,"ex":"The issue is politically sensitive and requires careful handling by the government.","exja":"その問題は政治的に繊細であり、政府による慎重な対応が求められる。"},{"id":5941,"en":"polity","ja":"政体\n国家・社会の統治の形態・組織","level":7,"lnum":1,"ex":"The ancient Greek polity laid the foundation for modern democratic governance.","exja":"古代ギリシャの政体は現代の民主的統治の基礎を築いた。"},{"id":5942,"en":"polo","ja":"ポロ\n馬に乗って行うスポーツ、またはポロシャツ","level":7,"lnum":1,"ex":"He learned to play polo at a prestigious sports club during his time abroad.","exja":"彼は海外滞在中に名門スポーツクラブでポロを習った。"},{"id":5943,"en":"ponder","ja":"熟考する\nじっくり深く考える。thinkより時間をかける","level":7,"lnum":1,"ex":"She sat quietly by the window, pondering the difficult decision she had to make.","exja":"彼女は窓際に静かに座り、下さなければならない難しい決断についてじっくりと考えた。"},{"id":5944,"en":"popularity","ja":"人気\n多くの人に好かれ・注目される度合い","level":7,"lnum":1,"ex":"The app's popularity grew rapidly after a famous influencer recommended it online.","exja":"有名なインフルエンサーがオンラインで紹介した後、そのアプリの人気は急速に高まった。"},{"id":5945,"en":"popularize/popularise","ja":"普及させる\n一般の人に広く知らせて浸透させる","level":7,"lnum":1,"ex":"Social media helped popularize the trend among young people worldwide.","exja":"ソーシャルメディアは若者の間でそのトレンドを世界中に広めた。"},{"id":5946,"en":"porch","ja":"玄関ポーチ\n家の入口にある屋根付きの半外部空間","level":7,"lnum":1,"ex":"They sat on the porch in the evening, watching the fireflies in the yard.","exja":"彼らは夕方にポーチに座り、庭で飛ぶホタルを眺めた。"},{"id":5947,"en":"portion","ja":"部分/一人前\n全体の一部、または食事の一人分の量","level":7,"lnum":1,"ex":"He saved a large portion of his monthly salary to fund his travels.","exja":"彼は旅行の資金にするために月給の多くの部分を貯蓄した。"},{"id":5948,"en":"pose","ja":"ポーズ\n体の姿勢・モデルのポーズ（名詞）","level":7,"lnum":1,"ex":"The model struck a dramatic pose for the photographer at the end of the runway.","exja":"モデルはランウェイの終わりで写真家のために劇的なポーズを決めた。"},{"id":5949,"en":"posh","ja":"上品な・高級な\n庶民的でなく洗練された雰囲気。やや皮肉的に使うこともある","level":7,"lnum":1,"ex":"They stayed at a posh hotel in the center of the city.","exja":"彼らは市の中心にある高級ホテルに宿泊した。"},{"id":5950,"en":"possessed","ja":"取り憑かれた\n悪霊などに支配されている状態。感情的に制御不能な様子にも使う","level":7,"lnum":1,"ex":"She looked possessed as she screamed at the top of her lungs during the argument.","exja":"口論の最中に声を限りに叫ぶ彼女は、まるで何かに取り憑かれているようだった。"},{"id":5951,"en":"postal","ja":"郵便の\n郵便サービスや郵便局に関連する形容詞","level":7,"lnum":1,"ex":"Please send the documents to my postal address by Friday.","exja":"書類を金曜日までに私の郵便住所に送ってください。"},{"id":5952,"en":"postpone","ja":"延期する\n予定を後ろにずらす。delayより公式的な場面で使われる","level":7,"lnum":1,"ex":"The outdoor concert was postponed due to the heavy rain.","exja":"屋外コンサートは大雨のために延期された。"},{"id":5953,"en":"potent","ja":"強力な・効き目のある\n薬や酒、議論などの効果が強い場合に使う","level":7,"lnum":1,"ex":"This medicine is very potent and should only be taken once a day.","exja":"この薬は非常に効き目が強いので、1日1回だけ服用するべきだ。"},{"id":5954,"en":"potential","ja":"潜在的な\nまだ実現していないが可能性を持つ意味。名詞としても使う","level":7,"lnum":1,"ex":"The coach saw great potential in the young athlete.","exja":"コーチはその若いアスリートに大きな可能性を見出した。"},{"id":5955,"en":"potentially","ja":"潜在的に・場合によっては\n将来的にそうなりうると示す副詞","level":7,"lnum":1,"ex":"The new policy could potentially affect millions of workers.","exja":"その新しい政策は何百万人もの労働者に影響を与える可能性がある。"},{"id":5956,"en":"pound","ja":"強く打つ・叩く\n激しく繰り返し打つ動作。心臓がドキドキするときにも使う","level":7,"lnum":1,"ex":"His heart was pounding as he waited for the exam results.","exja":"試験の結果を待ちながら、彼の心臓はドキドキしていた。"},{"id":5957,"en":"powder","ja":"粉にする・粉をかける\n物を細かくしたり粉状のものを塗る動作","level":7,"lnum":1,"ex":"She powdered her face lightly before going out.","exja":"彼女は外出前に顔に軽くパウダーをはたいた。"},{"id":5958,"en":"powerfully","ja":"力強く\n強さや説得力を持って行動する様子","level":7,"lnum":1,"ex":"He spoke powerfully about the need for climate action.","exja":"彼は気候変動対策の必要性について力強く語った。"},{"id":5959,"en":"practicality","ja":"実用性\n理論より現実・実践に役立つかどうかという性質","level":7,"lnum":1,"ex":"We need to consider the practicality of this plan before moving forward.","exja":"この計画を進める前に、実用性を考慮する必要がある。"},{"id":5960,"en":"practically","ja":"ほぼ・事実上\nalmostに近い意味で使うことが多い","level":7,"lnum":1,"ex":"The exam is tomorrow, so she has practically no time to prepare.","exja":"試験は明日なので、彼女には準備する時間がほとんどない。"},{"id":5961,"en":"praise","ja":"称賛する\n人の行動や成果を高く評価して誉める","level":7,"lnum":1,"ex":"The teacher praised the student for her excellent essay.","exja":"先生は彼女の優れた小論文を称賛した。"},{"id":5962,"en":"prance","ja":"跳ね回る\n誇らしげに高く膝を上げて歩く・踊るような動き","level":7,"lnum":1,"ex":"The horse pranced around the ring during the show.","exja":"馬はショーの最中に馬場の周りを跳ね回った。"},{"id":5963,"en":"prawn","ja":"エビ（大型）\n主にイギリス英語でよく使う大型のエビ","level":7,"lnum":1,"ex":"She ordered a prawn salad at the seaside restaurant.","exja":"彼女は海辺のレストランでエビのサラダを注文した。"},{"id":5964,"en":"precede","ja":"先行する・前に来る\n時間・順序・位置において前にあることを示す","level":7,"lnum":1,"ex":"A short introduction will precede the main presentation.","exja":"短い紹介が本発表の前に行われる。"},{"id":5965,"en":"precisely","ja":"正確に・まさに\nexactlyとほぼ同義だがやや格式張った表現","level":7,"lnum":1,"ex":"The surgery must be performed precisely to avoid complications.","exja":"合併症を避けるために、手術は正確に行われなければならない。"},{"id":5966,"en":"predicament","ja":"苦境・窮地\n解決が難しい困った状況。dilemmaより一般的","level":7,"lnum":1,"ex":"He found himself in a predicament when he forgot his wallet at home.","exja":"財布を家に忘れたとき、彼は困った状況に陥った。"},{"id":5967,"en":"predicate","ja":"述語とする\n文法用語または論理学で使う動詞","level":7,"lnum":1,"ex":"In the sentence \"The dog runs,\" \"runs\" is the predicate.","exja":"「The dog runs」という文では、「runs」が述語である。"},{"id":5968,"en":"predicative","ja":"叙述的な\nbe動詞などの後に置かれる形容詞の用法を指す文法用語","level":7,"lnum":1,"ex":"In \"The sky is blue,\" the adjective \"blue\" is in the predicative position.","exja":"「The sky is blue」では、形容詞「blue」は叙述的な位置にある。"},{"id":5969,"en":"predictable","ja":"予測可能な\n結果や行動が事前に読める。退屈という含みになることも","level":7,"lnum":1,"ex":"The ending of the movie was so predictable that I guessed it in the first ten minutes.","exja":"その映画の結末はあまりにも予測可能で、最初の10分で見当がついた。"},{"id":5970,"en":"predictive","ja":"予測の\n将来を予測する能力や技術に関する形容詞","level":7,"lnum":1,"ex":"The company uses predictive technology to forecast future sales trends.","exja":"その会社は将来の販売動向を予測するために予測技術を使用している。"},{"id":5971,"en":"predictor","ja":"予測因子・指標\n何かを予測するための変数や要因","level":7,"lnum":1,"ex":"Childhood education is a strong predictor of adult success.","exja":"幼少期の教育は、成人後の成功を示す強い予測因子である。"},{"id":5972,"en":"prefect","ja":"学級委員・長官\n学校でリーダー役の生徒、または行政上の長官","level":7,"lnum":1,"ex":"The school prefect was responsible for maintaining order in the hallways.","exja":"学校の学級委員は廊下の秩序を維持する責任があった。"},{"id":5973,"en":"preferable","ja":"より好ましい\n比較して一方が望ましい場合に使う","level":7,"lnum":1,"ex":"Taking the train is preferable to driving in heavy traffic.","exja":"渋滞の中では車を運転するよりも電車に乗る方が好ましい。"},{"id":5974,"en":"preferably","ja":"できれば・好ましくは\n希望や推奨を柔らかく伝える副詞","level":7,"lnum":1,"ex":"Please submit your application by Friday, preferably in the morning.","exja":"できれば午前中に、金曜日までに申請書を提出してください。"},{"id":5975,"en":"prehistoric","ja":"有史以前の\n文字記録が残る前の時代に関する","level":7,"lnum":1,"ex":"Scientists discovered prehistoric cave paintings in southern France.","exja":"科学者たちはフランス南部で有史以前の洞窟壁画を発見した。"},{"id":5976,"en":"prehuman","ja":"人類以前の\n人類が出現する前の状態や種族を指す","level":7,"lnum":1,"ex":"The museum displayed bones from prehuman ancestors millions of years old.","exja":"博物館では、数百万年前の人類以前の祖先の骨が展示されていた。"},{"id":5977,"en":"preindustrial","ja":"産業革命以前の\n工業化が始まる前の社会や時代を指す","level":7,"lnum":1,"ex":"In preindustrial societies, most people worked as farmers.","exja":"産業革命以前の社会では、ほとんどの人が農業従事者だった。"},{"id":5978,"en":"prejudge","ja":"予断する\n証拠なしに事前に判断を下してしまう","level":7,"lnum":1,"ex":"It is unfair to prejudge someone based on their appearance.","exja":"外見だけで人を予断するのは不公平だ。"},{"id":5979,"en":"preliminary","ja":"予備の・準備段階の\n本番前の準備・初期段階を表す形容詞","level":7,"lnum":1,"ex":"The team held a preliminary meeting to outline the project goals.","exja":"チームはプロジェクトの目標を概説するために予備会議を開いた。"},{"id":5980,"en":"preoccupy","ja":"心を占める\nある考えや問題が頭から離れない状態にする","level":7,"lnum":1,"ex":"The upcoming exam preoccupied him so much that he could barely sleep.","exja":"迫りくる試験が頭から離れず、ほとんど眠れなかった。"},{"id":5981,"en":"prescribe","ja":"処方する・規定する\n医師が薬を処方する、または規則を定める","level":7,"lnum":1,"ex":"The doctor prescribed antibiotics for the patient's infection.","exja":"医師は患者の感染症に対して抗生物質を処方した。"},{"id":5982,"en":"presenter","ja":"司会者・発表者\nテレビ番組の司会やプレゼンをする人","level":7,"lnum":1,"ex":"The presenter explained the new product features to the audience.","exja":"司会者は観客に新製品の特徴を説明した。"},{"id":5983,"en":"presidency","ja":"大統領職・議長職\n大統領や長の職務・任期を指す名詞","level":7,"lnum":1,"ex":"She became the first woman to win the presidency of the organization.","exja":"彼女はその組織の会長職を勝ち取った最初の女性となった。"},{"id":5984,"en":"presidential","ja":"大統領の\n大統領に関連する形容詞","level":7,"lnum":1,"ex":"The presidential election attracted attention from around the world.","exja":"大統領選挙は世界中から注目を集めた。"},{"id":5985,"en":"prestige","ja":"名声・威信\n社会的評価や尊敬を意味する。形容詞はprestigious","level":7,"lnum":1,"ex":"The university's prestige attracted top students from every country.","exja":"その大学の名声はすべての国からトップの学生を引き付けた。"},{"id":5986,"en":"prestigious","ja":"名声ある・一流の\n社会的に高い評価を受けた場所や人物に使う","level":7,"lnum":1,"ex":"She received a prestigious award for her groundbreaking research.","exja":"彼女は画期的な研究で権威ある賞を受賞した。"},{"id":5987,"en":"presumably","ja":"おそらく・推測するに\n証拠はないが合理的に推測できるという意味","level":7,"lnum":1,"ex":"He is not here, so presumably he has already left.","exja":"彼はここにいないので、おそらくすでに出発したのだろう。"},{"id":5988,"en":"pretend","ja":"ふりをする\n実際はそうでないのにそうであるかのように演じる","level":7,"lnum":1,"ex":"The children pretended to be superheroes in the backyard.","exja":"子どもたちは裏庭でスーパーヒーローのふりをして遊んだ。"},{"id":5989,"en":"prevail","ja":"勝る・広まる\n最終的に優位に立つ、または考えや習慣が広く行き渡る","level":7,"lnum":1,"ex":"Despite all the challenges, justice will eventually prevail.","exja":"あらゆる困難にもかかわらず、正義は最終的に勝る。"},{"id":5990,"en":"prevention","ja":"予防・防止\n問題や病気が起きないようにする行為","level":7,"lnum":1,"ex":"Regular exercise is key to the prevention of many diseases.","exja":"定期的な運動は多くの病気の予防に欠かせない。"},{"id":5991,"en":"preventive","ja":"予防的な\n問題が起きる前に防ぐための形容詞","level":7,"lnum":1,"ex":"Wearing sunscreen is an important preventive measure against skin cancer.","exja":"日焼け止めを塗ることは、皮膚がんに対する重要な予防策だ。"},{"id":5992,"en":"previously","ja":"以前に\n過去のある時点よりも前に起きたことを示す副詞","level":7,"lnum":1,"ex":"She had previously worked at a hospital before joining the clinic.","exja":"彼女はクリニックに加わる前に病院で働いていた。"},{"id":5993,"en":"priceless","ja":"非常に貴重な\nお金では買えない価値。面白い・ばかげたという俗語的意味もある","level":7,"lnum":1,"ex":"The museum displayed a priceless collection of ancient artifacts.","exja":"博物館は非常に貴重な古代の工芸品のコレクションを展示していた。"},{"id":5994,"en":"prick","ja":"針・とげ\n鋭い小さな痛み、または針状のもの","level":7,"lnum":1,"ex":"She felt a sharp prick when the nurse gave her the injection.","exja":"看護師が注射を打ったとき、彼女は鋭い刺すような痛みを感じた。"},{"id":5995,"en":"primary","ja":"主要な・第一の\n最も重要な、または最初の段階を表す","level":7,"lnum":1,"ex":"The primary goal of the project is to reduce carbon emissions.","exja":"そのプロジェクトの主要な目標は、二酸化炭素排出量を削減することだ。"},{"id":5996,"en":"prime","ja":"最良の・主要な\n質や重要性が最高の状態を示す形容詞","level":7,"lnum":1,"ex":"This location is in prime condition for starting a new business.","exja":"この場所は新しいビジネスを始めるのに最高の条件が整っている。"},{"id":5997,"en":"prime minister","ja":"首相\n議院内閣制における政府の最高責任者","level":7,"lnum":1,"ex":"The prime minister announced new economic policies at the press conference.","exja":"首相は記者会見で新しい経済政策を発表した。"},{"id":5998,"en":"prior","ja":"以前の・優先する\n時間的に前、または優先順位が高いことを示す","level":7,"lnum":1,"ex":"You need prior experience to apply for this position.","exja":"この職に応募するには以前の経験が必要だ。"},{"id":5999,"en":"priority","ja":"優先事項\n最初に対処すべき重要なこと","level":7,"lnum":1,"ex":"Finishing the report on time is my top priority this week.","exja":"今週の最優先事項は、報告書を期限内に仕上げることだ。"},{"id":6000,"en":"privately","ja":"内密に・個人的に\n公開せず非公式に行う様子","level":7,"lnum":1,"ex":"She privately disagreed with the decision but said nothing publicly.","exja":"彼女は非公式にはその決定に反対していたが、公には何も言わなかった。"},{"id":6001,"en":"privilege","ja":"特権・恩恵\n特定の人だけが持つ有利な権利や機会","level":7,"lnum":1,"ex":"Access to quality education is a privilege not everyone has.","exja":"質の高い教育を受けることは、誰もが持っているわけではない特権だ。"},{"id":6002,"en":"probable","ja":"ありそうな・おそらく\n起こる可能性が高いことを示す形容詞","level":7,"lnum":1,"ex":"It is probable that the game will be canceled due to the storm.","exja":"嵐のため、試合が中止になる可能性が高い。"},{"id":6003,"en":"probe","ja":"調査・探索\n詳しく調べる行為または探査機を指す","level":7,"lnum":1,"ex":"Scientists launched a probe to explore the surface of Mars.","exja":"科学者たちは火星の表面を探索するための探査機を打ち上げた。"},{"id":6004,"en":"procedure","ja":"手順・手続き\n決められた順序で行う方法やプロセス","level":7,"lnum":1,"ex":"Follow the safety procedure carefully before operating the machine.","exja":"機械を操作する前に、安全手順を注意深く守ってください。"},{"id":6005,"en":"profile","ja":"プロフィール・輪郭\n人物紹介や側面図。SNS上の自己紹介にも使う","level":7,"lnum":1,"ex":"She updated her profile on the job website with her latest work experience.","exja":"彼女は求人サイトのプロフィールを最新の職歴で更新した。"},{"id":6006,"en":"profit","ja":"利益・利潤\n収入から費用を引いた残りの金額","level":7,"lnum":1,"ex":"The company earned a large profit from its overseas sales.","exja":"その会社は海外販売から大きな利益を得た。"},{"id":6007,"en":"profitable","ja":"利益のある\n費用を上回る収益をもたらす","level":7,"lnum":1,"ex":"Starting an online business can be very profitable if done correctly.","exja":"オンラインビジネスを始めることは、正しく行えば非常に利益になる。"},{"id":6008,"en":"programming/programing","ja":"プログラミング\nコンピューターのプログラムを作成する行為","level":7,"lnum":1,"ex":"She studied programming for six months and built her first app.","exja":"彼女は6か月間プログラミングを学んで、最初のアプリを作った。"},{"id":6009,"en":"prohibit","ja":"禁止する\n法律や規則で行為を禁じる。forbidより公式的","level":7,"lnum":1,"ex":"Smoking is prohibited inside all public buildings.","exja":"公共の建物内での喫煙はすべて禁止されている。"},{"id":6010,"en":"projection","ja":"予測・投影\n将来の見通し、または映像の投影","level":7,"lnum":1,"ex":"The company's financial projection showed strong growth for next year.","exja":"会社の財務予測は来年の力強い成長を示していた。"},{"id":6011,"en":"prom","ja":"プロム（学校の舞踏会）\n主に米国の高校・大学で行われる正式なダンスパーティー","level":7,"lnum":1,"ex":"She bought a beautiful dress for her high school prom.","exja":"彼女は高校のプロムのために美しいドレスを購入した。"},{"id":6012,"en":"prominence","ja":"突出・名声\n目立った位置・名声のある状態","level":7,"lnum":1,"ex":"The young actor rose to prominence after his role in the hit film.","exja":"その若俳優はヒット映画での役の後、名声を得た。"},{"id":6013,"en":"prompt","ja":"迅速な・即座の\n遅れなくすぐに行動する形容詞","level":7,"lnum":1,"ex":"The customer service team is known for their prompt responses.","exja":"そのカスタマーサービスチームは迅速な対応で知られている。"},{"id":6014,"en":"prompt","ja":"きっかけ・促し\n行動を引き起こす合図または舞台のせりふ読みの補助","level":7,"lnum":1,"ex":"The teacher's question was a prompt for the students to start thinking critically.","exja":"教師の質問は生徒たちが批判的に考え始めるきっかけとなった。"},{"id":6015,"en":"prompt","ja":"促す・引き起こす\n行動や反応を引き起こす動詞","level":7,"lnum":1,"ex":"The coach's encouraging words prompted the team to try harder.","exja":"コーチの励ましの言葉がチームをより一層頑張るよう促した。"},{"id":6016,"en":"promptly","ja":"迅速に・ただちに\n遅れなくすぐに行動する様子を示す副詞","level":7,"lnum":1,"ex":"She promptly replied to the email as soon as she saw it.","exja":"彼女はメールを見るとすぐに素早く返信した。"},{"id":6017,"en":"proponent","ja":"支持者・提唱者\nある考えや計画を積極的に支持する人","level":7,"lnum":1,"ex":"He is a strong proponent of renewable energy.","exja":"彼は再生可能エネルギーの強力な支持者だ。"},{"id":6018,"en":"proposed","ja":"提案された\nまだ決定していないが提案された状態を示す","level":7,"lnum":1,"ex":"The proposed changes to the law sparked debate in parliament.","exja":"提案された法改正は議会で議論を巻き起こした。"},{"id":6019,"en":"prose","ja":"散文\n詩（poetry）に対して、通常の文章形式の文学","level":7,"lnum":1,"ex":"The author is known for her elegant prose style.","exja":"その作家は優雅な散文スタイルで知られている。"},{"id":6020,"en":"prosecute","ja":"起訴する・訴追する\n裁判で被告を訴える法律用語","level":7,"lnum":1,"ex":"The government decided to prosecute the company for violating environmental laws.","exja":"政府は環境法違反でその会社を起訴することを決定した。"},{"id":6021,"en":"prospect","ja":"見込み・展望\n将来の可能性や見通し","level":7,"lnum":1,"ex":"There is a good prospect of rain tomorrow, so bring an umbrella.","exja":"明日は雨の見込みが高いので、傘を持ってきてください。"},{"id":6022,"en":"prosper","ja":"繁栄する\n経済的・社会的に成功し豊かになる","level":7,"lnum":1,"ex":"The small business began to prosper after the new marketing campaign.","exja":"その小規模ビジネスは新しいマーケティングキャンペーン後に繁栄し始めた。"},{"id":6023,"en":"protest","ja":"抗議する\n不満や反対意見を公に表明する","level":7,"lnum":1,"ex":"Thousands of people gathered to protest the new tax policy.","exja":"新しい税制に抗議するために数千人が集まった。"},{"id":6024,"en":"proudly","ja":"誇らしげに\n誇りや自信を持って行動する様子","level":7,"lnum":1,"ex":"She proudly displayed her medal on the shelf.","exja":"彼女は棚にメダルを誇らしげに飾った。"},{"id":6025,"en":"proven","ja":"証明された\n証拠により真実であることが確認された","level":7,"lnum":1,"ex":"His method has been proven to be effective in reducing stress.","exja":"彼の方法はストレス軽減に効果的であることが証明されている。"},{"id":6026,"en":"province","ja":"州・地方\n国内の行政区画、または専門分野のこと","level":7,"lnum":1,"ex":"He grew up in a small province far from the capital city.","exja":"彼は首都から遠く離れた小さな州で育った。"},{"id":6027,"en":"provision","ja":"規定・供給\n法律上の条項、または食料などの備え","level":7,"lnum":1,"ex":"The new law includes a provision that protects workers' rights.","exja":"新しい法律には労働者の権利を守る規定が含まれている。"},{"id":6028,"en":"proximity","ja":"近さ・近接\n物理的または概念的に近い距離","level":7,"lnum":1,"ex":"The hotel's proximity to the beach made it very popular with tourists.","exja":"そのホテルはビーチに近いため、観光客にとても人気があった。"},{"id":6029,"en":"psychologically","ja":"心理的に\n心や精神の観点から見た副詞","level":7,"lnum":1,"ex":"The experience affected him psychologically for many years.","exja":"その経験は何年もの間、心理的に彼に影響を与えた。"},{"id":6030,"en":"psychology","ja":"心理学\n人間の心や行動を研究する学問","level":7,"lnum":1,"ex":"She decided to major in psychology to better understand human behavior.","exja":"彼女は人間の行動をより深く理解するために心理学を専攻することにした。"},{"id":6031,"en":"publication","ja":"出版・発行物\n本・雑誌などを出版する行為、またはその出版物","level":7,"lnum":1,"ex":"The publication of her first novel received widespread praise.","exja":"彼女の最初の小説の出版は広く称賛を受けた。"},{"id":6032,"en":"publicity","ja":"宣伝・パブリシティ\nメディアなどを通じて注目を集めること","level":7,"lnum":1,"ex":"The charity event gained a lot of publicity through social media.","exja":"そのチャリティーイベントはソーシャルメディアを通じて大きな宣伝効果を得た。"},{"id":6033,"en":"publicize/publicise","ja":"公表する・宣伝する\n情報を広く一般に知らせる","level":7,"lnum":1,"ex":"The company publicized its new environmental policy through social media.","exja":"その会社はソーシャルメディアを通じて新しい環境政策を公表した。"},{"id":6034,"en":"pulse","ja":"脈拍・パルス\n心臓の鼓動による血液の流れ。技術的な信号にも使う","level":7,"lnum":1,"ex":"The doctor checked the patient's pulse to monitor her heart rate.","exja":"医師は心拍数を確認するために患者の脈拍を調べた。"},{"id":6035,"en":"punch","ja":"パンチ・殴打\nこぶしで打つ行為または打撃の力","level":7,"lnum":1,"ex":"She gave him a light punch on the arm as a joke.","exja":"彼女はジョークで彼の腕を軽くパンチした。"},{"id":6036,"en":"punch","ja":"パンチする・殴る\nこぶしで打つ動作を表す動詞","level":7,"lnum":1,"ex":"He punched the wall in frustration after making a mistake.","exja":"彼は失敗してフラストレーションから壁をパンチした。"},{"id":6037,"en":"punctual","ja":"時間を守る\n約束の時間に正確に来ること","level":7,"lnum":1,"ex":"She is always punctual and never misses a deadline.","exja":"彼女はいつも時間を守り、締め切りを一度も逃したことがない。"},{"id":6038,"en":"punctuality","ja":"時間を守ること\n時間厳守の習慣や性質","level":7,"lnum":1,"ex":"His punctuality is one of the reasons why his boss trusts him so much.","exja":"彼の時間厳守は、上司が彼をとても信頼している理由の一つだ。"},{"id":6039,"en":"purchase","ja":"購入・買い物\n商品を買う行為または買ったもの","level":7,"lnum":1,"ex":"He purchased a new laptop for his university studies.","exja":"彼は大学の勉強のために新しいノートパソコンを購入した。"},{"id":6040,"en":"purchase","ja":"購入する\nbuyのより公式的な言い方","level":7,"lnum":1,"ex":"She purchased a new laptop for her online classes.","exja":"彼女はオンライン授業のために新しいノートパソコンを購入した。"},{"id":6041,"en":"purposeful","ja":"目的意識のある\n明確な目標を持って行動している様子","level":7,"lnum":1,"ex":"She walked into the meeting with a purposeful stride.","exja":"彼女は目的意識のある足取りで会議に入ってきた。"},{"id":6042,"en":"pursuit","ja":"追求・追跡\n目標を追い求める行為。in pursuit ofの形でよく使う","level":7,"lnum":1,"ex":"He spent years in pursuit of his dream of becoming a professional musician.","exja":"彼はプロの音楽家になるという夢を追求して何年も過ごした。"},{"id":6043,"en":"puzzled","ja":"困惑した\n理解できずに困っている状態","level":7,"lnum":1,"ex":"She looked puzzled when she read the confusing instructions.","exja":"分かりにくい説明書を読んで、彼女は困惑した様子だった。"},{"id":6044,"en":"qualification","ja":"資格・適性\nある職や課題に必要な能力や証明書","level":7,"lnum":1,"ex":"You need a teaching qualification to apply for the position.","exja":"その職に応募するには教員資格が必要だ。"},{"id":6045,"en":"quantify","ja":"数値化する\n数値や量として表現する","level":7,"lnum":1,"ex":"It is difficult to quantify the emotional impact of the disaster.","exja":"その災害の感情的な影響を数値化するのは難しい。"},{"id":6046,"en":"quarantine","ja":"隔離・検疫\n感染症を防ぐための隔離措置","level":7,"lnum":1,"ex":"All passengers were placed in quarantine after the outbreak was detected.","exja":"感染の拡大が確認された後、すべての乗客は隔離された。"},{"id":6047,"en":"quarrel","ja":"口論・けんか\n言葉によるもめごとや争い","level":7,"lnum":1,"ex":"The two neighbors quarreled about the noise late at night.","exja":"2人の隣人は深夜の騒音をめぐって口論した。"},{"id":6048,"en":"quarrel","ja":"口論する\n言葉でもめる動詞","level":7,"lnum":1,"ex":"The siblings quarreled over who would get to use the computer first.","exja":"兄弟はどちらが先にコンピューターを使えるかで口論した。"},{"id":6049,"en":"quarrelsome","ja":"口論好きな\nすぐに言い争いを起こしやすい性格","level":7,"lnum":1,"ex":"He was so quarrelsome that nobody wanted to work with him.","exja":"彼はとても口論好きで、誰も一緒に働きたがらなかった。"},{"id":6050,"en":"queer","ja":"奇妙な・クィアの\n変わった、またはLGBTQ+を自称する言葉（文脈に注意）","level":7,"lnum":1,"ex":"She had a queer feeling that something was about to go wrong.","exja":"何かがうまくいかないという奇妙な感覚を彼女は覚えた。"},{"id":6051,"en":"query","ja":"疑問・質問\n不明点や確認のための質問","level":7,"lnum":1,"ex":"She sent a query to the customer service team about her order.","exja":"彼女は注文について顧客サービスチームに問い合わせを送った。"},{"id":6052,"en":"queue","ja":"列に並ぶ\n主にイギリス英語で使うが、米語でも広まりつつある","level":7,"lnum":1,"ex":"A long queue formed outside the store before it opened.","exja":"開店前に店の外に長い列ができた。"},{"id":6053,"en":"quotable","ja":"引用に値する\n印象的で他人に紹介したくなるような言葉","level":7,"lnum":1,"ex":"The speaker made several quotable remarks during the lecture.","exja":"講演者は講義の中でいくつかの引用に値する発言をした。"},{"id":6054,"en":"quotation","ja":"引用・見積もり\n他者の言葉の引用、または価格の見積もり","level":7,"lnum":1,"ex":"He began his speech with a quotation from Shakespeare.","exja":"彼はシェイクスピアからの引用でスピーチを始めた。"},{"id":6055,"en":"quote","ja":"引用・引用文\n他者の言葉をそのまま用いたもの","level":7,"lnum":1,"ex":"He quoted a well-known philosopher to support his argument.","exja":"彼は主張を裏付けるために著名な哲学者の言葉を引用した。"},{"id":6056,"en":"quote","ja":"引用する・見積もる\n他者の言葉を使う、または価格を提示する","level":7,"lnum":1,"ex":"The journalist quoted the politician's exact words in the article.","exja":"ジャーナリストは記事の中で政治家の言葉をそのまま引用した。"},{"id":6057,"en":"racism","ja":"人種差別\n人種に基づく不当な差別や偏見","level":7,"lnum":1,"ex":"The organization works to raise awareness about racism in the workplace.","exja":"その組織は職場における人種差別への認識を高めるために活動している。"},{"id":6058,"en":"racist","ja":"人種差別主義者\n人種差別をする人または人種差別的な考えを持つ人","level":7,"lnum":1,"ex":"The court ruled that the comment made by the official was racist.","exja":"裁判所は、その当局者が行ったコメントは人種差別的だと判断した。"},{"id":6059,"en":"rack","ja":"棚・ラック\n物を置くための棚や支え。rack one's brainは「頭を絞る」","level":7,"lnum":1,"ex":"She placed the freshly washed dishes on the drying rack.","exja":"彼女は洗い終わった食器を乾燥ラックに置いた。"},{"id":6060,"en":"radar","ja":"レーダー\n電波を使った探知システム。比喩的に「気づき」の意味でも使う","level":7,"lnum":1,"ex":"The aircraft was detected by the military radar system.","exja":"その航空機は軍のレーダーシステムに探知された。"},{"id":6061,"en":"radiate","ja":"放射する・発する\n光や熱などを周囲に向けて発する","level":7,"lnum":1,"ex":"The fireplace radiated warmth throughout the room.","exja":"暖炉は部屋全体に温もりを放射した。"},{"id":6062,"en":"radical","ja":"急進派・根本的な変革者\n既存の体制を根本から変えようとする人や考え","level":7,"lnum":1,"ex":"The new government proposed radical changes to the education system.","exja":"新政府は教育制度に根本的な変革を提案した。"},{"id":6063,"en":"radically","ja":"根本的に・過激に\n従来とは大きく異なる方法で変化する様子","level":7,"lnum":1,"ex":"The introduction of smartphones has radically changed the way we communicate.","exja":"スマートフォンの普及は私たちのコミュニケーションのあり方を根本的に変えた。"},{"id":6064,"en":"radium","ja":"ラジウム\n放射性の化学元素（記号Ra）","level":7,"lnum":1,"ex":"Marie Curie is famous for her discovery of radium.","exja":"マリー・キュリーはラジウムの発見で有名だ。"},{"id":6065,"en":"rafter","ja":"垂木（たるき）\n屋根を支える斜めの木材","level":7,"lnum":1,"ex":"The old barn had thick wooden rafters supporting the roof.","exja":"古い納屋には屋根を支える太い木製の垂木があった。"},{"id":6066,"en":"rag","ja":"ぼろ布・端切れ\n古くなった布切れ。from rags to richesは「無一文から成功」","level":7,"lnum":1,"ex":"He used an old rag to clean the oil spill in the garage.","exja":"彼はガレージの油漏れを拭き取るために古いぼろ布を使った。"},{"id":6067,"en":"rainstorm","ja":"暴風雨\n激しい雨を伴う嵐","level":7,"lnum":1,"ex":"The hiking trip was canceled because of an unexpected rainstorm.","exja":"予期しない暴風雨のために、ハイキング旅行は中止された。"},{"id":6068,"en":"rally","ja":"集会・結集\n共通の目的のための集まり、または回復すること","level":7,"lnum":1,"ex":"Supporters gathered at the rally to listen to the candidate's speech.","exja":"支持者たちは候補者のスピーチを聞くために集会に集まった。"},{"id":6069,"en":"ram","ja":"雄羊・強く押す\n雄羊、または勢いをつけて激しく押し込む","level":7,"lnum":1,"ex":"The truck accidentally rammed into the barrier at the side of the road.","exja":"トラックが誤って道路脇のバリアに激突した。"},{"id":6070,"en":"ramp","ja":"斜面・ランプ\n傾斜路または料金の急激な引き上げ（ramp up）","level":7,"lnum":1,"ex":"Workers built a ramp at the entrance to make it accessible for wheelchair users.","exja":"労働者たちは車いすユーザーが利用できるよう入口にスロープを設置した。"},{"id":6071,"en":"range","ja":"範囲にわたる・及ぶ\nある幅の中で変動する動詞用法","level":7,"lnum":1,"ex":"The temperature ranged from minus five to plus twenty degrees during the week.","exja":"その週の気温はマイナス5度からプラス20度の範囲で変動した。"},{"id":6072,"en":"ranger","ja":"レンジャー・監視員\n森や公園を管理・警備する人","level":7,"lnum":1,"ex":"The park ranger warned visitors not to feed the wild animals.","exja":"公園の監視員は訪問者に野生動物に餌を与えないよう警告した。"},{"id":6073,"en":"rape","ja":"レイプ・強姦\n性的暴行。法律・社会的文脈で使う","level":7,"lnum":1,"ex":"The law strictly punishes anyone who rapes another person.","exja":"法律は他人を性的に暴行した者を厳しく罰する。"},{"id":6074,"en":"rape","ja":"レイプする\n性的暴行を加える動詞","level":7,"lnum":1,"ex":"The victim bravely testified in court against the man who had attacked her.","exja":"被害者は自分を襲った男に対して法廷で勇敢に証言した。"},{"id":6075,"en":"rash","ja":"無謀な・軽率な\n結果を十分に考えず行動する形容詞","level":7,"lnum":1,"ex":"Making such a rash decision without thinking of the consequences could cause serious problems.","exja":"結果を考えずにそのような軽率な決断を下すことは、深刻な問題を引き起こす可能性がある。"},{"id":6076,"en":"rate","ja":"評価する・格付けする\n品質や重要度を判断して順位づける","level":7,"lnum":1,"ex":"Critics rated the film as one of the best of the decade.","exja":"批評家たちはその映画を10年間で最高の作品の一つと評価した。"},{"id":6077,"en":"rattle","ja":"がたがた音を立てる\n固い物がぶつかる音、または赤ちゃんのガラガラおもちゃ","level":7,"lnum":1,"ex":"The old car rattled noisily every time it went over a bump.","exja":"古い車は段差を乗り越えるたびにガタガタと大きな音を立てた。"},{"id":6078,"en":"ravage","ja":"破壊・惨害\n甚大なダメージを与える行為や結果","level":7,"lnum":1,"ex":"The wildfire ravaged thousands of hectares of forest in just a few days.","exja":"山火事は数日でおよそ数千ヘクタールの森林を破壊した。"},{"id":6079,"en":"reaction","ja":"反応・リアクション\n刺激や出来事に対する応答","level":7,"lnum":1,"ex":"His reaction to the surprising news was a look of total shock.","exja":"驚くべきニュースに対する彼の反応は、完全な衝撃の表情だった。"},{"id":6080,"en":"readily","ja":"すぐに・快く\n難なく喜んで行う様子","level":7,"lnum":1,"ex":"She readily agreed to help her friend move to the new apartment.","exja":"彼女は友人の新しいアパートへの引越しを快く手伝うことに同意した。"},{"id":6081,"en":"real estate","ja":"不動産\n土地や建物などの財産","level":7,"lnum":1,"ex":"Investing in real estate can be a profitable long-term strategy.","exja":"不動産への投資は、長期的に利益をもたらす戦略になり得る。"},{"id":6082,"en":"realization/realisation","ja":"認識・実現\n何かに気づくこと、または夢や計画が達成されること","level":7,"lnum":1,"ex":"She came to a sudden realization that she had left her wallet at home.","exja":"彼女は財布を家に忘れてきたことに突然気づいた。"},{"id":6083,"en":"rear","ja":"後部の・後方の\n位置が後ろ側にあることを示す形容詞","level":7,"lnum":1,"ex":"The rear entrance of the building is used by staff only.","exja":"建物の後部入口はスタッフ専用だ。"},{"id":6084,"en":"reasonably","ja":"合理的に・かなり\n適切な範囲で、またはかなりの程度で","level":7,"lnum":1,"ex":"The hotel was reasonably priced for the quality it offered.","exja":"そのホテルは提供するサービスの質に対して合理的な価格設定だった。"},{"id":6085,"en":"rebel","ja":"反逆者・反乱者\n権威や体制に反抗する人","level":7,"lnum":1,"ex":"The citizens rebelled against the government's harsh new policies.","exja":"市民たちは政府の厳しい新政策に反乱を起こした。"},{"id":6086,"en":"rebel","ja":"反乱する・反抗する\n権威や体制に抵抗する動詞","level":7,"lnum":1,"ex":"The workers rebelled against the unfair working conditions at the factory.","exja":"労働者たちは工場の不当な労働条件に反乱を起こした。"},{"id":6087,"en":"rebellious","ja":"反抗的な\n権威に従わず反乱を起こす傾向がある","level":7,"lnum":1,"ex":"The rebellious teenager refused to obey his parents' curfew.","exja":"その反抗的な10代の少年は親の外出禁止令に従うことを拒否した。"},{"id":6088,"en":"recession","ja":"景気後退\n経済が一定期間縮小している状態","level":7,"lnum":1,"ex":"Many businesses closed during the economic recession.","exja":"経済的な景気後退の間、多くの企業が閉鎖した。"},{"id":6089,"en":"reckon","ja":"思う・計算する\n非公式にconsiderやthinkの意味で使う","level":7,"lnum":1,"ex":"I reckon it will take at least three hours to finish the project.","exja":"このプロジェクトを終えるのに少なくとも3時間はかかると思う。"},{"id":6090,"en":"recognition","ja":"認識・認知・表彰\n何かを識別すること、または功績を称えること","level":7,"lnum":1,"ex":"She finally received recognition for her years of hard work.","exja":"彼女はようやく長年の努力に対して認められた。"},{"id":6091,"en":"recollect","ja":"思い出す\n過去の記憶を呼び起こす。rememberより努力を要する感じ","level":7,"lnum":1,"ex":"He could barely recollect the details of the accident.","exja":"彼はその事故の詳細をほとんど思い出せなかった。"},{"id":6092,"en":"recollection","ja":"記憶・回想\n過去の出来事を思い出す行為またはその内容","level":7,"lnum":1,"ex":"Her recollection of childhood was filled with happy memories.","exja":"彼女の子供時代の記憶は幸せな思い出で満ちていた。"},{"id":6093,"en":"recommendable","ja":"推薦に値する\n他の人に勧める価値がある","level":7,"lnum":1,"ex":"The restaurant is highly recommendable for its fresh seafood dishes.","exja":"そのレストランは新鮮なシーフード料理で、強くお勧めできる。"},{"id":6094,"en":"recommendation","ja":"推薦・勧告\n人や物を勧めること、またはその内容","level":7,"lnum":1,"ex":"The professor wrote a strong recommendation letter for his student.","exja":"教授は学生のために力強い推薦状を書いた。"},{"id":6095,"en":"reconsider","ja":"再考する\n一度決めたことを改めて考え直す","level":7,"lnum":1,"ex":"After reading the feedback, she decided to reconsider her approach.","exja":"フィードバックを読んだ後、彼女はアプローチを再考することにした。"},{"id":6096,"en":"recreation","ja":"レクリエーション・娯楽\n休暇に行う楽しい活動","level":7,"lnum":1,"ex":"Hiking and swimming are popular forms of recreation in the summer.","exja":"ハイキングと水泳は夏の人気のレクリエーションだ。"},{"id":6097,"en":"recruit","ja":"採用する・勧誘する\n新しいメンバーを組織に加える","level":7,"lnum":1,"ex":"The company is recruiting experienced engineers for its new project.","exja":"その会社は新プロジェクトのために経験豊富なエンジニアを採用している。"},{"id":6098,"en":"rectangular","ja":"長方形の\n四つの直角を持つ長方形の形","level":7,"lnum":1,"ex":"The park has a large rectangular fountain in its center.","exja":"その公園の中央には大きな長方形の噴水がある。"},{"id":6099,"en":"redo","ja":"やり直す\nすでに行ったことを再度行う","level":7,"lnum":1,"ex":"The contractor had to redo the entire floor after finding a major crack.","exja":"業者は大きなひび割れを発見した後、床全体をやり直さなければならなかった。"},{"id":6100,"en":"redundant","ja":"余分な・不要な\nイギリス英語では解雇されたという意味でも使う","level":7,"lnum":1,"ex":"The second paragraph of the report is redundant and should be removed.","exja":"報告書の2番目の段落は余分なので削除するべきだ。"},{"id":6101,"en":"reed","ja":"葦・リード\n水辺に生える植物、または楽器の振動板","level":7,"lnum":1,"ex":"The musician played a haunting melody on a traditional reed instrument.","exja":"音楽家は伝統的なリード楽器で物悲しいメロディーを演奏した。"},{"id":6102,"en":"reference","ja":"参考・言及\n情報源として参照すること、または言及すること","level":7,"lnum":1,"ex":"She mentioned several academic references to support her argument.","exja":"彼女は主張を裏付けるためにいくつかの学術的な参考文献を挙げた。"},{"id":6103,"en":"referent","ja":"指示対象の\n言語記号が指し示すものに関する形容詞（言語学用語）","level":7,"lnum":1,"ex":"In linguistics, a referent is the actual object that a word refers to.","exja":"言語学では、指示対象とは単語が指す実際の物体のことだ。"},{"id":6104,"en":"refinery","ja":"精製所\n石油・砂糖などを精製する工場","level":7,"lnum":1,"ex":"The oil refinery operated day and night to meet the nation's energy demands.","exja":"その石油精製所は国のエネルギー需要を満たすために昼夜を問わず稼働した。"},{"id":6105,"en":"reflective","ja":"反省的な・反射性の\n深く考えている様子、または光を反射する性質","level":7,"lnum":1,"ex":"She spent the evening in a reflective mood, thinking about her future plans.","exja":"彼女は将来の計画について考えながら、内省的な気分で夕方を過ごした。"},{"id":6106,"en":"reform","ja":"改革・改正\n制度や慣行を改善するための変更","level":7,"lnum":1,"ex":"The government introduced sweeping reforms to improve the healthcare system.","exja":"政府は医療制度を改善するための大規模な改革を導入した。"},{"id":6107,"en":"refrain","ja":"控える・繰り返し部分\n歌の繰り返しサビ。refrain fromで「〜を控える」","level":7,"lnum":1,"ex":"Please refrain from using your phone during the performance.","exja":"公演中は携帯電話の使用をお控えください。"},{"id":6108,"en":"refresh","ja":"リフレッシュ・更新\nエネルギーを回復する、またはデータを最新に更新する","level":7,"lnum":1,"ex":"A cold glass of water is a great way to refresh yourself after exercise.","exja":"運動後に自分をリフレッシュするには、冷たいコップ一杯の水が最適だ。"},{"id":6109,"en":"refuge","ja":"避難所・避難\n危険や困難から逃れるための安全な場所","level":7,"lnum":1,"ex":"The abandoned house served as a refuge for the stray cats.","exja":"その廃屋は野良猫たちの避難所となっていた。"},{"id":6110,"en":"refugee","ja":"難民\n戦争・迫害などから逃れてきた人","level":7,"lnum":1,"ex":"The government set up camps to provide shelter for refugees from the war zone.","exja":"政府は戦闘地域からの難民に避難所を提供するためのキャンプを設けた。"},{"id":6111,"en":"refute","ja":"論破する・否定する\n証拠を示して主張が誤りであることを証明する","level":7,"lnum":1,"ex":"The scientist refuted the theory by presenting new experimental data.","exja":"科学者は新しい実験データを提示することで、その理論を論破した。"},{"id":6112,"en":"regard","ja":"配慮・みなし\n〜と見なす（regard A as B）の形でよく使う","level":7,"lnum":1,"ex":"She regards honesty as the most important quality in a friend.","exja":"彼女は誠実さを友人に最も重要な資質と見なしている。"},{"id":6113,"en":"regardless","ja":"かかわらず\nregardless ofで「〜に関係なく」の意味","level":7,"lnum":1,"ex":"Regardless of the weather, the outdoor event will go on as planned.","exja":"天気に関係なく、屋外イベントは予定通り行われる。"},{"id":6114,"en":"reggae","ja":"レゲエ\nジャマイカ発祥の音楽ジャンル","level":7,"lnum":1,"ex":"Bob Marley helped spread reggae music around the world.","exja":"ボブ・マーリーはレゲエ音楽を世界中に広めるのに貢献した。"},{"id":6115,"en":"regime","ja":"体制・政権\n特定の統治システムや政治体制","level":7,"lnum":1,"ex":"The country suffered greatly under the oppressive regime for decades.","exja":"その国は数十年間、抑圧的な政権下で多大な苦難を受けた。"},{"id":6116,"en":"regret","ja":"後悔・遺憾\n過去の行動を残念に思う気持ち","level":7,"lnum":1,"ex":"She regretted not studying harder before the final exam.","exja":"彼女は期末試験の前にもっと一生懸命勉強しなかったことを後悔した。"},{"id":6117,"en":"regrettably","ja":"残念ながら\ndisappointinglyと同義だがやや格式張った副詞","level":7,"lnum":1,"ex":"Regrettably, the event had to be canceled due to lack of funding.","exja":"残念ながら、資金不足のためイベントを中止せざるを得なかった。"},{"id":6118,"en":"regulate","ja":"規制する・調整する\n規則や法律で管理・制御する","level":7,"lnum":1,"ex":"The government passed a new law to regulate the use of social media by minors.","exja":"政府は未成年者のソーシャルメディア使用を規制する新しい法律を制定した。"},{"id":6119,"en":"rehearsal","ja":"リハーサル・練習\n本番前の練習。dress rehearsalは最終リハーサル","level":7,"lnum":1,"ex":"The final rehearsal for the school play took place the day before the performance.","exja":"学校劇の最終リハーサルは公演前日に行われた。"},{"id":6120,"en":"reinforce","ja":"強化する・補強する\n既存のものをさらに強くする","level":7,"lnum":1,"ex":"The company added new safety measures to reinforce employee protection.","exja":"その会社は従業員の保護を強化するために新しい安全対策を追加した。"},{"id":6121,"en":"reinforcement","ja":"強化・補強\n何かをより強くする行為またはその手段","level":7,"lnum":1,"ex":"The use of positive reinforcement can be very effective in motivating students.","exja":"ポジティブな強化を使うことは、生徒のやる気を引き出すのに非常に効果的だ。"},{"id":6122,"en":"rejection","ja":"拒絶・却下\n申し込みや提案を断ること","level":7,"lnum":1,"ex":"She was disappointed by the rejection of her job application.","exja":"彼女は就職応募が却下されてがっかりした。"},{"id":6123,"en":"rejoin","ja":"再合流する・再入会する\n一度離れたグループや場所に戻る","level":7,"lnum":1,"ex":"He rejoined the company after taking a year off to travel.","exja":"彼は1年間旅行のために休職した後、会社に復帰した。"},{"id":6124,"en":"related","ja":"関連した\n何かと関係・つながりがある状態","level":7,"lnum":1,"ex":"These two incidents are closely related and should be investigated together.","exja":"この2つの出来事は密接に関連しており、一緒に調査されるべきだ。"},{"id":6125,"en":"relativity","ja":"相対性\nアインシュタインの相対性理論で有名な概念","level":7,"lnum":1,"ex":"Einstein's theory of relativity changed the way scientists understand time and space.","exja":"アインシュタインの相対性理論は、科学者が時間と空間を理解する方法を変えた。"},{"id":6126,"en":"relaxation","ja":"リラックス・緩和\n緊張を解いて休む状態、または規制の緩和","level":7,"lnum":1,"ex":"A warm bath is perfect for relaxation after a long and stressful day.","exja":"温かいお風呂は長くストレスの多い1日の後のリラックスに最適だ。"},{"id":6127,"en":"relevant","ja":"関連性のある\n議論や状況に関係があり重要な","level":7,"lnum":1,"ex":"Make sure your cover letter includes only relevant work experience.","exja":"カバーレターには関連する職歴のみを記載するようにしてください。"},{"id":6128,"en":"relic","ja":"遺物・遺跡\n過去の時代から残ったもの","level":7,"lnum":1,"ex":"The ancient temple was preserved as a relic of the civilization.","exja":"その古代の神殿は文明の遺物として保存されていた。"},{"id":6129,"en":"relief","ja":"安堵・救済\n不安が解消される気持ち、または困っている人への支援","level":7,"lnum":1,"ex":"She felt a great sense of relief when she heard the test results were negative.","exja":"検査結果が陰性だと聞いて、彼女は大きな安堵感を覚えた。"},{"id":6130,"en":"relieve","ja":"和らげる・安堵させる\n痛みや苦しみを軽減する","level":7,"lnum":1,"ex":"The cold compress helped relieve the pain from the bruise.","exja":"冷湿布はあざの痛みを和らげるのに役立った。"},{"id":6131,"en":"relieved","ja":"ほっとした\n心配が解消されて安心した状態","level":7,"lnum":1,"ex":"He was relieved to find out that no one was hurt in the accident.","exja":"事故でけが人がいないと分かって、彼はほっとした。"},{"id":6132,"en":"reluctant","ja":"気が進まない・渋る\nしたくないが仕方なくやる気持ち","level":7,"lnum":1,"ex":"She was reluctant to accept the offer without reading the contract carefully.","exja":"彼女は契約書をよく読まずに申し出を受け入れることに気が進まなかった。"},{"id":6133,"en":"remaining","ja":"残りの\nまだ残っている状態を示す形容詞","level":7,"lnum":1,"ex":"There are only five remaining tickets for the concert.","exja":"コンサートのチケットは残り5枚だけだ。"},{"id":6134,"en":"remains","ja":"残骸・遺骨\n残ったもの。複数形で使うことが多い","level":7,"lnum":1,"ex":"The remains of the ancient city were discovered beneath the modern town.","exja":"現代の町の下に古代都市の残骸が発見された。"},{"id":6135,"en":"remark","ja":"発言・コメント\nある話題についての意見や気づきの一言","level":7,"lnum":1,"ex":"She made a remark about how quiet the office had become.","exja":"彼女はオフィスがとても静かになったことについてコメントした。"},{"id":6136,"en":"remarkably","ja":"著しく・目立って\n通常より際立って","level":7,"lnum":1,"ex":"The student improved remarkably in just a few months of studying.","exja":"その生徒はわずか数ヶ月の学習で著しく上達した。"},{"id":6137,"en":"reminder","ja":"リマインダー・思い出させるもの\n忘れないよう知らせるための合図やメッセージ","level":7,"lnum":1,"ex":"He set a reminder on his phone so he wouldn't forget the meeting.","exja":"彼は会議を忘れないよう、スマートフォンにリマインダーを設定した。"},{"id":6138,"en":"reorganize/reorganise","ja":"再編成する\n組織や物を改めて整理・構成し直す","level":7,"lnum":1,"ex":"The company reorganized its departments to improve communication and efficiency.","exja":"その会社はコミュニケーションと効率を改善するために部門を再編成した。"},{"id":6139,"en":"repaint","ja":"塗り直し\n再度ペンキなどを塗る行為または名詞","level":7,"lnum":1,"ex":"The landlord agreed to repaint the walls before the new tenants moved in.","exja":"大家は新しい入居者が引っ越す前に壁を塗り直すことに同意した。"},{"id":6140,"en":"repertoire","ja":"レパートリー\n演奏者や演者が実演できる作品の一覧","level":7,"lnum":1,"ex":"The pianist's repertoire includes both classical and contemporary pieces.","exja":"そのピアニストのレパートリーはクラシックと現代曲の両方を含む。"},{"id":6141,"en":"repetition","ja":"繰り返し\n同じことを何度も行うこと","level":7,"lnum":1,"ex":"The teacher used repetition to help the students memorize the vocabulary.","exja":"教師は生徒が語彙を覚えられるように繰り返しを用いた。"},{"id":6142,"en":"replacement","ja":"代替・交換\n元のものに代わるものを入れること","level":7,"lnum":1,"ex":"The old machine needed a replacement because it kept breaking down.","exja":"古い機械は故障が続いていたため、交換が必要だった。"},{"id":6143,"en":"replica","ja":"複製品・レプリカ\n本物を正確に模した複製","level":7,"lnum":1,"ex":"The museum displayed an exact replica of the famous painting.","exja":"博物館はその有名な絵画の精巧な複製品を展示していた。"},{"id":6144,"en":"repress","ja":"抑圧する・抑制する\n感情や行動を力で押さえ込む","level":7,"lnum":1,"ex":"He repressed his emotions and refused to talk about the accident.","exja":"彼は感情を抑え込み、その事故について話すことを拒否した。"},{"id":6145,"en":"repression","ja":"抑圧・弾圧\n自由や感情を力で抑え込む行為","level":7,"lnum":1,"ex":"The repression of free speech caused widespread anger among the population.","exja":"言論の自由の抑圧は、国民の間に広範な怒りを引き起こした。"},{"id":6146,"en":"reprint","ja":"重版・再印刷\n本や文書を再び印刷すること","level":7,"lnum":1,"ex":"The popular novel went into its tenth reprint within a year of publication.","exja":"その人気小説は出版から1年以内に10回目の重版を迎えた。"},{"id":6147,"en":"reprove","ja":"叱責する・たしなめる\n誰かの行動を穏やかに批判する","level":7,"lnum":1,"ex":"The teacher gently reproved the student for arriving late to class.","exja":"先生は授業に遅れて来た生徒を穏やかにたしなめた。"},{"id":6148,"en":"residence","ja":"住居・居住\n人が住む場所、または住んでいる事実","level":7,"lnum":1,"ex":"He moved his official residence to the capital after being elected.","exja":"当選後、彼は公式の住居を首都に移した。"},{"id":6149,"en":"resign","ja":"辞職する\n職や地位を自分から辞める","level":7,"lnum":1,"ex":"The director resigned from her position due to health reasons.","exja":"理事は健康上の理由で役職を辞職した。"},{"id":6150,"en":"resignation","ja":"辞職・辞表\n職を辞めること、またはその通知。やむを得ない諦めの意味もある","level":7,"lnum":1,"ex":"His sudden resignation shocked the entire company.","exja":"彼の突然の辞職は会社全体を驚かせた。"},{"id":6151,"en":"resistance","ja":"抵抗・反抗\n力や圧力に対して逆らうこと","level":7,"lnum":1,"ex":"The new drug faced strong resistance from traditional medical practitioners.","exja":"新薬は伝統的な医療従事者から強い抵抗に直面した。"},{"id":6152,"en":"resolution","ja":"決意・解決・決議\n問題の解決、または正式な決定・誓い","level":7,"lnum":1,"ex":"She made a firm resolution to exercise every morning from the new year.","exja":"彼女は新年から毎朝運動するという固い決意を固めた。"},{"id":6153,"en":"resonant","ja":"共鳴する・響く\n音が豊かに響く様子、または強い印象を与える","level":7,"lnum":1,"ex":"His deep, resonant voice filled the entire lecture hall.","exja":"彼の深く共鳴する声は講義室全体に響き渡った。"},{"id":6154,"en":"respectably","ja":"立派に・きちんと\n社会的に認められる水準で行動する様子","level":7,"lnum":1,"ex":"She performed respectably at the competition, finishing in the top ten.","exja":"彼女は競技会でトップ10に入り、立派な成績を収めた。"},{"id":6155,"en":"respected","ja":"尊敬される\n高い評価を受けている状態","level":7,"lnum":1,"ex":"He is a highly respected professor known for his research in biology.","exja":"彼は生物学の研究で知られる非常に尊敬される教授だ。"},{"id":6156,"en":"respiration","ja":"呼吸\n酸素を取り入れ二酸化炭素を排出する生理的プロセス","level":7,"lnum":1,"ex":"Normal respiration requires both the lungs and the diaphragm to work together.","exja":"通常の呼吸には、肺と横隔膜が協調して働くことが必要だ。"},{"id":6157,"en":"respiratory","ja":"呼吸の\n呼吸器系に関する形容詞","level":7,"lnum":1,"ex":"The doctor was concerned about the patient's respiratory problems.","exja":"医師は患者の呼吸器系の問題を懸念していた。"},{"id":6158,"en":"restriction","ja":"制限・規制\n自由に行動できる範囲を狭める決まり","level":7,"lnum":1,"ex":"The government imposed a restriction on the number of cars allowed in the city center.","exja":"政府は市の中心部への車の乗り入れ台数に制限を設けた。"},{"id":6159,"en":"resume","ja":"再開する\n一時中断したことを続ける。履歴書のresume（レジュメ）とは別語","level":7,"lnum":1,"ex":"After a short break, the meeting resumed with a discussion of the budget.","exja":"短い休憩の後、会議は予算の議論で再開された。"},{"id":6160,"en":"retailer","ja":"小売業者\n消費者に直接商品を販売する事業者","level":7,"lnum":1,"ex":"The retailer decided to lower prices to attract more customers.","exja":"その小売業者は顧客をより多く引き付けるために価格を下げることにした。"},{"id":6161,"en":"retard","ja":"遅らせる\n進展や発達を妨げて遅くする","level":7,"lnum":1,"ex":"Lack of sunlight can retard the growth of young plants.","exja":"日光不足は若い植物の成長を遅らせる可能性がある。"},{"id":6162,"en":"retina","ja":"網膜\n目の内側にある光を感知する組織","level":7,"lnum":1,"ex":"The doctor used a special light to examine the patient's retina.","exja":"医師は患者の網膜を調べるために特殊な光を使用した。"},{"id":6163,"en":"retirement","ja":"退職・引退\n職業活動から引退すること","level":7,"lnum":1,"ex":"He threw a party to celebrate his retirement after thirty years of service.","exja":"彼は30年間の勤務を終えた退職を祝うためにパーティーを開いた。"},{"id":6164,"en":"retreat","ja":"撤退・退避\n危険や困難から離れる動き、またはリトリート（研修合宿）","level":7,"lnum":1,"ex":"The team went on a weekend retreat to plan the company's future strategy.","exja":"チームは会社の将来の戦略を立案するために週末のリトリートに出かけた。"},{"id":6165,"en":"retreat","ja":"撤退する\n後退して安全な場所に移動する","level":7,"lnum":1,"ex":"The army was forced to retreat after suffering heavy losses in the battle.","exja":"軍は戦闘で大きな損害を受けた後、撤退を余儀なくされた。"},{"id":6166,"en":"retrieve","ja":"取り戻す・検索する\nなくしたものを回収する、またはデータを取り出す","level":7,"lnum":1,"ex":"The dog was trained to retrieve the ball and bring it back to its owner.","exja":"その犬はボールを取ってきて飼い主に戻すよう訓練されていた。"},{"id":6167,"en":"revelation","ja":"啓示・暴露\n隠れていた事実が明らかになること","level":7,"lnum":1,"ex":"The revelation that the company had been hiding its losses shocked investors.","exja":"その会社が損失を隠していたという暴露は投資家を驚かせた。"},{"id":6168,"en":"revenge","ja":"復讐\n受けた被害に対して仕返しをする行為","level":7,"lnum":1,"ex":"He sought revenge against those who had wronged him.","exja":"彼は自分を傷つけた者たちへの復讐を求めた。"},{"id":6169,"en":"revenue","ja":"収益・歳入\n事業や税金による収入","level":7,"lnum":1,"ex":"The city's revenue from tourism increased significantly last year.","exja":"昨年、市の観光収入が大幅に増加した。"},{"id":6170,"en":"reverence","ja":"崇敬・敬意\n深い尊敬の気持ち","level":7,"lnum":1,"ex":"The students showed great reverence for the elderly professor.","exja":"学生たちは年配の教授に深い崇敬の念を示した。"},{"id":6171,"en":"reverse","ja":"逆にする・後退させる\n方向や順序を逆にする、または車をバックさせる","level":7,"lnum":1,"ex":"The car reversed slowly out of the parking space.","exja":"車は駐車スペースからゆっくりとバックして出た。"},{"id":6172,"en":"revival","ja":"復活・再生\n衰退したものが再び盛んになること","level":7,"lnum":1,"ex":"The revival of traditional crafts has attracted younger generations.","exja":"伝統工芸の復活は若い世代を引き付けている。"},{"id":6173,"en":"revive","ja":"復活する・生き返らせる\n消えかけていたものを再び元気づける","level":7,"lnum":1,"ex":"The paramedics worked to revive the unconscious patient at the scene.","exja":"救急救命士は現場で意識不明の患者を蘇生させるために努力した。"},{"id":6174,"en":"revolution","ja":"革命\n根本的な変化、または一回転","level":7,"lnum":1,"ex":"The industrial revolution transformed the way people lived and worked.","exja":"産業革命は人々の生活と働き方を変革した。"},{"id":6175,"en":"revolutionary","ja":"革命的な\n既存のものを根本から変える革新的な様子","level":7,"lnum":1,"ex":"The invention of the internet was a revolutionary step in human communication.","exja":"インターネットの発明は人類のコミュニケーションにおける革命的な一歩だった。"},{"id":6176,"en":"revolutionize/revolutionise","ja":"革命的に変える\nある分野を根本から変える","level":7,"lnum":1,"ex":"The invention of the internet revolutionized the way people communicate.","exja":"インターネットの発明は人々のコミュニケーション方法を革命的に変えた。"},{"id":6177,"en":"revolve","ja":"回転する・中心に置く\n軸を中心に回る。revolved aroundで「〜を中心に」","level":7,"lnum":1,"ex":"The earth revolves around the sun once every 365 days.","exja":"地球は365日で一度、太陽を中心に回転する。"},{"id":6178,"en":"reward","ja":"報いる・報酬を与える\n努力や行動に対して見返りを与える","level":7,"lnum":1,"ex":"The company rewarded its employees with a bonus for their excellent performance.","exja":"会社は優れた業績に対して従業員にボーナスで報いた。"},{"id":6179,"en":"rhinoceros","ja":"サイ\n大型の有蹄類動物。rhinoと略すことが多い","level":7,"lnum":1,"ex":"The rhinoceros is one of the most endangered large animals in the world.","exja":"サイは世界で最も絶滅の危機に瀕している大型動物の一つだ。"},{"id":6180,"en":"rhyme","ja":"韻を踏む\n語尾の音が一致する詩の技法","level":7,"lnum":1,"ex":"The poet chose words that rhyme to create a musical effect in the verse.","exja":"詩人は詩に音楽的な効果を生み出すために韻を踏む言葉を選んだ。"},{"id":6181,"en":"rhythmic","ja":"リズミカルな\n一定のリズムを持つ規則的な動きや音","level":7,"lnum":1,"ex":"The dancer's rhythmic movements mesmerized the audience.","exja":"ダンサーのリズミカルな動きは観客を魅了した。"},{"id":6182,"en":"rib","ja":"肋骨・あばら骨\n胸部を守る骨。料理では「リブ」とも呼ばれる","level":7,"lnum":1,"ex":"She bruised a rib when she fell off her bicycle.","exja":"彼女は自転車から落ちて肋骨を打撲した。"},{"id":6183,"en":"riddle","ja":"なぞなぞ・謎\n答えを当てさせる問いかけ","level":7,"lnum":1,"ex":"He spent an hour trying to solve the riddle before giving up.","exja":"彼はあきらめる前に1時間なぞなぞを解こうとした。"},{"id":6184,"en":"rider","ja":"乗り手\n馬や自転車などに乗る人。契約の付帯条項の意味もある","level":7,"lnum":1,"ex":"The skilled rider guided the horse effortlessly through the obstacle course.","exja":"熟練した乗り手は障害物コースを難なく馬を導いた。"},{"id":6185,"en":"ridge","ja":"尾根・棟\n山の頂上付近の細長い部分、または屋根の棟","level":7,"lnum":1,"ex":"They reached the rocky ridge just before sunset and enjoyed the breathtaking view.","exja":"彼らは日没直前に岩だらけの尾根に到達し、息をのむような景色を楽しんだ。"},{"id":6186,"en":"righteousness","ja":"正義・徳\n道徳的に正しい行動や考え方","level":7,"lnum":1,"ex":"He devoted his life to the pursuit of righteousness and justice for all.","exja":"彼はすべての人のための正義と徳の追求に人生をささげた。"},{"id":6187,"en":"rightly","ja":"正当に・正しく\n当然の理由や根拠をもって","level":7,"lnum":1,"ex":"She was rightly criticized for her irresponsible behavior.","exja":"彼女は無責任な行動を正当に批判された。"},{"id":6188,"en":"rim","ja":"縁・へり\n円形のものの外側の端","level":7,"lnum":1,"ex":"He tapped the rim of his glass with a spoon to get everyone's attention.","exja":"彼はグラスの縁をスプーンで叩いてみんなの注意を引いた。"},{"id":6189,"en":"rip","ja":"裂く・引き裂く\n勢いよく引っ張って破る","level":7,"lnum":1,"ex":"She accidentally ripped her dress when she caught it on the door handle.","exja":"ドアハンドルに引っかけて、彼女は誤ってドレスを引き裂いてしまった。"},{"id":6190,"en":"risky","ja":"危険な・リスクの高い\n失敗や損害の可能性が高い状態","level":7,"lnum":1,"ex":"Investing all your savings in one stock is a risky financial decision.","exja":"すべての貯蓄を一つの株に投資することは、リスクの高い金融上の決断だ。"},{"id":6191,"en":"rite","ja":"儀式・式典\n宗教的または社会的な正式な行事","level":7,"lnum":1,"ex":"The graduation ceremony is considered a rite of passage into adulthood.","exja":"卒業式は大人への通過儀礼と見なされている。"},{"id":6192,"en":"ritual","ja":"儀式・習慣的な行為\n繰り返される決まった行動または宗教的儀式","level":7,"lnum":1,"ex":"Every morning, she followed the same ritual of making tea and reading the news.","exja":"毎朝、彼女はお茶を淹れてニュースを読むという同じ習慣的な行為を行っていた。"},{"id":6193,"en":"rival","ja":"競争相手\n同じ目標を争う相手","level":7,"lnum":1,"ex":"The two companies have been fierce rivals in the smartphone market for years.","exja":"その2社は何年もの間、スマートフォン市場で激しい競争相手だった。"},{"id":6194,"en":"roam","ja":"うろつく・さまよう\n目的なく広い範囲を歩き回る","level":7,"lnum":1,"ex":"The children were allowed to roam freely in the large garden.","exja":"子どもたちは広い庭を自由に歩き回ることを許された。"},{"id":6195,"en":"roar","ja":"吠える・轟音を立てる\nライオンのような大きな声を出す","level":7,"lnum":1,"ex":"The crowd roared with excitement when the team scored the winning goal.","exja":"チームが決勝点を決めたとき、群衆は興奮して轟音を立てた。"},{"id":6196,"en":"rocky","ja":"岩だらけの・不安定な\n岩が多い地形、または困難が多い状況","level":7,"lnum":1,"ex":"The relationship between the two countries has been rocky for decades.","exja":"2国間の関係は数十年間不安定だった。"},{"id":6197,"en":"roommate","ja":"ルームメイト\n同じ部屋や住居を共有する人","level":7,"lnum":1,"ex":"Her roommate was very tidy and kept the apartment spotlessly clean.","exja":"彼女のルームメイトはとても几帳面で、アパートをきれいに保っていた。"},{"id":6198,"en":"rosy","ja":"バラ色の・楽観的な\n明るく希望に満ちた見通し。やや楽観的すぎる含みもある","level":7,"lnum":1,"ex":"The economic forecast for next year looks quite rosy.","exja":"来年の経済見通しはかなり楽観的に見える。"},{"id":6199,"en":"royalty","ja":"王族・ロイヤルティ\n王室の人々、または著作権使用料","level":7,"lnum":1,"ex":"The author earned a significant amount in royalties from the sale of her books.","exja":"その作家は本の販売から相当な額の印税を得た。"},{"id":6200,"en":"rub","ja":"こする・摩擦する\n表面に圧力をかけてこする動作","level":7,"lnum":1,"ex":"She rubbed her tired eyes after staring at the screen for hours.","exja":"何時間も画面を見つめた後、彼女は疲れた目をこすった。"},{"id":6201,"en":"rubble","ja":"瓦礫・がれき\n壊れた建物などの破片","level":7,"lnum":1,"ex":"Rescue workers searched through the rubble for survivors after the earthquake.","exja":"救助隊員たちは地震後、瓦礫の中で生存者を探した。"},{"id":6202,"en":"ruinous","ja":"破滅的な\n深刻な損害や損失をもたらす","level":7,"lnum":1,"ex":"The ruinous cost of the construction project shocked the city council.","exja":"建設プロジェクトの破滅的な費用は市議会を驚かせた。"},{"id":6203,"en":"rural","ja":"農村の・地方の\n都市でなく農村や田舎に関する","level":7,"lnum":1,"ex":"She preferred the peaceful life of a rural village over the busy city.","exja":"彼女は忙しい都会よりも農村の静かな生活を好んだ。"},{"id":6204,"en":"rush hour","ja":"ラッシュアワー\n通勤・通学で道路や交通機関が混雑する時間帯","level":7,"lnum":1,"ex":"Traffic is always terrible during rush hour on weekday mornings.","exja":"平日の朝のラッシュアワー時は、いつも交通渋滞がひどい。"},{"id":6205,"en":"rusty","ja":"錆びた・腕が鈍った\n金属が錆びた状態、またはしばらく使っていない技術","level":7,"lnum":1,"ex":"After not speaking French for ten years, her language skills had become a little rusty.","exja":"10年間フランス語を話さなかったため、彼女の語学力は少し鈍ってしまっていた。"},{"id":6206,"en":"sack","ja":"解雇する\nイギリス英語でfireと同義の口語表現","level":7,"lnum":1,"ex":"The manager was sacked after the company's profits fell sharply.","exja":"会社の利益が急落した後、マネージャーは解雇された。"},{"id":6207,"en":"safeguard","ja":"守る・保護する\n危険から保護するための措置を講じる","level":7,"lnum":1,"ex":"The new law was introduced to safeguard the rights of young workers.","exja":"若い労働者の権利を守るために新しい法律が制定された。"},{"id":6208,"en":"sag","ja":"たるむ・垂れ下がる\n重さや老化で中央が下がる状態","level":7,"lnum":1,"ex":"The old mattress had begun to sag in the middle after years of use.","exja":"古いマットレスは長年の使用で真ん中がたるみ始めていた。"},{"id":6209,"en":"sage","ja":"賢人・セージ\n知恵者、またはハーブのセージ","level":7,"lnum":1,"ex":"The sage gave thoughtful advice to all who sought his wisdom.","exja":"その賢人は知恵を求めてやってくるすべての人に深く考えられたアドバイスを与えた。"},{"id":6210,"en":"salary","ja":"給料\n月給や年俸として支払われる固定の報酬","level":7,"lnum":1,"ex":"She negotiated a higher salary before accepting the job offer.","exja":"彼女は求人を受け入れる前に、より高い給料を交渉した。"},{"id":6211,"en":"salesmanship","ja":"販売術・セールス技術\n商品を効果的に売る能力","level":7,"lnum":1,"ex":"His excellent salesmanship allowed him to close deals that others couldn't.","exja":"彼の優れた販売術により、他の人ができない取引を成立させることができた。"},{"id":6212,"en":"salesperson","ja":"販売員\n性別を問わず使える現代的な表現","level":7,"lnum":1,"ex":"The salesperson explained all the features of the car before the test drive.","exja":"試乗前に販売員は車のすべての特徴を説明した。"},{"id":6213,"en":"saleswoman","ja":"女性販売員\n女性の販売員を指す呼称","level":7,"lnum":1,"ex":"The saleswoman helped the customer find a dress that suited her perfectly.","exja":"その女性販売員は顧客が完璧に似合うドレスを見つけるのを手伝った。"},{"id":6214,"en":"salon","ja":"サロン・美容院\n美容施設または社交的な集まりの場","level":7,"lnum":1,"ex":"She made an appointment at the hair salon for a cut and color.","exja":"彼女は美容院でカットとカラーの予約をした。"},{"id":6215,"en":"salsa","ja":"サルサ（ソース・ダンス）\nメキシコ料理のソース、またはラテン音楽のダンス","level":7,"lnum":1,"ex":"They danced to upbeat salsa music at the Latin festival.","exja":"彼らはラテンフェスティバルで陽気なサルサ音楽に合わせて踊った。"},{"id":6216,"en":"sandstone","ja":"砂岩\n砂が固まってできた岩石の一種","level":7,"lnum":1,"ex":"The ancient ruins were built with blocks of red sandstone.","exja":"その古代の遺跡は赤い砂岩のブロックで作られていた。"},{"id":6217,"en":"sanitary","ja":"衛生的な\n清潔で健康に害のない状態を保つ","level":7,"lnum":1,"ex":"All food preparation areas must be kept in sanitary condition at all times.","exja":"食品調理エリアはすべて常に衛生的な状態に保たなければならない。"},{"id":6218,"en":"sanitation","ja":"衛生設備・下水処理\n公衆衛生のためのインフラ整備","level":7,"lnum":1,"ex":"Improving sanitation in rural areas is essential for preventing disease.","exja":"農村地域の衛生設備を改善することは、病気の予防に不可欠だ。"},{"id":6219,"en":"satisfactory","ja":"満足のいく\n要求や基準を十分に満たしている","level":7,"lnum":1,"ex":"The teacher told him that his work was satisfactory but could be improved.","exja":"先生は彼の作業は満足のいくものだが、改善の余地があると伝えた。"},{"id":6220,"en":"saving/savings","ja":"貯蓄・節約\n将来のために蓄えたお金または節約した費用","level":7,"lnum":1,"ex":"She put most of her savings into a retirement fund for the future.","exja":"彼女は将来のために貯蓄のほとんどを退職基金に入れた。"},{"id":6221,"en":"saw","ja":"のこぎりで切る\nのこぎりを使って切断する動詞用法","level":7,"lnum":1,"ex":"He sawed the wooden plank in half to fit it through the doorway.","exja":"彼はドアを通すために木の板を半分にのこぎりで切った。"},{"id":6222,"en":"scan","ja":"スキャンする・ざっと見る\nデジタル化する、または素早く全体を見渡す","level":7,"lnum":1,"ex":"The doctor scanned the patient's brain to check for any abnormalities.","exja":"医師は異常がないか確認するために患者の脳をスキャンした。"},{"id":6223,"en":"scandal","ja":"スキャンダル・不祥事\n社会的に問題となる不名誉な事件","level":7,"lnum":1,"ex":"The financial scandal forced several executives to resign from the company.","exja":"その財務スキャンダルにより、数人の幹部が会社を辞職することを余儀なくされた。"},{"id":6224,"en":"scar","ja":"傷跡\n傷が治った後に残る跡。心の傷の意味でも使う","level":7,"lnum":1,"ex":"He had a small scar on his chin from a childhood accident.","exja":"彼は子供の頃の事故で顎に小さな傷跡があった。"},{"id":6225,"en":"scarcely","ja":"ほとんど〜ない\nhardlyとほぼ同義の否定的副詞","level":7,"lnum":1,"ex":"She had scarcely arrived home when the phone started ringing.","exja":"彼女が帰宅したとたん、電話が鳴り始めた。"},{"id":6226,"en":"scarlet","ja":"緋色の・真っ赤な\n鮮やかな赤色。Scarlet feverは猩紅熱","level":7,"lnum":1,"ex":"The scarlet leaves of the maple trees lit up the autumn landscape.","exja":"カエデの木の緋色の葉が秋の風景を明るく照らした。"},{"id":6227,"en":"scent","ja":"香り・香水\nにおいを指す名詞","level":7,"lnum":1,"ex":"She followed the sweet scent of flowers all the way to the garden.","exja":"彼女は甘い花の香りをたどって庭まで行った。"},{"id":6228,"en":"scheduled","ja":"予定された\n事前に計画・日程に組み込まれた状態","level":7,"lnum":1,"ex":"The flight is scheduled to depart at nine o'clock tomorrow morning.","exja":"フライトは明日の朝9時に出発する予定だ。"},{"id":6229,"en":"scheme","ja":"計画・策略\n詳細な計画。悪意ある策略のニュアンスを持つこともある","level":7,"lnum":1,"ex":"The government introduced a new scheme to help small businesses recover.","exja":"政府は中小企業の回復を助けるための新しい計画を導入した。"},{"id":6230,"en":"scholasticism","ja":"スコラ哲学\n中世ヨーロッパの神学と哲学を統合した思想体系","level":7,"lnum":1,"ex":"Scholasticism attempted to reconcile faith with reason in medieval Europe.","exja":"スコラ哲学は中世ヨーロッパで信仰と理性を調和させようとした。"},{"id":6231,"en":"schoolgirl","ja":"女学生\n学校に通う女子生徒","level":7,"lnum":1,"ex":"The young schoolgirl volunteered to help clean up the local park.","exja":"その若い女学生は地域の公園の清掃ボランティアに参加した。"},{"id":6232,"en":"scientifically","ja":"科学的に\n科学の方法や根拠に基づいて","level":7,"lnum":1,"ex":"The claims made in the article have not been scientifically proven.","exja":"その記事で主張されていることは科学的に証明されていない。"},{"id":6233,"en":"scooter","ja":"スクーター\n小型二輪車または蹴って進む乗り物","level":7,"lnum":1,"ex":"He commutes to work on a scooter to avoid traffic jams.","exja":"彼は渋滞を避けるためにスクーターで通勤している。"},{"id":6234,"en":"scramble","ja":"急いで動く・奪い合う\n急いで這って進む、または混乱して争う","level":7,"lnum":1,"ex":"Everyone scrambled to find their seats before the ceremony began.","exja":"式典が始まる前に、みんな急いで席を探した。"},{"id":6235,"en":"scratch","ja":"引っ掻く・ゼロから\n表面を爪などで傷つける。from scratchは「ゼロから」","level":7,"lnum":1,"ex":"She baked the birthday cake completely from scratch.","exja":"彼女は誕生日ケーキを完全にゼロから焼いた。"},{"id":6236,"en":"screw","ja":"ねじ込む・ネジで固定する\nネジを回す動作","level":7,"lnum":1,"ex":"He screwed the shelf firmly to the wall so it wouldn't fall.","exja":"彼は棚が落ちないように壁にしっかりとネジで固定した。"},{"id":6237,"en":"scribble","ja":"走り書きする\n雑に素早く書いたもの、または落書き","level":7,"lnum":1,"ex":"The note was hard to read because it was just a quick scribble.","exja":"そのメモは走り書きだったので、読みにくかった。"},{"id":6238,"en":"scrooge","ja":"けちんぼ\nディケンズ作品の登場人物から来た「守銭奴」の意味","level":7,"lnum":1,"ex":"Don't be such a scrooge — treat yourself to something nice for once.","exja":"そんなにけちにならないで、たまには自分に何かいいものを買ってあげなよ。"},{"id":6239,"en":"scuba","ja":"スキューバ\n水中で使う自給式水中呼吸装置","level":7,"lnum":1,"ex":"She took scuba diving lessons during her vacation in Thailand.","exja":"彼女はタイでの休暇中にスキューバダイビングのレッスンを受けた。"},{"id":6240,"en":"scythe","ja":"大鎌\n草を刈る大型の湾曲した刃を持つ農具","level":7,"lnum":1,"ex":"The old farmer used a scythe to cut the tall grass in the field.","exja":"老農夫は畑の背の高い草を刈るために大鎌を使った。"},{"id":6241,"en":"seal","ja":"アザラシ・封印\n動物のアザラシ、または封をする行為","level":7,"lnum":1,"ex":"He sealed the envelope carefully and wrote the address on the front.","exja":"彼は封筒を丁寧に封印し、表面に住所を書いた。"},{"id":6242,"en":"seasonal","ja":"季節的な\n特定の季節に関連する、または季節により変わる","level":7,"lnum":1,"ex":"The café offers seasonal menus that change with each new harvest.","exja":"そのカフェは新しい収穫のたびに変わる季節のメニューを提供している。"},{"id":6243,"en":"second person","ja":"二人称\nyouを指す文法用語","level":7,"lnum":1,"ex":"In English, \"you\" is the second person pronoun used to address the listener.","exja":"英語では「you」は聞き手に語りかける二人称の代名詞だ。"},{"id":6244,"en":"secondary","ja":"二次的な・中等の\n重要性が二番目。secondary schoolは中学・高校","level":7,"lnum":1,"ex":"Exercise is important, but secondary to maintaining a healthy diet.","exja":"運動は重要だが、健康的な食事を維持することよりは二次的なものだ。"},{"id":6245,"en":"secondly","ja":"第二に\n列挙するときの順序を示す副詞","level":7,"lnum":1,"ex":"Firstly, check the safety instructions, and secondly, put on your helmet.","exja":"まず、安全指示を確認し、次に、ヘルメットをかぶってください。"},{"id":6246,"en":"sector","ja":"部門・分野\n経済や社会の特定の領域","level":7,"lnum":1,"ex":"The technology sector has been growing rapidly over the past decade.","exja":"テクノロジー部門はここ10年で急速に成長している。"},{"id":6247,"en":"seesaw","ja":"シーソー・一進一退\n遊具のシーソー、または上下に変動する状況","level":7,"lnum":1,"ex":"The stock market has been going up and down like a seesaw all week.","exja":"株式市場は今週ずっとシーソーのように上下している。"},{"id":6248,"en":"segment","ja":"部分・セグメント\n全体を構成する一つの部分や区分","level":7,"lnum":1,"ex":"The company decided to focus on a younger segment of the market.","exja":"その会社は市場の若い層に焦点を当てることにした。"},{"id":6249,"en":"seldom","ja":"めったに〜ない\nrarelyと同義の頻度を表す副詞","level":7,"lnum":1,"ex":"She seldom goes to bed before midnight when she has an important deadline.","exja":"重要な締め切りがあるとき、彼女はめったに真夜中前に寝ない。"},{"id":6250,"en":"self-confidence","ja":"自信\n自分の能力を信じる気持ち","level":7,"lnum":1,"ex":"Building self-confidence is important for success in both work and life.","exja":"自信をつけることは、仕事においても人生においても成功に重要だ。"},{"id":6251,"en":"self-confident","ja":"自信のある\n自分の判断や能力に確信を持っている","level":7,"lnum":1,"ex":"He walked into the interview feeling self-confident and well-prepared.","exja":"彼は自信を持って、十分な準備をして面接に臨んだ。"},{"id":6252,"en":"selfless","ja":"無私の・利他的な\n自分よりも他人を優先する","level":7,"lnum":1,"ex":"Her selfless dedication to helping others inspired everyone around her.","exja":"他者を助けることへの彼女の無私の献身は、周りのすべての人を鼓舞した。"},{"id":6253,"en":"seller","ja":"売り手・売れている商品\n物を売る人、またはよく売れている商品","level":7,"lnum":1,"ex":"The online seller received hundreds of positive reviews from satisfied customers.","exja":"そのオンライン販売業者は満足した顧客から数百件の好意的なレビューを受けた。"},{"id":6254,"en":"semicolon","ja":"セミコロン\n文の区切りに使う「；」という句読点","level":7,"lnum":1,"ex":"A semicolon can be used to link two closely related independent clauses.","exja":"セミコロンは密接に関連する二つの独立した節をつなぐために使うことができる。"},{"id":6255,"en":"semi-final","ja":"準決勝\n決勝に進む前の試合","level":7,"lnum":1,"ex":"Our team won the semi-final and will compete in the championship next week.","exja":"私たちのチームは準決勝に勝ち、来週の選手権に出場する。"},{"id":6256,"en":"seminar","ja":"セミナー・討議\n少人数で行う研究や討議の授業・集会","level":7,"lnum":1,"ex":"Students were required to attend a weekly seminar to discuss their research.","exja":"学生たちは研究を議論するために毎週のセミナーに出席することが求められた。"},{"id":6257,"en":"senator","ja":"上院議員\n上院に属する立法府の議員","level":7,"lnum":1,"ex":"The senator introduced a bill to reduce carbon emissions nationwide.","exja":"その上院議員は全国的な二酸化炭素排出量を削減する法案を提出した。"},{"id":6258,"en":"sensible","ja":"分別のある・賢明な\n感情でなく理性で判断する。sensitiveとの混同に注意","level":7,"lnum":1,"ex":"It would be sensible to save money before making such a large purchase.","exja":"そんな大きな買い物をする前にお金を節約するのが分別のある行動だ。"},{"id":6259,"en":"sensitive","ja":"敏感な・繊細な\n感情や刺激に対して影響を受けやすい。sensibleと混同しない","level":7,"lnum":1,"ex":"She is very sensitive to criticism and often takes comments personally.","exja":"彼女は批判にとても敏感で、コメントをよく個人的に受け取ってしまう。"},{"id":6260,"en":"separately","ja":"別々に・独立して\n一緒でなく分けて行う様子","level":7,"lnum":1,"ex":"Please wash the dark and light clothes separately to avoid color bleeding.","exja":"色移りを防ぐために、濃い色と薄い色の衣類は別々に洗ってください。"},{"id":6261,"en":"serene","ja":"穏やかな・平和な\n完全に静かで落ち着いた状態","level":7,"lnum":1,"ex":"The mountain lake was serene and completely still in the early morning.","exja":"早朝、山の湖は穏やかでまったく静止していた。"},{"id":6262,"en":"serial","ja":"連続の・シリアル\n一連の順序で続く。連続犯罪者はserial criminal","level":7,"lnum":1,"ex":"The detective solved a series of crimes committed by a serial burglar.","exja":"刑事は連続泥棒犯が行った一連の犯罪を解決した。"},{"id":6263,"en":"servant","ja":"使用人・召使い\n雇われて主人の世話をする人","level":7,"lnum":1,"ex":"The king's loyal servant accompanied him everywhere he traveled.","exja":"王の忠実な使用人はどこへでも彼に付き添った。"},{"id":6264,"en":"setback","ja":"後退・挫折\n目標に向かう途中で起きる障害や失敗","level":7,"lnum":1,"ex":"Losing her job was a major setback, but she quickly found a new opportunity.","exja":"仕事を失うことは大きな後退だったが、彼女はすぐに新しいチャンスを見つけた。"},{"id":6265,"en":"sexism","ja":"性差別\n性別を理由にした不当な差別や偏見","level":7,"lnum":1,"ex":"She wrote a powerful essay about the experience of sexism in the workplace.","exja":"彼女は職場での性差別の経験についての力強いエッセイを書いた。"},{"id":6266,"en":"sexual","ja":"性的な\n性やセクシュアリティに関する形容詞","level":7,"lnum":1,"ex":"The company updated its policy to address sexual harassment in the workplace.","exja":"その会社は職場でのセクシャルハラスメントに対処するためにポリシーを更新した。"},{"id":6267,"en":"sexy","ja":"魅力的な・セクシーな\n性的魅力がある。口語では「かっこいい・魅力的」の意味でも使う","level":7,"lnum":1,"ex":"The sleek new design of the phone made it look surprisingly sexy.","exja":"スマートフォンの洗練された新しいデザインは、驚くほど魅力的に見えた。"},{"id":6268,"en":"shabby","ja":"みすぼらしい・汚い\n古くて傷んだ外観。扱いが不当な場合にも使う","level":7,"lnum":1,"ex":"He wore a shabby old coat that had seen better days.","exja":"彼はかつてはよかったが今はくたびれた古いコートを着ていた。"},{"id":6269,"en":"shaken","ja":"動揺した・震えた\n衝撃やショックで精神的・身体的に揺れた状態","level":7,"lnum":1,"ex":"She was clearly shaken after witnessing the accident on the street.","exja":"路上での事故を目撃した後、彼女は明らかに動揺していた。"},{"id":6270,"en":"Shakespearean","ja":"シェイクスピア的な\nシェイクスピアの作品や文体に関する","level":7,"lnum":1,"ex":"His dramatic speech was compared to a Shakespearean monologue by the audience.","exja":"彼の劇的なスピーチは、観客からシェイクスピア的なモノローグと比較された。"},{"id":6271,"en":"shaky","ja":"不安定な・自信のない\n物が揺れる、または立場や根拠が弱い状態","level":7,"lnum":1,"ex":"His voice was shaky as he delivered the speech in front of the large audience.","exja":"大勢の観客の前でスピーチをするとき、彼の声は震えていた。"},{"id":6272,"en":"sharply","ja":"急激に・鋭く\n急な変化や鋭い動きを表す副詞","level":7,"lnum":1,"ex":"House prices fell sharply after the interest rate was raised.","exja":"金利が引き上げられた後、住宅価格は急激に下落した。"},{"id":6273,"en":"shatter","ja":"粉々にする\nガラスなどを砕く。希望が打ち砕かれる意味でも使う","level":7,"lnum":1,"ex":"The glass shattered into dozens of pieces when it hit the floor.","exja":"床に当たったとき、ガラスは何十もの破片に粉々になった。"},{"id":6274,"en":"shed","ja":"物置・小屋\n屋外に建てた小型の収納施設","level":7,"lnum":1,"ex":"She stored the gardening tools in the shed at the back of the yard.","exja":"彼女は庭の裏の物置に園芸道具を保管した。"},{"id":6275,"en":"shell","ja":"砲撃する\n砲弾を発射する動詞。貝殻の意味とは別用法","level":7,"lnum":1,"ex":"Enemy forces shelled the town throughout the night.","exja":"敵軍は一晩中その町を砲撃した。"},{"id":6276,"en":"shield","ja":"盾・防護物\n攻撃から守るための物","level":7,"lnum":1,"ex":"The bodyguard used himself as a shield to protect the politician from danger.","exja":"ボディガードは政治家を危険から守るために自らを盾にした。"},{"id":6277,"en":"shift","ja":"交代勤務・シフト\n勤務時間の区切り、または立場・考えの変化","level":7,"lnum":1,"ex":"She works the night shift at the hospital three times a week.","exja":"彼女は週に3回、病院で夜勤のシフトに入っている。"},{"id":6278,"en":"shipping","ja":"輸送・海運\n貨物の輸送、特に海上輸送","level":7,"lnum":1,"ex":"The company reduced its shipping costs by switching to a new delivery service.","exja":"その会社は新しい配送サービスに切り替えることで輸送コストを削減した。"},{"id":6279,"en":"shipwreck","ja":"難破・難破船\n海で船が沈没した事故または沈んだ船","level":7,"lnum":1,"ex":"Divers discovered the remains of an old shipwreck off the coast.","exja":"ダイバーたちは沖合で古い難破船の残骸を発見した。"},{"id":6280,"en":"shooting","ja":"銃撃・撮影\n銃を使った事件、またはムービーの撮影","level":7,"lnum":1,"ex":"The filming crew completed the outdoor shooting ahead of schedule.","exja":"撮影クルーは予定より早く屋外撮影を終えた。"},{"id":6281,"en":"shopkeeper","ja":"店主\n店を経営・管理する人","level":7,"lnum":1,"ex":"The friendly shopkeeper offered free samples to attract new customers.","exja":"親切な店主は新しい客を引き付けるために無料サンプルを提供した。"},{"id":6282,"en":"shoplift","ja":"万引きする\n代金を払わずに店から商品を盗む","level":7,"lnum":1,"ex":"Security cameras caught him trying to shoplift a bottle of perfume.","exja":"防犯カメラが彼が香水のボトルを万引きしようとしているのを捉えた。"},{"id":6283,"en":"shoplifter","ja":"万引きする人\n店で商品を盗む人","level":7,"lnum":1,"ex":"The shoplifter was caught at the door by a store employee.","exja":"万引き犯は店員に出口で捕まえられた。"},{"id":6284,"en":"shoplifting","ja":"万引き\n店から商品を盗む行為","level":7,"lnum":1,"ex":"Shoplifting costs retailers billions of dollars every year.","exja":"万引きは毎年小売業者に何十億ドルものコストをかけさせる。"},{"id":6285,"en":"shortness","ja":"短さ・低身長\n長さや身長が短いこと","level":7,"lnum":1,"ex":"The shortness of the speech surprised the audience who expected more.","exja":"スピーチの短さは、もっと長いものを期待していた観客を驚かせた。"},{"id":6286,"en":"short-term","ja":"短期の\n短い期間に関する。long-termの対義語","level":7,"lnum":1,"ex":"The company focused on short-term profits instead of long-term growth.","exja":"その会社は長期的な成長よりも短期的な利益に焦点を当てた。"},{"id":6287,"en":"showbiz","ja":"芸能界\nshow businessの略。エンターテインメント産業","level":7,"lnum":1,"ex":"She dreamed of making it big in showbiz ever since she was a little girl.","exja":"小さな頃から、彼女は芸能界で成功することを夢見ていた。"},{"id":6288,"en":"showcase","ja":"見せ場・ショーケース\n才能や商品を見せるための機会や陳列棚","level":7,"lnum":1,"ex":"The art fair was a chance for young artists to showcase their work.","exja":"アートフェアは若いアーティストたちが自分の作品を発表する機会だった。"},{"id":6289,"en":"shrink","ja":"縮む・小さくなる\n洗濯などで布が縮む、または量や規模が減少する","level":7,"lnum":1,"ex":"He joked that he needed to see a shrink after such a stressful week.","exja":"そんなにストレスが多い週を過ごした後、精神科医にかかる必要があると彼は冗談を言った。"},{"id":6290,"en":"shrink","ja":"精神科医\n俗語でpsychiatristを指す","level":7,"lnum":1,"ex":"She visited a shrink to help deal with her anxiety and stress.","exja":"彼女は不安とストレスに対処するために精神科医のもとを訪れた。"},{"id":6291,"en":"shrug","ja":"肩をすくめる\n「どうでもいい」「知らない」の気持ちを示す動作","level":7,"lnum":1,"ex":"When asked about the missing documents, he simply shrugged and said he didn't know.","exja":"紛失した書類について聞かれると、彼はただ肩をすくめて知らないと言った。"},{"id":6292,"en":"sigh","ja":"ため息をつく\n疲れや悲しさ・安堵などでため息をつく","level":7,"lnum":1,"ex":"She sighed with relief when she found out that the project had been approved.","exja":"プロジェクトが承認されたと分かって、彼女は安堵のため息をついた。"},{"id":6293,"en":"significantly","ja":"著しく・重要なことに\n大きな意味を持って変化する様子","level":7,"lnum":1,"ex":"The new policy has significantly reduced the number of workplace accidents.","exja":"新しい政策は職場事故の件数を著しく減らした。"},{"id":6294,"en":"signify","ja":"意味する・示す\nある記号や行為が意味することを表す","level":7,"lnum":1,"ex":"A red traffic light signifies that drivers must stop immediately.","exja":"赤信号はドライバーがすぐに止まらなければならないことを意味する。"},{"id":6295,"en":"silverware","ja":"銀食器・カトラリー\nフォークやナイフなど食卓用の金属製道具","level":7,"lnum":1,"ex":"The antique silverware was displayed in a glass cabinet in the dining room.","exja":"アンティークの銀食器はダイニングルームのガラスキャビネットに展示されていた。"},{"id":6296,"en":"simplification","ja":"単純化\n複雑なものをわかりやすくすること","level":7,"lnum":1,"ex":"The simplification of the tax system made it easier for citizens to file their returns.","exja":"税制の単純化により、市民が申告書を提出しやすくなった。"},{"id":6297,"en":"simultaneous","ja":"同時の\n二つ以上のことが同じ時に起きる","level":7,"lnum":1,"ex":"The teacher offered simultaneous translation for students who didn't speak English.","exja":"先生は英語を話せない学生のために同時通訳を提供した。"},{"id":6298,"en":"sincere","ja":"誠実な・心からの\n偽りなく本心から行動や感情を示す","level":7,"lnum":1,"ex":"She gave a sincere apology for arriving late to the meeting.","exja":"彼女は会議に遅刻したことについて心からの謝罪をした。"},{"id":6299,"en":"sincerity","ja":"誠実さ\n本心からの真剣な気持ちや行動","level":7,"lnum":1,"ex":"His sincerity was obvious from the way he spoke about his passion for teaching.","exja":"教えることへの情熱について話す方法から、彼の誠実さは明らかだった。"},{"id":6300,"en":"sister-in-law","ja":"義理の姉妹\n配偶者の姉妹、または兄弟の妻","level":7,"lnum":1,"ex":"She spent the holidays with her sister-in-law, who had just moved to the city.","exja":"彼女はちょうど街に引っ越してきた義理の姉妹と休暇を過ごした。"},{"id":6301,"en":"skateboard","ja":"スケートボード\n四輪のボードに乗る乗り物","level":7,"lnum":1,"ex":"He learned to ride a skateboard in just two weeks of practice.","exja":"彼は2週間の練習でスケートボードの乗り方を覚えた。"},{"id":6302,"en":"skateboarder","ja":"スケートボーダー\nスケートボードをする人","level":7,"lnum":1,"ex":"The young skateboarder performed impressive tricks at the local park.","exja":"その若いスケートボーダーは地元の公園で印象的なトリックを披露した。"},{"id":6303,"en":"sketch","ja":"スケッチする・略述する\n素早く描く、または概要を説明する","level":7,"lnum":1,"ex":"The architect quickly sketched a rough plan of the proposed building.","exja":"建築家は提案された建物のおおまかな計画をさっとスケッチした。"},{"id":6304,"en":"skilled","ja":"熟練した\n高い技術や経験を持つ","level":7,"lnum":1,"ex":"The company hired skilled technicians to repair the complex machinery.","exja":"その会社は複雑な機械を修理するために熟練した技術者を雇った。"},{"id":6305,"en":"skillful/skilful","ja":"巧みな・上手な\n特定の技術において優れた能力がある","level":7,"lnum":1,"ex":"She is a skillful painter who creates beautiful landscapes in oil.","exja":"彼女は油絵で美しい風景画を描く巧みな画家だ。"},{"id":6306,"en":"skillfully/skilfully","ja":"巧みに\n高い技術をもって行う様子","level":7,"lnum":1,"ex":"The surgeon skillfully removed the tumor without damaging the surrounding tissue.","exja":"外科医は周囲の組織を傷つけることなく巧みに腫瘍を取り除いた。"},{"id":6307,"en":"skim","ja":"さっと読む・すくう\n表面だけを素早く通過する。skim-readは「流し読み」","level":7,"lnum":1,"ex":"He skimmed the newspaper over breakfast to check the main headlines.","exja":"彼は朝食をとりながら主要な見出しを確認するために新聞をさっと読んだ。"},{"id":6308,"en":"skip","ja":"スキップする・飛ばす\n軽く跳ぶ、または途中を飛ばす","level":7,"lnum":1,"ex":"She decided to skip the first chapter and start from chapter two.","exja":"彼女は最初の章を飛ばして第2章から始めることにした。"},{"id":6309,"en":"skylark","ja":"ヒバリ・ふざける\n鳴き声で知られる鳥、または無邪気にふざける","level":7,"lnum":1,"ex":"We stopped to listen to the beautiful song of a skylark in the field.","exja":"私たちは野原でヒバリの美しい歌を聴くために立ち止まった。"},{"id":6310,"en":"skyward/skywards","ja":"空に向かって\n上方・空の方向へ","level":7,"lnum":1,"ex":"The rocket soared skyward and disappeared into the clouds.","exja":"ロケットは空に向かって飛び上がり、雲の中に消えていった。"},{"id":6311,"en":"slam","ja":"バタンと閉める\n激しく叩きつける動作。ドアを勢いよく閉めるなど","level":7,"lnum":1,"ex":"He slammed the door behind him as he stormed out of the room.","exja":"彼は部屋を飛び出すときに後ろでドアをバタンと閉めた。"},{"id":6312,"en":"slang","ja":"スラング・俗語\n非公式な話し言葉","level":7,"lnum":1,"ex":"Using slang in a formal essay is generally considered inappropriate.","exja":"正式なエッセイでスラングを使うことは、一般的に不適切とみなされる。"},{"id":6313,"en":"slap","ja":"平手打ち\n手のひらで打つ行為","level":7,"lnum":1,"ex":"She slapped his hand away when he tried to take her fries.","exja":"彼がフライドポテトを取ろうとしたとき、彼女は彼の手を叩いて払いのけた。"},{"id":6314,"en":"slap","ja":"平手で打つ\n手のひらで叩く動作","level":7,"lnum":1,"ex":"She slapped him across the face when he made an offensive remark.","exja":"彼が不快な発言をしたとき、彼女は彼の顔を平手打ちした。"},{"id":6315,"en":"slash","ja":"斜線・大幅削減\n「/」の記号、または価格などを大幅に削る","level":7,"lnum":1,"ex":"The store slashed prices by fifty percent to clear its end-of-season stock.","exja":"その店は季節末の在庫を処分するために価格を50パーセント大幅に削減した。"},{"id":6316,"en":"slaughter","ja":"虐殺・屠殺\n大量に殺す残虐な行為","level":7,"lnum":1,"ex":"The film depicted the slaughter of innocent civilians during the war.","exja":"その映画は戦争中の無実の市民の虐殺を描写していた。"},{"id":6317,"en":"slice","ja":"スライスする・薄く切る\n薄い断面に切る動作","level":7,"lnum":1,"ex":"She sliced the bread into thick pieces for the sandwiches.","exja":"彼女はサンドイッチのためにパンを厚く切った。"},{"id":6318,"en":"slide","ja":"滑る・スライド\n表面を滑る動作、またはプレゼンの1枚","level":7,"lnum":1,"ex":"The children laughed as they slid down the icy slope.","exja":"子どもたちはつるつるの斜面を滑り降りながら笑った。"},{"id":6319,"en":"slight","ja":"わずかな・軽微な\n量や程度が小さい状態","level":7,"lnum":1,"ex":"There was a slight delay in the train schedule due to the snowstorm.","exja":"吹雪のため、電車のスケジュールにわずかな遅れがあった。"},{"id":6320,"en":"sliver","ja":"細い切れ端\n薄くて細長い破片","level":7,"lnum":1,"ex":"She cut a small sliver of cake and put it on the plate.","exja":"彼女はケーキを細い切れ端に切り分けて皿に置いた。"},{"id":6321,"en":"sloppy","ja":"だらしない・ずさんな\n注意が払われていない雑な仕事や外見","level":7,"lnum":1,"ex":"His sloppy work disappointed the manager who had expected better results.","exja":"彼のずさんな仕事は、より良い結果を期待していたマネージャーを失望させた。"},{"id":6322,"en":"smash","ja":"粉砕する・大ヒット\n力強く打ち砕く。smash hitは「大ヒット作」","level":7,"lnum":1,"ex":"The baseball player smashed the ball over the fence for a home run.","exja":"野球選手はホームランのためにフェンスを越えてボールを打ち砕いた。"},{"id":6323,"en":"smokestack","ja":"煙突\n工場などの大型煙突","level":7,"lnum":1,"ex":"Dark smoke billowed from the factory's smokestack throughout the day.","exja":"工場の煙突からは一日中黒い煙が立ち上っていた。"},{"id":6324,"en":"snap","ja":"パチンと折る・素早く\n急にバキッと折れる動作、または素早く写真を撮る","level":7,"lnum":1,"ex":"The branch snapped under his weight as he climbed the old tree.","exja":"古い木に登ったとき、彼の体重で枝がパキッと折れた。"},{"id":6325,"en":"sneak","ja":"こっそり動く\n気づかれないように静かに動く","level":7,"lnum":1,"ex":"The boy tried to sneak a cookie from the jar before dinner.","exja":"男の子は夕食前にこっそりクッキーの瓶からクッキーを取ろうとした。"},{"id":6326,"en":"sneer","ja":"冷笑・あざ笑い\n軽蔑した笑い","level":7,"lnum":1,"ex":"He sneered at the idea, calling it completely unrealistic.","exja":"彼はその考えを完全に非現実的だと言いながら冷笑した。"},{"id":6327,"en":"sneeze","ja":"くしゃみをする\n鼻からの突発的な空気の放出","level":7,"lnum":1,"ex":"She sneezed three times in a row and quickly reached for a tissue.","exja":"彼女は続けて3回くしゃみをして、すぐにティッシュを手に取った。"},{"id":6328,"en":"sniff","ja":"鼻をすする・においを嗅ぐ\n鼻から息を吸ってにおいを感じ取る","level":7,"lnum":1,"ex":"The dog sniffed the ground carefully, searching for the right trail.","exja":"犬は正しい道を探しながら、地面を丁寧に嗅いだ。"},{"id":6329,"en":"snore","ja":"いびき\n眠っているときにかくいびき","level":7,"lnum":1,"ex":"He snored so loudly that the people in the next room could hear it.","exja":"彼のいびきはとても大きく、隣の部屋の人にも聞こえた。"},{"id":6330,"en":"snore","ja":"いびきをかく\n睡眠中にいびきをかく動詞","level":7,"lnum":1,"ex":"His loud snoring kept his wife awake throughout the night.","exja":"彼の大きないびきで妻は一晩中眠れなかった。"},{"id":6331,"en":"snowball","ja":"雪玉・雪だるま式に増える\n雪玉、または問題が急速に大きくなるという意味","level":7,"lnum":1,"ex":"The scandal snowballed into a massive controversy that dominated the news.","exja":"そのスキャンダルはニュースを支配する大きな論争へと雪だるま式に発展した。"},{"id":6332,"en":"soak","ja":"浸す・染み込ませる\n液体に長時間つけ込む行為","level":7,"lnum":1,"ex":"He soaked the dirty shirt in soapy water for an hour before washing.","exja":"彼は洗う前に汚いシャツを石鹸水に1時間浸した。"},{"id":6333,"en":"soak","ja":"浸す\n液体に浸ける動詞","level":7,"lnum":1,"ex":"Soak the dried beans in water overnight before cooking them.","exja":"乾燥した豆は調理する前に一晩水に浸しておいてください。"},{"id":6334,"en":"soaked","ja":"ずぶ濡れの\n水が完全に染み込んだ状態","level":7,"lnum":1,"ex":"By the time they reached shelter, they were completely soaked from the rain.","exja":"避難場所に着いたころには、彼らは雨でずぶ濡れになっていた。"},{"id":6335,"en":"soaking","ja":"ずぶ濡れな\nsoakedと同義だがやや口語的","level":7,"lnum":1,"ex":"She came home soaking after being caught in the sudden downpour.","exja":"突然の土砂降りに遭遇して、彼女はずぶ濡れで帰宅した。"},{"id":6336,"en":"soar","ja":"急上昇する\n価格や数値が急激に上がる","level":7,"lnum":1,"ex":"The eagle soared high above the mountains, riding the warm air currents.","exja":"鷲は暖かい気流に乗りながら山々の上を高く舞い上がった。"},{"id":6337,"en":"sob","ja":"すすり泣く\n泣き声をあげながら涙を流す","level":7,"lnum":1,"ex":"The child sobbed quietly after losing his favorite toy at the park.","exja":"公園でお気に入りのおもちゃを失くした後、子どもは静かにすすり泣いた。"},{"id":6338,"en":"so-called","ja":"いわゆる\n「〜と呼ばれている」という皮肉や疑念を含む表現","level":7,"lnum":1,"ex":"The so-called expert turned out to have no real qualifications at all.","exja":"いわゆる専門家は、実際にはまったく資格がないことが判明した。"},{"id":6339,"en":"sociable","ja":"社交的な\n人付き合いを好む外向きな性格","level":7,"lnum":1,"ex":"She is very sociable and always makes new friends wherever she goes.","exja":"彼女はとても社交的で、どこへ行っても新しい友達を作る。"},{"id":6340,"en":"socialize/socialise","ja":"社交する・交流する\n人と会い交流を楽しむ","level":7,"lnum":1,"ex":"Moving to a new city gave her the chance to socialize with different people.","exja":"新しい街への引っ越しは彼女にさまざまな人々と交流する機会を与えた。"},{"id":6341,"en":"softness","ja":"柔らかさ\n質感が柔らかいこと、または性格の優しさ","level":7,"lnum":1,"ex":"The softness of the cashmere sweater made it extremely comfortable to wear.","exja":"カシミヤのセーターの柔らかさは、着心地を非常に快適にしていた。"},{"id":6342,"en":"solidity","ja":"堅固さ・安定性\n固くて崩れない性質","level":7,"lnum":1,"ex":"The solidity of the building's foundation made it resistant to earthquakes.","exja":"建物の基礎の堅固さは、それを地震に強くした。"},{"id":6343,"en":"soliloquy","ja":"独白\n演劇で一人が観客に語りかける長い台詞","level":7,"lnum":1,"ex":"The actor's soliloquy in the second act moved the entire audience to tears.","exja":"第2幕での俳優の独白は観客全員を涙させた。"},{"id":6344,"en":"solo","ja":"一人での・独奏の\n他の人なしに単独で行う形容詞","level":7,"lnum":1,"ex":"The guitarist played a three-minute solo that was the highlight of the concert.","exja":"ギタリストはコンサートのハイライトとなる3分間のソロを演奏した。"},{"id":6345,"en":"solo","ja":"一人で・単独で\n単独でという副詞用法","level":7,"lnum":1,"ex":"He traveled solo across Europe with only a backpack.","exja":"彼はバックパックひとつで一人でヨーロッパを旅した。"},{"id":6346,"en":"solo","ja":"独奏・ソロ\n単独で演奏すること、またはその作品","level":7,"lnum":1,"ex":"The guitarist performed an impressive solo at the end of the concert.","exja":"ギタリストはコンサートの終わりに印象的なソロを演奏した。"},{"id":6347,"en":"solvent","ja":"溶媒・支払い能力のある\n化学では溶かす液体。金融では「支払い能力がある」の意味も","level":7,"lnum":1,"ex":"After paying all its debts, the company remained barely solvent.","exja":"すべての借金を返済した後、その会社はかろうじて支払い能力を維持していた。"},{"id":6348,"en":"somewhat","ja":"やや・ある程度\n完全ではないが多少そうであるという修飾語","level":7,"lnum":1,"ex":"The results of the experiment were somewhat disappointing.","exja":"実験の結果はやや失望させるものだった。"},{"id":6349,"en":"son-in-law","ja":"義理の息子\n娘の配偶者","level":7,"lnum":1,"ex":"Her son-in-law drove them to the airport for their holiday trip.","exja":"彼女の義理の息子は休暇旅行のために彼らを空港まで送った。"},{"id":6350,"en":"sonnet","ja":"ソネット\n14行からなる定型詩の形式","level":7,"lnum":1,"ex":"Shakespeare wrote 154 sonnets, many of which are still studied today.","exja":"シェイクスピアは154のソネットを書き、その多くは今日でも研究されている。"},{"id":6351,"en":"sophisticated","ja":"洗練された・高度な\n経験や知識により洗練されている様子","level":7,"lnum":1,"ex":"The new software is highly sophisticated and can handle complex data analysis.","exja":"その新しいソフトウェアは非常に高度で、複雑なデータ分析を処理できる。"},{"id":6352,"en":"sort","ja":"分類する・整理する\n種類や基準に従って整える","level":7,"lnum":1,"ex":"Please sort these files into alphabetical order before the meeting.","exja":"会議の前にこれらのファイルをアルファベット順に整理してください。"},{"id":6353,"en":"soundtrack","ja":"サウンドトラック\n映画やゲームに付けられた音楽","level":7,"lnum":1,"ex":"The movie's powerful soundtrack enhanced every emotional scene.","exja":"映画の力強いサウンドトラックはすべての感情的なシーンを引き立てた。"},{"id":6354,"en":"southward/southwards","ja":"南へ向かって\n南の方向へ","level":7,"lnum":1,"ex":"The hikers continued southward toward the valley as the sun began to set.","exja":"ハイカーたちは太陽が沈み始める中、谷に向かって南へ進み続けた。"},{"id":6355,"en":"Soviet","ja":"ソビエトの・ソビエト人\n旧ソビエト連邦に関連する","level":7,"lnum":1,"ex":"The Soviet Union was officially dissolved in December 1991.","exja":"ソビエト連邦は1991年12月に正式に解体された。"},{"id":6356,"en":"spa","ja":"スパ・温泉保養地\n健康や美容のための施設","level":7,"lnum":1,"ex":"She treated herself to a weekend at a luxury spa to relax and recharge.","exja":"彼女はリラックスして英気を養うために、ラグジュアリースパで週末を過ごした。"},{"id":6357,"en":"span","ja":"〜にまたがる・〜の幅がある\n期間や距離をカバーする動詞","level":7,"lnum":1,"ex":"The bridge spans the river at its widest point.","exja":"その橋は川の最も広い地点にまたがっている。"},{"id":6358,"en":"spare","ja":"予備の・余分の\n本来使う分以外の余った分の形容詞","level":7,"lnum":1,"ex":"He never spares any effort when it comes to helping his students.","exja":"彼は学生を助けることに関しては、努力を惜しまない。"},{"id":6359,"en":"spare","ja":"惜しむ・節約する\n使わずに残しておく動詞","level":7,"lnum":1,"ex":"She spared no effort to ensure the success of the event.","exja":"彼女はイベントを成功させるためにどんな努力も惜しまなかった。"},{"id":6360,"en":"sparerib","ja":"スペアリブ\n豚のあばら骨部分の肉料理","level":7,"lnum":1,"ex":"The restaurant is famous for its tender and flavorful spareribs.","exja":"そのレストランは柔らかくて風味豊かなスペアリブで有名だ。"},{"id":6361,"en":"spark","ja":"火花・きっかけ\n小さな炎、または何かを引き起こす初めのきっかけ","level":7,"lnum":1,"ex":"Her presentation sparked a lively debate among the participants.","exja":"彼女のプレゼンテーションは参加者の間で活発な議論のきっかけとなった。"},{"id":6362,"en":"sparkling","ja":"きらめく・炭酸の\n輝く、または炭酸入り（sparkling water）","level":7,"lnum":1,"ex":"They toasted the new year with glasses of sparkling wine.","exja":"彼らはスパークリングワインのグラスを掲げて新年を祝った。"},{"id":6363,"en":"sparrow","ja":"スズメ\n小さな茶色の一般的な鳥","level":7,"lnum":1,"ex":"A small sparrow perched on the windowsill and sang a brief melody.","exja":"小さなスズメが窓台に止まり、短いメロディーを歌った。"},{"id":6364,"en":"specialty","ja":"専門・得意分野\n特定の技術や知識が特に優れている分野","level":7,"lnum":1,"ex":"The chef's specialty is a traditional dish made with locally sourced ingredients.","exja":"シェフの得意料理は地元産の食材を使った伝統料理だ。"},{"id":6365,"en":"specifically","ja":"特定して・具体的に\n一般的でなく特定の対象を明示する副詞","level":7,"lnum":1,"ex":"She asked him specifically not to mention her name in the report.","exja":"彼女は報告書に自分の名前を書かないよう、彼に特定して頼んだ。"},{"id":6366,"en":"specify","ja":"明記する・指定する\nはっきりと詳細を述べる","level":7,"lnum":1,"ex":"Please specify your dietary requirements when booking the restaurant.","exja":"レストランを予約する際には、食事の制限事項を明記してください。"},{"id":6367,"en":"spectacle","ja":"壮観・見せ物\n目を引く印象的な光景","level":7,"lnum":1,"ex":"The fireworks display was an incredible spectacle that amazed everyone present.","exja":"花火のショーは素晴らしい壮観で、その場にいた全員を驚かせた。"},{"id":6368,"en":"speeder","ja":"スピード違反者\n制限速度を超えて走る人","level":7,"lnum":1,"ex":"The police officer pulled over a speeder who was going thirty miles over the limit.","exja":"警察官は制限速度を30マイル超過していたスピード違反者を停車させた。"},{"id":6369,"en":"spellbound","ja":"魅了された・うっとりした\nまるで魔法にかかったように夢中になっている","level":7,"lnum":1,"ex":"The audience was spellbound by the magician's incredible performance.","exja":"観客は手品師の信じられないほどのパフォーマンスに魅了された。"},{"id":6370,"en":"spin","ja":"回転する・回す\n軸を中心にくるくる回る動作","level":7,"lnum":1,"ex":"The dancer spun gracefully across the stage during the final performance.","exja":"ダンサーは最終公演でステージを優雅に回転しながら動いた。"},{"id":6371,"en":"spite","ja":"意地悪・悪意\nin spite ofで「〜にもかかわらず」","level":7,"lnum":1,"ex":"In spite of the terrible weather, they decided to go ahead with the picnic.","exja":"ひどい天気にもかかわらず、彼らはピクニックを決行することにした。"},{"id":6372,"en":"splatter","ja":"飛び散る・飛沫\n液体などが勢いよく広がる","level":7,"lnum":1,"ex":"Paint splattered across the floor when he accidentally knocked over the can.","exja":"誤って缶を倒したとき、絵の具が床に飛び散った。"},{"id":6373,"en":"split","ja":"分割する・分裂する\n二つ以上に分ける","level":7,"lnum":1,"ex":"The political party split into two groups over the controversial policy.","exja":"その政党は論争的な政策をめぐって2つのグループに分裂した。"},{"id":6374,"en":"spokesman","ja":"(男性の)広報担当者\n組織の公式見解を伝える男性","level":7,"lnum":1,"ex":"The company's spokesman issued a statement denying all allegations.","exja":"会社の広報担当者はすべての申し立てを否定する声明を発表した。"},{"id":6375,"en":"spokeswoman","ja":"(女性の)広報担当者\n組織の公式見解を伝える女性","level":7,"lnum":1,"ex":"The spokeswoman for the charity explained how donations would be used.","exja":"その慈善団体の女性広報担当者は寄付金がどのように使われるかを説明した。"},{"id":6376,"en":"sponsor","ja":"スポンサーになる\n資金を出して活動を支援する","level":7,"lnum":1,"ex":"A well-known technology company agreed to sponsor the science festival.","exja":"有名なテクノロジー企業がサイエンスフェスティバルのスポンサーになることに同意した。"},{"id":6377,"en":"spray","ja":"スプレー・噴霧\n液体を霧状に噴射する","level":7,"lnum":1,"ex":"He used a can of spray paint to decorate the fence.","exja":"彼はフェンスを飾るためにスプレーペイントの缶を使った。"},{"id":6378,"en":"spray","ja":"噴霧する\n液体を霧状に吹き付ける動詞","level":7,"lnum":1,"ex":"She sprayed the plants with water every morning to keep them healthy.","exja":"彼女は植物を健康に保つために毎朝水を噴霧した。"},{"id":6379,"en":"spreadsheet","ja":"スプレッドシート\n計算や表を作成するためのデジタルツール","level":7,"lnum":1,"ex":"She organized all the financial data in a spreadsheet for easy reference.","exja":"彼女はすぐに参照できるようにすべての財務データをスプレッドシートにまとめた。"},{"id":6380,"en":"sprint","ja":"全力疾走\n短距離を最高速度で走ること","level":7,"lnum":1,"ex":"He sprinted to the finish line and crossed it just ahead of his rival.","exja":"彼はゴールラインに向かって全力疾走し、ライバルをわずかに先んじてゴールした。"},{"id":6381,"en":"spur","ja":"拍車・拍車をかける\n馬に使う拍車、または「刺激する」という比喩的意味","level":7,"lnum":1,"ex":"The coach's encouraging words spurred the team on to play their best game.","exja":"コーチの励ましの言葉がチームに最高の試合をするよう拍車をかけた。"},{"id":6382,"en":"squad","ja":"チーム・部隊\n特定の任務のために集まった小集団","level":7,"lnum":1,"ex":"The police squad was called in to handle the dangerous situation.","exja":"危険な状況に対処するために警察の部隊が呼ばれた。"},{"id":6383,"en":"squash","ja":"スカッシュ・押しつぶす\nラケットスポーツ、または圧力をかけてつぶす","level":7,"lnum":1,"ex":"She squashed the empty can with her foot before throwing it away.","exja":"彼女は空き缶を足で押しつぶしてから捨てた。"},{"id":6384,"en":"squash","ja":"押しつぶす\n力を加えてつぶす動詞","level":7,"lnum":1,"ex":"He squashed the empty can with his foot before throwing it away.","exja":"彼は空き缶を捨てる前に足で押しつぶした。"},{"id":6385,"en":"squeeze","ja":"絞る・圧迫する\n強く握ったり押したりして液体を出す","level":7,"lnum":1,"ex":"He squeezed the lemon over the salad to add some flavor.","exja":"彼はサラダに風味を加えるためにレモンを絞った。"},{"id":6386,"en":"stab","ja":"刺す\n刃物などで突き刺す","level":7,"lnum":1,"ex":"The chef accidentally stabbed his finger while chopping vegetables.","exja":"シェフは野菜を刻んでいるときに誤って指を刺してしまった。"},{"id":6387,"en":"stability","ja":"安定性\n変化や動揺がなく安定している状態","level":7,"lnum":1,"ex":"Economic stability is essential for attracting foreign investment.","exja":"経済的安定は外国投資を引き付けるために不可欠だ。"},{"id":6388,"en":"stack","ja":"積み重ね・スタック\n重ねて積んだもの、または大量のもの","level":7,"lnum":1,"ex":"There was a huge stack of papers on the teacher's desk.","exja":"先生の机の上に書類が山積みになっていた。"},{"id":6389,"en":"stagger","ja":"よろめく・驚愕させる\nバランスを失って歩く、または非常に驚かせる","level":7,"lnum":1,"ex":"He staggered out of the building after the explosion.","exja":"爆発の後、彼はよろめきながら建物から出てきた。"},{"id":6390,"en":"stain","ja":"染み・汚れ\n布などに残る汚れ","level":7,"lnum":1,"ex":"The red wine stained the tablecloth permanently.","exja":"赤ワインがテーブルクロスに永久に染みをつけた。"},{"id":6391,"en":"stain","ja":"染みをつける\n汚れや色をつける動詞","level":7,"lnum":1,"ex":"The red wine stained her white shirt and it was hard to remove.","exja":"赤ワインが白いシャツに染みをつけ、取り除くのが難しかった。"},{"id":6392,"en":"stake","ja":"賭け金・危機にある\n賭けの金額。at stakeで「危機にさらされている」","level":7,"lnum":1,"ex":"His career was at stake after the project failed completely.","exja":"プロジェクトが完全に失敗した後、彼のキャリアが危機にさらされた。"},{"id":6393,"en":"stammer","ja":"どもる\n緊張などで言葉をつかえさせる","level":7,"lnum":1,"ex":"He stammered nervously when the teacher called on him unexpectedly.","exja":"先生に突然あてられたとき、彼は緊張してどもった。"},{"id":6394,"en":"standby","ja":"待機中の・予備の\nいつでも使えるよう待機している状態","level":7,"lnum":1,"ex":"Keep a standby generator ready in case of a power outage.","exja":"停電に備えて予備の発電機を準備しておいてください。"},{"id":6395,"en":"standstill","ja":"停止状態\n完全に動きが止まった状態","level":7,"lnum":1,"ex":"The heavy snowstorm brought traffic to a complete standstill.","exja":"大雪嵐で交通が完全に停止状態になった。"},{"id":6396,"en":"stanza","ja":"連（詩の）\n詩を構成する段落の単位","level":7,"lnum":1,"ex":"The poem has four stanzas, each describing a different season.","exja":"その詩には4つの連があり、それぞれ異なる季節を描いている。"},{"id":6397,"en":"startle","ja":"びっくりさせる\n突然の出来事で驚かせる","level":7,"lnum":1,"ex":"The sudden loud noise startled everyone in the quiet library.","exja":"突然の大きな音が、静かな図書館にいた全員をびっくりさせた。"},{"id":6398,"en":"starvation","ja":"飢餓\n食べ物が不足して死に至るほどの飢え","level":7,"lnum":1,"ex":"Millions of people around the world face starvation due to drought.","exja":"干ばつのために世界中で何百万人もの人々が飢餓に直面している。"},{"id":6399,"en":"starve","ja":"飢える\n食べ物が全くなく極度に空腹な状態になる","level":7,"lnum":1,"ex":"The animals in the abandoned farm began to starve without food.","exja":"放棄された農場の動物たちは食べ物がなく飢え始めた。"},{"id":6400,"en":"starving","ja":"飢えている・超腹ペコな\n餓死しそうなほど空腹。口語では「とても空腹」の意味","level":7,"lnum":1,"ex":"After the long hike, all of us were absolutely starving.","exja":"長いハイキングの後、私たちは全員ものすごく腹が減っていた。"},{"id":6401,"en":"state","ja":"国家の・州の\n国家または州に関する形容詞","level":7,"lnum":1,"ex":"The senator gave a state dinner for the visiting foreign leaders.","exja":"上院議員は訪問した外国の指導者たちのために国家晩餐会を開いた。"},{"id":6402,"en":"state","ja":"述べる・明言する\n正式に宣言や説明をする動詞","level":7,"lnum":1,"ex":"The company stated that it would not comment on the ongoing investigation.","exja":"会社は進行中の調査についてはコメントしないと述べた。"},{"id":6403,"en":"statesman","ja":"政治家・国政指導者\n経験豊かな優れた政治家を指す尊称","level":7,"lnum":1,"ex":"He was remembered as a great statesman who brought peace to the region.","exja":"彼はその地域に平和をもたらした偉大な政治家として記憶されている。"},{"id":6404,"en":"statewide","ja":"州全体の・州全体にわたって\n特定の州の全域に関わる","level":7,"lnum":1,"ex":"The governor announced a statewide emergency due to the flooding.","exja":"知事は洪水のため州全体の緊急事態を宣言した。"},{"id":6405,"en":"statistics","ja":"統計・統計データ\n数値データを集めて分析する学問または数値の集合","level":7,"lnum":1,"ex":"According to statistics, the crime rate in this city has dropped by 20%.","exja":"統計によると、この都市の犯罪率は20%低下した。"},{"id":6406,"en":"steely","ja":"鋼鉄のような・強固な\n強く揺るぎない意志や決断力を持つ","level":7,"lnum":1,"ex":"She faced the difficult interview with steely determination.","exja":"彼女は鋼鉄のような決意を持って難しい面接に臨んだ。"},{"id":6407,"en":"steer","ja":"操縦する・導く\n乗り物を操作する、または人を特定の方向に導く","level":7,"lnum":1,"ex":"He steered the boat carefully through the narrow channel.","exja":"彼は狭い水路を慎重に船を操縦して進んだ。"},{"id":6408,"en":"steering wheel","ja":"ハンドル\n車などを操縦するための円形の装置","level":7,"lnum":1,"ex":"She gripped the steering wheel tightly as the storm grew worse.","exja":"嵐が激しくなるにつれ、彼女はハンドルをきつく握った。"},{"id":6409,"en":"stepfather","ja":"義理の父・継父\n母の再婚相手","level":7,"lnum":1,"ex":"Her stepfather taught her how to ride a bicycle when she was six.","exja":"義理の父が6歳のとき、彼女に自転車の乗り方を教えてくれた。"},{"id":6410,"en":"stepmother","ja":"義理の母・継母\n父の再婚相手","level":7,"lnum":1,"ex":"Her stepmother was kind and always encouraged her to follow her dreams.","exja":"義理の母は優しく、いつも彼女が夢を追うよう励ましてくれた。"},{"id":6411,"en":"stereotype","ja":"ステレオタイプ・固定観念\n集団に対する単純化された先入観","level":7,"lnum":1,"ex":"We should challenge the stereotype that girls are not good at math.","exja":"女の子は数学が苦手というステレオタイプに異議を唱えるべきだ。"},{"id":6412,"en":"stern","ja":"厳しい・厳格な\n規律に厳しく容赦しない様子","level":7,"lnum":1,"ex":"The stern principal warned students about the consequences of cheating.","exja":"厳格な校長は生徒たちにカンニングの結果について警告した。"},{"id":6413,"en":"stiff","ja":"硬い・こわばった\n柔軟でなく動かしにくい状態","level":7,"lnum":1,"ex":"My neck felt stiff after sleeping in an awkward position all night.","exja":"一晩中不自然な姿勢で寝たため、首がこわばった感じがした。"},{"id":6414,"en":"stimulant","ja":"刺激物・興奮剤\n神経や活動を活性化させる物質","level":7,"lnum":1,"ex":"Coffee is a mild stimulant that helps many people stay awake.","exja":"コーヒーは多くの人が目を覚ますのに役立つ穏やかな刺激物だ。"},{"id":6415,"en":"stimulate","ja":"刺激する・活性化する\n興味や活動を促す","level":7,"lnum":1,"ex":"Reading a variety of books can stimulate a child's imagination greatly.","exja":"様々な本を読むことは子どもの想像力を大いに刺激できる。"},{"id":6416,"en":"stimulation","ja":"刺激\n興奮や活動を引き起こすこと","level":7,"lnum":1,"ex":"Young children need both physical and mental stimulation to develop well.","exja":"幼い子どもたちはよく成長するために身体的・精神的刺激の両方が必要だ。"},{"id":6417,"en":"stingy","ja":"けちな\nお金や物を出し惜しむ","level":7,"lnum":1,"ex":"He was so stingy that he never left a tip at restaurants.","exja":"彼はとてもけちで、レストランでチップを払ったことがなかった。"},{"id":6418,"en":"stink","ja":"悪臭を放つ\n不快なにおいがする","level":7,"lnum":1,"ex":"The garbage bags left outside stank in the summer heat.","exja":"外に置かれたゴミ袋が夏の暑さの中で悪臭を放った。"},{"id":6419,"en":"stitch","ja":"縫い目・一針\n布を縫い合わせる一つの縫い目","level":7,"lnum":1,"ex":"She learned to stitch a simple pattern onto the fabric at the craft workshop.","exja":"彼女はクラフトワークショップで布に簡単な模様を縫い付けることを学んだ。"},{"id":6420,"en":"stock","ja":"在庫・株\n商品の在庫または会社の株","level":7,"lnum":1,"ex":"The store ran out of stock during the holiday shopping season.","exja":"その店は年末年始のショッピングシーズン中に在庫がなくなった。"},{"id":6421,"en":"stock market","ja":"株式市場\n株が売買される市場","level":7,"lnum":1,"ex":"The stock market crashed suddenly, causing panic among investors.","exja":"株式市場が突然暴落し、投資家の間でパニックが起きた。"},{"id":6422,"en":"stockpile","ja":"備蓄・蓄える\n将来のために大量に蓄える","level":7,"lnum":1,"ex":"The government decided to stockpile medical supplies for emergencies.","exja":"政府は緊急事態に備えて医療物資を備蓄することを決めた。"},{"id":6423,"en":"stonework","ja":"石造工事・石細工\n石を使った建築や装飾作業","level":7,"lnum":1,"ex":"The ancient cathedral featured beautiful stonework carved by skilled craftsmen.","exja":"その古い大聖堂には熟練した職人が彫った美しい石細工が施されていた。"},{"id":6424,"en":"stool","ja":"スツール・腰掛け\n背もたれのない椅子","level":7,"lnum":1,"ex":"She sat on a wooden stool at the kitchen counter while eating breakfast.","exja":"彼女は朝食をとりながらキッチンカウンターの木製スツールに座っていた。"},{"id":6425,"en":"stopover","ja":"途中寄港・乗り継ぎ\n長距離旅行での中間地点での滞在","level":7,"lnum":1,"ex":"We had a short stopover in Dubai on our way to London.","exja":"ロンドンへ向かう途中、ドバイで短い途中寄港があった。"},{"id":6426,"en":"stopwatch","ja":"ストップウォッチ\n時間を正確に計測するための時計","level":7,"lnum":1,"ex":"The coach used a stopwatch to time each swimmer's performance.","exja":"コーチはストップウォッチを使って各選手のタイムを計った。"},{"id":6427,"en":"straighten","ja":"まっすぐにする\n曲がったものを伸ばして整える","level":7,"lnum":1,"ex":"Please straighten your tie before we take the family photo.","exja":"家族写真を撮る前にネクタイをまっすぐ直してください。"},{"id":6428,"en":"straightforward","ja":"わかりやすい・率直な\n複雑でなくシンプルに理解できる様子","level":7,"lnum":1,"ex":"The instructions were clear and straightforward, so assembly was easy.","exja":"説明書は明確でわかりやすく、組み立ては簡単だった。"},{"id":6429,"en":"strain","ja":"緊張させる・酷使する\n力をかけすぎて疲弊させる","level":7,"lnum":1,"ex":"Working long hours without rest will strain your eyes and back.","exja":"休憩なしに長時間働くと目と背中を酷使することになる。"},{"id":6430,"en":"strait","ja":"海峡\n陸地に挟まれた狭い海の通路","level":7,"lnum":1,"ex":"Ships must pass through the Strait of Gibraltar to enter the Mediterranean.","exja":"地中海に入るには、ジブラルタル海峡を通らなければならない。"},{"id":6431,"en":"strand","ja":"取り残す・立ち往生させる\n交通手段がなくなって動けなくなる","level":7,"lnum":1,"ex":"The storm stranded hundreds of passengers at the airport overnight.","exja":"嵐で何百人もの乗客が一晩空港に立ち往生させられた。"},{"id":6432,"en":"strangle","ja":"首を絞める\nのどを圧迫して呼吸を妨げる","level":7,"lnum":1,"ex":"In the play, the villain attempts to strangle the hero in the final act.","exja":"その劇で、悪役は最終幕で主人公の首を絞めようとする。"},{"id":6433,"en":"strictly","ja":"厳密に・厳しく\n規則を例外なく正確に守る様子","level":7,"lnum":1,"ex":"Students are strictly prohibited from using phones during the exam.","exja":"試験中、生徒は携帯電話の使用を厳しく禁じられている。"},{"id":6434,"en":"stride","ja":"大股で歩く\n力強く大きな歩幅で歩く","level":7,"lnum":1,"ex":"She strode confidently into the interview room and greeted the panel.","exja":"彼女は自信を持って大股で面接室に入り、面接官に挨拶した。"},{"id":6435,"en":"striking","ja":"目立つ・印象的な\n見た目や内容が際立って印象に残る","level":7,"lnum":1,"ex":"The painting had a striking combination of red and gold that caught everyone's attention.","exja":"その絵は赤と金の印象的な組み合わせで、全員の注目を集めた。"},{"id":6436,"en":"strip","ja":"剥ぎ取る・脱ぐ\n覆いや衣服を取り除く","level":7,"lnum":1,"ex":"Workers stripped the old wallpaper off before repainting the walls.","exja":"作業員は壁を塗り直す前に古い壁紙を剥ぎ取った。"},{"id":6437,"en":"strive","ja":"努力する\n目標に向かって懸命に頑張る","level":7,"lnum":1,"ex":"Athletes must strive every day to improve their performance and technique.","exja":"アスリートはパフォーマンスと技術を向上させるために毎日努力しなければならない。"},{"id":6438,"en":"stroke","ja":"脳卒中・撫でる\n脳への血流障害、または軽くなでる行為","level":7,"lnum":1,"ex":"She stroked the cat gently and it began to purr softly.","exja":"彼女がそっと猫を撫でると、猫は静かにゴロゴロと鳴き始めた。"},{"id":6439,"en":"stroke","ja":"撫でる\n優しく表面をなでる動詞","level":7,"lnum":1,"ex":"She gently stroked the cat's fur as it sat on her lap.","exja":"猫が膝の上に座ると、彼女は優しくその毛を撫でた。"},{"id":6440,"en":"struggle","ja":"苦闘する\n困難に立ち向かいながら頑張る","level":7,"lnum":1,"ex":"She struggled to balance her studies and part-time job at the same time.","exja":"彼女は勉強とアルバイトを同時にこなすために苦労した。"},{"id":6441,"en":"stubbornly","ja":"頑固に\n考えを曲げずに主張し続ける様子","level":7,"lnum":1,"ex":"He stubbornly refused to apologize even though he knew he was wrong.","exja":"彼は自分が間違っているとわかっていても頑固に謝ることを拒んだ。"},{"id":6442,"en":"stuff","ja":"詰め込む\n物を無理やり詰め込む口語的な動詞","level":7,"lnum":1,"ex":"He stuffed all his clothes into one small suitcase for the trip.","exja":"彼は旅行のために全ての洋服を一つの小さなスーツケースに詰め込んだ。"},{"id":6443,"en":"subcontinent","ja":"亜大陸\nインド亜大陸など、大陸の一部をなす大きな陸地","level":7,"lnum":1,"ex":"India is located on the Indian subcontinent in South Asia.","exja":"インドは南アジアのインド亜大陸に位置している。"},{"id":6444,"en":"subculture","ja":"サブカルチャー\n主流文化の中に存在する独自の文化集団","level":7,"lnum":1,"ex":"Skateboarding started as a subculture in California in the 1960s.","exja":"スケートボードは1960年代にカリフォルニアでサブカルチャーとして始まった。"},{"id":6445,"en":"subdivision","ja":"細分化・小区分\nより小さい部分に分けること","level":7,"lnum":1,"ex":"The large estate was divided into smaller subdivisions for residential development.","exja":"広大な土地は住宅開発のためにより小さな区画に細分化された。"},{"id":6446,"en":"subjunctive","ja":"仮定法\n事実でない仮定や願望を表す文法的な法","level":7,"lnum":1,"ex":"The teacher explained the use of the subjunctive mood in conditional sentences.","exja":"先生は条件文における仮定法の使い方を説明した。"},{"id":6447,"en":"submit","ja":"提出する・従う\n書類などを提出する、または権威に従う","level":7,"lnum":1,"ex":"All applications must be submitted by the end of this month.","exja":"全ての申請書は今月末までに提出しなければならない。"},{"id":6448,"en":"subplot","ja":"サブプロット\n物語のメインストーリーに付随する副話","level":7,"lnum":1,"ex":"The romance between the two side characters forms an interesting subplot.","exja":"二人の脇役の間のロマンスが興味深いサブプロットを形成している。"},{"id":6449,"en":"subside","ja":"収まる・沈静化する\n騒ぎや嵐などが徐々に弱まる","level":7,"lnum":1,"ex":"The floods began to subside after several days of dry weather.","exja":"数日間晴天が続いた後、洪水が収まり始めた。"},{"id":6450,"en":"substance","ja":"物質・実質\n物理的な材料、または内容の本質的な部分","level":7,"lnum":1,"ex":"Scientists analyzed the unknown substance found near the chemical plant.","exja":"科学者たちは化学工場近くで発見された未知の物質を分析した。"},{"id":6451,"en":"substitute","ja":"代替する・代わりに使う\n別のもので代用する","level":7,"lnum":1,"ex":"The coach substituted the injured player with a younger team member.","exja":"コーチは怪我をした選手を若いチームメンバーと交代させた。"},{"id":6452,"en":"subtitle","ja":"字幕・副題\n映像の字幕、または本の副タイトル","level":7,"lnum":1,"ex":"The foreign film had English subtitles so everyone could enjoy it.","exja":"その外国映画には英語の字幕があり、全員が楽しめた。"},{"id":6453,"en":"subtle","ja":"微妙な・繊細な\nすぐには気づかないほど細かい違いや変化","level":7,"lnum":1,"ex":"There was a subtle difference in tone between the two paintings.","exja":"その二枚の絵の間にはトーンの微妙な違いがあった。"},{"id":6454,"en":"subtract","ja":"引き算する\n一方の数値から他方を差し引く","level":7,"lnum":1,"ex":"If you subtract 15 from 40, you get 25.","exja":"40から15を引くと25になる。"},{"id":6455,"en":"suburb","ja":"郊外\n都市の外縁部にある住宅地","level":7,"lnum":1,"ex":"Many families prefer to live in the suburbs where houses are bigger.","exja":"多くの家族は家が広い郊外に住むことを好む。"},{"id":6456,"en":"successive","ja":"連続した\n同じことが中断なく続けて起きる","level":7,"lnum":1,"ex":"The team won the championship for three successive years.","exja":"そのチームは3年連続で優勝した。"},{"id":6457,"en":"suck","ja":"吸う・最悪だ\n口で液体を吸う動作。口語で「ひどい」の意味もある","level":7,"lnum":1,"ex":"The baby sucked on the bottle happily during the flight.","exja":"赤ちゃんは飛行機の中で幸せそうに哺乳瓶を吸った。"},{"id":6458,"en":"sue","ja":"訴訟を起こす\n法的手段で損害賠償などを求める","level":7,"lnum":1,"ex":"The customer decided to sue the company for selling a defective product.","exja":"顧客は欠陥品を販売した会社を訴えることにした。"},{"id":6459,"en":"suffering","ja":"苦しみ・苦難\n痛みや悲しみを経験すること","level":7,"lnum":1,"ex":"The documentary showed the suffering of refugees in the war zone.","exja":"そのドキュメンタリーは戦争地帯における難民の苦しみを映し出した。"},{"id":6460,"en":"sufficiently","ja":"十分に\n必要な程度を満たす量や程度で","level":7,"lnum":1,"ex":"Make sure you are sufficiently prepared before taking the entrance exam.","exja":"入試を受ける前に十分な準備ができているか確認してください。"},{"id":6461,"en":"suitably","ja":"適切に\n目的や状況に合った形で","level":7,"lnum":1,"ex":"The candidate was suitably qualified for the senior management position.","exja":"その候補者は上級管理職にふさわしい資格を持っていた。"},{"id":6462,"en":"sulfur/sulphur","ja":"硫黄\n黄色の化学元素（記号S）。火薬や農薬に使われる","level":7,"lnum":1,"ex":"Volcanic areas often smell of sulfur due to underground gases.","exja":"火山地帯は地下のガスのために硫黄の臭いがすることが多い。"},{"id":6463,"en":"sunbeam","ja":"日光・日差し\n太陽から差し込む光の筋","level":7,"lnum":1,"ex":"A warm sunbeam streamed through the curtains and lit up the room.","exja":"温かい日差しがカーテン越しに差し込み、部屋を明るくした。"},{"id":6464,"en":"superb","ja":"素晴らしい・最高の\n非常に高い品質や卓越さを持つ","level":7,"lnum":1,"ex":"The chef prepared a superb meal that impressed all the guests.","exja":"シェフは素晴らしい食事を準備し、全ての客を感激させた。"},{"id":6465,"en":"superintendent","ja":"監督者・警視\n組織や部門を管理する責任者","level":7,"lnum":1,"ex":"The superintendent inspected all the school buildings before the new term began.","exja":"監督官は新学期が始まる前にすべての校舎を点検した。"},{"id":6466,"en":"supernatural","ja":"超自然的な\n自然の法則を超えた不思議な現象に関する","level":7,"lnum":1,"ex":"The horror story featured creatures with supernatural powers.","exja":"そのホラー小説には超自然的な力を持つ生き物が登場した。"},{"id":6467,"en":"supervise","ja":"監督する・指導する\n人や作業を監視し指示する","level":7,"lnum":1,"ex":"A qualified lifeguard supervised the children swimming in the pool.","exja":"資格を持ったライフガードがプールで泳ぐ子どもたちを監督した。"},{"id":6468,"en":"supervision","ja":"監督・管理\n責任者が部下や作業を見守る行為","level":7,"lnum":1,"ex":"The young workers carried out the repairs under the supervision of an expert.","exja":"若い作業員たちは専門家の監督のもとで修理を行った。"},{"id":6469,"en":"supervisor","ja":"上司・監督者\n部下を管理する立場の人","level":7,"lnum":1,"ex":"Her supervisor gave her positive feedback on her performance this quarter.","exja":"上司はこの四半期の彼女のパフォーマンスに対して肯定的なフィードバックをくれた。"},{"id":6470,"en":"supplement","ja":"補足・サプリメント\n不足している部分を補う追加のもの","level":7,"lnum":1,"ex":"Taking vitamin D supplements can help during the winter months.","exja":"冬の間、ビタミンDのサプリメントを摂取することは助けになる。"},{"id":6471,"en":"supplier","ja":"供給者・サプライヤー\n材料や商品を提供する企業や人","level":7,"lnum":1,"ex":"The company changed its main supplier after quality issues were discovered.","exja":"品質上の問題が発覚した後、会社は主要サプライヤーを変更した。"},{"id":6472,"en":"supply","ja":"供給する\n必要なものを提供する動詞","level":7,"lnum":1,"ex":"The city struggled to supply clean water to all its residents.","exja":"市は全住民に清潔な水を供給するのに苦労した。"},{"id":6473,"en":"suppress","ja":"抑圧する・隠す\n感情や情報を表に出ないようにする","level":7,"lnum":1,"ex":"The government tried to suppress the protest movement by arresting its leaders.","exja":"政府は指導者たちを逮捕することで抗議運動を抑圧しようとした。"},{"id":6474,"en":"surge","ja":"急増・押し寄せる\n急激な上昇や大波が押し寄せる状況","level":7,"lnum":1,"ex":"There was a sudden surge in demand for face masks during the pandemic.","exja":"パンデミックの間、マスクへの需要が突然急増した。"},{"id":6475,"en":"surrender","ja":"降伏する\n戦いや抵抗をやめ相手に従う","level":7,"lnum":1,"ex":"The general ordered his troops to surrender after the city was surrounded.","exja":"将軍は都市が包囲された後、部隊に降伏を命じた。"},{"id":6476,"en":"surroundings","ja":"周囲の環境\n人を取り囲む物理的・社会的環境","level":7,"lnum":1,"ex":"She felt calm and peaceful in the natural surroundings of the countryside.","exja":"彼女は田舎の自然環境の中で落ち着いた穏やかな気持ちになった。"},{"id":6477,"en":"surveillance","ja":"監視\n行動を記録・観察する行為。カメラ監視などに使う","level":7,"lnum":1,"ex":"The bank installed new surveillance cameras to improve security.","exja":"銀行はセキュリティ向上のために新しい監視カメラを設置した。"},{"id":6478,"en":"suspect","ja":"疑う\n信じるに足る根拠なしにそうかもしれないと思う","level":7,"lnum":1,"ex":"The detective suspected that the witness was hiding important information.","exja":"探偵は証人が重要な情報を隠していると疑った。"},{"id":6479,"en":"suspend","ja":"一時停止する・停学にする\n活動を一時的に止める、または資格を一時剥奪する","level":7,"lnum":1,"ex":"The student was suspended from school for a week for fighting.","exja":"その生徒はけんかをしたため1週間停学になった。"},{"id":6480,"en":"suspicious","ja":"疑い深い・怪しい\n信用できないと感じる、または疑われる様子","level":7,"lnum":1,"ex":"The neighbors grew suspicious when they noticed unusual activity at the house.","exja":"隣人たちはその家での不審な動きに気づいて怪しいと感じるようになった。"},{"id":6481,"en":"suspiciously","ja":"疑わしく・怪しく\n不審を感じさせる様子で行動する","level":7,"lnum":1,"ex":"He acted suspiciously, glancing over his shoulder every few minutes.","exja":"彼は数分ごとに肩越しにちらちら見て、不審な行動をとった。"},{"id":6482,"en":"sustain","ja":"持続する・支える\n長期間維持する、または重量を支える","level":7,"lnum":1,"ex":"The athlete sustained serious injuries during the final match of the tournament.","exja":"そのアスリートはトーナメントの最終試合で重傷を負った。"},{"id":6483,"en":"swan","ja":"白鳥\n白くて優雅な大型の水鳥","level":7,"lnum":1,"ex":"We watched a pair of swans glide gracefully across the lake.","exja":"私たちは一組の白鳥が優雅に湖を滑るように進むのを見た。"},{"id":6484,"en":"sweep","ja":"掃く・一掃する\nほうきで掃除する、または大きな範囲を一気に制覇する","level":7,"lnum":1,"ex":"She swept the kitchen floor every morning before preparing breakfast.","exja":"彼女は朝食の準備をする前に毎朝台所の床を掃いた。"},{"id":6485,"en":"swift","ja":"素早い・迅速な\n速度が非常に速い様子","level":7,"lnum":1,"ex":"The swift response of the firefighters saved the building from destruction.","exja":"消防士たちの迅速な対応が建物を破壊から救った。"},{"id":6486,"en":"swing","ja":"揺れ・変動\n前後に揺れる動き、または意見の大きな変化","level":7,"lnum":1,"ex":"The politician's opinion swung from one extreme to the other during the debate.","exja":"その政治家の意見は討論の中で一方の極端からもう一方へと大きく振れた。"},{"id":6487,"en":"swing","ja":"揺れる・振る\n前後または左右に揺れる動詞","level":7,"lnum":1,"ex":"The child swung on the playground swing for half an hour.","exja":"子供は30分間、公園のブランコで揺れて遊んだ。"},{"id":6488,"en":"syllable","ja":"音節\n単語を構成する発音の単位","level":7,"lnum":1,"ex":"The word \"beautiful\" has three syllables: beau-ti-ful.","exja":"\"beautiful\"という単語は3音節：beau-ti-fulある。"},{"id":6489,"en":"symbolic","ja":"象徴的な\n直接的でなく象徴として何かを表す","level":7,"lnum":1,"ex":"The white dove is symbolic of peace in many cultures around the world.","exja":"白い鳩は世界の多くの文化において平和の象徴だ。"},{"id":6490,"en":"sympathetic","ja":"同情的な・共感する\n他者の苦しみを理解し共感する様子","level":7,"lnum":1,"ex":"Her sympathetic response made the grieving family feel understood and supported.","exja":"彼女の共感的な反応は悲しみにくれる家族に理解されサポートされていると感じさせた。"},{"id":6491,"en":"sympathize/sympathise","ja":"同情する・共感する\n他者の感情を理解し共有する","level":7,"lnum":1,"ex":"It is hard to sympathize with someone who refuses to take any responsibility.","exja":"どんな責任も取ろうとしない人に同情するのは難しい。"},{"id":6492,"en":"synonym","ja":"類義語\n意味が同じまたは類似している別の単語","level":7,"lnum":1,"ex":"\"Happy\" and \"joyful\" are synonyms that can often be used interchangeably.","exja":"\"happy\"と\"joyful\"は類義語でしばしば交換して使うことができる。"},{"id":6493,"en":"tablecloth","ja":"テーブルクロス\nテーブルに敷く布","level":7,"lnum":1,"ex":"She ironed the tablecloth carefully before setting the dinner table.","exja":"彼女はディナーテーブルをセットする前にテーブルクロスを丁寧にアイロンがけした。"},{"id":6494,"en":"tabloid","ja":"タブロイドの\n大衆向けの扇情的なニュースに関する形容詞","level":7,"lnum":1,"ex":"She prefers tabloid newspapers because they are easier to read on the train.","exja":"彼女は電車の中で読みやすいので、タブロイド判の新聞の方が好きだ。"},{"id":6495,"en":"tabloid","ja":"タブロイド紙\nセンセーショナルな記事を載せる大衆紙","level":7,"lnum":1,"ex":"The tabloid published a shocking story about the actor's private life.","exja":"タブロイド紙はその俳優の私生活に関するショッキングな記事を掲載した。"},{"id":6496,"en":"tack","ja":"針で留める・方針を変える\n画鋲で留める、または戦略の方向を変える","level":7,"lnum":1,"ex":"She tacked the notice to the bulletin board with a small pin.","exja":"彼女は小さな画鋲で掲示板にお知らせを留めた。"},{"id":6497,"en":"tackle","ja":"取り組む・タックルする\n問題に正面から向き合う、またはフットボールのタックル","level":7,"lnum":1,"ex":"The committee agreed to tackle the issue of food waste in schools.","exja":"委員会は学校における食品廃棄の問題に取り組むことで合意した。"},{"id":6498,"en":"tactile","ja":"触覚の\n触ることや触感に関する形容詞","level":7,"lnum":1,"ex":"The museum has a tactile exhibit that allows visitors to touch historical objects.","exja":"その博物館には来場者が歴史的な物を触れる触覚展示がある。"},{"id":6499,"en":"tame","ja":"飼い慣らされた・おとなしい\n野生でなく人に慣れた動物。退屈でつまらないという含みもある","level":7,"lnum":1,"ex":"The once-wild horse became tame after months of patient training.","exja":"かつて野生だった馬は何ヶ月もの根気強いトレーニングで飼い慣らされた。"},{"id":6500,"en":"tan","ja":"日焼けした色\n皮膚が日焼けした茶色がかった色合い","level":7,"lnum":1,"ex":"She came back from the beach holiday with a deep tan.","exja":"彼女はビーチ休暇から深い日焼けをして戻ってきた。"},{"id":6501,"en":"tanned","ja":"日焼けした\n太陽などで肌が褐色になった状態","level":7,"lnum":1,"ex":"He looked healthy and tanned after spending two weeks in the Mediterranean.","exja":"地中海で2週間過ごした後、彼は健康的で日焼けした様子に見えた。"},{"id":6502,"en":"tap","ja":"軽くたたく・水道の蛇口\n軽くノックする動作、またはスマホの画面タップ","level":7,"lnum":1,"ex":"She tapped on the door lightly before entering the office.","exja":"彼女はオフィスに入る前にドアを軽くたたいた。"},{"id":6503,"en":"tatter","ja":"ぼろ・ぼろぼろ\n激しく破れた布などの状態","level":7,"lnum":1,"ex":"His old jacket was in tatters after years of use.","exja":"彼の古いジャケットは何年も使い続けてぼろぼろになっていた。"},{"id":6504,"en":"tattoo","ja":"タトゥー・入れ墨\n皮膚に描かれた永続的なデザイン","level":7,"lnum":1,"ex":"He got a tattoo of his hometown's skyline on his arm.","exja":"彼は腕に地元の街並みのタトゥーを入れた。"},{"id":6505,"en":"taunt","ja":"からかい・あざけり\n意地悪く笑い者にしたり侮辱したりする言動","level":7,"lnum":1,"ex":"The bully taunted the younger students on the playground every day.","exja":"いじめっ子は毎日運動場で年下の生徒たちをからかった。"},{"id":6506,"en":"tease","ja":"からかう\n意地悪くからかう、または軽くいじめる","level":7,"lnum":1,"ex":"He teased his little sister about her new haircut, making her laugh.","exja":"彼は妹の新しい髪型についてからかい、妹を笑わせた。"},{"id":6507,"en":"teaspoon","ja":"ティースプーン\n小さなスプーン（約5ml）","level":7,"lnum":1,"ex":"Add one teaspoon of sugar to the mixture and stir well.","exja":"混合物にティースプーン1杯の砂糖を加えてよくかき混ぜてください。"},{"id":6508,"en":"technical","ja":"技術的な\n専門的な技術や知識に関する","level":7,"lnum":1,"ex":"The mechanic gave a very technical explanation that was hard to follow.","exja":"整備士は非常に専門的な説明をしたので理解するのが難しかった。"},{"id":6509,"en":"technically","ja":"技術的には・厳密には\n正確には、または技術の観点からは","level":7,"lnum":1,"ex":"Technically, you need a visa to enter that country as a tourist.","exja":"厳密には、観光客としてその国に入国するにはビザが必要だ。"},{"id":6510,"en":"telescope","ja":"望遠鏡\n遠くの物を拡大して見る光学機器","level":7,"lnum":1,"ex":"He spent hours looking at the stars through his telescope on clear nights.","exja":"晴れた夜、彼は望遠鏡で何時間も星を眺めた。"},{"id":6511,"en":"temperate","ja":"温帯の・穏やかな\n気候が穏やか、または行動が節度ある","level":7,"lnum":1,"ex":"Japan has a temperate climate with four distinct seasons throughout the year.","exja":"日本は一年を通して四つのはっきりした季節がある温帯気候だ。"},{"id":6512,"en":"temporarily","ja":"一時的に\n限られた期間だけ続く様子","level":7,"lnum":1,"ex":"The road was temporarily closed for emergency repair work.","exja":"道路は緊急修理工事のため一時的に閉鎖された。"},{"id":6513,"en":"temptation","ja":"誘惑\n悪いとわかっていても引き寄せられる魅力的なもの","level":7,"lnum":1,"ex":"She resisted the temptation to check her phone during the lecture.","exja":"彼女は講義中に携帯を確認したいという誘惑に抵抗した。"},{"id":6514,"en":"tender","ja":"柔らかい・優しい\n食べ物が柔らかい、または感情的に優しく接する","level":7,"lnum":1,"ex":"The slow-cooked beef was so tender it practically melted in the mouth.","exja":"じっくり煮込んだ牛肉はとても柔らかく、口の中でとろけるほどだった。"},{"id":6515,"en":"tenderly","ja":"優しく・思いやりをもって\n温かみのある丁寧な態度で","level":7,"lnum":1,"ex":"She tenderly wrapped the injured bird in a soft cloth to keep it warm.","exja":"彼女は傷ついた鳥を温めるために優しく柔らかい布で包んだ。"},{"id":6516,"en":"tenderness","ja":"優しさ・柔らかさ\n人への思いやりの深さ、または食べ物の柔らかさ","level":7,"lnum":1,"ex":"The tenderness he showed toward his elderly parents was heartwarming.","exja":"彼が年老いた両親に示した優しさは心が温まるものだった。"},{"id":6517,"en":"terrace","ja":"テラス・段丘\n建物に接した外部の平らな空間","level":7,"lnum":1,"ex":"They enjoyed their morning coffee on the terrace overlooking the garden.","exja":"彼らは庭を見渡すテラスで朝のコーヒーを楽しんだ。"},{"id":6518,"en":"terrifying","ja":"恐ろしい\n強い恐怖を引き起こすほど怖い","level":7,"lnum":1,"ex":"The terrifying sound of thunder woke the children in the middle of the night.","exja":"恐ろしい雷の音が夜中に子どもたちを目覚めさせた。"},{"id":6519,"en":"territory","ja":"領土・縄張り\n国や動物が支配・管理する地域","level":7,"lnum":1,"ex":"The wolves defended their territory fiercely against rival packs.","exja":"オオカミたちはライバルの群れに対して縄張りを激しく守った。"},{"id":6520,"en":"testify","ja":"証言する\n法廷などで事実を述べる","level":7,"lnum":1,"ex":"The witness was called to testify about what she had seen that night.","exja":"証人はその夜目撃したことを証言するために呼ばれた。"},{"id":6521,"en":"testimony","ja":"証言・証拠\n法廷での発言、または何かの証明となるもの","level":7,"lnum":1,"ex":"His testimony was the key evidence that led to the conviction of the suspect.","exja":"彼の証言が容疑者の有罪につながる重要な証拠だった。"},{"id":6522,"en":"theme","ja":"テーマ・主題\n作品や議論の中心的な話題や考え","level":7,"lnum":1,"ex":"The main theme of the novel is the struggle between freedom and security.","exja":"その小説の主なテーマは自由と安全保障の間の葛藤だ。"},{"id":6523,"en":"theorist","ja":"理論家\n理論を構築・研究する学者","level":7,"lnum":1,"ex":"The political theorist argued that democracy requires an educated public.","exja":"その政治理論家は民主主義には教育ある市民が必要だと主張した。"},{"id":6524,"en":"therapist","ja":"セラピスト・治療士\n心や身体の治療・ケアを行う専門家","level":7,"lnum":1,"ex":"She visited a therapist every week to help manage her anxiety.","exja":"彼女は不安を管理するために毎週セラピストを訪れた。"},{"id":6525,"en":"therapy","ja":"療法・セラピー\n身体的または精神的な治療法","level":7,"lnum":1,"ex":"Art therapy has been shown to help patients express emotions they struggle to verbalize.","exja":"アート療法は言葉にするのが難しい感情を患者が表現するのを助けることが示されている。"},{"id":6526,"en":"thereafter","ja":"その後・それ以降\nある時点の後ずっと（やや格式的）","level":7,"lnum":1,"ex":"He moved to the countryside and thereafter lived a quieter life.","exja":"彼は田舎に引っ越し、その後は静かな生活を送った。"},{"id":6527,"en":"thermometer","ja":"温度計\n温度を測る器具","level":7,"lnum":1,"ex":"The nurse checked the patient's temperature with a digital thermometer.","exja":"看護師はデジタル温度計で患者の体温を確認した。"},{"id":6528,"en":"thesis","ja":"論文・主題\n大学の卒業論文、または議論の主要な主張","level":7,"lnum":1,"ex":"She spent two years researching and writing her master's thesis.","exja":"彼女は修士論文の研究と執筆に2年を費やした。"},{"id":6529,"en":"thickly","ja":"厚く・濃く\n厚みがある様子、または濃度が高い様子","level":7,"lnum":1,"ex":"He spread the butter thickly on the warm toast and took a big bite.","exja":"彼は温かいトーストにバターを厚く塗り、大きくかじった。"},{"id":6530,"en":"thickness","ja":"厚さ\n物体の厚みの程度","level":7,"lnum":1,"ex":"The engineer measured the thickness of the steel plates before construction.","exja":"エンジニアは建設前に鋼板の厚さを測定した。"},{"id":6531,"en":"thigh","ja":"太もも\n膝から上の脚の部分","level":7,"lnum":1,"ex":"The runner felt a sharp pain in her thigh during the final kilometer.","exja":"ランナーは最後の1kmで太ももに鋭い痛みを感じた。"},{"id":6532,"en":"thinker","ja":"思想家・考える人\n深く物事を考える人や哲学者","level":7,"lnum":1,"ex":"Albert Einstein was not only a scientist but also a profound thinker.","exja":"アルベルト・アインシュタインは科学者であるだけでなく、深遠な思想家でもあった。"},{"id":6533,"en":"third person","ja":"三人称\nhe/she/theyを指す文法用語","level":7,"lnum":1,"ex":"The essay is written in the third person to maintain an objective tone.","exja":"そのエッセイは客観的なトーンを保つために三人称で書かれている。"},{"id":6534,"en":"thirdly","ja":"第三に\n列挙するときの三番目を示す副詞","level":7,"lnum":1,"ex":"Thirdly, we need to address the issue of budget allocation for next year.","exja":"第三に、来年度の予算配分の問題に対処する必要がある。"},{"id":6535,"en":"thirst","ja":"渇き・渇望\n水を飲みたい感覚、または強い欲求","level":7,"lnum":1,"ex":"After the long run in the heat, he felt an overwhelming thirst.","exja":"暑さの中での長距離走の後、彼は強烈な渇きを感じた。"},{"id":6536,"en":"thoroughly","ja":"徹底的に\n細部まで完全に行う様子","level":7,"lnum":1,"ex":"Please read the contract thoroughly before signing it.","exja":"署名する前に契約書を徹底的に読んでください。"},{"id":6537,"en":"thoughtful","ja":"思いやりのある・深慮した\n他者を気にかける、または慎重に考える","level":7,"lnum":1,"ex":"She wrote a thoughtful thank-you letter to her mentor after graduation.","exja":"彼女は卒業後、メンターに思いやりのあるお礼の手紙を書いた。"},{"id":6538,"en":"thoughtless","ja":"思いやりのない・軽率な\n他者への配慮が欠けた行動","level":7,"lnum":1,"ex":"It was thoughtless of him to leave without saying goodbye to anyone.","exja":"誰にも別れを告げずに立ち去るのは彼の思いやりのない行動だった。"},{"id":6539,"en":"thread","ja":"糸・スレッド\n縫い糸、またはネット上の話題の流れ","level":7,"lnum":1,"ex":"She threaded the needle carefully before beginning to sew the button.","exja":"彼女はボタンを縫い始める前に慎重に針に糸を通した。"},{"id":6540,"en":"threaten","ja":"脅す・脅威となる\n危害を加えると言ったり、危機を引き起こしたりする","level":7,"lnum":1,"ex":"The company threatened to sue the blogger for spreading false information.","exja":"会社はブロガーが虚偽の情報を広めたとして訴訟を起こすと脅した。"},{"id":6541,"en":"thrill","ja":"スリル・興奮\n強い興奮や喜びの感覚","level":7,"lnum":1,"ex":"The roller coaster gave her such a thrill that she wanted to ride it again.","exja":"ジェットコースターは彼女にとてもスリルを与えたので、もう一度乗りたいと思った。"},{"id":6542,"en":"thrilled","ja":"興奮した・大喜びの\n非常に嬉しくて興奮した状態","level":7,"lnum":1,"ex":"She was thrilled to receive the scholarship she had applied for.","exja":"彼女は応募した奨学金を受け取れることに大喜びだった。"},{"id":6543,"en":"thrilling","ja":"スリリングな\n強い興奮や興味を引き起こす","level":7,"lnum":1,"ex":"The final match of the tournament was one of the most thrilling games of the year.","exja":"トーナメントの最終試合は今年最もスリリングな試合の一つだった。"},{"id":6544,"en":"tickle","ja":"くすぐる\n指などで体に触れて笑わせる、または「〜の気を引く」","level":7,"lnum":1,"ex":"The feather tickled her nose and she burst out laughing.","exja":"羽が鼻をくすぐって、彼女は突然笑い出した。"},{"id":6545,"en":"tightrope","ja":"綱渡り用ロープ\n綱渡りに使う張られたロープ。危険な立場の比喩にも使う","level":7,"lnum":1,"ex":"Managing the conflicting demands of work and family is like walking a tightrope.","exja":"仕事と家族の相反する要求を管理することは綱渡りのようなものだ。"},{"id":6546,"en":"timeless","ja":"時代を超えた\n特定の時代に限らずいつでも価値がある","level":7,"lnum":1,"ex":"The themes of love and loss in Shakespeare's plays are truly timeless.","exja":"シェイクスピアの劇における愛と喪失のテーマは真に時代を超えている。"},{"id":6547,"en":"timeliness","ja":"タイムリーさ\n適切な時期に行われるという性質","level":7,"lnum":1,"ex":"The timeliness of the emergency response was praised by the community.","exja":"緊急対応のタイムリーさが地域社会から称賛された。"},{"id":6548,"en":"times","ja":"〜倍\n数を掛ける前置詞用法（three times larger）","level":7,"lnum":1,"ex":"The new factory produces three times more goods than the old one.","exja":"新しい工場は古い工場の3倍の商品を生産している。"},{"id":6549,"en":"timing","ja":"タイミング\n行動を行う時期や時間の選び方","level":7,"lnum":1,"ex":"The timing of the announcement was perfect, just before the holiday season.","exja":"発表のタイミングは休暇シーズン直前でまさに完璧だった。"},{"id":6550,"en":"tip","ja":"傾ける・チップを払う\n端を傾ける、またはチップとして支払う動詞","level":7,"lnum":1,"ex":"She tipped the jar to pour out the last few drops of olive oil.","exja":"彼女はオリーブオイルの最後の数滴を注ぐために瓶を傾けた。"},{"id":6551,"en":"tiptoe","ja":"つま先立ちで歩く\n音を立てないようそっと歩く","level":7,"lnum":1,"ex":"She tiptoed down the hallway so as not to wake the sleeping baby.","exja":"彼女は眠っている赤ちゃんを起こさないよう廊下をつま先立ちで歩いた。"},{"id":6552,"en":"tiredness","ja":"疲れ\nエネルギーが不足して休みたい状態","level":7,"lnum":1,"ex":"He felt a deep tiredness after working three consecutive night shifts.","exja":"3回連続の夜勤をこなした後、彼は深い疲れを感じた。"},{"id":6553,"en":"tiresome","ja":"うんざりする・厄介な\n疲れを引き起こすほど退屈または面倒な","level":7,"lnum":1,"ex":"Filling out the same paperwork every year is a tiresome but necessary task.","exja":"毎年同じ書類を記入するのはうんざりするが必要な作業だ。"},{"id":6554,"en":"toenail","ja":"足の爪\n足の指に生えている爪","level":7,"lnum":1,"ex":"She painted her toenails bright red before going to the beach.","exja":"彼女はビーチに行く前に足の爪を鮮やかな赤に塗った。"},{"id":6555,"en":"toil","ja":"骨折り仕事をする\n長時間厳しく働く","level":7,"lnum":1,"ex":"Farmers toiled in the fields from sunrise to sunset during the harvest season.","exja":"農民たちは収穫期に日の出から日没まで畑で骨折り仕事をした。"},{"id":6556,"en":"tolerant","ja":"寛容な\n他者の考えや行動の違いを受け入れられる","level":7,"lnum":1,"ex":"A good teacher is tolerant of different learning styles and paces.","exja":"良い教師は様々な学習スタイルやペースに対して寛容だ。"},{"id":6557,"en":"tolerate","ja":"許容する・我慢する\n不快なことを受け入れ、または耐える","level":7,"lnum":1,"ex":"She could not tolerate the noise from the construction site next door.","exja":"彼女は隣の建設現場からの騒音を我慢できなかった。"},{"id":6558,"en":"toll","ja":"通行料・犠牲\n通行料金、または事故や災害の被害者数","level":7,"lnum":1,"ex":"The earthquake took a heavy toll on the local infrastructure.","exja":"地震は地域インフラに大きな被害をもたらした。"},{"id":6559,"en":"tomb","ja":"墓・墓室\n遺体を埋葬する構造物","level":7,"lnum":1,"ex":"Tourists visit the ancient tombs in Egypt to learn about its history.","exja":"観光客はエジプトの歴史を学ぶために古代の墓を訪れる。"},{"id":6560,"en":"tonne","ja":"トン（メートル法）\n1000kgに相当する重量単位","level":7,"lnum":1,"ex":"The truck was carrying a load of five tonnes of fresh produce.","exja":"そのトラックは5トンの新鮮な農産物を積んでいた。"},{"id":6561,"en":"torch","ja":"懐中電灯・たいまつ\nイギリス英語でフラッシュライトのこと","level":7,"lnum":1,"ex":"He used his torch to find his way through the dark cave.","exja":"彼は暗い洞窟を進むために懐中電灯を使った。"},{"id":6562,"en":"tortoiseshell","ja":"べっ甲・三毛模様\n亀の甲羅素材、または猫の三毛模様","level":7,"lnum":1,"ex":"The tortoiseshell cat sat on the windowsill and watched the birds outside.","exja":"三毛模様の猫が窓の棚に座って外の鳥を見ていた。"},{"id":6563,"en":"torture","ja":"拷問する\n強制的に情報を得るために激しい苦痛を与える","level":7,"lnum":1,"ex":"The use of torture during interrogations is prohibited under international law.","exja":"尋問中の拷問の使用は国際法の下で禁止されている。"},{"id":6564,"en":"toxic","ja":"有毒な・有害な\n体や精神に害を与える物質や状況","level":7,"lnum":1,"ex":"Exposure to toxic chemicals in the factory made many workers ill.","exja":"工場での有毒化学物質への曝露が多くの労働者を病気にした。"},{"id":6565,"en":"trace","ja":"追跡する・なぞる\n跡を追う、または線をなぞって描く","level":7,"lnum":1,"ex":"Investigators traced the phone call back to a hotel in the city center.","exja":"捜査官はその電話を市内中心部のホテルまで追跡した。"},{"id":6566,"en":"trader","ja":"商人・トレーダー\n物や株式などを売買する人","level":7,"lnum":1,"ex":"The trader bought goods in the south and sold them in the north for a profit.","exja":"その商人は南で商品を買い、北で利益を得るために売った。"},{"id":6567,"en":"trail","ja":"後を追う・トレイル\nゆっくり後に続く、または自然の遊歩道","level":7,"lnum":1,"ex":"We followed the hiking trail up the mountain until we reached the summit.","exja":"私たちは山頂に到達するまでハイキングの道を山の上まで追った。"},{"id":6568,"en":"trailer","ja":"予告編・トレーラー\n映画の予告動画、または荷台付き車両","level":7,"lnum":1,"ex":"The movie trailer got millions of views within hours of its release.","exja":"その映画の予告編は公開から数時間で何百万回もの再生回数を記録した。"},{"id":6569,"en":"trainee","ja":"研修生・訓練生\n仕事を学んでいる段階の人","level":7,"lnum":1,"ex":"The trainee nurse worked closely with experienced staff to learn the procedures.","exja":"研修生の看護師は手順を学ぶために経験豊富なスタッフと密に協力した。"},{"id":6570,"en":"trait","ja":"特性・特徴\n個人や物が持つ特別な性質","level":7,"lnum":1,"ex":"One of her most admirable traits is her ability to stay calm under pressure.","exja":"彼女の最も称賛すべき特性の一つはプレッシャーの下でも冷静でいられる能力だ。"},{"id":6571,"en":"traitor","ja":"裏切り者\n信頼した人や国を裏切る人","level":7,"lnum":1,"ex":"He was branded a traitor for revealing state secrets to the enemy.","exja":"彼は敵国に国家機密を漏らしたとして裏切り者の烙印を押された。"},{"id":6572,"en":"tramp","ja":"浮浪者・重い足音\n家のない放浪者、または重く踏みしめる音","level":7,"lnum":1,"ex":"A weary tramp knocked on the door asking for food and shelter.","exja":"疲れた浮浪者が食べ物と宿を求めてドアをノックした。"},{"id":6573,"en":"trample","ja":"踏みにじる\n足で踏みつけてつぶす、または権利を無視する","level":7,"lnum":1,"ex":"The protesters accidentally trampled the flower beds in the park.","exja":"抗議者たちは誤って公園の花壇を踏みにじった。"},{"id":6574,"en":"transcript","ja":"記録・議事録\n会話・授業などを文字に起こしたもの","level":7,"lnum":1,"ex":"She requested an official transcript from the university when applying for jobs.","exja":"彼女は就職活動のために大学に公式の成績証明書を申請した。"},{"id":6575,"en":"transfer","ja":"移転・転送\n場所や所有権を別の場所や人に移す","level":7,"lnum":1,"ex":"He transferred all the files to the new computer before returning the old one.","exja":"彼は古いパソコンを返却する前にすべてのファイルを新しいパソコンに転送した。"},{"id":6576,"en":"transfusion","ja":"輸血\n血液を患者に注入する医療行為","level":7,"lnum":1,"ex":"The patient received a blood transfusion during the emergency surgery.","exja":"患者は緊急手術中に輸血を受けた。"},{"id":6577,"en":"transient","ja":"一時的な・はかない\n長続きせず短い期間しか存在しない","level":7,"lnum":1,"ex":"The pain was transient and disappeared within a few minutes.","exja":"その痛みは一時的なもので、数分以内に消えた。"},{"id":6578,"en":"transistor","ja":"トランジスター\n電気信号を増幅・切り替える半導体部品","level":7,"lnum":1,"ex":"The invention of the transistor transformed the field of electronics forever.","exja":"トランジスターの発明は電子工学の分野を永遠に変えた。"},{"id":6579,"en":"transition","ja":"移行・過渡期\nある状態から別の状態へと変わっていく過程","level":7,"lnum":1,"ex":"The country is going through a difficult transition from war to peace.","exja":"その国は戦争から平和への困難な移行期を経験している。"},{"id":6580,"en":"transitive","ja":"他動詞の\n目的語を取る動詞に関する文法用語","level":7,"lnum":1,"ex":"In the sentence \"She kicked the ball,\" \"kicked\" is a transitive verb.","exja":"「She kicked the ball」という文において、「kicked」は他動詞だ。"},{"id":6581,"en":"transmission","ja":"送信・伝達\n信号・病気・情報などを伝える行為","level":7,"lnum":1,"ex":"The disease can be prevented by blocking its transmission through clean water.","exja":"その病気は清潔な水を通じた感染経路を遮断することで予防できる。"},{"id":6582,"en":"transmit","ja":"送信する・伝える\n信号や情報、病気などを伝達する","level":7,"lnum":1,"ex":"Mosquitoes can transmit dangerous diseases like malaria and dengue fever.","exja":"蚊はマラリアやデング熱などの危険な病気を伝染させることがある。"},{"id":6583,"en":"transparent","ja":"透明な・明瞭な\n光を通す、または隠し事がない状態","level":7,"lnum":1,"ex":"The company was praised for being transparent about its financial situation.","exja":"会社は財務状況について透明性があると称賛された。"},{"id":6584,"en":"transport","ja":"輸送する\n人や物を別の場所に運ぶ","level":7,"lnum":1,"ex":"The new railway line was built to transport goods between the two cities.","exja":"その新しい鉄道路線は二つの都市間で物資を輸送するために建設された。"},{"id":6585,"en":"traverse","ja":"横断・横切る\nある場所を端から端まで渡る","level":7,"lnum":1,"ex":"Hikers traverse the mountain range every summer despite the challenging terrain.","exja":"ハイカーたちは困難な地形にもかかわらず毎夏その山脈を横断する。"},{"id":6586,"en":"tray","ja":"お盆・トレイ\n物を運ぶための平たい容器","level":7,"lnum":1,"ex":"The waiter carried the drinks on a large silver tray across the room.","exja":"ウェイターは大きな銀のトレイに飲み物を乗せて部屋を横切った。"},{"id":6587,"en":"tread","ja":"踏む・歩く\n足で踏みしめる動作","level":7,"lnum":1,"ex":"Please tread carefully on the wet floor to avoid slipping.","exja":"滑らないよう濡れた床は慎重に踏んで歩いてください。"},{"id":6588,"en":"treaty","ja":"条約\n国家間の正式な合意文書","level":7,"lnum":1,"ex":"The two countries signed a peace treaty after years of armed conflict.","exja":"二国は何年もの武力紛争の後、平和条約に署名した。"},{"id":6589,"en":"trek","ja":"長距離の旅・トレッキング\n困難な長い旅や山歩き","level":7,"lnum":1,"ex":"They trekked for five days through the jungle before reaching the remote village.","exja":"彼らは辺境の村に到達するまで5日間ジャングルをトレッキングした。"},{"id":6590,"en":"tremendously","ja":"非常に・とても\n程度が非常に大きいことを示す副詞","level":7,"lnum":1,"ex":"The new policy has tremendously improved working conditions in the factory.","exja":"その新しい方針は工場の労働条件を非常に改善した。"},{"id":6591,"en":"tremor","ja":"震え・地震の余震\n小さな揺れ、または軽い地震の揺れ","level":7,"lnum":1,"ex":"She felt a slight tremor in her hands whenever she was anxious.","exja":"不安なとき、彼女はいつも手に軽い震えを感じた。"},{"id":6592,"en":"trial","ja":"裁判・試み\n法廷での審理、またはうまくいくか試してみること","level":7,"lnum":1,"ex":"The suspect will face trial next month for the charges brought against him.","exja":"容疑者は来月、彼に対して提起された起訴の裁判に臨む。"},{"id":6593,"en":"tribe","ja":"部族・集団\n共通の文化・言語を持つ人々のグループ","level":7,"lnum":1,"ex":"The tribe had lived in the rainforest for thousands of years undisturbed.","exja":"その部族は何千年もの間、邪魔されることなく熱帯雨林で暮らしていた。"},{"id":6594,"en":"tricky","ja":"難しい・やっかいな\n表面上は簡単そうに見えて実は難しい","level":7,"lnum":1,"ex":"Parallel parking is one of the trickiest skills to master when learning to drive.","exja":"縦列駐車は運転を学ぶときに習得が最も難しい技術の一つだ。"},{"id":6595,"en":"trio","ja":"三人組・トリオ\n三人または三つからなるグループ","level":7,"lnum":1,"ex":"The jazz trio performed an improvised set that amazed the audience.","exja":"そのジャズトリオは観客を驚かせた即興演奏を披露した。"},{"id":6596,"en":"trivial","ja":"取るに足らない・ささいな\n重要性や意味が非常に小さい","level":7,"lnum":1,"ex":"Don't waste your energy arguing over trivial matters that don't really matter.","exja":"本当に重要でないささいなことで口論してエネルギーを無駄にしないでください。"},{"id":6597,"en":"trolley","ja":"台車・ショッピングカート\n物を運ぶための車輪付きの台","level":7,"lnum":1,"ex":"She pushed the shopping trolley through the supermarket, filling it with groceries.","exja":"彼女はスーパーでショッピングカートを押しながら食料品を入れた。"},{"id":6598,"en":"troop","ja":"部隊・群れ\n軍隊の部隊、または動物や人の集まり","level":7,"lnum":1,"ex":"A troop of soldiers marched through the town during the military parade.","exja":"軍事パレードの間、一隊の兵士たちが町を行進した。"},{"id":6599,"en":"trophy","ja":"トロフィー\n勝利や功績を示す賞品","level":7,"lnum":1,"ex":"The team held up the trophy after winning the national championship.","exja":"チームは全国選手権に優勝した後、トロフィーを高く掲げた。"},{"id":6600,"en":"tropic","ja":"熱帯の\n赤道付近の高温多湿な地域に関する","level":7,"lnum":1,"ex":"The Tropic of Cancer passes through several countries in Asia and Africa.","exja":"北回帰線はアジアとアフリカのいくつかの国を通過している。"},{"id":6601,"en":"troublesome","ja":"やっかいな・面倒な\n問題を引き起こして困らせる様子","level":7,"lnum":1,"ex":"The leak in the roof was a troublesome problem that cost a lot to fix.","exja":"屋根の雨漏りは修理に多くの費用がかかるやっかいな問題だった。"},{"id":6602,"en":"trunk","ja":"幹・トランク\n木の主幹、または旅行用の大型かばん","level":7,"lnum":1,"ex":"The elephant used its trunk to pick up water and spray it over its body.","exja":"象は鼻を使って水を汲み上げ、体に吹きかけた。"},{"id":6603,"en":"trusty","ja":"信頼できる・頼もしい\n長年使い続けて信頼性が高い（やや古風）","level":7,"lnum":1,"ex":"He relied on his trusty old compass to navigate through the forest.","exja":"彼は森の中を進むために信頼できる古いコンパスに頼った。"},{"id":6604,"en":"truthful","ja":"正直な・真実を語る\n嘘をつかずに事実を話す","level":7,"lnum":1,"ex":"It is important to be truthful in your application, even if your grades are low.","exja":"成績が低くても、応募書類では正直に書くことが重要だ。"},{"id":6605,"en":"truthfulness","ja":"正直さ\n真実を言う習慣や性質","level":7,"lnum":1,"ex":"The judge praised the witness for her truthfulness and courage in court.","exja":"判事は証人の法廷での正直さと勇気を称賛した。"},{"id":6606,"en":"tub","ja":"たらい・浴槽\n洗濯や入浴に使う丸い容器","level":7,"lnum":1,"ex":"She filled the tub with hot water and bath salts after a long day.","exja":"長い一日の後、彼女は浴槽にお湯と入浴剤を入れた。"},{"id":6607,"en":"tuberculosis","ja":"結核\n肺などを侵す細菌性の感染症（TBと略す）","level":7,"lnum":1,"ex":"Tuberculosis was once a leading cause of death before antibiotics were developed.","exja":"結核は抗生物質が開発される前は死の主要な原因だった。"},{"id":6608,"en":"tug","ja":"引っ張る\n強く力を入れて引く動作","level":7,"lnum":1,"ex":"The child tugged at his mother's sleeve to get her attention.","exja":"子どもは母親の注意を引くために袖を引っ張った。"},{"id":6609,"en":"tuition","ja":"授業料・個別指導\n学費、または個人レッスンの指導","level":7,"lnum":1,"ex":"University tuition fees have risen dramatically over the past decade.","exja":"大学の授業料は過去10年間で劇的に上昇した。"},{"id":6610,"en":"tulip","ja":"チューリップ\n春に咲く球根植物の花","level":7,"lnum":1,"ex":"The fields in the Netherlands are famous for their colorful tulips in spring.","exja":"オランダの野原は春に色とりどりのチューリップで有名だ。"},{"id":6611,"en":"tumor/tumour","ja":"腫瘍\n体内の異常な細胞の塊","level":7,"lnum":1,"ex":"The doctor found a small tumor in the patient's lung during the scan.","exja":"医師はスキャン中に患者の肺に小さな腫瘍を発見した。"},{"id":6612,"en":"turbulent","ja":"荒れた・混乱した\n嵐のように激しく不安定な状態","level":7,"lnum":1,"ex":"The flight was turbulent, with the plane shaking violently for several minutes.","exja":"フライトは乱気流で、数分間飛行機が激しく揺れた。"},{"id":6613,"en":"tutor","ja":"家庭教師・指導教員\n個別指導を行う教師","level":7,"lnum":1,"ex":"She hired a private tutor to help her son prepare for the entrance exams.","exja":"彼女は息子の入試準備を助けるために家庭教師を雇った。"},{"id":6614,"en":"twinkle","ja":"きらめく・またたく\n星や光が細かく点滅して輝く","level":7,"lnum":1,"ex":"The stars twinkled brightly in the clear night sky above the mountains.","exja":"山の上の澄んだ夜空で星が明るくきらめいていた。"},{"id":6615,"en":"twisted","ja":"ねじれた・歪んだ\n物理的にねじれた状態、または性格が歪んでいる","level":7,"lnum":1,"ex":"The fallen tree had a twisted trunk that made it look like a piece of art.","exja":"倒れた木はねじれた幹を持ち、芸術作品のように見えた。"},{"id":6616,"en":"typhoid","ja":"腸チフス\n汚染された食物・水から感染する病気","level":7,"lnum":1,"ex":"Typhoid can be prevented by drinking clean water and practicing good hygiene.","exja":"腸チフスは清潔な水を飲み、衛生に気をつけることで予防できる。"},{"id":6617,"en":"tyranny","ja":"専制政治・暴政\n権力を乱用して国民を支配する統治形態","level":7,"lnum":1,"ex":"The revolution was sparked by the people's desire to escape the tyranny of the king.","exja":"その革命は王の専制政治から逃れたいという民衆の欲求によって引き起こされた。"},{"id":6618,"en":"tyrant","ja":"専制君主・暴君\n残酷に権力を行使する指導者","level":7,"lnum":1,"ex":"The people finally rose up and overthrew the cruel tyrant who had ruled for decades.","exja":"民衆はついに何十年も統治してきた残酷な暴君を打倒した。"},{"id":6619,"en":"ultimate","ja":"究極の・最終的な\n最高のまたは最終段階を示す形容詞","level":7,"lnum":1,"ex":"Her ultimate goal was to publish her own novel before turning thirty.","exja":"彼女の究極の目標は30歳になる前に自分の小説を出版することだった。"},{"id":6620,"en":"ultimately","ja":"最終的には\nすべてを考慮した結果として","level":7,"lnum":1,"ex":"After much debate, they ultimately decided to accept the compromise proposal.","exja":"多くの議論の末、彼らは最終的に妥協案を受け入れることに決めた。"},{"id":6621,"en":"unacceptable","ja":"受け入れられない\n基準や期待に届かない許容できない状態","level":7,"lnum":1,"ex":"The quality of the work submitted was completely unacceptable to the client.","exja":"提出された仕事の品質は顧客にとって全く受け入れられないものだった。"},{"id":6622,"en":"unashamedly","ja":"恥ずかしげもなく\n恥や後ろめたさを感じずに公言する様子","level":7,"lnum":1,"ex":"She unashamedly declared that pop music was her favorite genre.","exja":"彼女は恥ずかしげもなくポップミュージックが自分のお気に入りのジャンルだと宣言した。"},{"id":6623,"en":"unattractive","ja":"魅力のない\n見た目や性質が人を引きつけない","level":7,"lnum":1,"ex":"The apartment was unattractive from the outside but very comfortable inside.","exja":"そのアパートは外見は魅力がなかったが、内部は非常に快適だった。"},{"id":6624,"en":"unauthorized/unauthorised","ja":"無許可の\n正式な許可なく行われた","level":7,"lnum":1,"ex":"The unauthorized use of company equipment can lead to termination of employment.","exja":"会社の機器の無許可使用は解雇につながる可能性がある。"},{"id":6625,"en":"unavailable","ja":"利用不可の・不在の\n使用できない、または連絡が取れない状態","level":7,"lnum":1,"ex":"The doctor was unavailable that morning due to an emergency surgery.","exja":"その朝、医師は緊急手術のため対応不可だった。"},{"id":6626,"en":"unaware","ja":"気づいていない\nある事実や状況を知らない状態","level":7,"lnum":1,"ex":"She was completely unaware that her boss had already read her resignation letter.","exja":"彼女は上司がすでに退職届を読んでいたことに全く気づいていなかった。"},{"id":6627,"en":"unbearable","ja":"耐えられない\n苦しみや不快さが我慢の限界を超えた","level":7,"lnum":1,"ex":"The heat in the desert was almost unbearable during the afternoon.","exja":"砂漠の午後の暑さはほぼ耐えられないほどだった。"},{"id":6628,"en":"unbeatable","ja":"無敵の\n打ち負かすことができない","level":7,"lnum":1,"ex":"The champion had an unbeatable record of 50 wins and no losses.","exja":"そのチャンピオンは50勝無敗という無敵の記録を持っていた。"},{"id":6629,"en":"unchanged","ja":"変わっていない\n以前と同じ状態が続いている","level":7,"lnum":1,"ex":"The prices at this restaurant have remained unchanged for three years.","exja":"このレストランの価格は3年間変わっていない。"},{"id":6630,"en":"uncharacteristic","ja":"らしくない\nその人や物の典型的な特徴と異なる","level":7,"lnum":1,"ex":"It was uncharacteristic of her to arrive late, as she was usually very punctual.","exja":"彼女は通常非常に時間に正確なので、遅刻するのは彼女らしくなかった。"},{"id":6631,"en":"unclearly","ja":"不明瞭に\nはっきりしない様子で","level":7,"lnum":1,"ex":"The instructions were written so unclearly that no one could understand them.","exja":"説明書があまりにも不明瞭に書かれていて、誰も理解できなかった。"},{"id":6632,"en":"uncomfortably","ja":"不快に・居心地悪く\n不快感や緊張を伴う様子で","level":7,"lnum":1,"ex":"He shifted uncomfortably in his chair as the questions became more personal.","exja":"質問がより個人的になるにつれ、彼は椅子の中で居心地悪そうに体を動かした。"},{"id":6633,"en":"uncommon","ja":"珍しい・まれな\nありふれていなく頻繁に見られない","level":7,"lnum":1,"ex":"It is uncommon to see snow in this coastal city during winter.","exja":"この沿岸の都市では冬に雪が見られることは珍しい。"},{"id":6634,"en":"unconcerned","ja":"無関心な\n心配せず気にかけない様子","level":7,"lnum":1,"ex":"He seemed unconcerned about the deadline, which worried his teammates.","exja":"彼は締め切りについて無関心に見え、それがチームメンバーを心配させた。"},{"id":6635,"en":"unconscious","ja":"意識を失った・無意識の\n意識がない状態、または無意識の行動","level":7,"lnum":1,"ex":"The injured player was unconscious for a few seconds after the collision.","exja":"衝突後、負傷した選手は数秒間意識を失っていた。"},{"id":6636,"en":"underestimate","ja":"過小評価する\n実際の価値・能力より低く見積もる","level":7,"lnum":1,"ex":"Don't underestimate the difficulty of the final exam — it's very challenging.","exja":"最終試験の難しさを過小評価しないでください — 非常に難しいです。"},{"id":6637,"en":"undergraduate","ja":"学部生\n大学の学士課程に在籍する学生","level":7,"lnum":1,"ex":"She completed her undergraduate degree in biology before applying to medical school.","exja":"彼女は医学部に応募する前に生物学の学士課程を修了した。"},{"id":6638,"en":"underneath","ja":"〜の下に\n物の真下にある位置を示す副詞","level":7,"lnum":1,"ex":"The keys had fallen underneath the sofa and were hard to find.","exja":"鍵がソファの下に落ちていて見つけるのが難しかった。"},{"id":6639,"en":"undersea","ja":"海底の\n海の底に関する形容詞","level":7,"lnum":1,"ex":"Scientists discovered a new species of fish in an undersea cave near the coast.","exja":"科学者たちは海岸近くの海底洞窟で新しい魚の種を発見した。"},{"id":6640,"en":"understandable","ja":"理解できる・当然の\n理解しやすい、または納得できる","level":7,"lnum":1,"ex":"Her frustration was completely understandable given the circumstances.","exja":"彼女の不満は状況を考えれば完全に理解できるものだった。"},{"id":6641,"en":"undertake","ja":"引き受ける・着手する\n責任を持って仕事や任務を始める","level":7,"lnum":1,"ex":"The university agreed to undertake a research project on climate change adaptation.","exja":"大学は気候変動適応に関する研究プロジェクトを引き受けることに同意した。"},{"id":6642,"en":"underwater","ja":"水中で・水面下の\n水の中にある、または水中での活動","level":7,"lnum":1,"ex":"The divers photographed a stunning coral reef underwater near the tropical island.","exja":"ダイバーたちは熱帯の島の近くで水中の見事なサンゴ礁を撮影した。"},{"id":6643,"en":"undoubtedly","ja":"疑いなく\n確実に・間違いなく","level":7,"lnum":1,"ex":"She is undoubtedly one of the most talented pianists of her generation.","exja":"彼女は疑いなく彼女の世代で最も才能あるピアニストの一人だ。"},{"id":6644,"en":"undreamed","ja":"夢にも思わなかった\n想像したこともなかった（undreamed ofで使う）","level":7,"lnum":1,"ex":"The internet has created opportunities that were undreamed of fifty years ago.","exja":"インターネットは50年前には夢にも思わなかった機会を生み出した。"},{"id":6645,"en":"undressed","ja":"服を脱いだ\n衣服を着ていない状態","level":7,"lnum":1,"ex":"The child got undressed and ready for his bath without any help.","exja":"子どもは助けを借りずに服を脱いでお風呂の準備をした。"},{"id":6646,"en":"unease","ja":"不安・不快感\n漠然とした落ち着かない感覚","level":7,"lnum":1,"ex":"A feeling of unease settled over the crowd when the ceremony was delayed.","exja":"式典が遅延すると、群衆に不安感が漂い始めた。"},{"id":6647,"en":"uneasily","ja":"不安げに・落ち着かなく\n緊張や不安を感じながら行動する様子","level":7,"lnum":1,"ex":"She waited uneasily outside the principal's office, not knowing what to expect.","exja":"何を期待すればいいかわからず、彼女は不安げに校長室の外で待った。"},{"id":6648,"en":"unenthusiastic","ja":"乗り気でない\n熱意や意欲がない様子","level":7,"lnum":1,"ex":"The students were unenthusiastic about the extra homework assigned over the holidays.","exja":"生徒たちは休暇中に出された追加の宿題に乗り気でなかった。"},{"id":6649,"en":"uneven","ja":"不均等な・でこぼこの\n表面が平らでない、または配分が均等でない","level":7,"lnum":1,"ex":"The uneven surface of the old road made the bicycle ride very uncomfortable.","exja":"古い道路の凹凸のある表面が自転車に乗るのをとても不快にした。"},{"id":6650,"en":"unfamiliar","ja":"なじみのない・知らない\nよく知らない、または経験したことのない","level":7,"lnum":1,"ex":"She found herself in an unfamiliar city with no map and no phone battery.","exja":"彼女は地図も電話の電池もない見知らぬ都市にいることに気づいた。"},{"id":6651,"en":"unfashionable","ja":"時代遅れの\n現在の流行に合っていない","level":7,"lnum":1,"ex":"Wearing a tie to a casual office has become quite unfashionable in recent years.","exja":"カジュアルなオフィスでネクタイをすることは近年かなり時代遅れになっている。"},{"id":6652,"en":"unforeseen","ja":"予期しない\n事前に予測できなかった出来事","level":7,"lnum":1,"ex":"The delay was caused by unforeseen technical problems with the software.","exja":"遅延はソフトウェアの予期しない技術的問題によって引き起こされた。"},{"id":6653,"en":"ungodly","ja":"不敬な・ひどい\n神を敬わない、または非常識な時間帯などに使う","level":7,"lnum":1,"ex":"The alarm went off at an ungodly hour, long before sunrise.","exja":"目覚まし時計が日の出のずっと前の非常識な時間に鳴った。"},{"id":6654,"en":"unhappiness","ja":"不幸・悲しみ\n幸せでない状態や気持ち","level":7,"lnum":1,"ex":"Her unhappiness at work made her realize it was time to change careers.","exja":"仕事での不幸が彼女にキャリアを変える時だと気づかせた。"},{"id":6655,"en":"unhelpful","ja":"役に立たない\n助けにならない行動や人","level":7,"lnum":1,"ex":"The customer service representative was unhelpful and didn't solve any of her problems.","exja":"カスタマーサービスの担当者は役に立たず、彼女の問題を一つも解決しなかった。"},{"id":6656,"en":"unimaginable","ja":"想像できない\n心に思い描くことすら難しいほどの","level":7,"lnum":1,"ex":"The loss of a child is an unimaginable pain that no parent should face.","exja":"子を失うことは親が直面すべきでない想像できない痛みだ。"},{"id":6657,"en":"unimaginably","ja":"想像を絶するほど\n通常では思い描けないほど極端に","level":7,"lnum":1,"ex":"The scale of the disaster was unimaginably large, affecting millions of people.","exja":"その災害の規模は想像を絶するほど大きく、何百万人もの人々に影響を与えた。"},{"id":6658,"en":"united","ja":"団結した・統一された\n共同の目的のために一致した状態","level":7,"lnum":1,"ex":"The team stood united behind their captain during the difficult season.","exja":"チームは困難なシーズンの間、キャプテンを一致団結して支えた。"},{"id":6659,"en":"universal","ja":"普遍的な\nすべての人や場合に当てはまる","level":7,"lnum":1,"ex":"Music has a universal appeal that transcends language and culture.","exja":"音楽は言語と文化を超えた普遍的な魅力を持っている。"},{"id":6660,"en":"unjustly","ja":"不当に\n公正さに欠ける方法で","level":7,"lnum":1,"ex":"She felt unjustly treated when she was passed over for the promotion.","exja":"昇進を見送られたとき、彼女は不当な扱いを受けたと感じた。"},{"id":6661,"en":"unkind","ja":"不親切な・意地悪な\n他者への思いやりが欠けた","level":7,"lnum":1,"ex":"It was unkind of him to laugh at her mistake in front of everyone.","exja":"みんなの前で彼女の間違いを笑うのは彼の不親切な行動だった。"},{"id":6662,"en":"unlike","ja":"〜とは違って\n比較して異なることを示す前置詞","level":7,"lnum":1,"ex":"Unlike her sister, she preferred science over art at school.","exja":"姉とは違って、彼女は学校で美術より理科が好きだった。"},{"id":6663,"en":"unlimited","ja":"無制限の\n上限や制約がない状態","level":7,"lnum":1,"ex":"The subscription plan offers unlimited streaming of music and podcasts.","exja":"そのサブスクリプションプランは音楽とポッドキャストの無制限ストリーミングを提供している。"},{"id":6664,"en":"unload","ja":"荷を下ろす\n積んだ荷物を降ろす","level":7,"lnum":1,"ex":"The workers unloaded the delivery trucks as soon as they arrived at the warehouse.","exja":"作業員たちは倉庫に到着するとすぐにトラックから荷を下ろした。"},{"id":6665,"en":"unlock","ja":"鍵を開ける\n施錠されたものを解除する","level":7,"lnum":1,"ex":"He forgot the passcode and couldn't unlock his smartphone.","exja":"彼はパスコードを忘れてスマートフォンの鍵を開けられなかった。"},{"id":6666,"en":"unmistakable","ja":"間違えようのない\n非常に明確で見間違えない","level":7,"lnum":1,"ex":"The unmistakable smell of freshly baked bread filled the street.","exja":"焼きたてのパンの間違えようのない香りが通りに漂っていた。"},{"id":6667,"en":"unmistakably","ja":"明らかに・疑いなく\n見間違えようがないほど明確に","level":7,"lnum":1,"ex":"His accent was unmistakably British, even after years of living abroad.","exja":"何年も海外に住んでいても、彼のアクセントは明らかにイギリス英語だった。"},{"id":6668,"en":"unnatural","ja":"不自然な\n普通でない、または人工的に作られた","level":7,"lnum":1,"ex":"The child's behavior seemed unnatural, which concerned the school counselor.","exja":"その子どもの行動は不自然に見え、学校カウンセラーが心配した。"},{"id":6669,"en":"unofficial","ja":"非公式の\n正式な権限や承認のない","level":7,"lnum":1,"ex":"The two leaders had an unofficial meeting before the formal summit began.","exja":"正式なサミットが始まる前に、二人の指導者は非公式の会談を行った。"},{"id":6670,"en":"unpopular","ja":"不人気な\n多くの人に好かれない","level":7,"lnum":1,"ex":"The new tax policy was deeply unpopular with working-class families.","exja":"その新しい税制政策は労働者階級の家族の間で非常に不人気だった。"},{"id":6671,"en":"unrealistic","ja":"非現実的な\n実際には実現が難しい","level":7,"lnum":1,"ex":"His plan to finish the entire book in one day was completely unrealistic.","exja":"一日で本を全部読み終えるという彼の計画は全く非現実的だった。"},{"id":6672,"en":"unreasonable","ja":"不合理な\n道理に合わない、または過度な要求をする","level":7,"lnum":1,"ex":"The landlord made unreasonable demands that the tenant refused to accept.","exja":"家主は借家人が受け入れを拒否した不合理な要求をした。"},{"id":6673,"en":"unreliable","ja":"信頼できない\n当てにならない・信用できない","level":7,"lnum":1,"ex":"The old car was unreliable and often broke down on long journeys.","exja":"その古い車は信頼できず、長距離旅行でよく故障した。"},{"id":6674,"en":"unrest","ja":"不穏・動乱\n社会的な不満や混乱の状態","level":7,"lnum":1,"ex":"Social unrest spread through the city after the controversial verdict was announced.","exja":"物議を醸した判決が発表された後、社会不安が都市全体に広がった。"},{"id":6675,"en":"unsafe","ja":"危険な\n安全でない状態","level":7,"lnum":1,"ex":"The building was declared unsafe and residents were ordered to evacuate immediately.","exja":"建物は危険と宣言され、住民は直ちに避難するよう命じられた。"},{"id":6676,"en":"unsatisfactory","ja":"不満足な\n期待や基準を満たしていない","level":7,"lnum":1,"ex":"The inspector reported that the restaurant's hygiene standards were unsatisfactory.","exja":"監察官はレストランの衛生基準が不満足であると報告した。"},{"id":6677,"en":"unselfish","ja":"無私の\n自分の利益より他者を優先する","level":7,"lnum":1,"ex":"Her unselfish decision to donate her prize money helped dozens of local families.","exja":"賞金を寄付するという彼女の無私の決断が地元の多くの家族を助けた。"},{"id":6678,"en":"unstoppable","ja":"止められない\n何があっても止めることができない","level":7,"lnum":1,"ex":"The team's momentum seemed unstoppable as they won match after match.","exja":"チームは次々と試合に勝ち続け、その勢いは止められないように見えた。"},{"id":6679,"en":"unsuccessful","ja":"失敗した\n目標を達成できなかった","level":7,"lnum":1,"ex":"The first attempt was unsuccessful, but she refused to give up and tried again.","exja":"最初の試みは失敗したが、彼女はあきらめずにもう一度挑戦した。"},{"id":6680,"en":"unsuitable","ja":"不適切な\n目的や状況に合っていない","level":7,"lnum":1,"ex":"This movie is unsuitable for young children due to its violent scenes.","exja":"この映画は暴力的なシーンがあるため幼い子どもには不適切だ。"},{"id":6681,"en":"unsure","ja":"確信がない\nはっきりわからず迷っている状態","level":7,"lnum":1,"ex":"She was unsure whether to accept the job offer or wait for a better opportunity.","exja":"彼女は仕事のオファーを受け入れるか、より良い機会を待つか迷っていた。"},{"id":6682,"en":"untalented","ja":"才能のない\n特別な能力を持っていない","level":7,"lnum":1,"ex":"He felt untalented compared to his classmates, but he kept practicing every day.","exja":"彼はクラスメートと比べて才能がないと感じたが、毎日練習し続けた。"},{"id":6683,"en":"unthinkably","ja":"考えられないほど\n普通では思いもよらないほど極端に","level":7,"lnum":1,"ex":"The project was completed in an unthinkably short time thanks to the whole team.","exja":"チーム全員のおかげで、プロジェクトは考えられないほど短い時間で完成した。"},{"id":6684,"en":"untie","ja":"ほどく\n結んだものをほどく","level":7,"lnum":1,"ex":"She untied the ribbon carefully so she could reuse it later.","exja":"彼女は後で再利用できるようにリボンを丁寧にほどいた。"},{"id":6685,"en":"unto","ja":"〜へ・〜まで\ntoの古語・文語的な形","level":7,"lnum":1,"ex":"The knight swore loyalty unto his king until the very end.","exja":"騎士は最後まで王への忠誠を誓った。"},{"id":6686,"en":"untreated","ja":"未治療の・未処理の\n適切な処置がされていない状態","level":7,"lnum":1,"ex":"Untreated water from the river can cause serious health problems if consumed.","exja":"川の未処理の水を飲むと深刻な健康問題を引き起こす可能性がある。"},{"id":6687,"en":"untrimmed","ja":"刈り込まれていない\n端が整えられていない状態","level":7,"lnum":1,"ex":"The untrimmed hedge along the fence made the garden look neglected.","exja":"フェンス沿いの刈り込まれていない生垣が庭を荒れ放題に見せた。"},{"id":6688,"en":"unusualness","ja":"異常さ・珍しさ\n普通と異なる性質や状態","level":7,"lnum":1,"ex":"The unusualness of the situation left everyone uncertain about what to do next.","exja":"その状況の異常さが全員を次に何をすべきか不確かにした。"},{"id":6689,"en":"unwilling","ja":"気が進まない\nやりたくない・したくない気持ち","level":7,"lnum":1,"ex":"He was unwilling to share his research findings before they were published.","exja":"彼は研究成果が発表される前に共有することに気が進まなかった。"},{"id":6690,"en":"unwise","ja":"賢明でない\n判断や行動が適切でない","level":7,"lnum":1,"ex":"It was unwise to invest all your savings in a single company.","exja":"全ての貯金を一つの会社に投資するのは賢明でなかった。"},{"id":6691,"en":"unworldly","ja":"世間知らずの\n現実の世界の経験や知識がない","level":7,"lnum":1,"ex":"His unworldly attitude made it difficult for him to handle everyday practicalities.","exja":"彼の世間知らずな態度が日常的な実際的なことを処理するのを難しくした。"},{"id":6692,"en":"upbringing","ja":"育て方・しつけ\n子どもの頃に受けた教育や養育の方法","level":7,"lnum":1,"ex":"Her strict upbringing taught her the value of discipline and hard work.","exja":"厳しい育て方が彼女に規律と勤勉の価値を教えた。"},{"id":6693,"en":"update","ja":"最新情報・更新\n最新の状態に変更すること、またはその情報","level":7,"lnum":1,"ex":"The software update fixed several bugs and improved overall performance.","exja":"ソフトウェアの更新でいくつかのバグが修正され、全体的なパフォーマンスが向上した。"},{"id":6694,"en":"upgrade","ja":"アップグレード・改善\nより良い状態やバージョンに引き上げること","level":7,"lnum":1,"ex":"The airline offered to upgrade our seats to business class at no extra charge.","exja":"航空会社は追加料金なしで私たちの座席をビジネスクラスにアップグレードすることを申し出た。"},{"id":6695,"en":"upgrade","ja":"アップグレードする\n品質やバージョンを改善・引き上げる動詞","level":7,"lnum":1,"ex":"The company upgraded its software to improve security and performance.","exja":"その会社はセキュリティとパフォーマンスを向上させるためにソフトウェアをアップグレードした。"},{"id":6696,"en":"upright","ja":"まっすぐな・直立した\n垂直に立っている状態を示す形容詞","level":7,"lnum":1,"ex":"The upright posture of soldiers during the parade impressed the spectators.","exja":"パレード中の兵士の直立した姿勢が観客を感銘させた。"},{"id":6697,"en":"upright","ja":"直立して\nまっすぐ立った姿勢でという副詞","level":7,"lnum":1,"ex":"She sat upright in her chair during the entire interview.","exja":"彼女は面接の間ずっと椅子にまっすぐ直立して座っていた。"},{"id":6698,"en":"upside down","ja":"逆さまの\n上下が逆になった状態の形容詞","level":7,"lnum":1,"ex":"The toddler turned the bowl upside down and spilled porridge all over the table.","exja":"幼児がボウルを逆さまにして、テーブル中にお粥をこぼした。"},{"id":6699,"en":"upside down","ja":"逆さまに\n上下を逆にした状態での副詞","level":7,"lnum":1,"ex":"He accidentally put the map upside down and got completely lost.","exja":"彼は誤って地図を逆さまにして、完全に道に迷った。"},{"id":6700,"en":"urban","ja":"都市の\n都市や町に関連する形容詞","level":7,"lnum":1,"ex":"The city is facing serious challenges related to urban poverty and housing.","exja":"その都市は都市の貧困と住宅に関する深刻な課題に直面している。"},{"id":6701,"en":"urge","ja":"強く勧める・衝動\nぜひそうするよう促す動詞、または内側からの強い欲求","level":7,"lnum":1,"ex":"The doctor urged her to quit smoking for the sake of her health.","exja":"医師は健康のためにタバコをやめるよう彼女に強く勧めた。"},{"id":6702,"en":"urgently","ja":"緊急に\nすぐに対応が必要な様子で","level":7,"lnum":1,"ex":"The hospital urgently needs blood donations to treat accident victims.","exja":"病院は事故の被害者を治療するために緊急に血液の献血が必要だ。"},{"id":6703,"en":"usher","ja":"案内する\n劇場や式典などで席に誘導する","level":7,"lnum":1,"ex":"The staff ushered the guests to their seats before the concert began.","exja":"コンサートが始まる前にスタッフが客を席に案内した。"},{"id":6704,"en":"utility","ja":"実用性・公共サービス\n日常生活に役立つもの、または電気・水道などのサービス","level":7,"lnum":1,"ex":"The government subsidizes utility costs for low-income households.","exja":"政府は低所得世帯の公共サービス料金を補助している。"},{"id":6705,"en":"utilize/utilise","ja":"活用する\nuseのより公式的な言い方。資源や機会を有効に使う","level":7,"lnum":1,"ex":"The research team utilized advanced technology to analyze the data.","exja":"研究チームはデータを分析するために先進技術を活用した。"},{"id":6706,"en":"utter","ja":"口に出す\n言葉を声に出して発する","level":7,"lnum":1,"ex":"She could not utter a single word when she saw the accident happen.","exja":"事故が起きるのを見たとき、彼女は一言も口に出すことができなかった。"},{"id":6707,"en":"utterly","ja":"全く・完全に\n程度が完全であることを示す強調副詞","level":7,"lnum":1,"ex":"He was utterly exhausted after the marathon and could barely walk.","exja":"マラソン後、彼は全く疲れ果てて歩くのがやっとだった。"},{"id":6708,"en":"vacant","ja":"空いている・空虚な\n人や物が入っていない状態。またはぼんやりした表情","level":7,"lnum":1,"ex":"The apartment has been vacant for three months since the previous tenant left.","exja":"前の入居者が去ってから、そのアパートは3ヶ月間空いている。"},{"id":6709,"en":"vaccine","ja":"ワクチン\n免疫を付けるための予防接種薬","level":7,"lnum":1,"ex":"Scientists developed the vaccine in record time during the global health crisis.","exja":"科学者たちはグローバルな健康危機の中で記録的な速さでワクチンを開発した。"},{"id":6710,"en":"valentine","ja":"バレンタインカード・恋人\nバレンタインデーに贈るカードまたは恋人","level":7,"lnum":1,"ex":"He sent his girlfriend a handwritten valentine with a bouquet of red roses.","exja":"彼は彼女に赤いバラの花束とともに手書きのバレンタインカードを送った。"},{"id":6711,"en":"valid","ja":"有効な・正当な\n法的・論理的に認められる状態","level":7,"lnum":1,"ex":"Her student ID is valid until the end of the academic year.","exja":"彼女の学生証は学年末まで有効だ。"},{"id":6712,"en":"value","ja":"大切にする・評価する\n何かの価値を認めて重視する動詞","level":7,"lnum":1,"ex":"She values honesty above all other qualities in a friend.","exja":"彼女は友人において正直さを他のどの資質よりも大切にしている。"},{"id":6713,"en":"vanish","ja":"消える・姿を消す\n突然見えなくなる","level":7,"lnum":1,"ex":"The magician made the rabbit vanish into thin air before the audience's eyes.","exja":"手品師は観客の目の前でウサギを瞬時に消した。"},{"id":6714,"en":"vanity","ja":"虚栄心・無意味さ\n外見や地位への過度な関心。虚しいという哲学的な意味もある","level":7,"lnum":1,"ex":"His vanity prevented him from admitting that he needed glasses.","exja":"虚栄心が彼に眼鏡が必要だと認めることを妨げた。"},{"id":6715,"en":"variation","ja":"変化・バリエーション\n基準からの違い、または様々なバリエーション","level":7,"lnum":1,"ex":"There is a significant variation in temperature between the coast and the mountains.","exja":"海岸と山の間には気温に大きな変化がある。"},{"id":6716,"en":"varied","ja":"様々な・変化に富んだ\n種類や内容が多岐にわたる","level":7,"lnum":1,"ex":"The menu offered a varied selection of dishes from around the world.","exja":"メニューは世界各地の様々な料理の選択肢を提供していた。"},{"id":6717,"en":"venture","ja":"冒険・リスクを冒す\nリスクを伴う事業や行動","level":7,"lnum":1,"ex":"She ventured into the startup world after leaving her stable corporate job.","exja":"彼女は安定した企業での仕事を辞めてスタートアップの世界に踏み出した。"},{"id":6718,"en":"venue","ja":"会場\nイベントや集会が行われる場所","level":7,"lnum":1,"ex":"The wedding venue was a beautiful garden surrounded by cherry blossom trees.","exja":"結婚式の会場は桜の木に囲まれた美しい庭園だった。"},{"id":6719,"en":"verbal","ja":"言葉の・口頭の\n文字ではなく言葉や話し言葉に関する","level":7,"lnum":1,"ex":"The teacher gave verbal feedback to each student after their presentation.","exja":"先生はプレゼンテーションの後、各生徒に口頭でフィードバックを与えた。"},{"id":6720,"en":"verbally","ja":"口頭で\n言葉で直接伝える様子","level":7,"lnum":1,"ex":"The manager verbally agreed to the proposal but did not sign any contract.","exja":"マネージャーは提案に口頭で合意したが、いかなる契約にも署名しなかった。"},{"id":6721,"en":"verse","ja":"詩・節\n詩の一節、または聖書の一節","level":7,"lnum":1,"ex":"He versed a heartfelt tribute to his late grandmother at the memorial ceremony.","exja":"彼は追悼式で亡き祖母への心のこもった詩を作った。"},{"id":6722,"en":"verse","ja":"詩を作る\n詩を書く動詞（やや古風）","level":7,"lnum":1,"ex":"The poet versed his longing for home in a quiet and moving poem.","exja":"詩人は故郷への想いを静かで心打つ詩に詠んだ。"},{"id":6723,"en":"version","ja":"バージョン・版\n特定の形や段階のもの","level":7,"lnum":1,"ex":"The movie is based on an updated version of the classic fairy tale.","exja":"その映画は古典的な童話の更新されたバージョンに基づいている。"},{"id":6724,"en":"versus","ja":"〜対〜・〜に対して\n対立・比較を示す前置詞","level":7,"lnum":1,"ex":"The debate was framed as individual freedom versus collective responsibility.","exja":"その議論は個人の自由対集団的責任という形で組み立てられた。"},{"id":6725,"en":"veteran","ja":"ベテラン・退役軍人\n長年の経験を持つ人、または軍の退役者","level":7,"lnum":1,"ex":"The veteran teacher had over thirty years of experience in the classroom.","exja":"そのベテランの教師は教室で30年以上の経験を持っていた。"},{"id":6726,"en":"vibrate","ja":"振動する\n素早く前後に揺れる","level":7,"lnum":1,"ex":"The whole building began to vibrate when the earthquake started.","exja":"地震が始まったとき、建物全体が振動し始めた。"},{"id":6727,"en":"vibration","ja":"振動\n物体の素早い前後の動き","level":7,"lnum":1,"ex":"The vibration from the heavy machinery kept the workers awake all night.","exja":"重機からの振動が一晩中作業員を眠れなくさせた。"},{"id":6728,"en":"viewer","ja":"視聴者・見る人\nテレビや映像を見ている人","level":7,"lnum":1,"ex":"The documentary attracted over five million viewers on its first night.","exja":"そのドキュメンタリーは初日の夜に500万人以上の視聴者を引きつけた。"},{"id":6729,"en":"vigor/vigour","ja":"活力・精力\n強さや熱意をもって行動するエネルギー","level":7,"lnum":1,"ex":"She attacked the problem with great vigor and solved it within an hour.","exja":"彼女は大きな活力でその問題に取り組み、1時間以内に解決した。"},{"id":6730,"en":"vigorous","ja":"精力的な・元気な\n強い力や意欲を持って行動する","level":7,"lnum":1,"ex":"Regular vigorous exercise helps reduce the risk of heart disease.","exja":"定期的な激しい運動は心臓病のリスクを減らすのに役立つ。"},{"id":6731,"en":"vigorously","ja":"精力的に・活発に\n強い活力を持って行動する様子","level":7,"lnum":1,"ex":"The lawyer vigorously defended her client against the accusations.","exja":"弁護士は依頼人の弁護を精力的に行った。"},{"id":6732,"en":"villa","ja":"別荘・ヴィラ\n豪華な一軒家、特に保養地にある邸宅","level":7,"lnum":1,"ex":"They rented a private villa by the sea for their anniversary vacation.","exja":"彼らは記念日の休暇のために海辺のプライベートヴィラを借りた。"},{"id":6733,"en":"villager","ja":"村人\n村に住む人","level":7,"lnum":1,"ex":"The villagers gathered in the square to celebrate the annual harvest festival.","exja":"村人たちは毎年恒例の収穫祭を祝うために広場に集まった。"},{"id":6734,"en":"violate","ja":"侵害する・違反する\n法律や権利を破る","level":7,"lnum":1,"ex":"The company violated environmental regulations by dumping waste into the river.","exja":"その会社は廃棄物を川に捨てることで環境規制に違反した。"},{"id":6735,"en":"virtual reality","ja":"仮想現実\nコンピューターで作られた体験できる仮想の空間","level":7,"lnum":1,"ex":"Students can now explore ancient Rome through virtual reality in the classroom.","exja":"生徒たちは今や教室でバーチャルリアリティを通じて古代ローマを探索できる。"},{"id":6736,"en":"virtually","ja":"事実上・ほとんど\nほぼそうだといえるほどの状態","level":7,"lnum":1,"ex":"The project is virtually complete — just a few details remain to be finalized.","exja":"プロジェクトはほぼ完成しており、最終確認が必要な細部が少し残るだけだ。"},{"id":6737,"en":"virtue","ja":"美徳・長所\n道徳的に優れた性質や能力","level":7,"lnum":1,"ex":"Patience is a virtue that is especially important when dealing with children.","exja":"忍耐は子どもと接するときに特に重要な美徳だ。"},{"id":6738,"en":"visibly","ja":"目に見えて\n明らかに見える形で変化している様子","level":7,"lnum":1,"ex":"She was visibly shaken after hearing the unexpected news about her colleague.","exja":"同僚についての予期せぬニュースを聞いた後、彼女は目に見えて動揺していた。"},{"id":6739,"en":"vital","ja":"不可欠な・生命の\nなくてはならない重要なもの","level":7,"lnum":1,"ex":"Sleep is vital for the body to repair itself and maintain good health.","exja":"睡眠は体が自己修復して健康を維持するために不可欠だ。"},{"id":6740,"en":"vitamin","ja":"ビタミン\n健康維持に必要な栄養素","level":7,"lnum":1,"ex":"Eating fresh fruits is a great way to get the vitamins your body needs.","exja":"新鮮な果物を食べることは体に必要なビタミンを摂取する素晴らしい方法だ。"},{"id":6741,"en":"vocalist","ja":"ボーカリスト\n歌手。特に音楽グループの歌担当","level":7,"lnum":1,"ex":"The lead vocalist of the band has an extraordinary three-octave vocal range.","exja":"そのバンドのリードボーカリストは3オクターブという並外れた音域を持っている。"},{"id":6742,"en":"vomit","ja":"嘔吐物\n胃の内容物を吐いたもの","level":7,"lnum":1,"ex":"The motion of the ferry made several passengers feel sick and vomit.","exja":"フェリーの揺れが何人かの乗客を気分が悪くし、嘔吐させた。"},{"id":6743,"en":"voter","ja":"有権者・投票者\n選挙で投票する権利・義務を持つ人","level":7,"lnum":1,"ex":"Millions of voters turned out to cast their ballots in the historic election.","exja":"歴史的な選挙で何百万人もの有権者が投票するために来場した。"},{"id":6744,"en":"vow","ja":"誓い・誓約\n強く約束する正式な宣言","level":7,"lnum":1,"ex":"She made a vow to herself that she would travel the world before turning thirty.","exja":"彼女は30歳になる前に世界を旅すると自分に誓った。"},{"id":6745,"en":"wage","ja":"賃金・給与\n労働に対して支払われるお金（複数形wagesが多い）","level":7,"lnum":1,"ex":"Workers went on strike to demand higher wages and better working conditions.","exja":"労働者は高い賃金とより良い労働条件を要求するためにストライキを行った。"},{"id":6746,"en":"waist","ja":"ウエスト\n胴体の細くなった部分","level":7,"lnum":1,"ex":"She measured her waist before buying the formal dress online.","exja":"彼女はオンラインでフォーマルドレスを購入する前にウエストを測った。"},{"id":6747,"en":"waistcoat","ja":"チョッキ・ベスト\n袖なしの上着（イギリス英語）","level":7,"lnum":1,"ex":"He wore a smart waistcoat over his shirt for the job interview.","exja":"彼は就職面接のためにシャツの上に上品なチョッキを着た。"},{"id":6748,"en":"walkabout","ja":"歩き回り・気ままな旅\n公人が一般市民と交流する非公式な散歩","level":7,"lnum":1,"ex":"The prime minister went on a walkabout in the city center, greeting locals.","exja":"首相は市内中心部で市民と交流しながら歩き回りをした。"},{"id":6749,"en":"walker","ja":"歩行者・歩行補助器\n歩く人、または歩行を助ける器具","level":7,"lnum":1,"ex":"The walker rested on a bench by the trail to enjoy the mountain view.","exja":"歩行者はトレイル脇のベンチに座って山の景色を楽しみながら休んだ。"},{"id":6750,"en":"wallboard","ja":"壁板・ボード\n壁の内装に使われる板材","level":7,"lnum":1,"ex":"The interior walls were covered with wallboard before the plaster was applied.","exja":"漆喰を塗る前に内壁を壁板で覆った。"},{"id":6751,"en":"walnut","ja":"クルミ\n食用のナッツと、それが実る木","level":7,"lnum":1,"ex":"She added chopped walnuts to the salad for a crunchy texture.","exja":"彼女はサラダに刻んだクルミをサクサクした食感のために加えた。"},{"id":6752,"en":"warship","ja":"軍艦\n軍事目的の船","level":7,"lnum":1,"ex":"The navy sent three warships to patrol the disputed coastal waters.","exja":"海軍は係争中の沿岸水域を哨戒するために3隻の軍艦を派遣した。"},{"id":6753,"en":"wartime","ja":"戦時\n戦争が行われている期間","level":7,"lnum":1,"ex":"During wartime, food and fuel were rationed to ensure fair distribution.","exja":"戦時中、公正な配給を確保するために食料と燃料が配給制になった。"},{"id":6754,"en":"wasp","ja":"スズメバチ\n黄色と黒の縞模様を持つ刺す昆虫","level":7,"lnum":1,"ex":"She accidentally disturbed a wasp nest and got stung several times.","exja":"彼女は誤ってスズメバチの巣を刺激し、何度も刺された。"},{"id":6755,"en":"waterproof","ja":"防水の\n水が染み込まない性質の","level":7,"lnum":1,"ex":"She wore a waterproof jacket during the hike to stay dry in the rain.","exja":"彼女はハイキング中に雨で濡れないよう防水ジャケットを着た。"},{"id":6756,"en":"weaken","ja":"弱める・弱くなる\n強度や力を減少させる","level":7,"lnum":1,"ex":"The long illness weakened his immune system and made recovery slow.","exja":"長い病気が彼の免疫系を弱め、回復を遅らせた。"},{"id":6757,"en":"weakly","ja":"弱く・力なく\n力や勢いが不足している様子で","level":7,"lnum":1,"ex":"The injured bird flapped its wings weakly before being taken to the vet.","exja":"傷ついた鳥は獣医に連れて行かれる前に力なく羽を羽ばたかせた。"},{"id":6758,"en":"wealthy","ja":"裕福な・金持ちの\n多くの財産を持っている","level":7,"lnum":1,"ex":"The wealthy businesswoman donated millions to local charities every year.","exja":"その裕福な実業家は毎年地元の慈善団体に何百万ドルも寄付した。"},{"id":6759,"en":"wearisome","ja":"うんざりする・疲れる\n長く続いて飽き飽きする様子","level":7,"lnum":1,"ex":"The repetitive administrative tasks became wearisome after several weeks.","exja":"数週間後、繰り返しの行政作業はうんざりするものになった。"},{"id":6760,"en":"weary","ja":"疲れた・うんざりした\n疲れや嫌気を感じている","level":7,"lnum":1,"ex":"She was weary of arguing about the same issues over and over again.","exja":"彼女は何度も同じ問題について議論することにうんざりしていた。"},{"id":6761,"en":"weave","ja":"織る・縫うように進む\n糸を絡ませて布を作る、または曲がりくねって進む","level":7,"lnum":1,"ex":"The artisan weaved colorful threads together to create a beautiful tapestry.","exja":"職人は美しいタペストリーを作るために色とりどりの糸を織り合わせた。"},{"id":6762,"en":"wed","ja":"結婚する\nmarriageの格式的な動詞","level":7,"lnum":1,"ex":"The couple was wed in a small private ceremony attended by close family.","exja":"そのカップルは親しい家族が出席した小さなプライベートな式で結婚した。"},{"id":6763,"en":"weed","ja":"雑草\n農作物や庭を脅かす不要な植物","level":7,"lnum":1,"ex":"She spent the afternoon weeding the garden to prepare it for spring planting.","exja":"彼女は春の植え付けに備えて庭の雑草取りに午後を費やした。"},{"id":6764,"en":"welfare","ja":"福祉・幸福\n健康・幸福・生活の質に関する支援制度","level":7,"lnum":1,"ex":"The organization works to improve the welfare of children in developing countries.","exja":"その組織は発展途上国の子どもたちの福祉を向上させるために活動している。"},{"id":6765,"en":"well-balanced","ja":"バランスの取れた\n心身または内容が均衡している","level":7,"lnum":1,"ex":"A well-balanced diet includes proteins, carbohydrates, vitamins, and minerals.","exja":"バランスの取れた食事にはタンパク質、炭水化物、ビタミン、ミネラルが含まれる。"},{"id":6766,"en":"well-built","ja":"体格のいい\n体がしっかりと鍛えられている","level":7,"lnum":1,"ex":"The well-built athlete easily lifted weights that would challenge most people.","exja":"体格のいいアスリートはほとんどの人が苦労するような重りを楽々と持ち上げた。"},{"id":6767,"en":"well-organized/well-organised","ja":"きちんと整理された\n体系的でよく組織されている","level":7,"lnum":1,"ex":"The conference was well-organized, with every session running smoothly and on time.","exja":"会議はよく整理されており、すべてのセッションがスムーズに時間通りに進行した。"},{"id":6768,"en":"well-paid","ja":"高給の\n給料が高い仕事や人を指す","level":7,"lnum":1,"ex":"She chose a career in law because it is both challenging and well-paid.","exja":"彼女は法律の分野が挑戦的であり高給でもあるため、法律の仕事を選んだ。"},{"id":6769,"en":"wheat","ja":"小麦\nパンや麺の原料となる穀物","level":7,"lnum":1,"ex":"Japan imports a large amount of wheat from the United States each year.","exja":"日本は毎年大量の小麦をアメリカから輸入している。"},{"id":6770,"en":"whereas","ja":"〜である一方\n対比・逆接を示す接続詞。butよりフォーマル","level":7,"lnum":1,"ex":"Some students prefer studying alone, whereas others learn better in groups.","exja":"独りで勉強することを好む生徒がいる一方、グループで学ぶ方が得意な生徒もいる。"},{"id":6771,"en":"whichever","ja":"どちらでも・どれでも\n選択肢の中でどれを選んでも構わない","level":7,"lnum":1,"ex":"You can choose whichever option suits your schedule best.","exja":"あなたのスケジュールに最も合うどちらの選択肢も選んで構いません。"},{"id":6772,"en":"whip","ja":"鞭打つ・素早く動かす\n鞭で打つ、または素早く混ぜる","level":7,"lnum":1,"ex":"The chef whipped the cream until it formed stiff peaks.","exja":"シェフはクリームが固いツノを形成するまで泡立てた。"},{"id":6773,"en":"whiskey/whisky","ja":"ウイスキー\n大麦などを原料とした蒸留酒","level":7,"lnum":1,"ex":"He ordered a glass of whisky with ice at the end of a long workday.","exja":"長い仕事の日の終わりに、彼はウイスキーをロックで一杯注文した。"},{"id":6774,"en":"whisper","ja":"ささやく\n声を低く抑えて静かに話す","level":7,"lnum":1,"ex":"She whispered the answer to her friend so the teacher wouldn't hear.","exja":"先生に聞こえないように、彼女は友人に答えをささやいた。"},{"id":6775,"en":"whistle","ja":"口笛を吹く・笛を吹く\n唇や笛で鋭い音を出す","level":7,"lnum":1,"ex":"The referee blew his whistle to signal the end of the first half.","exja":"審判は前半の終わりを示すために笛を吹いた。"},{"id":6776,"en":"widen","ja":"広げる・広くなる\n幅や範囲を拡大する","level":7,"lnum":1,"ex":"The city plans to widen the main road to reduce traffic congestion.","exja":"市は交通渋滞を緩和するために幹線道路を広げる計画を立てている。"},{"id":6777,"en":"widow","ja":"未亡人\n夫を亡くした女性","level":7,"lnum":1,"ex":"The widow received many messages of condolence from around the world.","exja":"未亡人は世界中から多くの弔意のメッセージを受け取った。"},{"id":6778,"en":"width","ja":"幅\n物の左右の広がりの長さ","level":7,"lnum":1,"ex":"The bridge has a width of eight meters, allowing two lanes of traffic.","exja":"その橋は幅8メートルで、2車線の交通が可能だ。"},{"id":6779,"en":"wilderness","ja":"荒野・原野\n人の手が入っていない自然のままの広大な土地","level":7,"lnum":1,"ex":"They spent a week camping in the wilderness, far from any city or town.","exja":"彼らはどんな都市や町からも遠く離れた荒野で1週間キャンプをした。"},{"id":6780,"en":"willing","ja":"自発的な・喜んでする\n強制でなく自分から進んで行う","level":7,"lnum":1,"ex":"She was willing to work overtime to finish the project before the deadline.","exja":"彼女は締め切り前にプロジェクトを終わらせるために残業する気があった。"},{"id":6781,"en":"willingly","ja":"自発的に・喜んで\n強制されずに自分から行動する様子","level":7,"lnum":1,"ex":"He willingly gave up his seat on the bus for the elderly passenger.","exja":"彼は高齢の乗客のために自発的にバスの席を譲った。"},{"id":6782,"en":"winding","ja":"曲がりくねった\n道や川などが蛇行している状態","level":7,"lnum":1,"ex":"The winding mountain road made several passengers feel carsick.","exja":"曲がりくねった山道が何人かの乗客を車酔いさせた。"},{"id":6783,"en":"windshield","ja":"フロントガラス\n車の前面のガラス（米語）","level":7,"lnum":1,"ex":"The crack in the windshield made it difficult to see clearly while driving.","exja":"フロントガラスのひび割れが運転中にはっきり見えにくくさせた。"},{"id":6784,"en":"wink","ja":"ウィンク\n片目をすばやく閉じる合図","level":7,"lnum":1,"ex":"He winked at his sister across the table to signal that he was joking.","exja":"彼はジョークを言っているというサインを送るために、テーブル越しに妹にウィンクした。"},{"id":6785,"en":"wire","ja":"電線をつなぐ・配線する\n電気回路をつなぐ、またはお金を電子送金する","level":7,"lnum":1,"ex":"The technician wired the new speakers to the sound system in the hall.","exja":"技術者はホールのサウンドシステムに新しいスピーカーを配線した。"},{"id":6786,"en":"wit","ja":"機知・ユーモア\n素早く的確な言葉で笑わせる知的なユーモア","level":7,"lnum":1,"ex":"Her sharp wit made every conversation entertaining and memorable.","exja":"彼女の鋭い機知はあらゆる会話を楽しくて記憶に残るものにした。"},{"id":6787,"en":"withdraw","ja":"引き出す・撤退する\n銀行から現金を出す、または関与をやめる","level":7,"lnum":1,"ex":"He withdrew some cash from the ATM before leaving for the airport.","exja":"空港に向かう前に、彼はATMから現金を引き出した。"},{"id":6788,"en":"withdrawal","ja":"引き出し・撤退\nお金の引き出し、または関与の取り消し","level":7,"lnum":1,"ex":"The withdrawal of troops from the region helped stabilize the situation.","exja":"その地域からの軍の撤退が状況の安定化に役立った。"},{"id":6789,"en":"witness","ja":"目撃者\n事件や出来事を実際に見た人","level":7,"lnum":1,"ex":"Several people witnessed the accident and called the emergency services.","exja":"数人の人々が事故を目撃して緊急サービスに電話した。"},{"id":6790,"en":"witty","ja":"機知に富んだ\n素早くユーモアのある言葉が言える","level":7,"lnum":1,"ex":"Her witty remarks during the speech had the entire audience laughing.","exja":"スピーチ中の彼女の機知に富んだ発言が全聴衆を笑わせた。"},{"id":6791,"en":"wolf","ja":"オオカミ\nイヌ科の野生動物。群れで狩りをする","level":7,"lnum":1,"ex":"The wolf howled loudly at the full moon in the cold winter night.","exja":"オオカミは寒い冬の夜に満月に向かって大きく遠吠えした。"},{"id":6792,"en":"wondrous","ja":"驚異的な・素晴らしい\n驚くほど素晴らしい（やや文語的）","level":7,"lnum":1,"ex":"The northern lights are a wondrous natural phenomenon that fills the sky with color.","exja":"オーロラは空を色で満たす驚異的な自然現象だ。"},{"id":6793,"en":"woodcarving","ja":"木彫り\n木を彫って形を作る工芸技術","level":7,"lnum":1,"ex":"Traditional woodcarving is a craft that requires years of practice to master.","exja":"伝統的な木彫りは習得に何年もの練習が必要な工芸だ。"},{"id":6794,"en":"wordlessly","ja":"無言で\n言葉を発せずに","level":7,"lnum":1,"ex":"She nodded wordlessly, too moved to speak after the emotional performance.","exja":"感情的な演技の後、感極まって言葉が出ず、彼女は無言でうなずいた。"},{"id":6795,"en":"workaholic","ja":"仕事中毒の\n仕事に過剰に没頭する人の形容詞","level":7,"lnum":1,"ex":"He was such a workaholic that he often forgot to take his lunch break.","exja":"彼はとても仕事中毒だったので、昼休みを取るのをよく忘れた。"},{"id":6796,"en":"workbench","ja":"作業台\n工具を使って作業するための台","level":7,"lnum":1,"ex":"The carpenter laid out all his tools neatly on the workbench before starting.","exja":"大工は始める前に作業台の上にすべての道具をきれいに並べた。"},{"id":6797,"en":"workman","ja":"職人・作業員\n肉体的な仕事をする労働者","level":7,"lnum":1,"ex":"The workmen arrived early in the morning to begin repairing the roof.","exja":"職人たちは屋根の修理を始めるために朝早くに到着した。"},{"id":6798,"en":"worktable","ja":"作業テーブル\n手工芸や細かい作業のための専用テーブル","level":7,"lnum":1,"ex":"She spread her fabric patterns out on the worktable to begin cutting.","exja":"彼女は切り始めるために作業テーブルに布のパターンを広げた。"},{"id":6799,"en":"worldly","ja":"世俗的な・現実的な\n現実の世界や物質的なことに精通している","level":7,"lnum":1,"ex":"Despite her worldly experience, she still found joy in simple pleasures.","exja":"世俗的な経験にもかかわらず、彼女は依然として単純な喜びに喜びを見出した。"},{"id":6800,"en":"worldview","ja":"世界観\n世界や人生についての基本的な見方や考え方","level":7,"lnum":1,"ex":"Traveling to different countries can broaden your worldview significantly.","exja":"異なる国を旅することはあなたの世界観を大幅に広げることができる。"},{"id":6801,"en":"worm","ja":"ミミズ・虫\n土中に住む環形動物。コンピューターウイルスの一種も指す","level":7,"lnum":1,"ex":"The fisherman dug for worms in the garden to use as bait.","exja":"釣り人は餌として使うために庭でミミズを掘った。"},{"id":6802,"en":"wornout/worn out/worn-out","ja":"使い古した・疲れ果てた\n物が使いすぎて傷んだ、または人が極度に疲れた","level":7,"lnum":1,"ex":"His worn-out shoes were falling apart after years of daily use.","exja":"彼の使い古した靴は毎日何年も使い続けてボロボロになっていた。"},{"id":6803,"en":"worrying","ja":"心配な・気がかりな\n不安を引き起こす様子","level":7,"lnum":1,"ex":"The doctor said the test results were worrying and recommended further investigation.","exja":"医師はテスト結果が心配であるとし、さらなる検査を勧めた。"},{"id":6804,"en":"worsen","ja":"悪化する\n状況や状態が以前よりも悪くなる","level":7,"lnum":1,"ex":"The patient's condition worsened overnight despite the doctors' best efforts.","exja":"医師たちの最善の努力にもかかわらず、患者の状態は一晩で悪化した。"},{"id":6805,"en":"worship","ja":"崇拝・礼拝\n神や崇高な存在に祈りや敬意を捧げること","level":7,"lnum":1,"ex":"Thousands of pilgrims travel to the shrine each year to worship.","exja":"毎年何千人もの巡礼者が礼拝のために神社を訪れる。"},{"id":6806,"en":"worthless","ja":"価値のない\n役に立たない、または価値がない","level":7,"lnum":1,"ex":"The old currency became worthless after the country reformed its financial system.","exja":"国が財政制度を改革した後、古い通貨は価値のないものになった。"},{"id":6807,"en":"wound","ja":"傷つける\n刃物などで身体に傷を負わせる動詞","level":7,"lnum":1,"ex":"The soldier was wounded in the leg during the battle and needed surgery.","exja":"兵士は戦闘中に脚を傷つけられ、手術が必要だった。"},{"id":6808,"en":"wreck","ja":"難破船・残骸\n壊れた乗り物や建物の残骸","level":7,"lnum":1,"ex":"The divers explored the wreck of an ancient ship on the ocean floor.","exja":"ダイバーたちは海底の古代船の残骸を探索した。"},{"id":6809,"en":"wrongly","ja":"誤って・不当に\n間違った方法で、または不公平に","level":7,"lnum":1,"ex":"He was wrongly convicted of a crime he did not commit and spent years in prison.","exja":"彼は犯していない罪で不当に有罪とされ、何年も刑務所で過ごした。"},{"id":6810,"en":"X-ray","ja":"X線・レントゲン\n放射線を使って体内を撮影する検査","level":7,"lnum":1,"ex":"The doctor ordered an X-ray to check if the patient had any broken bones.","exja":"医師は患者に骨折がないか確認するためにレントゲン検査を指示した。"},{"id":6811,"en":"yearn","ja":"切望する\n何かを強く求めて恋しがる","level":7,"lnum":1,"ex":"She yearned to return to her home country after living abroad for so long.","exja":"彼女は長い間海外で暮らした後、故郷に帰ることを切望した。"},{"id":6812,"en":"yell","ja":"叫ぶ\n大声を出して叫ぶ","level":7,"lnum":1,"ex":"The coach yelled encouragement to the players from the sideline.","exja":"コーチはサイドラインから選手たちに激励の声を上げた。"},{"id":6813,"en":"yield","ja":"産出する・譲る\n作物や利益を生む、または主張をやめて従う","level":7,"lnum":1,"ex":"The apple trees in the orchard yielded a large harvest this autumn.","exja":"果樹園のリンゴの木は今年の秋に大きな収穫をもたらした。"},{"id":6814,"en":"youthful","ja":"若々しい\n実際の年齢より若く見えるまたは感じられる","level":7,"lnum":1,"ex":"Despite being in her sixties, she had a youthful energy and enthusiasm for life.","exja":"60代であるにもかかわらず、彼女は若々しいエネルギーと人生への熱意を持っていた。"},{"id":6815,"en":"zip","ja":"ジッパー・素早く動く\nチャックで留める、または素早く移動する","level":7,"lnum":1,"ex":"She zipped up her jacket against the cold wind before stepping outside.","exja":"彼女は外に出る前に冷たい風を防ぐためにジャケットのジッパーを閉めた。"},{"id":6816,"en":"zoom","ja":"急速に動く・ズームする\n素早く動く、またはカメラのズーム操作","level":7,"lnum":1,"ex":"The car zoomed past us at an incredible speed on the empty highway.","exja":"その車は空いた高速道路で信じられないほどのスピードで私たちの横を通り過ぎた。"}];